export const CATALOG = [{"id":"edb-0001","name":"כפיפת בטן מלאה 3 4","name_en":"3/4 sit-up","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors","lower back"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו את הידיים מאחורי הראש כשהמרפקים פונים החוצה.","תוך הפעלת שרירי הבטן, הרימו לאט את פלג הגוף העליון מהרצפה, בכיפוף קדימה עד שהגו נמצא בזווית של 45 מעלות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"2gPfomN"},{"id":"edb-0002","name":"כפיפה צדית 45°","name_en":"45° side bend","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והידיים מושטות ישר למטה לצידי הגוף.","כשהגב ישר וליבת הגוף מופעלת, כופפו לאט את הגו לצד אחד, תוך הורדת היד לכיוון הברך.","עצרו לרגע בתחתית התנועה, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו על התרגיל בצד השני.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your arms extended straight down by your sides.","Keeping your back straight and your core engaged, slowly bend your torso to one side, lowering your hand towards your knee.","Pause for a moment at the bottom, then slowly return to the starting position.","Repeat on the other side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"Hy9D21L"},{"id":"edb-0003","name":"air bike","name_en":"air bike","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שכבו על הגב כשהידיים מונחות מאחורי הראש.","הרימו את הרגליים מהרצפה וכופפו את הברכיים בזווית של 90 מעלות.","קרבו את המרפק הימני לכיוון הברך השמאלית תוך יישור הרגל הימנית בו-זמנית.","חזרו לעמדת ההתחלה וחזרו על התנועה בצד הנגדי, תוך קירוב המרפק השמאלי לברך הימנית ויישור הרגל השמאלית.","המשיכו להחליף צדדים בתנועת דיווש למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your hands placed behind your head.","Lift your legs off the ground and bend your knees at a 90-degree angle.","Bring your right elbow towards your left knee while simultaneously straightening your right leg.","Return to the starting position and repeat the movement on the opposite side, bringing your left elbow towards your right knee while straightening your left leg.","Continue alternating sides in a pedaling motion for the desired number of repetitions."],"mediaId":"1ZFqTDN"},{"id":"edb-1512","name":"מתיחה","name_en":"all fours squad stretch","muscle":"legs","equipment":"body weight","target":"quads","bodyPart":"upper legs","secondaryMuscles":["hamstrings","glutes"],"steps":["התחילו בעמידה על ארבע, כשהידיים ישר מתחת לכתפיים והברכיים ישר מתחת לירכיים.","הושיטו רגל אחת ישר לאחור, כשהברך כפופה וכף הרגל מכופפת.","הורידו לאט את הירכיים לכיוון הרצפה, תוך הרגשת מתיחה בשרירי הארבע-ראשי.","החזיקו בתנוחה זו במשך 20-30 שניות.","החליפו רגליים וחזרו על המתיחה בצד השני."],"steps_en":["Start on all fours with your hands directly under your shoulders and your knees directly under your hips.","Extend one leg straight back, keeping your knee bent and your foot flexed.","Slowly lower your hips towards the ground, feeling a stretch in your quads.","Hold this position for 20-30 seconds.","Switch legs and repeat the stretch on the other side."],"mediaId":"qBcKorM"},{"id":"edb-0006","name":"alternate heel touchers","name_en":"alternate heel touchers","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הושיטו את הידיים ישר הצידה, במקביל לרצפה.","תוך הפעלת שרירי הבטן, הרימו את הכתפיים מהרצפה והושיטו את היד הימנית לכיוון העקב הימני.","חזרו לעמדת ההתחלה וחזרו על התרגיל בצד שמאל, תוך הושטת היד השמאלית לכיוון העקב השמאלי.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your knees bent and feet flat on the ground.","Extend your arms straight out to the sides, parallel to the ground.","Engaging your abs, lift your shoulders off the ground and reach your right hand towards your right heel.","Return to the starting position and repeat on the left side, reaching your left hand towards your left heel.","Continue alternating sides for the desired number of repetitions."],"mediaId":"qaZVsGk"},{"id":"edb-0007","name":"משיכת פולי לסירוגין לצדדים","name_en":"alternate lateral pulldown","muscle":"back","equipment":"cable","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","rhomboids"],"steps":["שבו על מכונת הפולי כשהגב ישר וכפות הרגליים שטוחות על הרצפה.","אחזו בידיות באחיזה עליונה, ברוחב מעט גדול מרוחב הכתפיים.","הטו את הגוף מעט לאחור ומשכו את הידיות לכיוון החזה, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה, ולאחר מכן שחררו לאט את הידיות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the cable machine with your back straight and feet flat on the ground.","Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.","Lean back slightly and pull the handles towards your chest, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"4IKbhHV"},{"id":"edb-1368","name":"ankle circles","name_en":"ankle circles","muscle":"legs","equipment":"body weight","target":"calves","bodyPart":"lower legs","secondaryMuscles":["ankle stabilizers"],"steps":["שבו על הרצפה עם הרגליים מושטות לפניכם.","הרימו רגל אחת מהרצפה וסובבו את הקרסול בתנועה מעגלית.","בצעו את מספר הסיבובים הרצוי בכיוון אחד, ולאחר מכן החליפו לכיוון השני.","חזרו עם הרגל השנייה."],"steps_en":["Sit on the ground with your legs extended in front of you.","Lift one leg off the ground and rotate your ankle in a circular motion.","Perform the desired number of circles in one direction, then switch to the other direction.","Repeat with the other leg."],"mediaId":"uL9CsKm"},{"id":"edb-3293","name":"מתח","name_en":"archer pull up","muscle":"back","equipment":"body weight","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["התחילו בתלייה ממתקן מתח באחיזה עליונה, ברוחב מעט גדול מרוחב הכתפיים.","הפעילו את ליבת הגוף ומשכו את השכמות מטה ואחורה.","תוך כדי משיכת הגוף כלפי מעלה, כופפו יד אחת וקרבו את המרפק לכיוון הצד, בעוד היד השנייה נשארת ישרה.","המשיכו למשוך עד שהסנטר מעל המוט והיד הכפופה מכופפת לגמרי.","הורידו את עצמכם בחזרה בשליטה, יַשרו את היד הכפופה וחזרו על התנועה בצד השני.","החליפו צדדים בכל חזרה."],"steps_en":["Start by hanging from a pull-up bar with an overhand grip, slightly wider than shoulder-width apart.","Engage your core and pull your shoulder blades down and back.","As you pull yourself up, bend one arm and bring your elbow towards your side, while keeping the other arm straight.","Continue pulling until your chin is above the bar and your bent arm is fully flexed.","Lower yourself back down with control, straightening the bent arm and repeating the movement on the other side.","Alternate sides with each repetition."],"mediaId":"72BC5Za"},{"id":"edb-3294","name":"שכיבת סמיכה","name_en":"archer push up","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders","core"],"steps":["התחילו בתנוחת שכיבת סמיכה עם הידיים ברוחב מעט גדול מרוחב הכתפיים.","הושיטו יד אחת ישר הצידה, במקביל לרצפה.","הורידו את הגוף על ידי כיפוף המרפקים, תוך שמירה על גב ישר וליבת גוף מופעלת.","דחפו בחזרה למעלה לעמדת ההתחלה.","חזרו על התרגיל בצד השני, תוך הושטת היד הנגדית הצידה.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Start in a push-up position with your hands slightly wider than shoulder-width apart.","Extend one arm straight out to the side, parallel to the ground.","Lower your body by bending your elbows, keeping your back straight and core engaged.","Push back up to the starting position.","Repeat on the other side, extending the opposite arm out to the side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"A9qxk2F"},{"id":"edb-2355","name":"arm slingers hanging bent knee legs","name_en":"arm slingers hanging bent knee legs","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["shoulders","back"],"steps":["התלו ממתקן מתח כשהידיים מיושרות לגמרי והברכיים כפופות בזווית של 90 מעלות.","הפעילו את ליבת הגוף והרימו את הברכיים לכיוון החזה, תוך קירובן ככל האפשר למרפקים.","הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Hang from a pull-up bar with your arms fully extended and your knees bent at a 90-degree angle.","Engage your core and lift your knees towards your chest, bringing them as close to your elbows as possible.","Slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"uWpxD4v"},{"id":"edb-2333","name":"arm slingers hanging straight legs","name_en":"arm slingers hanging straight legs","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["shoulders","back"],"steps":["התלו ממתקן מתח כשהידיים מיושרות לגמרי והרגליים ישרות כלפי מטה.","הפעילו את ליבת הגוף והרימו את הרגליים לפנים עד שהן מקבילות לרצפה.","החזיקו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Hang from a pull-up bar with your arms fully extended and your legs straight down.","Engage your core and lift your legs up in front of you until they are parallel to the ground.","Hold for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"PXTIwgu"},{"id":"edb-3214","name":"arms apart circular toe touch (male)","name_en":"arms apart circular toe touch (male)","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והידיים מושטות הצידה.","תוך שמירה על רגליים ישרות, כופפו קדימה במותניים והושיטו את היד הימנית כלפי מטה לכיוון האצבעות.","תוך כדי ההושטה כלפי מטה, הרימו בו-זמנית את הרגל השמאלית ישר כלפי מעלה מאחוריכם, תוך שמירה על שיווי משקל.","חזרו לעמדת ההתחלה וחזרו על התנועה כשהיד השמאלית מושטת לכיוון האצבעות והרגל הימנית מתרוממת מאחוריכם.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and arms extended to the sides.","Keeping your legs straight, bend forward at the waist and reach down towards your toes with your right hand.","As you reach down, simultaneously lift your left leg straight up behind you, maintaining balance.","Return to the starting position and repeat the movement with your left hand reaching towards your toes and your right leg lifting up behind you.","Continue alternating sides for the desired number of repetitions."],"mediaId":"RtyAsy1"},{"id":"edb-3204","name":"כפיפת בטן מלאה מעל הראש","name_en":"arms overhead full sit-up (male)","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors","lower back"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הושיטו את הידיים מעל הראש, תוך שמירה עליהן ישרות.","תוך הפעלת שרירי הבטן, הרימו לאט את פלג הגוף העליון מהרצפה, בכיפוף קדימה עד שהגו זקוף.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your knees bent and feet flat on the ground.","Extend your arms overhead, keeping them straight.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is upright.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"NAkmgdx"},{"id":"edb-0009","name":"מקבילים בכריעה בסיוע","name_en":"assisted chest dip (kneeling)","muscle":"chest","equipment":"leverage machine","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["כווננו את המכונה לגובה הרצוי ואבטחו את הברכיים על הכרית.","אחזו בידיות כשכפות הידיים פונות מטה והידיים מיושרות לגמרי.","הורידו את הגוף על ידי כיפוף המרפקים עד שהזרועות מקבילות לרצפה.","עצרו לרגע, ולאחר מכן דחפו את עצמכם בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the machine to your desired height and secure your knees on the pad.","Grasp the handles with your palms facing down and your arms fully extended.","Lower your body by bending your elbows until your upper arms are parallel to the floor.","Pause for a moment, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"PAgTVaK"},{"id":"edb-0011","name":"הרמה בסיוע","name_en":"assisted hanging knee raise","muscle":"core","equipment":"assisted","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["התלו ממתקן מתח כשהידיים מיושרות לגמרי וכפות הידיים פונות הרחק מכם.","הפעילו את שרירי הליבה והרימו את הברכיים לכיוון החזה, תוך כיפוף במפרקי הירך והברכיים.","עצרו לרגע בשיא התנועה, תוך כיווץ שרירי הבטן.","הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Hang from a pull-up bar with your arms fully extended and your palms facing away from you.","Engage your core muscles and lift your knees towards your chest, bending at the hips and knees.","Pause for a moment at the top of the movement, squeezing your abs.","Slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"03lzqwk"},{"id":"edb-0010","name":"הרמה בסיוע","name_en":"assisted hanging knee raise with throw down","muscle":"core","equipment":"assisted","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors","lower back"],"steps":["התלו ממתקן מתח כשהידיים מיושרות לגמרי וכפות הידיים פונות הרחק מכם.","הפעילו את ליבת הגוף והרימו את הברכיים לכיוון החזה, תוך שמירה על הרגליים צמודות.","כשהברכיים בגובה החזה, זרקו בפיצוץ את הרגליים כלפי מטה לכיוון הרצפה, תוך יישורן לגמרי.","אפשרו לרגליים להתנדנד בחזרה כלפי מעלה וחזרו על התנועה למספר החזרות הרצוי."],"steps_en":["Hang from a pull-up bar with your arms fully extended and your palms facing away from you.","Engage your core and lift your knees towards your chest, keeping your legs together.","Once your knees are at chest level, explosively throw your legs down towards the ground, extending them fully.","Allow your legs to swing back up and repeat the movement for the desired number of repetitions."],"mediaId":"8K0w2yA"},{"id":"edb-1708","name":"מתיחה בשכיבה בסיוע","name_en":"assisted lying calves stretch","muscle":"legs","equipment":"assisted","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings"],"steps":["שכבו על הגב עם הרגליים מושטות.","כופפו ברך אחת והניחו את כף הרגל שטוחה על הרצפה.","בעזרת הידיים או מגבת, משכו בעדינות את האצבעות לכיוון הגוף, תוך הרגשת מתיחה בשוק.","החזיקו את המתיחה במשך 20-30 שניות.","שחררו את המתיחה וחזרו עם הרגל השנייה."],"steps_en":["Lie on your back with your legs extended.","Bend one knee and place your foot flat on the ground.","Using your hands or a towel, gently pull your toes towards your body, feeling a stretch in your calf.","Hold the stretch for 20-30 seconds.","Release the stretch and repeat on the other leg."],"mediaId":"GxDwDX0"},{"id":"edb-1709","name":"מתיחה בשכיבה בסיוע","name_en":"assisted lying glutes stretch","muscle":"glutes","equipment":"assisted","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings"],"steps":["שכבו על הגב עם הרגליים מושטות.","כופפו את הברך הימנית והניחו את הקרסול הימני על הירך השמאלית, ממש מעל הברך.","אחזו בירך השמאלית בשתי הידיים ומשכו אותה בעדינות לכיוון החזה.","החזיקו את המתיחה במשך 20-30 שניות.","שחררו וחזרו על התרגיל בצד השני."],"steps_en":["Lie on your back with your legs extended.","Bend your right knee and place your right ankle on your left thigh, just above the knee.","Grasp your left thigh with both hands and gently pull it towards your chest.","Hold the stretch for 20-30 seconds.","Release and repeat on the other side."],"mediaId":"yn0LjwL"},{"id":"edb-1710","name":"מתיחה בשכיבה בסיוע","name_en":"assisted lying gluteus and piriformis stretch","muscle":"glutes","equipment":"assisted","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings"],"steps":["שכבו על הגב עם הרגליים מושטות.","כופפו את הברך הימנית והניחו את הקרסול הימני על הירך השמאלית, ממש מעל הברך.","אחזו בירך השמאלית בשתי הידיים ומשכו אותה בעדינות לכיוון החזה.","החזיקו את המתיחה במשך 20-30 שניות.","שחררו את המתיחה וחזרו על התרגיל בצד השני."],"steps_en":["Lie on your back with your legs extended.","Bend your right knee and place your right ankle on your left thigh, just above the knee.","Grasp your left thigh with both hands and gently pull it towards your chest.","Hold the stretch for 20-30 seconds.","Release the stretch and repeat on the other side."],"mediaId":"RQNVT10"},{"id":"edb-0012","name":"הרמת רגליים בשכיבה לצדדים בסיוע","name_en":"assisted lying leg raise with lateral throw down","muscle":"core","equipment":"assisted","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors","obliques"],"steps":["שכבו על הגב עם הרגליים מושטות והידיים לצידי הגוף.","הניחו את הידיים מתחת לישבן לתמיכה.","הפעילו את שרירי הבטן והרימו את הרגליים מהרצפה, תוך שמירה עליהן ישרות.","תוך שמירה על הרגליים צמודות, הורידו אותן לצד אחד עד שהן נמצאות מספר סנטימטרים מעל הרצפה.","עצרו לרגע, ולאחר מכן הרימו את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התנועה לצד השני.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your legs extended and your arms by your sides.","Place your hands under your glutes for support.","Engage your abs and lift your legs off the ground, keeping them straight.","While keeping your legs together, lower them to one side until they are a few inches above the ground.","Pause for a moment, then lift your legs back to the starting position.","Repeat the movement to the other side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"UGhRD1A"},{"id":"edb-0013","name":"הרמת רגליים בשכיבה בסיוע","name_en":"assisted lying leg raise with throw down","muscle":"core","equipment":"assisted","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors","quadriceps"],"steps":["שכבו על הגב עם הרגליים מושטות והידיים לצידי הגוף.","הניחו את הידיים מתחת לישבן לתמיכה.","הפעילו את ליבת הגוף והרימו את הרגליים מהרצפה, תוך שמירה עליהן ישרות.","הרימו את הרגליים עד שהן ניצבות לרצפה.","הורידו את הרגליים בחזרה לעמדת ההתחלה.","בו-זמנית, זרקו את הרגליים כלפי מטה לכיוון הרצפה, תוך שמירה עליהן ישרות.","הרימו את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your legs extended and your arms by your sides.","Place your hands under your glutes for support.","Engage your core and lift your legs off the ground, keeping them straight.","Raise your legs until they are perpendicular to the ground.","Lower your legs back down to the starting position.","Simultaneously, throw your legs down towards the ground, keeping them straight.","Raise your legs back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"VX5YKR5"},{"id":"edb-0014","name":"פיתול רוסי בסיוע","name_en":"assisted motion russian twist","muscle":"core","equipment":"medicine ball","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","lower back"],"steps":["שבו על הרצפה עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","אחזו בכדור הכוח בשתי הידיים מול החזה.","הטו את הגוף מעט לאחור, תוך הפעלת שרירי הבטן ושמירה על גב ישר.","סובבו לאט את הגו ימינה, תוך קירוב כדור הכוח לצד הימני של הגוף.","עצרו לרגע, ולאחר מכן סובבו את הגו שמאלה, תוך קירוב כדור הכוח לצד השמאלי של הגוף.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Sit on the ground with your knees bent and feet flat on the floor.","Hold the medicine ball with both hands in front of your chest.","Lean back slightly, engaging your abs and keeping your back straight.","Slowly twist your torso to the right, bringing the medicine ball towards the right side of your body.","Pause for a moment, then twist your torso to the left, bringing the medicine ball towards the left side of your body.","Continue alternating sides for the desired number of repetitions."],"mediaId":"r7cT9YD"},{"id":"edb-0015","name":"מתח אחיזה צרה בסיוע","name_en":"assisted parallel close grip pull-up","muscle":"back","equipment":"leverage machine","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["כווננו את המכונה למשקל ולגובה הרצויים.","הניחו את הידיים על המקבילים באחיזה צרה, כשכפות הידיים פונות זו לזו.","התלו על המוטות כשהידיים מיושרות לגמרי וכפות הרגליים מורמות מהרצפה.","הפעילו את שרירי הגב ומשכו את הגוף כלפי מעלה לכיוון המוטות, תוך שמירה על המרפקים קרוב לגוף.","המשיכו למשוך עד שהסנטר מעל המוטות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הגוף בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the machine to your desired weight and height.","Place your hands on the parallel bars with a close grip, palms facing each other.","Hang from the bars with your arms fully extended and your feet off the ground.","Engage your back muscles and pull your body up towards the bars, keeping your elbows close to your body.","Continue pulling until your chin is above the bars.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"vrhHa6D"},{"id":"edb-0016","name":"assisted prone hamstring","name_en":"assisted prone hamstring","muscle":"legs","equipment":"assisted","target":"hamstrings","bodyPart":"upper legs","secondaryMuscles":["glutes","lower back"],"steps":["שכבו על הבטן על מזרן או ספסל עם הרגליים מיושרות לגמרי.","בקשו מבן זוג לאבטח את הקרסוליים או השתמשו בגומיית התנגדות לשם כך.","הפעילו את שרירי הירך האחוריים והרימו את הרגליים לכיוון הישבן, תוך שמירה על הברכיים ישרות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie face down on a mat or bench with your legs fully extended.","Have a partner or use a resistance band to secure your ankles.","Engage your hamstrings and lift your legs towards your glutes, keeping your knees straight.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"VedGSby"},{"id":"edb-1713","name":"מתיחה בשכיבה בשכיבה על הבטן בסיוע","name_en":"assisted prone lying quads stretch","muscle":"legs","equipment":"assisted","target":"quads","bodyPart":"upper legs","secondaryMuscles":["hamstrings","glutes"],"steps":["שכבו על הבטן על הרצפה עם הרגליים מושטות.","כופפו את הברך השמאלית והושיטו את היד השמאלית לאחור כדי לאחוז בכף הרגל או בקרסול השמאלי.","משכו בעדינות את כף הרגל השמאלית לכיוון הישבן, תוך הרגשת מתיחה בשריר הארבע-ראשי השמאלי.","החזיקו את המתיחה במשך 20-30 שניות, ולאחר מכן שחררו.","חזרו עם הרגל הימנית."],"steps_en":["Lie face down on the ground with your legs extended.","Bend your left knee and reach back with your left hand to grab your left foot or ankle.","Gently pull your left foot towards your glutes, feeling a stretch in your left quad.","Hold the stretch for 20-30 seconds, then release.","Repeat with your right leg."],"mediaId":"YUYAMEj"},{"id":"edb-1714","name":"מתיחה בשכיבה על הבטן בסיוע","name_en":"assisted prone rectus femoris stretch","muscle":"core","equipment":"assisted","target":"abs","bodyPart":"waist","secondaryMuscles":["quadriceps"],"steps":["שכבו על הבטן על הרצפה עם הרגליים ישרות.","כופפו את הברך הימנית והושיטו את היד הימנית לאחור כדי לאחוז בכף הרגל או בקרסול הימני.","משכו בעדינות את כף הרגל או הקרסול הימני לכיוון הישבן, תוך הרגשת מתיחה בחזית הירך הימנית.","החזיקו את המתיחה במשך 20-30 שניות.","שחררו וחזרו על התרגיל בצד השני."],"steps_en":["Lie face down on the ground with your legs straight.","Bend your right knee and reach back with your right hand to grab your right foot or ankle.","Gently pull your right foot or ankle towards your glutes, feeling a stretch in the front of your right thigh.","Hold the stretch for 20-30 seconds.","Release and repeat on the other side."],"mediaId":"2Ryn564"},{"id":"edb-0017","name":"מתח בסיוע","name_en":"assisted pull-up","muscle":"back","equipment":"leverage machine","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["כווננו את המכונה להגדרות המשקל והגובה הרצויים.","אחזו בידיות באחיזה עליונה, ברוחב מעט גדול מרוחב הכתפיים.","התלו כשהידיים מיושרות לגמרי וכפות הרגליים מורמות מהרצפה.","הפעילו את שרירי הגב ומשכו את הגוף כלפי מעלה לכיוון הידיות, תוך שמירה על המרפקים קרוב לגוף.","המשיכו למשוך עד שהסנטר מעל הידיות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הגוף בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the machine to your desired weight and height settings.","Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.","Hang with your arms fully extended and your feet off the ground.","Engage your back muscles and pull your body up towards the handles, keeping your elbows close to your body.","Continue pulling until your chin is above the handles.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"kiJ4Z2K"},{"id":"edb-1716","name":"מתיחה בישיבה עם כדור פיזיו","name_en":"assisted seated pectoralis major stretch with stability ball","muscle":"chest","equipment":"assisted","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["שבו על כדור פיזיו כשכפות הרגליים שטוחות על הרצפה והגב ישר.","אחזו בכדור פיזיו בשתי הידיים והושיטו את הידיים ישר לפניכם.","הורידו לאט את כדור הפיזיו לכיוון החזה, תוך הרגשת מתיחה בשרירי החזה.","החזיקו את המתיחה למספר שניות, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a stability ball with your feet flat on the ground and your back straight.","Hold a stability ball with both hands and extend your arms straight out in front of you.","Slowly lower the stability ball towards your chest, feeling a stretch in your pectoral muscles.","Hold the stretch for a few seconds, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"RoV1Rfa"},{"id":"edb-1712","name":"מתיחה בשכיבה צדי בסיוע","name_en":"assisted side lying adductor stretch","muscle":"legs","equipment":"assisted","target":"adductors","bodyPart":"upper legs","secondaryMuscles":["hamstrings","glutes"],"steps":["שכבו על הצד עם הרגליים ישרות ומונחות זו על גבי זו.","כופפו מעט את הרגל התחתונה לשם יציבות.","הניחו את כף הרגל העליונה על משטח יציב, כגון ספסל או מדרגה.","תוך שמירה על הרגל העליונה ישרה, הורידו אותה לאט לכיוון הרצפה, תוך הרגשת מתיחה בפנים הירך.","החזיקו את המתיחה במשך 20-30 שניות.","חזרו לעמדת ההתחלה וחזרו על התרגיל בצד השני."],"steps_en":["Lie on your side with your legs straight and stacked on top of each other.","Bend your bottom leg slightly for stability.","Place your top foot on a stable surface, such as a bench or step.","Keeping your top leg straight, slowly lower it towards the ground, feeling a stretch in your inner thigh.","Hold the stretch for 20-30 seconds.","Return to the starting position and repeat on the other side."],"mediaId":"hC6oYY5"},{"id":"edb-1758","name":"כפיפת בטן מלאה בסיוע","name_en":"assisted sit-up","muscle":"core","equipment":"assisted","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שבו על קצה ספסל או בקשו ממישהו להחזיק את הרגליים למטה.","שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו את הידיים מאחורי הראש כשהמרפקים פונים החוצה.","תוך הפעלת שרירי הבטן, הרימו לאט את פלג הגוף העליון מהרצפה, בכיפוף קדימה עד שהגו נמצא בזווית של 45 מעלות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the edge of a bench or have someone hold your feet down.","Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"aumB2IV"},{"id":"edb-1431","name":"מתח אחיזה תחתית בעמידה בסיוע","name_en":"assisted standing chin-up","muscle":"back","equipment":"leverage machine","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["כווננו את המכונה לרמת הסיוע הרצויה.","עמדו על משטח הרגליים ואחזו בידיות באחיזה עליונה, ברוחב מעט גדול מרוחב הכתפיים.","שמרו על החזה מורם והכתפיים לאחור, הפעילו את ליבת הגוף, וכופפו מעט את הברכיים.","משכו את הגוף כלפי מעלה על ידי כיפוף המרפקים והורדתם לכיוון הצדדים.","המשיכו למשוך עד שהסנטר מעל המוט.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הגוף בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the machine to your desired assistance level.","Stand on the foot platform and grip the handles with an overhand grip, slightly wider than shoulder-width apart.","Keep your chest up and shoulders back, engage your core, and slightly bend your knees.","Pull your body up by flexing your elbows and driving your elbows down towards your sides.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"7OeHptV"},{"id":"edb-1432","name":"מתח בעמידה בסיוע","name_en":"assisted standing pull-up","muscle":"back","equipment":"leverage machine","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["כווננו את המכונה להגדרות המשקל והגובה הרצויים.","עמדו מול המכונה עם הרגליים ברוחב הכתפיים.","אחזו בידיות באחיזה עליונה, ברוחב מעט גדול מרוחב הכתפיים.","הפעילו את שרירי הגב הרחבים והביצפס, ומשכו את עצמכם כלפי מעלה לכיוון הידיות.","עצרו לרגע בשיא התנועה, תוך כיווץ שרירי הגב.","הורידו את עצמכם לאט בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the machine to your desired weight and height settings.","Stand facing the machine with your feet shoulder-width apart.","Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.","Engage your lats and biceps, and pull yourself up towards the handles.","Pause for a moment at the top, squeezing your back muscles.","Slowly lower yourself back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"f4xtKBj"},{"id":"edb-0018","name":"פשיטת מרפק בעמידה בסיוע","name_en":"assisted standing triceps extension (with towel)","muscle":"triceps","equipment":"assisted","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו במגבת בשתי הידיים מאחורי הראש.","שמרו על המרפקים קרוב לאוזניים ועל הזרועות העליונות נייחות.","יַשרו לאט את האמות כלפי מעלה, תוך כיווץ שרירי הטריצפס בשיא התנועה.","עצרו לרגע, ולאחר מכן הורידו לאט את המגבת בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a towel with both hands behind your head.","Keep your elbows close to your ears and your upper arms stationary.","Slowly extend your forearms upward, squeezing your triceps at the top.","Pause for a moment, then slowly lower the towel back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"7HcfMBP"},{"id":"edb-0019","name":"מקבילים בכריעה בסיוע","name_en":"assisted triceps dip (kneeling)","muscle":"triceps","equipment":"leverage machine","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["כווננו את המכונה למשקל ולגובה הרצויים.","כרעו על הכרית מול המכונה, כשהידיים אוחזות בידיות.","הורידו את הגוף על ידי כיפוף המרפקים, תוך שמירה על גב ישר וקרוב למכונה.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו את עצמכם בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the machine to your desired weight and height.","Kneel down on the pad facing the machine, with your hands gripping the handles.","Lower your body by bending your elbows, keeping your back straight and close to the machine.","Pause for a moment at the bottom, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"J60bN17"},{"id":"edb-2364","name":"מקבילים אחיזה רחבה בכריעה בסיוע","name_en":"assisted wide-grip chest dip (kneeling)","muscle":"chest","equipment":"leverage machine","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["כווננו את המכונה לגובה הרצוי ואבטחו את הברכיים על הכרית.","אחזו בידיות באחיזה רחבה ושמרו על המרפקים כפופים מעט.","הורידו את הגוף על ידי כיפוף המרפקים עד שהזרועות מקבילות לרצפה.","דחפו את עצמכם בחזרה לעמדת ההתחלה על ידי יישור הידיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the machine to your desired height and secure your knees on the pad.","Grasp the handles with a wide grip and keep your elbows slightly bent.","Lower your body by bending your elbows until your upper arms are parallel to the floor.","Push yourself back up to the starting position by extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"PnZJIrk"},{"id":"edb-3220","name":"astride jumps (male)","name_en":"astride jumps (male)","muscle":"core","equipment":"body weight","target":"cardiovascular system","bodyPart":"cardio","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים.","כופפו את הברכיים והורידו את הגוף לתנוחת סקוואט.","קפצו בפיצוץ כלפי מעלה, תוך יישור הרגליים והידיים.","באוויר, פשקו את הרגליים והוציאו את הידיים הצידה.","נחתו ברכות עם הרגליים ברוחב הכתפיים, תוך כיפוף הברכיים לספיגת הזעזוע.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart.","Bend your knees and lower your body into a squat position.","Jump explosively upwards, extending your legs and arms.","While in the air, spread your legs apart and bring your arms out to the sides.","Land softly with your feet shoulder-width apart, bending your knees to absorb the impact.","Repeat for the desired number of repetitions."],"mediaId":"f9lVSSI"},{"id":"edb-3672","name":"back and forth step","name_en":"back and forth step","muscle":"core","equipment":"body weight","target":"cardiovascular system","bodyPart":"cardio","secondaryMuscles":["quadriceps","hamstrings","glutes","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים.","צעדו קדימה עם הרגל הימנית, כופפו את הברך והורידו את הגוף לתנוחת לאנג'.","דחפו עם הרגל הימנית וחזרו לעמדת ההתחלה.","חזרו על התנועה עם הרגל השמאלית, תוך החלפת רגליים בכל צעד.","המשיכו לצעוד קדימה ואחורה, תוך שמירה על קצב קבוע.","חזרו למשך הזמן או מספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart.","Step forward with your right foot, bending your knee and lowering your body into a lunge position.","Push off with your right foot and step back to the starting position.","Repeat the movement with your left foot, alternating legs with each step.","Continue stepping back and forth, maintaining a steady pace.","Repeat for the desired duration or number of repetitions."],"mediaId":"fNGumX0"},{"id":"edb-1314","name":"פשיטת גב","name_en":"back extension on exercise ball","muscle":"back","equipment":"stability ball","target":"spine","bodyPart":"back","secondaryMuscles":["glutes","hamstrings"],"steps":["הניחו את כדור הפיזיו על הרצפה ושכבו עליו על הבטן, כשהירכיים נשענות על הכדור וכפות הרגליים נשענות על קיר או משטח יציב אחר.","הניחו את הידיים מאחורי הראש או משוכלות על החזה.","הפעילו את ליבת הגוף והרימו לאט את פלג הגוף העליון מהכדור, תוך יישור הגב עד שהגוף יוצר קו ישר מהראש ועד העקבים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Place the stability ball on the ground and lie face down on top of it, with your hips resting on the ball and your feet against a wall or other stable surface.","Position your hands behind your head or crossed over your chest.","Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line from your head to your heels.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"qLpO4vV"},{"id":"edb-3297","name":"back lever","name_en":"back lever","muscle":"back","equipment":"body weight","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms","core"],"steps":["התחילו בתלייה ממתקן מתח באחיזה עליונה, כשהידיים ברוחב מעט גדול מרוחב הכתפיים.","הפעילו את ליבת הגוף ומשכו את השכמות מטה ואחורה.","כופפו את הברכיים וקרבו אותן לכיוון החזה.","הרימו לאט את הרגליים, תוך שמירה עליהן ישרות, עד שהגוף מקביל לרצפה.","החזיקו בתנוחה זו למספר שניות, ולאחר מכן הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by hanging from a pull-up bar with an overhand grip, hands slightly wider than shoulder-width apart.","Engage your core and pull your shoulder blades down and back.","Bend your knees and tuck them towards your chest.","Slowly lift your legs up, keeping them straight, until your body is parallel to the ground.","Hold this position for a few seconds, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"GaSzzuh"},{"id":"edb-1405","name":"מתיחה","name_en":"back pec stretch","muscle":"back","equipment":"body weight","target":"lats","bodyPart":"back","secondaryMuscles":["shoulders","chest"],"steps":["עמדו זקוף עם הרגליים ברוחב הכתפיים.","הושיטו את הידיים ישר לפניכם, במקביל לרצפה.","שלבו את הידיים מול הגוף, כשהיד הימנית מעל היד השמאלית.","שלבו את האצבעות וסובבו את כפות הידיים הרחק מהגוף.","הרימו לאט את הידיים כלפי מעלה והרחק מהגוף, תוך הרגשת מתיחה בגב ובחזה.","החזיקו את המתיחה במשך 15-30 שניות, ולאחר מכן שחררו.","חזרו על התרגיל בצד הנגדי."],"steps_en":["Stand tall with your feet shoulder-width apart.","Extend your arms straight out in front of you, parallel to the ground.","Cross your arms in front of your body, with your right arm over your left arm.","Interlock your fingers and rotate your palms away from your body.","Slowly raise your arms up and away from your body, feeling a stretch in your back and chest.","Hold the stretch for 15-30 seconds, then release.","Repeat on the opposite side."],"mediaId":"chfnQnM"},{"id":"edb-1473","name":"backward jump","name_en":"backward jump","muscle":"legs","equipment":"body weight","target":"quads","bodyPart":"upper legs","secondaryMuscles":["hamstrings","glutes","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים.","כופפו מעט את הברכיים וקפצו לאחור, תוך דחיפה עם שתי כפות הרגליים.","נחתו ברכות על כריות כפות הרגליים, תוך כיפוף הברכיים לספיגת הזעזוע.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart.","Bend your knees slightly and jump backwards, pushing off with both feet.","Land softly on the balls of your feet, bending your knees to absorb the impact.","Repeat for the desired number of repetitions."],"mediaId":"SaDOwk7"},{"id":"edb-0020","name":"balance board","name_en":"balance board","muscle":"legs","equipment":"body weight","target":"quads","bodyPart":"upper legs","secondaryMuscles":["calves","hamstrings","glutes"],"steps":["הניחו את לוח השיווי משקל על משטח שטוח.","עלו על לוח השיווי משקל עם רגל אחת, תוך ודוא שהוא ממורכז.","העבירו לאט את משקל הגוף לכף הרגל שעל לוח השיווי משקל, תוך שמירה על ליבת הגוף מופעלת.","שמרו על שיווי המשקל והיציבות תוך החזקת התנוחה למשך הזמן הרצוי.","חזרו על התרגיל עם הרגל השנייה."],"steps_en":["Place the balance board on a flat surface.","Step onto the balance board with one foot, ensuring it is centered.","Slowly shift your weight onto the foot on the balance board, keeping your core engaged.","Maintain your balance and stability as you hold the position for a desired amount of time.","Repeat the exercise with the other foot."],"mediaId":"xAySMB0"},{"id":"edb-0968","name":"כפיפת מרפק לסירוגין עם גומייה","name_en":"band alternating biceps curl","muscle":"biceps","equipment":"band","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו בגומייה באחיזה תחתית, כשכפות הידיים פונות למעלה.","שמרו על המרפקים קרוב לצדדים וכופפו לאט יד אחת כלפי מעלה לכיוון הכתף, תוך כיווץ הביצפס בשיא התנועה.","הורידו את היד בחזרה לעמדת ההתחלה וחזרו עם היד השנייה.","המשיכו להחליף ידיים למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold the band with an underhand grip, palms facing up.","Keep your elbows close to your sides and slowly curl one arm up towards your shoulder, squeezing your biceps at the top.","Lower the arm back down to the starting position and repeat with the other arm.","Continue alternating arms for the desired number of repetitions."],"mediaId":"3omWx6P"},{"id":"edb-0969","name":"band alternating v-up","name_en":"band alternating v-up","muscle":"core","equipment":"band","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שכבו על הגב עם הרגליים ישרות והידיים מושטות מעל הראש, כשהן אוחזות בגומייה.","הפעילו את שרירי הבטן והרימו את הרגליים ואת פלג הגוף העליון מהרצפה בו-זמנית, תוך הושטת הידיים לכיוון האצבעות.","תוך כדי הורדת הרגליים ופלג הגוף העליון בחזרה, החליפו את מיקום הרגליים, כשאחת חוצה מעל השנייה.","חזרו על התנועה, תוך החלפת מיקום הרגליים בכל חזרה.","המשיכו למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your legs straight and your arms extended overhead, holding the band.","Engage your abs and lift your legs and upper body off the ground simultaneously, reaching your hands towards your toes.","As you lower your legs and upper body back down, switch the position of your legs, crossing one over the other.","Repeat the movement, alternating the position of your legs with each repetition.","Continue for the desired number of repetitions."],"mediaId":"ztAa1RK"},{"id":"edb-0970","name":"מתח עם גומייה","name_en":"band assisted pull-up","muscle":"back","equipment":"band","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["חברו את הגומייה למתקן מתח או לנקודת עיגון יציבה.","עמדו על הגומייה ואחזו במוט כשכפות הידיים פונות הרחק מכם, בידיים ברוחב מעט גדול מרוחב הכתפיים.","התלו כשהידיים מיושרות לגמרי, תוך שמירה על ליבת הגוף מופעלת והכתפיים למטה ואחורה.","משכו את הגוף כלפי מעלה לכיוון המוט על ידי כיווץ השכמות זו לזו והורדת המרפקים לכיוון הירכיים.","המשיכו למשוך עד שהסנטר מעל המוט, ולאחר מכן הורידו את עצמכם לאט בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach the band to a pull-up bar or sturdy anchor point.","Step onto the band and grip the bar with your palms facing away from you, hands slightly wider than shoulder-width apart.","Hang with your arms fully extended, keeping your core engaged and your shoulders down and back.","Pull your body up towards the bar by squeezing your shoulder blades together and driving your elbows down towards your hips.","Continue pulling until your chin is above the bar, then slowly lower yourself back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"r1XNRYB"},{"id":"edb-0971","name":"band assisted wheel rollerout","name_en":"band assisted wheel rollerout","muscle":"core","equipment":"band","target":"abs","bodyPart":"waist","secondaryMuscles":["lower back"],"steps":["כרעו על הרצפה ואחזו בידיות הגומייה בשתי הידיים, כשכפות הידיים פונות מטה.","הניחו את הגומייה על הרצפה לפניכם ומקמו את הידיים ברוחב הכתפיים.","הפעילו את ליבת הגוף וגלגלו לאט את הגלגלת קדימה, תוך יישור הגוף רחוק ככל האפשר תוך שמירה על שליטה.","עצרו לרגע בנקודה הרחוקה ביותר, ולאחר מכן גלגלו לאט את הגלגלת בחזרה לכיוון הברכיים כדי לחזור לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Kneel on the floor and hold the handles of the band with both hands, palms facing down.","Place the band on the ground in front of you and position your hands shoulder-width apart.","Engage your core and slowly roll the wheel forward, extending your body as far as you can while maintaining control.","Pause for a moment at the furthest point, then slowly roll the wheel back towards your knees to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"zhF9lW4"},{"id":"edb-1254","name":"לחיצת חזה עם גומייה","name_en":"band bench press","muscle":"chest","equipment":"band","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["שכבו על ספסל כשכפות הרגליים שטוחות על הרצפה והגב צמוד לספסל.","אחזו בידיות הגומייה באחיזה עליונה, ברוחב מעט גדול מרוחב הכתפיים.","יַשרו את הידיים לגמרי, תוך דחיפת הגומיות הרחק מהחזה.","הורידו לאט את הגומיות בחזרה לכיוון החזה, תוך שמירה על המרפקים בזווית של 90 מעלות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the band handles with an overhand grip, slightly wider than shoulder-width apart.","Extend your arms fully, pushing the bands away from your chest.","Slowly lower the bands back down to your chest, keeping your elbows at a 90-degree angle.","Repeat for the desired number of repetitions."],"mediaId":"khlHMqs"},{"id":"edb-0980","name":"פשיטה בהטיה עם גומייה","name_en":"band bent-over hip extension","muscle":"glutes","equipment":"band","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","lower back"],"steps":["חברו את הגומייה לנקודת עיגון יציבה בגובה הקרסול.","עמדו כשגבכם לנקודת העיגון, עם הרגליים ברוחב הכתפיים.","צעדו לאחור כדי ליצור מתח בגומייה, תוך שמירה על הברכיים כפופות מעט.","כופפו במפרקי הירך והטו את הגוף קדימה, תוך שמירה על עמוד שדרה ניטרלי.","הושיטו את הרגל הימנית ישר לאחור, תוך כיווץ שרירי הישבן בשיא התנועה.","הורידו את הרגל הימנית בחזרה וחזרו עם הרגל השמאלית.","המשיכו להחליף רגליים למספר החזרות הרצוי."],"steps_en":["Attach the band to a sturdy anchor point at ankle height.","Stand facing away from the anchor point with your feet shoulder-width apart.","Step back to create tension in the band, keeping your knees slightly bent.","Hinge at the hips and lean forward, maintaining a neutral spine.","Extend your right leg straight back, squeezing your glutes at the top.","Lower your right leg back down and repeat with the left leg.","Continue alternating legs for the desired number of repetitions."],"mediaId":"wSScovH"},{"id":"edb-0972","name":"כפיפת בטן עם גומייה","name_en":"band bicycle crunch","muscle":"core","equipment":"band","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors","obliques"],"steps":["שכבו על הגב עם הידיים מאחורי הראש והברכיים כפופות.","הרימו את כפות הרגליים מהרצפה וקרבו את הברך הימנית לכיוון החזה, תוך סיבוב הגו בו-זמנית כדי לקרב את המרפק השמאלי לברך הימנית.","יַשרו את הרגל הימנית תוך קירוב הברך השמאלית לכיוון החזה וסיבוב הגו כדי לקרב את המרפק הימני לברך השמאלית.","המשיכו להחליף בתנועת הסיבוב, כאילו אתם מדוושים על אופניים, תוך שמירה על ליבת הגוף מופעלת לאורך כל התנועה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your hands behind your head and your knees bent.","Lift your feet off the ground and bring your right knee towards your chest while simultaneously twisting your torso to bring your left elbow towards your right knee.","Straighten your right leg while bringing your left knee towards your chest and twisting your torso to bring your right elbow towards your left knee.","Continue alternating the twisting motion, as if you are pedaling a bicycle, while keeping your core engaged throughout the movement.","Repeat for the desired number of repetitions."],"mediaId":"tZkGYZ9"},{"id":"edb-0974","name":"משיכת פולי אחיזה צרה עם גומייה","name_en":"band close-grip pulldown","muscle":"back","equipment":"band","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["חברו את הגומייה לנקודת עיגון גבוהה, כגון מתקן מתח או קורה יציבה.","עמדו מול נקודת העיגון ואחזו בגומייה באחיזה תחתית, כשהידיים ברוחב הכתפיים.","צעדו לאחור כדי ליצור מתח בגומייה, תוך שמירה על הרגליים ברוחב הירכיים.","הפעילו את ליבת הגוף ושמרו על גב ישר תוך משיכת הגומייה כלפי מטה לכיוון החזה, תוך כיווץ השכמות זו לזו.","עצרו לרגע בתחתית התנועה, ולאחר מכן שחררו לאט את הגומייה בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach the band to a high anchor point, such as a pull-up bar or sturdy beam.","Stand facing the anchor point and grab the band with an underhand grip, hands shoulder-width apart.","Step back to create tension in the band, keeping your feet hip-width apart.","Engage your core and keep your back straight as you pull the band down towards your chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the band back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"DptumMx"},{"id":"edb-0975","name":"שכיבת סמיכה אחיזה צרה עם גומייה","name_en":"band close-grip push-up","muscle":"triceps","equipment":"band","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["הניחו גומייה סביב הזרועות העליונות, ממש מעל המרפקים.","היכנסו לתנוחת שכיבת סמיכה כשהידיים ישר מתחת לכתפיים והגוף יוצר קו ישר מהראש ועד העקבים.","כופפו את המרפקים והורידו את החזה לכיוון הרצפה, תוך שמירה על המרפקים קרוב לצדדים.","דחפו דרך כפות הידיים כדי ליישר את הידיים ולחזור לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Place a band around your upper arms, just above the elbows.","Assume a push-up position with your hands directly under your shoulders and your body in a straight line from head to heels.","Bend your elbows and lower your chest towards the ground, keeping your elbows close to your sides.","Push through your palms to extend your arms and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ufaxB52"},{"id":"edb-0976","name":"כפיפת מרפק עם גומייה","name_en":"band concentration curl","muscle":"biceps","equipment":"band","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל או כיסא עם הרגליים פשוקות וכפות הרגליים שטוחות על הרצפה.","אחזו בקצה אחד של הגומייה ביד ודרכו על הקצה השני עם הרגל באותו צד.","הטו את הגוף מעט קדימה והניחו את המרפק על פנים הירך, ממש מעל הברך.","כשכף היד פונה למעלה, כופפו לאט את היד לכיוון הכתף, תוך שמירה על הזרוע העליונה נייחת.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את היד בחזרה לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Sit on a bench or chair with your legs spread apart and your feet flat on the ground.","Hold one end of the band in your hand and step on the other end with your foot on the same side.","Lean forward slightly and rest your elbow on the inside of your thigh, just above the knee.","With your palm facing up, slowly curl your hand towards your shoulder, keeping your upper arm stationary.","Pause for a moment at the top, then slowly lower your hand back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"kmVVAfu"},{"id":"edb-3117","name":"משיכת פולי אחיזה צרה עם גומייה","name_en":"band fixed back close grip pulldown","muscle":"back","equipment":"band","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["חברו את הגומייה לנקודה קבועה מעליכם, כגון מתקן מתח או קורה יציבה.","שבו על ספסל או כיסא מול הגומייה, כשכפות הרגליים שטוחות על הרצפה והברכיים כפופות.","אחזו בגומייה באחיזה צרה, כשכפות הידיים פונות אליכם.","שמרו על גב ישר והפעילו את ליבת הגוף.","משכו את הגומייה כלפי מטה לכיוון החזה, תוך כיווץ השכמות זו לזו.","עצרו לרגע בתחתית התנועה, תוך הרגשת הכיווץ בשרירי הגב הרחבים.","שחררו לאט את הגומייה בחזרה לעמדת ההתחלה, תוך שמירה על שליטה לאורך כל התנועה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach the band to a fixed point above you, such as a pull-up bar or sturdy beam.","Sit down on a bench or chair facing the band, with your feet flat on the ground and your knees bent.","Grasp the band with a close grip, palms facing towards you.","Keep your back straight and engage your core.","Pull the band down towards your chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, feeling the contraction in your lats.","Slowly release the band back to the starting position, maintaining control throughout the movement.","Repeat for the desired number of repetitions."],"mediaId":"4LoWllp"},{"id":"edb-3116","name":"משיכת פולי עם גומייה","name_en":"band fixed back underhand pulldown","muscle":"back","equipment":"band","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","rhomboids","rear deltoids"],"steps":["חברו את הגומייה לנקודת עיגון יציבה מעל הראש.","עמדו מול נקודת העיגון עם הרגליים ברוחב הכתפיים.","אחזו בגומייה באחיזה תחתית, בידיים ברוחב מעט גדול מרוחב הכתפיים.","צעדו לאחור כדי ליצור מתח בגומייה, תוך שמירה על הידיים מיושרות לגמרי.","הפעילו את ליבת הגוף וכווצו את השכמות זו לזו.","משכו את הגומייה כלפי מטה לכיוון החזה, תוך הובלת התנועה עם המרפקים.","עצרו לרגע בתחתית התנועה, תוך הרגשת הכיווץ בשרירי הגב הרחבים.","שחררו לאט את המתח בגומייה וחזרו לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach the band to a sturdy anchor point above your head.","Stand facing the anchor point with your feet shoulder-width apart.","Grasp the band with an underhand grip, hands slightly wider than shoulder-width apart.","Step back to create tension in the band, keeping your arms fully extended.","Engage your core and squeeze your shoulder blades together.","Pull the band down towards your chest, leading with your elbows.","Pause for a moment at the bottom of the movement, feeling the contraction in your lats.","Slowly release the tension in the band and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ZH68exZ"},{"id":"edb-0977","name":"הרחקת כתפיים לצדדים קדמי עם גומייה","name_en":"band front lateral raise","muscle":"shoulders","equipment":"band","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","upper back"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו בגומייה מול הירכיים כשכפות הידיים פונות מטה.","שמרו על הידיים ישרות והרימו את הגומייה לפניכם עד שהידיים מקבילות לרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הגומייה בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold the band in front of your thighs with your palms facing down.","Keep your arms straight and lift the band up in front of you until your arms are parallel to the ground.","Pause for a moment at the top, then slowly lower the band back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"sTg7iys"},{"id":"edb-0978","name":"הרמה קדמית עם גומייה","name_en":"band front raise","muscle":"shoulders","equipment":"band","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו בגומייה מול הירכיים כשכפות הידיים פונות מטה.","שמרו על הידיים ישרות והרימו אותן לאט קדימה עד שהן מקבילות לרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הידיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold the band in front of your thighs with your palms facing down.","Keep your arms straight and slowly raise them forward until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"TFA88iB"},{"id":"edb-1408","name":"band hip lift","name_en":"band hip lift","muscle":"glutes","equipment":"band","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו גומיית התנגדות ממש מעל הברכיים.","הפעילו את שרירי הישבן וליבת הגוף.","לחצו את העקבים לתוך הרצפה והרימו את הירכיים מהרצפה, תוך כיווץ שרירי הישבן בשיא התנועה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הירכיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie on your back with your knees bent and feet flat on the ground.","Place a resistance band just above your knees.","Engage your glutes and core muscles.","Press your heels into the ground and lift your hips off the floor, squeezing your glutes at the top.","Pause for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"E4R8Hz1"},{"id":"edb-0979","name":"לחיצה עם גומייה","name_en":"band horizontal pallof press","muscle":"core","equipment":"band","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","glutes"],"steps":["חברו את הגומייה לנקודת עיגון יציבה בגובה המותניים.","עמדו בניצב לנקודת העיגון עם הרגליים ברוחב הכתפיים.","אחזו בידית הגומייה בשתי הידיים והתרחקו מנקודת העיגון כדי ליצור מתח בגומייה.","קרבו את הידיים לחזה, תוך שמירה על המרפקים כפופים וקרובים לגוף.","הפעילו את ליבת הגוף ושמרו על עמידה יציבה.","הושיטו את הידיים ישר לפניכם, תוך דחיפת הגומייה הרחק מהגוף.","החזיקו בתנוחה המושטת למספר שניות, תוך התמקדות בשמירה על מתח בליבת הגוף.","קרבו לאט את הידיים בחזרה לחזה, תוך התנגדות למשיכת הגומייה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach the band to a sturdy anchor point at waist height.","Stand perpendicular to the anchor point with your feet shoulder-width apart.","Grasp the band handle with both hands and step away from the anchor point to create tension in the band.","Bring your hands to your chest, keeping your elbows bent and close to your body.","Engage your core and maintain a stable stance.","Extend your arms straight out in front of you, pushing the band away from your body.","Hold the extended position for a few seconds, focusing on maintaining tension in your core.","Slowly bring your hands back to your chest, resisting the pull of the band.","Repeat for the desired number of repetitions."],"mediaId":"9pa4H5m"},{"id":"edb-0981","name":"כפיפת בטן מלאה עם גומייה","name_en":"band jack knife sit-up","muscle":"core","equipment":"band","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שכבו על הגב עם הרגליים ישרות והידיים מושטות מעל הראש, כשהן אוחזות בגומייה.","הפעילו את שרירי הבטן והרימו את הרגליים ואת פלג הגוף העליון בו-זמנית, תוך קירוב הידיים לכיוון הרגליים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגליים ואת פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your legs straight and your arms extended overhead, holding the band.","Engage your abs and lift your legs and upper body simultaneously, bringing your hands towards your feet.","Pause for a moment at the top, then slowly lower your legs and upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"KCBKjma"},{"id":"edb-0983","name":"משיכת פולי ביד אחת בכריעה עם גומייה","name_en":"band kneeling one arm pulldown","muscle":"back","equipment":"band","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","rhomboids"],"steps":["חברו את הגומייה לנקודת עיגון יציבה מעל הראש.","כרעו ואחזו בגומייה ביד אחת, כשכף היד פונה מטה.","הושיטו את היד לגמרי מעל הראש, תוך שמירה על המרפק כפוף מעט.","הפעילו את שרירי הגב הרחבים ומשכו את הגומייה כלפי מטה לכיוון הצד, תוך קירוב המרפק לבית החזה.","עצרו לרגע בתחתית התנועה, ולאחר מכן שחררו לאט את המתח וחזרו לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Attach the band to a sturdy anchor point above your head.","Kneel down and hold the band with one hand, palm facing down.","Extend your arm fully overhead, keeping your elbow slightly bent.","Engage your lat muscles and pull the band down towards your side, bringing your elbow towards your ribcage.","Pause for a moment at the bottom, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"pmnrOp0"},{"id":"edb-0985","name":"כפיפת בטן בכריעה עם גומייה","name_en":"band kneeling twisting crunch","muscle":"core","equipment":"band","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques"],"steps":["חברו את הגומייה לנקודת עיגון יציבה בגובה המותניים.","כרעו כשגבכם לנקודת העיגון ואחזו בגומייה בשתי הידיים, תוך שמירה על המרפקים כפופים וקרובים לצדדים.","הפעילו את שרירי הבטן וסובבו לאט את הגו לצד אחד, תוך קירוב הידיים לירך הנגדית.","עצרו לרגע, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו על התרגיל בצד השני.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Attach the band to a sturdy anchor point at waist height.","Kneel down facing away from the anchor point and hold the band with both hands, keeping your elbows bent and close to your sides.","Engage your abs and slowly twist your torso to one side, bringing your hands towards your opposite hip.","Pause for a moment, then slowly return to the starting position.","Repeat on the other side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"225x2Vd"},{"id":"edb-0984","name":"band lying hip internal rotation","name_en":"band lying hip internal rotation","muscle":"glutes","equipment":"band","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps"],"steps":["שכבו על הגב עם הרגליים ישרות וגומיית התנגדות כרוכה סביב כפות הרגליים.","כופפו את הברכיים וקרבו אותן לכיוון החזה, תוך שמירה על כפות הרגליים צמודות.","סובבו לאט את הברכיים החוצה, זו מזו, תוך שמירה על כפות הרגליים צמודות.","עצרו לרגע בסוף הסיבוב, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie on your back with your legs straight and a resistance band looped around your feet.","Bend your knees and bring them towards your chest, keeping your feet together.","Slowly rotate your knees outwards, away from each other, while keeping your feet together.","Pause for a moment at the end of the rotation, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"vIICElP"},{"id":"edb-1002","name":"הרמת רגליים בשכיבה עם גומייה","name_en":"band lying straight leg raise","muscle":"core","equipment":"band","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שכבו על הגב עם הרגליים ישרות וכפות הרגליים צמודות.","הניחו את הגומייה סביב קשתות כפות הרגליים ואחזו בקצוות הגומייה בידיים.","תוך הפעלת שרירי הבטן, הרימו את שתי הרגליים מהרצפה עד שהן ניצבות אליה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your legs straight and your feet together.","Place the band around the arches of your feet and hold the ends of the band with your hands.","Engaging your abs, lift both legs off the ground until they are perpendicular to the floor.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"bbLR7fB"},{"id":"edb-0986","name":"כפיפת מרפק ביד אחת מעל הראש עם גומייה","name_en":"band one arm overhead biceps curl","muscle":"biceps","equipment":"band","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms","shoulders"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והניחו קצה אחד של הגומייה מתחת לכף הרגל.","אחזו בקצה השני של הגומייה כשהיד מיושרת לגמרי מעל הראש וכף היד פונה קדימה.","תוך שמירה על הזרוע העליונה נייחת, כופפו את האמה לכיוון הכתף, תוך כיווץ הביצפס.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את האמה בחזרה לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Stand with your feet shoulder-width apart and place one end of the band under your foot.","Hold the other end of the band with your arm fully extended overhead, palm facing forward.","Keeping your upper arm stationary, curl your forearm towards your shoulder, squeezing your biceps.","Pause for a moment at the top, then slowly lower your forearm back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"UNAB8ak"},{"id":"edb-0987","name":"סקוואט מפוצל ביד אחת ברגל אחת עם גומייה","name_en":"band one arm single leg split squat","muscle":"legs","equipment":"band","target":"quads","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings"],"steps":["עמדו עם הרגליים ברוחב הירכיים והניחו גומיית התנגדות סביב הקרסוליים.","הושיטו רגל אחת קדימה והניחו את גב כף הרגל על ספסל או מדרגה מאחוריכם.","אחזו במשענת ביד אחת לשם שיווי משקל.","כופפו את רגל התמיכה והורידו את הגוף לתנוחת סקוואט, תוך שמירה על הברך בקו אחד עם האצבעות.","דחפו דרך העקב כדי לחזור לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו רגליים."],"steps_en":["Stand with your feet hip-width apart and place a resistance band around your ankles.","Extend one leg forward and rest the top of your foot on a bench or step behind you.","Hold onto a support with one hand for balance.","Bend your standing leg and lower your body down into a squat position, keeping your knee in line with your toes.","Push through your heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"mediaId":"arsYEd3"},{"id":"edb-0988","name":"חתירה ביד אחת בעמידה נמוך עם גומייה","name_en":"band one arm standing low row","muscle":"back","equipment":"band","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","shoulders"],"steps":["חברו את הגומייה לנקודת עיגון יציבה בגובה המותניים.","עמדו מול נקודת העיגון עם הרגליים ברוחב הכתפיים.","אחזו בגומייה ביד אחת, כשכף היד פונה פנימה, וצעדו לאחור כדי ליצור מתח בגומייה.","כופפו מעט את הברכיים והטו את הגוף קדימה במפרקי הירך, תוך שמירה על גב ישר.","משכו את הגומייה לכיוון המותניים, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה, ולאחר מכן שחררו לאט את הגומייה בחזרה לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Attach the band to a stable anchor point at waist height.","Stand facing the anchor point with your feet shoulder-width apart.","Hold the band with one hand, palm facing inward, and step back to create tension in the band.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Pull the band towards your waist, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly release the band back to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"km0sQC0"},{"id":"edb-0989","name":"לחיצת חזה ביד אחת עם גומייה","name_en":"band one arm twisting chest press","muscle":"chest","equipment":"band","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["חברו את הגומייה לנקודת עיגון יציבה בגובה החזה.","עמדו כשהצד שלכם פונה לנקודת העיגון ואחזו בגומייה ביד אחת.","התרחקו מנקודת העיגון כדי ליצור מתח בגומייה.","מקמו את הרגליים ברוחב הכתפיים וכופפו מעט את הברכיים.","קרבו את היד האוחזת בגומייה על פני הגוף, לכיוון הכתף הנגדית.","תוך שמירה על מתח בגומייה, דחפו את היד קדימה והרחק מהגוף, תוך יישור הזרוע.","חזרו לאט לעמדת ההתחלה וחזרו למספר החזרות הרצוי.","החליפו צדדים וחזרו על התרגיל עם היד השנייה."],"steps_en":["Attach the band to a sturdy anchor point at chest height.","Stand with your side facing the anchor point and grab the band with one hand.","Step away from the anchor point to create tension in the band.","Position your feet shoulder-width apart and slightly bend your knees.","Bring your hand holding the band across your body, towards the opposite shoulder.","While maintaining tension in the band, push your hand forward and away from your body, extending your arm.","Slowly return to the starting position and repeat for the desired number of repetitions.","Switch sides and repeat the exercise with the other hand."],"mediaId":"c16nYGA"},{"id":"edb-0990","name":"חתירה ביד אחת בישיבה עם גומייה","name_en":"band one arm twisting seated row","muscle":"back","equipment":"band","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","shoulders"],"steps":["שבו על ספסל או כיסא כשכפות הרגליים שטוחות על הרצפה והגב ישר.","אחזו בגומייה ביד אחת והושיטו את הזרוע לגמרי לפניכם.","תוך שמירה על גב ישר, משכו את הגומייה לכיוון הגוף על ידי כיפוף המרפק וכיווץ השכמות זו לזו.","בו-זמנית, סובבו את הגו לכיוון הצד של היד המושכת.","עצרו לרגע בשיא התנועה, ולאחר מכן שחררו לאט את המתח בגומייה וחזרו לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ליד השנייה."],"steps_en":["Sit on a bench or chair with your feet flat on the ground and your back straight.","Hold the band with one hand and extend your arm fully in front of you.","Keeping your back straight, pull the band towards your body by bending your elbow and squeezing your shoulder blades together.","At the same time, twist your torso towards the side of the pulling arm.","Pause for a moment at the top, then slowly release the tension in the band and return to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"mediaId":"DKBwJrL"},{"id":"edb-0991","name":"band pull through","name_en":"band pull through","muscle":"glutes","equipment":"band","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","lower back"],"steps":["חברו גומיית התנגדות לנקודת עיגון יציבה בגובה הרצפה.","עמדו כשגבכם לנקודת העיגון, עם הרגליים ברוחב הכתפיים.","צעדו קדימה כדי ליצור מתח בגומייה, תוך שמירה על הברכיים כפופות מעט.","כופפו במפרקי הירך ודחפו את הישבן לאחור, תוך שמירה על כיפוף קל בברכיים.","הורידו את הגו עד שהוא מקביל לרצפה, תוך הרגשת מתיחה בשרירי הירך האחוריים.","דחפו את הירכיים קדימה וכווצו את שרירי הישבן כדי לחזור לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a resistance band to a sturdy anchor point at ground level.","Stand facing away from the anchor point with your feet shoulder-width apart.","Step forward to create tension in the band, keeping your knees slightly bent.","Hinge at the hips and push your glutes back, maintaining a slight bend in your knees.","Lower your torso until it is parallel to the ground, feeling a stretch in your hamstrings.","Drive your hips forward and squeeze your glutes to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"VtTbiP3"},{"id":"edb-0992","name":"כפיפת בטן מלאה עם גומייה","name_en":"band push sit-up","muscle":"core","equipment":"band","target":"abs","bodyPart":"waist","secondaryMuscles":["shoulders","chest"],"steps":["חברו את הגומייה באופן בטוח לנקודת עיגון יציבה.","שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","אחזו בגומייה בשתי הידיים והושיטו את הידיים ישר כלפי מעלה לכיוון התקרה.","תוך הפעלת שרירי הבטן, הרימו לאט את פלג הגוף העליון מהרצפה, בכיפוף קדימה עד שהגו נמצא בזווית של 45 מעלות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach the band securely to a stable anchor point.","Lie flat on your back with your knees bent and feet flat on the ground.","Hold the band with both hands and extend your arms straight up towards the ceiling.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"zFzbBfL"},{"id":"edb-0993","name":"פרפר הפוך עם גומייה","name_en":"band reverse fly","muscle":"shoulders","equipment":"band","target":"delts","bodyPart":"shoulders","secondaryMuscles":["upper back","trapezius"],"steps":["חברו את הגומייה לעצם נייח בגובה החזה.","עמדו עם הרגליים ברוחב הכתפיים ואחזו בגומייה בשתי הידיים לפניכם.","שמרו על הידיים ישרות והרימו אותן הצידה עד שהן מקבילות לרצפה.","כווצו את השכמות זו לזו בשיא התנועה.","הורידו לאט את הידיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach the band to a stationary object at chest height.","Stand with your feet shoulder-width apart and hold the band with both hands in front of you.","Keep your arms straight and lift them out to the sides until they are parallel to the ground.","Squeeze your shoulder blades together at the top of the movement.","Slowly lower your arms back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"sTfvVsG"},{"id":"edb-0994","name":"כפיפת שורש כף היד הפוך עם גומייה","name_en":"band reverse wrist curl","muscle":"biceps","equipment":"band","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל או כיסא כשכפות הרגליים שטוחות על הרצפה.","אחזו בגומייה באחיזה עליונה, כשכפות הידיים פונות מטה, וכרכו אותה סביב האצבעות.","הניחו את האמות על הירכיים, כשפרקי הידיים תלויים מעבר לקצה.","כופפו לאט את פרקי הידיים כלפי מעלה, תוך כיווץ האמות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פרקי הידיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench or chair with your feet flat on the ground.","Hold the band with an overhand grip, palms facing down, and wrap it around your fingers.","Rest your forearms on your thighs, with your wrists hanging off the edge.","Slowly curl your wrists upward, squeezing your forearms.","Pause for a moment at the top, then slowly lower your wrists back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Ezpnw9d"},{"id":"edb-0996","name":"band seated hip internal rotation","name_en":"band seated hip internal rotation","muscle":"glutes","equipment":"band","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps"],"steps":["שבו על כיסא או ספסל כשהגב ישר וכפות הרגליים שטוחות על הרצפה.","הניחו גומיית התנגדות סביב הירכיים, ממש מעל הברכיים.","שמרו על הברכיים כפופות בזווית של 90 מעלות והרגליים ברוחב הכתפיים.","הפעילו את שרירי הישבן וסובבו לאט את הברכיים החוצה, תוך דחיפה כנגד ההתנגדות של הגומייה.","עצרו לרגע בסוף התנועה, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a chair or bench with your back straight and feet flat on the ground.","Place a resistance band around your thighs, just above your knees.","Keep your knees bent at a 90-degree angle and your feet shoulder-width apart.","Engage your glutes and slowly rotate your knees outward, pushing against the resistance of the band.","Pause for a moment at the end of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"9gbyYKk"},{"id":"edb-1011","name":"פיתול בישיבה עם גומייה","name_en":"band seated twist","muscle":"core","equipment":"band","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques"],"steps":["שבו על הרצפה עם הרגליים מושטות לפניכם והגב ישר.","כרכו את הגומייה סביב המותניים ואחזו בקצוות בשתי הידיים.","הפעילו את שרירי הבטן וסובבו לאט את פלג הגוף העליון לצד אחד, תוך שמירה על גב ישר ורגליים על הרצפה.","עצרו לרגע בסוף הסיבוב, ולאחר מכן חזרו לאט למצב ההתחלתי.","חזרו על הסיבוב לצד השני.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Sit on the ground with your legs extended in front of you and your back straight.","Wrap the band around your waist and hold the ends with both hands.","Engage your abs and slowly twist your torso to one side, keeping your back straight and your feet on the ground.","Pause for a moment at the end of the twist, then slowly return to the starting position.","Repeat the twist to the other side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"S1JXDAG"},{"id":"edb-0997","name":"לחיצת כתפיים עם גומייה","name_en":"band shoulder press","muscle":"shoulders","equipment":"band","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והניחו את הגומייה מתחת לרגליים.","אחזו בגומייה כשכפות הידיים פונות קדימה והרימו את הידיים לגובה הכתפיים, עם מרפקים כפופים.","דחפו את הגומייה מעל הראש, תוך יישור מלא של הידיים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הגומייה בחזרה לגובה הכתפיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and place the band under your feet.","Hold the band with your palms facing forward and raise your hands to shoulder height, elbows bent.","Press the band overhead, fully extending your arms.","Pause for a moment at the top, then slowly lower the band back to shoulder height.","Repeat for the desired number of repetitions."],"mediaId":"peAeMR3"},{"id":"edb-1018","name":"משיכת כתפיים עם גומייה","name_en":"band shrug","muscle":"back","equipment":"band","target":"traps","bodyPart":"back","secondaryMuscles":["shoulders"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והניחו את הגומייה מתחת לרגליים, כשאתם אוחזים בקצוות בידיים.","שמרו על הידיים ישרות ורפויות, ותנו לגומייה להישאר תלויה מול הירכיים.","הפעילו את שרירי הטרפז על ידי הרמת הכתפיים כלפי מעלה, והרימו את הגומייה כמה שיותר גבוה.","החזיקו את הכיווץ לרגע, ולאחר מכן הורידו לאט את הכתפיים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and place the band under your feet, holding the ends with your hands.","Keep your arms straight and relaxed, and let the band hang in front of your thighs.","Engage your traps by shrugging your shoulders upward, lifting the band as high as possible.","Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"trmte8s"},{"id":"edb-0998","name":"פשיטת מרפק צדי עם גומייה","name_en":"band side triceps extension","muscle":"triceps","equipment":"band","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו בגומייה בשתי הידיים, כשכפות הידיים פונות מטה.","יישרו את הידיים החוצה לצדדים, במקביל לרצפה.","כופפו לאט את המרפקים והביאו את הידיים לכיוון הכתפיים, תוך שמירה על הזרוע העליונה ללא תזוזה.","עצרו לרגע, ולאחר מכן יישרו לאט את הידיים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold the band with both hands, palms facing down.","Extend your arms straight out to the sides, keeping them parallel to the ground.","Slowly bend your elbows and bring your hands towards your shoulders, keeping your upper arms still.","Pause for a moment, then slowly extend your arms back out to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"obe5LMq"},{"id":"edb-0999","name":"הרמת עקבים ברגל אחת עם גומייה","name_en":"band single leg calf raise","muscle":"legs","equipment":"band","target":"calves","bodyPart":"lower legs","secondaryMuscles":["ankles","feet"],"steps":["עמדו עם הרגליים ברוחב האגן והניחו את הגומייה סביב כרית כף הרגל השמאלית.","אחזו בעצם יציב לשמירה על שיווי משקל במידת הצורך.","הרימו לאט את עקב הרגל השמאלית מהרצפה, כשמשקל הגוף עובר לכרית כף הרגל.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקב השמאלי בחזרה למצב ההתחלתי.","חזרו על התנועה למספר החזרות הרצוי, ולאחר מכן עברו לרגל הימנית."],"steps_en":["Stand with your feet hip-width apart and place the band around the ball of your left foot.","Hold onto a stable object for balance if needed.","Slowly raise your left heel off the ground, lifting your body weight onto the ball of your foot.","Pause for a moment at the top, then slowly lower your left heel back down to the starting position.","Repeat for the desired number of repetitions, then switch to the right leg."],"mediaId":"9JprnPh"},{"id":"edb-1000","name":"הרמת עקבים ברגל אחת הפוך עם גומייה","name_en":"band single leg reverse calf raise","muscle":"legs","equipment":"band","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings","glutes"],"steps":["עמדו עם הרגליים ברוחב האגן והניחו את הגומייה סביב כרית כף הרגל.","אחזו בעצם יציב לשמירה על שיווי משקל.","הרימו לאט את העקב מהרצפה, כשמשקל הגוף עובר לכרית כף הרגל.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקב בחזרה למצב ההתחלתי.","חזרו על התנועה למספר החזרות הרצוי, ולאחר מכן עברו לרגל השנייה."],"steps_en":["Stand with your feet hip-width apart and place the band around the ball of your foot.","Hold onto a stable object for balance.","Slowly raise your heel off the ground, lifting your body weight onto the ball of your foot.","Pause for a moment at the top, then slowly lower your heel back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other leg."],"mediaId":"QsSQWbf"},{"id":"edb-1001","name":"סקוואט מפוצל ברגל אחת עם גומייה","name_en":"band single leg split squat","muscle":"legs","equipment":"band","target":"quads","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings"],"steps":["עמדו עם הרגליים ברוחב הירכיים והניחו גומיית התנגדות סביב הקרסוליים.","עשו צעד גדול קדימה עם הרגל הימנית וצעד קטן יותר אחורה עם הרגל השמאלית.","כופפו את הברכיים והורידו את הגוף עד שהירך הימנית מקבילה לרצפה, כשהברך השמאלית נשארת מעט מעל הרצפה.","דחפו דרך העקב הימני כדי לחזור למצב ההתחלתי.","חזרו על התרגיל בצד השני."],"steps_en":["Stand with your feet hip-width apart and place a resistance band around your ankles.","Take a big step forward with your right foot and a smaller step back with your left foot.","Bend your knees and lower your body until your right thigh is parallel to the ground, keeping your left knee slightly above the ground.","Push through your right heel to return to the starting position.","Repeat on the other side."],"mediaId":"y8bYM8w"},{"id":"edb-1004","name":"סקוואט עם גומייה","name_en":"band squat","muscle":"glutes","equipment":"band","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשהגומייה ממוקמת מעט מעל הברכיים.","תוך שמירה על החזה זקוף ושרירי הליבה מופעלים, דחפו את האגן אחורה וכופפו את הברכיים כדי לרדת לתנוחת סקוואט.","ודאו שהברכיים נמצאות בקו עם הבהונות ושהמשקל מונח על העקבים.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, with the band placed just above your knees.","Keeping your chest up and core engaged, push your hips back and bend your knees to lower into a squat position.","Make sure your knees are tracking over your toes and your weight is in your heels.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"TUZLh71"},{"id":"edb-1003","name":"חתירה עם גומייה","name_en":"band squat row","muscle":"glutes","equipment":"band","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps","back"],"steps":["חברו את הגומייה לנקודת עיגון יציבה בגובה המותניים.","עמדו מול נקודת העיגון עם הרגליים ברוחב הכתפיים.","אחזו בידיות הגומייה כשכפות הידיים פונות זו לזו והידיים מושטות לפניכם.","כופפו את הברכיים ורדו לתנוחת סקוואט, תוך שמירה על גב ישר וחזה מורם.","מתנוחת הסקוואט, משכו את ידיות הגומייה לכיוון הגוף, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה, ולאחר מכן שחררו לאט את המתח וחזרו למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach the band to a sturdy anchor point at waist height.","Stand facing the anchor point with your feet shoulder-width apart.","Hold the band handles with your palms facing each other and your arms extended in front of you.","Bend your knees and lower into a squat position, keeping your back straight and chest lifted.","From the squat position, pull the band handles towards your body, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"w1NOByi"},{"id":"edb-1005","name":"כפיפת בטן בעמידה עם גומייה","name_en":"band standing crunch","muscle":"core","equipment":"band","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques"],"steps":["חברו את הגומייה לנקודת עיגון יציבה בגובה המותניים.","עמדו כשגבכם לנקודת העיגון, עם הרגליים ברוחב הכתפיים.","אחזו בגומייה בשתי הידיים והביאו אותה לגובה החזה, כשהמרפקים כפופים וקרובים לגוף.","הפעילו את שרירי הבטן והתכופפו לאט קדימה, תוך קירוב החזה לברכיים.","עצרו לרגע בשיא הכפיפה, ולאחר מכן חזרו לאט למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach the band to a sturdy anchor point at waist height.","Stand facing away from the anchor point with your feet shoulder-width apart.","Hold the band with both hands and bring it up to your chest, keeping your elbows bent and close to your body.","Engage your abs and slowly crunch forward, bringing your chest towards your knees.","Pause for a moment at the top of the crunch, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Kzg30R7"},{"id":"edb-1022","name":"חתירת כתף אחורית בעמידה עם גומייה","name_en":"band standing rear delt row","muscle":"shoulders","equipment":"band","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","rhomboids","biceps"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והניחו את הגומייה מתחת לרגליים.","אחזו בידיות הגומייה כשכפות הידיים פונות זו לזו והידיים מושטות לפניכם.","כופפו מעט את הברכיים והטו את הגוף קדימה במפרקי הירך, תוך שמירה על גב ישר.","משכו את הגומייה לכיוון החזה, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה, ולאחר מכן שחררו לאט את המתח וחזרו למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and place the band under your feet.","Hold the band handles with your palms facing each other and your arms extended in front of you.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Pull the band towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"tc5dYrf"},{"id":"edb-1007","name":"כפיפת בטן בעמידה עם גומייה","name_en":"band standing twisting crunch","muscle":"core","equipment":"band","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והניחו את הגומייה סביב הגב העליון, כשהיא חוצה את החזה מלפנים.","אחזו בקצוות הגומייה בידיים, כשהמרפקים כפופים וקרובים לגוף.","הפעילו את שרירי הבטן וסובבו את פלג הגוף העליון לצד אחד, תוך קירוב המרפק לברך הנגדית.","עצרו לרגע, ולאחר מכן חזרו למצב ההתחלתי.","חזרו על התרגיל בצד השני.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and place the band around your upper back, crossing it in front of your chest.","Hold the ends of the band with your hands, keeping your elbows bent and close to your sides.","Engage your abs and twist your torso to one side, bringing your elbow towards the opposite knee.","Pause for a moment, then return to the starting position.","Repeat on the other side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"euq4pwp"},{"id":"edb-1008","name":"עלייה על ספסל עם גומייה","name_en":"band step-up","muscle":"glutes","equipment":"band","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["הניחו גומייה סביב הירכיים, מעט מעל הברכיים.","עמדו מול מדרגה או משטח מוגבה, עם הרגליים ברוחב האגן.","עלו על המשטח עם הרגל הימנית, תוך דחיפה דרך העקב.","יישרו את הרגל השמאלית מאחוריכם, כשהיא נשארת ישרה.","הורידו את כף הרגל השמאלית בחזרה לרצפה.","חזרו על התנועה כשהרגל השמאלית עולה על המשטח.","המשיכו להחליף רגליים למספר החזרות הרצוי."],"steps_en":["Place a band around your thighs, just above your knees.","Stand facing a step or platform with your feet hip-width apart.","Step up onto the platform with your right foot, pushing through your heel.","Extend your left leg behind you, keeping it straight.","Lower your left foot back down to the ground.","Repeat with your left foot stepping up onto the platform.","Continue alternating legs for the desired number of repetitions."],"mediaId":"d5bTEPV"},{"id":"edb-1009","name":"דדליפט רגליים ישרות עם גומייה","name_en":"band stiff leg deadlift","muscle":"glutes","equipment":"band","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","lower back"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והניחו את הגומייה סביב הקרסוליים.","אחזו בגומייה בשתי הידיים מול הירכיים, כשכפות הידיים פונות לגוף.","תוך שמירה על גב ישר ושרירי ליבה מופעלים, כופפו באגן והורידו לאט את פלג הגוף העליון לכיוון הרצפה.","תוך כדי הירידה, דחפו את האגן אחורה ואפשרו לברכיים להתכופף מעט.","הורידו את הגומייה לכיוון הרצפה, תוך הרגשת מתיחה בשרירי הירך האחוריים.","עצרו לרגע בתחתית התנועה, ולאחר מכן הפעילו את שרירי הישבן והירך האחוריים כדי להרים את פלג הגוף העליון בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and place the band around your ankles.","Hold the band with both hands in front of your thighs, palms facing your body.","Keeping your back straight and your core engaged, hinge at the hips and slowly lower your upper body towards the ground.","As you lower, push your hips back and allow your knees to bend slightly.","Lower the band towards the ground, feeling a stretch in your hamstrings.","Pause for a moment at the bottom, then engage your glutes and hamstrings to lift your upper body back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"kuMiR2T"},{"id":"edb-1023","name":"דדליפט רגליים ישרות עם גומייה","name_en":"band straight back stiff leg deadlift","muscle":"glutes","equipment":"band","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","lower back"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והניחו את הגומייה סביב חלק הרגליים העליון.","אחזו בגומייה בשתי הידיים מול הירכיים, כשכפות הידיים פונות לגוף.","תוך שמירה על גב ישר וברכיים כפופות מעט, כופפו באגן והורידו את הגומייה לכיוון הרצפה.","הרגישו את המתיחה בשרירי הירך האחוריים תוך כדי הורדת הגומייה.","הפעילו את שרירי הישבן והירך האחוריים כדי להרים את הגוף בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and place the band around your upper legs.","Hold the band with both hands in front of your thighs, palms facing your body.","Keeping your back straight and your knees slightly bent, hinge at the hips and lower the band towards the ground.","Feel the stretch in your hamstrings as you lower the band.","Engage your glutes and hamstrings to lift your body back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"lHeUULr"},{"id":"edb-1010","name":"דדליפט עם גומייה","name_en":"band straight leg deadlift","muscle":"back","equipment":"band","target":"spine","bodyPart":"back","secondaryMuscles":["hamstrings","glutes"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והניחו את הגומייה סביב הרגליים.","אחזו בגומייה בשתי הידיים, כשכפות הידיים פונות לגוף, ושמרו על הידיים ישרות.","הפעילו את שרירי הליבה ושמרו על כפיפה קלה בברכיים.","כופפו לאט קדימה באגן, תוך שמירה על גב ישר וחזה מורם.","הורידו את הגומייה לכיוון הרצפה תוך שמירה על רגליים ישרות.","עצרו לרגע בתחתית התנועה, ולאחר מכן כווצו את שרירי הישבן והירך האחוריים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and place the band around your feet.","Hold the band with both hands, palms facing your body, and keep your arms straight.","Engage your core and maintain a slight bend in your knees.","Slowly hinge forward at your hips, keeping your back straight and chest lifted.","Lower the band towards the ground while keeping your legs straight.","Pause for a moment at the bottom, then squeeze your glutes and hamstrings to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"KUaoUV8"},{"id":"edb-1012","name":"לחיצה מעל הראש עם גומייה","name_en":"band twisting overhead press","muscle":"shoulders","equipment":"band","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והניחו את הגומייה מתחת לרגליים.","אחזו בידיות הגומייה בגובה הכתפיים כשכפות הידיים פונות קדימה.","הפעילו את שרירי הליבה ודחפו את הגומייה מעל הראש, תוך יישור מלא של הידיים.","תוך כדי הדחיפה, סובבו את פלג הגוף העליון לצד אחד, כשהאגן נשאר יציב.","עצרו לרגע בשיא התנועה, ולאחר מכן חזרו למצב ההתחלתי.","חזרו על הדחיפה והסיבוב לצד הנגדי.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and place the band under your feet.","Hold the band handles at shoulder height with your palms facing forward.","Engage your core and press the band overhead, fully extending your arms.","As you press, twist your torso to one side, keeping your hips stable.","Pause for a moment at the top, then return to the starting position.","Repeat the press and twist on the opposite side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"u4bAmKp"},{"id":"edb-1369","name":"הרמת עקבים עם גומייה","name_en":"band two legs calf raise - (band under both legs) v. 2","muscle":"legs","equipment":"band","target":"calves","bodyPart":"lower legs","secondaryMuscles":["ankles","feet"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והניחו גומיית התנגדות מתחת לשתי הרגליים.","אחזו בקצוות הגומייה בידיים לשם יציבות.","הרימו את העקבים מהרצפה כמה שיותר גבוה, תוך שימוש בשרירי השוק.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקבים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and place a resistance band under both feet.","Hold the ends of the band with your hands for stability.","Raise your heels off the ground as high as possible, using your calves.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"jl6uxZV"},{"id":"edb-1013","name":"משיכת פולי עם גומייה","name_en":"band underhand pulldown","muscle":"back","equipment":"band","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["חברו את הגומייה לנקודת עיגון גבוהה, כגון מתקן מתח או קורה יציבה.","עמדו מול נקודת העיגון עם הרגליים ברוחב הכתפיים.","אחזו בגומייה באחיזה תחתית, בידיים ברוחב מעט גדול מרוחב הכתפיים.","יישרו את הידיים לגמרי מעל הראש, כשהמרפקים כפופים מעט.","הפעילו את שרירי הגב הרחבים ומשכו את הגומייה מטה לכיוון החזה, תוך כיווץ השכמות זו לזו.","עצרו לרגע בתחתית התנועה, ולאחר מכן שחררו לאט את המתח וחזרו למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach the band to a high anchor point, such as a pull-up bar or sturdy beam.","Stand facing the anchor point with your feet shoulder-width apart.","Grasp the band with an underhand grip, hands slightly wider than shoulder-width apart.","Extend your arms fully overhead, keeping your elbows slightly bent.","Engage your lats and pull the band down towards your chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"k6tUeqS"},{"id":"edb-1014","name":"band v-up","name_en":"band v-up","muscle":"core","equipment":"band","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שכבו על הגב עם הרגליים ישרות והידיים מושטות מעל הראש, כשהן אוחזות בגומייה.","תוך הפעלת שרירי הבטן, הרימו את הרגליים ואת פלג הגוף העליון מהרצפה בו-זמנית, והושיטו את הידיים לכיוון הבהונות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגליים ואת פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your legs straight and your arms extended overhead, holding the band.","Engaging your abs, lift your legs and upper body off the ground simultaneously, reaching your hands towards your toes.","Pause for a moment at the top, then slowly lower your legs and upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"H6ETwO9"},{"id":"edb-1015","name":"לחיצה עם גומייה","name_en":"band vertical pallof press","muscle":"core","equipment":"band","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","glutes"],"steps":["עמדו עם הרגליים ברוחב הכתפיים וכרכו את הגומייה סביב עצם יציב בגובה החזה.","אחזו בגומייה בשתי הידיים והתרחקו מנקודת העיגון, כך שתיווצר מתיחה בגומייה.","מקמו את עצמכם בניצב לנקודת העיגון, כשהצד שלכם פונה לגומייה.","יישרו את הידיים לפניכם, כשהידיים נשארות בגובה החזה.","הפעילו את שרירי הליבה ודחפו את הגומייה הרחק מהחזה, תוך יישור מלא של הידיים.","החזיקו את התנוחה למספר שניות, ולאחר מכן החזירו לאט את הגומייה לכיוון החזה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Stand with your feet shoulder-width apart and wrap the band around a sturdy object at chest height.","Hold the band with both hands and step away from the anchor point, creating tension in the band.","Position yourself perpendicular to the anchor point, with your side facing the band.","Extend your arms straight out in front of you, keeping your hands at chest height.","Engage your core and press the band away from your chest, fully extending your arms.","Hold the position for a few seconds, then slowly bring the band back towards your chest.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"G7PXMlT"},{"id":"edb-1016","name":"כפיפת שורש כף היד עם גומייה","name_en":"band wrist curl","muscle":"biceps","equipment":"band","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["biceps","triceps"],"steps":["שבו על ספסל או כיסא כשכפות הרגליים שטוחות על הרצפה.","אחזו בגומייה בשתי הידיים, כשכפות הידיים פונות למעלה, והניחו את האמות על הירכיים.","כופפו לאט את פרקי הידיים כלפי מעלה, תוך כיווץ האמות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פרקי הידיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench or chair with your feet flat on the ground.","Hold the band with both hands, palms facing up, and rest your forearms on your thighs.","Slowly curl your wrists upward, squeezing your forearms.","Pause for a moment at the top, then slowly lower your wrists back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"vUTfFHw"},{"id":"edb-1017","name":"הרמה עם גומייה","name_en":"band y-raise","muscle":"shoulders","equipment":"band","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","rhomboids"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו בגומייה מול הירכיים כשכפות הידיים פונות פנימה.","שמרו על הידיים ישרות והרימו אותן החוצה לצדדים, כך שהגוף יוצר צורת 'Y'.","כווצו את השכמות זו לזו בשיא התנועה.","הורידו לאט את הידיים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold the band in front of your thighs with your palms facing inwards.","Keep your arms straight and lift them up and out to the sides, forming a 'Y' shape with your body.","Squeeze your shoulder blades together at the top of the movement.","Slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"aHDy5O5"},{"id":"edb-0023","name":"כפיפת מרפק לסירוגין עם מוט","name_en":"barbell alternate biceps curl","muscle":"biceps","equipment":"barbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף עם הרגליים ברוחב הכתפיים ואחזו מוט בכל יד, כשכפות הידיים פונות קדימה.","שמרו על הזרוע העליונה ללא תזוזה ונשפו החוצה תוך כדי כיפוף המשקולות וכיווץ שרירי הביצפס.","המשיכו להרים את המוטות עד ששרירי הביצפס מכווצים לגמרי והמוטות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר תוך כדי הורדה לאטה של המוטות בחזרה למצב ההתחלתי.","חזרו על התנועה למספר החזרות הרצוי, תוך החלפת ידיים."],"steps_en":["Stand up straight with your feet shoulder-width apart and hold a barbell in each hand, palms facing forward.","Keep your upper arms stationary and exhale as you curl the weights while contracting your biceps.","Continue to raise the barbells until your biceps are fully contracted and the barbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale as you slowly begin to lower the barbells back to the starting position.","Repeat for the desired number of repetitions, alternating arms."],"mediaId":"Yza7XrQ"},{"id":"edb-0024","name":"סקוואט קדמי עם מוט","name_en":"barbell bench front squat","muscle":"legs","equipment":"barbell","target":"quads","bodyPart":"upper legs","secondaryMuscles":["hamstrings","glutes","calves"],"steps":["התחילו בעמידה עם הרגליים ברוחב הכתפיים והמוט מונח על החזה העליון, מתחת לעצם הבריח.","אחזו במוט באחיזה עליונה, כשהמרפקים מורמים והזרוע העליונה מקבילה לרצפה.","הורידו את הגוף לתנוחת סקוואט על ידי כפיפת הברכיים והאגן, תוך שמירה על גב ישר וחזה זקוף.","עצרו לרגע בתחתית הסקוואט, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by standing with your feet shoulder-width apart and the barbell resting on your upper chest, just below your collarbone.","Hold the barbell with an overhand grip, keeping your elbows up and your upper arms parallel to the ground.","Lower your body down into a squat position by bending at the knees and hips, keeping your back straight and your chest up.","Pause for a moment at the bottom of the squat, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Y7YcmIJ"},{"id":"edb-0025","name":"לחיצת חזה במוט","name_en":"barbell bench press","muscle":"chest","equipment":"barbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["שכבו על ספסל כשכפות הרגליים שטוחות על הרצפה והגב צמוד לספסל.","אחזו במוט באחיזה עליונה מעט רחבה יותר מרוחב הכתפיים.","הרימו את המוט מהמעמד והחזיקו אותו ישר מעל החזה כשהידיים מיושרות לגמרי.","הורידו את המוט לאט לכיוון החזה, כשהמרפקים צמודים לגוף.","עצרו לרגע כשהמוט נוגע בחזה.","דחפו את המוט בחזרה למצב ההתחלתי על ידי יישור הידיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with an overhand grip slightly wider than shoulder-width apart.","Lift the barbell off the rack and hold it directly above your chest with your arms fully extended.","Lower the barbell slowly towards your chest, keeping your elbows tucked in.","Pause for a moment when the barbell touches your chest.","Push the barbell back up to the starting position by extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"EIeI8Vf"},{"id":"edb-0026","name":"סקוואט עם מוט","name_en":"barbell bench squat","muscle":"legs","equipment":"barbell","target":"quads","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings","calves"],"steps":["הציבו מוט על מעמד סקוואט בגובה החזה.","עמדו כשגבכם למעמד, עם הרגליים ברוחב הכתפיים.","כופפו את הברכיים והורידו את הגוף לתנוחת סקוואט, תוך שמירה על גב ישר וחזה זקוף.","אחזו במוט באחיזה עליונה, מעט רחבה יותר מרוחב הכתפיים.","הרימו את המוט מהמעמד וצעדו אחורה, תוך ודא שהרגליים עדיין ברוחב הכתפיים.","הורידו את הגוף לתנוחת סקוואט, כשהברכיים בקו עם הבהונות.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up a barbell on a squat rack at chest height.","Stand facing away from the rack, with your feet shoulder-width apart.","Bend your knees and lower your body down into a squat position, keeping your back straight and chest up.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lift the barbell off the rack and step back, ensuring your feet are still shoulder-width apart.","Lower your body down into a squat, keeping your knees in line with your toes.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"W9pFVv1"},{"id":"edb-1316","name":"פולאובר בהטיה עם מוט","name_en":"barbell bent arm pullover","muscle":"back","equipment":"barbell","target":"lats","bodyPart":"back","secondaryMuscles":["triceps","chest"],"steps":["שכבו על הגב על ספסל, עם הראש בקצה אחד והרגליים על הרצפה.","אחזו במוט באחיזה ברוחב הכתפיים ויישרו את הידיים ישר מעל החזה.","הורידו את המוט מאחורי הראש כשהידיים כפופות מעט.","עצרו לרגע, ולאחר מכן הרימו את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your head at one end and your feet on the floor.","Hold a barbell with a shoulder-width grip and extend your arms straight above your chest.","Lower the barbell behind your head while keeping your arms slightly bent.","Pause for a moment, then raise the barbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"cA9FuWG"},{"id":"edb-0027","name":"חתירה במוט בהטיה","name_en":"barbell bent over row","muscle":"back","equipment":"barbell","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","התכופפו קדימה באגן תוך שמירה על גב ישר וחזה זקוף.","אחזו במוט באחיזה עליונה, כשהידיים מעט רחבות יותר מרוחב הכתפיים.","משכו את המוט לכיוון החזה התחתון על ידי כיווץ השכמות ולחיצת שרירי הגב.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and knees slightly bent.","Bend forward at the hips while keeping your back straight and chest up.","Grasp the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Pull the barbell towards your lower chest by retracting your shoulder blades and squeezing your back muscles.","Pause for a moment at the top, then slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"eZyBC3j"},{"id":"edb-2407","name":"כפיפת מרפק עם מוט","name_en":"barbell biceps curl (with arm blaster)","muscle":"biceps","equipment":"barbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף עם הרגליים ברוחב הכתפיים ואחזו במוט באחיזה תחתונה, כשכפות הידיים פונות למעלה.","הניחו את הזרוע העליונה על תומך המרפקים (ארם בלאסטר), כשהמרפקים קרובים לגוף.","תוך שמירה על הזרוע העליונה ללא תזוזה, נשפו החוצה וכופפו את המשקולות תוך כיווץ שרירי הביצפס.","המשיכו להרים את המוט עד ששרירי הביצפס מכווצים לגמרי והמוט בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing up.","Place your upper arms against the arm blaster, keeping your elbows close to your torso.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the barbell until your biceps are fully contracted and the bar is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"aee2Fcj"},{"id":"edb-0028","name":"קלין עם מוט","name_en":"barbell clean and press","muscle":"legs","equipment":"barbell","target":"quads","bodyPart":"upper legs","secondaryMuscles":["hamstrings","glutes","shoulders","triceps"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והמוט על הרצפה לפניכם.","כופפו את הברכיים והתכופפו באגן כדי לרדת ולאחוז במוט באחיזה עליונה, כשהידיים מעט רחבות יותר מרוחב הכתפיים.","דחפו דרך העקבים ויישרו את האגן והברכיים כדי להרים את המוט מהרצפה, תוך שמירה עליו קרוב לגוף.","כשהמוט מגיע לירכיים, יישרו בעוצמה את האגן, הרימו את הכתפיים ומשכו את המוט כלפי מעלה לכיוון החזה.","כשהמוט מגיע לגובה החזה, רדו במהירות מתחתיו ותפסו אותו בגובה הכתפיים, כשהמרפקים פונים קדימה וכפות הידיים פונות למעלה.","מתנוחת התפיסה, דחפו את המוט מעל הראש על ידי יישור הידיים ודחיפת המוט ישר כלפי מעלה.","הורידו את המוט בחזרה למצב ההתחלתי וחזרו על התנועה למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and the barbell on the floor in front of you.","Bend your knees and hinge at the hips to lower down and grip the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Drive through your heels and extend your hips and knees to lift the barbell off the floor, keeping it close to your body.","As the barbell reaches your thighs, explosively extend your hips, shrug your shoulders, and pull the barbell up towards your chest.","As the barbell reaches chest height, quickly drop under it and catch it at shoulder level, with your elbows pointing forward and your palms facing up.","From the catch position, press the barbell overhead by extending your arms and pushing the barbell straight up.","Lower the barbell back down to the starting position and repeat for the desired number of repetitions."],"mediaId":"SGY8Zui"},{"id":"edb-0029","name":"סקוואט קדמי עם מוט","name_en":"barbell clean-grip front squat","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves","core"],"steps":["התחילו בעמידה עם הרגליים ברוחב הכתפיים והמוט מונח על החזה העליון, כשהמרפקים פונים קדימה.","הורידו את הגוף על ידי כפיפת הברכיים ודחיפת האגן אחורה, כאילו אתם מתיישבים על כיסא.","שמרו על החזה זקוף והגב ישר תוך כדי הירידה, וודאו שהברכיים אינן חורגות מקו הבהונות.","המשיכו לרדת עד שהירכיים מקבילות לרצפה, או עד למקסימום שנוח לכם.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו דרך העקבים כדי לחזור לעמידה, תוך יישור האגן והברכיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by standing with your feet shoulder-width apart and the barbell resting on your upper chest, with your elbows pointing forward.","Lower your body by bending your knees and pushing your hips back, as if you are sitting back into a chair.","Keep your chest up and your back straight as you lower down, making sure your knees do not go past your toes.","Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to stand back up, extending your hips and knees.","Repeat for the desired number of repetitions."],"mediaId":"qi996YS"},{"id":"edb-0030","name":"לחיצת חזה אחיזה צרה עם מוט","name_en":"barbell close-grip bench press","muscle":"triceps","equipment":"barbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["שכבו על ספסל כשכפות הרגליים שטוחות על הרצפה והגב צמוד לספסל.","אחזו במוט באחיזה צרה, מעט צרה יותר מרוחב הכתפיים.","הרימו את המוט מהמעמד והורידו אותו לאט לכיוון החזה, כשהמרפקים צמודים לגוף.","עצרו לרגע כשהמוט נוגע בחזה.","דחפו את המוט בחזרה למצב ההתחלתי, תוך יישור מלא של הידיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with a close grip, slightly narrower than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows close to your body.","Pause for a moment when the barbell touches your chest.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"J6Dx1Mu"},{"id":"edb-0031","name":"כפיפת מרפק במוט","name_en":"barbell curl","muscle":"biceps","equipment":"barbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף עם הרגליים ברוחב הכתפיים ואחזו במוט באחיזה תחתונה, כשכפות הידיים פונות קדימה.","שמרו על המרפקים קרובים לגוף ונשפו החוצה תוך כדי כיפוף המשקולות וכיווץ שרירי הביצפס.","המשיכו להרים את המוט עד ששרירי הביצפס מכווצים לגמרי והמוט בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר תוך כדי הורדה לאטה של המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing forward.","Keep your elbows close to your torso and exhale as you curl the weights while contracting your biceps.","Continue to raise the bar until your biceps are fully contracted and the bar is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale as you slowly begin to lower the bar back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"25GPyDY"},{"id":"edb-0032","name":"דדליפט","name_en":"barbell deadlift","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","lower back"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והמוט על הרצפה לפניכם.","כופפו את הברכיים והתכופפו באגן כדי להוריד את פלג הגוף העליון ולאחוז במוט באחיזה עליונה, כשהידיים מעט רחבות יותר מרוחב הכתפיים.","שמרו על גב ישר וחזה מורם תוך דחיפה דרך העקבים כדי להרים את המוט מהרצפה, תוך יישור האגן והברכיים.","תוך כדי חזרה לעמידה זקופה, כווצו את שרירי הישבן ושמרו על שרירי הליבה מופעלים.","הורידו את המוט בחזרה לרצפה על ידי כפיפת האגן והברכיים, תוך שמירה על גב ישר.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and the barbell on the ground in front of you.","Bend your knees and hinge at the hips to lower your torso and grip the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Keep your back straight and chest lifted as you drive through your heels to lift the barbell off the ground, extending your hips and knees.","As you stand up straight, squeeze your glutes and keep your core engaged.","Lower the barbell back down to the ground by bending at the hips and knees, keeping your back straight.","Repeat for the desired number of repetitions."],"mediaId":"ila4NZS"},{"id":"edb-0033","name":"לחיצת חזה בשיפוע שלילי עם מוט","name_en":"barbell decline bench press","muscle":"chest","equipment":"barbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["שכבו על ספסל בשיפוע יורד עם הרגליים מקובעות והראש נמוך יותר מהאגן.","אחזו במוט באחיזה עליונה מעט רחבה יותר מרוחב הכתפיים.","הרימו את המוט מהמעמד והורידו אותו לאט לכיוון החזה, כשהמרפקים צמודים לגוף.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie on a decline bench with your feet secured and your head lower than your hips.","Grasp the barbell with an overhand grip slightly wider than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in.","Pause for a moment at the bottom, then push the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"GrO65fd"},{"id":"edb-0034","name":"פולאובר בשיפוע שלילי בהטיה עם מוט","name_en":"barbell decline bent arm pullover","muscle":"back","equipment":"barbell","target":"lats","bodyPart":"back","secondaryMuscles":["triceps","chest"],"steps":["שכבו על ספסל בשיפוע יורד כשהראש נמוך יותר מהאגן והרגליים מקובעות.","אחזו במוט באחיזה עליונה (כפות הידיים פונות הרחק מכם) ויישרו את הידיים ישר מעל החזה.","הורידו את המוט מאחורי הראש באופן מבוקר, כשהידיים כפופות מעט.","עצרו לרגע, ולאחר מכן הרימו את המוט בחזרה למצב ההתחלתי על ידי כיווץ שרירי הגב הרחבים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie down on a decline bench with your head lower than your hips and your feet secured.","Hold a barbell with a pronated grip (palms facing away from you) and extend your arms straight above your chest.","Lower the barbell behind your head in a controlled manner, keeping your arms slightly bent.","Pause for a moment, then raise the barbell back to the starting position by contracting your lats.","Repeat for the desired number of repetitions."],"mediaId":"hMEptv0"},{"id":"edb-0035","name":"לחיצה אחיזה צרה בשיפוע שלילי עם מוט","name_en":"barbell decline close grip to skull press","muscle":"triceps","equipment":"barbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["שכבו על ספסל בשיפוע יורד כשהראש נמוך יותר מהרגליים ואחזו במוט באחיזה צרה.","הורידו את המוט לכיוון המצח על ידי כפיפת המרפקים, כשהזרוע העליונה נשארת ללא תזוזה.","עצרו לרגע, ולאחר מכן יישרו את הידיים כדי לדחוף את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie on a decline bench with your head lower than your feet and hold a barbell with a close grip.","Lower the barbell towards your forehead by bending your elbows, keeping your upper arms stationary.","Pause for a moment, then extend your arms to press the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"LMGXZn8"},{"id":"edb-1255","name":"פולאובר בשיפוע שלילי עם מוט","name_en":"barbell decline pullover","muscle":"chest","equipment":"barbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["שכבו על ספסל בשיפוע יורד כשהראש נמוך יותר מהאגן והרגליים מקובעות.","אחזו במוט באחיזה עליונה (כפות הידיים פונות הרחק מכם) כשהידיים מעט רחבות יותר מרוחב הכתפיים.","יישרו את הידיים מעל החזה, כשהמרפקים כפופים מעט.","הורידו את המוט בתנועת קשת מאחורי הראש, תוך הרגשת מתיחה בחזה ובכתפיים.","עצרו לרגע, ולאחר מכן החזירו את המוט למצב ההתחלתי על ידי היפוך התנועה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie down on a decline bench with your head lower than your hips and your feet secured.","Hold the barbell with a pronated grip (palms facing away from you) and your hands slightly wider than shoulder-width apart.","Extend your arms above your chest, keeping a slight bend in your elbows.","Lower the barbell in an arc motion behind your head, feeling a stretch in your chest and shoulders.","Pause for a moment, then return the barbell to the starting position by reversing the motion.","Repeat for the desired number of repetitions."],"mediaId":"9sgNE2O"},{"id":"edb-0036","name":"לחיצה אחיזה רחבה בשיפוע שלילי עם מוט","name_en":"barbell decline wide-grip press","muscle":"chest","equipment":"barbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["שכבו על ספסל בשיפוע יורד עם הרגליים מקובעות והראש נמוך יותר מהאגן.","אחזו במוט באחיזה רחבה, מעט רחבה יותר מרוחב הכתפיים.","הורידו את המוט לכיוון החזה, כשהמרפקים פונים החוצה לצדדים.","דחפו את המוט בחזרה למצב ההתחלתי, תוך יישור מלא של הידיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie on a decline bench with your feet secured and your head lower than your hips.","Grasp the barbell with a wide grip, slightly wider than shoulder-width apart.","Lower the barbell to your chest, keeping your elbows out to the sides.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"hl8DUh8"},{"id":"edb-0037","name":"פולאובר אחיזה רחבה בשיפוע שלילי עם מוט","name_en":"barbell decline wide-grip pullover","muscle":"back","equipment":"barbell","target":"lats","bodyPart":"back","secondaryMuscles":["triceps","chest"],"steps":["שכבו על ספסל בשיפוע יורד עם הרגליים מקובעות והראש נמוך יותר מהאגן.","אחזו במוט באחיזה רחבה ויישרו את הידיים ישר מעל החזה.","הורידו את המוט מאחורי הראש באופן מבוקר, כשהידיים נשארות ישרות.","עצרו לרגע, ולאחר מכן הרימו את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie on a decline bench with your head lower than your hips and your feet secured.","Hold a barbell with a wide grip and extend your arms straight above your chest.","Lower the barbell behind your head in a controlled manner, keeping your arms straight.","Pause for a moment, then raise the barbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Hj4FOCd"},{"id":"edb-0038","name":"כפיפת מרפק עם מוט","name_en":"barbell drag curl","muscle":"biceps","equipment":"barbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו במוט באחיזה תחתונה, כשכפות הידיים פונות למעלה.","תנו למוט להישאר תלוי באורך הזרוע מול הירכיים.","תוך שמירה על הזרוע העליונה ללא תזוזה, כופפו את המוט כלפי מעלה לכיוון החזה על ידי כיווץ שרירי הביצפס.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing up.","Let the barbell hang at arm's length in front of your thighs.","Keeping your upper arms stationary, curl the barbell up towards your chest by contracting your biceps.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"IENzBdA"},{"id":"edb-1370","name":"הרמת עקבים עם מוט","name_en":"barbell floor calf raise","muscle":"legs","equipment":"barbell","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings"],"steps":["הניחו מוט על הרצפה לפניכם.","עמדו עם כריות כפות הרגליים על קצה המוט, כשהעקבים תלויים באוויר.","אחזו בעצם יציב לשמירה על שיווי משקל במידת הצורך.","הרימו את העקבים כמה שיותר גבוה, תוך שימוש בשרירי השוק להרמת הגוף.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקבים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Place a barbell on the floor in front of you.","Stand with the balls of your feet on the edge of the barbell, with your heels hanging off.","Hold onto a stable object for balance if needed.","Raise your heels as high as possible, using your calves to lift your body.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"2IHEa2T"},{"id":"edb-0039","name":"סקוואט קדמי עם מוט","name_en":"barbell front chest squat","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves","core"],"steps":["התחילו בעמידה עם הרגליים ברוחב הכתפיים והבהונות פונות מעט החוצה.","אחזו במוט מול החזה כשהידיים ברוחב הכתפיים והמרפקים פונים קדימה.","הפעילו את שרירי הליבה ושמרו על החזה זקוף תוך הורדת הגוף לתנוחת סקוואט, דחיפת האגן אחורה וכפיפת הברכיים.","רדו עד שהירכיים מקבילות לרצפה, או עד למקסימום שנוח לכם.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by standing with your feet shoulder-width apart, toes slightly turned out.","Hold the barbell in front of your chest with your hands shoulder-width apart, elbows pointing forward.","Engage your core and keep your chest up as you lower your body down into a squat position, pushing your hips back and bending your knees.","Lower until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"IeTIEqg"},{"id":"edb-0041","name":"הרמה קדמית עם מוט","name_en":"barbell front raise","muscle":"shoulders","equipment":"barbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["biceps","triceps"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו במוט מול הירכיים באחיזה עליונה.","שמרו על הידיים ישרות והרימו את המוט קדימה ולמעלה עד שהוא מגיע לגובה הכתפיים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a barbell in front of your thighs with an overhand grip.","Keep your arms straight and lift the barbell forward and upward until it reaches shoulder level.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"b2Uoz54"},{"id":"edb-0040","name":"הרמה קדמית עם מוט","name_en":"barbell front raise and pullover","muscle":"chest","equipment":"barbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["deltoids","triceps"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו במוט באחיזה עליונה, כשכפות הידיים פונות מטה.","שמרו על הידיים ישרות והרימו את המוט לפניכם עד שהוא מגיע לגובה הכתפיים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את המוט בחזרה למצב ההתחלתי.","לאחר מכן, הורידו את המוט מאחורי הראש, כשהידיים נשארות ישרות.","עצרו לרגע בתחתית התנועה, ולאחר מכן הרימו את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, palms facing down.","Keep your arms straight and raise the barbell in front of you until it reaches shoulder height.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Next, lower the barbell behind your head, keeping your arms straight.","Pause for a moment at the bottom, then raise the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"33AzZeV"},{"id":"edb-0042","name":"סקוואט קדמי עם מוט","name_en":"barbell front squat","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves","core"],"steps":["התחילו בעמידה עם הרגליים ברוחב הכתפיים והבהונות פונות מעט החוצה.","אחזו במוט מול הכתפיים, כשהוא מונח על עצם הבריח והכתפיים.","הפעילו את שרירי הליבה ושמרו על החזה זקוף תוך הורדת הגוף לתנוחת סקוואט, דחיפת האגן אחורה וכפיפת הברכיים.","רדו עד שהירכיים מקבילות לרצפה, או עד למקסימום שנוח לכם.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by standing with your feet shoulder-width apart, toes slightly turned out.","Hold the barbell in front of your shoulders, resting it on your collarbone and shoulders.","Engage your core and keep your chest up as you lower your body down into a squat position, pushing your hips back and bending your knees.","Lower until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"zG0zs85"},{"id":"edb-0043","name":"סקוואט","name_en":"barbell full squat","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והבהונות פונות מעט החוצה.","אחזו במוט על הגב העליון, כשהוא מונח על שרירי הטרפז או הדלטואיד האחורי.","הפעילו את שרירי הליבה ושמרו על החזה זקוף תוך תחילת הירידה עם הגוף.","כופפו בברכיים ובאגן, דחפו את האגן אחורה ולמטה כאילו אתם מתיישבים על כיסא.","רדו עד שהירכיים מקבילות לרצפה או מעט מתחת לכך.","שמרו על הברכיים בקו עם הבהונות ועל המשקל בעקבים.","דחפו דרך העקבים כדי לחזור לעמידה, תוך יישור האגן והברכיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, toes slightly turned out.","Hold the barbell across your upper back, resting it on your traps or rear delts.","Engage your core and keep your chest up as you begin to lower your body down.","Bend at the knees and hips, pushing your hips back and down as if sitting into a chair.","Lower yourself until your thighs are parallel to the ground or slightly below.","Keep your knees in line with your toes and your weight in your heels.","Drive through your heels to stand back up, extending your hips and knees.","Repeat for the desired number of repetitions."],"mediaId":"qXTaZnJ"},{"id":"edb-1461","name":"סקוואט עם מוט","name_en":"barbell full squat (back pov)","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והבהונות פונות מעט החוצה.","אחזו במוט על הגב העליון, כשהוא מונח על שרירי הטרפז או הדלטואיד האחורי.","הפעילו את שרירי הליבה ושמרו על החזה זקוף תוך תחילת הירידה עם הגוף.","כופפו בברכיים ובאגן, דחפו את האגן אחורה ולמטה כאילו אתם מתיישבים על כיסא.","הורידו את הגוף עד שהירכיים מקבילות לרצפה או מעט מתחת לכך.","שמרו על הברכיים בקו עם הבהונות ועל המשקל בעקבים.","דחפו דרך העקבים כדי לחזור לעמידה, תוך יישור האגן והברכיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, toes slightly turned out.","Hold the barbell across your upper back, resting it on your traps or rear delts.","Engage your core and keep your chest up as you begin to lower your body down.","Bend at the knees and hips, pushing your hips back and down as if sitting into a chair.","Lower your body until your thighs are parallel to the ground or slightly below.","Keep your knees in line with your toes and your weight in your heels.","Drive through your heels to stand back up, extending your hips and knees.","Repeat for the desired number of repetitions."],"mediaId":"DhMl549"},{"id":"edb-1462","name":"סקוואט עם מוט","name_en":"barbell full squat (side pov)","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והבהונות פונות מעט החוצה.","אחזו במוט על הגב העליון, כשהוא מונח על שרירי הטרפז או הדלטואיד האחורי.","הפעילו את שרירי הליבה ושמרו על החזה זקוף תוך תחילת הירידה עם הגוף.","כופפו בברכיים ובאגן, דחפו את האגן אחורה ולמטה כאילו אתם מתיישבים על כיסא.","הורידו את הגוף עד שהירכיים מקבילות לרצפה או מעט מתחת לכך.","שמרו על הברכיים בקו עם הבהונות ועל המשקל בעקבים.","דחפו דרך העקבים כדי לחזור לעמידה, תוך יישור האגן והברכיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, toes slightly turned out.","Hold the barbell across your upper back, resting it on your traps or rear delts.","Engage your core and keep your chest up as you begin to lower your body down.","Bend at the knees and hips, pushing your hips back and down as if sitting into a chair.","Lower your body until your thighs are parallel to the ground or slightly below.","Keep your knees in line with your toes and your weight in your heels.","Drive through your heels to stand back up, extending your hips and knees.","Repeat for the desired number of repetitions."],"mediaId":"iYzB0Cz"},{"id":"edb-1545","name":"סקוואט עם מוט","name_en":"barbell full zercher squat","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והבהונות פונות מעט החוצה.","אחזו במוט בקפל המרפקים, כשהידיים אוחזות במוט לשם יציבות.","הפעילו את שרירי הליבה ושמרו על החזה מורם תוך הורדת האגן אחורה ולמטה לתנוחת סקוואט.","שמרו על הברכיים בקו עם הבהונות ועל המשקל בעקבים.","רדו עד שהירכיים מקבילות לרצפה, או עד למקסימום שנוח לכם.","דחפו דרך העקבים כדי לחזור לעמידה, תוך כיווץ שרירי הישבן בשיא התנועה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and toes slightly turned out.","Hold the barbell in the crooks of your elbows, with your hands gripping the barbell for stability.","Engage your core and keep your chest lifted as you lower your hips back and down into a squat position.","Keep your knees in line with your toes and your weight in your heels.","Lower until your thighs are parallel to the ground, or as low as you can comfortably go.","Drive through your heels to stand back up, squeezing your glutes at the top of the movement.","Repeat for the desired number of repetitions."],"mediaId":"vR1vold"},{"id":"edb-1409","name":"גשר ישבן עם מוט","name_en":"barbell glute bridge","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","lower back"],"steps":["התחילו בשכיבה על הגב על הרצפה, עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו מוט על האגן, כשאתם אוחזים בו היטב בשתי הידיים.","הפעילו את שרירי הישבן והליבה, ולאחר מכן הרימו את האגן מהרצפה עד שהגוף יוצר קו ישר מהברכיים ועד הכתפיים.","עצרו לרגע בשיא התנועה, תוך כיווץ שרירי הישבן.","הורידו לאט את האגן בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by lying flat on your back on the ground with your knees bent and feet flat on the floor.","Place a barbell across your hips, holding it securely with both hands.","Engage your glutes and core muscles, then lift your hips off the ground until your body forms a straight line from your knees to your shoulders.","Pause for a moment at the top, squeezing your glutes.","Slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"qKBpF7I"},{"id":"edb-3562","name":"גשר ישבן עם מוט","name_en":"barbell glute bridge two legs on bench (male)","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","core"],"steps":["התחילו בישיבה בקצה ספסל כשהגב העליון נשען עליו וכפות הרגליים שטוחות על הרצפה, ברוחב האגן.","הניחו מוט על האגן, כשאתם אוחזים בו היטב בשתי הידיים.","הפעילו את שרירי הישבן והליבה, ולאחר מכן דחפו דרך העקבים כדי להרים את האגן מהספסל, ליצירת קו ישר מהברכיים ועד הכתפיים.","עצרו לרגע בשיא התנועה, תוך כיווץ שרירי הישבן.","הורידו לאט את האגן בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by sitting on the edge of a bench with your upper back resting against it and your feet flat on the ground, hip-width apart.","Place a barbell across your hips, holding it securely with both hands.","Engage your glutes and core muscles, then press through your heels to lift your hips off the bench, creating a straight line from your knees to your shoulders.","Pause for a moment at the top, squeezing your glutes.","Slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"qg2PGl6"},{"id":"edb-0044","name":"גוד מורנינג עם מוט","name_en":"barbell good morning","muscle":"legs","equipment":"barbell","target":"hamstrings","bodyPart":"upper legs","secondaryMuscles":["lower back"],"steps":["התחילו בעמידה עם הרגליים ברוחב הכתפיים והמוט מונח על הגב העליון.","תוך שמירה על גב ישר ושרירי ליבה מופעלים, כופפו קדימה באגן, דחפו את הישבן אחורה כאילו אתם מנסים לגעת בקיר מאחוריכם עם הישבן.","הורידו את הגו עד שהוא מקביל לרצפה, תוך הרגשת מתיחה בשרירי הירך האחוריים.","עצרו לרגע, ולאחר מכן חזרו למצב ההתחלתי על ידי כיווץ שרירי הישבן ודחיפת האגן קדימה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by standing with your feet shoulder-width apart and the barbell resting on your upper back.","Keeping your back straight and your core engaged, hinge forward at the hips, pushing your buttocks back as if you were trying to touch the wall behind you with your glutes.","Lower your torso until it is parallel to the ground, feeling a stretch in your hamstrings.","Pause for a moment, then return to the starting position by squeezing your glutes and pushing your hips forward.","Repeat for the desired number of repetitions."],"mediaId":"XlZ4lAC"},{"id":"edb-0045","name":"לחיצת חזה עם מוט","name_en":"barbell guillotine bench press","muscle":"chest","equipment":"barbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["שכבו על ספסל כשכפות הרגליים שטוחות על הרצפה והגב צמוד לספסל.","אחזו במוט באחיזה עליונה, מעט רחבה יותר מרוחב הכתפיים.","הורידו את המוט לאט לכיוון הצוואר, כשהמרפקים פונים החוצה.","עצרו לרגע כשהמוט נמצא מעט מעל הצוואר.","דחפו את המוט בחזרה למצב ההתחלתי, תוך יישור מלא של הידיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lower the barbell slowly towards your neck, keeping your elbows pointed outwards.","Pause for a moment when the barbell is just above your neck.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"GXoaSgn"},{"id":"edb-0046","name":"האק סקוואט עם מוט","name_en":"barbell hack squat","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["התחילו בעמידה עם הרגליים ברוחב הכתפיים והבהונות פונות מעט החוצה.","אחזו במוט מאחורי הרגליים, כשהוא מונח על חלק הירך העליון.","הורידו את הגוף על ידי כפיפת הברכיים והאגן, תוך שמירה על גב ישר וחזה זקוף.","המשיכו לרדת עד שהירכיים מקבילות לרצפה, או עד למקסימום שנוח לכם.","עצרו לרגע, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by standing with your feet shoulder-width apart and your toes slightly turned out.","Hold the barbell behind your legs, resting it on your upper thighs.","Lower your body by bending at the knees and hips, keeping your back straight and your chest up.","Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"5VCj6iH"},{"id":"edb-1436","name":"סקוואט גבוה עם מוט","name_en":"barbell high bar squat","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והבהונות פונות מעט החוצה.","הניחו את המוט על הגב העליון, כך שהוא מונח על שרירי הטרפז.","הפעילו את שרירי הליבה ושמרו על החזה זקוף תוך תחילת הסקוואט, דחיפת האגן אחורה וכפיפת הברכיים.","רדו עד שהירכיים מקבילות לרצפה, או עד למקסימום שנוח לכם.","דחפו דרך העקבים כדי לחזור לעמידה, תוך יישור האגן והברכיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, toes slightly turned out.","Place the barbell on your upper back, resting it on your traps.","Engage your core and keep your chest up as you begin to squat down, pushing your hips back and bending your knees.","Lower yourself until your thighs are parallel to the ground, or as low as you can comfortably go.","Drive through your heels to stand back up, extending your hips and knees.","Repeat for the desired number of repetitions."],"mediaId":"Gnfo4FM"},{"id":"edb-0047","name":"לחיצת חזה בשיפוע עם מוט","name_en":"barbell incline bench press","muscle":"chest","equipment":"barbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["הציבו ספסל בשיפוע עולה בזווית של 45 מעלות.","שכבו על הספסל עם כפות הרגליים שטוחות על הרצפה.","אחזו במוט באחיזה עליונה, מעט רחבה יותר מרוחב הכתפיים.","הרימו את המוט מהמעמד והורידו אותו לאט לכיוון החזה, כשהמרפקים בזווית של 45 מעלות.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up an incline bench at a 45-degree angle.","Lie down on the bench with your feet flat on the ground.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows at a 45-degree angle.","Pause for a moment at the bottom, then push the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"3TZduzM"},{"id":"edb-1719","name":"לחיצת חזה אחיזה צרה בשיפוע עם מוט","name_en":"barbell incline close grip bench press","muscle":"triceps","equipment":"barbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["הציבו ספסל בשיפוע עולה בזווית של 45 מעלות.","שכבו על הספסל עם כפות הרגליים שטוחות על הרצפה.","אחזו במוט באחיזה צרה, מעט צרה יותר מרוחב הכתפיים.","הרימו את המוט מהמעמד והורידו אותו לאט לכיוון החזה, כשהמרפקים צמודים לגוף.","עצרו לרגע כשהמוט נוגע בחזה.","דחפו את המוט בחזרה למצב ההתחלתי, תוך יישור מלא של הידיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up an incline bench at a 45-degree angle.","Lie down on the bench with your feet flat on the ground.","Grasp the barbell with a close grip, slightly narrower than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows close to your body.","Pause for a moment when the barbell touches your chest.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"gx7s7uF"},{"id":"edb-0048","name":"לחיצה אחיזה הפוכה בשיפוע עם מוט","name_en":"barbell incline reverse-grip press","muscle":"triceps","equipment":"barbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["הציבו ספסל בשיפוע עולה בזווית של 45 מעלות.","שכבו על הספסל ואחזו במוט באחיזה הפוכה, כשהידיים מעט רחבות יותר מרוחב הכתפיים.","הרימו את המוט מהמעמד והורידו אותו לכיוון החזה העליון, כשהמרפקים צמודים לגוף.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up an incline bench at a 45-degree angle.","Lie back on the bench and grasp the barbell with a reverse grip, hands slightly wider than shoulder-width apart.","Unrack the barbell and lower it towards your upper chest, keeping your elbows tucked in.","Pause for a moment at the bottom, then push the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"641mIfk"},{"id":"edb-0049","name":"חתירה בשיפוע עם מוט","name_en":"barbell incline row","muscle":"back","equipment":"barbell","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["הציבו ספסל בשיפוע עולה בזווית של 45 מעלות.","שכבו על הבטן על הספסל, כשהחזה נשען על הכרית וכפות הרגליים שטוחות על הרצפה.","אחזו במוט באחיזה עליונה, מעט רחבה יותר מרוחב הכתפיים.","שמרו על גב ישר ושרירי ליבה מופעלים.","משכו את המוט לכיוון החזה, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up an incline bench at a 45-degree angle.","Lie face down on the bench with your chest against the pad and your feet flat on the ground.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Keep your back straight and your core engaged.","Pull the barbell towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"dmgMp3n"},{"id":"edb-0050","name":"הרמה בשיפוע עם מוט","name_en":"barbell incline shoulder raise","muscle":"chest","equipment":"barbell","target":"serratus anterior","bodyPart":"chest","secondaryMuscles":["deltoids","trapezius"],"steps":["הציבו ספסל בשיפוע עולה בזווית של 45 מעלות.","שבו על הספסל כשהגב נשען על הכרית וכפות הרגליים שטוחות על הרצפה.","אחזו במוט באחיזה עליונה, מעט רחבה יותר מרוחב הכתפיים.","הרימו את המוט לגובה הכתפיים, כשהמרפקים כפופים מעט.","הרימו לאט את המוט מעל הראש, תוך יישור מלא של הידיים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את המוט בחזרה לגובה הכתפיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up an incline bench at a 45-degree angle.","Sit on the bench with your back against the pad and feet flat on the ground.","Hold a barbell with an overhand grip, slightly wider than shoulder-width apart.","Lift the barbell up to shoulder height, keeping your elbows slightly bent.","Slowly raise the barbell overhead, extending your arms fully.","Pause for a moment at the top, then slowly lower the barbell back to shoulder height.","Repeat for the desired number of repetitions."],"mediaId":"xi0yckC"},{"id":"edb-0051","name":"סקוואט עם מוט","name_en":"barbell jefferson squat","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והבהונות פונות מעט החוצה.","אחזו במוט באחיזה עליונה, כשהוא מונח על חזית הגוף, מעט מתחת למותניים.","צעדו עם הרגל השמאלית קדימה והרגל הימנית אחורה, כשהרגליים ברוחב הכתפיים.","כופפו את הברכיים והורידו את הגוף לתנוחת סקוואט, תוך שמירה על גב ישר וחזה זקוף.","דחפו דרך העקבים כדי לחזור לעמידה במצב ההתחלתי.","חזרו על התנועה, תוך החלפת הרגל הקדמית והאחורית בכל חזרה."],"steps_en":["Stand with your feet shoulder-width apart and toes slightly turned out.","Hold the barbell with an overhand grip, resting it on the front of your body, just below your waist.","Step your left foot forward and your right foot back, keeping your feet shoulder-width apart.","Bend your knees and lower your body down into a squat position, keeping your back straight and chest up.","Push through your heels to stand back up to the starting position.","Repeat the movement, alternating your forward and back foot with each repetition."],"mediaId":"pkSoCW9"},{"id":"edb-0052","name":"לחיצת חזה עם מוט","name_en":"barbell jm bench press","muscle":"triceps","equipment":"barbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["שכבו על ספסל כשכפות הרגליים שטוחות על הרצפה והגב צמוד לספסל.","אחזו במוט באחיזה עליונה, מעט רחבה יותר מרוחב הכתפיים.","הורידו את המוט לכיוון החזה, כשהמרפקים צמודים לגוף.","דחפו את המוט בחזרה למצב ההתחלתי, תוך יישור מלא של הידיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lower the barbell to your chest, keeping your elbows tucked in close to your body.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"ZsiqXYa"},{"id":"edb-0053","name":"סקוואט עם מוט","name_en":"barbell jump squat","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["התחילו בעמידה עם הרגליים ברוחב הכתפיים, כשאתם אוחזים במוט על הגב העליון.","הורידו את הגוף לתנוחת סקוואט על ידי כפיפת הברכיים ודחיפת האגן אחורה.","כשאתם מגיעים לתחתית הסקוואט, פרצו כלפי מעלה בקפיצה מהרצפה.","תוך כדי הקפיצה, יישרו את האגן, הברכיים והקרסוליים, ודחפו דרך הבהונות.","נחתו ברכות בחזרה לתנוחת הסקוואט וחזרו מיד על התנועה למספר החזרות הרצוי."],"steps_en":["Start by standing with your feet shoulder-width apart, holding a barbell across your upper back.","Lower your body into a squat position by bending your knees and pushing your hips back.","Once you reach the bottom of the squat, explode upwards by jumping off the ground.","As you jump, extend your hips, knees, and ankles, pushing through your toes.","Land softly back into the squat position and immediately repeat the movement for the desired number of repetitions."],"mediaId":"1gFNTZV"},{"id":"edb-1410","name":"לאנג׳ לצדדים עם מוט","name_en":"barbell lateral lunge","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים במוט על הגב העליון.","עשו צעד גדול הצידה עם הרגל הימנית, כשהרגל השמאלית נשארת נטועה במקום.","כופפו את הברך הימנית והורידו את הגוף לתנוחת לאנג', כשהרגל השמאלית נשארת ישרה.","דחפו עם הרגל הימנית וחזרו למצב ההתחלתי.","חזרו על התנועה בצד השני, עם צעד ברגל השמאלית."],"steps_en":["Stand with your feet shoulder-width apart, holding a barbell across your upper back.","Take a big step to the side with your right foot, keeping your left foot planted.","Bend your right knee and lower your body down into a lunge position, keeping your left leg straight.","Push off with your right foot and return to the starting position.","Repeat on the other side, stepping with your left foot."],"mediaId":"py1HSzx"},{"id":"edb-1435","name":"סקוואט נמוך עם מוט","name_en":"barbell low bar squat","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והמוט מונח על הגב העליון.","תוך שמירה על החזה זקוף ושרירי הליבה מופעלים, הורידו לאט את הגוף על ידי כפיפת הברכיים ודחיפת האגן אחורה.","המשיכו לרדת עד שהירכיים מקבילות לרצפה או מעט מתחת לכך.","עצרו לרגע, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and the barbell resting on your upper back.","Keeping your chest up and core engaged, slowly lower your body by bending your knees and pushing your hips back.","Continue lowering until your thighs are parallel to the ground or slightly below.","Pause for a moment, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"bTpEUcm"},{"id":"edb-0054","name":"לאנג׳","name_en":"barbell lunge","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["התחילו בעמידה עם הרגליים ברוחב הכתפיים והמוט מונח על הגב העליון.","עשו צעד קדימה עם הרגל הימנית, כשפלג הגוף העליון נשאר זקוף.","הורידו את הגוף על ידי כפיפת הברך הימנית עד שהירך מקבילה לרצפה.","דחפו דרך העקב הימני כדי לחזור למצב ההתחלתי.","חזרו עם הרגל השמאלית, תוך החלפת רגליים למספר החזרות הרצוי."],"steps_en":["Start by standing with your feet shoulder-width apart and a barbell resting on your upper back.","Take a step forward with your right foot, keeping your torso upright.","Lower your body by bending your right knee until your thigh is parallel to the ground.","Push through your right heel to return to the starting position.","Repeat with your left leg, alternating legs for the desired number of repetitions."],"mediaId":"t8iSghb"},{"id":"edb-1720","name":"פשיטת מרפק בשכיבה עם מוט","name_en":"barbell lying back of the head tricep extension","muscle":"triceps","equipment":"barbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שכבו על הגב על ספסל, כשכפות הרגליים שטוחות על הרצפה והראש בקצה הספסל.","אחזו במוט באחיזה עליונה, כשהידיים ברוחב הכתפיים, ויישרו את הידיים ישר מעל החזה.","תוך שמירה על הזרוע העליונה ללא תזוזה, הורידו לאט את המוט מאחורי הראש על ידי כפיפת המרפקים.","עצרו לרגע, ולאחר מכן יישרו את הידיים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Hold a barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest.","Keeping your upper arms stationary, slowly lower the barbell behind your head by bending your elbows.","Pause for a moment, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"yg8Totb"},{"id":"edb-0055","name":"לחיצה אחיזה צרה בשכיבה עם מוט","name_en":"barbell lying close-grip press","muscle":"triceps","equipment":"barbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["שכבו על ספסל כשכפות הרגליים שטוחות על הרצפה והגב צמוד לספסל.","אחזו במוט באחיזה צרה, כשהידיים ברוחב הכתפיים וכפות הידיים פונות לכיוון הרגליים.","הרימו את המוט מהמעמד והחזיקו אותו ישר מעל החזה כשהידיים מיושרות לגמרי.","הורידו לאט את המוט לכיוון החזה, כשהמרפקים צמודים לגוף.","עצרו לרגע כשהמוט נוגע בחזה, ולאחר מכן דחפו אותו בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with a close grip, hands shoulder-width apart, palms facing towards your feet.","Lift the barbell off the rack and hold it directly above your chest with your arms fully extended.","Slowly lower the barbell towards your chest, keeping your elbows close to your body.","Pause for a moment when the barbell touches your chest, then push it back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"EcaV7aL"},{"id":"edb-0056","name":"פשיטת מרפק אחיזה צרה בשכיבה עם מוט","name_en":"barbell lying close-grip triceps extension","muscle":"triceps","equipment":"barbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שכבו על הגב על ספסל, כשכפות הרגליים שטוחות על הרצפה והראש בקצה הספסל.","אחזו במוט באחיזה צרה, כשהידיים ברוחב הכתפיים וכפות הידיים פונות למעלה.","יישרו את הידיים לגמרי, תוך הרמת המוט מעל החזה.","תוך שמירה על הזרוע העליונה ללא תזוזה, הורידו לאט את המוט לכיוון המצח על ידי כפיפת המרפקים.","עצרו לרגע בתחתית התנועה, ולאחר מכן יישרו את הידיים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Grasp the barbell with a close grip, hands shoulder-width apart, palms facing up.","Extend your arms fully, lifting the barbell above your chest.","Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows.","Pause for a moment at the bottom, then extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"HJ63mSO"},{"id":"edb-0057","name":"פשיטה בשכיבה עם מוט","name_en":"barbell lying extension","muscle":"triceps","equipment":"barbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שכבו על הגב על ספסל, כשכפות הרגליים שטוחות על הרצפה והראש בקצה הספסל.","אחזו במוט באחיזה עליונה, כשהידיים ברוחב הכתפיים, ויישרו את הידיים ישר מעל החזה.","תוך שמירה על הזרוע העליונה ללא תזוזה, הורידו לאט את המוט לכיוון המצח על ידי כפיפת המרפקים.","עצרו לרגע, ולאחר מכן יישרו את הידיים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Hold the barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest.","Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows.","Pause for a moment, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"EMpUwRI"},{"id":"edb-0058","name":"barbell lying lifting (on hip)","name_en":"barbell lying lifting (on hip)","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps"],"steps":["שכבו על הגב על ספסל, כשכפות הרגליים שטוחות על הרצפה והברכיים כפופות.","אחזו במוט באחיזה עליונה ומקמו אותו על האגן.","תוך הפעלת שרירי הישבן, הרימו את האגן מהספסל עד שהגוף יוצר קו ישר מהברכיים ועד הכתפיים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הירכיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back on a bench with your feet flat on the ground and your knees bent.","Hold the barbell with an overhand grip and position it on your hips.","Engaging your glutes, lift your hips off the bench until your body forms a straight line from your knees to your shoulders.","Pause for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"SNFfUff"},{"id":"edb-0059","name":"כפיפת מרפק בכיסא הטפה בשכיבה עם מוט","name_en":"barbell lying preacher curl","muscle":"biceps","equipment":"barbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל פריצ'ר כשהחזה נשען על הכרית והידיים מושטות מעל הקצה, כשאתם אוחזים במוט באחיזה תחתונה.","תוך שמירה על הזרוע העליונה ללא תזוזה, נשפו החוצה וכופפו את המשקולות תוך כיווץ שרירי הביצפס.","המשיכו להרים את המוט עד ששרירי הביצפס מכווצים לגמרי והמוט בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a preacher bench with your chest against the pad and your arms extended over the edge, holding a barbell with an underhand grip.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the bar until your biceps are fully contracted and the bar is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"SYJ4Bkt"},{"id":"edb-0061","name":"סקאל קראשר","name_en":"barbell lying triceps extension","muscle":"triceps","equipment":"barbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שכבו על הגב על ספסל, כשכפות הרגליים שטוחות על הרצפה והראש בקצה הספסל.","אחזו במוט באחיזה עליונה, כשהידיים ברוחב הכתפיים, ויישרו את הידיים ישר מעל החזה.","תוך שמירה על הזרוע העליונה ללא תזוזה, הורידו לאט את המוט לכיוון המצח על ידי כפיפת המרפקים.","עצרו לרגע בתחתית התנועה, ולאחר מכן יישרו את הידיים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Hold the barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest.","Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows.","Pause for a moment at the bottom, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"iZop9xO"},{"id":"edb-0060","name":"פשיטת מרפק בשכיבה עם מוט","name_en":"barbell lying triceps extension skull crusher","muscle":"triceps","equipment":"barbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שכבו על הגב על ספסל, כשכפות הרגליים שטוחות על הרצפה והראש בקצה הספסל.","אחזו במוט באחיזה עליונה, כשהידיים ברוחב הכתפיים, ויישרו את הידיים ישר מעל החזה.","תוך שמירה על הזרוע העליונה ללא תזוזה, הורידו לאט את המוט לכיוון המצח על ידי כפיפת המרפקים.","עצרו לרגע כשהמוט נמצא מעט מעל המצח, ולאחר מכן יישרו את הידיים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Hold the barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest.","Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows.","Pause for a moment when the barbell is just above your forehead, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"h8LFzo9"},{"id":"edb-0063","name":"סקוואט צר עם מוט","name_en":"barbell narrow stance squat","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והבהונות פונות מעט החוצה.","אחזו במוט על הגב העליון, כשהוא מונח על שרירי הטרפז או הדלטואיד האחורי.","הפעילו את שרירי הליבה ושמרו על החזה זקוף תוך הורדה לאטה של הגוף על ידי כפיפת הברכיים ודחיפת האגן אחורה.","המשיכו לרדת עד שהירכיים מקבילות לרצפה או מעט מתחת לכך.","עצרו לרגע, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and toes pointing slightly outward.","Hold the barbell across your upper back, resting it on your traps or rear delts.","Engage your core and keep your chest up as you slowly lower your body by bending your knees and pushing your hips back.","Continue lowering until your thighs are parallel to the ground or slightly below.","Pause for a moment, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"elhhVgj"},{"id":"edb-0064","name":"חתירה בהטיה ביד אחת עם מוט","name_en":"barbell one arm bent over row","muscle":"back","equipment":"barbell","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, הברכיים כפופות מעט, ואחזו במוט ביד אחת באחיזה עליונה.","התכופפו קדימה באגן, תוך שמירה על גב ישר וראש בתנוחה נייטרלית.","משכו את המוט כלפי מעלה לכיוון החזה, כשהמרפק צמוד לגוף ותוך כיווץ השכמות זו לזו.","הורידו את המוט בחזרה למצב ההתחלתי באופן מבוקר.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ליד השנייה."],"steps_en":["Stand with your feet shoulder-width apart, knees slightly bent, and hold a barbell with one hand using an overhand grip.","Bend forward at the hips, keeping your back straight and your head in a neutral position.","Pull the barbell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together.","Lower the barbell back down to the starting position in a controlled manner.","Repeat for the desired number of repetitions, then switch to the other arm."],"mediaId":"Jsgsc27"},{"id":"edb-0065","name":"לחיצה מהרצפה ביד אחת עם מוט","name_en":"barbell one arm floor press","muscle":"triceps","equipment":"barbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["שכבו על הגב על הרצפה, כשהברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","אחזו במוט ביד אחת, כשכף היד פונה למעלה, ויישרו את הזרוע ישר מעל החזה.","הורידו לאט את המוט לכיוון החזה, כשהמרפק צמוד לגוף.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו את המוט בחזרה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Lie flat on your back on the floor with your knees bent and feet flat on the ground.","Hold the barbell with one hand, palm facing up, and extend your arm straight up over your chest.","Slowly lower the barbell towards your chest, keeping your elbow close to your body.","Pause for a moment at the bottom, then push the barbell back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"vtusOWT"},{"id":"edb-0066","name":"דדליפט ביד אחת צדי עם מוט","name_en":"barbell one arm side deadlift","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps","lower back"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים במוט ביד אחת באחיזה עליונה.","שמרו על גב ישר ושרירי ליבה מופעלים.","התכופפו באגן והורידו את המוט לכיוון החלק החיצוני של הרגל, כשהזרוע נשארת ישרה והחזה זקוף.","הורידו את המוט עד כמה שניתן תוך שמירה על טכניקה נכונה.","עצרו לרגע, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Stand with your feet shoulder-width apart, holding a barbell in one hand with an overhand grip.","Keep your back straight and your core engaged.","Bend at the hips and lower the barbell towards the outside of your leg, keeping your arm straight and your chest up.","Lower the barbell as far as you can while maintaining good form.","Pause for a moment, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"2DxtqHL"},{"id":"edb-0067","name":"סנאץ׳ ביד אחת עם מוט","name_en":"barbell one arm snatch","muscle":"shoulders","equipment":"barbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","forearms","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והבהונות פונות מעט החוצה.","אחזו במוט באחיזה עליונה, כשהידיים מעט רחבות יותר מרוחב הכתפיים.","כופפו את הברכיים והורידו את האגן לתנוחת סקוואט, תוך שמירה על גב ישר וחזה זקוף.","יישרו בעוצמה את האגן, הברכיים והקרסוליים, תוך דחיפת המוט כלפי מעלה.","כשהמוט מגיע לגובה החזה, משכו אותו כלפי מעלה עם הזרוע, תוך שמירה עליו קרוב לגוף.","סובבו את המרפק מתחת למוט ויישרו את הזרוע לגמרי מעל הראש, תוך נעילת המרפק.","הורידו את המוט בחזרה למצב ההתחלתי באופן מבוקר.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Stand with your feet shoulder-width apart, toes pointing slightly outwards.","Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Bend your knees and lower your hips into a squat position, keeping your back straight and chest up.","Explosively extend your hips, knees, and ankles, driving the barbell upwards.","As the barbell reaches chest level, pull it upwards with your arm, keeping it close to your body.","Rotate your elbow under the barbell and extend your arm fully overhead, locking out your elbow.","Lower the barbell back down to the starting position in a controlled manner.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"xHKN2s8"},{"id":"edb-0068","name":"סקוואט ברגל אחת עם מוט","name_en":"barbell one leg squat","muscle":"legs","equipment":"barbell","target":"quads","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו במוט על הגב העליון.","הרימו רגל אחת מהרצפה ויישרו אותה קדימה, כשהיא מקבילה לרצפה.","כופפו את רגל התמיכה והורידו את הגוף כאילו אתם מתיישבים על כיסא, תוך שמירה על החזה זקוף והגב ישר.","רדו עד שהירך מקבילה לרצפה, ולאחר מכן דחפו דרך העקב כדי לחזור למצב ההתחלתי.","חזרו על התנועה למספר החזרות הרצוי, ולאחר מכן החליפו רגליים וחזרו שוב."],"steps_en":["Stand with your feet shoulder-width apart and hold a barbell across your upper back.","Lift one foot off the ground and extend it forward, keeping it parallel to the ground.","Bend your standing leg and lower your body down as if sitting back into a chair, keeping your chest up and your back straight.","Lower yourself until your thigh is parallel to the ground, then push through your heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs and repeat."],"mediaId":"uKyN64F"},{"id":"edb-0069","name":"סקוואט מעל הראש עם מוט","name_en":"barbell overhead squat","muscle":"legs","equipment":"barbell","target":"quads","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings","calves","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והבהונות פונות מעט החוצה.","אחזו במוט באחיזה רחבה, ומקמו אותו מעל הראש כשהידיים מיושרות לגמרי.","הפעילו את שרירי הליבה והורידו את הגוף לתנוחת סקוואט, תוך שמירה על החזה זקוף והברכיים בקו עם הבהונות.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and toes slightly turned out.","Hold the barbell with a wide grip, positioning it overhead with your arms fully extended.","Engage your core and lower your body down into a squat position, keeping your chest up and knees tracking over your toes.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"gfk9kD4"},{"id":"edb-1411","name":"כפיפת שורש כף היד עם מוט","name_en":"barbell palms down wrist curl over a bench","muscle":"biceps","equipment":"barbell","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["biceps","brachialis"],"steps":["שבו על ספסל כשכפות הרגליים שטוחות על הרצפה והאמות נשענות על הירכיים, כשכפות הידיים פונות מטה.","אחזו במוט באחיזה עליונה, כשהידיים ברוחב הכתפיים.","הורידו את המוט לכיוון הרצפה על ידי כיפוף שורשי כף היד, כשהאמות נשארות ללא תזוזה.","עצרו לרגע בתחתית התנועה, ולאחר מכן הרימו לאט את המוט בחזרה על ידי יישור שורשי כף היד.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your feet flat on the ground and your forearms resting on your thighs, palms facing down.","Hold a barbell with an overhand grip, hands shoulder-width apart.","Lower the barbell towards the ground by flexing your wrists, keeping your forearms stationary.","Pause for a moment at the bottom, then slowly raise the barbell back up by extending your wrists.","Repeat for the desired number of repetitions."],"mediaId":"yzYH9pI"},{"id":"edb-1412","name":"כפיפת שורש כף היד עם מוט","name_en":"barbell palms up wrist curl over a bench","muscle":"biceps","equipment":"barbell","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["biceps","shoulders"],"steps":["שבו על ספסל כשכפות הרגליים שטוחות על הרצפה ואחזו במוט באחיזה תחתונה, כשכפות הידיים פונות למעלה.","הניחו את האמות על הספסל, כששורשי כף היד תלויים מעבר לקצה.","תוך שמירה על האמות ללא תזוזה, נשפו החוצה וכופפו את שורשי כף היד כלפי מעלה עד כמה שניתן.","החזיקו את התנוחה המכווצת לרגע קצר, ולאחר מכן שאפו אוויר והורידו לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your feet flat on the ground and hold a barbell with an underhand grip, palms facing up.","Rest your forearms on the bench, allowing your wrists to hang off the edge.","Keeping your forearms stationary, exhale and curl your wrists upwards as far as possible.","Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"SJAA2IQ"},{"id":"edb-3017","name":"חתירה עם מוט","name_en":"barbell pendlay row","muscle":"back","equipment":"barbell","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","התכופפו קדימה באגן, תוך שמירה על גב ישר וחזה זקוף.","אחזו במוט באחיזה עליונה, מעט רחבה יותר מרוחב הכתפיים.","משכו את המוט לכיוון הבטן העליונה, תוך כיווץ השכמות זו לזו.","הורידו את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your knees slightly bent.","Bend forward at the hips, keeping your back straight and your chest up.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Pull the barbell towards your upper abdomen, squeezing your shoulder blades together.","Lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"r0z6xzQ"},{"id":"edb-1751","name":"barbell pin presses","name_en":"barbell pin presses","muscle":"triceps","equipment":"barbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["הציבו מוט על מעמד כוח בגובה החזה.","עמדו מול המוט ומקמו את עצמכם מתחתיו, עם הרגליים ברוחב הכתפיים.","אחזו במוט באחיזה עליונה, מעט רחבה יותר מרוחב הכתפיים.","הרימו את המוט מהמעמד והחזיקו אותו ישר מעל החזה, כשהידיים מיושרות לגמרי.","הורידו את המוט לכיוון החזה, כשהמרפקים צמודים לגוף.","עצרו לרגע כשהמוט נוגע בחזה.","דחפו את המוט בחזרה למצב ההתחלתי, תוך יישור מלא של הידיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up a barbell on a power rack at chest height.","Stand facing the barbell and position yourself underneath it, with your feet shoulder-width apart.","Grip the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lift the barbell off the rack and hold it directly above your chest, with your arms fully extended.","Lower the barbell down towards your chest, keeping your elbows tucked in close to your body.","Pause for a moment when the barbell touches your chest.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"bndCa3Q"},{"id":"edb-0070","name":"כפיפת מרפק בכיסא הטפה עם מוט","name_en":"barbell preacher curl","muscle":"biceps","equipment":"barbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל פריצ'ר כשהזרוע העליונה נשענת על הכרית והחזה נשען על התומך.","אחזו במוט באחיזה תחתונה, מעט רחבה יותר מרוחב הכתפיים.","תוך שמירה על הזרוע העליונה ללא תזוזה, נשפו החוצה וכופפו את המוט כלפי מעלה לכיוון הכתפיים.","עצרו לרגע בשיא התנועה, תוך כיווץ שרירי הביצפס.","שאפו אוויר והורידו לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a preacher bench with your upper arms resting on the pad and your chest against the support.","Grasp the barbell with an underhand grip, slightly wider than shoulder-width apart.","Keeping your upper arms stationary, exhale and curl the barbell up towards your shoulders.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"qOgPVf6"},{"id":"edb-0071","name":"כפיפת בטן מלאה עם מוט","name_en":"barbell press sit-up","muscle":"core","equipment":"barbell","target":"abs","bodyPart":"waist","secondaryMuscles":["shoulders","chest"],"steps":["שכבו על הגב על מזרן, כשהברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","אחזו במוט באחיזה עליונה, כשהוא מונח על החזה.","תוך הפעלת שרירי הבטן, הרימו לאט את פלג הגוף העליון מהרצפה, בכיפוף קדימה עד שהגו נמצא בזווית של 45 מעלות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back on a mat with your knees bent and feet flat on the ground.","Hold the barbell with an overhand grip, resting it on your chest.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"wnEscH8"},{"id":"edb-0072","name":"כפיפת מרפק בשיפוע בשכיבה על הבטן עם מוט","name_en":"barbell prone incline curl","muscle":"biceps","equipment":"barbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["הציבו ספסל בשיפוע עולה בזווית של 45 מעלות.","שכבו על הבטן על הספסל, כשהחזה והבטן נשענים עליו.","אחזו במוט באחיזה תחתונה, ברוחב הכתפיים.","יישרו את הזרועות במלואן, כך שהמוט ייתלה כלפי הרצפה.","תוך שמירה על הזרוע העליונה ללא תזוזה, נשפו החוצה וכופפו את המשקולות תוך כיווץ שרירי הביצפס.","המשיכו להרים את המוט עד ששרירי הביצפס מכווצים לגמרי והמוט בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up an incline bench at a 45-degree angle.","Lie face down on the bench with your chest and stomach resting against it.","Hold a barbell with an underhand grip, shoulder-width apart.","Extend your arms fully, allowing the barbell to hang down towards the floor.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the barbell until your biceps are fully contracted and the bar is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"WLvTAv5"},{"id":"edb-0073","name":"פולאובר עם מוט","name_en":"barbell pullover","muscle":"back","equipment":"barbell","target":"lats","bodyPart":"back","secondaryMuscles":["chest","triceps"],"steps":["שכבו על הגב על ספסל, עם הראש בקצה אחד והרגליים על הרצפה.","אחזו במוט באחיזה ברוחב הכתפיים ויישרו את הידיים ישר מעל החזה.","תוך שמירה על זרועות ישרות, הורידו את המוט מאחורי הראש בצורה מבוקרת עד שתרגישו מתיחה בשריר הרחב הגבי.","עצרו לרגע, ולאחר מכן הרימו את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your head at one end and your feet on the floor.","Hold a barbell with a shoulder-width grip and extend your arms straight above your chest.","Keeping your arms straight, lower the barbell behind your head in a controlled manner until you feel a stretch in your lats.","Pause for a moment, then raise the barbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"i6LWjok"},{"id":"edb-0022","name":"פולאובר עם מוט","name_en":"barbell pullover to press","muscle":"back","equipment":"barbell","target":"lats","bodyPart":"back","secondaryMuscles":["triceps","chest","shoulders"],"steps":["שכבו ישר על ספסל כאשר הראש בקצה אחד והרגליים על הרצפה.","אחזו את המוט באחיזה פרונטלית (כפות הידיים פונות הרחק מכם) ויישרו את הזרועות מעל החזה.","תוך שמירה על זרועות ישרות, הורידו את המוט מאחורי הראש בתנועה קשתית עד שתרגישו מתיחה בשריר הרחב הגבי.","עצרו לרגע, ולאחר מכן הפכו את התנועה ודחפו את המוט חזרה למצב ההתחלתי מעל החזה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your head at one end and your feet on the ground.","Hold the barbell with a pronated grip (palms facing away from you) and extend your arms straight above your chest.","Keeping your arms straight, lower the barbell behind your head in an arc-like motion until you feel a stretch in your lats.","Pause for a moment, then reverse the motion and press the barbell back to the starting position above your chest.","Repeat for the desired number of repetitions."],"mediaId":"znLogoF"},{"id":"edb-0074","name":"barbell rack pull","name_en":"barbell rack pull","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","lower back"],"steps":["הניחו מוט על מתקן בגובה הברכיים.","עמדו עם הרגליים ברוחב הכתפיים והבהונות פונות מעט החוצה.","כופפו את הירכיים והברכיים כדי לרדת ואחזו את המוט באחיזה עלית, כאשר הידיים במרחק רוחב הכתפיים.","הפעילו את שרירי הליבה והרימו את המוט על ידי יישור הירכיים והברכיים, משכו את הכתפיים לאחור וכווצו את שרירי הישבן בשיא התנועה.","הורידו את המוט חזרה למצב ההתחלתי על ידי כיפוף הירכיים והברכיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up a barbell on a rack at knee height.","Stand with your feet shoulder-width apart, toes pointing slightly outwards.","Bend at the hips and knees to lower yourself down and grip the barbell with an overhand grip, hands shoulder-width apart.","Engage your core and lift the barbell by extending your hips and knees, pulling your shoulders back and squeezing your glutes at the top.","Lower the barbell back down to the starting position by bending at the hips and knees.","Repeat for the desired number of repetitions."],"mediaId":"za9Ni4z"},{"id":"edb-0075","name":"הרמה אחורי עם מוט","name_en":"barbell rear delt raise","muscle":"shoulders","equipment":"barbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","rhomboids"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו במוט באחיזה עליונה, כשכפות הידיים פונות מטה.","כופפו מעט את הברכיים והטו את הגוף קדימה במפרקי הירך, תוך שמירה על גב ישר.","הרימו את המוט הצידה, תוך שמירה על זרועות ישרות, עד שהן מקבילות לרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, palms facing down.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Raise the barbell out to the sides, keeping your arms straight, until they are parallel to the ground.","Pause for a moment at the top, then slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Ln9iTbU"},{"id":"edb-0076","name":"חתירת כתף אחורית עם מוט","name_en":"barbell rear delt row","muscle":"shoulders","equipment":"barbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","rhomboids","biceps"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","אחזו מוט באחיזה עלית, כאשר הידיים מעט רחבות יותר מרוחב הכתפיים.","התכופפו קדימה מהירכיים, תוך שמירה על גב ישר וחזה מורם.","משכו את המוט לכיוון החזה, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and knees slightly bent.","Hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Bend forward at the hips, keeping your back straight and chest up.","Pull the barbell towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"S9zHIvU"},{"id":"edb-0078","name":"לאנג׳ אחורי עם מוט","name_en":"barbell rear lunge","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["התחילו בעמידה עם הרגליים ברוחב הכתפיים והמוט מונח על הגב העליון.","צעדו צעד אחורה עם הרגל הימנית, ונחתו על כרית כף הרגל.","כופפו את שתי הברכיים כדי להוריד את הגוף עד שהירך השמאלית מקבילה לרצפה.","דחפו דרך העקב השמאלי כדי לחזור למצב ההתחלתי.","חזרו עם הרגל השנייה."],"steps_en":["Start by standing with your feet shoulder-width apart and a barbell resting on your upper back.","Take a step backward with your right foot, landing on the ball of your foot.","Bend both knees to lower your body until your left thigh is parallel to the ground.","Push through your left heel to return to the starting position.","Repeat with the other leg."],"mediaId":"VaP75jl"},{"id":"edb-0077","name":"לאנג׳ אחורי עם מוט","name_en":"barbell rear lunge v. 2","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו במוט על הגב העליון.","צעדו צעד אחורה עם הרגל הימנית, ונחתו על כרית כף הרגל.","כופפו את שתי הברכיים כדי להוריד את הגוף עד שהירך השמאלית מקבילה לרצפה.","דחפו דרך העקב השמאלי כדי לחזור למצב ההתחלתי.","חזרו עם הרגל השנייה."],"steps_en":["Stand with your feet shoulder-width apart and hold a barbell across your upper back.","Take a step backward with your right foot, landing on the ball of your foot.","Bend both knees to lower your body until your left thigh is parallel to the ground.","Push through your left heel to return to the starting position.","Repeat with the other leg."],"mediaId":"62Nw60O"},{"id":"edb-0079","name":"כפיפת שורש כף היד עם מוט","name_en":"barbell revers wrist curl v. 2","muscle":"biceps","equipment":"barbell","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["biceps","brachialis"],"steps":["שבו על ספסל כשכפות הרגליים שטוחות על הרצפה והברכיים כפופות.","אחזו מוט באחיזה עלית, כפות הידיים פונות מטה, במרחק רוחב הכתפיים.","הניחו את האמות על הירכיים כך שפרקי הידיים תלויים מעבר לקצה.","תוך שמירה על האמות ללא תנועה, נשפו וכופפו את פרקי הידיים כלפי מעלה עד כמה שניתן.","החזיקו את התנוחה המכווצת לרגע קצר, ולאחר מכן שאפו אוויר והורידו לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your feet flat on the ground and your knees bent.","Hold a barbell with an overhand grip, palms facing down, and your hands shoulder-width apart.","Rest your forearms on your thighs, allowing your wrists to hang off the edge.","Keeping your forearms stationary, exhale and curl your wrists upward as far as possible.","Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"qDnGfDb"},{"id":"edb-2187","name":"לחיצת חזה אחיזה צרה הפוך עם מוט","name_en":"barbell reverse close-grip bench press","muscle":"triceps","equipment":"barbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["שכבו על ספסל כשכפות הרגליים שטוחות על הרצפה והגב צמוד לספסל.","אחזו את המוט באחיזה הפוכה, כאשר הידיים במרחק רוחב הכתפיים.","הרימו את המוט מהמעמד והחזיקו אותו ישר מעל החזה כשהידיים מיושרות לגמרי.","הורידו את המוט באיטיות לכיוון החזה, תוך שמירה על המרפקים קרובים לגוף.","עצרו לרגע כאשר המוט נמצא ממש מעל החזה.","דחפו את המוט בחזרה למצב ההתחלתי, תוך יישור מלא של הידיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with a reverse grip, hands shoulder-width apart.","Lift the barbell off the rack and hold it directly above your chest with your arms fully extended.","Slowly lower the barbell down towards your chest, keeping your elbows close to your body.","Pause for a moment when the barbell is just above your chest.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"YqJw82s"},{"id":"edb-0080","name":"כפיפת מרפק הפוך עם מוט","name_en":"barbell reverse curl","muscle":"biceps","equipment":"barbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף עם הרגליים במרחק רוחב הכתפיים ואחזו מוט באחיזה עלית, כפות הידיים פונות מטה.","שמרו על הזרוע העליונה ללא תנועה ונשפו תוך כדי כיפוף המוט כלפי מעלה, תוך כיווץ שריר הביצפס.","המשיכו להרים את המוט עד ששריר הביצפס מכווץ במלואו והמוט נמצא בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר תוך כדי הורדת המוט באיטיות חזרה למצב ההתחלתי, תוך שמירה על הזרוע העליונה ללא תנועה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand up straight with your feet shoulder-width apart and hold a barbell with an overhand grip, palms facing down.","Keep your upper arms stationary and exhale as you curl the barbell upward, contracting your biceps.","Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale as you slowly lower the barbell back to the starting position, keeping your upper arms stationary.","Repeat for the desired number of repetitions."],"mediaId":"xNrS20v"},{"id":"edb-0118","name":"חתירה בהטיה אחיזה הפוכה עם מוט","name_en":"barbell reverse grip bent over row","muscle":"back","equipment":"barbell","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","אחזו מוט באחיזה עלית, כפות הידיים פונות מטה, כאשר הידיים מעט רחבות יותר מרוחב הכתפיים.","התכופפו קדימה מהירכיים, תוך שמירה על גב ישר וחזה מורם, עד שפלג הגוף העליון כמעט מקביל לרצפה.","משכו את המוט לכיוון החלק התחתון של החזה, תוך כיווץ השכמות יחד.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and knees slightly bent.","Hold a barbell with an overhand grip, palms facing down, and hands slightly wider than shoulder-width apart.","Bend forward at the hips, keeping your back straight and chest up, until your torso is almost parallel to the floor.","Pull the barbell towards your lower chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"SzX3uzM"},{"id":"edb-1256","name":"לחיצת חזה בשיפוע שלילי אחיזה הפוכה עם מוט","name_en":"barbell reverse grip decline bench press","muscle":"chest","equipment":"barbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["שכבו על ספסל בשיפוע יורד עם הרגליים מקובעות והראש נמוך יותר מהאגן.","אחזו את המוט באחיזה הפוכה, מעט רחבה יותר מרוחב הכתפיים.","הרימו את המוט מהמעמד והורידו אותו לאט לכיוון החזה, כשהמרפקים צמודים לגוף.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie on a decline bench with your feet secured and your head lower than your hips.","Grasp the barbell with a reverse grip, slightly wider than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in.","Pause for a moment at the bottom, then push the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"DotAgEF"},{"id":"edb-1257","name":"לחיצת חזה בשיפוע אחיזה הפוכה עם מוט","name_en":"barbell reverse grip incline bench press","muscle":"chest","equipment":"barbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["הציבו ספסל בשיפוע עולה בזווית של 45 מעלות.","שכבו על הספסל עם כפות הרגליים שטוחות על הרצפה.","אחזו את המוט באחיזה הפוכה, כאשר הידיים מעט רחבות יותר מרוחב הכתפיים.","הרימו את המוט מהמעמד והורידו אותו לאט לכיוון החזה, כשהמרפקים צמודים לגוף.","עצרו לרגע כשהמוט נוגע בחזה.","דחפו את המוט בחזרה למצב ההתחלתי, תוך יישור מלא של הידיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up an incline bench at a 45-degree angle.","Lie down on the bench with your feet flat on the ground.","Grasp the barbell with a reverse grip, hands slightly wider than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in.","Pause for a moment when the barbell touches your chest.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"DU7I633"},{"id":"edb-1317","name":"חתירה אחיזה הפוכה בשיפוע עם מוט","name_en":"barbell reverse grip incline bench row","muscle":"back","equipment":"barbell","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["הציבו ספסל בשיפוע עולה בזווית של 45 מעלות.","שבו על הספסל כשאתם פונים למשענת והחזה נצמד אליה.","אחזו את המוט באחיזה הפוכה (כפות הידיים פונות מטה) כאשר הידיים מעט רחבות יותר מרוחב הכתפיים.","שמרו על גב ישר ושרירי ליבה פעילים.","משכו את המוט לכיוון הבטן העליונה, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה.","הורידו את המוט באיטיות חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up an incline bench at a 45-degree angle.","Sit on the bench facing the backrest with your chest against it.","Grab the barbell with a reverse grip (palms facing down) and hands slightly wider than shoulder-width apart.","Keep your back straight and core engaged.","Pull the barbell towards your upper abdomen, squeezing your shoulder blades together.","Pause for a moment at the top of the movement.","Slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"8d8qJQI"},{"id":"edb-1721","name":"barbell reverse grip skullcrusher","name_en":"barbell reverse grip skullcrusher","muscle":"triceps","equipment":"barbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שכבו על הגב על ספסל, כשכפות הרגליים שטוחות על הרצפה והראש בקצה הספסל.","אחזו את המוט באחיזה הפוכה, כפות הידיים פונות לכיוון הפנים, במרחק רוחב הכתפיים.","יישרו את הזרועות כלפי מעלה מעל החזה, תוך שמירה על המרפקים קרובים לגוף ופרקי הידיים ישרים.","הורידו את המוט באיטיות לכיוון המצח על ידי כיפוף המרפקים, תוך שמירה על הזרוע העליונה ללא תנועה.","עצרו לרגע בתחתית התנועה, ולאחר מכן יישרו את הידיים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Hold the barbell with a reverse grip, palms facing towards your face, and your hands shoulder-width apart.","Extend your arms straight up over your chest, keeping your elbows in and your wrists straight.","Slowly lower the barbell towards your forehead by bending your elbows, keeping your upper arms stationary.","Pause for a moment at the bottom, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"yRLPCLu"},{"id":"edb-0081","name":"כפיפת מרפק בכיסא הטפה הפוך עם מוט","name_en":"barbell reverse preacher curl","muscle":"biceps","equipment":"barbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל פריצ'ר כשהחזה נצמד לכרית והזרועות ישרות כלפי מטה, אוחזים מוט באחיזה עלית.","תוך שמירה על הזרוע העליונה ללא תנועה, נשפו וכופפו את המוט כלפי מעלה תוך כיווץ שריר הביצפס.","המשיכו להרים את המוט עד ששריר הביצפס מכווץ במלואו והמוט נמצא בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והורידו את המוט באיטיות חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a preacher bench with your chest against the pad and your arms extended straight down, holding a barbell with an overhand grip.","Keeping your upper arms stationary, exhale and curl the barbell upward while contracting your biceps.","Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"4LIG9xr"},{"id":"edb-0082","name":"כפיפת שורש כף היד הפוך עם מוט","name_en":"barbell reverse wrist curl","muscle":"biceps","equipment":"barbell","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["biceps","brachialis"],"steps":["שבו על ספסל כשכפות הרגליים שטוחות על הרצפה ואחזו מוט באחיזה עלית, כפות הידיים פונות מטה.","הניחו את האמות על הירכיים כך שפרקי הידיים תלויים מעבר לקצה.","כופפו את פרקי הידיים כלפי מעלה באיטיות, תוך קירוב המוט לגוף.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your feet flat on the ground and hold a barbell with an overhand grip, palms facing down.","Rest your forearms on your thighs, allowing your wrists to hang off the edge.","Slowly curl your wrists upward, bringing the barbell towards your body.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"LsZkfU6"},{"id":"edb-0084","name":"barbell rollerout","name_en":"barbell rollerout","muscle":"core","equipment":"barbell","target":"abs","bodyPart":"waist","secondaryMuscles":["lower back"],"steps":["כרעו על הרצפה ואחזו מוט בשתי הידיים, במרחק רוחב הכתפיים.","גלגלו את המוט קדימה, תוך יישור הזרועות ושמירה על שרירי הליבה פעילים.","המשיכו לגלגל קדימה עד שהגוף מיושר לחלוטין והזרועות מעל הראש.","עצרו לרגע, ולאחר מכן גלגלו את המוט באיטיות חזרה לכיוון הברכיים, תוך שמירה על שליטה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Kneel on the floor and hold a barbell with both hands, shoulder-width apart.","Roll the barbell forward, extending your arms and keeping your core engaged.","Continue rolling forward until your body is fully extended and your arms are overhead.","Pause for a moment, then slowly roll the barbell back towards your knees, maintaining control.","Repeat for the desired number of repetitions."],"mediaId":"7M66AVi"},{"id":"edb-0083","name":"barbell rollerout from bench","name_en":"barbell rollerout from bench","muscle":"core","equipment":"barbell","target":"abs","bodyPart":"waist","secondaryMuscles":["shoulders","triceps"],"steps":["התחילו בכריעה על הרצפה כאשר המוט מונח על ספסל לפניכם.","אחזו במוט באחיזה עליונה, מעט רחבה יותר מרוחב הכתפיים.","תוך שמירה על שרירי הליבה פעילים וגב ישר, גלגלו את המוט קדימה באיטיות, תוך יישור הזרועות לפניכם.","המשיכו לגלגל את המוט קדימה עד שהגוף מיושר לחלוטין והזרועות מעל הראש.","עצרו לרגע במצב היישור המלא, ולאחר מכן גלגלו את המוט באיטיות חזרה לכיוון הגוף, וחזרו למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by kneeling on the floor with a barbell placed on a bench in front of you.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Keeping your core engaged and your back straight, slowly roll the barbell forward, extending your arms in front of you.","Continue rolling the barbell forward until your body is fully extended and your arms are overhead.","Pause for a moment at the fully extended position, then slowly roll the barbell back towards your body, returning to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Gxg9lDc"},{"id":"edb-0085","name":"דדליפט רומני","name_en":"barbell romanian deadlift","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","lower back"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים ואצבעות הרגליים פונות קדימה.","אחזו במוט באחיזה עליונה, כשהידיים מעט רחבות יותר מרוחב הכתפיים.","כופפו מהירכיים, תוך שמירה על גב ישר וברכיים כפופות מעט.","הורידו את המוט לכיוון הרצפה, תוך שמירה עליו קרוב לגוף.","הרגישו את המתיחה בשרירי הירך האחוריים תוך כדי הורדת המוט.","ברגע שאתם מרגישים מתיחה בשרירי הירך האחוריים, דחפו את הירכיים קדימה ועמדו זקוף.","כווצו את שרירי הישבן בשיא התנועה.","הורידו את המוט בחזרה למצב ההתחלתי וחזרו על התנועה למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your toes pointing forward.","Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Bend at the hips, keeping your back straight and your knees slightly bent.","Lower the barbell towards the ground, keeping it close to your body.","Feel the stretch in your hamstrings as you lower the barbell.","Once you feel a stretch in your hamstrings, push your hips forward and stand up straight.","Squeeze your glutes at the top of the movement.","Lower the barbell back down to the starting position and repeat for the desired number of repetitions."],"mediaId":"wQ2c4XD"},{"id":"edb-0086","name":"לחיצה צבאית מאחורי העורף בישיבה עם מוט","name_en":"barbell seated behind head military press","muscle":"shoulders","equipment":"barbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["שבו על ספסל עם גב ישר וכפות רגליים שטוחות על הרצפה.","אחזו את המוט באחיזה עלית, מעט רחבה יותר מרוחב הכתפיים.","הרימו את המוט מהמתקן והורידו אותו לגובה הכתפיים, מאחורי הראש.","דחפו את המוט כלפי מעלה עד שהזרועות ישרות לחלוטין.","הורידו את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your back straight and feet flat on the ground.","Hold the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lift the barbell off the rack and bring it down to shoulder level, behind your head.","Press the barbell upward until your arms are fully extended.","Lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ngPpyRS"},{"id":"edb-0087","name":"לחיצה בישיבה עם מוט","name_en":"barbell seated bradford rocky press","muscle":"shoulders","equipment":"barbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["שבו על ספסל עם גב ישר וכפות רגליים שטוחות על הרצפה.","אחזו את המוט באחיזה עלית, מעט רחבה יותר מרוחב הכתפיים.","הרימו את המוט לגובה הכתפיים, תוך שמירה על המרפקים כפופים מעט ופונים קדימה.","דחפו את המוט מעל הראש, תוך יישור מלא של הזרועות.","הורידו את המוט חזרה לגובה הכתפיים וחזרו על התנועה למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your back straight and feet flat on the ground.","Hold the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lift the barbell to shoulder height, keeping your elbows slightly bent and pointing forward.","Press the barbell overhead, fully extending your arms.","Lower the barbell back to shoulder height and repeat for the desired number of repetitions."],"mediaId":"0dCyly0"},{"id":"edb-0088","name":"הרמת עקבים בישיבה עם מוט","name_en":"barbell seated calf raise","muscle":"legs","equipment":"barbell","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings","quadriceps"],"steps":["שבו על ספסל עם כפות הרגליים שטוחות על הרצפה והמוט מונח על הירכיים.","הניחו את כריות כפות הרגליים על משטח מוגבה, כגון קובייה או מדרגה.","הניחו את המוט לרוחב הירכיים ואחזו אותו היטב בידיים.","תוך שמירה על גב ישר ושרירי ליבה פעילים, הרימו את העקבים מהרצפה על ידי יישור הקרסוליים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקבים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your feet flat on the floor and a barbell resting on your thighs.","Place the balls of your feet on a raised platform, such as a block or step.","Position the barbell across your thighs and hold it securely with your hands.","Keeping your back straight and your core engaged, lift your heels off the ground by extending your ankles.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ktsFQAZ"},{"id":"edb-1371","name":"הרמת עקבים בישיבה עם מוט","name_en":"barbell seated calf raise","muscle":"legs","equipment":"barbell","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings"],"steps":["שבו על ספסל עם כפות הרגליים שטוחות על הרצפה והמוט מונח על הירכיים.","הניחו את כריות כפות הרגליים על משטח מוגבה, כגון קובייה או מדרגה.","הורידו את העקבים עד כמה שניתן, תוך הרגשת מתיחה בשרירי השוק.","הרימו את העקבים עד כמה שניתן, תוך כיווץ שרירי השוק.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your feet flat on the floor and a barbell resting on your thighs.","Place the balls of your feet on a raised platform, such as a block or step.","Lower your heels as far as possible, feeling a stretch in your calves.","Raise your heels as high as possible, contracting your calves.","Repeat for the desired number of repetitions."],"mediaId":"ipvgBnC"},{"id":"edb-1718","name":"פשיטת מרפק אחיזה צרה מאחורי העורף בישיבה עם מוט","name_en":"barbell seated close grip behind neck triceps extension","muscle":"triceps","equipment":"barbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שבו על ספסל עם גב ישר וכפות רגליים שטוחות על הרצפה.","אחזו את המוט באחיזה צרה מאחורי הצוואר, כפות הידיים פונות קדימה.","שמרו על המרפקים קרובים לראש והורידו את המוט באיטיות לכיוון אחורי הראש.","עצרו לרגע, ולאחר מכן יישרו את הידיים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your back straight and feet flat on the ground.","Hold the barbell with a close grip behind your neck, palms facing forward.","Keep your elbows close to your head and slowly lower the barbell towards the back of your head.","Pause for a moment, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"4CBIBOM"},{"id":"edb-0089","name":"כפיפת מרפק אחיזה צרה בישיבה עם מוט","name_en":"barbell seated close-grip concentration curl","muscle":"biceps","equipment":"barbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל עם כפות הרגליים שטוחות על הרצפה ואחזו מוט באחיזה תחתית, במרחק רוחב הכתפיים.","הניחו את הזרועות העליונות על החלק הפנימי של הירכיים, ממש מעל הברכיים, ותנו למוט להישאר תלוי לפניכם.","תוך שמירה על הזרוע העליונה ללא תנועה, נשפו וכופפו את המוט כלפי מעלה לכיוון הכתפיים, תוך כיווץ שריר הביצפס.","החזיקו את מצב הכיווץ לעצירה קצרה, ולאחר מכן שאפו אוויר והורידו את המוט באיטיות חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your feet flat on the floor and hold a barbell with an underhand grip, hands shoulder-width apart.","Rest your upper arms against your inner thighs, just above your knees, and let the barbell hang down in front of you.","Keeping your upper arms stationary, exhale and curl the barbell up towards your shoulders, contracting your biceps.","Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"1V1gj1u"},{"id":"edb-0090","name":"גוד מורנינג בישיבה עם מוט","name_en":"barbell seated good morning","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","lower back"],"steps":["שבו על ספסל עם כפות הרגליים שטוחות על הרצפה והמוט מונח על הגב העליון.","שמרו על גב ישר וחזה מורם.","התכופפו קדימה מהירכיים באיטיות, תוך הורדת פלג הגוף העליון לכיוון הרצפה.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your feet flat on the ground and a barbell resting on your upper back.","Keep your back straight and your chest up.","Slowly hinge forward at the hips, lowering your torso towards the ground.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"d960PgE"},{"id":"edb-0091","name":"לחיצה מעל הראש בישיבה עם מוט","name_en":"barbell seated overhead press","muscle":"shoulders","equipment":"barbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["שבו על ספסל עם גב ישר וכפות רגליים שטוחות על הרצפה.","אחזו את המוט באחיזה עלית, מעט רחבה יותר מרוחב הכתפיים.","הרימו את המוט מהמתקן והביאו אותו לגובה הכתפיים, כשהמרפקים כפופים וכפות הידיים פונות קדימה.","דחפו את המוט מעל הראש על ידי יישור מלא של הזרועות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המוט באיטיות חזרה לגובה הכתפיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your back straight and feet flat on the ground.","Hold the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lift the barbell off the rack and bring it to shoulder level, with your elbows bent and palms facing forward.","Press the barbell overhead by extending your arms fully.","Pause for a moment at the top, then slowly lower the barbell back to shoulder level.","Repeat for the desired number of repetitions."],"mediaId":"kTbSH9h"},{"id":"edb-0092","name":"פשיטת מרפק בישיבה מעל הראש עם מוט","name_en":"barbell seated overhead triceps extension","muscle":"triceps","equipment":"barbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שבו על ספסל עם גב ישר וכפות רגליים שטוחות על הרצפה.","אחזו מוט באחיזה עלית, כאשר הידיים במרחק רוחב הכתפיים, והרימו אותו מעל הראש.","הורידו את המוט מאחורי הראש על ידי כיפוף המרפקים, תוך שמירה על הזרועות העליונות קרובות לראש.","עצרו לרגע, ולאחר מכן יישרו את הזרועות כדי להרים את המוט חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your back straight and feet flat on the ground.","Hold a barbell with an overhand grip, hands shoulder-width apart, and raise it overhead.","Lower the barbell behind your head by bending your elbows, keeping your upper arms close to your head.","Pause for a moment, then extend your arms to raise the barbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"5uFK1xr"},{"id":"edb-0094","name":"פיתול בישיבה עם מוט","name_en":"barbell seated twist","muscle":"core","equipment":"barbell","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","lower back"],"steps":["שבו על ספסל שטוח עם כפות הרגליים שטוחות על הרצפה והברכיים כפופות.","אחזו מוט בשתי הידיים מול החזה, תוך שמירה על המרפקים כפופים מעט.","הפעילו את שרירי הליבה וסובבו את פלג הגוף העליון באיטיות לצד אחד, תוך שמירה על גב ישר.","עצרו לרגע בסוף הסיבוב, ולאחר מכן סובבו באיטיות חזרה למצב ההתחלתי.","חזרו על הסיבוב לצד השני.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Sit on a flat bench with your feet flat on the ground and your knees bent.","Hold a barbell with both hands in front of your chest, keeping your elbows slightly bent.","Engage your core and slowly twist your torso to one side, keeping your back straight.","Pause for a moment at the end of the twist, then slowly rotate back to the starting position.","Repeat the twist to the other side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"dFSNDOA"},{"id":"edb-0095","name":"משיכת כתפיים עם מוט","name_en":"barbell shrug","muscle":"back","equipment":"barbell","target":"traps","bodyPart":"back","secondaryMuscles":["shoulders"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים ואחזו מוט לפניכם באחיזה עלית.","שמרו על זרועות ישרות וגב ישר לאורך כל התרגיל.","הרימו את הכתפיים לכיוון האוזניים עד כמה שניתן, תוך כיווץ שריר הטרפז בשיא התנועה.","החזיקו לרגע, ולאחר מכן הורידו את הכתפיים באיטיות חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a barbell in front of you with an overhand grip.","Keep your arms straight and your back straight throughout the exercise.","Lift your shoulders up towards your ears as high as possible, squeezing your traps at the top.","Hold for a moment, then slowly lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"dG7tG5y"},{"id":"edb-0096","name":"barbell side bent v. 2","name_en":"barbell side bent v. 2","muscle":"core","equipment":"barbell","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","lower back"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים ואחזו מוט בשתי הידיים, כפות הידיים פונות מטה.","שמרו על גב ישר ושרירי ליבה פעילים לאורך כל התרגיל.","כופפו את פלג הגוף העליון באיטיות לצד ימין, תוך הורדת המוט לכיוון הברך הימנית.","עצרו לרגע, ולאחר מכן חזרו למצב ההתחלתי.","חזרו על התנועה בצד שמאל.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a barbell with both hands, palms facing down.","Keep your back straight and core engaged throughout the exercise.","Slowly bend your torso to the right side, lowering the barbell towards your right knee.","Pause for a moment, then return to the starting position.","Repeat the movement on the left side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"i4JkUaL"},{"id":"edb-0098","name":"סקוואט מפוצל צדי עם מוט","name_en":"barbell side split squat","muscle":"legs","equipment":"barbell","target":"quads","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings","calves"],"steps":["עמדו עם הרגליים רחבות יותר מרוחב הכתפיים, אצבעות הרגליים פונות מעט החוצה.","אחזו מוט לרוחב הגב העליון, כשהוא נשען על שריר הטרפז.","הפעילו את שרירי הליבה ושמרו על חזה מורם תוך הורדת הגוף לתנוחת סקוואט, בכיפוף הברכיים והירכיים.","תוך כדי הירידה, דחפו את הברכיים החוצה לצדדים ושמרו על המשקל על העקבים.","רדו עד שהירכיים מקבילות לרצפה, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet wider than shoulder-width apart, toes pointing slightly outward.","Hold a barbell across your upper back, resting it on your traps.","Engage your core and keep your chest up as you lower your body down into a squat position, bending at the knees and hips.","As you lower, push your knees out to the sides and keep your weight on your heels.","Lower until your thighs are parallel to the ground, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"W31mMjd"},{"id":"edb-0097","name":"סקוואט מפוצל צדי עם מוט","name_en":"barbell side split squat v. 2","muscle":"legs","equipment":"barbell","target":"quads","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings","calves"],"steps":["עמדו עם הרגליים רחבות יותר מרוחב הכתפיים, אצבעות הרגליים פונות מעט החוצה.","אחזו מוט לרוחב הגב העליון, כשהוא נשען על הכתפיים.","עשו צעד גדול הצידה עם הרגל הימנית, כשהרגל השמאלית נשארת נטועה במקום.","כופפו את הברך הימנית והורידו את הגוף לתנוחת סקוואט, תוך שמירה על חזה מורם וגב ישר.","דחפו דרך העקב הימני כדי לחזור למצב ההתחלתי.","חזרו על התנועה בצד השני, בצעד עם הרגל השמאלית.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Stand with your feet wider than shoulder-width apart, toes pointing slightly outwards.","Hold a barbell across your upper back, resting it on your shoulders.","Take a big step to the side with your right foot, keeping your left foot planted.","Bend your right knee and lower your body down into a squat position, keeping your chest up and your back straight.","Push through your right heel to return to the starting position.","Repeat on the other side, stepping out with your left foot.","Continue alternating sides for the desired number of repetitions."],"mediaId":"HUEqZ1y"},{"id":"edb-1756","name":"דדליפט ברגל אחת עם מוט","name_en":"barbell single leg deadlift","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","lower back"],"steps":["עמדו עם הרגליים במרחק רוחב האגן, אוחזים מוט לפני הירכיים באחיזה עלית.","העבירו את המשקל לרגל השמאלית והרימו את הרגל הימנית מעט מהרצפה.","התכופפו קדימה מהירכיים, תוך שמירה על גב ישר והרגל הימנית מיושרת מאחור לצורך שיווי משקל.","הורידו את המוט לכיוון הרצפה, תוך שמירה עליו קרוב לגוף והרגל השמאלית כפופה מעט.","עצרו לרגע בתחתית התנועה, ולאחר מכן הפעילו את שרירי הישבן והירך האחוריים כדי להרים את פלג הגוף העליון חזרה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Stand with your feet hip-width apart, holding a barbell in front of your thighs with an overhand grip.","Shift your weight onto your left foot and lift your right foot slightly off the ground.","Hinge forward at the hips, keeping your back straight and your right leg extended behind you for balance.","Lower the barbell towards the ground, keeping it close to your body and your left leg slightly bent.","Pause for a moment at the bottom, then engage your glutes and hamstrings to lift your torso back up to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"gEyURal"},{"id":"edb-0099","name":"סקוואט מפוצל ברגל אחת עם מוט","name_en":"barbell single leg split squat","muscle":"legs","equipment":"barbell","target":"quads","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים במוט על הגב העליון.","צעדו צעד גדול קדימה עם רגל אחת, תוך שמירה על פלג הגוף העליון זקוף.","הורידו את הגוף על ידי כיפוף הברך והירך הקדמיות, תוך שמירה על הרגל האחורית ישרה.","המשיכו לרדת עד שהירך הקדמית מקבילה לרצפה.","עצרו לרגע, ולאחר מכן דחפו דרך העקב הקדמי כדי לחזור למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו רגליים."],"steps_en":["Stand with your feet shoulder-width apart, holding a barbell across your upper back.","Take a large step forward with one leg, keeping your torso upright.","Lower your body by bending your front knee and hip, while keeping your back leg straight.","Continue lowering until your front thigh is parallel to the ground.","Pause for a moment, then push through your front heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"mediaId":"gGNQmVt"},{"id":"edb-2799","name":"הרמת רגליים לסירוגין עם מוט","name_en":"barbell sitted alternate leg raise","muscle":"core","equipment":"barbell","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שבו על ספסל עם גב ישר ואחזו מוט לרוחב הירכיים.","תוך שמירה על רגליים ישרות, הרימו רגל אחת עד כמה שניתן תוך שמירה על הרגל השנייה על הרצפה.","הורידו את הרגל המורמת בחזרה וחזרו על התנועה עם הרגל השנייה.","המשיכו להחליף רגליים למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your back straight and hold a barbell across your thighs.","Keeping your legs straight, lift one leg up as high as possible while keeping the other leg on the ground.","Lower the raised leg back down and repeat with the other leg.","Continue alternating legs for the desired number of repetitions."],"mediaId":"G7xoEzr"},{"id":"edb-2800","name":"הרמת רגליים לסירוגין עם מוט","name_en":"barbell sitted alternate leg raise (female)","muscle":"core","equipment":"barbell","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors","quadriceps"],"steps":["שבו על ספסל עם גב ישר ואחזו מוט לרוחב הירכיים.","הניחו את הידיים על צידי הספסל לתמיכה.","תוך שמירה על רגליים ישרות, הרימו רגל אחת עד כמה שניתן תוך שמירה עליה מקבילה לרצפה.","הורידו את הרגל בחזרה וחזרו על התנועה עם הרגל השנייה.","המשיכו להחליף רגליים למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your back straight and hold a barbell across your thighs.","Place your hands on the sides of the bench for support.","Keeping your legs straight, lift one leg up as high as possible while keeping it parallel to the ground.","Lower the leg back down and repeat with the other leg.","Continue alternating legs for the desired number of repetitions."],"mediaId":"BCs0G2F"},{"id":"edb-0100","name":"barbell skier","name_en":"barbell skier","muscle":"shoulders","equipment":"barbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו במוט מול הירכיים באחיזה עליונה.","כופפו את הברכיים מעט והתכופפו קדימה מהירכיים, תוך שמירה על גב ישר וחזה מורם.","הרימו את המוט לכיוון הכתפיים תוך כדי קפיצה קלה מהרצפה, במקביל.","כאשר אתם מגיעים לשיא התנועה, הפכו את הכיוון במהירות והורידו את המוט חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a barbell in front of your thighs with an overhand grip.","Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up.","Simultaneously lift the barbell up towards your shoulders while jumping slightly off the ground.","As you reach the top of the movement, quickly reverse the motion and lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"4Leypho"},{"id":"edb-0101","name":"סקוואט עם מוט","name_en":"barbell speed squat","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והבהונות פונות מעט החוצה.","אחזו במוט על הגב העליון, כשהוא מונח על שרירי הטרפז או הדלטואיד האחורי.","הפעילו את שרירי הליבה ושמרו על חזה מורם תוך הורדת הירכיים אחורה ומטה, כאילו אתם יושבים על כיסא.","רדו עד שהירכיים מקבילות לרצפה, או עד למקסימום שנוח לכם.","דחפו דרך העקבים כדי לחזור לעמידה, תוך כיווץ שרירי הישבן בשיא התנועה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, toes slightly turned out.","Hold the barbell across your upper back, resting it on your traps or rear delts.","Engage your core and keep your chest up as you lower your hips back and down, as if sitting into a chair.","Lower until your thighs are parallel to the ground, or as low as you can comfortably go.","Drive through your heels to stand back up, squeezing your glutes at the top.","Repeat for the desired number of repetitions."],"mediaId":"euI1BwR"},{"id":"edb-2810","name":"סקוואט מפוצל עם מוט","name_en":"barbell split squat v. 2","muscle":"legs","equipment":"barbell","target":"quads","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings","calves"],"steps":["התחילו בעמידה עם הרגליים ברוחב הכתפיים, כשאתם אוחזים במוט על הגב העליון.","צעדו צעד גדול קדימה עם הרגל הימנית, תוך שמירה על פלג הגוף העליון זקוף.","הורידו את הגוף על ידי כיפוף הברכיים והירכיים עד שהירך הימנית מקבילה לרצפה.","עצרו לרגע, ולאחר מכן דחפו דרך העקב הימני כדי לחזור למצב ההתחלתי.","חזרו על התנועה עם הרגל השמאלית קדימה למספר החזרות הרצוי."],"steps_en":["Start by standing with your feet shoulder-width apart, holding a barbell across your upper back.","Take a large step forward with your right foot, keeping your torso upright.","Lower your body by bending your knees and hips until your right thigh is parallel to the ground.","Pause for a moment, then push through your right heel to return to the starting position.","Repeat with your left leg forward for the desired number of repetitions."],"mediaId":"HBYyX94"},{"id":"edb-0102","name":"סקוואט עם מוט","name_en":"barbell squat (on knees)","muscle":"legs","equipment":"barbell","target":"quads","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings","calves"],"steps":["התחילו בכריעה על הרצפה עם הברכיים במרחק רוחב האגן ואצבעות הרגליים פונות קדימה.","הניחו מוט לרוחב הכתפיים, אחזו אותו באחיזה עלית כשהידיים מעט רחבות יותר מרוחב הכתפיים.","הפעילו את שרירי הליבה ושמרו על חזה מורם תוך הורדת הגוף באיטיות על ידי כיפוף הברכיים, ושמרו על גב ישר.","המשיכו לרדת עד שהירכיים מקבילות לרצפה, או עד למקסימום שנוח לכם.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by kneeling on the ground with your knees hip-width apart and your toes pointing forward.","Place a barbell across your shoulders, gripping it with an overhand grip and your hands slightly wider than shoulder-width apart.","Engage your core and keep your chest lifted as you slowly lower your body down by bending your knees, keeping your back straight.","Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"oR7O9LW"},{"id":"edb-2798","name":"סקוואט אחורי עם מוט","name_en":"barbell squat jump step rear lunge","muscle":"legs","equipment":"barbell","target":"quads","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings","calves"],"steps":["התחילו בעמידה עם הרגליים ברוחב הכתפיים, כשאתם אוחזים במוט על הגב העליון.","הורידו את הגוף לתנוחת סקוואט על ידי כפיפת הברכיים ודחיפת האגן אחורה.","התפרצו כלפי מעלה, קפצו מהרצפה עד כמה שניתן.","נחתו ברכות על הרגליים ומיד צעדו אחורה עם רגל אחת לתנוחת לאנג' הפוך.","הורידו את הגוף עד שהירך הקדמית מקבילה לרצפה, תוך שמירה על גב ישר.","דחפו דרך העקב הקדמי כדי לחזור למצב ההתחלתי.","חזרו על רצף הקפיצה והלאנג' עם הרגל השנייה.","המשיכו להחליף רגליים למספר החזרות הרצוי."],"steps_en":["Start by standing with your feet shoulder-width apart, holding a barbell across your upper back.","Lower your body into a squat position by bending your knees and pushing your hips back.","Explode upwards, jumping off the ground as high as you can.","Land softly on your feet and immediately step back with one leg into a reverse lunge.","Lower your body down until your front thigh is parallel to the ground, keeping your back straight.","Push through your front heel to return to the starting position.","Repeat the jump and lunge sequence on the other leg.","Continue alternating legs for the desired number of repetitions."],"mediaId":"RYcV1kH"},{"id":"edb-0103","name":"barbell standing ab rollerout","name_en":"barbell standing ab rollerout","muscle":"core","equipment":"barbell","target":"abs","bodyPart":"waist","secondaryMuscles":["shoulders","lower back"],"steps":["עמדו זקוף עם הרגליים במרחק רוחב הכתפיים ואחזו את המוט בשתי הידיים לפני הירכיים.","הפעילו את שרירי הליבה וגלגלו את המוט באיטיות כלפי הרצפה, תוך שמירה על גב ישר וזרועות מיושרות.","המשיכו לגלגל את המוט קדימה עד שהגוף מיושר לחלוטין והידיים ישירות מעל הראש.","עצרו לרגע, ולאחר מכן גלגלו את המוט באיטיות חזרה לכיוון הירכיים, תוך שמירה על שליטה ושרירי ליבה פעילים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand upright with your feet shoulder-width apart and hold the barbell with both hands in front of your thighs.","Engage your core and slowly roll the barbell down towards the ground, keeping your back straight and your arms extended.","Continue rolling the barbell forward until your body is fully extended and your hands are directly above your head.","Pause for a moment, then slowly roll the barbell back towards your thighs, maintaining control and keeping your core engaged.","Repeat for the desired number of repetitions."],"mediaId":"xnInPfE"},{"id":"edb-0104","name":"כפיפת שורש כף היד בעמידה עם מוט","name_en":"barbell standing back wrist curl","muscle":"biceps","equipment":"barbell","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["biceps","shoulders"],"steps":["עמדו זקוף עם הרגליים במרחק רוחב הכתפיים ואחזו מוט באחיזה עלית.","הניחו את המוט על גב כפות הידיים כאשר כפות הידיים פונות מטה והאצבעות פונות לכיוון הגוף.","תוך שמירה על הזרוע העליונה ללא תנועה, נשפו וכופפו את פרקי הידיים כלפי מעלה עד כמה שניתן.","החזיקו את התנוחה המכווצת לרגע קצר, ולאחר מכן שאפו אוויר והורידו לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand up straight with your feet shoulder-width apart and hold a barbell with an overhand grip.","Rest the barbell on the back of your hands with your palms facing down and your fingers pointing towards your body.","Keeping your upper arms stationary, exhale and curl your wrists upwards as far as possible.","Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"2qTvJAZ"},{"id":"edb-0105","name":"לחיצה בעמידה עם מוט","name_en":"barbell standing bradford press","muscle":"shoulders","equipment":"barbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים ואחזו את המוט לפני הכתפיים באחיזה עלית.","דחפו את המוט מעל הראש, תוך יישור מלא של הזרועות.","הורידו את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold the barbell in front of your shoulders with an overhand grip.","Press the barbell overhead, fully extending your arms.","Lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"dCPESfR"},{"id":"edb-1372","name":"הרמת עקבים בעמידה עם מוט","name_en":"barbell standing calf raise","muscle":"legs","equipment":"barbell","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings","glutes"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים והניחו מוט לרוחב הגב העליון.","הרימו את העקבים מהרצפה עד כמה שניתן, תוך שימוש באצבעות הרגליים בלבד.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקבים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and place a barbell across your upper back.","Raise your heels off the ground as high as possible, using only your toes.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"8ozhUIZ"},{"id":"edb-0106","name":"כפיפת מרפק אחיזה צרה בעמידה עם מוט","name_en":"barbell standing close grip curl","muscle":"biceps","equipment":"barbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף עם הרגליים במרחק רוחב הכתפיים ואחזו מוט באחיזה תחתית, כשהידיים קרובות זו לזו.","שמרו על המרפקים קרובים לגוף והזרוע העליונה ללא תנועה לאורך כל התנועה.","נשפו תוך כדי כיפוף המשקולות וכיווץ שריר הביצפס. המשיכו להרים את המוט עד ששריר הביצפס מכווץ במלואו והמוט נמצא בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר תוך כדי החזרת המוט באיטיות למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, hands close together.","Keep your elbows close to your torso and your upper arms stationary throughout the movement.","Exhale as you curl the weights while contracting your biceps. Continue to raise the bar until your biceps are fully contracted and the bar is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale as you slowly begin to bring the barbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"4dUn2iv"},{"id":"edb-1456","name":"לחיצה צבאית אחיזה צרה בעמידה עם מוט","name_en":"barbell standing close grip military press","muscle":"shoulders","equipment":"barbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים ואחזו את המוט באחיזה עלית, כאשר הידיים מעט צרות יותר מרוחב הכתפיים.","הרימו את המוט לגובה הכתפיים, תוך שמירה על המרפקים קרובים לגוף.","דחפו את המוט מעל הראש, תוך יישור מלא של הזרועות.","הורידו את המוט חזרה לגובה הכתפיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold the barbell with an overhand grip, hands slightly closer than shoulder-width apart.","Lift the barbell to shoulder height, keeping your elbows close to your body.","Press the barbell overhead, extending your arms fully.","Lower the barbell back to shoulder height.","Repeat for the desired number of repetitions."],"mediaId":"wdRZISl"},{"id":"edb-2414","name":"כפיפת מרפק בעמידה עם מוט","name_en":"barbell standing concentration curl","muscle":"biceps","equipment":"barbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים ואחזו מוט ביד אחת, כף היד פונה כלפי מעלה.","הניחו את היד השנייה על הירך לתמיכה.","תוך שמירה על הזרוע העליונה ללא תנועה, נשפו וכופפו את המשקולת כלפי מעלה לכיוון הכתף.","עצרו לרגע בשיא התנועה, תוך כיווץ שרירי הביצפס.","שאפו אוויר והורידו את המשקולת באיטיות חזרה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Stand with your feet shoulder-width apart and hold a barbell in one hand, palm facing up.","Rest your opposite hand on your thigh for support.","Keeping your upper arm stationary, exhale and curl the weight up towards your shoulder.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the weight back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"vsMcDi9"},{"id":"edb-0107","name":"הרמה קדמית בעמידה עם מוט","name_en":"barbell standing front raise over head","muscle":"shoulders","equipment":"barbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים, אוחזים מוט לפני הירכיים באחיזה עלית.","שמרו על גב ישר והפעילו את ליבת הגוף.","הרימו את המוט באיטיות לפניכם, תוך שמירה על זרועות ישרות וכפות הידיים פונות מטה.","המשיכו להרים עד שהמוט נמצא מעט מעל גובה הכתפיים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a barbell in front of your thighs with an overhand grip.","Keep your back straight and engage your core.","Slowly raise the barbell in front of you, keeping your arms straight and your palms facing down.","Continue lifting until the barbell is slightly above shoulder level.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"S8mo30S"},{"id":"edb-0108","name":"הרמת עקבים בעמידה עם מוט","name_en":"barbell standing leg calf raise","muscle":"legs","equipment":"barbell","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings","glutes"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים והניחו מוט לרוחב הגב העליון.","הרימו את העקבים מהרצפה כמה שיותר גבוה, תוך שימוש בשרירי השוק.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקבים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and place a barbell across your upper back.","Raise your heels off the ground as high as possible, using your calves.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"rGwhJ5o"},{"id":"edb-0109","name":"פשיטת מרפק מעל הראש","name_en":"barbell standing overhead triceps extension","muscle":"triceps","equipment":"barbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים ואחזו מוט באחיזה עלית.","הרימו את המוט מעל הראש, תוך יישור מלא של הזרועות.","תוך שמירה על הזרועות העליונות קרובות לראש, הורידו את המוט באיטיות מאחורי הראש על ידי כיפוף המרפקים.","עצרו לרגע, ולאחר מכן הרימו את המוט חזרה למצב ההתחלתי על ידי יישור הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a barbell with an overhand grip.","Raise the barbell overhead, fully extending your arms.","Keeping your upper arms close to your head, slowly lower the barbell behind your head by bending your elbows.","Pause for a moment, then raise the barbell back to the starting position by extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"dZl9Q27"},{"id":"edb-0110","name":"כפיפת מרפק אחיזה הפוכה בעמידה עם מוט","name_en":"barbell standing reverse grip curl","muscle":"biceps","equipment":"barbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף עם הרגליים ברוחב הכתפיים ואחזו במוט באחיזה תחתונה, כשכפות הידיים פונות למעלה.","שמרו על המרפקים קרובים לגוף והזרוע העליונה ללא תנועה.","נשפו וכופפו את המשקולות תוך כיווץ שריר הביצפס, תוך קירוב המוט לכתפיים עד כמה שניתן.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והורידו את המוט באיטיות חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing up.","Keep your elbows close to your torso and your upper arms stationary.","Exhale and curl the weights while contracting your biceps, bringing the barbell as close to your shoulders as possible.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"LWuA3aZ"},{"id":"edb-0111","name":"הרמת עקבים בעמידה עם מוט","name_en":"barbell standing rocking leg calf raise","muscle":"legs","equipment":"barbell","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings","quadriceps"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו במוט על הגב העליון.","הרימו את העקבים מהרצפה עד כמה שניתן, תוך שיווי משקל על כריות כפות הרגליים.","הורידו את העקבים באיטיות חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a barbell across your upper back.","Raise your heels off the ground as high as possible, balancing on the balls of your feet.","Slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"6HiHHe0"},{"id":"edb-0112","name":"פיתול בעמידה עם מוט","name_en":"barbell standing twist","muscle":"core","equipment":"barbell","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","lower back"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים ואחזו מוט מול החזה בשתי הידיים, כפות הידיים פונות מטה.","הפעילו את שרירי הליבה ושמרו על גב ישר לאורך כל התרגיל.","סובבו את פלג הגוף העליון באיטיות ימינה, תוך סיבוב על הרגליים והירכיים, ושמרו על פלג הגוף התחתון יציב.","עצרו לרגע בסוף הסיבוב, ולאחר מכן חזרו לאט למצב ההתחלתי.","חזרו על הסיבוב לצד שמאל.","המשיכו לסובב לסירוגין למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a barbell in front of your chest with both hands, palms facing down.","Engage your core and keep your back straight throughout the exercise.","Slowly twist your torso to the right, pivoting on your feet and hips, while keeping your lower body stable.","Pause for a moment at the end of the twist, then slowly return to the starting position.","Repeat the twist to the left side.","Continue alternating twists for the desired number of repetitions."],"mediaId":"yQe5HpE"},{"id":"edb-1629","name":"כפיפת מרפק אחיזה רחבה בעמידה עם מוט","name_en":"barbell standing wide grip biceps curl","muscle":"biceps","equipment":"barbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים ואחזו מוט באחיזה תחתית, כשהידיים רחבות יותר מרוחב הכתפיים.","שמרו על גב ישר והמרפקים קרובים לגוף.","נשפו וכופפו את המוט כלפי מעלה לכיוון הכתפיים, תוך שמירה על הזרוע העליונה ללא תנועה.","עצרו לרגע בשיא התנועה, תוך כיווץ שרירי הביצפס.","שאפו אוויר והורידו את המוט באיטיות חזרה למצב ההתחלתי, תוך יישור מלא של הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a barbell with an underhand grip, hands wider than shoulder-width apart.","Keep your back straight and your elbows close to your torso.","Exhale and curl the barbell up towards your shoulders, keeping your upper arms stationary.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the barbell back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"faHKVkK"},{"id":"edb-1457","name":"לחיצה צבאית בעמידה רחב עם מוט","name_en":"barbell standing wide military press","muscle":"shoulders","equipment":"barbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים ואחזו את המוט באחיזה עלית, מעט רחבה יותר מרוחב הכתפיים.","הרימו את המוט לגובה הכתפיים, תוך שמירה על המרפקים מעט לפני המוט.","דחפו את המוט מעל הראש, תוך יישור מלא של הזרועות.","הורידו את המוט חזרה לגובה הכתפיים וחזרו על התנועה למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold the barbell with an overhand grip, slightly wider than shoulder-width.","Lift the barbell to shoulder height, keeping your elbows slightly in front of the bar.","Press the barbell overhead, extending your arms fully.","Lower the barbell back to shoulder height and repeat for the desired number of repetitions."],"mediaId":"Kyd9Rz5"},{"id":"edb-0113","name":"כפיפת מרפק אחיזה רחבה בעמידה עם מוט","name_en":"barbell standing wide-grip curl","muscle":"biceps","equipment":"barbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms","shoulders"],"steps":["עמדו זקוף עם הרגליים במרחק רוחב הכתפיים ואחזו מוט באחיזה עלית, כשהידיים רחבות יותר מרוחב הכתפיים.","תנו למוט להישאר תלוי באורך זרוע לפני הירכיים, כפות הידיים פונות הרחק מהגוף.","תוך שמירה על הזרוע העליונה ללא תנועה, נשפו וכופפו את המוט כלפי מעלה על ידי כיווץ שריר הביצפס.","המשיכו להרים את המוט עד ששריר הביצפס מכווץ במלואו והמוט נמצא בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand up straight with your feet shoulder-width apart and hold a barbell with an overhand grip, hands wider than shoulder-width apart.","Let the barbell hang at arm's length in front of your thighs, with your palms facing away from your body.","Keeping your upper arms stationary, exhale and curl the barbell upward by contracting your biceps.","Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"NdIb5Z1"},{"id":"edb-0114","name":"עלייה על ספסל עם מוט","name_en":"barbell step-up","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו מול ספסל או מדרגה כאשר המוט מונח על הגב העליון.","הניחו רגל אחת על הספסל או המדרגה, וודאו שכל כף הרגל במגע עם המשטח.","דחפו דרך העקב ועלו על הספסל או המדרגה, תוך יישור מלא של הירך והברך.","עצרו לרגע קצר בשיא התנועה, ולאחר מכן רדו חזרה למצב ההתחלתי.","חזרו על התנועה עם הרגל השנייה.","המשיכו להחליף רגליים למספר החזרות הרצוי."],"steps_en":["Stand in front of a bench or step with a barbell resting on your upper back.","Place one foot on the bench or step, ensuring your entire foot is in contact with the surface.","Push through your heel and step up onto the bench or step, fully extending your hip and knee.","Pause briefly at the top, then lower yourself back down to the starting position.","Repeat with the opposite leg.","Continue alternating legs for the desired number of repetitions."],"mediaId":"Kxquu2E"},{"id":"edb-0115","name":"גוד מורנינג עם מוט","name_en":"barbell stiff leg good morning","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","lower back"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","אחזו את המוט לרוחב הגב העליון, כשהוא נשען על שריר הטרפז.","תוך שמירה על גב ישר, התכופפו קדימה מהירכיים, תוך דחיפת הישבן אחורה.","הורידו את הגו עד שהוא מקביל לרצפה, תוך הרגשת מתיחה בשרירי הירך האחוריים.","הפעילו את שרירי הישבן והירך האחוריים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your knees slightly bent.","Hold the barbell across your upper back, resting it on your traps.","Keeping your back straight, hinge forward at the hips, pushing your glutes back.","Lower your torso until it is parallel to the ground, feeling a stretch in your hamstrings.","Engage your glutes and hamstrings to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"JrOHAZc"},{"id":"edb-0116","name":"דדליפט עם מוט","name_en":"barbell straight leg deadlift","muscle":"legs","equipment":"barbell","target":"hamstrings","bodyPart":"upper legs","secondaryMuscles":["glutes","lower back"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים ואצבעות הרגליים פונות קדימה.","אחזו במוט באחיזה עליונה, כשהידיים מעט רחבות יותר מרוחב הכתפיים.","כופפו מהירכיים והורידו את המוט לכיוון הרצפה, תוך שמירה על גב ישר וברכיים כפופות מעט.","הורידו את המוט עד שתרגישו מתיחה בשרירי הירך האחוריים.","הפעילו את שרירי הירך האחוריים והישבן כדי להרים את המוט חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your toes pointing forward.","Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Bend at your hips and lower the barbell towards the ground, keeping your back straight and your knees slightly bent.","Lower the barbell until you feel a stretch in your hamstrings.","Engage your hamstrings and glutes to lift the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"hrVQWvE"},{"id":"edb-0117","name":"דדליפט עם מוט","name_en":"barbell sumo deadlift","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps","lower back"],"steps":["עמדו עם הרגליים רחבות יותר מרוחב הכתפיים, אצבעות הרגליים פונות החוצה.","הניחו מוט על הרצפה לפניכם, במרכז בין הרגליים.","כופפו את הברכיים והורידו את הירכיים, תוך שמירה על גב ישר וחזה מורם, ואחזו את המוט באחיזה עלית.","הפעילו את שרירי הליבה ודחפו דרך העקבים כדי להרים את המוט מהרצפה, תוך יישור הירכיים והברכיים במקביל.","תוך כדי ההרמה, שמרו על חזה מורם וגב ישר, ודחפו את הירכיים קדימה כדי להפעיל את שרירי הישבן במלואם.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המוט באיטיות חזרה למצב ההתחלתי, תוך שמירה על שליטה לאורך כל התנועה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet wider than shoulder-width apart, toes pointing outwards.","Place a barbell on the ground in front of you, centered between your feet.","Bend your knees and lower your hips, keeping your back straight and chest up, to grip the barbell with an overhand grip.","Engage your core and drive through your heels to lift the barbell off the ground, extending your hips and knees simultaneously.","As you lift, keep your chest up and back straight, and push your hips forward to fully engage your glutes.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position, maintaining control throughout the movement.","Repeat for the desired number of repetitions."],"mediaId":"KgI0tqW"},{"id":"edb-3305","name":"תראסטר עם מוט","name_en":"barbell thruster","muscle":"shoulders","equipment":"barbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["quadriceps","glutes","hamstrings","core"],"steps":["התחילו בעמידה עם הרגליים במרחק רוחב הכתפיים, אוחזים מוט בגובה הכתפיים באחיזה עלית.","רדו לתנוחת סקוואט על ידי כיפוף הברכיים ודחיפת הירכיים אחורה.","כשאתם מגיעים לתחתית הסקוואט, דחפו בפיצוץ דרך העקבים כדי לעמוד, תוך דחיפת המוט מעל הראש במקביל.","הורידו את המוט חזרה לגובה הכתפיים תוך כדי חזרה לתנוחת הסקוואט.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by standing with your feet shoulder-width apart, holding a barbell at shoulder height with an overhand grip.","Lower into a squat position by bending your knees and pushing your hips back.","As you reach the bottom of the squat, explosively drive through your heels to stand up, simultaneously pressing the barbell overhead.","Lower the barbell back to shoulder height as you lower back into the squat position.","Repeat for the desired number of repetitions."],"mediaId":"f7Y9eDZ"},{"id":"edb-0120","name":"חתירה זקופה עם מוט","name_en":"barbell upright row","muscle":"shoulders","equipment":"barbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","biceps"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים ואחזו מוט באחיזה עלית, כשהידיים מעט רחבות יותר מרוחב הכתפיים.","תנו למוט להישאר תלוי לפני הירכיים, הזרועות ישרות לחלוטין.","תוך שמירה על גב ישר ושרירי ליבה פעילים, נשפו והרימו את המוט ישר כלפי מעלה לכיוון הסנטר, כשהמרפקים מובילים.","עצרו לרגע בשיא התנועה, ולאחר מכן שאפו אוויר והורידו את המוט באיטיות חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Let the barbell hang in front of your thighs, arms fully extended.","Keeping your back straight and core engaged, exhale and lift the barbell straight up towards your chin, leading with your elbows.","Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"UDlhcO8"},{"id":"edb-0119","name":"חתירה זקופה עם מוט","name_en":"barbell upright row v. 2","muscle":"shoulders","equipment":"barbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","biceps"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים ואחזו מוט באחיזה עלית, כשהידיים מעט רחבות יותר מרוחב הכתפיים.","תנו למוט להישאר תלוי לפני הירכיים, הזרועות ישרות לחלוטין.","תוך שמירה על גב ישר, נשפו והרימו את המוט ישר כלפי מעלה לכיוון הסנטר, כשהמרפקים מובילים.","עצרו לרגע בשיא התנועה, ולאחר מכן שאפו אוויר והורידו את המוט באיטיות חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Let the barbell hang in front of your thighs, arms fully extended.","Keeping your back straight, exhale and lift the barbell straight up towards your chin, leading with your elbows.","Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"83HoW9X"},{"id":"edb-0121","name":"חתירה זקופה עם מוט","name_en":"barbell upright row v. 3","muscle":"shoulders","equipment":"barbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","biceps"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים ואחזו מוט באחיזה עלית, כשהידיים מעט רחבות יותר מרוחב הכתפיים.","תנו למוט להישאר תלוי לפני הירכיים, הזרועות ישרות לחלוטין.","תוך שמירה על שרירי ליבה פעילים וגב ישר, נשפו תוך כדי הרמת המוט ישר כלפי מעלה לכיוון הסנטר, כשהמרפקים מובילים.","עצרו לרגע בשיא התנועה, ולאחר מכן שאפו אוויר תוך כדי הורדת המוט באיטיות חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Let the barbell hang in front of your thighs, arms fully extended.","Keeping your core engaged and back straight, exhale as you lift the barbell straight up towards your chin, leading with your elbows.","Pause for a moment at the top, then inhale as you slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"fI18Rbc"},{"id":"edb-0122","name":"לחיצת חזה רחב עם מוט","name_en":"barbell wide bench press","muscle":"chest","equipment":"barbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["שכבו על ספסל כשכפות הרגליים שטוחות על הרצפה והגב צמוד לספסל.","אחזו במוט באחיזה רחבה, מעט רחבה יותר מרוחב הכתפיים.","הרימו את המוט מהמעמד והחזיקו אותו ישר מעל החזה כשהידיים מיושרות לגמרי.","הורידו את המוט באיטיות לכיוון החזה, תוך שמירה על המרפקים פתוחים מעט הצידה.","עצרו לרגע כשהמוט נוגע בחזה, ולאחר מכן דחפו אותו בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with a wide grip, slightly wider than shoulder-width apart.","Lift the barbell off the rack and hold it directly above your chest with your arms fully extended.","Lower the barbell slowly towards your chest, keeping your elbows slightly flared out.","Pause for a moment when the barbell touches your chest, then push it back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"JsKq9so"},{"id":"edb-1258","name":"לחיצת חזה אחיזה הפוכה רחב עם מוט","name_en":"barbell wide reverse grip bench press","muscle":"chest","equipment":"barbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["שכבו על ספסל כשכפות הרגליים שטוחות על הרצפה והגב צמוד לספסל.","אחזו את המוט באחיזה הפוכה רחבה, מעט רחבה יותר מרוחב הכתפיים.","הרימו את המוט מהמעמד והחזיקו אותו ישר מעל החזה כשהידיים מיושרות לגמרי.","הורידו את המוט באיטיות לכיוון החזה, תוך שמירה על המרפקים צמודים לגוף ופרקי הידיים ישרים.","עצרו לרגע כשהמוט נוגע בחזה, ולאחר מכן דחפו אותו בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with a wide reverse grip, slightly wider than shoulder-width apart.","Lift the barbell off the rack and hold it directly above your chest with your arms fully extended.","Lower the barbell slowly towards your chest, keeping your elbows tucked in and your wrists straight.","Pause for a moment when the barbell touches your chest, then push it back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"945zpRg"},{"id":"edb-0124","name":"סקוואט רחב עם מוט","name_en":"barbell wide squat","muscle":"legs","equipment":"barbell","target":"quads","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings","calves"],"steps":["עמדו עם הרגליים רחבות יותר מרוחב הכתפיים, אצבעות הרגליים פונות מעט החוצה.","אחזו במוט על הגב העליון, כשהוא מונח על שרירי הטרפז או הדלטואיד האחורי.","הפעילו את שרירי הליבה ושמרו על חזה מורם תוך הורדת הגוף לתנוחת סקוואט, בדחיפת הירכיים אחורה וכיפוף הברכיים.","רדו עד שהירכיים מקבילות לרצפה, או עד למקסימום שנוח לכם.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet wider than shoulder-width apart, toes pointing slightly outward.","Hold the barbell across your upper back, resting it on your traps or rear delts.","Engage your core and keep your chest up as you lower your body down into a squat, pushing your hips back and bending your knees.","Lower until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"s7HX1BY"},{"id":"edb-0123","name":"חתירה זקופה אחיזה רחבה עם מוט","name_en":"barbell wide-grip upright row","muscle":"shoulders","equipment":"barbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","biceps"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים ואחזו מוט באחיזה עלית, כשהידיים רחבות יותר מרוחב הכתפיים.","תנו למוט להישאר תלוי לפני הירכיים, הזרועות ישרות לחלוטין.","תוך שמירה על גב ישר, נשפו והרימו את המוט ישר כלפי מעלה לכיוון הסנטר, כשהמרפקים מובילים.","עצרו לרגע בשיא התנועה, ולאחר מכן שאפו אוויר והורידו את המוט באיטיות חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands wider than shoulder-width apart.","Let the barbell hang in front of your thighs, arms fully extended.","Keeping your back straight, exhale and lift the barbell straight up towards your chin, leading with your elbows.","Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"RgJDRR1"},{"id":"edb-0126","name":"כפיפת שורש כף היד עם מוט","name_en":"barbell wrist curl","muscle":"biceps","equipment":"barbell","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["biceps","brachialis"],"steps":["שבו על ספסל עם כפות הרגליים שטוחות על הרצפה והאמות נשענות על הירכיים, אוחזים מוט באחיזה תחתית.","תנו למוט להתגלגל עד לקצות האצבעות, תוך שמירה על פרקי הידיים ישרים.","כופפו את המוט באיטיות כלפי מעלה לכיוון האמות על ידי כיפוף פרקי הידיים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your feet flat on the ground and your forearms resting on your thighs, holding a barbell with an underhand grip.","Allow the barbell to roll down to your fingertips, keeping your wrists straight.","Slowly curl the barbell up towards your forearms by flexing your wrists.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"82LxxkW"},{"id":"edb-0125","name":"כפיפת שורש כף היד עם מוט","name_en":"barbell wrist curl v. 2","muscle":"biceps","equipment":"barbell","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["biceps","brachialis"],"steps":["שבו על ספסל כשכפות הרגליים שטוחות על הרצפה והברכיים כפופות.","אחזו מוט באחיזה תחתית, כפות הידיים פונות כלפי מעלה, במרחק רוחב הכתפיים.","הניחו את האמות על הירכיים כך שפרקי הידיים תלויים מעבר לקצה.","כופפו את פרקי הידיים כלפי מעלה באיטיות, תוך קירוב המוט לאמות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your feet flat on the ground and your knees bent.","Hold a barbell with an underhand grip, palms facing up, and your hands shoulder-width apart.","Rest your forearms on your thighs, allowing your wrists to hang off the edge.","Slowly curl your wrists upward, bringing the barbell towards your forearms.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"6kSxYnw"},{"id":"edb-0127","name":"סקוואט עם מוט","name_en":"barbell zercher squat","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והבהונות פונות מעט החוצה.","אחזו את המוט בכיפוף המרפקים, כאשר הידיים אוחזות במוט לשם יציבות.","הפעילו את שרירי הליבה ושמרו על החזה מורם תוך הורדת האגן אחורה ולמטה לתנוחת סקוואט.","שמרו על הברכיים בקו עם הבהונות ועל המשקל בעקבים.","עצרו לרגע בתחתית הסקוואט, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and toes slightly turned out.","Hold the barbell in the crooks of your elbows, with your hands gripping the bar for stability.","Engage your core and keep your chest lifted as you lower your hips back and down into a squat position.","Keep your knees in line with your toes and your weight in your heels.","Pause for a moment at the bottom of the squat, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"LSTChY9"},{"id":"edb-3212","name":"basic toe touch (male)","name_en":"basic toe touch (male)","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","calves"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים והזרועות לצידי הגוף.","התכופפו קדימה מהמותניים, תוך שמירה על גב ישר וברכיים כפופות מעט.","שלחו את הידיים כלפי מטה לכיוון אצבעות הרגליים, תוך שמירה על הרגליים ישרות ככל האפשר.","עצרו לרגע בתחתית התנועה, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your arms by your sides.","Bend forward at the waist, keeping your back straight and your knees slightly bent.","Reach down towards your toes with your hands, keeping your legs as straight as possible.","Pause for a moment at the bottom, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"BbfB8Gb"},{"id":"edb-0128","name":"battling ropes","name_en":"battling ropes","muscle":"shoulders","equipment":"rope","target":"delts","bodyPart":"shoulders","secondaryMuscles":["forearms","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","אחזו קצה אחד של החבל בכל יד, כאשר כפות הידיים פונות זו לזו.","הרימו את הזרועות לגובה הכתפיים, תוך שמירה על המרפקים כפופים מעט.","התחילו ליצור גלים לסירוגין עם החבלים על ידי הרמה והורדה מהירה של כל זרוע.","המשיכו למשך הזמן או מספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and knees slightly bent.","Hold one end of the rope in each hand, with your palms facing each other.","Raise your arms to shoulder height, keeping your elbows slightly bent.","Begin making alternating waves with the ropes by rapidly raising and lowering each arm.","Continue for the desired duration or number of repetitions."],"mediaId":"RJa4tCo"},{"id":"edb-3360","name":"bear crawl","name_en":"bear crawl","muscle":"core","equipment":"body weight","target":"cardiovascular system","bodyPart":"cardio","secondaryMuscles":["core","shoulders","triceps"],"steps":["התחילו בעמידה על ארבע, כשהידיים ישר מתחת לכתפיים והברכיים ישר מתחת לירכיים.","הרימו את הברכיים מעט מהרצפה, תוך שמירה על גב שטוח ושרירי ליבה פעילים.","הזיזו את היד הימנית והרגל השמאלית קדימה במקביל, ולאחר מכן את היד השמאלית והרגל הימנית.","המשיכו לזחול קדימה, תוך החלפת תנועות הידיים והרגליים.","שמרו על קצב יציב ושרירי ליבה מכווצים לאורך כל התרגיל.","המשיכו למרחק או זמן הרצוי."],"steps_en":["Start on all fours with your hands directly under your shoulders and your knees directly under your hips.","Lift your knees slightly off the ground, keeping your back flat and your core engaged.","Move your right hand and left foot forward simultaneously, followed by your left hand and right foot.","Continue crawling forward, alternating your hand and foot movements.","Maintain a steady pace and keep your core tight throughout the exercise.","Continue for the desired distance or time."],"mediaId":"0Yz8WdV"},{"id":"edb-1259","name":"מתיחה מאחורי העורף","name_en":"behind head chest stretch","muscle":"chest","equipment":"assisted","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["עמדו זקוף עם הרגליים ברוחב הכתפיים.","שזרו את האצבעות מאחורי הראש כאשר המרפקים פונים החוצה.","כווצו את השכמות יחד באיטיות ודחפו את החזה קדימה.","החזיקו את המתיחה למשך 15-30 שניות.","שחררו את המתיחה וחזרו כרצונכם."],"steps_en":["Stand tall with your feet shoulder-width apart.","Interlace your fingers behind your head with your elbows pointing outwards.","Slowly squeeze your shoulder blades together and push your chest forward.","Hold the stretch for 15-30 seconds.","Release the stretch and repeat as desired."],"mediaId":"QoHIhPl"},{"id":"edb-0129","name":"מקבילים בהטיה","name_en":"bench dip (knees bent)","muscle":"triceps","equipment":"body weight","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["שבו על קצה הספסל או הכיסא כאשר הידיים אוחזות בקצה ליד הירכיים.","החליקו את הישבן מהספסל ויישרו את הרגליים לפניכם, תוך שמירה על העקבים על הרצפה.","כופפו את המרפקים והורידו את הגוף לכיוון הרצפה, תוך שמירה על הגב קרוב לספסל.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו את עצמכם בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the edge of a bench or chair with your hands gripping the edge next to your hips.","Slide your butt off the bench and straighten your legs in front of you, keeping your heels on the ground.","Bend your elbows and lower your body towards the ground, keeping your back close to the bench.","Pause for a moment at the bottom, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"RrLske5"},{"id":"edb-1399","name":"מקבילים","name_en":"bench dip on floor","muscle":"triceps","equipment":"body weight","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["שבו על קצה הספסל או הכיסא כאשר הידיים אוחזות בקצה, האצבעות פונות קדימה.","החליקו את הישבן מהספסל, תוך תמיכת המשקל בידיים.","הורידו את הגוף על ידי כיפוף המרפקים עד שהזרועות מקבילות לרצפה.","דחפו את עצמכם חזרה למצב ההתחלתי על ידי יישור הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the edge of a bench or chair with your hands gripping the edge, fingers pointing forward.","Slide your butt off the bench, supporting your weight with your hands.","Lower your body by bending your elbows until your upper arms are parallel to the floor.","Push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"mediaId":"9RT8oQW"},{"id":"edb-0130","name":"פשיטה","name_en":"bench hip extension","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings"],"steps":["שבו על ספסל כשהגב נשען על הספסל וכפות הרגליים שטוחות על הרצפה.","הניחו את הידיים על הספסל לתמיכה.","הפעילו את שרירי הישבן והירך האחוריים, ולאחר מכן הרימו את הירכיים מהספסל עד שהגוף יוצר קו ישר מהברכיים ועד הכתפיים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הירכיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your back against the bench and your feet flat on the ground.","Place your hands on the bench for support.","Engage your glutes and hamstrings, then lift your hips off the bench until your body forms a straight line from your knees to your shoulders.","Pause for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"u27Kcdz"},{"id":"edb-3019","name":"bench pull-ups","name_en":"bench pull-ups","muscle":"back","equipment":"body weight","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["התמקמו מתחת למוט או משטח אופקי יציב בגובה החזה.","אחזו את המוט או המשטח באחיזה עלית, מעט רחבה יותר מרוחב הכתפיים.","היתלו כאשר הזרועות ישרות לחלוטין והגוף ישר.","משכו את החזה לכיוון המוט או המשטח על ידי כיווץ השכמות יחד וכיפוף המרפקים.","המשיכו למשוך עד שהסנטר מעל המוט או המשטח.","רדו חזרה למצב ההתחלתי בשליטה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Position yourself under a bar or a sturdy horizontal surface that is at chest height.","Grab the bar or surface with an overhand grip, slightly wider than shoulder-width apart.","Hang with your arms fully extended and your body straight.","Pull your chest towards the bar or surface by squeezing your shoulder blades together and bending your elbows.","Continue pulling until your chin is above the bar or surface.","Lower yourself back down to the starting position with control.","Repeat for the desired number of repetitions."],"mediaId":"mExgrF9"},{"id":"edb-3639","name":"פיתול בשכיבה בהטיה","name_en":"bent knee lying twist (male)","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["obliques","hip flexors"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","יישרו את הזרועות הצידה, בניצב לגוף.","תוך שמירה על הברכיים צמודות זו לזו, הורידו אותן באיטיות לצד אחד, בניסיון לגעת ברצפה עם הברכיים.","עצרו לרגע, ולאחר מכן הפעילו את שרירי הליבה והרימו את הברכיים באיטיות חזרה למצב ההתחלתי.","חזרו על התנועה לצד השני.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your knees bent and feet flat on the ground.","Extend your arms out to the sides, perpendicular to your body.","Keeping your knees together, slowly lower them to one side, aiming to touch the ground with your knees.","Pause for a moment, then engage your core and slowly lift your knees back to the starting position.","Repeat the movement to the other side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"6sYyrRX"},{"id":"edb-1770","name":"כפיפת מרפק","name_en":"biceps leg concentration curl","muscle":"biceps","equipment":"body weight","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל עם הרגליים פשוקות וכפות הרגליים שטוחות על הרצפה.","אחזו משקולת יד אחת והניחו את המרפק על החלק הפנימי של הירך, ממש מעל הברך.","כשכף היד פונה כלפי מעלה, כופפו את המשקולת לכיוון הכתף תוך שמירה על הזרוע העליונה ללא תנועה.","כווצו את שריר הביצפס בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות חזרה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Sit on a bench with your legs spread apart and your feet flat on the ground.","Hold a dumbbell in one hand and place your elbow on the inside of your thigh, just above the knee.","With your palm facing up, curl the dumbbell towards your shoulder while keeping your upper arm stationary.","Squeeze your biceps at the top of the movement, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"sJFIDIp"},{"id":"edb-0139","name":"biceps narrow pull-ups","name_en":"biceps narrow pull-ups","muscle":"biceps","equipment":"body weight","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms","shoulders"],"steps":["היתלו ממתקן מתח כאשר כפות הידיים פונות אליכם והידיים במרחק רוחב הכתפיים.","הפעילו את שרירי הליבה ומשכו את עצמכם כלפי מעלה לכיוון המוט, תוך התמקדות בשימוש בשריר הביצפס להרמת הגוף.","עצרו לרגע בשיא התנועה, ולאחר מכן רדו באיטיות חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Hang from a pull-up bar with your palms facing towards you and your hands shoulder-width apart.","Engage your core and pull yourself up towards the bar, focusing on using your biceps to lift your body.","Pause for a moment at the top, then slowly lower yourself back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"50BETrz"},{"id":"edb-0140","name":"מתח","name_en":"biceps pull-up","muscle":"biceps","equipment":"body weight","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms","shoulders"],"steps":["היתלו ממתקן מתח כאשר כפות הידיים פונות הרחק מכם והידיים במרחק רוחב הכתפיים.","הפעילו את שרירי הליבה ומשכו את עצמכם כלפי מעלה על ידי כיפוף המרפקים, תוך קירוב החזה למוט.","עצרו בשיא התנועה, ולאחר מכן רדו באיטיות חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Hang from a pull-up bar with your palms facing away from you and your hands shoulder-width apart.","Engage your core and pull yourself up by bending your elbows, bringing your chest towards the bar.","Pause at the top of the movement, then slowly lower yourself back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"guT8YnS"},{"id":"edb-0137","name":"body-up","name_en":"body-up","muscle":"triceps","equipment":"body weight","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["התחילו בהנחת הידיים על משטח מוגבה, כגון ספסל או מקבילים, כאשר כפות הידיים פונות מטה והאצבעות פונות קדימה.","יישרו את הרגליים לפניכם, תוך שמירה על העקבים על הרצפה והגוף ישר.","הורידו את הגוף על ידי כיפוף המרפקים, תוך שמירה עליהם קרובים לגוף, עד שהזרועות העליונות מקבילות לרצפה.","עצרו לרגע, ולאחר מכן דחפו דרך כפות הידיים כדי ליישר את הזרועות ולהרים את הגוף חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by placing your hands on a raised surface, such as a bench or parallel bars, with your palms facing down and fingers pointing forward.","Extend your legs out in front of you, keeping your heels on the ground and your body straight.","Lower your body by bending your elbows, keeping them close to your sides, until your upper arms are parallel to the ground.","Pause for a moment, then push through your palms to straighten your arms and lift your body back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"U6G2gk9"},{"id":"edb-3543","name":"סקוואט","name_en":"bodyweight drop jump squat","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים.","הורידו את הגוף לתנוחת סקוואט על ידי כפיפת הברכיים ודחיפת האגן אחורה.","קפצו כלפי מעלה בפיצוץ, תוך יישור הירכיים, הברכיים והקרסוליים.","באוויר, קרבו את הרגליים זו לזו במהירות.","נחתו ברכות על כריות כפות הרגליים ומיד רדו לתנוחת סקוואט.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart.","Lower your body into a squat position by bending your knees and pushing your hips back.","Jump up explosively, extending your hips, knees, and ankles.","While in mid-air, quickly bring your feet together.","Land softly on the balls of your feet and immediately drop back into a squat position.","Repeat for the desired number of repetitions."],"mediaId":"wfotm7S"},{"id":"edb-3544","name":"פלאנק צדי בשיפוע","name_en":"bodyweight incline side plank","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","shoulders"],"steps":["התחילו בשכיבה על הצד כאשר הרגליים ישרות ומונחות זו על גבי זו.","הניחו את האמה על הרצפה ישירות מתחת לכתף, כאשר המרפק כפוף בזווית של 90 מעלות.","הפעילו את שרירי הליבה והרימו את הירכיים מהרצפה, כך שייווצר קו ישר מהראש ועד הרגליים.","החזיקו את התנוחה למשך הזמן הרצוי.","הורידו את הירכיים בחזרה לרצפה וחזרו על התנועה בצד השני."],"steps_en":["Start by lying on your side with your legs extended and stacked on top of each other.","Place your forearm on the ground directly below your shoulder, with your elbow bent at a 90-degree angle.","Engage your core and lift your hips off the ground, creating a straight line from your head to your feet.","Hold this position for the desired amount of time.","Lower your hips back down to the ground and repeat on the other side."],"mediaId":"5VXmnV5"},{"id":"edb-1771","name":"פשיטת מרפק בכריעה","name_en":"bodyweight kneeling triceps extension","muscle":"triceps","equipment":"body weight","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders","chest"],"steps":["כרעו על הרצפה עם הברכיים במרחק רוחב האגן.","הניחו את הידיים על הרצפה לפניכם, במרחק רוחב הכתפיים, האצבעות פונות קדימה.","יישרו את הרגליים מאחוריכם, תוך שיווי משקל על אצבעות הרגליים והידיים, כך שייווצר קו ישר מהראש ועד העקבים.","כופפו את המרפקים והורידו את פלג הגוף העליון לכיוון הרצפה, תוך שמירה על המרפקים קרובים לגוף.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו דרך הידיים כדי ליישר את הזרועות ולחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Kneel down on the ground with your knees hip-width apart.","Place your hands on the ground in front of you, shoulder-width apart, fingers pointing forward.","Extend your legs straight behind you, balancing on your toes and hands, forming a straight line from head to heels.","Bend your elbows and lower your upper body towards the ground, keeping your elbows close to your sides.","Pause for a moment at the bottom, then push through your hands to straighten your arms and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"s0HKO2I"},{"id":"edb-1769","name":"כפיפת מרפק בשכיבה צדי","name_en":"bodyweight side lying biceps curl","muscle":"biceps","equipment":"body weight","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שכבו על הצד כאשר הרגליים ישרות והראש נתמך על ידי הזרוע.","החזיקו את הזרוע העליונה צמודה לגוף וכופפו את המרפק כדי לקרב את האמה לכתף.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את האמה באיטיות חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie on your side with your legs extended and your head supported by your arm.","Hold your upper arm against your side and bend your elbow to curl your forearm towards your shoulder.","Pause for a moment at the top, then slowly lower your forearm back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"gscGLOU"},{"id":"edb-3168","name":"חתירה","name_en":"bodyweight squatting row","muscle":"back","equipment":"body weight","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","shoulders"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים, אוחזים בעצם יציב או ברצועות אימון תלויות כאשר הזרועות ישרות.","הורידו את הגוף לתנוחת סקוואט, תוך שמירה על גב ישר והברכיים מאחורי קצות הרגליים.","מתנוחת הסקוואט, משכו את הגוף כלפי מעלה לכיוון העצם או רצועות האימון, תוך כיווץ השכמות יחד.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הגוף בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding onto a sturdy object or suspension trainer with your arms extended.","Lower your body into a squat position, keeping your back straight and your knees behind your toes.","From the squat position, pull your body up towards the object or suspension trainer, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"3xK09Sk"},{"id":"edb-3167","name":"חתירה","name_en":"bodyweight squatting row (with towel)","muscle":"back","equipment":"body weight","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","shoulders"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים, אוחזים מגבת לפניכם כאשר כפות הידיים פונות מטה.","כופפו את הברכיים והורידו את הגוף לתנוחת סקוואט, תוך שמירה על גב ישר וחזה מורם.","תוך כדי הירידה לסקוואט, משכו במקביל את המגבת לכיוון החזה, תוך כיווץ השכמות יחד.","עצרו לרגע בתחתית הסקוואט, ולאחר מכן חזרו באיטיות למצב ההתחלתי תוך יישור הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a towel in front of you with your palms facing down.","Bend your knees and lower your body into a squat position, keeping your back straight and your chest up.","As you lower into the squat, simultaneously pull the towel towards your chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the squat, then slowly return to the starting position while extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"BReCuOn"},{"id":"edb-1373","name":"הרמת עקבים בעמידה","name_en":"bodyweight standing calf raise","muscle":"legs","equipment":"body weight","target":"calves","bodyPart":"lower legs","secondaryMuscles":["ankles","feet"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים, אצבעות הרגליים פונות קדימה.","הניחו את הידיים על קיר או משטח יציב לשיווי משקל.","הרימו את העקבים מהרצפה באיטיות, תוך העברת משקל הגוף לכריות כפות הרגליים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקבים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, toes pointing forward.","Place your hands on a wall or stable surface for balance.","Slowly raise your heels off the ground, lifting your body weight onto the balls of your feet.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"bJYHBIN"},{"id":"edb-3156","name":"חתירה ביד אחת אחיזה צרה בעמידה","name_en":"bodyweight standing close-grip one arm row","muscle":"back","equipment":"body weight","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים, הברכיים כפופות מעט, ואחזו משקולת יד אחת באחיזה ניטרלית.","התכופפו קדימה מהירכיים, תוך שמירה על גב ישר ושרירי ליבה פעילים.","משכו את המשקולת כלפי מעלה לכיוון החזה, תוך שמירה על המרפק קרוב לגוף וכיווץ השכמות יחד.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות חזרה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Stand with your feet shoulder-width apart, knees slightly bent, and hold a dumbbell in one hand with a neutral grip.","Bend forward at the hips, keeping your back straight and your core engaged.","Pull the dumbbell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"v2DfH14"},{"id":"edb-3158","name":"חתירה אחיזה צרה בעמידה","name_en":"bodyweight standing close-grip row","muscle":"back","equipment":"body weight","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","התכופפו קדימה מהמותניים, תוך שמירה על גב ישר ושרירי ליבה פעילים.","יישרו את הזרועות לפניכם, אחזו את המוט או הידיות באחיזה צרה.","משכו את המוט או הידיות לכיוון הגוף, תוך כיווץ השכמות יחד.","עצרו לרגע בשיא התנועה, ולאחר מכן שחררו באיטיות וחזרו למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and knees slightly bent.","Bend forward at the waist, keeping your back straight and your core engaged.","Extend your arms straight in front of you, gripping the bar or handles with a close grip.","Pull the bar or handles towards your body, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly release and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"tig3PXb"},{"id":"edb-3162","name":"חתירה ביד אחת בעמידה","name_en":"bodyweight standing one arm row","muscle":"back","equipment":"body weight","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים, הברכיים כפופות מעט, ואחזו משקולת יד אחת.","התכופפו קדימה מהירכיים, תוך שמירה על גב ישר ושרירי ליבה פעילים.","תנו למשקולת להישאר תלויה ישר לפניכם, כשהזרוע ישרה לחלוטין.","משכו את המשקולת כלפי מעלה לכיוון החזה, תוך שמירה על המרפק קרוב לגוף.","כווצו את השכמות זו לזו בשיא התנועה.","הורידו את המשקולת חזרה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Stand with your feet shoulder-width apart, knees slightly bent, and hold a dumbbell in one hand.","Bend forward at the hips, keeping your back straight and your core engaged.","Let the dumbbell hang straight down in front of you, with your arm fully extended.","Pull the dumbbell up towards your chest, keeping your elbow close to your body.","Squeeze your shoulder blades together at the top of the movement.","Lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"xbkPfaw"},{"id":"edb-3161","name":"חתירה ביד אחת בעמידה","name_en":"bodyweight standing one arm row (with towel)","muscle":"back","equipment":"body weight","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים, הברכיים כפופות מעט, ואחזו מגבת ביד אחת.","התכופפו קדימה מהירכיים, תוך שמירה על גב ישר ושרירי ליבה פעילים.","משכו את המגבת לכיוון החזה, תוך כיווץ השכמות יחד.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המגבת באיטיות חזרה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ליד השנייה."],"steps_en":["Stand with your feet shoulder-width apart, knees slightly bent, and hold a towel with one hand.","Bend forward at the hips, keeping your back straight and your core engaged.","Pull the towel towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the towel back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"mediaId":"O4oIqQD"},{"id":"edb-3166","name":"חתירה בעמידה","name_en":"bodyweight standing row","muscle":"back","equipment":"body weight","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","shoulders"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","אחזו מוט או ידיות באחיזה עלית, כפות הידיים פונות מטה.","שמרו על גב ישר ושרירי ליבה פעילים.","משכו את המוט או הידיות לכיוון הגוף, תוך כיווץ השכמות יחד.","עצרו לרגע בשיא התנועה.","שחררו באיטיות ויישרו את הזרועות חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and knees slightly bent.","Grasp a bar or handles with an overhand grip, palms facing down.","Keep your back straight and core engaged.","Pull the bar or handles towards your body, squeezing your shoulder blades together.","Pause for a moment at the top of the movement.","Slowly release and extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"wd4ds3s"},{"id":"edb-3165","name":"חתירה בעמידה","name_en":"bodyweight standing row (with towel)","muscle":"back","equipment":"body weight","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","shoulders"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים ואחזו מגבת לפניכם בשתי הידיים.","כופפו מעט את הברכיים והטו את הגוף קדימה במפרקי הירך, תוך שמירה על גב ישר.","משכו את המגבת לכיוון החזה, תוך כיווץ השכמות יחד.","עצרו לרגע בשיא התנועה, ולאחר מכן שחררו לאט את המתח וחזרו למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a towel in front of you with both hands.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Pull the towel towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"uTv34oq"},{"id":"edb-0138","name":"bottoms-up","name_en":"bottoms-up","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","hip flexors"],"steps":["שכבו על הגב עם הרגליים מושטות והידיים לצידי הגוף.","כופפו את הברכיים וקרבו אותן לכיוון החזה, תוך שמירה על הרגליים מורמות מהרצפה.","תוך הפעלת שרירי הבטן, הרימו את הירכיים מהרצפה, תוך קירוב הברכיים לכיוון הראש.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הירכיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your legs extended and your arms by your sides.","Bend your knees and bring them towards your chest, keeping your feet off the ground.","Engaging your abs, lift your hips off the ground, bringing your knees towards your head.","Pause for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"CI6baTY"},{"id":"edb-1374","name":"box jump down with one leg stabilization","name_en":"box jump down with one leg stabilization","muscle":"legs","equipment":"body weight","target":"calves","bodyPart":"lower legs","secondaryMuscles":["quadriceps","hamstrings","glutes"],"steps":["עמדו מול קופסה או משטח מוגבה כשרגליכם ברוחב הכתפיים.","כופפו את הברכיים וקפצו על הקופסה, נחתו ברכות כשרגל אחת על הקופסה והרגל השנייה תלויה מעבר לקצה.","ייצבו את עצמכם על הקופסה עם הרגל שנמצאת עליה, תוך שמירה על הרגל השנייה מורמת מהרצפה.","החזיקו בתנוחה זו למספר שניות, תוך הפעלת שרירי השוק לשמירה על שיווי המשקל.","רדו לאט עם הרגל שעל הקופסה, וחזרו לתנוחת ההתחלה.","חזרו על התרגיל עם הרגל השנייה."],"steps_en":["Stand in front of a box or platform with your feet shoulder-width apart.","Bend your knees and jump onto the box, landing softly with one foot on the box and the other foot hanging off the edge.","Stabilize yourself on the box with the foot that is on it, while keeping the other foot off the ground.","Hold this position for a few seconds, engaging your calf muscles to maintain balance.","Slowly step down with the foot that is on the box, returning to the starting position.","Repeat the exercise with the other leg."],"mediaId":"iPm26QU"},{"id":"edb-2466","name":"גשר","name_en":"bridge - mountain climber (cross body)","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["glutes","quadriceps","hamstrings","shoulders","triceps"],"steps":["התחילו בתנוחת פלאנק גבוה כשהידיים ישירות מתחת לכתפיים והגוף בקו ישר.","הפעילו את שרירי הליבה והרימו את כף הרגל הימנית מהרצפה, תוך קירוב הברך הימנית למרפק השמאלי.","החזירו את כף הרגל הימנית לתנוחת ההתחלה וחזרו על התנועה עם כף הרגל השמאלית לכיוון המרפק הימני.","המשיכו להחליף צדדים תוך שמירה על קצב מבוקר.","שמרו על האגן ישר והימנעו מהרמת האגן גבוה מדי או שקיעתו נמוך מדי.","שמרו על נשימה קבועה לאורך כל התרגיל.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a high plank position with your hands directly under your shoulders and your body in a straight line.","Engage your core and lift your right foot off the ground, bringing your right knee towards your left elbow.","Return your right foot to the starting position and repeat the movement with your left foot towards your right elbow.","Continue alternating sides, moving at a controlled pace.","Keep your hips level and avoid lifting your hips too high or sagging them too low.","Maintain a steady breathing pattern throughout the exercise.","Repeat for the desired number of repetitions."],"mediaId":"9c6T1YX"},{"id":"edb-1160","name":"burpee","name_en":"burpee","muscle":"core","equipment":"body weight","target":"cardiovascular system","bodyPart":"cardio","secondaryMuscles":["quadriceps","hamstrings","calves","shoulders","chest"],"steps":["התחילו בעמידה כשרגליכם ברוחב הכתפיים.","הורידו את הגוף לתנוחת סקוואט על ידי כיפוף הברכיים והנחת הידיים על הרצפה לפניכם.","בעטו ברגליים לאחור לתנוחת שכיבת סמיכה.","בצעו שכיבת סמיכה תוך שמירה על הגוף בקו ישר.","קפצו עם הרגליים בחזרה לתנוחת הסקוואט.","קפצו למעלה בפיצוץ כוח, תוך הושטת הידיים מעל הראש.","נחתו ברכות ורדו מיד חזרה לתנוחת סקוואט כדי להתחיל את החזרה הבאה."],"steps_en":["Start in a standing position with your feet shoulder-width apart.","Lower your body into a squat position by bending your knees and placing your hands on the floor in front of you.","Kick your feet back into a push-up position.","Perform a push-up, keeping your body in a straight line.","Jump your feet back into the squat position.","Jump up explosively, reaching your arms overhead.","Land softly and immediately lower back into a squat position to begin the next repetition."],"mediaId":"dK9394r"},{"id":"edb-0870","name":"butt-ups","name_en":"butt-ups","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors","lower back"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו את הידיים לצדי הגוף, כפות הידיים פונות למטה.","תוך הפעלת שרירי הבטן, הרימו את הרגליים מהרצפה וקרבו את הברכיים לחזה.","בשיא התנועה, כווצו את שרירי הבטן ועצרו לרגע.","הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands by your sides, palms facing down.","Engaging your abs, lift your legs off the ground, bringing your knees towards your chest.","At the top of the movement, squeeze your abs and pause for a moment.","Slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"qcNN2FN"},{"id":"edb-1494","name":"butterfly yoga pose","name_en":"butterfly yoga pose","muscle":"legs","equipment":"body weight","target":"adductors","bodyPart":"upper legs","secondaryMuscles":["hamstrings","groin"],"steps":["שבו על הרצפה כשהרגליים מושטות לפניכם.","כופפו את הברכיים וקרבו את כפות הרגליים זו לזו, תוך הנחת הברכיים ליפול לצדדים.","אחזו בקרסוליים או בכפות הרגליים בידיים.","שבו זקוף והאריכו את עמוד השדרה.","לחצו בעדינות את הברכיים כלפי מטה לכיוון הרצפה, תוך הרגשת מתיחה בפנים הירך.","החזיקו בתנוחה זו למשך כמה נשימות.","כדי לשחרר, הביאו את הברכיים חזרה למעלה לאט ויישרו את הרגליים."],"steps_en":["Sit on the floor with your legs extended in front of you.","Bend your knees and bring the soles of your feet together, allowing your knees to fall out to the sides.","Hold onto your ankles or feet with your hands.","Sit up tall and lengthen your spine.","Gently press your knees down towards the floor, feeling a stretch in your inner thighs.","Hold this position for a few breaths.","To release, slowly bring your knees back up and extend your legs."],"mediaId":"bWlZvXh"},{"id":"edb-0148","name":"לחיצת כתפיים לסירוגין בפולי","name_en":"cable alternate shoulder press","muscle":"shoulders","equipment":"cable","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["עמדו כשרגליכם ברוחב הכתפיים ואחזו בידיות מכונת הפולי באחיזה עליונה.","מקמו את הידיים בגובה הכתפיים, כשכפות הידיים פונות קדימה.","שמרו על שרירי הליבה מופעלים והגב ישר.","דחפו ידית אחת למעלה וקדימה עד שהזרוע מיושרת לחלוטין.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את הידית לאט חזרה לתנוחת ההתחלה.","חזרו עם הזרוע השנייה.","החליפו בין הזרועות למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and grasp the handles of the cable machine with an overhand grip.","Position your hands at shoulder height, with your palms facing forward.","Keep your core engaged and your back straight.","Press one handle up and forward until your arm is fully extended.","Pause for a moment at the top, then slowly lower the handle back to the starting position.","Repeat with the other arm.","Alternate between arms for the desired number of repetitions."],"mediaId":"KHPZL0b"},{"id":"edb-0149","name":"פשיטת מרפק לסירוגין בפולי","name_en":"cable alternate triceps extension","muscle":"triceps","equipment":"cable","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["עמדו מול מכונת הפולי כשרגליכם ברוחב הכתפיים.","אחזו בידית הפולי ביד ימין והרימו את הזרוע כך שהזרוע העליונה מקבילה לרצפה והמרפק כפוף בזווית של 90 מעלות.","שמרו על הזרוע העליונה קבועה ויישרו את האמה לאחור, עד ליישור מלא של הזרוע.","עצרו לרגע, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו עם יד שמאל.","המשיכו להחליף ידיים למספר החזרות הרצוי."],"steps_en":["Stand facing the cable machine with your feet shoulder-width apart.","Hold the cable handle with your right hand and bring your arm up so that your upper arm is parallel to the ground and your elbow is bent at a 90-degree angle.","Keep your upper arm stationary and extend your forearm backward, fully straightening your arm.","Pause for a moment, then slowly return to the starting position.","Repeat with your left arm.","Continue alternating arms for the desired number of repetitions."],"mediaId":"Gchi5Tr"},{"id":"edb-3235","name":"כפיפת ברך בפולי","name_en":"cable assisted inverse leg curl","muscle":"legs","equipment":"cable","target":"hamstrings","bodyPart":"upper legs","secondaryMuscles":["glutes","calves"],"steps":["כווננו את מכונת הפולי כך שרצועת הקרסול נמצאת בהגדרה הנמוכה ביותר.","שכבו על הבטן על הספסל כשהרגליים ישרות ורצועת הקרסול מהודקת לקרסוליים.","אחזו בידיות הספסל לשם יציבות.","תוך שמירה על פלג הגוף העליון קבוע, נשפו וכופפו את הרגליים כלפי מעלה לכיוון הישבן על ידי כיפוף הברכיים.","עצרו לרגע בשיא התנועה, תוך כיווץ שרירי הירך האחוריים.","שאפו והורידו את הרגליים לאט חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the cable machine so that the ankle attachment is at the lowest setting.","Lie face down on the bench with your legs straight and the ankle attachment secured to your ankles.","Hold onto the handles of the bench for stability.","Keeping your upper body stationary, exhale and curl your legs up towards your glutes by flexing your knees.","Pause for a moment at the top of the movement, squeezing your hamstrings.","Inhale and slowly lower your legs back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"zHEpuuc"},{"id":"edb-0150","name":"משיכת פולי לצדדים בפולי","name_en":"cable bar lateral pulldown","muscle":"back","equipment":"cable","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","rhomboids","rear deltoids"],"steps":["כווננו את גלגלת הפולי לעמדה גבוהה וחברו מוט ישר.","שבו מול מכונת הפולי כשכפות הרגליים שטוחות על הרצפה והברכיים כפופות מעט.","אחזו במוט באחיזה עליונה, ברוחב מעט גדול מרוחב הכתפיים.","הטו את הגוף מעט אחורה ושמרו על החזה מורם, תוך שמירה על קמור קל בגב התחתון.","משכו את המוט כלפי מטה לכיוון החזה, תוך הובלה עם המרפקים וכיווץ השכמות זו לזו.","עצרו לרגע בתחתית התנועה, ולאחר מכן החזירו את המוט לאט לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the cable pulley to a high position and attach a straight bar.","Sit facing the cable machine with your feet flat on the ground and your knees slightly bent.","Grasp the bar with an overhand grip, slightly wider than shoulder-width apart.","Lean back slightly and keep your chest up, maintaining a slight arch in your lower back.","Pull the bar down towards your chest, leading with your elbows and squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly return the bar to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"eYnzaCm"},{"id":"edb-0151","name":"לחיצת חזה בפולי","name_en":"cable bench press","muscle":"chest","equipment":"cable","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["כווננו את מכונת הפולי לגובה החזה וחברו את הידיות.","עמדו כשגבכם למכונה ורגליכם ברוחב הכתפיים.","אחזו בידיות באחיזה עליונה וצעדו קדימה כדי ליצור מתח בכבלים.","מקמו את הרגליים בבטחה על הרצפה והפעילו את שרירי הליבה.","כופפו את המרפקים והביאו את הידיים לגובה הכתפיים, תוך שמירה על זווית של 90 מעלות במרפקים.","דחפו את הידיות קדימה, תוך יישור מלא של הזרועות לפניכם.","עצרו לרגע, ולאחר מכן הפכו את התנועה לאט, תוך החזרת הידיים לגובה הכתפיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the cable machine to chest height and attach the handles.","Stand facing away from the machine with your feet shoulder-width apart.","Grasp the handles with an overhand grip and step forward to create tension in the cables.","Position your feet firmly on the ground and engage your core.","Bend your elbows and bring your hands to shoulder level, keeping your elbows at a 90-degree angle.","Push the handles forward, extending your arms fully in front of you.","Pause for a moment, then slowly reverse the movement, bringing your hands back to shoulder level.","Repeat for the desired number of repetitions."],"mediaId":"7xI5MXA"},{"id":"edb-1630","name":"כפיפת מרפק אחיזה צרה בפולי","name_en":"cable close grip curl","muscle":"biceps","equipment":"cable","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["חברו מוט ישר לגלגלת תחתונה של מכונת הפולי.","עמדו מול המכונה כשרגליכם ברוחב הכתפיים והברכיים כפופות מעט.","אחזו במוט באחיזה תחתונה, כשהידיים ברוחב הכתפיים.","שמרו על המרפקים צמודים לגוף והזרועות העליונות קבועות לאורך כל התרגיל.","נשפו וכופפו את המוט כלפי מעלה לכיוון הכתפיים, תוך כיווץ שריר הביצפס.","עצרו לרגע בשיא התנועה, תוך כיווץ שריר הביצפס.","שאפו והורידו את המוט לאט חזרה לתנוחת ההתחלה, תוך יישור מלא של הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a straight bar to a low pulley cable machine.","Stand facing the machine with your feet shoulder-width apart and your knees slightly bent.","Grasp the bar with an underhand grip, hands shoulder-width apart.","Keep your elbows close to your sides and your upper arms stationary throughout the exercise.","Exhale and curl the bar up towards your shoulders, contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the bar back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"BCGQ6J5"},{"id":"edb-1631","name":"כפיפת מרפק בפולי","name_en":"cable concentration curl","muscle":"biceps","equipment":"cable","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל או כיסא כשכפות הרגליים שטוחות על הרצפה והברכיים כפופות מעט.","אחזו בידית הפולי באחיזה תחתונה והניחו את המרפק על פנים הירך.","תוך שמירה על הזרוע העליונה קבועה, נשפו וכופפו את ידית הפולי לכיוון הכתף תוך כיווץ הביצפס.","עצרו לרגע בשיא התנועה, ולאחר מכן שאפו והורידו את ידית הפולי לאט חזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Sit on a bench or chair with your feet flat on the floor and your knees slightly bent.","Hold the cable handle with an underhand grip and rest your elbow against the inside of your thigh.","Keeping your upper arm stationary, exhale and curl the cable handle towards your shoulder while contracting your biceps.","Pause for a moment at the top of the movement, then inhale and slowly lower the cable handle back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"NvfE43H"},{"id":"edb-0152","name":"פשיטה בפולי","name_en":"cable concentration extension (on knee)","muscle":"triceps","equipment":"cable","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל או כיסא כשהברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","אחזו בידית הפולי ביד ימין והניחו את המרפק על פנים הברך הימנית.","יישרו את הזרוע לחלוטין, תוך שמירה על המרפק קבוע וצמוד לברך.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את הזרוע לאט חזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Sit on a bench or chair with your knees bent and feet flat on the ground.","Hold the cable handle with your right hand and place your elbow on the inside of your right knee.","Extend your arm fully, keeping your elbow stationary and close to your knee.","Pause for a moment at the top, then slowly lower your arm back to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"Db7eEgw"},{"id":"edb-0153","name":"קרוסאובר לצדדים בפולי","name_en":"cable cross-over lateral pulldown","muscle":"back","equipment":"cable","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","rhomboids","rear deltoids"],"steps":["חברו ידית פולי לכל צד של מכונת הפולי בגובה הכתפיים.","עמדו במרכז המכונה כשרגליכם ברוחב הכתפיים.","אחזו בידיות באחיזה עליונה וצעדו אחורה כדי ליצור מתח בכבלים.","הטו את הגוף מעט קדימה מהמותניים, תוך שמירה על הגב ישר והחזה מורם.","משכו את הידיות כלפי מטה ולרוחב הגוף, תוך כיווץ השכמות זו לזו.","עצרו לרגע בתחתית התנועה, ולאחר מכן חזרו לאט לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a cable handle to each side of a cable machine at shoulder height.","Stand in the middle of the machine with your feet shoulder-width apart.","Grasp the handles with an overhand grip and step back to create tension in the cables.","Lean forward slightly from the hips, keeping your back straight and your chest up.","Pull the handles down and across your body, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"OQ1otBN"},{"id":"edb-0154","name":"קרוסאובר בפולי","name_en":"cable cross-over revers fly","muscle":"shoulders","equipment":"cable","target":"delts","bodyPart":"shoulders","secondaryMuscles":["rhomboids","trapezius"],"steps":["חברו ידית D לכל כבל בגלגלת התחתונה ועמדו במרכז מכונת הפולי המוצלבת.","אחזו בידיות באחיזה פרונטית (כפות הידיים פונות למטה) וצעדו צעד קדימה, כשרגליכם ברוחב הכתפיים.","כופפו את הברכיים מעט והטו את הגוף קדימה מהמותניים, תוך שמירה על הגב ישר ושרירי הבטן מופעלים.","כשהזרועות מושטות הצדה וכפופות מעט במרפקים, נשפו וכווצו את השכמות זו לזו תוך משיכת הכבלים אחורה ומעלה בתנועת פרפר הפוכה.","עצרו לרגע בשיא הכיווץ, ולאחר מכן שאפו וחזרו לאט לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a D-handle to each low pulley cable and stand in the middle of the cable crossover machine.","Grasp the handles with a pronated grip (palms facing down) and take a step forward, positioning your feet shoulder-width apart.","Bend your knees slightly and lean forward at the waist, keeping your back straight and your abs engaged.","With your arms extended out to the sides and slightly bent at the elbows, exhale and squeeze your shoulder blades together as you pull the cables back and upward in a reverse fly motion.","Pause for a moment at the peak contraction, then inhale and slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"aqvSOQE"},{"id":"edb-0155","name":"קרוסאובר בפולי","name_en":"cable cross-over variation","muscle":"chest","equipment":"cable","target":"pectorals","bodyPart":"chest","secondaryMuscles":["deltoids","triceps"],"steps":["כווננו את גלגלות הפולי לגובה החזה.","עמדו במרכז מכונת הפולי כשרגל אחת לפני השנייה.","אחזו בידיות כשכפות הידיים פונות למטה והזרועות מושטות הצדה.","צעדו צעד קדימה, תוך שמירה על הזרועות כפופות מעט.","עם כיפוף קל במרפקים, קרבו את הידיים זו לזו לפני החזה.","עצרו לרגע, ולאחר מכן החזירו את הזרועות לאט לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the cable pulleys to chest height.","Stand in the center of the cable machine with one foot in front of the other.","Grasp the handles with your palms facing down and your arms extended out to the sides.","Take a step forward, keeping your arms slightly bent.","With a slight bend in your elbows, bring your hands together in front of your chest.","Pause for a moment, then slowly return your arms back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"0CXGHya"},{"id":"edb-0868","name":"כפיפת מרפק בפולי","name_en":"cable curl","muscle":"biceps","equipment":"cable","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו מול מכונת הפולי כשרגליכם ברוחב הכתפיים.","אחזו באביזר הפולי באחיזה תחתונה, כשכפות הידיים פונות למעלה.","שמרו על המרפקים צמודים לגוף והזרועות העליונות קבועות.","נשפו וכופפו את אביזר הפולי לכיוון הכתפיים, תוך כיווץ הביצפס.","עצרו לרגע בשיא התנועה, תוך כיווץ שריר הביצפס.","שאפו והורידו את אביזר הפולי לאט חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand facing the cable machine with your feet shoulder-width apart.","Grasp the cable attachment with an underhand grip, palms facing up.","Keep your elbows close to your sides and your upper arms stationary.","Exhale and curl the cable attachment towards your shoulders, contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the cable attachment back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"G08RZcQ"},{"id":"edb-0157","name":"דדליפט בפולי","name_en":"cable deadlift","muscle":"glutes","equipment":"cable","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps","lower back"],"steps":["עמדו מול מכונת הפולי כשרגליכם ברוחב הכתפיים.","כופפו במותניים ובברכיים, תוך הורדת פלג הגוף העליון עד שהגב מקביל לרצפה.","אחזו בידיות הפולי באחיזה עליונה, תוך שמירה על הזרועות ישרות והכתפיים לאחור.","הפעילו את שרירי הישבן והירך האחורית כדי להרים את ידיות הפולי, תוך יישור האגן וזקיפת הגוף.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את ידיות הפולי לאט חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand facing the cable machine with your feet shoulder-width apart.","Bend at the hips and knees, lowering your torso until your back is parallel to the ground.","Grasp the cable handles with an overhand grip, keeping your arms straight and your shoulders back.","Engage your glutes and hamstrings to lift the cable handles, extending your hips and standing up straight.","Pause for a moment at the top, then slowly lower the cable handles back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"eGDudUV"},{"id":"edb-0158","name":"פרפר בשיפוע שלילי בפולי","name_en":"cable decline fly","muscle":"chest","equipment":"cable","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["כווננו את מכונת הפולי לעמדה יורדת.","עמדו כשגבכם למכונה ורגליכם ברוחב הכתפיים.","אחזו בידיות כשכפות הידיים פונות קדימה והזרועות מושטות ישר לפניכם.","תוך שמירה על כיפוף קל במרפקים, פתחו את הזרועות הצדה בתנועה מבוקרת.","עצרו לרגע בתנוחת היישור המלא, ולאחר מכן חזרו לאט לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the cable machine to a decline position.","Stand facing away from the machine with your feet shoulder-width apart.","Hold the handles with your palms facing forward and your arms extended straight out in front of you.","Keeping a slight bend in your elbows, open your arms out to the sides in a controlled motion.","Pause for a moment at the fully extended position, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"7saC5zz"},{"id":"edb-1260","name":"לחיצה ביד אחת בשיפוע שלילי בפולי","name_en":"cable decline one arm press","muscle":"chest","equipment":"cable","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["כווננו את מכונת הפולי לעמדה יורדת.","עמדו כשגבכם למכונה ואחזו בידית ביד אחת.","מקמו את עצמכם כשהגב שלכם צמוד לספסל היורד והזרוע מושטת ישר לפניכם.","כופפו את המרפק והורידו את הידית לכיוון החזה תוך שמירה על הזרוע העליונה קבועה.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו את הידית חזרה למעלה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Adjust the cable machine to a decline position.","Stand facing away from the machine and grab the handle with one hand.","Position yourself with your back against the decline bench and your arm extended straight in front of you.","Bend your elbow and lower the handle towards your chest while keeping your upper arm stationary.","Pause for a moment at the bottom, then push the handle back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"KHGNa16"},{"id":"edb-1261","name":"לחיצה בשיפוע שלילי בפולי","name_en":"cable decline press","muscle":"chest","equipment":"cable","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["כווננו את מכונת הפולי לעמדה יורדת.","שבו על הספסל היורד מול מכונת הפולי.","אחזו בידיות באחיזה עליונה ומקמו אותן בגובה החזה.","שמרו על כפות הרגליים שטוחות על הרצפה והגב צמוד היטב לספסל.","נשפו ודחפו את הידיות הרחק מהגוף, תוך יישור מלא של הזרועות.","עצרו לרגע בסוף התנועה, תוך כיווץ שרירי החזה.","שאפו והחזירו את הידיות לאט לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the cable machine to a decline position.","Sit on the decline bench facing the cable machine.","Grasp the handles with an overhand grip and position them at chest level.","Keep your feet flat on the ground and your back firmly against the bench.","Exhale and push the handles away from your body, extending your arms fully.","Pause for a moment at the end of the movement, squeezing your chest muscles.","Inhale and slowly return the handles back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"2Pya1cP"},{"id":"edb-0159","name":"חתירה אחיזה רחבה בשיפוע שלילי בישיבה בפולי","name_en":"cable decline seated wide-grip row","muscle":"back","equipment":"cable","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["שבו על הספסל היורד מול מכונת הפולי כשכפות הרגליים מונחות בבטחה על משעני הרגליים.","אחזו באביזר הפולי באחיזה עליונה רחבה, כשכפות הידיים פונות למטה.","הטו את הגוף מעט אחורה, תוך שמירה על הגב ישר ושרירי הליבה מופעלים.","משכו את הכבל לכיוון תחתית החזה, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא הכיווץ, ולאחר מכן שחררו את הכבל לאט חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the decline bench facing the cable machine with your feet securely placed on the footrests.","Grasp the cable attachment with a wide overhand grip, palms facing down.","Lean back slightly, keeping your back straight and your core engaged.","Pull the cable towards your lower chest, squeezing your shoulder blades together.","Pause for a moment at the peak of the contraction, then slowly release the cable back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"kesXOpB"},{"id":"edb-1632","name":"כפיפת מרפק בפולי","name_en":"cable drag curl","muscle":"biceps","equipment":"cable","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו מול מכונת הפולי כשרגליכם ברוחב הכתפיים.","אחזו באביזר הפולי באחיזה תחתונה, כפות הידיים פונות למעלה, והזרועות מיושרות לחלוטין.","תוך שמירה על הזרועות העליונות קבועות, נשפו וכופפו את אביזר הפולי לכיוון הכתפיים על ידי כיווץ הביצפס.","עצרו לרגע בשיא התנועה, תוך כיווץ שריר הביצפס.","שאפו והורידו את אביזר הפולי לאט חזרה לתנוחת ההתחלה, תוך יישור מלא של הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand facing a cable machine with your feet shoulder-width apart.","Grasp the cable attachment with an underhand grip, palms facing up, and arms fully extended.","Keeping your upper arms stationary, exhale and curl the cable attachment towards your shoulders by contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the cable attachment back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"dXz8zjF"},{"id":"edb-0160","name":"חתירה אחיזה רחבה בישיבה בפולי","name_en":"cable floor seated wide-grip row","muscle":"back","equipment":"cable","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["שבו על הרצפה כשהרגליים מושטות והגב ישר.","חברו ידית פולי לגלגלת תחתונה ומקמו את מכונת הפולי מאחוריכם.","אחזו בידית באחיזה עליונה רחבה, כשכפות הידיים פונות למטה.","הטו את הגוף מעט אחורה, תוך שמירה על הגב ישר והחזה מורם.","משכו את הידית לכיוון המותניים, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה, ולאחר מכן שחררו את הידית לאט חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the floor with your legs extended and your back straight.","Attach a cable handle to a low pulley and position the cable machine behind you.","Grasp the handle with a wide overhand grip, palms facing down.","Lean back slightly, keeping your back straight and your chest lifted.","Pull the handle towards your waist, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly release the handle back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"veXwo0D"},{"id":"edb-0161","name":"הרמה בפולי","name_en":"cable forward raise","muscle":"shoulders","equipment":"cable","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","אחזו בידית הפולי באחיזה עליונה, כפות הידיים פונות למטה, והזרועות מיושרות לחלוטין לפניכם.","תוך שמירה על הזרועות ישרות, הרימו את ידית הפולי לגובה הכתפיים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את ידית הפולי לאט חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your knees slightly bent.","Hold the cable handle with an overhand grip, palms facing down, and your arms fully extended in front of you.","Keeping your arms straight, raise the cable handle up to shoulder level.","Pause for a moment at the top, then slowly lower the cable handle back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"hvHhCv8"},{"id":"edb-0162","name":"הרמה קדמית בפולי","name_en":"cable front raise","muscle":"shoulders","equipment":"cable","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","forearms"],"steps":["עמדו כשרגליכם ברוחב הכתפיים ואחזו בידית הפולי באחיזה עליונה.","שמרו על גב ישר ושרירי ליבה מופעלים.","הרימו את ידית הפולי לפניכם, תוך שמירה על הזרועות ישרות וכפות הידיים פונות למטה.","המשיכו להרים עד שהזרועות מקבילות לרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את ידית הפולי לאט חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and grasp the cable handle with an overhand grip.","Keep your back straight and your core engaged.","Raise the cable handle in front of you, keeping your arms straight and your palms facing down.","Continue lifting until your arms are parallel to the floor.","Pause for a moment at the top, then slowly lower the cable handle back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"u2X71Np"},{"id":"edb-0164","name":"הרמה קדמי בפולי","name_en":"cable front shoulder raise","muscle":"shoulders","equipment":"cable","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","biceps"],"steps":["עמדו כשרגליכם ברוחב הכתפיים ואחזו בידית הפולי באחיזה עליונה.","שמרו על גב ישר ושרירי ליבה מופעלים.","הרימו את ידית הפולי לפניכם, תוך שמירה על הזרועות ישרות וכפות הידיים פונות למטה.","המשיכו להרים עד שהזרועות מקבילות לרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את ידית הפולי לאט חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and grasp the cable handle with an overhand grip.","Keep your back straight and your core engaged.","Raise the cable handle in front of you, keeping your arms straight and your palms facing down.","Continue lifting until your arms are parallel to the floor.","Pause for a moment at the top, then slowly lower the cable handle back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"mTT3KLn"},{"id":"edb-0165","name":"כפיפת פטיש עם חבל בפולי","name_en":"cable hammer curl (with rope)","muscle":"biceps","equipment":"cable","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף כשרגליכם ברוחב הכתפיים וכיפוף קל בברכיים.","אחזו באביזר החבל של הפולי באחיזה תחתונה, כפות הידיים פונות זו לזו, והזרועות מיושרות לחלוטין.","תוך שמירה על הזרוע העליונה ללא תזוזה, נשפו החוצה וכופפו את המשקולות תוך כיווץ שרירי הביצפס.","המשיכו להרים את אביזר החבל עד שהביצפס מכווץ לחלוטין והחבל בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו והתחילו להוריד לאט את אביזר החבל חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand upright with your feet shoulder-width apart and a slight bend in your knees.","Hold the cable rope attachment with an underhand grip, palms facing each other, and your arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the cable rope attachment until your biceps are fully contracted and the rope is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the cable rope attachment back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"HPlPoQA"},{"id":"edb-1722","name":"פשיטת מרפק מעל הראש גבוה בפולי","name_en":"cable high pulley overhead tricep extension","muscle":"triceps","equipment":"cable","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["חברו חבל לגלגלת עליונה ועמדו כשגבכם למכונה.","אחזו בחבל בשתי הידיים ויישרו את הזרועות מעל הראש.","שמרו על המרפקים קרובים לראש והזרועות העליונות קבועות.","הורידו את החבל לאט מאחורי הראש על ידי כיפוף המרפקים.","עצרו לרגע, ולאחר מכן יישרו את הזרועות חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a rope to a high pulley and stand facing away from the machine.","Grasp the rope with both hands and extend your arms overhead.","Keep your elbows close to your head and your upper arms stationary.","Slowly lower the rope behind your head by bending your elbows.","Pause for a moment, then extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"1xHyxys"},{"id":"edb-0167","name":"חתירה בכריעה גבוה בפולי","name_en":"cable high row (kneeling)","muscle":"back","equipment":"cable","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","shoulders"],"steps":["חברו מוט ישר למכונת הפולי בגובה החזה.","כרעו לפני מכונת הפולי ואחזו במוט באחיזה עליונה, כשהידיים ברוחב הכתפיים.","שבו על העקבים, תוך שמירה על הגב ישר ושרירי הליבה מופעלים.","משכו את המוט לכיוון החלק העליון של הבטן, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה, ולאחר מכן שחררו את המוט לאט חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a straight bar to a cable machine at chest height.","Kneel down in front of the cable machine and grab the bar with an overhand grip, hands shoulder-width apart.","Sit back on your heels, keeping your back straight and your core engaged.","Pull the bar towards your upper abdomen, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly release the bar back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ZSJNetl"},{"id":"edb-0168","name":"cable hip adduction","name_en":"cable hip adduction","muscle":"legs","equipment":"cable","target":"adductors","bodyPart":"upper legs","secondaryMuscles":["glutes","quadriceps"],"steps":["חברו את רצועת הקרסול לקרסול ועמדו מול מכונת הפולי.","מקמו את עצמכם רחוק מספיק מהמכונה כך שיהיה מתח על הכבל.","הניחו את הידיים על המכונה לתמיכה.","תוך שמירה על הרגל ישרה, הזיזו אותה לאט לרוחב הגוף לכיוון קו האמצע.","עצרו לרגע בסוף התנועה, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach the ankle cuff to your ankle and stand facing the cable machine.","Position yourself far enough away from the machine so that there is tension on the cable.","Place your hands on the machine for support.","Keeping your leg straight, slowly move your leg across your body towards the midline.","Pause for a moment at the end of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"hBGWILP"},{"id":"edb-0169","name":"לחיצת חזה בשיפוע בפולי","name_en":"cable incline bench press","muscle":"chest","equipment":"cable","target":"pectorals","bodyPart":"chest","secondaryMuscles":["deltoids","triceps"],"steps":["כווננו את הספסל לשיפוע של 45 מעלות.","חברו את ידיות הפולי לגלגלות העליונות.","שבו על הספסל מול מכונת הפולי כשכפות הרגליים שטוחות על הרצפה.","אחזו בידיות באחיזה עליונה והביאו אותן לגובה הכתפיים.","דחפו את הידיות קדימה ומעלה עד שהזרועות מיושרות לחלוטין.","עצרו לרגע, ולאחר מכן הורידו את הידיות לאט חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the bench to a 45-degree incline.","Attach the cable handles to the high pulleys.","Sit on the bench facing the cable machine with your feet flat on the ground.","Grasp the handles with an overhand grip and bring them to shoulder height.","Push the handles forward and upward until your arms are fully extended.","Pause for a moment, then slowly lower the handles back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Vh0GsK4"},{"id":"edb-1318","name":"חתירה בשיפוע בפולי","name_en":"cable incline bench row","muscle":"back","equipment":"cable","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","rear deltoids"],"steps":["הציבו ספסל משופע בזווית של 45 מעלות וחברו ידית פולי לגלגלת התחתונה.","שבו על הספסל מול מכונת הפולי כשכפות הרגליים שטוחות על הרצפה והברכיים כפופות מעט.","אחזו בידית הפולי באחיזה עליונה ויישרו את הזרועות לחלוטין לפניכם.","הטו את הגוף קדימה מהמותניים תוך שמירה על הגב ישר ושרירי הליבה מופעלים.","משכו את ידית הפולי לכיוון החזה על ידי קירוב השכמות וכיפוף המרפקים.","כווצו את שרירי הגב בשיא התנועה, ולאחר מכן יישרו את הזרועות לאט חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up an incline bench at a 45-degree angle and attach a cable handle to the low pulley.","Sit on the bench facing the cable machine with your feet flat on the floor and your knees slightly bent.","Grasp the cable handle with an overhand grip and extend your arms fully in front of you.","Lean forward from your hips while keeping your back straight and your core engaged.","Pull the cable handle towards your chest by retracting your shoulder blades and bending your elbows.","Squeeze your back muscles at the top of the movement, then slowly extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"yaMIo4D"},{"id":"edb-0171","name":"פרפר בשיפוע בפולי","name_en":"cable incline fly","muscle":"chest","equipment":"cable","target":"pectorals","bodyPart":"chest","secondaryMuscles":["deltoids","triceps"],"steps":["כווננו את מכונת הפולי לעמדה נמוכה וחברו את הידיות.","שבו על ספסל משופע כשהגב צמוד לכרית וכפות הרגליים שטוחות על הרצפה.","אחזו בידיות באחיזה עליונה ויישרו את הזרועות ישר לפניכם.","תוך שמירה על כיפוף קל במרפקים, פתחו את הזרועות הצדה בתנועה מבוקרת.","עצרו לרגע בתנוחת היישור המלא, ולאחר מכן חזרו לאט לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the cable machine to a low position and attach the handles.","Sit on an incline bench with your back against the pad and feet flat on the floor.","Grasp the handles with an overhand grip and extend your arms straight out in front of you.","Keeping a slight bend in your elbows, open your arms out to the sides in a controlled motion.","Pause for a moment at the fully extended position, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"tBWXbIT"},{"id":"edb-0170","name":"פרפר בשיפוע עם כדור פיזיו","name_en":"cable incline fly (on stability ball)","muscle":"chest","equipment":"cable","target":"pectorals","bodyPart":"chest","secondaryMuscles":["deltoids","triceps"],"steps":["הציבו כדור יציבות בזווית משופעת.","חברו את ידיות הפולי לגלגלות העליונות של מכונת הפולי.","שבו על כדור היציבות כשגבכם למכונה, כשכפות הרגליים נטועות היטב על הרצפה.","אחזו בידיות הפולי באחיזה עליונה, כשכפות הידיים פונות קדימה.","הטו את הגוף מעט קדימה, תוך שמירה על הגב ישר ושרירי הליבה מופעלים.","בתנועה מבוקרת, הביאו את הזרועות הצדה, תוך שמירה על כיפוף קל במרפקים.","המשיכו בתנועה עד שהזרועות מקבילות לרצפה.","עצרו לרגע, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up a stability ball at an incline angle.","Attach the cable handles to the high pulleys of a cable machine.","Sit on the stability ball facing away from the machine, with your feet firmly planted on the ground.","Grasp the cable handles with an overhand grip, palms facing forward.","Lean forward slightly, keeping your back straight and core engaged.","With a controlled motion, bring your arms out to the sides, keeping a slight bend in your elbows.","Continue the motion until your arms are parallel to the ground.","Pause for a moment, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"27NNGFr"},{"id":"edb-0172","name":"פשיטת מרפק בפולי בשיפוע בפולי","name_en":"cable incline pushdown","muscle":"back","equipment":"cable","target":"lats","bodyPart":"back","secondaryMuscles":["triceps","shoulders"],"steps":["חברו מוט ישר לגלגלת עליונה של מכונת הפולי.","עמדו כשגבכם למכונה ורגליכם ברוחב הכתפיים.","אחזו במוט באחיזה עליונה, כשהידיים ברוחב מעט גדול מרוחב הכתפיים.","הטו את הגוף מעט קדימה ושמרו על הגב ישר.","משכו את המוט כלפי מטה לכיוון הירכיים על ידי יישור המרפקים.","עצרו לרגע בתחתית התנועה, ולאחר מכן החזירו את המוט לאט לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a straight bar to a high pulley cable machine.","Stand facing away from the machine with your feet shoulder-width apart.","Grasp the bar with an overhand grip, hands slightly wider than shoulder-width apart.","Lean forward slightly and keep your back straight.","Pull the bar down towards your thighs by extending your elbows.","Pause for a moment at the bottom, then slowly return the bar to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"1PK5Uo3"},{"id":"edb-0173","name":"פשיטת מרפק בשיפוע בפולי","name_en":"cable incline triceps extension","muscle":"triceps","equipment":"cable","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["כווננו את מכונת הפולי לעמדת גלגלת תחתונה.","חברו מוט ישר לכבל.","עמדו כשגבכם למכונה ורגליכם ברוחב הכתפיים.","אחזו במוט באחיזה עליונה ויישרו את הזרועות ישר מעל הראש.","הטו את הגוף מעט קדימה, תוך שמירה על הגב ישר ושרירי הליבה מופעלים.","כופפו את המרפקים והורידו את המוט מאחורי הראש, תוך שמירה על הזרועות העליונות קרובות לאוזניים.","עצרו לרגע, ולאחר מכן יישרו את הזרועות חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the cable machine to a low pulley position.","Attach a straight bar to the cable.","Stand facing away from the machine with your feet shoulder-width apart.","Grasp the bar with an overhand grip and extend your arms straight overhead.","Lean forward slightly, keeping your back straight and core engaged.","Bend your elbows and lower the bar behind your head, keeping your upper arms close to your ears.","Pause for a moment, then extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Hx1WC8I"},{"id":"edb-0174","name":"cable judo flip","name_en":"cable judo flip","muscle":"core","equipment":"cable","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","shoulders"],"steps":["עמדו מול מכונת הפולי כשרגליכם ברוחב הכתפיים.","אחזו בידית הפולי בשתי הידיים בגובה החזה, כשכפות הידיים פונות למטה.","הפעילו את שרירי הליבה וסובבו את פלג הגוף העליון ימינה, תוך משיכת הכבל לרוחב הגוף.","תוך כדי הסיבוב, סובבו את כף הרגל האחורית ואפשרו לאגן להסתובב באופן טבעי.","יישרו את הזרועות לחלוטין וסיימו את התנועה על ידי הפניית ידית הפולי מעל הכתף.","חזרו לתנוחת ההתחלה על ידי היפוך התנועה, תוך סיבוב פלג הגוף העליון חזרה למרכז.","חזרו על התנועה בצד הנגדי.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Stand facing the cable machine with your feet shoulder-width apart.","Hold the cable handle with both hands at chest level, palms facing down.","Engage your core and rotate your torso to the right, pulling the cable across your body.","As you rotate, pivot your back foot and allow your hips to rotate naturally.","Extend your arms fully and finish the movement by flipping the cable handle over your shoulder.","Return to the starting position by reversing the movement, rotating your torso back to the center.","Repeat the movement on the opposite side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"MvQPqVW"},{"id":"edb-0860","name":"בעיטה אחורית בפולי","name_en":"cable kickback","muscle":"triceps","equipment":"cable","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["עמדו מול מכונת הפולי כשרגליכם ברוחב הכתפיים.","אחזו בידית הפולי ביד ימין וצעדו אחורה כדי ליצור מתח בכבל.","כופפו מעט את הברכיים והטו את הגוף קדימה במפרקי הירך, תוך שמירה על גב ישר.","שמרו על הזרוע העליונה צמודה לגוף והמרפק כפוף בזווית של 90 מעלות.","יישרו את האמה לאחור, עד ליישור מלא של הזרוע.","עצרו לרגע, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Stand facing a cable machine with your feet shoulder-width apart.","Hold the cable handle with your right hand and step back to create tension in the cable.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Keep your upper arm close to your body and your elbow bent at a 90-degree angle.","Extend your forearm backward, straightening your arm fully.","Pause for a moment, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"HEJ6DIX"},{"id":"edb-0175","name":"כפיפת בטן בפולי","name_en":"cable kneeling crunch","muscle":"core","equipment":"cable","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques"],"steps":["חברו ידית חבל לגלגלת עליונה וכרעו כשגבכם למכונה.","אחזו בידית החבל בשתי הידיים והניחו אותה מאחורי הראש, תוך שמירה על המרפקים הצדה.","תוך שמירה על האגן קבוע, כופפו את המותניים וקמטו את פלג הגוף העליון כלפי מטה לכיוון הירכיים.","עצרו לרגע בתחתית התנועה, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a rope handle to a high pulley and kneel down facing away from the machine.","Hold the rope handle with both hands and place it behind your head, keeping your elbows out to the sides.","Keeping your hips stationary, flex your waist and crunch your torso down towards your thighs.","Pause for a moment at the bottom, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"WW95auq"},{"id":"edb-3697","name":"חתירת כתף אחורית בכריעה עם חבל בפולי","name_en":"cable kneeling rear delt row (with rope) (male)","muscle":"shoulders","equipment":"cable","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","rhomboids","biceps"],"steps":["חברו ידית חבל לגלגלת תחתונה של הפולי וכרעו מול המכונה.","אחזו בחבל באחיזה ניטרלית (כפות הידיים פונות זו לזו) ויישרו את הזרועות לחלוטין לפניכם.","תוך שמירה על הגב ישר ושרירי הליבה מופעלים, משכו את החבל לכיוון הגוף על ידי קירוב השכמות.","כווצו את השכמות זו לזו בסוף התנועה והחזיקו לעצירה קצרה.","שחררו את המתח לאט וחזרו לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a rope handle to a low cable pulley and kneel down facing the machine.","Grasp the rope with a neutral grip (palms facing each other) and extend your arms fully in front of you.","Keeping your back straight and core engaged, pull the rope towards your body by retracting your shoulder blades.","Squeeze your shoulder blades together at the end of the movement and hold for a brief pause.","Slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"G61cXLk"},{"id":"edb-0176","name":"פשיטת מרפק בכריעה בפולי","name_en":"cable kneeling triceps extension","muscle":"triceps","equipment":"cable","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["חברו ידית חבל לגלגלת עליונה וכרעו מול מכונת הפולי.","אחזו בחבל באחיזה ניטרלית (כפות הידיים פונות זו לזו) והביאו את הידיים לצדי הראש.","שמרו על המרפקים קרובים לראש והזרועות העליונות קבועות לאורך כל התרגיל.","יישרו את האמות על ידי כיווץ שריר הטריצפס עד שהזרועות מיושרות לחלוטין.","עצרו לרגע, ולאחר מכן חזרו לאט לתנוחת ההתחלה על ידי כיפוף המרפקים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a rope handle to a high pulley and kneel down facing the cable machine.","Grasp the rope with a neutral grip (palms facing each other) and bring your hands to the sides of your head.","Keep your elbows close to your head and your upper arms stationary throughout the exercise.","Extend your forearms by contracting your triceps until your arms are fully extended.","Pause for a moment, then slowly return to the starting position by bending your elbows.","Repeat for the desired number of repetitions."],"mediaId":"KWdF2JI"},{"id":"edb-2330","name":"פולי עליון","name_en":"cable lat pulldown full range of motion","muscle":"back","equipment":"cable","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","rhomboids","rear deltoids"],"steps":["שבו על מכונת פולי עליון כשהברכיים ממוקמות מתחת לכריות.","אחזו במוט הפולי באחיזה עליונה, ברוחב מעט גדול מרוחב הכתפיים.","הטו את הגוף מעט אחורה ושמרו על החזה מורם, תוך שמירה על קמור קל בגב התחתון.","משכו את המוט כלפי מטה לכיוון החלק העליון של החזה, תוך כיווץ השכמות זו לזו.","עצרו לרגע בתחתית התנועה, ולאחר מכן שחררו את המוט לאט חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the lat pulldown machine with your knees positioned under the pads.","Grasp the cable bar with an overhand grip, slightly wider than shoulder-width apart.","Lean back slightly and keep your chest up, maintaining a slight arch in your lower back.","Pull the bar down towards your upper chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the bar back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"LEprlgG"},{"id":"edb-0177","name":"משיכת פולי לצדדים עם חבל בפולי","name_en":"cable lateral pulldown (with rope attachment)","muscle":"back","equipment":"cable","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["חברו אביזר חבל למכונת הפולי בעמדה גבוהה.","עמדו מול המכונה עם הרגליים ברוחב הכתפיים.","אחזו בחבל באחיזה עליונה, כשכפות הידיים פונות זו לזו.","שמרו על הגב ישר והטו את הגוף מעט אחורה.","משכו את החבל כלפי מטה לצדי הגוף, תוך כיווץ השכמות זו לזו.","עצרו לרגע בתחתית התנועה.","שחררו את המתח לאט ואפשרו לחבל לחזור לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a rope attachment to the cable machine at a high position.","Stand facing the machine with your feet shoulder-width apart.","Grasp the rope with an overhand grip, palms facing each other.","Keep your back straight and lean slightly back.","Pull the rope down towards your sides, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement.","Slowly release the tension and allow the rope to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"CuaWCmC"},{"id":"edb-2616","name":"משיכת פולי עם ידית V לצדדים בפולי","name_en":"cable lateral pulldown with v-bar","muscle":"back","equipment":"cable","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["שבו על מכונת הפולי העליון ואחזו באביזר מוט ה-V באחיזה עליונה.","כווננו את כרית הברכיים כך שהירכיים מהודקות מתחתיה.","שמרו על הגב ישר והטו את הגוף מעט אחורה.","משכו את מוט ה-V כלפי מטה לכיוון החלק העליון של החזה תוך שמירה על המרפקים צמודים לגוף.","כווצו את שרירי הגב בתחתית התנועה.","החזירו את מוט ה-V לאט לתנוחת ההתחלה וחזרו למספר החזרות הרצוי."],"steps_en":["Sit down on the cable pulldown machine and grab the v-bar attachment with an overhand grip.","Adjust the knee pad so that your thighs are secured under it.","Keep your back straight and lean back slightly.","Pull the v-bar down towards your upper chest while keeping your elbows close to your body.","Squeeze your back muscles at the bottom of the movement.","Slowly return the v-bar to the starting position and repeat for the desired number of repetitions."],"mediaId":"4c9BhzB"},{"id":"edb-0178","name":"הרחקת כתפיים לצדדים בפולי","name_en":"cable lateral raise","muscle":"shoulders","equipment":"cable","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","triceps"],"steps":["עמדו כשרגליכם ברוחב הכתפיים ואחזו בידיות הפולי באחיזה עליונה.","שמרו על הזרועות ישרות ושרירי הליבה מופעלים.","הרימו את הזרועות הצדה עד שהן מקבילות לרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הידיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and grasp the cable handles with an overhand grip.","Keep your arms straight and your core engaged.","Raise your arms out to the sides until they are parallel to the floor.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"goJ6ezq"},{"id":"edb-0179","name":"פרפר נמוך בפולי","name_en":"cable low fly","muscle":"chest","equipment":"cable","target":"pectorals","bodyPart":"chest","secondaryMuscles":["deltoids","triceps"],"steps":["חברו את הידיות לגלגלות התחתונות של מכונת הפולי ובחרו משקל מתאים.","עמדו במרכז המכונה כשרגליכם ברוחב הכתפיים וכיפוף קל בברכיים.","אחזו בידיות באחיזה עליונה ויישרו את הזרועות הצדה, תוך שמירה על כיפוף קל במרפקים.","תוך שמירה על שליטה, הביאו את הזרועות לאט קדימה בתנועה מקיפה, תוך הצלבתן לפני הגוף.","עצרו לרגע בשיא התנועה, תוך הרגשת מתיחה בשרירי החזה.","הפכו את התנועה והחזירו את הזרועות לאט לתנוחת ההתחלה, תוך שמירה על מתח בשרירי החזה לאורך כל הדרך.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach the handles to the low pulleys of a cable machine and select an appropriate weight.","Stand in the middle of the machine with your feet shoulder-width apart and a slight bend in your knees.","Grasp the handles with an overhand grip and extend your arms out to the sides, keeping a slight bend in your elbows.","Maintaining control, slowly bring your arms forward in a sweeping motion, crossing them in front of your body.","Pause for a moment at the peak of the movement, feeling the stretch in your chest muscles.","Reverse the motion and slowly return your arms to the starting position, keeping tension on your chest muscles throughout.","Repeat for the desired number of repetitions."],"mediaId":"FVmZVhk"},{"id":"edb-0180","name":"חתירה בישיבה נמוך בפולי","name_en":"cable low seated row","muscle":"back","equipment":"cable","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["שבו על המכונה כשכפות הרגליים שטוחות על משעני הרגליים והברכיים כפופות מעט.","אחזו בידיות באחיזה עליונה, כשכפות הידיים פונות למטה.","שמרו על הגב ישר והטו את הגוף מעט קדימה, תוך שמירה על כיפוף קל במרפקים.","משכו את הידיות לכיוון הגוף, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה, ולאחר מכן שחררו לאט את הידיות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the machine with your feet flat on the footrests and your knees slightly bent.","Grasp the handles with an overhand grip, palms facing down.","Keep your back straight and lean slightly forward, maintaining a slight bend in your elbows.","Pull the handles towards your body, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"hvV79Si"},{"id":"edb-1634","name":"כפיפת מרפק בשכיבה בפולי","name_en":"cable lying bicep curl","muscle":"biceps","equipment":"cable","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["חברו מוט ישר לגלגלת תחתונה של מכונת הפולי.","שכבו על הגב על ספסל שטוח כשכפות הרגליים שטוחות על הרצפה.","אחזו במוט באחיזה תחתונה, כשהידיים ברוחב הכתפיים.","יישרו את הזרועות לחלוטין, תוך שמירה על המרפקים צמודים לגוף.","תוך שמירה על הזרועות העליונות קבועות, נשפו וכופפו את המוט כלפי מעלה לכיוון הכתפיים.","עצרו לרגע בשיא התנועה, תוך כיווץ שרירי הביצפס.","שאפו והורידו את המוט לאט חזרה לתנוחת ההתחלה, תוך יישור מלא של הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a straight bar to a low pulley cable machine.","Lie face up on a flat bench with your feet flat on the ground.","Grasp the bar with an underhand grip, hands shoulder-width apart.","Extend your arms fully, keeping your elbows close to your sides.","Keeping your upper arms stationary, exhale and curl the bar up towards your shoulders.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the bar back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"otqIxU4"},{"id":"edb-0182","name":"כפיפת מרפק אחיזה צרה בשכיבה בפולי","name_en":"cable lying close-grip curl","muscle":"biceps","equipment":"cable","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["חברו מוט ישר לגלגלת תחתונה של מכונת הפולי.","שכבו על הגב על ספסל שטוח כשכפות הרגליים שטוחות על הרצפה.","אחזו במוט באחיזה תחתונה, כשהידיים ברוחב הכתפיים.","יישרו את הזרועות לחלוטין, תוך שמירה על המרפקים צמודים לגוף.","תוך שמירה על הזרועות העליונות קבועות, כופפו את המוט לכיוון החזה על ידי כיווץ הביצפס.","עצרו לרגע בשיא התנועה, תוך כיווץ שרירי הביצפס.","הורידו את המוט לאט חזרה לתנוחת ההתחלה, תוך יישור מלא של הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a straight bar to a low pulley cable machine.","Lie face up on a flat bench with your feet flat on the ground.","Grasp the bar with an underhand grip, hands shoulder-width apart.","Extend your arms fully, keeping your elbows close to your sides.","Keeping your upper arms stationary, curl the bar towards your chest by contracting your biceps.","Pause for a moment at the top, squeezing your biceps.","Slowly lower the bar back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"61GrD55"},{"id":"edb-0184","name":"פשיטה בשכיבה עם חבל בפולי","name_en":"cable lying extension pullover (with rope attachment)","muscle":"back","equipment":"cable","target":"lats","bodyPart":"back","secondaryMuscles":["triceps","shoulders"],"steps":["חברו חבל למכונת הפולי וכווננו את הגלגלת לעמדה הגבוהה ביותר.","שכבו על ספסל כשהראש לכיוון מכונת הפולי.","אחזו בחבל בשתי הידיים ויישרו את הזרועות ישר למעלה מעל החזה.","תוך שמירה על הזרועות ישרות, הורידו את החבל לאט מאחורי הראש תוך שמירה על שליטה.","עצרו לרגע בתחתית התנועה, ולאחר מכן הרימו את החבל לאט חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a rope to a cable machine and set the pulley at the highest position.","Lie down on a bench with your head towards the cable machine.","Hold the rope with both hands and extend your arms straight up above your chest.","Keeping your arms straight, slowly lower the rope behind your head while maintaining control.","Pause for a moment at the bottom, then slowly raise the rope back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Q2Eu1Ax"},{"id":"edb-0185","name":"פרפר בשכיבה בפולי","name_en":"cable lying fly","muscle":"chest","equipment":"cable","target":"pectorals","bodyPart":"chest","secondaryMuscles":["deltoids","triceps"],"steps":["חברו את הידיות לכבלים ושכבו שטוח על ספסל כשכפות הרגליים שטוחות על הרצפה.","אחזו בידיות כשכפות הידיים פונות זו לזו והזרועות מושטות ישר מעל החזה.","תוך שמירה על כיפוף קל במרפקים, הורידו את הזרועות הצדה בקשת רחבה עד שתרגישו מתיחה בחזה.","עצרו לרגע, ולאחר מכן כווצו את שרירי החזה כדי להחזיר את הזרועות לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach the handles to the cables and lie flat on a bench with your feet flat on the ground.","Hold the handles with your palms facing each other and your arms extended straight above your chest.","Keeping a slight bend in your elbows, lower your arms out to the sides in a wide arc until you feel a stretch in your chest.","Pause for a moment, then squeeze your chest muscles to bring your arms back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"lJJ7Yq8"},{"id":"edb-0186","name":"פשיטת מרפק בשכיבה בפולי","name_en":"cable lying triceps extension v. 2","muscle":"triceps","equipment":"cable","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["חברו ידית חבל לגלגלת תחתונה של מכונת הפולי.","שכבו על ספסל שטוח כשפניכם למעלה והראש לכיוון מכונת הפולי.","אחזו בידית החבל בשתי הידיים, כפות הידיים פונות זו לזו, ויישרו את הזרועות ישר למעלה מעל החזה.","תוך שמירה על הזרועות העליונות קבועות, הורידו לאט את ידית החבל לכיוון המצח על ידי כיפוף המרפקים.","עצרו לרגע בתחתית התנועה, ולאחר מכן יישרו את הידיים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a rope handle to a low pulley cable machine.","Lie down on a flat bench facing up, with your head towards the cable machine.","Grasp the rope handle with both hands, palms facing each other, and extend your arms straight up over your chest.","Keeping your upper arms stationary, slowly lower the rope handle towards your forehead by bending your elbows.","Pause for a moment at the bottom, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"uxJcFUU"},{"id":"edb-0188","name":"פרפר אמצעי בפולי","name_en":"cable middle fly","muscle":"chest","equipment":"cable","target":"pectorals","bodyPart":"chest","secondaryMuscles":["deltoids","triceps"],"steps":["חברו כבלים לשני צדי מכונת הפולי בגובה החזה.","עמדו במרכז המכונה כשרגל אחת מעט לפני השנייה.","אחזו בידיות באחיזה עליונה ויישרו את הזרועות הצדה.","שמרו על כיפוף קל במרפקים ושמרו על הטיה קלה קדימה.","הפעילו את שרירי החזה והביאו את הזרועות קדימה בתנועה מקיפה.","עצרו לרגע במרכז, ולאחר מכן החזירו את הזרועות לאט לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach cables to both sides of a cable machine at chest height.","Stand in the center of the machine with one foot slightly in front of the other.","Grasp the handles with an overhand grip and extend your arms out to the sides.","Keep a slight bend in your elbows and maintain a slight forward lean.","Engage your chest muscles and bring your arms forward in a sweeping motion.","Pause for a moment at the center, then slowly return your arms back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"xLYSdtg"},{"id":"edb-0189","name":"חתירה בהטיה ביד אחת בפולי","name_en":"cable one arm bent over row","muscle":"back","equipment":"cable","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["עמדו מול מכונת הפולי כשרגליכם ברוחב הכתפיים.","כופפו מעט את הברכיים והטו את הגוף קדימה במפרקי הירך, תוך שמירה על גב ישר.","אחזו בידית הפולי ביד אחת, כף היד פונה פנימה, ויישרו את הזרוע לחלוטין.","משכו את ידית הפולי לכיוון הגוף, תוך שמירה על המרפק צמוד לגוף, עד שהיד מגיעה לתחתית החזה.","עצרו לרגע, ולאחר מכן יישרו את הזרוע לאט חזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Stand facing a cable machine with your feet shoulder-width apart.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Grasp the cable handle with one hand, palm facing inward, and extend your arm fully.","Pull the cable handle towards your body, keeping your elbow close to your side, until your hand reaches your lower chest.","Pause for a moment, then slowly extend your arm back to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"EIsE3u8"},{"id":"edb-0190","name":"כפיפת מרפק ביד אחת בפולי","name_en":"cable one arm curl","muscle":"biceps","equipment":"cable","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו מול מכונת הפולי כשרגליכם ברוחב הכתפיים.","אחזו בידית הפולי באחיזה תחתונה, כף היד פונה למעלה.","שמרו על המרפק צמוד לגוף וכופפו את האמה לאט כלפי מעלה לכיוון הכתף.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את האמה באיטיות חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand facing the cable machine with your feet shoulder-width apart.","Grasp the cable handle with an underhand grip, palm facing up.","Keep your elbow close to your side and slowly curl your forearm up towards your shoulder.","Pause for a moment at the top, then slowly lower your forearm back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"YTur5nR"},{"id":"edb-1262","name":"פרפר ביד אחת בשיפוע שלילי בפולי","name_en":"cable one arm decline chest fly","muscle":"chest","equipment":"cable","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["חברו ידית D לגלגלת תחתונה של מכונת הפולי וכווננו את הספסל לזווית יורדת.","שכבו על הספסל כשהראש לכיוון המכונה ואחזו בידית ביד ימין.","יישרו את הזרוע ישר למעלה מעל החזה, תוך שמירה על כיפוף קל במרפק.","בתנועה מבוקרת, הורידו את הזרוע הצדה עד שהיד מיושרת עם הכתף.","עצרו לרגע, ולאחר מכן הפכו את התנועה והחזירו את הזרוע לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן עברו ליד שמאל וחזרו על התרגיל."],"steps_en":["Attach a D-handle to a low pulley cable machine and set the bench to a decline angle.","Lie down on the bench with your head towards the machine and grab the handle with your right hand.","Extend your arm straight up above your chest, keeping a slight bend in your elbow.","With a controlled motion, lower your arm out to the side until your hand is in line with your shoulder.","Pause for a moment, then reverse the motion and bring your arm back to the starting position.","Repeat for the desired number of repetitions, then switch to your left arm and repeat the exercise."],"mediaId":"w4dLzSx"},{"id":"edb-1263","name":"פרפר ביד אחת בפולי","name_en":"cable one arm fly on exercise ball","muscle":"chest","equipment":"cable","target":"pectorals","bodyPart":"chest","secondaryMuscles":["deltoids","triceps"],"steps":["שבו על כדור התעמלות כשכפות הרגליים שטוחות על הרצפה והגב ישר.","אחזו בידית הפולי ביד אחת ויישרו את הזרוע הצדה, במקביל לרצפה.","שמרו על המרפק כפוף מעט וכף היד פונה קדימה.","הביאו את הזרוע לאט לרוחב הגוף, תוך כיווץ שרירי החזה.","עצרו לרגע בסוף התנועה, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a cable handle in one hand and extend your arm out to the side, parallel to the ground.","Keep your elbow slightly bent and your palm facing forward.","Slowly bring your arm across your body, squeezing your chest muscles.","Pause for a moment at the end of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"hHy8tQG"},{"id":"edb-1264","name":"פרפר ביד אחת בשיפוע בפולי","name_en":"cable one arm incline fly on exercise ball","muscle":"chest","equipment":"cable","target":"pectorals","bodyPart":"chest","secondaryMuscles":["deltoids","triceps"],"steps":["שבו על כדור התעמלות כשכפות הרגליים שטוחות על הרצפה והגב צמוד לספסל משופע.","אחזו בידית הפולי ביד אחת כשהזרוע מיושרת וכף היד פונה פנימה.","תוך שמירה על כיפוף קל במרפק, הורידו את הזרוע לאט הצדה עד שהיד מיושרת עם הכתף.","עצרו לרגע, ולאחר מכן כווצו את שרירי החזה כדי להחזיר את הזרוע לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Sit on an exercise ball with your feet flat on the ground and your back against an incline bench.","Hold a cable handle in one hand with your arm extended and palm facing inward.","Keeping a slight bend in your elbow, slowly lower your arm out to the side until your hand is in line with your shoulder.","Pause for a moment, then squeeze your chest muscles to bring your arm back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"P14Dz9D"},{"id":"edb-1265","name":"לחיצה ביד אחת בשיפוע בפולי","name_en":"cable one arm incline press","muscle":"chest","equipment":"cable","target":"pectorals","bodyPart":"chest","secondaryMuscles":["deltoids","triceps"],"steps":["כווננו את מכונת הפולי לעמדת גלגלת תחתונה.","שבו על ספסל משופע כשגבכם למכונת הפולי.","אחזו בידית ביד אחת והביאו אותה לגובה הכתפיים.","מקמו את הרגליים בבטחה על הרצפה ושמרו על תנוחה יציבה.","דחפו את הידית קדימה ומעלה, תוך יישור מלא של הזרוע.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את הידית לאט חזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Adjust the cable machine to a low pulley position.","Sit on an incline bench facing away from the cable machine.","Grasp the handle with one hand and bring it up to shoulder height.","Position your feet firmly on the ground and maintain a stable position.","Press the handle forward and upward, extending your arm fully.","Pause for a moment at the top, then slowly lower the handle back to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"GKEH6jj"},{"id":"edb-1266","name":"לחיצה ביד אחת בשיפוע בפולי","name_en":"cable one arm incline press on exercise ball","muscle":"chest","equipment":"cable","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["שבו על כדור התעמלות כשכפות הרגליים שטוחות על הרצפה והגב נשען על ספסל משופע.","אחזו בידית הפולי ביד אחת ומקמו את הזרוע בזווית של 90 מעלות עם המרפק כפוף.","דחפו את ידית הפולי קדימה ומעלה, תוך יישור מלא של הזרוע.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את ידית הפולי לאט חזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ליד השנייה."],"steps_en":["Sit on an exercise ball with your feet flat on the ground and your back resting against an incline bench.","Hold a cable handle in one hand and position your arm at a 90-degree angle with your elbow bent.","Press the cable handle forward and upward, extending your arm fully.","Pause for a moment at the top, then slowly lower the cable handle back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"mediaId":"6t00BsF"},{"id":"edb-0191","name":"cable one arm lateral bent-over","name_en":"cable one arm lateral bent-over","muscle":"chest","equipment":"cable","target":"pectorals","bodyPart":"chest","secondaryMuscles":["deltoids","trapezius"],"steps":["עמדו כשרגליכם ברוחב הכתפיים, מול מכונת הפולי.","אחזו בידית ביד אחת וצעדו אחורה כדי ליצור מתח על הכבל.","התכופפו קדימה מהמותניים, תוך שמירה על גב ישר ושרירי ליבה פעילים.","יישרו את הזרוע הצדה, במקביל לרצפה, עם כיפוף קל במרפק.","החזירו את הזרוע לאט לתנוחת ההתחלה, תוך שמירה על שליטה לאורך כל התנועה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Stand with your feet shoulder-width apart, facing a cable machine.","Grasp the handle with one hand and step back to create tension on the cable.","Bend forward at the waist, keeping your back straight and your core engaged.","Extend your arm out to the side, parallel to the ground, with a slight bend in your elbow.","Slowly bring your arm back to the starting position, maintaining control throughout the movement.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"dB07vDu"},{"id":"edb-0192","name":"הרחקת כתפיים לצדדים ביד אחת בפולי","name_en":"cable one arm lateral raise","muscle":"shoulders","equipment":"cable","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","triceps"],"steps":["עמדו כשרגליכם ברוחב הכתפיים, מול מכונת הפולי.","אחזו בידית הפולי ביד אחת, כף היד פונה למטה, ועמדו רחוק מספיק מהמכונה כך שיהיה מתח על הכבל.","שמרו על הזרוע ישרה והרימו אותה לאט הצדה עד שהיא מקבילה לרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את הזרוע לאט חזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Stand with your feet shoulder-width apart, facing the cable machine.","Hold the cable handle with one hand, palm facing down, and stand far enough away from the machine so that there is tension on the cable.","Keep your arm straight and slowly raise it out to the side until it is parallel to the ground.","Pause for a moment at the top, then slowly lower your arm back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"wEulIzp"},{"id":"edb-1633","name":"כפיפת מרפק בכיסא הטפה ביד אחת בפולי","name_en":"cable one arm preacher curl","muscle":"biceps","equipment":"cable","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["כווננו את מכונת הפולי כך שכרית הפרייצ'ר תהיה בגובה החזה.","עמדו מול מכונת הפולי כשרגליכם ברוחב הכתפיים.","אחזו בידית הפולי באחיזה תחתונה ומקמו את הזרוע העליונה על כרית הפרייצ'ר.","שמרו על גב ישר ושרירי ליבה מופעלים.","כופפו את ידית הפולי לאט לכיוון הכתף, תוך שמירה על הזרוע העליונה על הכרית.","עצרו לרגע בשיא התנועה, תוך כיווץ שריר הביצפס.","הורידו את ידית הפולי לאט חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי.","החליפו זרועות וחזרו על התרגיל."],"steps_en":["Adjust the cable machine so that the preacher curl pad is at chest height.","Stand facing the cable machine with your feet shoulder-width apart.","Grasp the cable handle with an underhand grip and position your upper arm against the preacher curl pad.","Keep your back straight and your core engaged.","Slowly curl the cable handle towards your shoulder, keeping your upper arm against the pad.","Pause for a moment at the top of the movement, squeezing your biceps.","Slowly lower the cable handle back to the starting position.","Repeat for the desired number of repetitions.","Switch arms and repeat the exercise."],"mediaId":"eHBlPsa"},{"id":"edb-1267","name":"לחיצה ביד אחת בפולי","name_en":"cable one arm press on exercise ball","muscle":"chest","equipment":"cable","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["שבו על כדור התעמלות כשכפות הרגליים שטוחות על הרצפה והגב ישר.","אחזו בידית הפולי ביד אחת ומקמו את הזרוע בגובה החזה, המרפק כפוף.","הניחו את היד השנייה על הירך לשם יציבות.","דחפו את ידית הפולי קדימה, תוך יישור מלא של הזרוע.","עצרו לרגע, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a cable handle in one hand and position your arm at chest height, elbow bent.","Place your other hand on your hip for stability.","Press the cable handle forward, extending your arm fully.","Pause for a moment, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"MKIelrR"},{"id":"edb-3563","name":"משיכת פולי ביד אחת בפולי","name_en":"cable one arm pulldown","muscle":"back","equipment":"cable","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["חברו ידית בודדת לגלגלת עליונה של מכונת הפולי.","עמדו מול המכונה עם הרגליים ברוחב הכתפיים.","אחזו בידית באחיזה עליונה ויישרו את הזרוע לחלוטין.","שמרו על גב ישר ושרירי ליבה מופעלים.","משכו את הידית כלפי מטה לצד הגוף תוך שמירה על המרפק צמוד לגוף.","עצרו לרגע בתחתית התנועה, תוך כיווץ שריר הגב הרחב.","שחררו את הידית לאט חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי.","החליפו צדדים וחזרו על התרגיל עם הזרוע השנייה."],"steps_en":["Attach a single handle to a high pulley cable machine.","Stand facing the machine with your feet shoulder-width apart.","Grasp the handle with an overhand grip and extend your arm fully.","Keep your back straight and your core engaged.","Pull the handle down towards your side while keeping your elbow close to your body.","Pause for a moment at the bottom of the movement, squeezing your lat muscle.","Slowly release the handle back to the starting position.","Repeat for the desired number of repetitions.","Switch sides and repeat the exercise with the other arm."],"mediaId":"U5INZY6"},{"id":"edb-1635","name":"כפיפת מרפק בכיסא הטפה ביד אחת הפוך בפולי","name_en":"cable one arm reverse preacher curl","muscle":"biceps","equipment":"cable","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["כווננו את מכונת הפולי כך שהגלגלת תהיה בעמדה הנמוכה ביותר.","עמדו מול מכונת הפולי כשרגליכם ברוחב הכתפיים.","אחזו בידית הפולי באחיזה תחתונה ומקמו את הזרוע העליונה על כרית ספסל הפרייצ'ר.","שמרו על הגב ישר ושרירי הליבה מופעלים לאורך כל התרגיל.","כופפו את האמה לאט לכיוון הביצפס, תוך שמירה על הזרוע העליונה קבועה על הכרית.","עצרו לרגע בשיא התנועה, תוך כיווץ הביצפס.","הורידו את ידית הפולי לאט חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי.","החליפו זרועות וחזרו על התרגיל."],"steps_en":["Adjust the cable machine so that the pulley is at the lowest position.","Stand facing the cable machine with your feet shoulder-width apart.","Grasp the cable handle with an underhand grip and position your upper arm against the preacher bench pad.","Keep your back straight and your core engaged throughout the exercise.","Slowly curl your forearm towards your bicep, keeping your upper arm stationary against the pad.","Pause for a moment at the top of the movement, squeezing your bicep.","Slowly lower the cable handle back to the starting position.","Repeat for the desired number of repetitions.","Switch arms and repeat the exercise."],"mediaId":"ZXnjcOQ"},{"id":"edb-0193","name":"חתירה ביד אחת בכריעה גבוה בפולי","name_en":"cable one arm straight back high row (kneeling)","muscle":"back","equipment":"cable","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","shoulders"],"steps":["חברו ידית למכונת הפולי בגובה המותניים.","כרעו מול מכונת הפולי ואחזו בידית ביד אחת.","שמרו על גב ישר ושרירי ליבה מופעלים.","משכו את הידית לכיוון החזה, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה.","שחררו את הידית לאט חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי.","החליפו צדדים וחזרו על התרגיל עם הזרוע השנייה."],"steps_en":["Attach a handle to a cable machine at waist height.","Kneel down facing the cable machine and grab the handle with one hand.","Keep your back straight and your core engaged.","Pull the handle towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top of the movement.","Slowly release the handle back to the starting position.","Repeat for the desired number of repetitions.","Switch sides and repeat the exercise with the other arm."],"mediaId":"WrYPP2g"},{"id":"edb-1723","name":"פשיטת מרפק בפולי ביד אחת בפולי","name_en":"cable one arm tricep pushdown","muscle":"triceps","equipment":"cable","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו מול מכונת הפולי עם אביזר מוט ישר בגובה החזה.","אחזו במוט באחיזה עליונה וצעדו אחורה כדי ליצור מתח בכבל.","מקמו את הרגליים ברוחב הכתפיים וכופפו מעט את הברכיים.","שמרו על גב ישר ושרירי ליבה פעילים לאורך כל התרגיל.","התחילו עם הזרוע מיושרת לחלוטין וניצבת לרצפה.","תוך שמירה על הזרוע העליונה קבועה, נשפו ודחפו את המוט כלפי מטה עד שהזרוע מיושרת לחלוטין.","עצרו לרגע, ולאחר מכן שאפו וחזרו לאט לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Stand facing a cable machine with a straight bar attachment at chest height.","Grasp the bar with an overhand grip and step back to create tension in the cable.","Position your feet shoulder-width apart and slightly bend your knees.","Keep your back straight and core engaged throughout the exercise.","Start with your arm fully extended and perpendicular to the floor.","Keeping your upper arm stationary, exhale and push the bar down until your arm is fully extended.","Pause for a moment, then inhale and slowly return to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"qRZ5S1N"},{"id":"edb-1636","name":"כפיפת מרפק מעל הראש בפולי","name_en":"cable overhead curl","muscle":"biceps","equipment":"cable","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms","shoulders"],"steps":["חברו מוט ישר לגלגלת עליונה של מכונת הפולי.","עמדו מול המכונה עם הרגליים ברוחב הכתפיים.","אחזו במוט באחיזה תחתונה, כשהידיים ברוחב הכתפיים.","שמרו על המרפקים צמודים לגוף והזרועות העליונות קבועות.","נשפו וכופפו את המוט כלפי מטה לכיוון המצח, תוך שמירה על הזרועות העליונות קבועות במקומן.","עצרו לרגע בתחתית התנועה, תוך כיווץ שרירי הביצפס.","שאפו והחזירו את המוט באיטיות לנקודת ההתחלה, תוך יישור מלא של הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a straight bar to a high pulley cable machine.","Stand facing the machine with your feet shoulder-width apart.","Grasp the bar with an underhand grip, hands shoulder-width apart.","Keep your elbows close to your sides and your upper arms stationary.","Exhale and curl the bar down towards your forehead, keeping your upper arms stationary.","Pause for a moment at the bottom of the movement, squeezing your biceps.","Inhale and slowly return the bar to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"wDUqY2u"},{"id":"edb-1637","name":"כפיפת מרפק מעל הראש בפולי","name_en":"cable overhead curl on exercise ball","muscle":"biceps","equipment":"cable","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms","shoulders"],"steps":["שבו על כדור התעמלות ואחזו בידית הפולי באחיזה תחתית.","ישרו את הזרועות לגמרי מעל הראש, תוך שמירה על המרפקים קרובים לאוזניים.","כופפו את הפולי באיטיות כלפי מטה לכיוון המצח, תוך שמירה על הזרועות העליונות קבועות במקומן.","עצרו לרגע בתחתית התנועה, ולאחר מכן חזרו לאט לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on an exercise ball and hold the cable handle with an underhand grip.","Extend your arms fully overhead, keeping your elbows close to your ears.","Slowly curl the cable down towards your forehead, keeping your upper arms stationary.","Pause for a moment at the bottom of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ioTf098"},{"id":"edb-0194","name":"פשיטת מרפק מעל הראש עם חבל בפולי","name_en":"cable overhead triceps extension (rope attachment)","muscle":"triceps","equipment":"cable","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["חברו חבל לפולי במכונת כבלים במיקום גבוה.","עמדו כשגבכם למכונה ורגליכם ברוחב הכתפיים.","אחזו בחבל בשתי הידיים, כשכפות הידיים פונות זו לזו, והביאו את הידיים מעל הראש.","שמרו על הזרועות העליונות קרובות לראש והמרפקים פונים קדימה.","הורידו את החבל לאט מאחורי הראש על ידי כיפוף המרפקים.","עצרו לרגע, ולאחר מכן יישרו את הידיים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a rope to a cable machine at a high position.","Stand facing away from the machine with your feet shoulder-width apart.","Grasp the rope with both hands, palms facing each other, and bring your hands above your head.","Keep your upper arms close to your head and your elbows pointing forward.","Slowly lower the rope behind your head by bending your elbows.","Pause for a moment, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"2IxROQ1"},{"id":"edb-1319","name":"חתירה בפולי","name_en":"cable palm rotational row","muscle":"back","equipment":"cable","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["חברו ידית למכונת הפולי בגובה המותניים.","עמדו מול המכונה עם הרגליים ברוחב הכתפיים.","אחזו בידית באחיזה עילית, כפות הידיים פונות מטה.","צעדו אחורה כדי ליצור מתח בכבל, תוך שמירה על גב ישר וברכיים כפופות מעט.","משכו את הידית לכיוון הגוף, תוך סיבוב כפות הידיים כלפי מעלה במהלך התנועה.","כווצו את השכמות זו לזו בסיום התנועה.","שחררו את הידית לאט חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a handle to a cable machine at waist height.","Stand facing the machine with your feet shoulder-width apart.","Grasp the handle with an overhand grip, palms facing down.","Step back to create tension on the cable, keeping your back straight and knees slightly bent.","Pull the handle towards your body, rotating your palms to face upwards as you do so.","Squeeze your shoulder blades together at the end of the movement.","Slowly release the handle back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"OmQ8w0p"},{"id":"edb-0195","name":"כפיפת מרפק בכיסא הטפה בפולי","name_en":"cable preacher curl","muscle":"biceps","equipment":"cable","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["כווננו את מכונת הפולי כך שכרית הפרייצ'ר תהיה בגובה החזה.","שבו על ספסל הפריצ'ר והניחו את הזרועות העליונות על הכרית, תוך אחיזה בידית הכבל באחיזה תחתית.","שמרו על גב ישר והמרפקים צמודים לגוף.","כופפו את ידית הכבל באיטיות כלפי מעלה לכיוון הכתפיים, תוך כיווץ הביצפס בשיא התנועה.","עצרו לרגע, ולאחר מכן הורידו את ידית הכבל באיטיות בחזרה לנקודת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the cable machine so that the preacher curl pad is at chest height.","Sit on the preacher curl bench and place your upper arms on the pad, gripping the cable attachment with an underhand grip.","Keep your back straight and your elbows tucked in at your sides.","Slowly curl the cable attachment up towards your shoulders, squeezing your biceps at the top of the movement.","Pause for a moment, then slowly lower the cable attachment back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"P2lNrGL"},{"id":"edb-1268","name":"לחיצה בפולי","name_en":"cable press on exercise ball","muscle":"chest","equipment":"cable","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["שבו על כדור התעמלות כשכפות הרגליים מונחות שטוח על הרצפה והברכיים בזווית של 90 מעלות.","אחזו בידיות הכבל בגובה החזה, כשכפות הידיים פונות מטה והמרפקים כפופים.","הפעילו את שרירי הליבה ודחפו את ידיות הכבל קדימה עד ליישור מלא של הזרועות.","עצרו לרגע, ולאחר מכן שחררו את המתח באיטיות והחזירו את ידיות הכבל לנקודת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on an exercise ball with your feet flat on the ground and your knees at a 90-degree angle.","Hold the cable handles at chest height with your palms facing down and your elbows bent.","Engage your core and press the cable handles forward until your arms are fully extended.","Pause for a moment, then slowly release the tension and bring the cable handles back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"vAwm6rK"},{"id":"edb-0196","name":"cable pull through (with rope)","name_en":"cable pull through (with rope)","muscle":"glutes","equipment":"cable","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","lower back"],"steps":["עמדו כשגבכם אל מכונת הכבלים, כשכפות הרגליים ברוחב הכתפיים.","אחזו בידית החבל בשתי הידיים וצעדו קדימה, ליצירת מתח בכבל.","התכופפו במפרקי הירך והורידו את פלג הגוף העליון עד שיהיה מקביל לרצפה, תוך שמירה על גב ישר.","הפעילו את שרירי הישבן והירך האחורית כדי למשוך את הגוף בחזרה למעלה לנקודת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand facing away from the cable machine with your feet shoulder-width apart.","Grab the rope attachment with both hands and step forward, creating tension in the cable.","Bend at the hips and lower your upper body until it is parallel to the ground, keeping your back straight.","Engage your glutes and hamstrings to pull your body back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"OM46QHm"},{"id":"edb-0198","name":"משיכת פולי בפולי","name_en":"cable pulldown","muscle":"back","equipment":"cable","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["כווננו את מכונת המשיכה מלמעלה כך שהמושב יהיה בגובה נוח והכרית לברך מאובטחת.","שבו על המושב כשגבכם ישר וכפות הרגליים מונחות שטוח על הרצפה.","אחזו במוט הפולי באחיזה עליונה, ברוחב מעט גדול מרוחב הכתפיים.","הטו את הגוף מעט אחורה והפעילו את שרירי הליבה.","משכו את מוט הכבל כלפי מטה לכיוון החזה, תוך כיווץ השכמות זו לזו.","עצרו לרגע בתחתית התנועה, ולאחר מכן שחררו את המוט לאט חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the cable pulldown machine so that the seat is at a comfortable height and the knee pad is secured.","Sit on the seat with your back straight and your feet flat on the ground.","Grasp the cable bar with an overhand grip, slightly wider than shoulder-width apart.","Lean back slightly and engage your core.","Pull the cable bar down towards your chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the bar back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"RVwzP10"},{"id":"edb-0197","name":"משיכת פולי בפולי","name_en":"cable pulldown (pro lat bar)","muscle":"back","equipment":"cable","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["כווננו את גובה המושב כך שהירכיים יהיו מקבילות לרצפה וכפות הרגליים מונחות שטוח על הרצפה.","אחזו במוט הרחב באחיזה עילית, מעט רחבה יותר מרוחב הכתפיים.","שבו והטו את הגוף מעט אחורה, תוך שמירה על החזה מורם וגב ישר.","משכו את המוט כלפי מטה לכיוון החזה, תוך כיווץ השכמות זו לזו.","עצרו לרגע בתחתית התנועה, ולאחר מכן שחררו את המוט באיטיות בחזרה למעלה לנקודת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height so that your thighs are parallel to the ground and your feet are flat on the floor.","Grasp the lat bar with an overhand grip, slightly wider than shoulder-width apart.","Sit down and lean back slightly, keeping your chest up and your back straight.","Pull the bar down towards your chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the bar back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"qdRxqCj"},{"id":"edb-1638","name":"כפיפת מרפק בפולי","name_en":"cable pulldown bicep curl","muscle":"biceps","equipment":"cable","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["חברו מוט ישר למכונת הכבלים בהגדרה הגבוהה ביותר.","עמדו מול המכונה עם הרגליים ברוחב הכתפיים.","אחזו במוט באחיזה תחתונה, כשהידיים ברוחב הכתפיים.","שמרו על המרפקים צמודים לגוף והזרועות העליונות קבועות.","נשפו וכופפו את המוט באיטיות כלפי מטה לכיוון הירכיים, תוך שמירה על שורשי הידיים ישרים.","עצרו לרגע בתחתית התנועה, תוך כיווץ שרירי הביצפס.","שאפו והחזירו את המוט באיטיות לנקודת ההתחלה, תוך יישור מלא של הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a straight bar to the cable machine at the highest setting.","Stand facing the machine with your feet shoulder-width apart.","Grasp the bar with an underhand grip, hands shoulder-width apart.","Keep your elbows close to your sides and your upper arms stationary.","Exhale and slowly curl the bar down towards your thighs, keeping your wrists straight.","Pause for a moment at the bottom of the movement, squeezing your biceps.","Inhale and slowly return the bar to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"QTXKWPh"},{"id":"edb-0201","name":"פשיטת מרפק בפולי בפולי","name_en":"cable pushdown","muscle":"triceps","equipment":"cable","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["חברו מוט ישר לגלגלת עליונה של מכונת הפולי.","עמדו מול המכונה כשכפות הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","אחזו במוט באחיזה עילית, הידיים ברוחב הכתפיים.","שמרו על המרפקים צמודים לגוף והזרועות העליונות קבועות.","נשפו ודחפו את המוט כלפי מטה עד ליישור מלא של המרפקים.","עצרו לרגע, ולאחר מכן שאפו והחזירו את המוט באיטיות לנקודת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a straight bar to a high pulley cable machine.","Stand facing the machine with your feet shoulder-width apart and a slight bend in your knees.","Grasp the bar with an overhand grip, hands shoulder-width apart.","Keep your elbows close to your sides and your upper arms stationary.","Exhale and push the bar down until your elbows are fully extended.","Pause for a moment, then inhale and slowly return the bar to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"3ZflifB"},{"id":"edb-0199","name":"פשיטת מרפק בפולי בפולי","name_en":"cable pushdown (straight arm) v. 2","muscle":"back","equipment":"cable","target":"lats","bodyPart":"back","secondaryMuscles":["triceps","shoulders"],"steps":["חברו מוט ישר לגלגלת עליונה של מכונת הפולי.","עמדו מול המכונה כשכפות הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","אחזו במוט באחיזה עילית, תוך שמירה על הזרועות ישרות וכפות הידיים פונות מטה.","הפעילו את שרירי הליבה ושמרו על גב ישר תוך שאתם נושפים ודוחפים את המוט כלפי מטה לכיוון הירכיים.","עצרו לרגע בתחתית, ולאחר מכן החזירו את המוט באיטיות לנקודת ההתחלה תוך שאיפה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a straight bar to a high pulley cable machine.","Stand facing the machine with your feet shoulder-width apart and a slight bend in your knees.","Grasp the bar with an overhand grip, keeping your arms straight and your palms facing down.","Engage your core and keep your back straight as you exhale and push the bar down towards your thighs.","Pause for a moment at the bottom, then slowly return the bar to the starting position while inhaling.","Repeat for the desired number of repetitions."],"mediaId":"PskORrA"},{"id":"edb-0200","name":"פשיטת מרפק בפולי עם חבל בפולי","name_en":"cable pushdown (with rope attachment)","muscle":"triceps","equipment":"cable","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["חברו ידית חבל לפולי גבוה במכונת כבלים.","עמדו מול המכונה כשכפות הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","אחזו בחבל באחיזה עליונה, כשכפות הידיים פונות זו לזו.","שמרו על המרפקים צמודים לגוף והזרועות העליונות קבועות לאורך כל התרגיל.","נשפו ודחפו את החבל כלפי מטה על ידי יישור המרפקים עד שהזרועות ישרות לגמרי.","עצרו לרגע, ולאחר מכן שאפו וחזרו באיטיות לנקודת ההתחלה על ידי כיפוף המרפקים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a rope attachment to a high pulley on a cable machine.","Stand facing the machine with your feet shoulder-width apart and a slight bend in your knees.","Grasp the rope with an overhand grip, palms facing each other.","Keep your elbows close to your sides and your upper arms stationary throughout the exercise.","Exhale and push the rope downward by extending your elbows until your arms are fully extended.","Pause for a moment, then inhale and slowly return to the starting position by allowing your elbows to flex.","Repeat for the desired number of repetitions."],"mediaId":"dU605di"},{"id":"edb-0202","name":"חתירת כתף אחורית בפולי","name_en":"cable rear delt row (stirrups)","muscle":"shoulders","equipment":"cable","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","rhomboids","biceps"],"steps":["חברו ידית ארכובה לפולי כבל נמוך ועמדו מול המכונה.","אחזו בידית ביד השמאלית וצעדו צעד אחורה עם הרגל הימנית, תוך מיקום הגוף בזווית קלה.","כופפו את הברכיים מעט והטו את הגוף קדימה ממפרקי הירך, תוך שמירה על גב ישר והפעלת שרירי הליבה.","כשהזרוע השמאלית ישרה וכף היד פונה מטה, משכו את הידית לכיוון החזה על ידי כיווץ השכמה.","עצרו לרגע בשיא התנועה, תוך כיווץ השכמה.","שחררו את הידית באיטיות בחזרה לנקודת ההתחלה וחזרו על התנועה במספר החזרות הרצוי.","החליפו צדדים וחזרו על התרגיל עם הזרוע הימנית."],"steps_en":["Attach a stirrup handle to a low cable pulley and stand facing the machine.","Grasp the handle with your left hand and take a step back with your right foot, positioning your body at a slight angle.","Bend your knees slightly and hinge forward at the hips, keeping your back straight and your core engaged.","With your left arm extended and your palm facing down, pull the handle towards your chest by retracting your shoulder blade.","Pause for a moment at the top of the movement, squeezing your shoulder blade.","Slowly release the handle back to the starting position and repeat for the desired number of repetitions.","Switch sides and repeat the exercise with your right arm."],"mediaId":"yUdIGNs"},{"id":"edb-0203","name":"חתירת כתף אחורית עם חבל בפולי","name_en":"cable rear delt row (with rope)","muscle":"shoulders","equipment":"cable","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","rhomboids","biceps"],"steps":["חברו ידית חבל לגלגלת תחתונה של מכונת הפולי.","עמדו מול המכונה עם הרגליים ברוחב הכתפיים.","אחזו בידית החבל באחיזה עילית, כפות הידיים פונות זו לזו.","כופפו מעט את הברכיים והטו את הגוף קדימה במפרקי הירך, תוך שמירה על גב ישר.","שמרו על המרפקים כפופים מעט ומשכו את החבל לכיוון החזה, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה, ולאחר מכן שחררו את המתח באיטיות וחזרו לנקודת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a rope handle to a low pulley cable machine.","Stand facing the machine with your feet shoulder-width apart.","Grasp the rope handle with an overhand grip, palms facing each other.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Keep your elbows slightly bent and pull the rope towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"wqNPGCg"},{"id":"edb-0204","name":"cable rear drive","name_en":"cable rear drive","muscle":"triceps","equipment":"cable","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders","back"],"steps":["חברו ידית לפולי כבל נמוך ועמדו כשגבכם אל המכונה.","אחזו בידית באחיזה עילית וישרו את הזרועות ישר לפניכם.","תוך שמירה על המרפקים קבועים במקומם, משכו את הידית בחזרה לכיוון הגוף, תוך כיווץ שרירי הטריצפס בסיום התנועה.","החזירו את הידית באיטיות לנקודת ההתחלה וחזרו על התנועה במספר החזרות הרצוי."],"steps_en":["Attach a handle to a low pulley cable machine and stand facing away from the machine.","Grasp the handle with an overhand grip and extend your arms straight out in front of you.","Keeping your elbows stationary, pull the handle back towards your body, squeezing your triceps at the end of the movement.","Slowly return the handle to the starting position and repeat for the desired number of repetitions."],"mediaId":"c3QQLPi"},{"id":"edb-0205","name":"משיכת פולי אחורי בפולי","name_en":"cable rear pulldown","muscle":"back","equipment":"cable","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","rhomboids","rear deltoids"],"steps":["כווננו את מכונת הכבלים כך שהפולי יהיה במיקום הגבוה ביותר.","שבו מול המכונה כשכפות הרגליים מונחות שטוח על הרצפה והברכיים כפופות מעט.","אחזו בידית הכבל באחיזה עילית, הידיים רחבות מעט יותר מרוחב הכתפיים.","הטו את הגוף מעט אחורה, תוך שמירה על גב ישר וחזה מורם.","משכו את ידית הכבל כלפי מטה לכיוון החזה, תוך כיווץ השכמות זו לזו.","עצרו לרגע בתחתית התנועה, ולאחר מכן שחררו את הכבל באיטיות בחזרה למעלה לנקודת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the cable machine so that the pulley is at the highest position.","Sit facing the machine with your feet flat on the ground and your knees slightly bent.","Grasp the cable attachment with an overhand grip, hands slightly wider than shoulder-width apart.","Lean back slightly, keeping your back straight and your chest up.","Pull the cable attachment down towards your chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the cable back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"SpsOSXk"},{"id":"edb-0873","name":"כפיפת בטן הפוכה בפולי","name_en":"cable reverse crunch","muscle":"core","equipment":"cable","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["חברו כבל לפולי נמוך ושכבו על הגב על מזרן.","אחזו בכבל בשתי הידיים וישרו את הזרועות ישר כלפי מעלה לכיוון התקרה.","כופפו את הברכיים והרימו את הרגליים כלפי מעלה, תוך קירוב הירכיים לחזה.","תוך שמירה על יציבות פלג הגוף העליון, כופפו את האגן כלפי מעלה לכיוון החזה, תוך הרמת האגן מהמזרן.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הירכיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a cable to a low pulley and lie down facing up on a mat.","Hold the cable with both hands and extend your arms straight up towards the ceiling.","Bend your knees and lift your legs up, bringing your thighs towards your chest.","While keeping your upper body stable, curl your pelvis up towards your chest, lifting your hips off the mat.","Pause for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"RqOtqD7"},{"id":"edb-0206","name":"כפיפת מרפק הפוך בפולי","name_en":"cable reverse curl","muscle":"biceps","equipment":"cable","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["חברו מוט ישר לגלגלת תחתונה של מכונת הפולי.","עמדו מול המכונה כשרגליכם ברוחב הכתפיים והברכיים כפופות מעט.","אחזו במוט באחיזה תחתונה, כשהידיים ברוחב הכתפיים.","שמרו על המרפקים צמודים לגוף והזרועות העליונות קבועות לאורך כל התרגיל.","נשפו וכופפו את המוט כלפי מעלה לכיוון הכתפיים, תוך כיווץ שריר הביצפס.","עצרו לרגע בשיא התנועה, תוך כיווץ שרירי הביצפס.","שאפו והורידו את המוט לאט חזרה לתנוחת ההתחלה, תוך יישור מלא של הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a straight bar to a low pulley cable machine.","Stand facing the machine with your feet shoulder-width apart and your knees slightly bent.","Grasp the bar with an underhand grip, hands shoulder-width apart.","Keep your elbows close to your sides and your upper arms stationary throughout the exercise.","Exhale and curl the bar up towards your shoulders, contracting your biceps.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the bar back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"eOG0r6v"},{"id":"edb-2406","name":"פשיטת מרפק בפולי אחיזה הפוכה בפולי","name_en":"cable reverse grip triceps pushdown (sz-bar) (with arm blaster)","muscle":"triceps","equipment":"cable","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["חברו מוט ישר למכונת הכבלים בהגדרה הגבוהה ביותר.","עמדו מול מכונת הפולי כשרגליכם ברוחב הכתפיים.","אחזו במוט באחיזה תחתית, כפות הידיים פונות מעלה, והידיים ברוחב הכתפיים.","שמרו על המרפקים צמודים לגוף והזרועות העליונות קבועות לאורך כל התרגיל.","הפעילו את שרירי הטריצפס ודחפו את המוט באיטיות כלפי מטה עד ליישור מלא של הזרועות.","עצרו לרגע בתחתית התנועה, ולאחר מכן החזירו את המוט לאט לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a straight bar to the cable machine at the highest setting.","Stand facing the cable machine with your feet shoulder-width apart.","Grasp the bar with an underhand grip, palms facing up, and your hands shoulder-width apart.","Keep your elbows close to your sides and your upper arms stationary throughout the exercise.","Engage your triceps and slowly push the bar down until your arms are fully extended.","Pause for a moment at the bottom, then slowly return the bar to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ThKP69G"},{"id":"edb-1413","name":"כפיפת מרפק ביד אחת הפוך בפולי","name_en":"cable reverse one arm curl","muscle":"biceps","equipment":"cable","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו מול מכונת הפולי כשרגליכם ברוחב הכתפיים.","אחזו בידית הכבל באחיזה תחתית, כף היד פונה מטה.","שמרו על המרפק צמוד לגוף וכופפו את האמה לאט כלפי מעלה לכיוון הכתף.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את האמה באיטיות חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand facing a cable machine with your feet shoulder-width apart.","Grasp the cable handle with an underhand grip, palm facing down.","Keep your elbow close to your side and slowly curl your forearm up towards your shoulder.","Pause for a moment at the top, then slowly lower your forearm back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"gVlnLIJ"},{"id":"edb-0209","name":"כפיפת מרפק בכיסא הטפה הפוך בפולי","name_en":"cable reverse preacher curl","muscle":"biceps","equipment":"cable","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["כווננו את מכונת הפולי כך שכרית הפרייצ'ר תהיה בגובה החזה.","שבו על ספסל הפריצ'ר והניחו את הזרועות העליונות על הכרית, כשכפות הידיים פונות מטה והמרפקים ישרים לגמרי.","אחזו בידיות הכבל באחיזה תחתית, ברוחב הכתפיים.","תוך שמירה על הזרועות העליונות קבועות במקומן, נשפו וכופפו את הידיות לכיוון הכתפיים, תוך כיווץ הביצפס.","עצרו לרגע בשיא התנועה, תוך כיווץ שריר הביצפס.","שאפו והורידו את הידיות באיטיות בחזרה לנקודת ההתחלה, תוך יישור מלא של המרפקים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the cable machine so that the preacher curl pad is at chest height.","Sit on the preacher curl bench and place your upper arms on the pad, with your palms facing down and your elbows fully extended.","Grab the cable handles with an underhand grip, shoulder-width apart.","Keeping your upper arms stationary, exhale and curl the handles towards your shoulders, contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the handles back to the starting position, fully extending your elbows.","Repeat for the desired number of repetitions."],"mediaId":"IwX5NqK"},{"id":"edb-0210","name":"כפיפת שורש כף היד הפוך בפולי","name_en":"cable reverse wrist curl","muscle":"biceps","equipment":"cable","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["forearms","wrists"],"steps":["חברו כבל לפולי נמוך ושבו על ספסל מול מכונת הכבלים.","אחזו בידית הכבל באחיזה עילית, כפות הידיים פונות מטה.","הניחו את האמות על הירכיים, כשפרקי הידיים תלויים מעבר לקצה.","תוך שמירה על האמות ללא תנועה, נשפו וכופפו את פרקי הידיים כלפי מעלה עד כמה שניתן.","עצרו לרגע למעלה, ולאחר מכן שאפו והורידו את שורשי הידיים באיטיות בחזרה לנקודת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a cable to a low pulley and sit on a bench facing the cable machine.","Grasp the cable handle with an overhand grip, palms facing down.","Rest your forearms on your thighs, with your wrists hanging off the edge.","Keeping your forearms stationary, exhale and curl your wrists upward as far as possible.","Pause for a moment at the top, then inhale and slowly lower your wrists back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"eYmsEPR"},{"id":"edb-0207","name":"פשיטת מרפק בפולי אחיזה הפוכה בפולי","name_en":"cable reverse-grip pushdown","muscle":"triceps","equipment":"cable","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["חברו מוט ישר לגלגלת עליונה של מכונת הפולי.","עמדו מול המכונה עם הרגליים ברוחב הכתפיים.","אחזו במוט באחיזה תחתית, כפות הידיים פונות מעלה, והידיים ברוחב הכתפיים.","שמרו על המרפקים צמודים לגוף והזרועות העליונות קבועות לאורך כל התרגיל.","באמצעות שרירי הטריצפס, דחפו את המוט כלפי מטה עד שהזרועות ישרות לגמרי והטריצפס מכווץ.","עצרו לרגע, ולאחר מכן החזירו את המוט באיטיות לנקודת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a straight bar to a high pulley cable machine.","Stand facing the machine with your feet shoulder-width apart.","Grasp the bar with an underhand grip, palms facing up, and your hands shoulder-width apart.","Keep your elbows close to your sides and your upper arms stationary throughout the exercise.","Using your triceps, push the bar down until your arms are fully extended and your triceps are contracted.","Pause for a moment, then slowly return the bar to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"VjYliFZ"},{"id":"edb-0208","name":"חתירה אחיזה הפוכה בישיבה גבוה בפולי","name_en":"cable reverse-grip straight back seated high row","muscle":"back","equipment":"cable","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["שבו על המושב מול מכונת הכבלים כשכפות הרגליים מונחות שטוח על הרצפה.","אחזו בידית הכבל באחיזה תחתית, כפות הידיים פונות מעלה, והידיים ברוחב הכתפיים.","שמרו על גב ישר והטו את הגוף מעט קדימה ממפרקי הירך.","משכו את הכבל לכיוון הגו על ידי כיווץ השכמות ולחיצת שרירי הגב.","עצרו לרגע בשיא הכיווץ, ולאחר מכן שחררו את הכבל לאט חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the seat facing the cable machine with your feet flat on the floor.","Grasp the cable attachment with an underhand grip, palms facing up, and your hands shoulder-width apart.","Keep your back straight and lean slightly forward from your hips.","Pull the cable towards your torso by retracting your shoulder blades and squeezing your back muscles.","Pause for a moment at the peak of the contraction, then slowly release the cable back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"PNtsX17"},{"id":"edb-1320","name":"חתירה בישיבה עם חבל בפולי","name_en":"cable rope crossover seated row","muscle":"back","equipment":"cable","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["שבו על מכונת החתירה כשכפות הרגליים מונחות שטוח על משענות הרגליים והברכיים כפופות מעט.","אחזו בחבלי הכבל באחיזה עילית, כפות הידיים פונות זו לזו.","הטו את הגוף מעט אחורה, תוך שמירה על הגב ישר ושרירי הליבה מופעלים.","משכו את חבלי הכבל לכיוון החזה, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה, ולאחר מכן שחררו את המתח באיטיות וחזרו לנקודת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the rowing machine with your feet flat on the footrests and your knees slightly bent.","Grasp the cable ropes with an overhand grip, palms facing each other.","Lean back slightly, keeping your back straight and your core engaged.","Pull the cable ropes towards your chest, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"UFGF6gk"},{"id":"edb-1321","name":"חתירה בישיבה עם חבל בפולי","name_en":"cable rope elevated seated row","muscle":"back","equipment":"cable","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["שבו על המושב המוגבה מול מכונת הכבלים.","אחזו בידיות חבל הכבל באחיזה עילית, כפות הידיים פונות זו לזו.","שמרו על גב ישר והטו מעט אחורה, תוך שמירה על כיפוף קל בברכיים.","משכו את הכבל לכיוון הגוף על ידי כיווץ השכמות ולחיצת שרירי הגב.","עצרו לרגע במצב הכיווץ המלא.","שחררו את המתח באיטיות וישרו את הזרועות בחזרה לנקודת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the elevated seat facing the cable machine.","Grab the cable rope handles with an overhand grip, palms facing each other.","Keep your back straight and lean slightly back, maintaining a slight bend in your knees.","Pull the cable towards your body by retracting your shoulder blades and squeezing your back muscles.","Pause for a moment at the fully contracted position.","Slowly release the tension and extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"c8oybX6"},{"id":"edb-1322","name":"חתירה בשיפוע עם חבל בפולי","name_en":"cable rope extension incline bench row","muscle":"back","equipment":"cable","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","shoulders"],"steps":["הציבו ספסל משופע בזווית של 45 מעלות וחברו מכונת כבלים לפולי הנמוך.","חברו ידית חבל למכונת הכבלים ושבו על הספסל המשופע מול המכונה.","אחזו בידית החבל באחיזה עילית והטו את הגוף קדימה, תוך שמירה על גב ישר.","ישרו את הזרועות לגמרי, תוך משיכת החבל לכיוון החזה העליון ושמירה על המרפקים קרובים לגוף.","כווצו את השכמות זו לזו בסיום התנועה.","שחררו את המתח לאט וחזרו לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up an incline bench at a 45-degree angle and attach a cable machine to the low pulley.","Attach a rope handle to the cable machine and sit on the incline bench facing the machine.","Grab the rope handle with an overhand grip and lean forward, keeping your back straight.","Extend your arms fully, pulling the rope towards your upper chest while keeping your elbows close to your body.","Squeeze your shoulder blades together at the end of the movement.","Slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"MgKwAAo"},{"id":"edb-1639","name":"כפיפת מרפק בכיסא הטפה עם חבל בפולי","name_en":"cable rope hammer preacher curl","muscle":"biceps","equipment":"cable","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["חברו ידית חבל לפולי נמוך במכונת כבלים.","עמדו מול המכונה עם הרגליים ברוחב הכתפיים.","אחזו בחבל באחיזה ניטרלית (כפות הידיים פונות זו לזו).","הניחו את הזרועות העליונות על כרית ספסל הפריצ'ר, תוך שמירה על המרפקים כפופים מעט.","תוך שמירה על הזרועות העליונות קבועות במקומן, נשפו וכופפו את החבל לכיוון הכתפיים על ידי כיווץ הביצפס.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו והורידו את החבל באיטיות בחזרה לנקודת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a rope attachment to a low pulley cable machine.","Stand facing the machine with your feet shoulder-width apart.","Grasp the rope with a neutral grip (palms facing each other).","Position your upper arms against the preacher bench pad, keeping your elbows slightly bent.","Keeping your upper arms stationary, exhale and curl the rope towards your shoulders by contracting your biceps.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the rope back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"PcPe0P5"},{"id":"edb-1724","name":"פשיטת מרפק מעל הראש גבוה עם חבל בפולי","name_en":"cable rope high pulley overhead tricep extension","muscle":"triceps","equipment":"cable","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["חברו חבל לפולי גבוה וכווננו את המשקל בהתאם.","עמדו כשגבכם אל מכונת הפולי, כפות הרגליים ברוחב הכתפיים.","אחזו בחבל בשתי הידיים, כפות הידיים פונות מטה, והביאו את הידיים מעל הראש.","שמרו על הזרועות העליונות קרובות לראש ומאונכות לרצפה.","הורידו את החבל לאט מאחורי הראש על ידי כיפוף המרפקים.","עצרו לרגע, ולאחר מכן יישרו את הזרועות חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a rope to a high pulley and adjust the weight accordingly.","Stand facing away from the pulley machine with your feet shoulder-width apart.","Grasp the rope with both hands, palms facing down, and bring your hands above your head.","Keep your upper arms close to your head and perpendicular to the floor.","Slowly lower the rope behind your head by bending your elbows.","Pause for a moment, then extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"NN8nSNT"},{"id":"edb-1725","name":"פשיטת מרפק בשיפוע עם חבל בפולי","name_en":"cable rope incline tricep extension","muscle":"triceps","equipment":"cable","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["חברו חבל לפולי גבוה וכווננו את הספסל המשופע לזווית נוחה.","עמדו כשגבכם אל הפולי, כפות הרגליים ברוחב הכתפיים.","אחזו בחבל באחיזה עילית וישרו את הזרועות ישר מעל הראש.","שמרו על המרפקים קרובים לראש והזרועות העליונות קבועות לאורך כל התרגיל.","הורידו את החבל מאחורי הראש על ידי כיפוף המרפקים עד שהאמות נוגעות בביצפס.","עצרו לרגע, ולאחר מכן יישרו את הזרועות חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a rope to a high pulley and adjust the incline bench to a comfortable angle.","Stand facing away from the pulley with your feet shoulder-width apart.","Grasp the rope with an overhand grip and extend your arms straight overhead.","Keep your elbows close to your head and your upper arms stationary throughout the exercise.","Lower the rope behind your head by bending your elbows until your forearms touch your biceps.","Pause for a moment, then extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ZujAdR9"},{"id":"edb-1726","name":"פשיטת מרפק בשכיבה עם חבל בפולי","name_en":"cable rope lying on floor tricep extension","muscle":"triceps","equipment":"cable","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["חברו חבל למכונת כבלים והגדירו אותו למיקום הנמוך ביותר.","שכבו על הרצפה על הגב, כשהראש פונה לכיוון מכונת הכבלים.","אחזו בחבל בשתי הידיים, כפות הידיים פונות זו לזו, וישרו את הזרועות ישר כלפי מעלה לכיוון התקרה.","שמרו על הזרועות העליונות קבועות במקומן והורידו את החבל באיטיות לכיוון המצח, תוך כיפוף המרפקים.","עצרו לרגע, ולאחר מכן יישרו את הידיים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a rope to a cable machine and set it to the lowest position.","Lie on the floor facing up, with your head towards the cable machine.","Hold the rope with both hands, palms facing each other, and extend your arms straight up towards the ceiling.","Keep your upper arms stationary and slowly lower the rope towards your forehead, bending your elbows.","Pause for a moment, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"U3ffHlY"},{"id":"edb-1640","name":"כפיפת מרפק בכיסא הטפה ביד אחת עם חבל בפולי","name_en":"cable rope one arm hammer preacher curl","muscle":"biceps","equipment":"cable","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["חברו ידית חבל לגלגלת תחתונה של מכונת הפולי.","עמדו מול המכונה עם הרגליים ברוחב הכתפיים.","אחזו בידית החבל באחיזה תחתית, כפות הידיים פונות מעלה.","הניחו את הזרוע העליונה על כרית ספסל הפריצ'ר, תוך שמירה על המרפק כפוף מעט.","שמרו על הגב ישר ושרירי הליבה מופעלים לאורך כל התרגיל.","כופפו את ידית החבל באיטיות לכיוון הכתף, תוך שמירה על הזרוע העליונה קבועה במקומה.","כווצו את הביצפס בשיא התנועה, ולאחר מכן הורידו את ידית החבל באיטיות בחזרה לנקודת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Attach a rope handle to a low pulley cable machine.","Stand facing the machine with your feet shoulder-width apart.","Grasp the rope handle with an underhand grip, palms facing up.","Position your upper arm against the preacher bench pad, keeping your elbow slightly bent.","Keep your back straight and your core engaged throughout the exercise.","Slowly curl the rope handle towards your shoulder, keeping your upper arm stationary.","Squeeze your biceps at the top of the movement, then slowly lower the rope handle back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"4hATdoB"},{"id":"edb-1323","name":"חתירה בישיבה עם חבל בפולי","name_en":"cable rope seated row","muscle":"back","equipment":"cable","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["שבו על מכונת החתירה כשכפות הרגליים מונחות שטוח על משענות הרגליים והברכיים כפופות מעט.","אחזו בחבלי הכבל באחיזה עילית, כפות הידיים פונות זו לזו.","שמרו על הגב ישר והטו את הגוף מעט קדימה, תוך שמירה על כיפוף קל במרפקים.","משכו את חבלי הכבל לכיוון הגוף, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה, ולאחר מכן שחררו את המתח באיטיות וחזרו לנקודת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the rowing machine with your feet flat on the footrests and knees slightly bent.","Grasp the cable ropes with an overhand grip, palms facing each other.","Keep your back straight and lean slightly forward, maintaining a slight bend in your elbows.","Pull the cable ropes towards your body, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"SJqRxOt"},{"id":"edb-0211","name":"cable russian twists (on stability ball)","name_en":"cable russian twists (on stability ball)","muscle":"core","equipment":"cable","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","lower back"],"steps":["שבו על כדור יציבות כשכפות הרגליים מונחות שטוח על הרצפה והברכיים כפופות בזווית של 90 מעלות.","אחזו בידית הכבל בשתי הידיים וישרו את הזרועות ישר לפניכם.","הטו את הגוף מעט אחורה, תוך שמירה על גב ישר והפעלת שרירי הליבה.","סובבו את פלג הגוף ימינה, תוך קירוב ידית הכבל לירך הימנית.","עצרו לרגע, ולאחר מכן סובבו את פלג הגוף שמאלה, תוך קירוב ידית הכבל לירך השמאלית.","המשיכו לסובב לסירוגין למספר החזרות הרצוי."],"steps_en":["Sit on a stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Hold the cable handle with both hands and extend your arms straight out in front of you.","Lean back slightly while keeping your back straight and your core engaged.","Twist your torso to the right, bringing the cable handle towards your right hip.","Pause for a moment, then twist your torso to the left, bringing the cable handle towards your left hip.","Continue alternating twists for the desired number of repetitions."],"mediaId":"d9Xaxq6"},{"id":"edb-2144","name":"לחיצת חזה בישיבה בפולי","name_en":"cable seated chest press","muscle":"chest","equipment":"cable","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["כווננו את גובה המושב ואת ידיות הכבל למיקום נוח.","שבו על הספסל כשגבכם ישר וכפות הרגליים מונחות שטוח על הרצפה.","אחזו בידיות הכבל באחיזה עילית בגובה הכתפיים.","דחפו את הידיות קדימה והרחק מהגוף, תוך יישור מלא של הזרועות.","עצרו לרגע, ולאחר מכן החזירו את הידיות באיטיות לנקודת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and cable handles to a comfortable position.","Sit on the bench with your back straight and feet flat on the floor.","Grasp the cable handles with an overhand grip at shoulder height.","Push the handles forward and away from your body, extending your arms fully.","Pause for a moment, then slowly bring the handles back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"nIR4Rwl"},{"id":"edb-0212","name":"כפיפת בטן בישיבה בפולי","name_en":"cable seated crunch","muscle":"core","equipment":"cable","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques"],"steps":["שבו על מכונת כבלים כשכפות הרגליים מונחות שטוח על הרצפה והברכיים כפופות.","אחזו בידית הכבל בשתי הידיים ומקמו אותה מאחורי הראש.","הפעילו את שרירי הבטן וכופפו את פלג הגוף העליון קדימה באיטיות, תוך קירוב החזה לברכיים.","עצרו לרגע למעלה, ולאחר מכן חזרו באיטיות לנקודת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a cable machine with your feet flat on the ground and your knees bent.","Hold the cable handle with both hands and position it behind your head.","Engage your abs and slowly curl your upper body forward, bringing your chest towards your knees.","Pause for a moment at the top, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"8xUv4J7"},{"id":"edb-1641","name":"כפיפת מרפק בישיבה בפולי","name_en":"cable seated curl","muscle":"biceps","equipment":"cable","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על מכונת כבלים כשכפות הרגליים מונחות שטוח על הרצפה והגב ישר.","אחזו בידית הכבל באחיזה תחתית, כפות הידיים פונות מעלה, והזרועות ישרות לגמרי.","תוך שמירה על הזרועות העליונות קבועות במקומן, נשפו וכופפו את ידית הכבל לכיוון הכתפיים, תוך כיווץ הביצפס.","עצרו לרגע בשיא התנועה, תוך כיווץ שריר הביצפס.","שאפו והורידו את אביזר הפולי לאט חזרה לתנוחת ההתחלה, תוך יישור מלא של הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a cable machine with your feet flat on the ground and your back straight.","Grasp the cable attachment with an underhand grip, palms facing up, and your arms fully extended.","Keeping your upper arms stationary, exhale and curl the cable attachment towards your shoulders, contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the cable attachment back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"8oYqOt9"},{"id":"edb-0213","name":"חתירה עם ידית V בישיבה גבוה בפולי","name_en":"cable seated high row (v-bar)","muscle":"back","equipment":"cable","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","rhomboids","rear deltoids"],"steps":["שבו על מכונת הכבלים כשכפות הרגליים מונחות שטוח על הרצפה והברכיים כפופות מעט.","אחזו בידית ה-V באחיזה עילית, כפות הידיים פונות זו לזו, והידיים ברוחב הכתפיים.","שמרו על גב ישר והטו את הגוף מעט קדימה ממפרקי הירך.","משכו את ידית ה-V לכיוון הגו על ידי כיווץ השכמות ולחיצת שרירי הגב.","עצרו לרגע בשיא הכיווץ, ולאחר מכן שחררו את המתח באיטיות וחזרו לנקודת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the cable machine with your feet flat on the floor and your knees slightly bent.","Grasp the v-bar attachment with an overhand grip, palms facing each other, and your hands shoulder-width apart.","Keep your back straight and lean slightly forward from the hips.","Pull the v-bar towards your torso by retracting your shoulder blades and squeezing your back muscles.","Pause for a moment at the peak of the contraction, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"pwt0pnM"},{"id":"edb-0214","name":"חתירה ביד אחת בישיבה לסירוגין בפולי","name_en":"cable seated one arm alternate row","muscle":"back","equipment":"cable","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["שבו על ספסל מול מכונת כבלים כשכפות הרגליים מונחות שטוח על הרצפה והברכיים כפופות מעט.","אחזו בידית ביד אחת ושמרו על הזרוע ישרה לגמרי לפניכם.","משכו את הידית לכיוון הגוף, תוך כיווץ השכמה ושמירה על המרפק קרוב לצד הגוף.","עצרו לרגע בשיא התנועה, תוך כיווץ שרירי הגב.","שחררו את הידית לאט חזרה לתנוחת ההתחלה.","חזרו עם הזרוע השנייה.","החליפו בין הזרועות למספר החזרות הרצוי."],"steps_en":["Sit on a bench facing a cable machine with your feet flat on the ground and knees slightly bent.","Grasp the handle with one hand and keep your arm fully extended in front of you.","Pull the handle towards your body, retracting your shoulder blade and keeping your elbow close to your side.","Pause for a moment at the top of the movement, squeezing your back muscles.","Slowly release the handle back to the starting position.","Repeat with the other arm.","Alternate between arms for the desired number of repetitions."],"mediaId":"vpp9Ku2"},{"id":"edb-1642","name":"כפיפת מרפק ביד אחת בישיבה בפולי","name_en":"cable seated one arm concentration curl","muscle":"biceps","equipment":"cable","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל כשכפות הרגליים מונחות שטוח על הרצפה והגב ישר.","אחזו בידית הכבל ביד אחת והניחו את המרפק על החלק הפנימי של הירך, ממש מעל הברך.","שמרו על הזרוע העליונה קבועה במקומה וכופפו את ידית הכבל לכיוון הכתף תוך נשיפה.","עצרו לרגע בשיא התנועה, תוך כיווץ שריר הביצפס.","הורידו את ידית הכבל באיטיות בחזרה לנקודת ההתחלה תוך שאיפה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Sit on a bench with your feet flat on the floor and your back straight.","Hold a cable handle with one hand and place your elbow on the inside of your thigh, just above the knee.","Keep your upper arm stationary and curl the cable handle towards your shoulder while exhaling.","Pause for a moment at the top of the movement, squeezing your biceps.","Slowly lower the cable handle back to the starting position while inhaling.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"rZ80Gbp"},{"id":"edb-1643","name":"כפיפת מרפק בישיבה מעל הראש בפולי","name_en":"cable seated overhead curl","muscle":"biceps","equipment":"cable","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms","shoulders"],"steps":["שבו על ספסל מול מכונת הכבלים כשכפות הרגליים מונחות שטוח על הרצפה.","אחזו בידית הכבל באחיזה תחתית, כפות הידיים פונות מעלה, והידיים ברוחב הכתפיים.","שמרו על הזרועות העליונות קבועות במקומן והמרפקים צמודים לגוף.","נשפו וכופפו את אביזר הפולי לכיוון הכתפיים, תוך כיווץ הביצפס.","עצרו לרגע בשיא התנועה, תוך כיווץ שריר הביצפס.","שאפו והורידו את אביזר הפולי לאט חזרה לתנוחת ההתחלה, תוך יישור מלא של הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench facing the cable machine with your feet flat on the ground.","Grasp the cable attachment with an underhand grip, palms facing up, and your hands shoulder-width apart.","Keep your upper arms stationary and your elbows close to your sides.","Exhale and curl the cable attachment towards your shoulders, contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the cable attachment back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"DpWMFP5"},{"id":"edb-0215","name":"הרחקת כתפיים לצדדים בישיבה אחורי בפולי","name_en":"cable seated rear lateral raise","muscle":"shoulders","equipment":"cable","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","rhomboids"],"steps":["שבו על ספסל מול מכונת הכבלים כשכפות הרגליים מונחות שטוח על הרצפה.","אחזו בידיות הכבל באחיזה עילית וישרו את הזרועות ישר לפניכם.","תוך שמירה על הזרועות ישרות, הרימו אותן באיטיות הצדה עד שיהיו מקבילות לרצפה.","עצרו לרגע למעלה, ולאחר מכן הורידו את הזרועות באיטיות בחזרה לנקודת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench facing the cable machine with your feet flat on the ground.","Grasp the cable handles with an overhand grip and extend your arms straight in front of you.","Keeping your arms straight, slowly raise them out to the sides until they are parallel to the floor.","Pause for a moment at the top, then slowly lower your arms back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"x825CZm"},{"id":"edb-0861","name":"חתירה בישיבה","name_en":"cable seated row","muscle":"back","equipment":"cable","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["שבו על מכונת חתירת הכבלים כשכפות הרגליים מונחות שטוח על משענות הרגליים והברכיים כפופות מעט.","אחזו בידיות באחיזה עילית, תוך שמירה על גב ישר וכתפיים רפויות.","משכו את הידיות לכיוון הגוף, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה, ולאחר מכן שחררו לאט את הידיות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the cable row machine with your feet flat on the footrests and your knees slightly bent.","Grasp the handles with an overhand grip, keeping your back straight and your shoulders relaxed.","Pull the handles towards your body, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"fUBheHs"},{"id":"edb-0216","name":"cable seated shoulder internal rotation","name_en":"cable seated shoulder internal rotation","muscle":"shoulders","equipment":"cable","target":"delts","bodyPart":"shoulders","secondaryMuscles":["rotator cuff","triceps"],"steps":["שבו על ספסל או כיסא מול מכונת הכבלים כשכפות הרגליים מונחות שטוח על הרצפה.","אחזו בידית הכבל כשהזרוע ישרה ומושטת לפניכם, מקבילה לרצפה.","שמרו על המרפק כפוף מעט והשכמות משוכות אחורה ומטה.","סובבו את הזרוע פנימה באיטיות, תוך קירוב ידית הכבל למרכז הגוף.","עצרו לרגע בסוף התנועה, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Sit on a bench or chair facing the cable machine with your feet flat on the ground.","Hold the cable handle with your arm extended straight out in front of you, parallel to the ground.","Keep your elbow slightly bent and your shoulder blades pulled back and down.","Slowly rotate your arm inward, bringing the cable handle towards the center of your body.","Pause for a moment at the end of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"YPoVrBi"},{"id":"edb-2399","name":"פיתול בישיבה בפולי","name_en":"cable seated twist","muscle":"core","equipment":"cable","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques"],"steps":["שבו על מכונת כבלים כשכפות הרגליים מונחות שטוח על הרצפה והברכיים כפופות מעט.","אחזו בידית הכבל בשתי הידיים וישרו את הזרועות ישר לפניכם.","תוך הפעלת שרירי הליבה, סובבו את פלג הגוף באיטיות לצד אחד, תוך משיכת הכבל לרוחב הגוף.","עצרו לרגע בקצה טווח התנועה, ולאחר מכן סובבו באיטיות בחזרה לנקודת ההתחלה.","חזרו על התרגיל בצד השני.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Sit on a cable machine with your feet flat on the ground and your knees slightly bent.","Hold the cable handle with both hands and extend your arms straight in front of you.","Keeping your core engaged, slowly rotate your torso to one side, pulling the cable across your body.","Pause for a moment at the end of the range of motion, then slowly rotate back to the starting position.","Repeat on the other side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"UEjSrKI"},{"id":"edb-0218","name":"חתירה אחיזה רחבה בישיבה בפולי","name_en":"cable seated wide-grip row","muscle":"back","equipment":"cable","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["שבו על מכונת חתירת הכבלים כשכפות הרגליים מונחות שטוח על משענות הרגליים והברכיים כפופות מעט.","אחזו בידית באחיזה עליונה רחבה, כשכפות הידיים פונות למטה.","שמרו על גב ישר והטו את הגוף מעט קדימה ממפרקי הירך.","משכו את הידית לכיוון החזה התחתון, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא הכיווץ.","שחררו את הידית באיטיות בחזרה לנקודת ההתחלה, תוך יישור מלא של הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the cable row machine with your feet flat on the footrests and your knees slightly bent.","Grasp the handle with a wide overhand grip, palms facing down.","Keep your back straight and lean slightly forward from the hips.","Pull the handle towards your lower chest, squeezing your shoulder blades together.","Pause for a moment at the peak of the contraction.","Slowly release the handle back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"qcY50ZD"},{"id":"edb-0219","name":"לחיצת כתפיים בפולי","name_en":"cable shoulder press","muscle":"shoulders","equipment":"cable","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["כווננו את מכונת הכבלים כך שהידיות יהיו בגובה הכתפיים.","עמדו כשגבכם למכונה ורגליכם ברוחב הכתפיים.","אחזו בידיות באחיזה עילית והביאו אותן לגובה הכתפיים, כשהמרפקים כפופים ופונים החוצה.","דחפו את הידיות כלפי מעלה עד ליישור מלא של הזרועות מעל הראש.","עצרו לרגע למעלה, ולאחר מכן הורידו את הידיות באיטיות בחזרה לגובה הכתפיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the cable machine so that the handles are at shoulder height.","Stand facing away from the machine with your feet shoulder-width apart.","Grasp the handles with an overhand grip and bring them up to shoulder level, with your elbows bent and pointing outwards.","Press the handles upwards until your arms are fully extended overhead.","Pause for a moment at the top, then slowly lower the handles back down to shoulder level.","Repeat for the desired number of repetitions."],"mediaId":"PzQanLE"},{"id":"edb-0220","name":"משיכת כתפיים בפולי","name_en":"cable shrug","muscle":"back","equipment":"cable","target":"traps","bodyPart":"back","secondaryMuscles":["shoulders"],"steps":["עמדו מול מכונת הפולי כשרגליכם ברוחב הכתפיים.","אחזו בידיות הכבל באחיזה עילית ותנו לזרועות לתלות לפניכם.","תוך שמירה על הזרועות ישרות, משכו את הכתפיים כלפי מעלה לכיוון האוזניים.","החזיקו את הכיווץ לרגע, ולאחר מכן הורידו לאט את הכתפיים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand facing the cable machine with your feet shoulder-width apart.","Grasp the cable handles with an overhand grip and let your arms hang down in front of you.","Keeping your arms straight, shrug your shoulders up towards your ears.","Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Eg98Ft9"},{"id":"edb-0222","name":"כפיפה צדית בפולי","name_en":"cable side bend","muscle":"core","equipment":"cable","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques"],"steps":["עמדו כשכפות הרגליים ברוחב הכתפיים ואחזו בידית הכבל ביד אחת.","שמרו על גב ישר ושרירי ליבה מופעלים.","כופפו את הגוף הצדה באיטיות במותניים, תוך הורדת ידית הכבל לכיוון הברך.","עצרו לרגע, ולאחר מכן חזרו למצב ההתחלתי.","חזרו על התרגיל בצד השני.","החליפו צדדים במספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and grasp the cable handle with one hand.","Keep your back straight and your core engaged.","Slowly bend sideways at the waist, lowering the cable handle towards your knee.","Pause for a moment, then return to the starting position.","Repeat on the other side.","Alternate sides for the desired number of repetitions."],"mediaId":"wPypxFY"},{"id":"edb-0221","name":"כפיפה צדית על בוסו","name_en":"cable side bend crunch (bosu ball)","muscle":"core","equipment":"cable","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques"],"steps":["עמדו כשכפות הרגליים ברוחב הכתפיים, כשידית כבל אחת בידכם.","הניחו את היד השנייה על הירך.","הפעילו את שרירי הליבה והתכופפו הצדה באיטיות לכיוון היד האוחזת בכבל, תוך שמירה על גב ישר.","עצרו לרגע בתחתית התנועה, ולאחר מכן חזרו לאט לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Stand with your feet shoulder-width apart, holding a cable handle in one hand.","Place the other hand on your hip.","Engage your core and slowly bend sideways towards the hand holding the cable, keeping your back straight.","Pause for a moment at the bottom of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"qatbkEd"},{"id":"edb-0223","name":"כפיפת בטן צדי בפולי","name_en":"cable side crunch","muscle":"core","equipment":"cable","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques"],"steps":["חברו ידית כבל לפולי נמוך ועמדו בצד למכונה.","אחזו בידית ביד הרחוקה יותר מהמכונה והניחו את היד השנייה על הירך.","שמרו על כפות הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","תוך הפעלת שרירי הבטן, כופפו את הגוף הצדה במותניים, תוך הורדת המרפק לכיוון הירך.","עצרו לרגע בתחתית התנועה, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Attach a cable handle to a low pulley and stand sideways to the machine.","Grasp the handle with the hand furthest from the machine and place your other hand on your hip.","Keep your feet shoulder-width apart and your knees slightly bent.","With your abs engaged, bend sideways at the waist, bringing your elbow down towards your hip.","Pause for a moment at the bottom, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"q2ADGqV"},{"id":"edb-1717","name":"חתירה עם חבל בפולי","name_en":"cable squat row (with rope attachment)","muscle":"back","equipment":"cable","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","rhomboids","rear deltoids"],"steps":["חברו חבל למכונת כבלים בגובה המותניים.","עמדו מול מכונת הפולי כשרגליכם ברוחב הכתפיים.","כופפו את הברכיים והורידו את הגוף למצב סקוואט, תוך שמירה על גב ישר וחזה מורם.","אחזו בחבל באחיזה עילית, הידיים ברוחב הכתפיים.","הפעילו את שרירי הליבה ומשכו את החבל לכיוון הגוף, תוך כיווץ השכמות זו לזו.","שמרו על המרפקים קרובים לגוף והמשיכו למשוך עד שהידיים מגיעות לחזה.","עצרו לרגע בשיא התנועה, ולאחר מכן שחררו את החבל באיטיות וישרו את הזרועות בחזרה לנקודת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a rope to a cable machine at waist height.","Stand facing the cable machine with your feet shoulder-width apart.","Bend your knees and lower your body into a squat position, keeping your back straight and chest up.","Grasp the rope with an overhand grip, with your hands shoulder-width apart.","Engage your core and pull the rope towards your body, squeezing your shoulder blades together.","Keep your elbows close to your body and continue pulling until your hands reach your chest.","Pause for a moment at the top of the movement, then slowly release the rope and extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"f7fnAIB"},{"id":"edb-1644","name":"כפיפת מרפק בפולי","name_en":"cable squatting curl","muscle":"biceps","equipment":"cable","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["חברו ידית כבל להגדרה הנמוכה ביותר במכונת כבלים.","עמדו מול המכונה עם הרגליים ברוחב הכתפיים.","אחזו בידית הכבל באחיזה תחתית, כפות הידיים פונות מעלה, והזרועות ישרות לגמרי.","הורידו את הגוף למצב סקוואט, תוך שמירה על גב ישר וברכיים מאחורי קצות האצבעות.","תוך כדי הירידה לסקוואט, כופפו את ידית הכבל לכיוון הכתפיים, תוך שמירה על המרפקים צמודים לגוף.","עצרו לרגע בשיא הכיפוף, תוך כיווץ הביצפס.","הורידו את ידית הכבל באיטיות בחזרה לנקודת ההתחלה, תוך יישור מלא של הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a cable handle to the lowest setting on a cable machine.","Stand facing the machine with your feet shoulder-width apart.","Hold the cable handle with an underhand grip, palms facing up, and arms fully extended.","Lower your body into a squat position, keeping your back straight and knees behind your toes.","As you squat down, curl the cable handle towards your shoulders, keeping your elbows close to your sides.","Pause for a moment at the top of the curl, squeezing your biceps.","Slowly lower the cable handle back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"3XFdb1Z"},{"id":"edb-0224","name":"כפיפת שורש כף היד בעמידה בפולי","name_en":"cable standing back wrist curl","muscle":"biceps","equipment":"cable","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["biceps","brachialis"],"steps":["עמדו מול מכונת הפולי כשרגליכם ברוחב הכתפיים.","אחזו בידית הכבל באחיזה עילית, כפות הידיים פונות מטה.","שמרו על הזרועות ישרות והמרפקים צמודים לגוף.","כופפו את שורשי הידיים באיטיות כלפי מעלה, תוך קירוב ידית הכבל לגוף.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את ידית הפולי לאט חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand facing a cable machine with your feet shoulder-width apart.","Hold the cable handle with an overhand grip, palms facing down.","Keep your arms straight and your elbows close to your sides.","Slowly curl your wrists upward, bringing the cable handle towards your body.","Pause for a moment at the top, then slowly lower the cable handle back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"VhX2JdE"},{"id":"edb-1375","name":"הרמת עקבים בעמידה בפולי","name_en":"cable standing calf raise","muscle":"legs","equipment":"cable","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings","glutes"],"steps":["עמדו מול מכונת הפולי כשרגליכם ברוחב הכתפיים.","אחזו בידיות מכונת הכבלים או חברו רצועת קרסול לכבל סביב הקרסוליים.","הרימו את העקבים מהרצפה על ידי יישור הקרסוליים לגובה המרבי האפשרי.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקבים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand facing a cable machine with your feet shoulder-width apart.","Hold onto the cable machine handles or attach a cable ankle strap to your ankles.","Raise your heels off the ground by extending your ankles as high as possible.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"yl2IYyy"},{"id":"edb-0225","name":"פרפר הפוך בעמידה גבוה בפולי","name_en":"cable standing cross-over high reverse fly","muscle":"shoulders","equipment":"cable","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","rhomboids","rear deltoids"],"steps":["חברו ידית D לכל צד של מכונת כבלים בגובה הכתפיים.","עמדו במרכז מכונת הכבלים כשכפות הרגליים ברוחב הכתפיים.","אחזו בידיות באחיזה עילית וישרו את הזרועות הצדה, כפות הידיים פונות קדימה.","שמרו על כיפוף קל במרפקים וגב ישר לאורך כל התרגיל.","הפעילו את שרירי הכתפיים וכווצו את השכמות זו לזו תוך משיכת הידיות לכיוון קדמת הגוף.","עצרו לרגע בשיא התנועה, ולאחר מכן חזרו באיטיות לנקודת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a D-handle to each side of a cable machine at shoulder height.","Stand in the middle of the cable machine with your feet shoulder-width apart.","Grasp the handles with an overhand grip and extend your arms out to the sides, palms facing forward.","Keep a slight bend in your elbows and maintain a straight back throughout the exercise.","Engage your shoulder muscles and squeeze your shoulder blades together as you pull the handles towards the front of your body.","Pause for a moment at the peak of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"P5p0j8B"},{"id":"edb-0226","name":"כפיפת בטן בעמידה בפולי","name_en":"cable standing crunch","muscle":"core","equipment":"cable","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques"],"steps":["חברו ידית כבל לפולי גבוה ועמדו כשגבכם אל המכונה.","אחזו בידית בשתי הידיים והניחו אותה מאחורי הראש, תוך שמירה על המרפקים כפופים.","עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","תוך הפעלת שרירי הבטן, נשפו וכופפו את פלג הגוף כלפי מטה לכיוון הברכיים, תוך קירוב המרפקים לירכיים.","עצרו לרגע בתחתית התנועה, ולאחר מכן חזרו לאט לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a cable handle to a high pulley and stand facing away from the machine.","Hold the handle with both hands and place it behind your head, keeping your elbows bent.","Stand with your feet shoulder-width apart and your knees slightly bent.","Keeping your abs engaged, exhale and crunch your torso down towards your knees, bringing your elbows towards your thighs.","Pause for a moment at the bottom of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"jpgqxiS"},{"id":"edb-0874","name":"כפיפת בטן בעמידה עם חבל בפולי","name_en":"cable standing crunch (with rope attachment)","muscle":"core","equipment":"cable","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques"],"steps":["חברו חבל למכונת כבלים בגובה החזה.","עמדו כשגבכם למכונה ורגליכם ברוחב הכתפיים.","אחזו בחבל בשתי הידיים והביאו אותו מאחורי הראש, תוך שמירה על המרפקים כפופים.","הפעילו את שרירי הבטן וכופפו את פלג הגוף קדימה באיטיות, תוך קירוב המרפקים לברכיים.","עצרו לרגע בשיא הכפיפה, ולאחר מכן חזרו לאט למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a rope to a cable machine at chest height.","Stand facing away from the machine with your feet shoulder-width apart.","Hold the rope with both hands and bring it behind your head, keeping your elbows bent.","Engage your abs and slowly crunch your torso forward, bringing your elbows towards your knees.","Pause for a moment at the top of the crunch, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"XU3ePuv"},{"id":"edb-0227","name":"פרפר בעמידה בפולי","name_en":"cable standing fly","muscle":"chest","equipment":"cable","target":"pectorals","bodyPart":"chest","secondaryMuscles":["deltoids","triceps"],"steps":["חברו את הידיות לכבלים בגובה החזה.","עמדו כשכפות הרגליים ברוחב הכתפיים, כשגבכם אל מכונת הכבלים.","אחזו בידיות באחיזה עילית, כפות הידיים פונות קדימה.","צעדו מעט קדימה ליצירת מתח בכבלים.","הפעילו את שרירי הליבה ושמרו על גב ישר לאורך כל התרגיל.","עם כיפוף קל במרפקים, הביאו את הזרועות קדימה ויחד באיטיות לפני החזה.","כווצו את שרירי החזה בשיא התנועה.","הפכו את התנועה באיטיות, תוך החזרת הזרועות לנקודת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach the handles to the cables at chest height.","Stand with your feet shoulder-width apart, facing away from the cable machine.","Grasp the handles with an overhand grip, palms facing forward.","Step forward slightly to create tension in the cables.","Keep your core engaged and your back straight throughout the exercise.","With a slight bend in your elbows, slowly bring your arms forward and together in front of your chest.","Squeeze your chest muscles at the peak of the movement.","Slowly reverse the movement, returning your arms to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Pr9Rhf4"},{"id":"edb-0228","name":"פשיטה בעמידה בפולי","name_en":"cable standing hip extension","muscle":"glutes","equipment":"cable","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps"],"steps":["חברו כבל לפולי נמוך ועמדו כשגבכם אל המכונה.","הניחו את הכבל סביב הקרסול ועמדו כשכפות הרגליים ברוחב הכתפיים.","הפעילו את שרירי הליבה ושמרו על גב ישר לאורך כל התרגיל.","ישרו את הרגל באיטיות ישר אחורה, תוך כיווץ שרירי הישבן בשיא התנועה.","עצרו לרגע, ולאחר מכן חזרו למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי.","החליפו צדדים וחזרו על התרגיל עם הרגל השנייה."],"steps_en":["Attach a cable to a low pulley and stand facing away from the machine.","Place the cable around your ankle and stand with your feet shoulder-width apart.","Keep your core engaged and your back straight throughout the exercise.","Slowly extend your leg straight back, squeezing your glutes at the top of the movement.","Pause for a moment, then return to the starting position.","Repeat for the desired number of repetitions.","Switch sides and repeat with the other leg."],"mediaId":"Kpajagk"},{"id":"edb-0229","name":"כפיפת מרפק בעמידה בפולי","name_en":"cable standing inner curl","muscle":"biceps","equipment":"cable","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו מול מכונת הפולי כשרגליכם ברוחב הכתפיים.","אחזו בידית הכבל באחיזה תחתית, כפות הידיים פונות מעלה.","שמרו על המרפקים צמודים לגוף והזרועות העליונות קבועות.","נשפו וכופפו את ידית הכבל לכיוון הכתפיים, תוך כיווץ הביצפס.","עצרו לרגע בשיא התנועה, תוך כיווץ שריר הביצפס.","שאפו והורידו את ידית הכבל באיטיות בחזרה לנקודת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand facing a cable machine with your feet shoulder-width apart.","Grasp the cable handle with an underhand grip, palms facing up.","Keep your elbows close to your sides and your upper arms stationary.","Exhale and curl the cable handle towards your shoulders, contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the cable handle back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"YwnI4ja"},{"id":"edb-0230","name":"cable standing lift","name_en":"cable standing lift","muscle":"core","equipment":"cable","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","lower back"],"steps":["עמדו מול מכונת הפולי כשרגליכם ברוחב הכתפיים.","אחזו בידית הכבל בשתי הידיים ומקמו אותה בגובה המותניים.","הפעילו את שרירי הליבה ושמרו על גב ישר לאורך כל התרגיל.","תוך שמירה על הזרועות ישרות, נשפו והרימו את ידית הכבל לכיוון הכתף הנגדית, תוך סיבוב פלג הגוף.","עצרו לרגע למעלה, ולאחר מכן שאפו והורידו את ידית הכבל באיטיות בחזרה לנקודת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Stand facing the cable machine with your feet shoulder-width apart.","Hold the cable handle with both hands and position it at waist height.","Engage your core and maintain a straight back throughout the exercise.","Keeping your arms straight, exhale and lift the cable handle up towards your opposite shoulder, rotating your torso.","Pause for a moment at the top, then inhale and slowly lower the cable handle back to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"qFpAkpP"},{"id":"edb-0231","name":"פשיטת מרפק ביד אחת בעמידה בפולי","name_en":"cable standing one arm triceps extension","muscle":"triceps","equipment":"cable","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["עמדו כשרגליכם ברוחב הכתפיים, מול מכונת הפולי.","אחזו בידית הכבל ביד הימנית, כף היד פונה מטה, ומקמו את הזרוע כך שתהיה ישרה לגמרי ומקבילה לרצפה.","שמרו על המרפק קבוע במקומו וקרוב לגוף.","כופפו את המרפק באיטיות, תוך הורדת ידית הכבל לכיוון אחורי הראש.","עצרו לרגע בתחתית התנועה, ולאחר מכן ישרו את הזרוע בחזרה לנקודת ההתחלה.","חזרו על התנועה במספר החזרות הרצוי, ולאחר מכן החליפו צדדים ובצעו את התרגיל עם הזרוע השמאלית."],"steps_en":["Stand with your feet shoulder-width apart, facing the cable machine.","Hold the cable handle with your right hand, palm facing down, and position your arm so that it is fully extended and parallel to the ground.","Keep your elbow stationary and close to your body.","Slowly bend your elbow, lowering the cable handle towards the back of your head.","Pause for a moment at the bottom of the movement, then extend your arm back to the starting position.","Repeat for the desired number of repetitions, then switch sides and perform the exercise with your left arm."],"mediaId":"sYCcnon"},{"id":"edb-1376","name":"הרמת עקבים ברגל אחת בעמידה בפולי","name_en":"cable standing one leg calf raise","muscle":"legs","equipment":"cable","target":"calves","bodyPart":"lower legs","secondaryMuscles":["ankles","feet"],"steps":["עמדו מול מכונת הפולי כשרגליכם ברוחב הכתפיים.","אחזו במכונת הכבלים לתמיכה.","הרימו רגל אחת מהרצפה ושמרו על שיווי משקל על הרגל השנייה.","הרימו את העקב באיטיות מהרצפה, תוך הרמת הגוף על קצות האצבעות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקב בחזרה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו רגליים."],"steps_en":["Stand facing a cable machine with your feet shoulder-width apart.","Hold onto the cable machine for support.","Lift one leg off the ground and balance on the other leg.","Slowly raise your heel off the ground, lifting your body up onto your toes.","Pause for a moment at the top, then slowly lower your heel back down to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"mediaId":"fgc9Xdl"},{"id":"edb-0232","name":"משיכת פולי בעמידה עם חבל בפולי","name_en":"cable standing pulldown (with rope)","muscle":"biceps","equipment":"cable","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms","shoulders"],"steps":["חברו חבל למכונת הכבלים בהגדרה הגבוהה ביותר.","עמדו מול המכונה עם הרגליים ברוחב הכתפיים.","אחזו בחבל באחיזה עילית, כפות הידיים פונות מטה.","שמרו על גב ישר ושרירי ליבה פעילים לאורך כל התרגיל.","משכו את החבל כלפי מטה לכיוון הירכיים, תוך כיווץ הביצפס.","עצרו לרגע בתחתית, ולאחר מכן שחררו את החבל באיטיות בחזרה למעלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a rope to the cable machine at the highest setting.","Stand facing the machine with your feet shoulder-width apart.","Grasp the rope with an overhand grip, palms facing down.","Keep your back straight and core engaged throughout the exercise.","Pull the rope down towards your thighs, squeezing your biceps.","Pause for a moment at the bottom, then slowly release the rope back up.","Repeat for the desired number of repetitions."],"mediaId":"CvPn9WV"},{"id":"edb-0233","name":"חתירת כתף אחורית בעמידה עם חבל בפולי","name_en":"cable standing rear delt row (with rope)","muscle":"shoulders","equipment":"cable","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","rhomboids","biceps"],"steps":["עמדו מול מכונת הפולי כשרגליכם ברוחב הכתפיים.","אחזו בידית הכבל בשתי הידיים, כפות הידיים פונות זו לזו, וצעדו אחורה ליצירת מתח בכבל.","שמרו על גב ישר ושרירי ליבה מופעלים.","משכו את הכבל לכיוון הגוף, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה, ולאחר מכן שחררו את הכבל באיטיות בחזרה לנקודת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand facing a cable machine with your feet shoulder-width apart.","Hold the cable attachment with both hands, palms facing each other, and step back to create tension in the cable.","Keep your back straight and your core engaged.","Pull the cable towards your body, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the cable back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ZfyAGhK"},{"id":"edb-1727","name":"פשיטת מרפק ביד אחת אחיזה הפוכה בעמידה מעל הראש בפולי","name_en":"cable standing reverse grip one arm overhead tricep extension","muscle":"triceps","equipment":"cable","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["עמדו כשגבכם אל מכונת הכבלים, כשכפות הרגליים ברוחב הכתפיים.","אחזו בידית הכבל באחיזה תחתית וישרו את הזרוע מעל הראש, תוך שמירה על המרפק קרוב לראש.","שמרו על הזרוע העליונה קבועה במקומה והורידו את ידית הכבל באיטיות מאחורי הראש על ידי כיפוף המרפק.","עצרו לרגע בתחתית, ולאחר מכן ישרו את הזרוע בחזרה לנקודת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Stand facing away from the cable machine with your feet shoulder-width apart.","Hold the cable handle with an underhand grip and extend your arm overhead, keeping your elbow close to your head.","Keep your upper arm stationary and slowly lower the cable handle behind your head by bending your elbow.","Pause for a moment at the bottom, then extend your arm back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"i11JWU7"},{"id":"edb-0234","name":"חתירה עם ידית V בעמידה בפולי","name_en":"cable standing row (v-bar)","muscle":"back","equipment":"cable","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","shoulders"],"steps":["עמדו מול מכונת הפולי כשרגליכם ברוחב הכתפיים.","אחזו בידית ה-V באחיזה עילית, כפות הידיים פונות מטה.","שמרו על גב ישר ושרירי ליבה מופעלים.","משכו את ידית ה-V לכיוון הגוף, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה, ולאחר מכן שחררו את המתח באיטיות וחזרו לנקודת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand facing the cable machine with your feet shoulder-width apart.","Grasp the v-bar attachment with an overhand grip, palms facing down.","Keep your back straight and your core engaged.","Pull the v-bar towards your body, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"4f8RXP8"},{"id":"edb-0235","name":"cable standing shoulder external rotation","name_en":"cable standing shoulder external rotation","muscle":"shoulders","equipment":"cable","target":"delts","bodyPart":"shoulders","secondaryMuscles":["rotator cuff","trapezius"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","אחזו בידית הכבל כשהזרוע מושטת לפניכם, מקבילה לרצפה.","שמרו על המרפק כפוף מעט והשכמות משוכות אחורה.","סובבו את הזרוע החוצה, הרחק מהגוף, תוך שמירה על המרפק באותו מיקום.","עצרו לרגע בסוף התנועה, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your knees slightly bent.","Hold the cable handle with your arm extended in front of you, parallel to the ground.","Keep your elbow slightly bent and your shoulder blades pulled back.","Slowly rotate your arm outward, away from your body, while keeping your elbow in the same position.","Pause for a moment at the end of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"FWdVhcW"},{"id":"edb-0236","name":"חתירה עם ידית V בעמידה בפולי","name_en":"cable standing twist row (v-bar)","muscle":"back","equipment":"cable","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","shoulders"],"steps":["חברו ידית V למכונת כבלים בגובה החזה.","עמדו מול מכונת הפולי כשרגליכם ברוחב הכתפיים.","אחזו בידית ה-V באחיזה עילית, כפות הידיים פונות מטה.","צעדו צעד אחורה ליצירת מתח בכבל.","שמרו על גב ישר ושרירי ליבה פעילים לאורך כל התרגיל.","משכו את ידית ה-V לכיוון הגו על ידי כיווץ השכמות וכיפוף המרפקים.","תוך כדי המשיכה, סובבו את פלג הגוף לצד אחד, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה, תוך הרגשת הכיווץ בגב העליון.","שחררו את המתח באיטיות וחזרו לנקודת ההתחלה, תוך ביטול סיבוב פלג הגוף.","חזרו על התנועה במספר החזרות הרצוי, תוך החלפת כיוון הסיבוב בכל חזרה."],"steps_en":["Attach a v-bar attachment to a cable machine at chest height.","Stand facing the cable machine with your feet shoulder-width apart.","Grasp the v-bar with an overhand grip, palms facing down.","Take a step back to create tension in the cable.","Keep your back straight and core engaged throughout the exercise.","Pull the v-bar towards your torso by retracting your shoulder blades and bending your elbows.","As you pull, twist your torso to one side, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, feeling the contraction in your upper back.","Slowly release the tension and return to the starting position, untwisting your torso.","Repeat the movement for the desired number of repetitions, alternating the twisting direction with each rep."],"mediaId":"JOZhu2h"},{"id":"edb-1269","name":"cable standing up straight crossovers","name_en":"cable standing up straight crossovers","muscle":"chest","equipment":"cable","target":"pectorals","bodyPart":"chest","secondaryMuscles":["deltoids","triceps"],"steps":["עמדו במרכז מכונת כבלים כשכפות הרגליים ברוחב הכתפיים.","אחזו בידיות הכבלים כשכפות הידיים פונות מטה והזרועות ישרות הצדה.","תוך שמירה על הזרועות ישרות, הביאו את הידיים יחד לפני הגוף, תוך הצלבתן זו על זו.","עצרו לרגע, ולאחר מכן חזרו באיטיות לנקודת ההתחלה, תוך שמירה על הזרועות ישרות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand in the middle of a cable machine with your feet shoulder-width apart.","Hold the handles of the cables with your palms facing down and your arms extended straight out to the sides.","Keeping your arms straight, bring your hands together in front of your body, crossing them over each other.","Pause for a moment, then slowly return to the starting position, keeping your arms extended.","Repeat for the desired number of repetitions."],"mediaId":"UKWTJWR"},{"id":"edb-0238","name":"משיכת פולי בפולי","name_en":"cable straight arm pulldown","muscle":"back","equipment":"cable","target":"lats","bodyPart":"back","secondaryMuscles":["shoulders","biceps"],"steps":["חברו מוט ישר לפולי הגבוה של מכונת כבלים.","עמדו מול המכונה עם הרגליים ברוחב הכתפיים.","אחזו במוט באחיזה עילית, תוך שמירה על הזרועות ישרות וכפות הידיים פונות מטה.","הפעילו את שרירי הגב הרחבים ומשכו את המוט כלפי מטה לכיוון הירכיים, תוך שמירה על הזרועות ישרות לאורך כל התנועה.","עצרו לרגע בתחתית התנועה, ולאחר מכן החזירו את המוט לאט לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a straight bar to the high pulley of a cable machine.","Stand facing the machine with your feet shoulder-width apart.","Grasp the bar with an overhand grip, keeping your arms straight and your palms facing down.","Engage your lats and pull the bar down towards your thighs, keeping your arms straight throughout the movement.","Pause for a moment at the bottom, then slowly return the bar to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"x69MAlq"},{"id":"edb-0237","name":"משיכת פולי עם חבל בפולי","name_en":"cable straight arm pulldown (with rope)","muscle":"back","equipment":"cable","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["חברו חבל למכונת הכבלים בהגדרה הגבוהה ביותר.","עמדו מול המכונה עם הרגליים ברוחב הכתפיים.","אחזו בחבל בשתי הידיים, כפות הידיים פונות מטה.","ישרו את הזרועות לגמרי לפניכם, תוך שמירה על המרפקים כפופים מעט.","הפעילו את שרירי הגב הרחבים ומשכו את החבל באיטיות כלפי מטה לכיוון הירכיים, תוך שמירה על הזרועות ישרות.","עצרו לרגע בתחתית התנועה, ולאחר מכן שחררו לאט את המתח וחזרו לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a rope to the cable machine at the highest setting.","Stand facing the machine with your feet shoulder-width apart.","Grasp the rope with both hands, palms facing down.","Extend your arms fully in front of you, keeping your elbows slightly bent.","Engage your lats and slowly pull the rope down towards your thighs, keeping your arms straight.","Pause for a moment at the bottom, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"DT14T9T"},{"id":"edb-0239","name":"חתירה בישיבה בפולי","name_en":"cable straight back seated row","muscle":"back","equipment":"cable","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms","shoulders"],"steps":["שבו על מכונת חתירת הכבלים כשכפות הרגליים מונחות שטוח על משענות הרגליים והברכיים כפופות מעט.","אחזו בידיות הכבל באחיזה עילית, כפות הידיים פונות מטה.","שמרו על גב ישר והטו את הגוף מעט קדימה ממפרקי הירך.","משכו את ידיות הכבל לכיוון הגוף, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה, ולאחר מכן שחררו לאט את הידיות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the cable row machine with your feet flat on the footrests and your knees slightly bent.","Grasp the cable handles with an overhand grip, palms facing down.","Keep your back straight and lean slightly forward from the hips.","Pull the cable handles towards your body, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Tq6gbK6"},{"id":"edb-0240","name":"פרפר הפוך בשכיבה על הגב בפולי","name_en":"cable supine reverse fly","muscle":"shoulders","equipment":"cable","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","rhomboids"],"steps":["חברו ידית D לפולי כבל נמוך ושכבו על הבטן על ספסל שטוח.","אחזו בידית ה-D בכל יד, כפות הידיים פונות מטה, וישרו את הזרועות ישר לפניכם.","תוך שמירה על הזרועות ישרות, הרימו אותן הצדה עד שיהיו מקבילות לרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הידיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a D-handle to a low pulley cable machine and lie face down on a flat bench.","Grasp the D-handle with each hand, palms facing down, and extend your arms straight out in front of you.","Keeping your arms straight, raise them out to the sides until they are parallel to the floor.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"PQcUlDi"},{"id":"edb-2464","name":"חתירה בפולי","name_en":"cable thibaudeau kayak row","muscle":"back","equipment":"cable","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","rhomboids","rear deltoids"],"steps":["חברו ידית כבל לפולי נמוך ושבו מול המכונה כשכפות הרגליים מונחות שטוח על הרצפה.","אחזו בידית ביד הימנית וישרו את הזרוע לגמרי, תוך שמירה על כיפוף קל במרפק.","הטו את הגוף קדימה ממפרקי הירך, תוך שמירה על גב ישר והפעלת שרירי הבטן.","משכו את הידית לכיוון הגו על ידי כיווץ השכמה וכיפוף המרפק, תוך שמירה על הזרוע קרובה לגוף.","כווצו את שרירי הגב בשיא התנועה, ולאחר מכן חזרו באיטיות לנקודת ההתחלה.","חזרו במספר החזרות הרצוי, ולאחר מכן החליפו צדדים ובצעו עם הזרוע השמאלית."],"steps_en":["Attach a cable handle to a low pulley and sit facing the machine with your feet flat on the floor.","Grasp the handle with your right hand and extend your arm fully, keeping a slight bend in your elbow.","Lean forward from your hips, keeping your back straight and your abs engaged.","Pull the handle towards your torso by retracting your shoulder blade and bending your elbow, keeping your arm close to your body.","Squeeze your back muscles at the top of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch sides and perform with your left arm."],"mediaId":"ZgwWBoC"},{"id":"edb-0241","name":"פשיטת מרפק בפולי","name_en":"cable triceps pushdown (v-bar)","muscle":"triceps","equipment":"cable","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["חברו ידית V למכונת הכבלים בהגדרה הגבוהה ביותר.","עמדו מול מכונת הפולי כשרגליכם ברוחב הכתפיים.","אחזו בידית ה-V באחיזה עילית, כפות הידיים פונות מטה, והידיים ברוחב הכתפיים.","שמרו על המרפקים צמודים לגוף והזרועות העליונות קבועות לאורך כל התרגיל.","הפעילו את שרירי הטריצפס ונשפו תוך דחיפת ידית ה-V כלפי מטה עד ליישור מלא של הזרועות.","עצרו לרגע בתחתית התנועה, תוך כיווץ הטריצפס.","שאפו תוך החזרת ידית ה-V באיטיות לנקודת ההתחלה, תוך שמירה על שליטה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a v-bar attachment to the cable machine at the highest setting.","Stand facing the cable machine with your feet shoulder-width apart.","Grasp the v-bar with an overhand grip, palms facing down, and your hands shoulder-width apart.","Keep your elbows close to your sides and your upper arms stationary throughout the exercise.","Engage your triceps and exhale as you push the v-bar down until your arms are fully extended.","Pause for a moment at the bottom of the movement, squeezing your triceps.","Inhale as you slowly return the v-bar to the starting position, maintaining control.","Repeat for the desired number of repetitions."],"mediaId":"gAwDzB3"},{"id":"edb-2405","name":"פשיטת מרפק בפולי עם ידית V בפולי","name_en":"cable triceps pushdown (v-bar) (with arm blaster)","muscle":"triceps","equipment":"cable","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["חברו ידית V למכונת הכבלים בהגדרה הגבוהה ביותר.","עמדו מול מכונת הפולי כשרגליכם ברוחב הכתפיים.","אחזו בידית ה-V באחיזה עילית, כפות הידיים פונות מטה, והידיים ברוחב הכתפיים.","שמרו על המרפקים צמודים לגוף והזרועות העליונות קבועות לאורך כל התרגיל.","הפעילו את שרירי הטריצפס ונשפו תוך דחיפת ידית ה-V כלפי מטה עד ליישור מלא של הזרועות.","עצרו לרגע בתחתית התנועה, תוך כיווץ הטריצפס.","שאפו תוך החזרת ידית ה-V באיטיות לנקודת ההתחלה, תוך שמירה על שליטה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a v-bar attachment to the cable machine at the highest setting.","Stand facing the cable machine with your feet shoulder-width apart.","Grasp the v-bar with an overhand grip, palms facing down, and your hands shoulder-width apart.","Keep your elbows close to your sides and your upper arms stationary throughout the exercise.","Engage your triceps and exhale as you push the v-bar down until your arms are fully extended.","Pause for a moment at the bottom of the movement, squeezing your triceps.","Inhale as you slowly return the v-bar to the starting position, maintaining control.","Repeat for the desired number of repetitions."],"mediaId":"OxJk1fg"},{"id":"edb-0242","name":"כפיפת בטן הפוכה בפולי","name_en":"cable tuck reverse crunch","muscle":"core","equipment":"cable","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["חברו כבל לפולי נמוך ושכבו על מזרן על הגב.","אחזו בכבל בשתי הידיים וישרו את הזרועות ישר כלפי מעלה מעל החזה.","כופפו את הברכיים והרימו את הרגליים כלפי מעלה, תוך קירוב הברכיים לחזה.","במקביל, כופפו את האגן כלפי מעלה לכיוון החזה, תוך הרמת האגן מהרצפה.","עצרו לרגע למעלה, ולאחר מכן הורידו את הרגליים והאגן באיטיות בחזרה לנקודת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a cable to a low pulley and lie down on a mat facing up.","Hold the cable with both hands and extend your arms straight up above your chest.","Bend your knees and lift your legs up, bringing your knees towards your chest.","At the same time, curl your pelvis up towards your chest, lifting your hips off the ground.","Pause for a moment at the top, then slowly lower your legs and hips back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"TXtXc84"},{"id":"edb-0243","name":"פיתול בפולי","name_en":"cable twist","muscle":"core","equipment":"cable","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques"],"steps":["עמדו כשרגליכם ברוחב הכתפיים, מול מכונת הפולי.","אחזו בידית הכבל בשתי הידיים לפני החזה, תוך שמירה על הזרועות כפופות מעט.","הפעילו את שרירי הליבה וסובבו את פלג הגוף ימינה, תוך משיכת הכבל לרוחב הגוף.","עצרו לרגע בסוף התנועה, תוך הרגשת הכיווץ בשרירי הבטן והאלכסונים.","חזרו באיטיות לנקודת ההתחלה, תוך התנגדות למשיכת הכבל.","חזרו על התנועה לצד השמאלי.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, facing the cable machine.","Hold the cable handle with both hands in front of your chest, keeping your arms slightly bent.","Engage your core and twist your torso to the right, pulling the cable across your body.","Pause for a moment at the end of the movement, feeling the contraction in your abs and obliques.","Slowly return to the starting position, resisting the cable's pull.","Repeat the movement to the left side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"aVs3BR3"},{"id":"edb-0862","name":"פיתול בפולי","name_en":"cable twist (up-down)","muscle":"core","equipment":"cable","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","lower back"],"steps":["עמדו כשרגליכם ברוחב הכתפיים, מול מכונת הפולי.","אחזו בידית הכבל בשתי הידיים לפני החזה, תוך שמירה על הזרועות כפופות מעט.","הפעילו את שרירי הליבה וסובבו את פלג הגוף באיטיות לצד אחד, תוך שמירה על יציבות הירכיים והרגליים.","עצרו לרגע בסוף הסיבוב, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו על הסיבוב לצד הנגדי.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, facing the cable machine.","Hold the cable handle with both hands in front of your chest, keeping your arms slightly bent.","Engage your core and slowly rotate your torso to one side, keeping your hips and legs stable.","Pause for a moment at the end of the rotation, then slowly return to the starting position.","Repeat the rotation to the opposite side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"fhZQPlV"},{"id":"edb-0244","name":"cable twisting pull","name_en":"cable twisting pull","muscle":"back","equipment":"cable","target":"lats","bodyPart":"back","secondaryMuscles":["shoulders","biceps"],"steps":["חברו ידית כבל לפולי נמוך ועמדו מול המכונה.","אחזו בידית ביד השמאלית והתרחקו מהמכונה, תוך יישור מלא של הזרוע.","מקמו את כפות הרגליים ברוחב הכתפיים, עם הברכיים כפופות מעט.","שמרו על הגב ישר ושרירי הליבה מופעלים לאורך כל התרגיל.","משכו את הידית לכיוון הגוף, תוך סיבוב פלג הגוף ימינה במהלך התנועה.","כווצו את שרירי הגב בסיום התנועה.","חזרו באיטיות לנקודת ההתחלה, תוך שמירה על מתח בכבל.","חזרו במספר החזרות הרצוי, ולאחר מכן החליפו צדדים ובצעו עם היד הימנית."],"steps_en":["Attach a cable handle to a low pulley and stand facing the machine.","Grasp the handle with your left hand and step away from the machine, extending your arm fully.","Position your feet shoulder-width apart, with your knees slightly bent.","Keep your back straight and your core engaged throughout the exercise.","Pull the handle towards your body, rotating your torso to the right as you do so.","Squeeze your back muscles at the end of the movement.","Slowly return to the starting position, keeping tension on the cable.","Repeat for the desired number of repetitions, then switch sides and perform with your right hand."],"mediaId":"zCgxPbV"},{"id":"edb-1645","name":"כפיפת מרפק בשתי ידיים בשיפוע בפולי","name_en":"cable two arm curl on incline bench","muscle":"biceps","equipment":"cable","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל משופע כשגבכם נשען על הכרית וכפות הרגליים מונחות שטוח על הרצפה.","אחזו בידיות הכבל באחיזה תחתית, כפות הידיים פונות מעלה, והזרועות ישרות לגמרי.","תוך שמירה על הזרועות העליונות קבועות במקומן, נשפו וכופפו את הידיות לכיוון הכתפיים תוך כיווץ הביצפס.","עצרו לרגע בשיא התנועה, תוך כיווץ שריר הביצפס.","שאפו והורידו את הידיות באיטיות בחזרה לנקודת ההתחלה, תוך יישור מלא של הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on an incline bench with your back against the pad and your feet flat on the ground.","Grasp the cable handles with an underhand grip, palms facing up, and your arms fully extended.","Keeping your upper arms stationary, exhale and curl the handles towards your shoulders while contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the handles back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"H9y3Dkr"},{"id":"edb-1728","name":"בעיטה אחורית בשתי ידיים בפולי","name_en":"cable two arm tricep kickback","muscle":"triceps","equipment":"cable","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","אחזו בידית הכבל בכל יד, כשכפות הידיים פונות פנימה והזרועות כפופות בזווית של 90 מעלות.","תוך שמירה על הזרועות העליונות קבועות במקומן, ישרו את האמות אחורה עד שהזרועות ישרות לגמרי.","עצרו לרגע, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and knees slightly bent.","Hold the cable handle in each hand with your palms facing inwards and your arms bent at a 90-degree angle.","Keeping your upper arms stationary, extend your forearms backwards until your arms are fully extended.","Pause for a moment, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"vvNjDJS"},{"id":"edb-0245","name":"משיכת פולי בפולי","name_en":"cable underhand pulldown","muscle":"back","equipment":"cable","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["כווננו את מכונת הכבלים כך שמוט המשיכה יהיה בגובה מעל הראש.","שבו על המושב ואחזו במוט המשיכה באחיזה תחתית, הידיים רחבות מעט יותר מרוחב הכתפיים.","שמרו על הגב ישר והטו את הגוף מעט אחורה.","משכו את המוט כלפי מטה לכיוון החזה, תוך כיווץ השכמות זו לזו.","עצרו לרגע בתחתית התנועה, ולאחר מכן שחררו את המוט באיטיות בחזרה למעלה לנקודת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the cable machine so that the pulldown bar is at a height above your head.","Sit down on the seat and grab the pulldown bar with an underhand grip, hands slightly wider than shoulder-width apart.","Keep your back straight and lean back slightly.","Pull the bar down towards your chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the bar back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"xBYcQHj"},{"id":"edb-1270","name":"cable upper chest crossovers","name_en":"cable upper chest crossovers","muscle":"chest","equipment":"cable","target":"pectorals","bodyPart":"chest","secondaryMuscles":["deltoids","triceps"],"steps":["חברו את הידיות לכבלים בגובה החזה.","עמדו במרכז מכונת הכבלים עם רגל אחת מעט לפני השנייה.","אחזו בידיות כשכפות הידיים פונות למטה והזרועות מושטות הצדה.","שמרו על כיפוף קל במרפקים והפעילו את שרירי הליבה.","משכו את הפולים יחד לפני החזה, כשהם חוצים זה את זה.","כווצו את שרירי החזה בשיא התנועה.","שחררו לאט את הפולים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach the handles to the cables at chest height.","Stand in the center of the cable machine with one foot slightly in front of the other.","Grasp the handles with your palms facing down and your arms extended out to the sides.","Keep a slight bend in your elbows and engage your core.","Pull the cables together in front of your chest, crossing them over each other.","Squeeze your chest muscles at the peak of the movement.","Slowly release the cables back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"j7XMAyn"},{"id":"edb-1324","name":"חתירה בפולי","name_en":"cable upper row","muscle":"back","equipment":"cable","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","shoulders"],"steps":["חברו מוט ישר למכונת הפולי בגובה החזה.","עמדו מול המכונה עם הרגליים ברוחב הכתפיים.","אחזו במוט באחיזה עליונה, כשהידיים ברוחב מעט גדול מרוחב הכתפיים.","שמרו על גב ישר ושרירי ליבה מופעלים.","משכו את המוט לכיוון החזה העליון, תוך כדי כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה.","שחררו לאט את המוט בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a straight bar to a cable machine at chest height.","Stand facing the machine with your feet shoulder-width apart.","Grasp the bar with an overhand grip, hands slightly wider than shoulder-width apart.","Keep your back straight and your core engaged.","Pull the bar towards your upper chest, squeezing your shoulder blades together.","Pause for a moment at the top of the movement.","Slowly release the bar back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"PQStVXH"},{"id":"edb-0246","name":"חתירה זקופה בפולי","name_en":"cable upright row","muscle":"shoulders","equipment":"cable","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","biceps"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, הברכיים כפופות מעט, ואחזו בידית הפולי באחיזה עליונה.","שמרו על הגב ישר ושרירי הליבה מופעלים לאורך כל התרגיל.","משכו את ידית הפולי ישר כלפי מעלה לכיוון הסנטר, כשהמרפקים מובילים את התנועה.","עצרו לרגע בשיא התנועה, תוך כיווץ השכמות זו לזו.","הורידו לאט את ידית הפולי בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, knees slightly bent, and hold the cable attachment with an overhand grip.","Keep your back straight and your core engaged throughout the exercise.","Pull the cable attachment straight up towards your chin, leading with your elbows.","Pause for a moment at the top, squeezing your shoulder blades together.","Slowly lower the cable attachment back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"cALKspW"},{"id":"edb-1325","name":"משיכת פולי אחיזה רחבה מאחורי העורף אחורי בפולי","name_en":"cable wide grip rear pulldown behind neck","muscle":"back","equipment":"cable","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","rhomboids","rear deltoids"],"steps":["כווננו את מכונת הכבלים כך שמוט המשיכה יהיה בגובה מעל הראש.","שבו על המושב ואחזו במוט המשיכה באחיזה עליונה רחבה.","שמרו על הגב ישר והחזה מורם תוך הטיה קלה לאחור.","משכו את המוט כלפי מטה לכיוון החלק העליון של החזה, תוך כיווץ השכמות זו לזו.","עצרו לרגע בתחתית התנועה, ולאחר מכן שחררו את המוט באיטיות בחזרה למעלה לנקודת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the cable machine so that the pulldown bar is at a height above your head.","Sit down on the seat and grab the pulldown bar with a wide overhand grip.","Keep your back straight and your chest up as you lean back slightly.","Pull the bar down towards your upper chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the bar back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"CmEr4pM"},{"id":"edb-0247","name":"כפיפת שורש כף היד בפולי","name_en":"cable wrist curl","muscle":"biceps","equipment":"cable","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["biceps","brachialis"],"steps":["חברו מוט ישר לגלגלת תחתונה של מכונת הפולי.","עמדו מול המכונה עם הרגליים ברוחב הכתפיים.","אחזו במוט באחיזה תחתית, כפות הידיים פונות מעלה, והידיים ברוחב הכתפיים.","הניחו את האמות על ספסל או משטח מרופד, כשפרקי הידיים תלויים מעבר לקצה.","תוך שמירה על האמות ללא תנועה, נשפו וכופפו את פרקי הידיים כלפי מעלה עד כמה שניתן.","עצרו לרגע בשיא התנועה, לאחר מכן שאפו אוויר והורידו לאט את המוט בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a straight bar to a low pulley cable machine.","Stand facing the machine with your feet shoulder-width apart.","Grasp the bar with an underhand grip, palms facing up, and your hands shoulder-width apart.","Rest your forearms on a bench or pad, with your wrists hanging off the edge.","Keeping your forearms stationary, exhale and curl your wrists upward as far as possible.","Pause for a moment at the top, then inhale and slowly lower the bar back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"LrV4s90"},{"id":"edb-1407","name":"מתיחה","name_en":"calf push stretch with hands against wall","muscle":"legs","equipment":"body weight","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings"],"steps":["עמדו מול קיר עם הרגליים ברוחב האגן.","הניחו את הידיים על הקיר בגובה הכתפיים.","צעדו לאחור עם רגל אחת, כשהעקב נשאר על הרצפה והרגל ישרה.","כופפו מעט את הברך הקדמית והתכופפו קדימה, עד שתרגישו מתיחה בשוק.","החזיקו את המתיחה במשך 20-30 שניות.","החליפו רגליים וחזרו על המתיחה."],"steps_en":["Stand facing a wall with your feet hip-width apart.","Place your hands against the wall at shoulder height.","Step back with one foot, keeping your heel on the ground and your leg straight.","Bend your front knee slightly and lean forward, feeling a stretch in your calf.","Hold the stretch for 20-30 seconds.","Switch legs and repeat the stretch."],"mediaId":"PzNxakt"},{"id":"edb-1377","name":"מתיחה","name_en":"calf stretch with hands against wall","muscle":"legs","equipment":"body weight","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings"],"steps":["עמדו מול קיר עם הרגליים ברוחב האגן.","הניחו את הידיים על הקיר בגובה הכתפיים.","צעדו עם הרגל הימנית לאחור, כשהעקב נשאר על הרצפה והרגל ישרה.","כופפו את הברך השמאלית והתכופפו קדימה, כשהרגל האחורית נשארת ישרה והעקב על הרצפה.","החזיקו את המתיחה במשך 20-30 שניות.","החליפו רגליים וחזרו על המתיחה."],"steps_en":["Stand facing a wall with your feet hip-width apart.","Place your hands against the wall at shoulder height.","Step your right foot back, keeping your heel on the ground and your leg straight.","Bend your left knee and lean forward, keeping your back leg straight and your heel on the ground.","Hold the stretch for 20-30 seconds.","Switch legs and repeat the stretch."],"mediaId":"m0tCHqc"},{"id":"edb-1378","name":"מתיחה עם חבל","name_en":"calf stretch with rope","muscle":"legs","equipment":"rope","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings"],"steps":["עמדו מול קיר או עצם יציב עם הרגליים ברוחב האגן.","אחזו בקצות החבל בכל יד והניחו את אמצע החבל סביב כרית כף הרגל הימנית.","צעדו לאחור עם הרגל השמאלית, כשהעקב נשאר על הרצפה והרגל ישרה.","התכופפו קדימה תוך שמירה על גב ישר, ומשכו בעדינות את החבל כדי למתוח את השוק.","החזיקו את המתיחה במשך 20-30 שניות, ולאחר מכן שחררו.","חזרו על הרגל השנייה."],"steps_en":["Stand facing a wall or sturdy object with your feet hip-width apart.","Hold the ends of the rope in each hand and place the middle of the rope around the ball of your right foot.","Step back with your left foot, keeping your heel on the ground and your leg straight.","Lean forward, keeping your back straight, and gently pull on the rope to stretch your calf.","Hold the stretch for 20-30 seconds, then release.","Repeat on the other leg."],"mediaId":"1LVFcEn"},{"id":"edb-0248","name":"חתירה בשכיבה","name_en":"cambered bar lying row","muscle":"back","equipment":"barbell","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["הניחו מוט על הרצפה ושכבו על הבטן על ספסל כשהחזה מעט מעבר לקצה.","התכופפו ואחזו במוט באחיזה עליונה, מעט רחבה יותר מרוחב הכתפיים.","כשהרגליים ישרות וכפות הרגליים על הרצפה, הרימו את המוט מהרצפה על ידי פשיטת הידיים.","משכו את המוט לכיוון החזה, תוך כיווץ השכמות זו לזו.","הורידו את המוט בחזרה למצב ההתחלתי וחזרו על התנועה למספר החזרות הרצוי."],"steps_en":["Set up a barbell on the floor and lie face down on a bench with your chest just off the edge.","Reach down and grab the barbell with an overhand grip, slightly wider than shoulder-width apart.","With your legs straight and feet on the ground, lift the barbell off the floor by extending your arms.","Pull the barbell towards your chest, squeezing your shoulder blades together.","Lower the barbell back down to the starting position and repeat for the desired number of repetitions."],"mediaId":"R5swFnc"},{"id":"edb-2963","name":"הרמת רגליים","name_en":"captains chair straight leg raise","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שבו על כיסא הקפטן כשהגב צמוד למשענת והאמות מונחות על משטחי התמיכה.","שמרו על פלג הגוף העליון יציב והגב ישר.","הפעילו את שרירי הבטן והרימו את הרגליים קדימה כשהן ישרות.","המשיכו להרים עד שהרגליים מקבילות לרצפה או עד לגובה הנוח לכם.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the captain's chair with your back against the backrest and your forearms resting on the arm pads.","Keep your upper body stable and your back straight.","Engage your abs and lift your legs up in front of you, keeping them straight.","Continue lifting until your legs are parallel to the ground or as high as you can comfortably go.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"weoDEpH"},{"id":"edb-1548","name":"מתיחה","name_en":"chair leg extended stretch","muscle":"legs","equipment":"body weight","target":"quads","bodyPart":"upper legs","secondaryMuscles":["hamstrings","calves"],"steps":["שבו על קצה כיסא כשהגב ישר וכפות הרגליים שטוחות על הרצפה.","פשטו רגל אחת ישר קדימה, כשהעקב נשאר על הרצפה.","התכופפו מעט קדימה, עד שתרגישו מתיחה בשריר הארבע ראשי.","החזיקו בתנוחה זו במשך 20-30 שניות.","החליפו רגליים וחזרו על המתיחה."],"steps_en":["Sit on the edge of a chair with your back straight and feet flat on the ground.","Extend one leg straight out in front of you, keeping your heel on the ground.","Lean forward slightly, feeling a stretch in your quadriceps.","Hold this position for 20-30 seconds.","Switch legs and repeat the stretch."],"mediaId":"xGgAGPm"},{"id":"edb-1271","name":"מתיחה קדמי","name_en":"chest and front of shoulder stretch","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["deltoids"],"steps":["עמדו זקוף עם הרגליים ברוחב הכתפיים.","פשטו את הידיים ישר קדימה בגובה הכתפיים.","שלבו את הידיים לפני הגוף, כשהיד הימנית מעל היד השמאלית.","שזרו את האצבעות ולחצו את כפות הידיים זו לזו.","כווצו בעדינות את השכמות זו לזו ודחפו את הידיים קדימה, עד שתרגישו מתיחה בחזה ובחלק הקדמי של הכתפיים.","החזיקו את המתיחה במשך 20-30 שניות, ולאחר מכן שחררו.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand tall with your feet shoulder-width apart.","Extend your arms straight out in front of you at shoulder height.","Cross your arms in front of your body, with your right arm on top of your left arm.","Interlace your fingers and press your palms together.","Gently squeeze your shoulder blades together and push your hands forward, feeling a stretch in your chest and front of your shoulders.","Hold the stretch for 20-30 seconds, then release.","Repeat for the desired number of repetitions."],"mediaId":"Uto7l43"},{"id":"edb-0251","name":"מקבילים","name_en":"chest dip","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["התמקמו על מקבילים כשהידיים ישרות לגמרי והגוף ישר.","הורידו את הגוף על ידי כיפוף המרפקים עד שהכתפיים מתחת למרפקים.","דחפו את עצמכם חזרה למצב ההתחלתי על ידי יישור הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Position yourself on parallel bars with your arms fully extended and your body straight.","Lower your body by bending your elbows until your shoulders are below your elbows.","Push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"mediaId":"9WTm7dq"},{"id":"edb-1430","name":"מתח","name_en":"chest dip (on dip-pull-up cage)","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["התאימו את מוטות הדיפ לגובה שמאפשר אחיזה נוחה.","עמדו בין המוטות והניחו את הידיים על כל מוט, מעט רחב יותר מרוחב הכתפיים.","קפצו למעלה ויישרו את הידיים, כשמשקל הגוף נתמך על המוטות.","כופפו את הברכיים ושלבו את הקרסוליים מאחור.","הורידו את הגוף על ידי כיפוף המרפקים, כשהחזה מורם והכתפיים למטה.","המשיכו להוריד עד שהכתפיים מתחת למרפקים או עד שתרגישו מתיחה בחזה.","דחפו דרך כפות הידיים ופשטו את המרפקים כדי להרים את הגוף בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the dip bars to a height that allows you to comfortably grip them.","Stand between the bars and place your hands on each bar, slightly wider than shoulder-width apart.","Jump up and straighten your arms, supporting your body weight on the bars.","Bend your knees and cross your ankles behind you.","Lower your body by bending your elbows, keeping your chest up and your shoulders down.","Continue lowering until your shoulders are below your elbows or until you feel a stretch in your chest.","Push through your palms and extend your elbows to raise your body back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"XgWyAiA"},{"id":"edb-2462","name":"מקבילים","name_en":"chest dip on straight bar","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["אחזו במקבילים כשכפות הידיים פונות מטה והידיים ישרות לגמרי.","כופפו את הברכיים ושלבו את הקרסוליים.","הורידו את הגוף על ידי כיפוף הידיים עד שהכתפיים מתחת למרפקים.","דחפו את עצמכם חזרה למצב ההתחלתי על ידי יישור הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Grab the parallel bars with your palms facing down and your arms fully extended.","Bend your knees and cross your ankles.","Lower your body by bending your arms until your shoulders are below your elbows.","Push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"mediaId":"LQFOrMn"},{"id":"edb-1272","name":"מתיחה","name_en":"chest stretch with exercise ball","muscle":"chest","equipment":"stability ball","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["שבו על כדור הפיזיו כשכפות הרגליים שטוחות על הרצפה והגב ישר.","אחזו בכדור ההתעמלות בשתי הידיים ופשטו אותן ישר קדימה.","קרבו לאט את כדור ההתעמלות לכיוון החזה, עד שתרגישו מתיחה בשרירי החזה.","החזיקו את המתיחה למספר שניות, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the stability ball with your feet flat on the ground and your back straight.","Hold the exercise ball with both hands and extend your arms straight out in front of you.","Slowly bring the exercise ball towards your chest, feeling a stretch in your chest muscles.","Hold the stretch for a few seconds, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ykA5tU7"},{"id":"edb-3216","name":"שכיבת סמיכה","name_en":"chest tap push-up (male)","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["התחילו בעמדת פלאנק גבוה כשהידיים מעט רחבות יותר מרוחב הכתפיים והגוף בקו ישר.","הורידו את הגוף לכיוון הרצפה על ידי כיפוף המרפקים, כשהם צמודים לגוף.","תוך כדי הירידה, געו בחזה עם היד הימנית.","דחפו את עצמכם בחזרה לעמדת ההתחלה.","חזרו על התנועה, הפעם תוך נגיעה בחזה עם היד השמאלית.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Start in a high plank position with your hands slightly wider than shoulder-width apart and your body in a straight line.","Lower your body towards the ground by bending your elbows, keeping them close to your sides.","As you lower yourself, tap your chest with your right hand.","Push yourself back up to the starting position.","Repeat the movement, this time tapping your chest with your left hand.","Continue alternating sides for the desired number of repetitions."],"mediaId":"7E06s6d"},{"id":"edb-1326","name":"מתח אחיזה תחתית","name_en":"chin-up","muscle":"back","equipment":"body weight","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["היתלו ממתקן מתח כאשר כפות הידיים פונות אליכם והידיים במרחק רוחב הכתפיים.","הפעילו את שרירי הליבה ומשכו את הגוף כלפי מעלה לכיוון המוט, כשהחזה מוביל את התנועה.","המשיכו למשוך עד שהסנטר מעל המוט.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הגוף בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Hang from a pull-up bar with your palms facing towards you and your hands shoulder-width apart.","Engage your core and pull your body up towards the bar, leading with your chest.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"T2mxWqc"},{"id":"edb-0253","name":"chin-ups (narrow parallel grip)","name_en":"chin-ups (narrow parallel grip)","muscle":"back","equipment":"body weight","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["היתלו על מתח באחיזה מקבילה צרה, כשכפות הידיים פונות אליכם.","הפעילו את שרירי הגב ומשכו את הגוף כלפי מעלה לכיוון המוט, כשהמרפקים צמודים לגוף.","המשיכו למשוך עד שהסנטר מעל המוט.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הגוף בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Hang from a pull-up bar with a narrow parallel grip, palms facing towards you.","Engage your back muscles and pull your body up towards the bar, keeping your elbows close to your body.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"G70mEAJ"},{"id":"edb-0257","name":"מתיחה","name_en":"circles knee stretch","muscle":"legs","equipment":"body weight","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings","quadriceps"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והידיים על המותניים.","כופפו מעט את הברכיים והרימו את העקבים מהרצפה, תוך שמירה על שיווי משקל על כריות כפות הרגליים.","כשהברכיים כפופות, סובבו אותן בתנועה מעגלית, תחילה עם כיוון השעון ולאחר מכן נגד כיוון השעון.","בצעו את התנועה למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your hands on your hips.","Bend your knees slightly and lift your heels off the ground, balancing on the balls of your feet.","Keeping your knees bent, rotate your knees in a circular motion, first clockwise and then counterclockwise.","Perform the movement for the desired number of repetitions."],"mediaId":"X7jbxra"},{"id":"edb-1273","name":"שכיבת סמיכה","name_en":"clap push up","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["התחילו בעמדת פלאנק גבוה כשהידיים מעט רחבות יותר מרוחב הכתפיים.","הורידו את הגוף לכיוון הרצפה על ידי כיפוף המרפקים, תוך הפעלת שרירי הליבה.","דחפו דרך כפות הידיים בעוצמה כדי להדחיף את הגוף מהרצפה.","בזמן שאתם באוויר, מחאו כפיים לפני שאתם נוחתים בחזרה בעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a high plank position with your hands slightly wider than shoulder-width apart.","Lower your body towards the ground by bending your elbows, keeping your core engaged.","Push through your palms explosively to propel your body off the ground.","While in mid-air, clap your hands together before landing back in the starting position.","Repeat for the desired number of repetitions."],"mediaId":"wigSg76"},{"id":"edb-0258","name":"שכיבת סמיכה","name_en":"clock push-up","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders","core"],"steps":["התחילו בתנוחת פלאנק גבוה כשהידיים ישירות מתחת לכתפיים והגוף בקו ישר.","הורידו את הגוף לכיוון הרצפה על ידי כיפוף המרפקים, כשהם צמודים לגוף.","תוך כדי הירידה, סובבו את הגוף שמאלה ופשטו את היד השמאלית הצידה.","דחפו בחזרה למעלה לעמדת ההתחלה, תוך סיבוב הגוף חזרה למרכז.","חזרו על שכיבת הסמיכה, הפעם תוך סיבוב הגוף ימינה ופשיטת היד הימנית הצידה.","המשיכו להחליף צדדים עם כל חזרה."],"steps_en":["Start in a high plank position with your hands directly under your shoulders and your body in a straight line.","Lower your body towards the ground by bending your elbows, keeping them close to your sides.","As you lower, rotate your body to the left, extending your left arm straight out to the side.","Push back up to the starting position, while rotating your body to the center.","Repeat the push-up, this time rotating your body to the right and extending your right arm out to the side.","Continue alternating sides with each repetition."],"mediaId":"CMAxnsG"},{"id":"edb-1327","name":"מתח אחיזה תחתית אחיזה צרה","name_en":"close grip chin-up","muscle":"back","equipment":"body weight","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["אחזו במוט המתח כשכפות הידיים פונות אליכם והידיים ברוחב הכתפיים.","היתלו על המוט כשהידיים ישרות לגמרי וכפות הרגליים באוויר.","הפעילו את שרירי הגב ומשכו את הגוף כלפי מעלה לכיוון המוט, כשהמרפקים צמודים לגוף.","המשיכו למשוך עד שהסנטר מעל המוט.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הגוף בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Grab the pull-up bar with your palms facing towards you and your hands shoulder-width apart.","Hang from the bar with your arms fully extended and your feet off the ground.","Engage your back muscles and pull your body up towards the bar, keeping your elbows close to your body.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"VnfUNW7"},{"id":"edb-0259","name":"שכיבת סמיכה אחיזה צרה","name_en":"close-grip push-up","muscle":"triceps","equipment":"body weight","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["התחילו בעמדת פלאנק גבוה כשהידיים קרובות זו לזו, ישירות מתחת לכתפיים.","הפעילו את שרירי הליבה והורידו את הגוף לכיוון הרצפה, כשהמרפקים צמודים לגוף.","דחפו דרך כפות הידיים כדי ליישר את הידיים ולחזור לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a high plank position with your hands placed close together, directly under your shoulders.","Engage your core and lower your body towards the ground, keeping your elbows close to your sides.","Push through your palms to extend your arms and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"x6KpKpq"},{"id":"edb-2398","name":"שכיבת סמיכה אחיזה צרה","name_en":"close-grip push-up (on knees)","muscle":"triceps","equipment":"body weight","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["התחילו בעמידה על הידיים והברכיים, כשהידיים ברוחב הכתפיים והברכיים ברוחב האגן.","הורידו את פלג הגוף העליון לכיוון הרצפה על ידי כיפוף המרפקים, כשהם צמודים לגוף.","עצרו לרגע כשהחזה נמצא ממש מעל הרצפה.","דחפו דרך כפות הידיים כדי ליישר את הידיים ולחזור לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by getting on your hands and knees, with your hands shoulder-width apart and your knees hip-width apart.","Lower your upper body towards the ground by bending your elbows, keeping them close to your sides.","Pause for a moment when your chest is just above the ground.","Push through your palms to straighten your arms and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"v3vLFW0"},{"id":"edb-0260","name":"cocoons","name_en":"cocoons","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors","lower back"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו את הידיים מאחורי הראש כשהמרפקים פונים החוצה.","תוך הפעלת שרירי הבטן, הרימו לאט את פלג הגוף העליון מהרצפה, בכיפוף קדימה עד שהגו נמצא בזווית של 45 מעלות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"SLKj2pX"},{"id":"edb-1468","name":"פיתול","name_en":"crab twist toe touch","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","hip flexors"],"steps":["התחילו בישיבה על הרצפה כשהברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו את הידיים מאחוריכם, כשהאצבעות מכוונות לכיוון הרגליים, והרימו את האגן מהרצפה.","פשטו רגל אחת ישר קדימה תוך כדי הושטת היד הנגדית לכיוון בהונות הרגל.","חזרו לעמדת ההתחלה וחזרו על התרגיל בצד השני.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Start by sitting on the ground with your knees bent and feet flat on the floor.","Place your hands behind you, fingers pointing towards your feet, and lift your hips off the ground.","Extend one leg straight out in front of you while simultaneously reaching your opposite hand towards your toes.","Return to the starting position and repeat on the other side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"xgsGFVM"},{"id":"edb-0262","name":"כפיפת בטן","name_en":"cross body crunch","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו את הידיים מאחורי הראש כשהמרפקים פונים החוצה.","תוך הפעלת שרירי הבטן, הרימו את פלג הגוף העליון מהרצפה וסובבו כדי לקרב את המרפק הימני לברך השמאלית.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התנועה בצד השני, תוך קירוב המרפק השמאלי לברך הימנית.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, lift your upper body off the ground and twist to bring your right elbow towards your left knee.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat on the other side, bringing your left elbow towards your right knee.","Repeat for the desired number of repetitions."],"mediaId":"rbu5UUb"},{"id":"edb-0267","name":"כפיפת בטן מעל הראש","name_en":"crunch (hands overhead)","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","פשטו את הידיים ישר מעל הראש.","תוך הפעלת שרירי הבטן, הרימו את פלג הגוף העליון מהרצפה, כשאתם מתכופפים קדימה לכיוון הברכיים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your knees bent and feet flat on the ground.","Extend your arms straight above your head.","Engaging your abs, lift your upper body off the ground, curling forward towards your knees.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"kjJ3VoQ"},{"id":"edb-0271","name":"כפיפת בטן עם כדור פיזיו","name_en":"crunch (on stability ball)","muscle":"core","equipment":"stability ball","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שבו על כדור הפיזיו כשכפות הרגליים שטוחות על הרצפה והברכיים כפופות בזווית של 90 מעלות.","שכבו לאחור על הכדור עד שהגב התחתון נתמך ופלג הגוף העליון מקביל לרצפה.","הניחו את הידיים מאחורי הראש או לרוחב החזה.","הפעילו את שרירי הבטן והרימו את פלג הגוף העליון לכיוון הברכיים, תוך כיפוף הגו קדימה.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Lie back on the ball until your lower back is supported and your upper body is parallel to the floor.","Place your hands behind your head or across your chest.","Engage your abs and lift your upper body towards your knees, curling your torso forward.","Pause for a moment at the top of the movement, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"MCUhf1F"},{"id":"edb-0272","name":"כפיפת בטן עם כדור פיזיו","name_en":"crunch (on stability ball, arms straight)","muscle":"core","equipment":"stability ball","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שבו על כדור הפיזיו כשכפות הרגליים שטוחות על הרצפה והברכיים כפופות בזווית של 90 מעלות.","שכבו לאחור על הכדור עד שהגב התחתון נתמך ופלג הגוף העליון מקביל לרצפה.","הניחו את הידיים מאחורי הראש או שלבו אותן על החזה.","הפעילו את שרירי הבטן והרימו את פלג הגוף העליון מהכדור, תוך קירוב הכתפיים לכיוון האגן.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Lie back on the ball until your lower back is supported and your upper body is parallel to the floor.","Place your hands behind your head or cross them over your chest.","Engage your abs and lift your upper body off the ball, curling your shoulders towards your hips.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Sn8wxAI"},{"id":"edb-0274","name":"כפיפת בטן","name_en":"crunch floor","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו את הידיים מאחורי הראש כשהמרפקים פונים החוצה.","הפעילו את שרירי הבטן והרימו את הכתפיים מהרצפה, תוך כיפוף קדימה לכיוון הברכיים.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את הכתפיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engage your abs and lift your shoulders off the ground, curling forward towards your knees.","Pause for a moment at the top, then slowly lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"TFqbd8t"},{"id":"edb-3016","name":"כפיפת מרפק","name_en":"curl-up","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו את הידיים מאחורי הראש כשהמרפקים פונים החוצה.","תוך הפעלת שרירי הבטן, הרימו לאט את פלג הגוף העליון מהרצפה, בכיפוף קדימה עד שהגו נמצא בזווית של 45 מעלות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"g2oKspu"},{"id":"edb-3769","name":"סקוואט","name_en":"curtsey squat","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים.","צעדו באלכסון לאחור עם הרגל הימנית, כך שהיא חוצה מאחורי הרגל השמאלית.","כופפו את שתי הברכיים כאילו אתם מבצעים קידה, תוך הורדת הגוף לכיוון הרצפה.","שמרו על הגו זקוף ומשקל הגוף על הרגל הקדמית.","דחפו דרך הרגל הקדמית כדי לחזור לעמדת ההתחלה.","חזרו על התנועה בצד השני, תוך צעידה באלכסון לאחור עם הרגל השמאלית."],"steps_en":["Stand with your feet shoulder-width apart.","Take a step diagonally behind and across your body with your right foot, crossing it behind your left leg.","Bend both knees as if you were curtsying, lowering your body towards the ground.","Keep your torso upright and your weight on your front foot.","Push through your front foot to return to the starting position.","Repeat on the other side, stepping diagonally behind and across your body with your left foot."],"mediaId":"gUjqdei"},{"id":"edb-2331","name":"cycle cross trainer","name_en":"cycle cross trainer","muscle":"core","equipment":"leverage machine","target":"cardiovascular system","bodyPart":"cardio","secondaryMuscles":["quadriceps","hamstrings","glutes"],"steps":["התאימו את גובה המושב והתמקמו על אופני הקרוס טריינר.","הניחו את כפות הרגליים על הדוושות ואחזו בכידון.","התחילו לדווש בתנועה חלקה ומבוקרת.","שמרו על קצב יציב והגבירו את ההתנגדות אם תרצו.","המשיכו לדווש למשך הזמן הרצוי של אימון הקרדיו."],"steps_en":["Adjust the seat height and position yourself on the cycle cross trainer.","Place your feet on the pedals and grip the handlebars.","Start pedaling in a smooth and controlled motion.","Maintain a steady pace and increase the resistance if desired.","Continue pedaling for the desired duration of your cardio workout."],"mediaId":"XSCHmiI"},{"id":"edb-0276","name":"dead bug","name_en":"dead bug","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors","lower back"],"steps":["שכבו על הגב כשהידיים פשוטות לכיוון התקרה.","כופפו את הברכיים והרימו את הרגליים מהרצפה, כך שתיווצר זווית של 90 מעלות באגן ובברכיים.","הפעילו את שרירי הליבה והגב התחתון כדי ללחוץ את הגב התחתון אל הרצפה.","הורידו לאט את היד הימנית והרגל השמאלית לכיוון הרצפה, כשהן ישרות ומרחפות ממש מעל הרצפה.","עצרו לרגע, ולאחר מכן חזרו למצב ההתחלתי.","חזרו על התנועה עם היד השמאלית והרגל הימנית.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your arms extended towards the ceiling.","Bend your knees and lift your legs off the ground, creating a 90-degree angle at your hips and knees.","Engage your core and lower back to press your lower back into the ground.","Slowly lower your right arm and left leg towards the ground, keeping them straight and hovering just above the floor.","Pause for a moment, then return to the starting position.","Repeat the movement with your left arm and right leg.","Continue alternating sides for the desired number of repetitions."],"mediaId":"iny3m5y"},{"id":"edb-0277","name":"כפיפת בטן בשיפוע שלילי","name_en":"decline crunch","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שכבו על ספסל בשיפוע שלילי כשכפות הרגליים מקובעות והברכיים כפופות בזווית של 90 מעלות.","הניחו את הידיים מאחורי הראש או לרוחב החזה.","הפעילו את שרירי הבטן והרימו את פלג הגוף העליון לכיוון הברכיים, תוך כיפוף הגו.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie on a decline bench with your feet secured and your knees bent at a 90-degree angle.","Place your hands behind your head or across your chest.","Engage your abs and lift your upper body towards your knees, curling your torso.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"9Ap7miY"},{"id":"edb-0279","name":"שכיבת סמיכה בשיפוע שלילי","name_en":"decline push-up","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["הניחו את הידיים על הרצפה מעט רחב יותר מרוחב הכתפיים, כשכפות הרגליים מוגבהות על משטח יציב.","שמרו על הגוף בקו ישר מהראש ועד הרגליים, תוך הפעלת שרירי הליבה.","הורידו את החזה לכיוון הרצפה על ידי כיפוף המרפקים, כשהם צמודים לגוף.","דחפו דרך כפות הידיים כדי ליישר את הידיים ולחזור לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Place your hands on the ground slightly wider than shoulder-width apart, with your feet elevated on a stable surface.","Keep your body in a straight line from head to toe, engaging your core muscles.","Lower your chest towards the ground by bending your elbows, keeping them close to your body.","Push through your palms to extend your arms and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"i5cEhka"},{"id":"edb-0282","name":"כפיפת בטן מלאה בשיפוע שלילי","name_en":"decline sit-up","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors","lower back"],"steps":["שכבו על ספסל בשיפוע שלילי כשכפות הרגליים מקובעות והברכיים כפופות.","הניחו את הידיים מאחורי הראש או לרוחב החזה.","הפעילו את שרירי הבטן והרימו את פלג הגוף העליון מהספסל, תוך כיפוף קדימה לכיוון הברכיים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie on a decline bench with your feet secured and your knees bent.","Place your hands behind your head or across your chest.","Engage your abs and lift your upper body off the bench, curling forward towards your knees.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"QLL2gdc"},{"id":"edb-1274","name":"שכיבת סמיכה","name_en":"deep push up","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["התחילו בעמדת פלאנק גבוה כשהידיים מעט רחבות יותר מרוחב הכתפיים והגוף בקו ישר.","הורידו את החזה לכיוון הרצפה על ידי כיפוף המרפקים, כשהם צמודים לגוף.","דחפו דרך כפות הידיים כדי ליישר את הידיים ולחזור לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a high plank position with your hands slightly wider than shoulder-width apart and your body in a straight line.","Lower your chest towards the ground by bending your elbows, keeping them close to your body.","Push through your palms to extend your arms and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"vptOQ4N"},{"id":"edb-0283","name":"שכיבת סמיכה","name_en":"diamond push-up","muscle":"triceps","equipment":"body weight","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["התחילו בעמדת פלאנק גבוה כשהידיים קרובות זו לזו, ויוצרות צורת יהלום עם האגודלים והאצבעות המורות.","שמרו על הגוף בקו ישר מהראש ועד הרגליים, תוך הפעלת שרירי הליבה והישבן.","הורידו את החזה לכיוון צורת היהלום שיוצרות הידיים, כשהמרפקים צמודים לגוף.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו את עצמכם בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a high plank position with your hands close together, forming a diamond shape with your thumbs and index fingers.","Keep your body in a straight line from head to toe, engaging your core and glutes.","Lower your chest towards the diamond shape formed by your hands, keeping your elbows close to your body.","Pause for a moment at the bottom, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"soIB2rj"},{"id":"edb-0284","name":"הרמת עקבים","name_en":"donkey calf raise","muscle":"legs","equipment":"body weight","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings","glutes"],"steps":["עמדו כשקצות כפות הרגליים על משטח מוגבה, כגון מדרגה או בלוק.","הניחו את הידיים על משטח יציב, כגון קיר או מעקה, לשם שיווי משקל.","הרימו את העקבים כמה שיותר גבוה, תוך העברת משקל הגוף לכריות כפות הרגליים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקבים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your toes on an elevated surface, such as a step or block.","Place your hands on a stable support, such as a wall or railing, for balance.","Raise your heels as high as possible, lifting your body weight onto the balls of your feet.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"u5ESqzH"},{"id":"edb-1275","name":"שכיבת סמיכה","name_en":"drop push up","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["התחילו בעמדת פלאנק גבוה כשהידיים מעט רחבות יותר מרוחב הכתפיים.","הורידו את החזה לכיוון הרצפה, כשהמרפקים צמודים לגוף.","כשהחזה ממש מעל הרצפה, הורידו במהירות את הברכיים אל הרצפה.","דחפו את עצמכם בחזרה לעמדת ההתחלה על ידי יישור הידיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a high plank position with your hands slightly wider than shoulder-width apart.","Lower your chest towards the ground, keeping your elbows close to your body.","Once your chest is just above the ground, quickly drop your knees to the ground.","Push yourself back up to the starting position by extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"Q497lAE"},{"id":"edb-0285","name":"כפיפת מרפק לסירוגין עם משקולות","name_en":"dumbbell alternate biceps curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף כשבכל יד משקולת, כפות הידיים פונות קדימה והידיים ישרות לגמרי.","תוך שמירה על הזרוע העליונה ללא תזוזה, נשפו החוצה וכופפו את המשקולות תוך כיווץ שרירי הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התנועה למספר החזרות הרצוי, תוך החלפת ידיים."],"steps_en":["Stand up straight with a dumbbell in each hand, palms facing forward and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions, alternating arms."],"mediaId":"BU15nH4"},{"id":"edb-2403","name":"כפיפת מרפק לסירוגין עם משקולות","name_en":"dumbbell alternate biceps curl (with arm blaster)","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף עם הרגליים ברוחב הכתפיים ואחזו משקולת בכל יד, כשכפות הידיים פונות קדימה.","הניחו את תומך הזרועות (ארם בלאסטר) על הזרועות העליונות, וודאו שהוא מהודק היטב.","כשהזרועות העליונות נייחות, נשפו החוצה וכופפו משקולת אחת כלפי הכתף תוך כיווץ הביצפס.","המשיכו להרים את המשקולת עד שהביצפס מכווץ לגמרי והמשקולת בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והורידו לאט את המשקולת בחזרה לעמדת ההתחלה.","חזרו על התנועה עם היד השנייה.","המשיכו להחליף ידיים למספר החזרות הרצוי."],"steps_en":["Stand up straight with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward.","Place the arm blaster on your upper arms, ensuring a secure fit.","Keeping your upper arms stationary, exhale and curl one dumbbell up towards your shoulder while contracting your biceps.","Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat the movement with the opposite arm.","Continue alternating arms for the desired number of repetitions."],"mediaId":"CfKsRbG"},{"id":"edb-1646","name":"כפיפת מרפק בכיסא הטפה לסירוגין עם משקולות","name_en":"dumbbell alternate hammer preacher curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל סקוט כשבכל יד משקולת, כפות הידיים פונות לגוף והידיים ישרות לגמרי.","שמרו על הזרוע העליונה ללא תזוזה ונשפו החוצה תוך כדי כיפוף המשקולות וכיווץ שרירי הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התנועה למספר החזרות המומלץ."],"steps_en":["Sit on a preacher bench with a dumbbell in each hand, palms facing your torso and arms fully extended.","Keep your upper arms stationary and exhale as you curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the recommended amount of repetitions."],"mediaId":"fy7Tgy4"},{"id":"edb-1647","name":"כפיפת מרפק בכיסא הטפה לסירוגין עם משקולות","name_en":"dumbbell alternate preacher curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל סקוט כשבכל יד משקולת, כפות הידיים פונות מעלה.","הניחו את הזרועות העליונות על משטח ספסל הסקוט, כך שהידיים יוכלו להתיישר לגמרי.","כשהזרועות העליונות נייחות, נשפו החוצה וכופפו את המשקולת ביד הימנית תוך כיווץ הביצפס.","המשיכו לכופף את המשקולת עד שהביצפס מכווץ לגמרי והמשקולת בגובה הכתפיים.","עצרו לרגע, לאחר מכן שאפו אוויר והורידו לאט את המשקולת בחזרה לעמדת ההתחלה.","חזרו על התנועה עם היד השמאלית.","המשיכו להחליף ידיים למספר החזרות הרצוי."],"steps_en":["Sit on a preacher bench with a dumbbell in each hand, palms facing up.","Rest your upper arms on the pad of the preacher bench, allowing your arms to fully extend.","Keeping your upper arms stationary, exhale and curl the dumbbell in your right hand as you contract your biceps.","Continue to curl the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Pause for a moment, then inhale and slowly lower the dumbbell back to the starting position.","Repeat the movement with your left arm.","Continue alternating arms for the desired number of repetitions."],"mediaId":"NlfIbzq"},{"id":"edb-1648","name":"כפיפת פטיש בישיבה לסירוגין עם משקולות","name_en":"dumbbell alternate seated hammer curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל כשבכל יד משקולת, כפות הידיים פונות לגוף והידיים פשוטות מטה.","שמרו על גב ישר והמרפקים קרובים לגוף.","נשפו החוצה וכופפו את המשקולת ביד הימנית לכיוון הכתף, כשהזרוע העליונה נייחת.","המשיכו להרים את המשקולת עד שהביצפס מכווץ לגמרי והמשקולת בגובה הכתפיים.","עצרו לרגע קצר, לאחר מכן שאפו אוויר והורידו לאט את המשקולת בחזרה לעמדת ההתחלה.","חזרו על התנועה עם היד השמאלית.","המשיכו להחליף ידיים למספר החזרות הרצוי."],"steps_en":["Sit on a bench with a dumbbell in each hand, palms facing your torso and arms extended down.","Keep your back straight and your elbows close to your torso.","Exhale and curl the dumbbell in your right hand towards your shoulder, keeping your upper arm stationary.","Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Pause for a brief moment, then inhale and slowly lower the dumbbell back to the starting position.","Repeat the movement with your left arm.","Continue alternating arms for the desired number of repetitions."],"mediaId":"6em2Dxj"},{"id":"edb-0286","name":"לחיצה לסירוגין צדי עם משקולות","name_en":"dumbbell alternate side press","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשבכל יד משקולת בגובה הכתפיים.","דחפו משקולת אחת מעל הראש כשהמשקולת השנייה נשארת בגובה הכתפיים.","הורידו את המשקולת שנדחפה בחזרה לגובה הכתפיים תוך כדי דחיפת המשקולת השנייה מעל הראש.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder height.","Press one dumbbell overhead while keeping the other dumbbell at shoulder height.","Lower the pressed dumbbell back to shoulder height while pressing the other dumbbell overhead.","Continue alternating sides for the desired number of repetitions."],"mediaId":"izMnLqz"},{"id":"edb-1649","name":"כפיפת מרפק לסירוגין עם משקולות","name_en":"dumbbell alternating bicep curl with leg raised on exercise ball","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms","shoulders"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו משקולת בכל יד, כשכפות הידיים פונות קדימה.","הניחו כדור התעמלות מאחוריכם והציבו רגל אחת עליו, תוך שמירה על שיווי משקל.","כשהידיים ישרות לגמרי והמרפקים צמודים לגוף, כופפו משקולת אחת לכיוון הכתף כשהזרוע העליונה נייחת.","הורידו את המשקולת בחזרה לעמדת ההתחלה וחזרו על התנועה עם היד השנייה.","המשיכו להחליף ידיים למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward.","Place an exercise ball behind you and position one foot on top of it, keeping your balance.","With your arms fully extended and elbows close to your sides, curl one dumbbell towards your shoulder while keeping your upper arm stationary.","Lower the dumbbell back down to the starting position and repeat with the other arm.","Continue alternating arms for the desired number of repetitions."],"mediaId":"Zwiw7XR"},{"id":"edb-1650","name":"כפיפת מרפק בישיבה לסירוגין עם משקולות","name_en":"dumbbell alternating seated bicep curl on exercise ball","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על כדור התעמלות כשכפות הרגליים שטוחות על הרצפה והגב ישר.","אחזו משקולת בכל יד כשכפות הידיים פונות קדימה והידיים ישרות לגמרי.","כשהזרועות העליונות נייחות, נשפו החוצה וכופפו משקולת אחת תוך סיבוב האמה עד שכף היד פונה לכתף.","שאפו אוויר והורידו לאט את המשקולת בחזרה לעמדת ההתחלה.","חזרו על תנועת הכיפוף עם היד השנייה.","המשיכו להחליף ידיים למספר החזרות הרצוי."],"steps_en":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in each hand with your palms facing forward and your arms fully extended.","Keeping your upper arms stationary, exhale and curl one dumbbell while rotating your forearm until your palm is facing your shoulder.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat the curl with the other arm.","Continue alternating curls for the desired number of repetitions."],"mediaId":"J74XlNf"},{"id":"edb-2137","name":"לחיצה עם משקולות","name_en":"dumbbell arnold press","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper chest"],"steps":["שבו על ספסל עם משענת גב ואחזו משקולת בכל יד בגובה הכתפיים, כשכפות הידיים פונות לגוף והמרפקים כפופים.","דחפו את המשקולות כלפי מעלה עד שהידיים ישרות לגמרי וכפות הידיים פונות קדימה.","סובבו את פרקי הידיים תוך כדי ההרמה, כך שכפות הידיים יפנו קדימה בשיא התנועה.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with back support and hold a dumbbell in each hand at shoulder level, palms facing your body and elbows bent.","Press the dumbbells upward until your arms are fully extended and your palms are facing forward.","Rotate your wrists as you lift, so that your palms are facing forward at the top of the movement.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Xy4jlWA"},{"id":"edb-0287","name":"לחיצה עם משקולות","name_en":"dumbbell arnold press v. 2","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper chest"],"steps":["שבו על ספסל עם משענת גב ואחזו משקולת בכל יד בגובה הכתפיים, כשכפות הידיים פונות לגוף והמרפקים כפופים.","דחפו את המשקולות כלפי מעלה עד שהידיים ישרות לגמרי וכפות הידיים פונות קדימה.","סובבו את פרקי הידיים תוך כדי ההרמה, כך שכפות הידיים יסתיימו כשהן פונות קדימה בשיא התנועה.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with back support and hold a dumbbell in each hand at shoulder level, palms facing your body and elbows bent.","Press the dumbbells upward until your arms are fully extended and your palms are facing forward.","Rotate your wrists as you lift, so that your palms end up facing forward at the top of the movement.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"eOrFCnx"},{"id":"edb-0288","name":"פולאובר עם משקולות","name_en":"dumbbell around pullover","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","latissimus dorsi"],"steps":["שכבו על ספסל כשהראש בקצה אחד וכפות הרגליים יציבות על הרצפה.","אחזו משקולת בשתי הידיים ופשטו אותן ישר מעל החזה.","כשהידיים ישרות, הורידו לאט את המשקולת מאחורי הראש בתנועת קשת.","עצרו לרגע בתחתית התנועה, לאחר מכן הרימו את המשקולת בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your head at one end and your feet firmly on the ground.","Hold a dumbbell with both hands and extend your arms straight above your chest.","Keeping your arms straight, slowly lower the dumbbell behind your head in an arc motion.","Pause for a moment at the bottom, then raise the dumbbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"vi8EhoE"},{"id":"edb-0289","name":"לחיצת חזה עם משקולות","name_en":"dumbbell bench press","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["שכבו על ספסל כשכפות הרגליים שטוחות על הרצפה והגב צמוד לספסל.","אחזו משקולת בכל יד, כשכפות הידיים פונות קדימה והידיים פשוטות מעל החזה.","הורידו לאט את המשקולות לצדי החזה, כשהמרפקים בזווית של 90 מעלות.","עצרו לרגע, לאחר מכן דחפו את המשקולות בחזרה למעלה לעמדת ההתחלה, תוך פשיטת הידיים לגמרי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Hold a dumbbell in each hand, with your palms facing forward and your arms extended above your chest.","Lower the dumbbells slowly to the sides of your chest, keeping your elbows at a 90-degree angle.","Pause for a moment, then push the dumbbells back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"SpYC0Kp"},{"id":"edb-0290","name":"לחיצה בישיבה עם משקולות","name_en":"dumbbell bench seated press","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","chest"],"steps":["שבו על ספסל כשבכל יד משקולת המונחת על הירכיים.","הטו את הגוף לאחור והציבו את המשקולות לצדי החזה, כשכפות הידיים פונות קדימה.","דחפו את המשקולות כלפי מעלה עד שהידיים ישרות לגמרי.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with a dumbbell in each hand, resting on your thighs.","Lean back and position the dumbbells to the sides of your chest, palms facing forward.","Press the dumbbells upward until your arms are fully extended.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"3d7wHyd"},{"id":"edb-0291","name":"סקוואט עם משקולות","name_en":"dumbbell bench squat","muscle":"glutes","equipment":"dumbbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["הניחו משקולת על הרצפה מול ספסל.","עמדו כשגבכם לספסל, עם הרגליים ברוחב הכתפיים.","כופפו את הברכיים והאגן כדי להוריד את עצמכם לכיוון הספסל, כשהחזה מורם והגב ישר.","כשהישבן נוגע בספסל, דחפו דרך העקבים כדי לחזור לעמידה בעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Place a dumbbell on the ground in front of a bench.","Stand facing away from the bench with your feet shoulder-width apart.","Bend at the knees and hips to lower yourself down towards the bench, keeping your chest up and back straight.","Once your glutes touch the bench, push through your heels to stand back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"mnzcrIB"},{"id":"edb-0293","name":"חתירה בהטיה עם משקולות","name_en":"dumbbell bent over row","muscle":"back","equipment":"dumbbell","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, הברכיים כפופות מעט, ואחזו משקולת בכל יד כשכפות הידיים פונות לגוף.","התכופפו קדימה מהירכיים, תוך שמירה על גב ישר ושרירי ליבה פעילים.","הניחו לידיים לתלות ישר כלפי הרצפה, כשהמרפקים כפופים מעט.","משכו את המשקולות כלפי מעלה לכיוון החזה, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, knees slightly bent, and hold a dumbbell in each hand with your palms facing your body.","Bend forward at the hips, keeping your back straight and your core engaged.","Let your arms hang straight down towards the floor, with your elbows slightly bent.","Pull the dumbbells up towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"BJ0Hz5L"},{"id":"edb-1651","name":"כפיפת מרפק עם משקולות","name_en":"dumbbell bicep curl lunge with bowling motion","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms","shoulders"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשבכל יד משקולת וכפות הידיים פונות קדימה.","צעדו קדימה עם הרגל הימנית, כופפו את הברך הימנית והורידו את הגוף לעמדת לאנג'.","תוך כדי הלאנג' קדימה, כופפו את המשקולות כלפי הכתפיים, כשהמרפקים צמודים לגוף.","בתחתית הלאנג', סובבו את הגו ימינה, כאילו אתם מגלגלים כדור באולינג.","הפכו את התנועה, צעדו לאחור עם הרגל הימנית וחזרו לעמדת ההתחלה תוך הורדת המשקולות בחזרה.","חזרו על תנועת הלאנג' והכיפוף, הפעם תוך סיבוב הגו שמאלה.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing forward.","Take a step forward with your right foot, bending your right knee and lowering your body into a lunge position.","As you lunge forward, curl the dumbbells up towards your shoulders, keeping your elbows close to your body.","At the bottom of the lunge, rotate your torso to the right, as if you were bowling a ball.","Reverse the motion, stepping back with your right foot and returning to the starting position while lowering the dumbbells back down.","Repeat the lunge and curl motion, this time rotating your torso to the left.","Continue alternating sides for the desired number of repetitions."],"mediaId":"1VpF8db"},{"id":"edb-1652","name":"כפיפת מרפק עם משקולות","name_en":"dumbbell bicep curl on exercise ball with leg raised","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms","shoulders"],"steps":["שבו על כדור התעמלות כשכפות הרגליים שטוחות על הרצפה והגב ישר.","אחזו משקולת בכל יד כשכפות הידיים פונות קדימה והידיים ישרות לגמרי.","כופפו לאט את המשקולות לכיוון הכתפיים, כשהמרפקים צמודים לגוף.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","תוך כדי ביצוע כיפוף הביצפס, הרימו רגל אחת מהרצפה והחזיקו אותה באוויר למשך כל התרגיל.","חזרו על התנועה למספר החזרות הרצוי, ולאחר מכן החליפו רגליים וחזרו שוב."],"steps_en":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in each hand with your palms facing forward and your arms fully extended.","Slowly curl the dumbbells towards your shoulders, keeping your elbows close to your sides.","Pause for a moment at the top of the movement, then slowly lower the dumbbells back to the starting position.","While performing the bicep curl, raise one leg off the ground and hold it in the air for the duration of the exercise.","Repeat for the desired number of repetitions, then switch legs and repeat."],"mediaId":"2NImIAG"},{"id":"edb-1653","name":"כפיפת מרפק עם משקולות","name_en":"dumbbell bicep curl with stork stance","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו משקולת בכל יד, כשכפות הידיים פונות קדימה.","פשטו רגל אחת מאחוריכם, תוך שמירה על שיווי משקל על בהונות אותה רגל.","תוך שמירה על הזרוע העליונה ללא תזוזה, נשפו החוצה וכופפו את המשקולות תוך כיווץ שרירי הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התנועה למספר החזרות הרצוי, ולאחר מכן החליפו רגליים וחזרו שוב."],"steps_en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward.","Extend one leg behind you, balancing on the toes of that foot.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions, then switch legs and repeat."],"mediaId":"uSkDMYl"},{"id":"edb-0294","name":"כפיפת מרפק במשקולות","name_en":"dumbbell biceps curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף כשבכל יד משקולת, כפות הידיים פונות קדימה והידיים ישרות לגמרי.","תוך שמירה על הזרוע העליונה ללא תזוזה, נשפו החוצה וכופפו את המשקולות תוך כיווץ שרירי הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand up straight with a dumbbell in each hand, palms facing forward and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"NbVPDMW"},{"id":"edb-2401","name":"כפיפת מרפק עם משקולות","name_en":"dumbbell biceps curl (with arm blaster)","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף כשבכל יד משקולת, כפות הידיים פונות קדימה.","שמרו על המרפקים קרובים לגוף והזרוע העליונה ללא תנועה.","נשפו החוצה וכופפו את המשקולות תוך כיווץ הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand up straight with a dumbbell in each hand, palms facing forward.","Keep your elbows close to your torso and your upper arms stationary.","Exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"nlJsbkW"},{"id":"edb-1654","name":"כפיפת מרפק הפוך עם משקולות","name_en":"dumbbell biceps curl reverse","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף כשבכל יד משקולת, כפות הידיים פונות מטה והידיים ישרות לגמרי.","תוך שמירה על הזרוע העליונה ללא תזוזה, נשפו החוצה וכופפו את המשקולות תוך כיווץ שרירי הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand up straight with a dumbbell in each hand, palms facing down and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"nFc4FyV"},{"id":"edb-1655","name":"כפיפת מרפק עם משקולות","name_en":"dumbbell biceps curl squat","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשבכל יד משקולת וכפות הידיים פונות קדימה.","כששמור על גב ישר והמרפקים צמודים לגוף, נשפו החוצה וכופפו את המשקולות כלפי הכתפיים.","עצרו לרגע בשיא התנועה, תוך כיווץ שרירי הביצפס.","שאפו אוויר והורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing forward.","Keeping your back straight and your elbows close to your sides, exhale and curl the dumbbells up towards your shoulders.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"niXESDw"},{"id":"edb-1656","name":"כפיפת מרפק על בוסו","name_en":"dumbbell biceps curl v sit on bosu ball","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms","shoulders"],"steps":["שבו על כדור בוסו כשכפות הרגליים שטוחות על הרצפה והברכיים כפופות בזווית של 90 מעלות.","אחזו משקולת בכל יד כשכפות הידיים פונות קדימה והידיים פשוטות לגמרי לצדי הגוף.","תוך שמירה על הזרוע העליונה ללא תזוזה, נשפו החוצה וכופפו את המשקולות תוך כיווץ שרירי הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bosu ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Hold a dumbbell in each hand with your palms facing forward and your arms fully extended down by your sides.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"H1XAdpk"},{"id":"edb-1201","name":"dumbbell burpee","name_en":"dumbbell burpee","muscle":"core","equipment":"dumbbell","target":"cardiovascular system","bodyPart":"cardio","secondaryMuscles":["quadriceps","hamstrings","calves","shoulders","triceps","core"],"steps":["התחילו בעמידה כשהרגליים ברוחב הכתפיים ובכל יד משקולת.","הורידו את הגוף לעמדת סקוואט, תוך הנחת המשקולות על הרצפה לפניכם.","בעטו את הרגליים לאחור לעמדת שכיבת סמיכה, כשהגוף בקו ישר.","בצעו שכיבת סמיכה, כפפו את המרפקים והורידו את החזה לכיוון הרצפה.","קפצו עם הרגליים לכיוון הידיים, ונחתו בעמדת סקוואט.","קומו בעוצמה, תוך הרמת המשקולות מהרצפה והבאתן לכתפיים.","דחפו את המשקולות מעל הראש, תוך פשיטת הידיים לגמרי.","הורידו את המשקולות בחזרה לכתפיים וחזרו על הרצף כולו למספר החזרות הרצוי."],"steps_en":["Start in a standing position with your feet shoulder-width apart and a dumbbell in each hand.","Lower your body into a squat position, placing the dumbbells on the ground in front of you.","Kick your feet back into a push-up position, keeping your body in a straight line.","Perform a push-up, bending your elbows and lowering your chest towards the ground.","Jump your feet back towards your hands, landing in a squat position.","Stand up explosively, lifting the dumbbells off the ground and bringing them to your shoulders.","Press the dumbbells overhead, fully extending your arms.","Lower the dumbbells back to your shoulders and repeat the entire sequence for the desired number of repetitions."],"mediaId":"0JtKWum"},{"id":"edb-0295","name":"קלין עם משקולות","name_en":"dumbbell clean","muscle":"glutes","equipment":"dumbbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשבכל יד משקולת באחיזה עליונה.","כופפו את הברכיים והורידו את האגן לתנוחת סקוואט, תוך שמירה על גב ישר וחזה זקוף.","פשטו בעוצמה את האגן והברכיים, תוך דחיפה דרך העקבים כדי לקפוץ מהרצפה.","תוך כדי הקפיצה, משכו את הכתפיים כלפי מעלה ומשכו את המשקולות לכיוון הכתפיים, כשהן צמודות לגוף.","תפסו את המשקולות בגובה הכתפיים, כשהמרפקים מכוונים קדימה וכפות הידיים פונות מעלה.","הורידו את המשקולות בחזרה לעמדת ההתחלה על ידי ביצוע התנועה ההפוכה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.","Bend your knees and lower your hips into a squat position, keeping your back straight and chest up.","Explosively extend your hips and knees, driving through your heels to jump off the ground.","As you jump, shrug your shoulders and pull the dumbbells up towards your shoulders, keeping them close to your body.","Catch the dumbbells at shoulder height, with your elbows pointing forward and your palms facing up.","Lower the dumbbells back down to the starting position by reversing the movement.","Repeat for the desired number of repetitions."],"mediaId":"7Hg55JG"},{"id":"edb-1731","name":"לחיצה אחיזה צרה עם משקולות","name_en":"dumbbell close grip press","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["שבו על ספסל שטוח כשבכל יד משקולת המונחת על הירכיים.","בעזרת הירכיים להרמת המשקולות, הרימו אותן אחת בכל פעם כך שתוכלו להחזיק אותן לפניכם ברוחב הכתפיים.","כשהמשקולות ברוחב הכתפיים, סובבו את פרקי הידיים קדימה כך שכפות הידיים פונות הרחק מכם. זו תהיה עמדת ההתחלה שלכם.","תוך כדי שאיפת אוויר, הורידו לאט את המשקולות הצידה עד שהן בערך בגובה החזה.","תוך כדי נשיפת אוויר, השתמשו בטריצפס כדי להרים את המשקולות בחזרה לעמדת ההתחלה. הקפידו להשתמש רק בטריצפס ולא באמות או בביצפס כדי לסייע בהרמת המשקולות.","לאחר עצירה של שנייה בעמדת הכיווץ, חזרו על התנועה למספר החזרות הנקוב."],"steps_en":["Sit on a flat bench with a dumbbell in each hand, resting on your thighs.","Using your thighs to help raise the dumbbells, lift the dumbbells one at a time so that you can hold them in front of you at shoulder width.","Once at shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. This will be your starting position.","As you breathe in, slowly lower the dumbbells to your side until they are about level with your chest.","As you exhale, use your triceps to lift the dumbbells back to the starting position. Make sure to use only your triceps and do not use your forearms or biceps to help lift the dumbbells.","After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions."],"mediaId":"7jGOBF3"},{"id":"edb-0296","name":"לחיצה אחיזה צרה עם משקולות","name_en":"dumbbell close-grip press","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["שבו על ספסל שטוח כשבכל יד משקולת המונחת על הירכיים.","בעזרת הירכיים להרמת המשקולות, הרימו אותן אחת בכל פעם כך שתוכלו להחזיק אותן לפניכם ברוחב הכתפיים.","כשהמשקולות ברוחב הכתפיים, סובבו את פרקי הידיים קדימה כך שכפות הידיים פונות הרחק מכם. זו תהיה עמדת ההתחלה שלכם.","תוך כדי שאיפת אוויר, הורידו לאט את המשקולות הצידה עד שהן בערך בגובה החזה.","תוך כדי נשיפת אוויר, השתמשו בטריצפס כדי להרים את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a flat bench with a dumbbell in each hand, resting on your thighs.","Using your thighs to help raise the dumbbells, lift the dumbbells one at a time so that you can hold them in front of you at shoulder width.","Once at shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. This will be your starting position.","As you breathe in, slowly lower the dumbbells to your side until they are about level with your chest.","As you exhale, use your triceps to lift the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"RxayqAZ"},{"id":"edb-0297","name":"כפיפת מרפק עם משקולות","name_en":"dumbbell concentration curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל כשהרגליים פשוקות ומשקולת ביד אחת, כשהמרפק נשען על החלק הפנימי של הירך.","פשטו את היד לגמרי ואחזו את המשקולת באחיזה תחתונה.","כשהזרוע העליונה נייחת, נשפו החוצה וכופפו את המשקולת כלפי הכתף תוך כיווץ הביצפס.","המשיכו להרים את המשקולת עד שהביצפס מכווץ לגמרי והמשקולת בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והורידו לאט את המשקולת בחזרה לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Sit on a bench with your legs spread apart and a dumbbell in one hand, resting your elbow on the inside of your thigh.","Fully extend your arm and hold the dumbbell with an underhand grip.","Keeping your upper arm stationary, exhale and curl the weight up towards your shoulder while contracting your biceps.","Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"gvsWLQw"},{"id":"edb-3635","name":"לאנג׳ עם משקולות","name_en":"dumbbell contralateral forward lunge","muscle":"glutes","equipment":"dumbbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשבכל יד משקולת.","צעדו קדימה עם הרגל הימנית, כשהגב ישר ושרירי הליבה מופעלים.","הורידו את הגוף על ידי כיפוף שתי הברכיים עד שהירך הימנית מקבילה לרצפה.","דחפו דרך העקב הימני כדי לחזור למצב ההתחלתי.","חזרו על התנועה עם הרגל השמאלית.","החליפו רגליים למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand.","Take a step forward with your right foot, keeping your back straight and core engaged.","Lower your body by bending both knees until your right thigh is parallel to the ground.","Push through your right heel to return to the starting position.","Repeat with your left leg.","Alternate legs for the desired number of repetitions."],"mediaId":"ecl28tP"},{"id":"edb-0298","name":"כפיפת פטיש עם משקולות","name_en":"dumbbell cross body hammer curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף כשבכל יד משקולת, כפות הידיים פונות לגוף.","שמרו על המרפקים קרובים לגוף והזרוע העליונה ללא תנועה.","נשפו החוצה וכופפו את המשקולות תוך כיווץ הביצפס, כשאתם מקרבים אותן לרוחב הגוף לכיוון הכתף הנגדית.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand up straight with a dumbbell in each hand, palms facing your body.","Keep your elbows close to your torso and your upper arms stationary.","Exhale and curl the weights while contracting your biceps, bringing the dumbbells across your body towards your opposite shoulder.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Qyk5J3p"},{"id":"edb-1657","name":"כפיפת פטיש עם משקולות","name_en":"dumbbell cross body hammer curl v. 2","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף כשבכל יד משקולת, כפות הידיים פונות לגוף.","שמרו על המרפקים קרובים לגוף והזרוע העליונה ללא תנועה.","נשפו החוצה וכופפו את המשקולות תוך כיווץ הביצפס, תוך קירובן ככל האפשר לכתף הנגדית.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand up straight with a dumbbell in each hand, palms facing your body.","Keep your elbows close to your torso and your upper arms stationary.","Exhale and curl the weights while contracting your biceps, bringing the dumbbells as close to your opposite shoulder as possible.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"HDYiZcY"},{"id":"edb-0299","name":"לחיצה עם משקולות","name_en":"dumbbell cuban press","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשבכל יד משקולת בגובה הכתפיים וכפות הידיים פונות מטה.","כששרירי הליבה מופעלים והמרפקים כפופים מעט, דחפו את המשקולות למעלה ומעל הראש עד שהידיים ישרות לגמרי.","סובבו את פרקי הידיים כך שכפות הידיים פונות קדימה.","הורידו לאט את המשקולות בחזרה לעמדת ההתחלה, תוך סיבוב פרקי הידיים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder height with your palms facing down.","Keeping your core engaged and your elbows slightly bent, press the dumbbells up and overhead until your arms are fully extended.","Rotate your wrists so that your palms are facing forward.","Slowly lower the dumbbells back to the starting position, rotating your wrists back to the starting position as you do so.","Repeat for the desired number of repetitions."],"mediaId":"QfAKy1G"},{"id":"edb-2136","name":"לחיצה עם משקולות","name_en":"dumbbell cuban press v. 2","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשבכל יד משקולת בגובה הכתפיים וכפות הידיים פונות מטה.","כששרירי הליבה מופעלים והגב ישר, דחפו את המשקולות ישר מעלה מעל הראש עד שהידיים ישרות לגמרי.","סובבו את פרקי הידיים כך שכפות הידיים פונות קדימה.","הורידו את המשקולות בחזרה לגובה הכתפיים, תוך סיבוב פרקי הידיים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder height with your palms facing down.","Keeping your core engaged and your back straight, press the dumbbells straight up overhead until your arms are fully extended.","Rotate your wrists so that your palms are facing forward.","Lower the dumbbells back down to shoulder height, rotating your wrists back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"BqgCRif"},{"id":"edb-0300","name":"דדליפט עם משקולות","name_en":"dumbbell deadlift","muscle":"glutes","equipment":"dumbbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","lower back"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים, אצבעות הרגליים פונות קדימה.","אחזו משקולת בכל יד, כשכפות הידיים פונות לגוף והידיים פשוטות כלפי מטה.","כופפו את האגן והברכיים, תוך הורדת המשקולות לכיוון הרצפה כשהגב נשאר ישר.","דחפו דרך העקבים ופשטו את האגן והברכיים, תוך הרמת המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, toes pointing forward.","Hold a dumbbell in each hand, palms facing your body, arms extended downwards.","Bend at your hips and knees, lowering the dumbbells towards the ground while keeping your back straight.","Push through your heels and extend your hips and knees, lifting the dumbbells back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"nUwVh7b"},{"id":"edb-0301","name":"לחיצת חזה בשיפוע שלילי עם משקולות","name_en":"dumbbell decline bench press","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["שכבו על ספסל בשיפוע שלילי כשכפות הרגליים מקובעות והראש נמוך מהאגן.","אחזו משקולת בכל יד ופשטו את הידיים ישר מעל החזה, כשכפות הידיים פונות קדימה.","הורידו לאט את המשקולות לצדי החזה, כשהמרפקים בזווית של 90 מעלות.","דחפו את המשקולות בחזרה למעלה לעמדת ההתחלה, תוך פשיטת הידיים לגמרי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie down on a decline bench with your feet secured and your head lower than your hips.","Hold a dumbbell in each hand and extend your arms straight up above your chest, palms facing forward.","Lower the dumbbells slowly to the sides of your chest, keeping your elbows at a 90-degree angle.","Push the dumbbells back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"DwhEmmE"},{"id":"edb-0302","name":"פרפר בשיפוע שלילי עם משקולות","name_en":"dumbbell decline fly","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders"],"steps":["שכבו על ספסל בשיפוע יורד עם הרגליים מקובעות והראש נמוך יותר מהאגן.","אחזו משקולת בכל יד כשכפות הידיים פונות זו לזו והידיים פשוטות מעל החזה.","הורידו את המשקולות הצידה בתנועת קשת רחבה עד שתרגישו מתיחה בחזה.","עצרו לרגע, לאחר מכן כווצו את שרירי החזה כדי להחזיר את המשקולות לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie on a decline bench with your feet secured and your head lower than your hips.","Hold a dumbbell in each hand with your palms facing each other and your arms extended above your chest.","Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest.","Pause for a moment, then squeeze your chest muscles to bring the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"xXm4nYq"},{"id":"edb-0303","name":"לחיצה בשיפוע שלילי עם משקולות","name_en":"dumbbell decline hammer press","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["שכבו על ספסל בשיפוע יורד עם הרגליים מקובעות והראש נמוך יותר מהאגן.","אחזו משקולת בכל יד כשכפות הידיים פונות זו לזו והידיים פשוטות מעל החזה.","הורידו את המשקולות לצדי החזה, כשהמרפקים כפופים מעט.","דחפו את המשקולות בחזרה למעלה לעמדת ההתחלה, תוך פשיטת הידיים לגמרי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie on a decline bench with your feet secured and your head lower than your hips.","Hold a dumbbell in each hand with your palms facing each other and your arms extended above your chest.","Lower the dumbbells to the sides of your chest, keeping your elbows slightly bent.","Press the dumbbells back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"1qrWgZ2"},{"id":"edb-1276","name":"פרפר ביד אחת בשיפוע שלילי עם משקולות","name_en":"dumbbell decline one arm fly","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders"],"steps":["שכבו על ספסל בשיפוע שלילי כשמשקולת ביד אחת מונחת על הירך.","בעזרת הירך להרמת המשקולת, הרימו אותה עד לרוחב הכתפיים כשכף היד פונה לגוף.","סובבו את פרק כף היד כך שכף היד פונה קדימה.","תוך כדי שאיפת אוויר, הורידו לאט את המשקולת הצידה עד שתרגישו מתיחה בחזה.","נשפו החוצה והשתמשו בשרירי החזה כדי להחזיר את המשקולת לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Lie down on a decline bench with a dumbbell in one hand, resting it on your thigh.","Using your thigh to help raise the dumbbell, lift it up to shoulder width with your palm facing your torso.","Rotate your wrist so that the palm of your hand is facing forward.","As you breathe in, lower the dumbbell slowly to the side until you feel a stretch in your chest.","Exhale and use your chest muscles to bring the dumbbell back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"NL6YBwN"},{"id":"edb-1617","name":"לחיצה ביד אחת בשיפוע שלילי עם משקולות","name_en":"dumbbell decline one arm hammer press","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["שכבו על ספסל בשיפוע שלילי כשמשקולת ביד אחת מונחת על החזה.","פשטו את היד ישר מעלה, כשהמרפק כפוף מעט.","הורידו את המשקולת לכיוון הכתף, כשהמרפק צמוד לגוף.","דחפו את המשקולת בחזרה למעלה לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Lie on a decline bench with a dumbbell in one hand, resting on your chest.","Extend your arm straight up, keeping your elbow slightly bent.","Lower the dumbbell down towards your shoulder, keeping your elbow close to your body.","Press the dumbbell back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"SHUMp5H"},{"id":"edb-0305","name":"משיכת כתפיים בשיפוע שלילי עם משקולות","name_en":"dumbbell decline shrug","muscle":"back","equipment":"dumbbell","target":"traps","bodyPart":"back","secondaryMuscles":["shoulders","rhomboids"],"steps":["כווננו ספסל בשיפוע שלילי לזווית של 45 מעלות.","שכבו על הבטן על הספסל, כשהחזה והבטן נשענים עליו.","אחזו משקולת בכל יד כשהידיים פשוטות לגמרי כלפי הרצפה.","כשהידיים ישרות, הרימו את הכתפיים לכיוון האוזניים כמה שיותר גבוה.","החזיקו את הכיווץ לרגע, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up a decline bench at a 45-degree angle.","Lie face down on the bench with your chest and stomach resting against it.","Hold a dumbbell in each hand with your arms fully extended towards the floor.","Keeping your arms straight, raise your shoulders towards your ears as high as possible.","Hold the contraction for a moment, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"cwsAI4G"},{"id":"edb-0304","name":"משיכת כתפיים בשיפוע שלילי עם משקולות","name_en":"dumbbell decline shrug v. 2","muscle":"back","equipment":"dumbbell","target":"traps","bodyPart":"back","secondaryMuscles":["shoulders","rhomboids"],"steps":["כווננו ספסל בשיפוע שלילי לזווית של 45 מעלות.","שכבו על הבטן על הספסל, כשהחזה והבטן נשענים עליו.","אחזו משקולת בכל יד כשכפות הידיים פונות זו לזו והידיים ישרות לגמרי.","כשהידיים ישרות, הרימו את הכתפיים כמה שיותר גבוה תוך כיווץ השכמות זו לזו.","החזיקו את הכיווץ לרגע קצר, לאחר מכן הורידו את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up a decline bench at a 45-degree angle.","Lie face down on the bench with your chest and stomach resting on it.","Hold a dumbbell in each hand with your palms facing each other and your arms fully extended.","Keeping your arms straight, raise your shoulders as high as possible while squeezing your shoulder blades together.","Hold the contraction for a brief pause, then lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"bRlbdjK"},{"id":"edb-0306","name":"פשיטת מרפק בשיפוע שלילי עם משקולות","name_en":"dumbbell decline triceps extension","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שכבו על ספסל בשיפוע שלילי כשהראש נמוך מהרגליים, ואחזו משקולת בכל יד כשכפות הידיים פונות זו לזו.","פשטו את הידיים לגמרי, כשהמרפקים קרובים לראש.","הורידו לאט את המשקולות מאחורי הראש, תוך כיפוף המרפקים.","עצרו לרגע, לאחר מכן הרימו את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie on a decline bench with your head lower than your feet and hold a dumbbell in each hand, palms facing each other.","Extend your arms fully, keeping your elbows close to your head.","Lower the dumbbells slowly behind your head, bending your elbows.","Pause for a moment, then raise the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"OTgkHwR"},{"id":"edb-0307","name":"פרפר בשיפוע שלילי עם משקולות","name_en":"dumbbell decline twist fly","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["שכבו על ספסל בשיפוע שלילי כשהראש נמוך מהאגן.","אחזו משקולת בכל יד כשכפות הידיים פונות זו לזו והידיים פשוטות ישר מעל החזה.","הורידו את המשקולות הצידה בתנועת קשת רחבה עד שתרגישו מתיחה בחזה.","תוך כדי הורדת המשקולות, סובבו את פרקי הידיים כך שכפות הידיים יפנו קדימה בתחתית התנועה.","בצעו את התנועה ההפוכה והחזירו את המשקולות למעלה לעמדת ההתחלה, תוך כיווץ שרירי החזה בשיא התנועה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie down on a decline bench with your head lower than your hips.","Hold a dumbbell in each hand with your palms facing each other and your arms extended straight up over your chest.","Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest.","As you lower the dumbbells, twist your wrists so that your palms face forward at the bottom of the movement.","Reverse the motion and bring the dumbbells back up to the starting position, squeezing your chest muscles at the top.","Repeat for the desired number of repetitions."],"mediaId":"reFHapa"},{"id":"edb-1437","name":"dumbbell finger curls","name_en":"dumbbell finger curls","muscle":"biceps","equipment":"dumbbell","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["wrist flexors","wrist extensors"],"steps":["שבו על ספסל או כיסא כשכפות הרגליים שטוחות על הרצפה והגב ישר.","אחזו משקולת ביד אחת באחיזה תחתונה, כשהאמה נשענת על הירך וכף היד פונה מעלה.","אפשרו למשקולת להתגלגל עד לקצות האצבעות, לאחר מכן כופפו אותה בחזרה על ידי כיפוף האצבעות.","חזרו למספר החזרות הרצוי, לאחר מכן עברו ליד השנייה."],"steps_en":["Sit on a bench or chair with your feet flat on the ground and your back straight.","Hold a dumbbell in one hand with an underhand grip, resting your forearm on your thigh, palm facing up.","Allow the dumbbell to roll down to your fingertips, then curl it back up by flexing your fingers.","Repeat for the desired number of repetitions, then switch to the other hand."],"mediaId":"mtXengz"},{"id":"edb-0308","name":"פרפר עם משקולות","name_en":"dumbbell fly","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders"],"steps":["שכבו על ספסל כשבכל יד משקולת, כפות הידיים פונות זו לזו.","פשטו את הידיים ישר מעל החזה, עם כיפוף קל במרפקים.","תוך שמירה על כיפוף קל במרפקים, הורידו את הזרועות הצדה בקשת רחבה עד שתרגישו מתיחה בחזה.","עצרו לרגע, לאחר מכן בצעו את התנועה ההפוכה והחזירו את המשקולות למעלה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with a dumbbell in each hand, palms facing each other.","Extend your arms straight up over your chest, with a slight bend in your elbows.","Keeping a slight bend in your elbows, lower your arms out to the sides in a wide arc until you feel a stretch in your chest.","Pause for a moment, then reverse the movement and bring the dumbbells back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"yz9nUhF"},{"id":"edb-1277","name":"פרפר עם משקולות","name_en":"dumbbell fly on exercise ball","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["שבו על כדור התעמלות ואחזו משקולת בכל יד.","צעדו עם הרגליים קדימה וגלגלו את הגוף למטה עד שהראש, הצוואר וחלק הגב העליון נתמכים על ידי הכדור.","פשטו את הידיים ישר מעל החזה, כשכפות הידיים פונות זו לזו.","כופפו מעט את המרפקים והורידו את הידיים הצידה בתנועת קשת רחבה עד שתרגישו מתיחה בחזה.","עצרו לרגע, לאחר מכן בצעו את התנועה ההפוכה וכווצו את שרירי החזה תוך החזרת המשקולות לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on an exercise ball and hold a dumbbell in each hand.","Walk your feet forward and roll your body down until your head, neck, and upper back are supported by the ball.","Extend your arms straight up above your chest, palms facing each other.","Bend your elbows slightly and lower your arms out to the sides in a wide arc until you feel a stretch in your chest.","Pause for a moment, then reverse the movement and squeeze your chest muscles as you bring the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Lt3iWnf"},{"id":"edb-1732","name":"פשיטת מרפק עם משקולות","name_en":"dumbbell forward lunge triceps extension","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשבכל יד משקולת.","צעדו קדימה עם הרגל הימנית, תוך הורדת הגוף לעמדת לאנג'.","שמרו על גב ישר וחזה מורם.","פשטו את הידיים ישר מעל הראש, כשהמרפקים קרובים לאוזניים.","הורידו את המשקולות מאחורי הראש על ידי כיפוף המרפקים.","עצרו לרגע, לאחר מכן יישרו את הידיים כדי לחזור לעמדת ההתחלה.","חזרו על התנועה למספר החזרות הרצוי, לאחר מכן החליפו רגליים וחזרו על התהליך."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand.","Take a step forward with your right foot, lowering your body into a lunge position.","Keep your back straight and your chest up.","Extend your arms straight overhead, keeping your elbows close to your ears.","Lower the dumbbells behind your head by bending your elbows.","Pause for a moment, then straighten your arms to return to the starting position.","Repeat the movement for the desired number of repetitions, then switch legs and repeat."],"mediaId":"XalXcvM"},{"id":"edb-0310","name":"הרמה קדמית עם משקולות","name_en":"dumbbell front raise","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["biceps","trapezius"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשבכל יד משקולת וכפות הידיים פונות לירכיים.","כשהידיים ישרות, נשפו החוצה והרימו את המשקולות לפניכם עד לגובה הכתפיים.","עצרו לרגע בשיא התנועה, לאחר מכן שאפו אוויר והורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your thighs.","Keeping your arms straight, exhale and lift the dumbbells in front of you until they are at shoulder level.","Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"3eGE2JC"},{"id":"edb-0309","name":"הרמה קדמית עם משקולות","name_en":"dumbbell front raise v. 2","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","biceps"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשבכל יד משקולת וכפות הידיים פונות לירכיים.","שמרו על גב ישר והפעילו את ליבת הגוף.","הרימו לאט את המשקולות לפניכם, כשהידיים ישרות, עד לגובה הכתפיים.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your thighs.","Keep your back straight and engage your core.","Slowly lift the dumbbells in front of you, with your arms straight, until they are at shoulder level.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Rr7S3yg"},{"id":"edb-0311","name":"הרחקת כתפיים לצדדים עם משקולות","name_en":"dumbbell full can lateral raise","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","rotator cuff"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשבכל יד משקולת וכפות הידיים פונות לגוף.","שמרו על גב ישר והפעילו את ליבת הגוף.","הרימו את הידיים הצידה, עם כיפוף קל במרפקים, עד שהן מקבילות לרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הידיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your body.","Keep your back straight and engage your core.","Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"AQ0mC4Y"},{"id":"edb-1760","name":"סקוואט גובלט עם משקולות","name_en":"dumbbell goblet squat","muscle":"legs","equipment":"dumbbell","target":"quads","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים משקולת אנכית מול החזה בשתי הידיים.","כשהחזה מורם ושרירי הליבה מופעלים, הורידו את הגוף לעמדת סקוואט על ידי דחיפת האגן לאחור וכיפוף הברכיים.","המשיכו לרדת עד שהירכיים מקבילות לרצפה, או עד למקסימום שנוח לכם.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell vertically against your chest with both hands.","Keeping your chest up and core engaged, lower your body down into a squat position by pushing your hips back and bending your knees.","Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"yn8yg1r"},{"id":"edb-0313","name":"כפיפת פטיש","name_en":"dumbbell hammer curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף כשבכל יד משקולת, כפות הידיים פונות לגוף.","שמרו על המרפקים צמודים לגוף וסובבו את כפות הידיים עד שהן פונות קדימה.","זו תהיה עמדת ההתחלה שלכם.","כעת, כשהזרועות העליונות נייחות, נשפו החוצה וכופפו את המשקולות תוך כיווץ הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","לאחר מכן, שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התנועה למספר החזרות המומלץ."],"steps_en":["Stand up straight with a dumbbell in each hand, palms facing your torso.","Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward.","This will be your starting position.","Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Then, inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the recommended amount of repetitions."],"mediaId":"slDvUAU"},{"id":"edb-1659","name":"כפיפת פטיש עם משקולות","name_en":"dumbbell hammer curl on exercise ball","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על כדור התעמלות כשכפות הרגליים שטוחות על הרצפה והגב ישר.","אחזו משקולת בכל יד כשכפות הידיים פונות לגוף והידיים ישרות לגמרי.","כשהזרועות העליונות נייחות, נשפו החוצה וכופפו את המשקולות תוך כיווץ הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in each hand with your palms facing your body and your arms fully extended.","Keeping your upper arms stationary, exhale and curl the dumbbells while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"fY68AyX"},{"id":"edb-0312","name":"כפיפת פטיש עם משקולות","name_en":"dumbbell hammer curl v. 2","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף כשבכל יד משקולת, כפות הידיים פונות לגוף.","שמרו על המרפקים צמודים לגוף וסובבו את כפות הידיים עד שהן פונות קדימה.","זו תהיה עמדת ההתחלה שלכם.","כעת, כשהזרועות העליונות נייחות, נשפו החוצה וכופפו את המשקולות תוך כיווץ הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","לאחר מכן, שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התנועה למספר החזרות המומלץ."],"steps_en":["Stand up straight with a dumbbell in each hand, palms facing your torso.","Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward.","This will be your starting position.","Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Then, inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the recommended amount of repetitions."],"mediaId":"2NpxjC1"},{"id":"edb-2402","name":"dumbbell hammer curls (with arm blaster)","name_en":"dumbbell hammer curls (with arm blaster)","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף כשבכל יד משקולת, כפות הידיים פונות לגוף.","שמרו על המרפקים צמודים לגוף וסובבו את כפות הידיים עד שהן פונות קדימה.","זו תהיה עמדת ההתחלה שלכם.","כעת, כשהזרוע העליונה נייחת, נשפו החוצה וכופפו את המשקולות תוך כיווץ הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","לאחר מכן, שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התנועה למספר החזרות המומלץ."],"steps_en":["Stand up straight with a dumbbell in each hand, palms facing your torso.","Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward.","This will be your starting position.","Now, while holding your upper arm stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Then, inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the recommended amount of repetitions."],"mediaId":"GNhAeJ0"},{"id":"edb-1664","name":"כפיפת מרפק גבוה עם משקולות","name_en":"dumbbell high curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף כשבכל יד משקולת, כפות הידיים פונות קדימה.","שמרו על הזרועות העליונות נייחות וכופפו את המשקולות כמה שיותר גבוה תוך כיווץ הביצפס.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand up straight with a dumbbell in each hand, palms facing forward.","Keep your upper arms stationary and curl the dumbbells as high as possible while contracting your biceps.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"qAmNMJY"},{"id":"edb-3545","name":"לחיצה בשיפוע לסירוגין עם משקולות","name_en":"dumbbell incline alternate press","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["שבו על ספסל בשיפוע חיובי כשבכל יד משקולת המונחת על הירכיים.","הישענו לאחור על הספסל והשתמשו בירכיים כדי לסייע בהרמת המשקולות לגובה הכתפיים, כשכפות הידיים פונות קדימה.","כשהמשקולות בגובה הכתפיים, סובבו את פרקי הידיים כך שכפות הידיים פונות קדימה.","דחפו את המשקולות למעלה בעזרת החזה והכתפיים, תוך פשיטת הידיים לגמרי.","הורידו את המשקולות בחזרה לעמדת ההתחלה, כשהמרפקים כפופים מעט.","חזרו על התנועה למספר החזרות הרצוי, תוך החלפת ידיים."],"steps_en":["Sit on an incline bench with a dumbbell in each hand, resting on your thighs.","Lean back on the bench and use your thighs to help raise the dumbbells to shoulder height, palms facing forward.","Once at shoulder height, rotate your wrists so that the palms of your hands are facing forward.","Push the dumbbells up with your chest and shoulders, extending your arms fully.","Lower the dumbbells back down to the starting position, keeping your elbows slightly bent.","Repeat for the desired number of repetitions, alternating arms."],"mediaId":"TVdivgY"},{"id":"edb-0314","name":"לחיצת חזה בשיפוע (משקולות)","name_en":"dumbbell incline bench press","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["הציבו ספסל בשיפוע עולה בזווית של 45 מעלות.","שבו על הספסל כשכפות הרגליים שטוחות על הרצפה והגב צמוד היטב לספסל.","אחזו משקולת בכל יד, כשכפות הידיים פונות קדימה, והרימו אותן לגובה הכתפיים.","הורידו לאט את המשקולות לצדי החזה, כשהמרפקים בזווית של 90 מעלות.","דחפו את המשקולות בחזרה למעלה לעמדת ההתחלה, תוך פשיטת הידיים לגמרי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up an incline bench at a 45-degree angle.","Sit on the bench with your feet flat on the ground and your back pressed firmly against the bench.","Hold a dumbbell in each hand, palms facing forward, and lift them to shoulder height.","Slowly lower the dumbbells to the sides of your chest, keeping your elbows at a 90-degree angle.","Push the dumbbells back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"ns0SIbU"},{"id":"edb-0315","name":"כפיפת מרפק בשיפוע עם משקולות","name_en":"dumbbell incline biceps curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל בשיפוע חיובי כשבכל יד משקולת, כפות הידיים פונות קדימה והידיים ישרות לגמרי.","תוך שמירה על הזרוע העליונה ללא תזוזה, נשפו החוצה וכופפו את המשקולות תוך כיווץ שרירי הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on an incline bench with a dumbbell in each hand, palms facing forward, and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"F3xgbjF"},{"id":"edb-0316","name":"dumbbell incline breeding","name_en":"dumbbell incline breeding","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["הציבו ספסל בשיפוע עולה בזווית של 45 מעלות.","שבו על הספסל כשהגב נשען על הכרית וכפות הרגליים שטוחות על הרצפה.","אחזו משקולת בכל יד באחיזה עליונה, כשכפות הידיים פונות קדימה.","התחילו כשהידיים ישרות לגמרי, בניצב לרצפה.","הורידו לאט את המשקולות לצדי החזה, כשהמרפקים בזווית של 90 מעלות.","עצרו לרגע בתחתית התנועה, לאחר מכן דחפו את המשקולות בחזרה למעלה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up an incline bench at a 45-degree angle.","Sit on the bench with your back against the pad and feet flat on the ground.","Hold a dumbbell in each hand with an overhand grip, palms facing forward.","Start with your arms fully extended, perpendicular to the ground.","Lower the dumbbells slowly to the sides of your chest, keeping your elbows at a 90-degree angle.","Pause for a moment at the bottom, then push the dumbbells back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"B3Rxp6L"},{"id":"edb-0318","name":"כפיפת מרפק בשיפוע עם משקולות","name_en":"dumbbell incline curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["כווננו ספסל לשיפוע חיובי של 45 מעלות ושבו עליו כשבכל יד משקולת, כפות הידיים פונות קדימה.","הניחו את הזרועות העליונות על ספסל השיפוע ואפשרו למרפקים לתלות כלפי מטה, תוך פשיטת הידיים לגמרי.","תוך שמירה על הזרוע העליונה ללא תזוזה, נשפו החוצה וכופפו את המשקולות תוך כיווץ שרירי הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing forward.","Rest your upper arms on the incline bench and let your elbows hang down, fully extending your arms.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ae9UoXQ"},{"id":"edb-0317","name":"כפיפת מרפק בשיפוע עם משקולות","name_en":"dumbbell incline curl v. 2","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל בשיפוע חיובי כשבכל יד משקולת, כפות הידיים פונות קדימה והידיים ישרות לגמרי.","תוך שמירה על הזרוע העליונה ללא תזוזה, נשפו החוצה וכופפו את המשקולות תוך כיווץ שרירי הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on an incline bench with a dumbbell in each hand, palms facing forward and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"RaflbWD"},{"id":"edb-0319","name":"פרפר בשיפוע עם משקולות","name_en":"dumbbell incline fly","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders"],"steps":["כווננו ספסל משופע לזווית של 45 מעלות.","שבו על הספסל כשמשקולת בכל יד, כפות הידיים פונות זו לזו.","שכבו על הספסל ודחפו את המשקולות למעלה לתנוחת ההתחלה, ישירות מעל החזה.","הורידו את המשקולות הצידה בתנועת קשת רחבה עד שתרגישו מתיחה בחזה.","עצרו לרגע, ולאחר מכן כווצו את שרירי החזה כדי להחזיר את המשקולות לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set an incline bench to a 45-degree angle.","Sit on the bench with a dumbbell in each hand, palms facing each other.","Lie back on the bench and press the dumbbells up to the starting position, directly above your chest.","Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest.","Pause for a moment, then squeeze your chest muscles to bring the dumbbells back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ESOd5Pl"},{"id":"edb-1278","name":"פרפר בשיפוע עם משקולות","name_en":"dumbbell incline fly on exercise ball","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders"],"steps":["הציבו ספסל בשיפוע עולה בזווית של 45 מעלות.","שבו על כדור פיטבול והתגלגלו קדימה עד שהגב העליון נשען על הספסל המשופע.","אחזו משקולת בכל יד כשכפות הידיים פונות זו לזו והידיים פשוטות מעל החזה.","הורידו את המשקולות הצידה בתנועת קשת רחבה עד שתרגישו מתיחה בחזה.","עצרו לרגע, לאחר מכן כווצו את שרירי החזה כדי להחזיר את המשקולות לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up an incline bench at a 45-degree angle.","Sit on an exercise ball and roll forward until your upper back is resting on the incline bench.","Hold a dumbbell in each hand with your palms facing each other and your arms extended above your chest.","Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest.","Pause for a moment, then squeeze your chest muscles to bring the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"HYe1ZqR"},{"id":"edb-0320","name":"כפיפת פטיש בשיפוע עם משקולות","name_en":"dumbbell incline hammer curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל משופע כשמשקולת בכל יד, כפות הידיים פונות לגוף והידיים ישרות לגמרי.","שמרו על הגב צמוד לספסל ועל כפות הרגליים שטוחות על הרצפה.","תוך שמירה על הזרוע העליונה נייחת, נשפו וכופפו את המשקולות תוך כיווץ הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on an incline bench with a dumbbell in each hand, palms facing your torso and arms fully extended.","Keep your back against the bench and your feet flat on the floor.","While keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ByX0WxV"},{"id":"edb-0321","name":"לחיצה בשיפוע עם משקולות","name_en":"dumbbell incline hammer press","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["כווננו ספסל משופע לזווית של 45 מעלות ושבו עליו כשמשקולת בכל יד, מונחות על הירכיים.","שכבו על הספסל ומקמו את המשקולות בגובה הכתפיים כשכפות הידיים פונות זו לזו.","דחפו את המשקולות למעלה והרחק מהגוף עד שהידיים ישרות לגמרי.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, resting on your thighs.","Lie back on the bench and position the dumbbells at shoulder level with your palms facing each other.","Press the dumbbells up and away from your body until your arms are fully extended.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"PG1kcIb"},{"id":"edb-1618","name":"לחיצה בשיפוע עם משקולות","name_en":"dumbbell incline hammer press on exercise ball","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["שבו על כדור פיטבול כשמשקולת בכל יד, כפות הידיים פונות זו לזו.","צעדו עם הרגליים קדימה וגלגלו את הגוף למטה על הכדור עד שהראש, הצוואר והגב העליון נשענים על הכדור.","אחזו את המשקולות בגובה הכתפיים, כשהמרפקים כפופים ופונים החוצה לצדדים.","דחפו את המשקולות למעלה ומעט פנימה, כשכפות הידיים ממשיכות לפנות זו לזו.","יישרו את הידיים לגמרי, וכווצו את הטריצפס בשיא התנועה.","הורידו את המשקולות באיטיות בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on an exercise ball with a dumbbell in each hand, palms facing each other.","Walk your feet forward and roll your body down the ball until your head, neck, and upper back are supported on the ball.","Hold the dumbbells at shoulder level, elbows bent and pointing out to the sides.","Press the dumbbells up and slightly inward, keeping your palms facing each other.","Extend your arms fully, squeezing your triceps at the top of the movement.","Slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"wkgnGfb"},{"id":"edb-0322","name":"כפיפת מרפק בשיפוע עם משקולות","name_en":"dumbbell incline inner biceps curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל משופע כשמשקולת בכל יד, כפות הידיים פונות זו לזו.","הניחו את הזרועות העליונות על הספסל, כך שהמרפקים תלויים למטה וכפות הידיים פונות קדימה.","תוך שמירה על הזרוע העליונה ללא תזוזה, נשפו החוצה וכופפו את המשקולות תוך כיווץ שרירי הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on an incline bench with a dumbbell in each hand, palms facing each other.","Rest your upper arms on the bench, allowing your elbows to hang down and your palms to face forward.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"LCtQPn8"},{"id":"edb-1279","name":"פרפר ביד אחת בשיפוע עם משקולות","name_en":"dumbbell incline one arm fly","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["deltoids","triceps"],"steps":["כווננו את הספסל המשופע לזווית של 30-45 מעלות.","שבו על הספסל כשמשקולת אחת ביד, מונחת על הירך.","שכבו על הספסל, כשכפות הרגליים שטוחות על הרצפה.","אחזו את המשקולת כשהיד ישרה לגמרי מעל החזה.","הורידו את המשקולת החוצה לצד בקשת רחבה, תוך שמירה על כיפוף קל במרפק.","עצרו כשהיד מקבילה לרצפה, ולאחר מכן הפכו את התנועה כדי להחזיר את המשקולת לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Adjust the incline bench to a 30-45 degree angle.","Sit on the bench with a dumbbell in one hand, resting it on your thigh.","Lie back on the bench, keeping your feet flat on the ground.","Hold the dumbbell with your arm extended straight up over your chest.","Lower the dumbbell out to the side in a wide arc, keeping a slight bend in your elbow.","Pause when your arm is parallel to the ground, then reverse the motion to bring the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"Gw2HFvW"},{"id":"edb-1280","name":"פרפר ביד אחת בשיפוע עם משקולות","name_en":"dumbbell incline one arm fly on exercise ball","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders"],"steps":["שבו על כדור פיטבול כשמשקולת אחת ביד.","צעדו עם הרגליים קדימה וגלגלו את הגוף למטה עד שהראש, הצוואר והגב העליון נשענים על הכדור.","אחזו את המשקולת כשהיד ישרה לגמרי מעל החזה, כף היד פונה פנימה.","הורידו את המשקולת באיטיות החוצה לצד, תוך שמירה על כיפוף קל במרפק.","עצרו לרגע כשהיד מקבילה לרצפה.","הפעילו את שרירי החזה כדי להחזיר את המשקולת לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Sit on an exercise ball with a dumbbell in one hand.","Walk your feet forward and roll your body down until your head, neck, and upper back are supported on the ball.","Hold the dumbbell with your arm extended straight up over your chest, palm facing inwards.","Slowly lower the dumbbell out to the side, keeping a slight bend in your elbow.","Pause for a moment when your arm is parallel to the ground.","Engage your chest muscles to bring the dumbbell back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"LLNh6q5"},{"id":"edb-1619","name":"לחיצה ביד אחת בשיפוע עם משקולות","name_en":"dumbbell incline one arm hammer press","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders","chest"],"steps":["שבו על ספסל משופע כשמשקולת אחת ביד, מונחת על הירך.","הישענו לאחור על הספסל והיעזרו בירך כדי להרים את המשקולת לגובה הכתפיים.","סובבו את שורש כף היד כך שכף היד תפנה פנימה, לכיוון הגוף.","דחפו את המשקולת למעלה והרחק מהגוף, תוך יישור מלא של היד.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות חזרה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Sit on an incline bench with a dumbbell in one hand, resting on your thigh.","Lean back on the bench and use your thigh to help raise the dumbbell to shoulder height.","Rotate your wrist so that your palm is facing inward, towards your body.","Press the dumbbell up and away from your body, extending your arm fully.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"LL1UiTX"},{"id":"edb-1620","name":"לחיצה ביד אחת בשיפוע עם משקולות","name_en":"dumbbell incline one arm hammer press on exercise ball","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders","chest"],"steps":["שבו על כדור פיטבול כשמשקולת אחת ביד.","צעדו עם הרגליים קדימה וגלגלו את הגוף למטה עד שהראש, הצוואר והגב העליון נשענים על הכדור.","אחזו את המשקולת כשכף היד פונה פנימה והמרפק כפוף בזווית של 90 מעלות.","דחפו את המשקולת למעלה לכיוון התקרה, תוך יישור היד.","הורידו את המשקולת חזרה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Sit on an exercise ball with a dumbbell in one hand.","Walk your feet forward and roll your body down until your head, neck, and upper back are supported on the ball.","Hold the dumbbell with your palm facing inward and your elbow bent at a 90-degree angle.","Press the dumbbell up towards the ceiling, straightening your arm.","Lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"jDnrkar"},{"id":"edb-0323","name":"הרחקת כתפיים לצדדים ביד אחת בשיפוע עם משקולות","name_en":"dumbbell incline one arm lateral raise","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","triceps"],"steps":["שבו על ספסל משופע כשמשקולת אחת ביד, מונחת על הירך.","הישענו קדימה ומקמו את הזרוע העליונה כנגד החלק הפנימי של הירך.","הרימו את המשקולת לצד, כשהיד כפופה מעט וכף היד פונה מטה.","המשיכו להרים עד שהיד מקבילה לרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ליד השנייה."],"steps_en":["Sit on an incline bench with a dumbbell in one hand, resting it on your thigh.","Lean forward and position your upper arm against the inside of your thigh.","Raise the dumbbell to the side, keeping your arm slightly bent and your palm facing down.","Continue lifting until your arm is parallel to the floor.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"mediaId":"aTNKZiC"},{"id":"edb-1281","name":"לחיצה ביד אחת בשיפוע עם משקולות","name_en":"dumbbell incline one arm press","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["שבו על ספסל משופע כשמשקולת אחת ביד, מונחת על הירך.","שכבו על הספסל ומקמו את המשקולת בגובה הכתף, כף היד פונה קדימה.","דחפו את המשקולת למעלה ומעט פנימה, תוך יישור מלא של היד.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ליד השנייה."],"steps_en":["Sit on an incline bench with a dumbbell in one hand, resting on your thigh.","Lie back on the bench and position the dumbbell at shoulder level, palm facing forward.","Press the dumbbell upward and slightly inward, extending your arm fully.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"mediaId":"rDAiRf9"},{"id":"edb-1282","name":"לחיצה ביד אחת בשיפוע עם משקולות","name_en":"dumbbell incline one arm press on exercise ball","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["שבו על כדור פיטבול כשמשקולת אחת ביד, כפות הרגליים שטוחות על הרצפה.","צעדו באיטיות עם הרגליים קדימה, וגלגלו את הכדור עד שהראש, הצוואר והגב העליון נשענים עליו.","אחזו את המשקולת בגובה הכתף כשכף היד פונה קדימה.","דחפו את המשקולת למעלה עד שהיד ישרה לגמרי.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ליד השנייה."],"steps_en":["Sit on an exercise ball with a dumbbell in one hand, feet flat on the ground.","Slowly walk your feet forward, rolling the ball until your head, neck, and upper back are supported on the ball.","Hold the dumbbell at shoulder height with your palm facing forward.","Press the dumbbell upward until your arm is fully extended.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"mediaId":"Bg5JKSH"},{"id":"edb-0324","name":"לחיצה בשיפוע עם משקולות","name_en":"dumbbell incline palm-in press","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["הציבו ספסל בשיפוע עולה בזווית של 45 מעלות.","שבו על הספסל כשמשקולת בכל יד, כפות הידיים פונות זו לזו.","הציבו את כפות הרגליים היטב על הרצפה ושמרו על הגב ישר וצמוד לספסל.","התחילו עם המשקולות בגובה הכתפיים, המרפקים כפופים וכפות הידיים פונות זו לזו.","דחפו את המשקולות למעלה והרחק מהגוף, תוך יישור מלא של הידיים.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up an incline bench at a 45-degree angle.","Sit on the bench with a dumbbell in each hand, palms facing each other.","Plant your feet firmly on the ground and keep your back straight against the bench.","Start with the dumbbells at shoulder level, elbows bent and palms facing each other.","Press the dumbbells up and away from your body, extending your arms fully.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"OVLmUuL"},{"id":"edb-1283","name":"לחיצה בשיפוע עם משקולות","name_en":"dumbbell incline press on exercise ball","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["שבו על כדור פיטבול כשמשקולת בכל יד, כפות הידיים פונות קדימה.","צעדו באיטיות עם הרגליים קדימה, גלגלו את הגוף למטה על הכדור עד שהראש, הצוואר והגב העליון נשענים עליו.","אחזו את המשקולות בגובה הכתפיים, כשהמרפקים כפופים ופונים החוצה לצדדים.","דחפו את המשקולות למעלה, תוך יישור מלא של הידיים.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on an exercise ball with a dumbbell in each hand, palms facing forward.","Slowly walk your feet forward, rolling your body down the ball until your head, neck, and upper back are supported on the ball.","Hold the dumbbells at shoulder level, elbows bent and pointing out to the sides.","Press the dumbbells upward, extending your arms fully.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"bfiHMpI"},{"id":"edb-0325","name":"הרמה בשיפוע עם משקולות","name_en":"dumbbell incline raise","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","triceps"],"steps":["שבו על ספסל בשיפוע חיובי כשבכל יד משקולת המונחת על הירכיים.","הישענו לאחור על הספסל והרימו את המשקולות לגובה הכתפיים, כפות הידיים פונות קדימה.","תוך שמירה על הגב צמוד לספסל, נשפו והרימו את המשקולות מעל הראש, תוך יישור מלא של הידיים.","עצרו לרגע בשיא התנועה, ולאחר מכן שאפו אוויר והורידו את המשקולות באיטיות בחזרה לגובה הכתפיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on an incline bench with a dumbbell in each hand, resting on your thighs.","Lean back on the bench and raise the dumbbells to shoulder height, palms facing forward.","Keeping your back against the bench, exhale and raise the dumbbells above your head, fully extending your arms.","Pause for a moment at the top, then inhale and slowly lower the dumbbells back to shoulder height.","Repeat for the desired number of repetitions."],"mediaId":"nxW6BkN"},{"id":"edb-0326","name":"הרחקת כתפיים לצדדים בשיפוע אחורי עם משקולות","name_en":"dumbbell incline rear lateral raise","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","rhomboids"],"steps":["הציבו ספסל בשיפוע עולה בזווית של 45 מעלות.","שבו על הספסל כשהחזה צמוד למשענת, ואחזו משקולת בכל יד.","יישרו את הידיים ישר למטה כשכפות הידיים פונות זו לזו.","תוך שמירה על כיפוף קל במרפקים, הרימו את הידיים לצדדים עד שהן מקבילות לרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הידיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up an incline bench at a 45-degree angle.","Sit on the bench with your chest against the backrest and hold a dumbbell in each hand.","Extend your arms straight down with your palms facing each other.","Keeping a slight bend in your elbows, raise your arms out to the sides until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"vYk8lqw"},{"id":"edb-0327","name":"חתירה בשיפוע עם משקולות","name_en":"dumbbell incline row","muscle":"back","equipment":"dumbbell","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","shoulders"],"steps":["הציבו ספסל בשיפוע עולה בזווית של 45 מעלות.","אחזו משקולת בכל יד ושבו על הספסל כשהחזה צמוד למשופע.","יישרו את הידיים לגמרי, כשהמשקולות תלויות ישר למטה מהכתפיים.","משכו את המשקולות כלפי מעלה לכיוון החזה, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up an incline bench at a 45-degree angle.","Grab a dumbbell in each hand and sit on the bench with your chest against the incline.","Extend your arms fully, allowing the dumbbells to hang straight down from your shoulders.","Pull the dumbbells up towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"7vG5o25"},{"id":"edb-0328","name":"הרמה בשיפוע עם משקולות","name_en":"dumbbell incline shoulder raise","muscle":"chest","equipment":"dumbbell","target":"serratus anterior","bodyPart":"chest","secondaryMuscles":["deltoids","trapezius"],"steps":["כווננו ספסל משופע לזווית של 45 מעלות ושבו עליו כשמשקולת בכל יד, כפות הידיים פונות מטה.","הניחו את המשקולות על הירכיים והישענו לאחור על הספסל.","היעזרו בירכיים כדי להרים את המשקולות לגובה הכתפיים, ולאחר מכן סובבו את שורשי כפות הידיים כך שיפנו קדימה.","נשפו והרימו את המשקולות באיטיות מעל הראש, תוך שמירה על כיפוף קל במרפקים.","עצרו לרגע בשיא התנועה, ולאחר מכן שאפו אוויר והורידו את המשקולות באיטיות בחזרה לגובה הכתפיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing down.","Rest the dumbbells on your thighs and lean back onto the bench.","Use your thighs to help raise the dumbbells to shoulder height, then rotate your wrists so that your palms are facing forward.","Exhale and slowly raise the dumbbells above your head, keeping a slight bend in your elbows.","Pause for a moment at the top, then inhale and slowly lower the dumbbells back to shoulder height.","Repeat for the desired number of repetitions."],"mediaId":"6e2DcYX"},{"id":"edb-0329","name":"משיכת כתפיים בשיפוע עם משקולות","name_en":"dumbbell incline shrug","muscle":"back","equipment":"dumbbell","target":"traps","bodyPart":"back","secondaryMuscles":["shoulders"],"steps":["כווננו ספסל משופע לזווית של 45 מעלות ושבו עליו כשמשקולת בכל יד.","הניחו את כפות הרגליים שטוחות על הרצפה ותנו לידיים להיתלות ישר למטה כשכפות הידיים פונות לגוף.","תוך שמירה על הידיים ישרות, משכו את הכתפיים כלפי מעלה לכיוון האוזניים, גבוה ככל האפשר.","החזיקו את הכיווץ לרגע, ולאחר מכן הורידו לאט את הכתפיים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand.","Place your feet flat on the ground and let your arms hang straight down with your palms facing your body.","Keeping your arms straight, shrug your shoulders up towards your ears as high as possible.","Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"JymLInS"},{"id":"edb-3542","name":"הרמה בשיפוע עם משקולות","name_en":"dumbbell incline t-raise","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","rhomboids"],"steps":["כווננו ספסל משופע לזווית של 45 מעלות ושבו עליו כשמשקולת בכל יד, כפות הידיים פונות פנימה.","הישענו קדימה ותנו לידיים להיתלות ישר למטה, בניצב לרצפה.","תוך שמירה על הידיים ישרות, הרימו אותן לצדדים עד שהן מקבילות לרצפה, ויוצרות עם הגוף צורת 'T'.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הידיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing inwards.","Lean forward and let your arms hang straight down, perpendicular to the floor.","Keeping your arms straight, raise them out to the sides until they are parallel to the floor, forming a 'T' shape with your body.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"jgbvVJ0"},{"id":"edb-0330","name":"פשיטת מרפק בשיפוע עם משקולות","name_en":"dumbbell incline triceps extension","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שבו על ספסל משופע כשמשקולת בכל יד, כפות הידיים פונות פנימה.","יישרו את הידיים לגמרי מעל הראש, כשהמרפקים קרובים לראש.","הורידו את המשקולות מאחורי הראש על ידי כיפוף המרפקים, תוך שמירה על הזרועות העליונות נייחות.","עצרו לרגע, ולאחר מכן הרימו את המשקולות בחזרה לתנוחת ההתחלה על ידי יישור הידיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on an incline bench with a dumbbell in each hand, palms facing inwards.","Extend your arms fully overhead, keeping your elbows close to your head.","Lower the dumbbells behind your head by bending your elbows, keeping your upper arms stationary.","Pause for a moment, then raise the dumbbells back to the starting position by extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"OVIKwsd"},{"id":"edb-0331","name":"dumbbell incline twisted flyes","name_en":"dumbbell incline twisted flyes","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["כווננו ספסל משופע לזווית של 45 מעלות ושבו עליו כשמשקולת בכל יד, כפות הידיים פונות זו לזו.","שכבו על הספסל ודחפו את המשקולות למעלה לתנוחת ההתחלה, ישירות מעל החזה, כשהידיים ישרות.","הורידו את המשקולות הצידה בתנועת קשת רחבה עד שתרגישו מתיחה בחזה.","תוך כדי הורדת המשקולות, סובבו את שורשי כפות הידיים כך שיפנו קדימה בתחתית התנועה.","הפכו את התנועה והחזירו את המשקולות למעלה לתנוחת ההתחלה, כשאתם מכווצים את שרירי החזה בשיא התנועה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing each other.","Lie back on the bench and press the dumbbells up to the starting position, directly above your chest, with your arms extended.","Lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest.","As you lower the dumbbells, rotate your wrists so that your palms face forward at the bottom of the movement.","Reverse the motion and bring the dumbbells back up to the starting position, squeezing your chest muscles together at the top.","Repeat for the desired number of repetitions."],"mediaId":"1PLE8e9"},{"id":"edb-1733","name":"פשיטה בשתי ידיים בשיפוע עם משקולות","name_en":"dumbbell incline two arm extension","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שבו על ספסל בשיפוע חיובי כשבכל יד משקולת המונחת על הירכיים.","שכבו באיטיות על הספסל, כשהמשקולות קרובות לחזה.","לאחר ששכבתם לגמרי, יישרו את הידיים כלפי מעלה לכיוון התקרה, תוך שמירה על כיפוף קל במרפקים.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on an incline bench with a dumbbell in each hand, resting on your thighs.","Slowly lie back on the bench, keeping the dumbbells close to your chest.","Once you are fully lying down, extend your arms straight up towards the ceiling, keeping your elbows slightly bent.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"U7D9Fx3"},{"id":"edb-3541","name":"הרמה בשיפוע עם משקולות","name_en":"dumbbell incline y-raise","muscle":"back","equipment":"dumbbell","target":"upper back","bodyPart":"back","secondaryMuscles":["shoulders","rear deltoids"],"steps":["כווננו ספסל משופע לזווית של 45 מעלות ושבו עליו כשמשקולת בכל יד, כפות הידיים פונות פנימה.","הישענו מעט קדימה ותנו לידיים להיתלות ישר למטה, תוך שמירה על כיפוף קל במרפקים.","הרימו את הידיים לצדדים ולמעלה בצורת Y עד שהן מקבילות לרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הידיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set an incline bench to a 45-degree angle and sit on it with a dumbbell in each hand, palms facing inwards.","Lean forward slightly and let your arms hang straight down, keeping a slight bend in your elbows.","Raise your arms out to the sides and up in a Y shape until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"PbzNu7c"},{"id":"edb-0332","name":"dumbbell iron cross","name_en":"dumbbell iron cross","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","chest"],"steps":["עמדו כשכפות הרגליים ברוחב הכתפיים, ואחזו משקולת בכל יד לצד הגוף.","הרימו את הידיים לצדדים עד שהן מקבילות לרצפה, ויוצרות עם הגוף צורת T.","עצרו לרגע, ולאחר מכן הורידו את הידיים באיטיות בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at your sides.","Raise your arms out to the sides until they are parallel to the ground, forming a T shape with your body.","Pause for a moment, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"cALkHHX"},{"id":"edb-0333","name":"בעיטה אחורית עם משקולות","name_en":"dumbbell kickback","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["עמדו כשכפות הרגליים ברוחב הכתפיים ואחזו משקולת בכל יד.","כופפו מעט את הברכיים והטו את הגוף קדימה במפרקי הירך, תוך שמירה על גב ישר.","קרבו את הזרועות העליונות לצדי הגוף, כשהמרפקים כפופים בזווית של 90 מעלות.","יישרו את הידיים ישר לאחור, וכווצו את הטריצפס בשיא התנועה.","עצרו לרגע, ולאחר מכן הורידו את המשקולות באיטיות בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Bring your upper arms close to your sides, with your elbows bent at a 90-degree angle.","Extend your arms straight back, squeezing your triceps at the top of the movement.","Pause for a moment, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"W6PxUkg"},{"id":"edb-1734","name":"dumbbell kickbacks on exercise ball","name_en":"dumbbell kickbacks on exercise ball","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders","back"],"steps":["שבו על כדור התעמלות כשכפות הרגליים שטוחות על הרצפה והגב ישר.","אחזו משקולת בכל יד כשכפות הידיים פונות פנימה והידיים כפופות בזווית של 90 מעלות.","יישרו את הידיים ישר לאחור, וכווצו את הטריצפס בשיא התנועה.","עצרו לרגע, ולאחר מכן הורידו את המשקולות באיטיות בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in each hand with your palms facing inwards and your arms bent at a 90-degree angle.","Extend your arms straight back, squeezing your triceps at the top of the movement.","Pause for a moment, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"cAvTaSg"},{"id":"edb-1660","name":"כפיפת מרפק בכריעה עם משקולות","name_en":"dumbbell kneeling bicep curl exercise ball","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["כרעו על הרצפה עם כדור פיטבול לפניכם.","הניחו את המרפקים על גבי כדור הפיטבול, כשאתם אוחזים משקולת בכל יד וכפות הידיים פונות מעלה.","כשהזרועות העליונות נייחות, נשפו החוצה וכופפו את המשקולות תוך כיווץ הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Kneel on the floor with an exercise ball in front of you.","Place your elbows on top of the exercise ball, holding a dumbbell in each hand with your palms facing up.","Keeping your upper arms stationary, exhale and curl the dumbbells while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"2JCuFTU"},{"id":"edb-0334","name":"הרחקת כתפיים לצדדים","name_en":"dumbbell lateral raise","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps"],"steps":["עמדו כשכפות הרגליים ברוחב הכתפיים ואחזו משקולת בכל יד, כפות הידיים פונות לגוף.","שמרו על גב ישר והפעילו את ליבת הגוף.","הרימו את הידיים לצדדים עד שהן מקבילות לרצפה, תוך שמירה על כיפוף קל במרפקים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הידיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body.","Keep your back straight and engage your core.","Raise your arms out to the sides until they are parallel to the floor, keeping a slight bend in your elbows.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"DsgkuIt"},{"id":"edb-0335","name":"הרמה קדמית לצדדים עם משקולות","name_en":"dumbbell lateral to front raise","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","biceps"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשבכל יד משקולת וכפות הידיים פונות לגוף.","שמרו על גב ישר והפעילו את ליבת הגוף.","הרימו את הידיים לצדדים עד שהן מקבילות לרצפה, תוך שמירה על כיפוף קל במרפקים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הידיים בחזרה לעמדת ההתחלה.","לאחר מכן, הרימו את הידיים לפניכם עד שהן מקבילות לרצפה, שוב תוך שמירה על כיפוף קל במרפקים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הידיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your body.","Keep your back straight and engage your core.","Raise your arms out to the sides until they are parallel to the ground, keeping a slight bend in your elbows.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Next, raise your arms in front of you until they are parallel to the ground, again keeping a slight bend in your elbows.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"xMjBKwn"},{"id":"edb-0336","name":"לאנג׳ עם משקולות","name_en":"dumbbell lunge","muscle":"glutes","equipment":"dumbbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשבכל יד משקולת.","צעדו קדימה עם הרגל הימנית, תוך הורדת הגוף לעמדת לאנג'.","שמרו על הגב ישר והחזה מורם בזמן שאתם מורידים את הגוף.","דחפו דרך העקב הימני כדי לחזור למצב ההתחלתי.","חזרו על התנועה עם הרגל השמאלית.","החליפו רגליים למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand.","Take a step forward with your right foot, lowering your body into a lunge position.","Keep your back straight and your chest up as you lower your body.","Push through your right heel to return to the starting position.","Repeat with your left leg.","Alternate legs for the desired number of repetitions."],"mediaId":"RRWFUcw"},{"id":"edb-1658","name":"כפיפת מרפק עם משקולות","name_en":"dumbbell lunge with bicep curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["quadriceps","hamstrings"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשבכל יד משקולת וכפות הידיים פונות קדימה.","צעדו קדימה עם כף הרגל הימנית והורידו את הגוף לתנוחת לאנג'. הברך הימנית צריכה להיות כפופה בזווית של 90 מעלות והברך השמאלית צריכה לרחף ממש מעל הרצפה.","תוך כדי הלאנג' קדימה, כופפו בו-זמנית את המשקולות לכיוון הכתפיים, כשהמרפקים קרובים לגוף.","עצרו לרגע בתחתית הלאנג', ולאחר מכן דחפו דרך העקב הימני כדי לחזור לתנוחת ההתחלה, תוך הורדת המשקולות בחזרה לצדי הגוף.","חזרו על הלאנג' וכפיפת הביצפס בצד הנגדי, תוך צעידה קדימה עם כף הרגל השמאלית.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing forward.","Take a step forward with your right foot, lowering your body into a lunge position. Your right knee should be bent at a 90-degree angle and your left knee should be hovering just above the ground.","As you lunge forward, simultaneously curl the dumbbells towards your shoulders, keeping your elbows close to your body.","Pause for a moment at the bottom of the lunge, then push through your right heel to return to the starting position, lowering the dumbbells back down to your sides.","Repeat the lunge and bicep curl on the opposite side, stepping forward with your left foot.","Continue alternating sides for the desired number of repetitions."],"mediaId":"Mz6lLcW"},{"id":"edb-0337","name":"פשיטה בשכיבה עם משקולות","name_en":"dumbbell lying extension (across face)","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שכבו על הגב על ספסל, כשכפות הרגליים שטוחות על הרצפה והראש בקצה הספסל.","אחזו משקולת בשתי הידיים ויישרו את הידיים ישר מעל החזה, כפות הידיים פונות זו לזו.","תוך שמירה על הזרועות העליונות נייחות, הורידו את המשקולת באיטיות בקשת מאחורי הראש עד שאמות הידיים מקבילות לרצפה.","עצרו לרגע, ולאחר מכן כווצו את הטריצפס כדי להחזיר את המשקולת לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Hold a dumbbell with both hands and extend your arms straight up above your chest, palms facing each other.","Keeping your upper arms stationary, slowly lower the dumbbell in an arc behind your head until your forearms are parallel to the ground.","Pause for a moment, then contract your triceps to bring the dumbbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"L2V5Nan"},{"id":"edb-1729","name":"פשיטה בשכיבה לסירוגין עם משקולות","name_en":"dumbbell lying alternate extension","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שכבו על ספסל כשבכל יד משקולת, כפות הידיים פונות זו לזו.","יישרו את הידיים ישר מעל החזה, תוך שמירה על כיפוף קל במרפקים.","הורידו משקולת אחת לכיוון הראש, תוך כיפוף המרפק, כשהיד השנייה נשארת ישרה.","עצרו לרגע בתחתית התנועה, ולאחר מכן הרימו את המשקולת בחזרה לתנוחת ההתחלה.","חזרו על התנועה עם היד השנייה, תוך החלפת צדדים למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with a dumbbell in each hand, palms facing each other.","Extend your arms straight up over your chest, keeping a slight bend in your elbows.","Lower one dumbbell down towards your head, bending at the elbow, while keeping the other arm extended.","Pause for a moment at the bottom, then raise the dumbbell back up to the starting position.","Repeat with the other arm, alternating sides for the desired number of repetitions."],"mediaId":"NfP83rA"},{"id":"edb-0338","name":"לחיצה בשכיבה עם משקולות","name_en":"dumbbell lying elbow press","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["שכבו ישר על ספסל כשמשקולת בכל יד, כפות הידיים פונות זו לזו והידיים ישרות מעל החזה.","הורידו את המשקולות לכיוון הכתפיים על ידי כיפוף המרפקים, תוך שמירה על הזרועות העליונות נייחות.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו את המשקולות בחזרה לתנוחת ההתחלה על ידי יישור המרפקים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with a dumbbell in each hand, palms facing each other and arms extended straight up over your chest.","Lower the dumbbells towards your shoulders by bending your elbows, keeping your upper arms stationary.","Pause for a moment at the bottom, then press the dumbbells back up to the starting position by extending your elbows.","Repeat for the desired number of repetitions."],"mediaId":"eOCOwIR"},{"id":"edb-0863","name":"dumbbell lying external shoulder rotation","name_en":"dumbbell lying external shoulder rotation","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["rotator cuff","triceps"],"steps":["שכבו על הצד על ספסל ישר כשהזרוע העליונה צמודה לגוף והמרפק כפוף ב-90 מעלות.","אחזו משקולת ביד כשכף היד פונה מטה.","תוך שמירה על הזרוע העליונה צמודה לגוף, סובבו את אמת היד באיטיות כלפי מעלה עד כמה שניתן.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את האמה באיטיות חזרה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Lie on your side on a flat bench with your upper arm against your side and your elbow bent 90 degrees.","Hold a dumbbell in your hand with your palm facing down.","Keeping your upper arm against your side, slowly rotate your forearm upward as far as possible.","Pause for a moment at the top, then slowly lower your forearm back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"bmBf7LN"},{"id":"edb-0339","name":"dumbbell lying femoral","name_en":"dumbbell lying femoral","muscle":"legs","equipment":"dumbbell","target":"hamstrings","bodyPart":"upper legs","secondaryMuscles":["glutes"],"steps":["שכבו ישר על הגב כשהרגליים ישרות ומשקולת מונחת על הבטן התחתונה.","כופפו את הברכיים והביאו את המשקולת לכיוון הישבן, כשכפות הרגליים שטוחות על הרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your legs extended and a dumbbell resting on your lower abdomen.","Bend your knees and bring the dumbbell towards your glutes, keeping your feet flat on the ground.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"FkBIE6a"},{"id":"edb-0340","name":"לחיצה בשכיבה עם משקולות","name_en":"dumbbell lying hammer press","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["שכבו ישר על ספסל כשמשקולת בכל יד, כפות הידיים פונות זו לזו והידיים ישרות כלפי מעלה.","הורידו את המשקולות לצידי החזה, כשהמרפקים בזווית של 90 מעלות.","דחפו את המשקולות בחזרה למעלה לעמדת ההתחלה, תוך פשיטת הידיים לגמרי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with a dumbbell in each hand, palms facing each other and arms extended straight up.","Lower the dumbbells to the sides of your chest, keeping your elbows at a 90-degree angle.","Press the dumbbells back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"7gdLIXa"},{"id":"edb-2470","name":"הרמה בשכיבה אחורי עם משקולות","name_en":"dumbbell lying on floor rear delt raise","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","rhomboids"],"steps":["שכבו על הבטן על הרצפה כשמשקולת בכל יד, כפות הידיים פונות זו לזו.","יישרו את הידיים ישר לפניכם, תוך שמירה על כיפוף קל במרפקים.","תוך הפעלת שרירי הכתפיים, הרימו את הידיים למעלה ולצדדים, וכווצו את השכמות זו לזו.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הידיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie face down on the floor with a dumbbell in each hand, palms facing each other.","Extend your arms straight out in front of you, keeping a slight bend in your elbows.","Engaging your shoulder muscles, lift your arms up and out to the sides, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Ion0XWz"},{"id":"edb-0341","name":"dumbbell lying one arm deltoid rear","name_en":"dumbbell lying one arm deltoid rear","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","rhomboids"],"steps":["שכבו על הבטן על ספסל ישר כשמשקולת אחת ביד, כף היד פונה פנימה.","יישרו את היד ישר לכיוון הרצפה, תוך שמירה עליה קרובה לגוף.","הרימו את היד למעלה ולאחור, וכווצו את השכמה לכיוון עמוד השדרה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את הזרוע לאט חזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Lie face down on a flat bench with a dumbbell in one hand, palm facing inwards.","Extend your arm straight down towards the floor, keeping it close to your body.","Raise your arm up and back, squeezing your shoulder blade towards your spine.","Pause for a moment at the top, then slowly lower your arm back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"gSw59a4"},{"id":"edb-0343","name":"לחיצה ביד אחת בשכיבה עם משקולות","name_en":"dumbbell lying one arm press","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["שכבו ישר על ספסל כשמשקולת אחת ביד וכפות הרגליים שטוחות על הרצפה.","אחזו את המשקולת בגובה הכתף כשכף היד פונה קדימה.","דחפו את המשקולת למעלה עד שהיד ישרה לגמרי.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ליד השנייה."],"steps_en":["Lie flat on a bench with a dumbbell in one hand and your feet flat on the ground.","Hold the dumbbell at shoulder level with your palm facing forward.","Press the dumbbell upward until your arm is fully extended.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"mediaId":"zGSIWQi"},{"id":"edb-0342","name":"לחיצה ביד אחת בשכיבה עם משקולות","name_en":"dumbbell lying one arm press v. 2","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["שכבו ישר על ספסל כשהגב נתמך וכפות הרגליים שטוחות על הרצפה.","אחזו משקולת ביד אחת כשכף היד פונה לכיוון הרגליים.","יישרו את היד כלפי מעלה לכיוון התקרה, תוך שמירה על כיפוף קל במרפק.","הורידו את המשקולת באיטיות לכיוון החזה, תוך שמירה על המרפק קרוב לגוף.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו את המשקולת בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ליד השנייה."],"steps_en":["Lie flat on a bench with your back supported and feet flat on the ground.","Hold a dumbbell in one hand with your palm facing towards your feet.","Extend your arm straight up towards the ceiling, keeping your elbow slightly bent.","Slowly lower the dumbbell down towards your chest, keeping your elbow close to your body.","Pause for a moment at the bottom, then push the dumbbell back up to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"mediaId":"K3dIO25"},{"id":"edb-0344","name":"פשיטת מרפק ביד אחת בשכיבה עם משקולות","name_en":"dumbbell lying one arm pronated triceps extension","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שכבו ישר על ספסל כשהגב והראש נתמכים וכפות הרגליים שטוחות על הרצפה.","אחזו משקולת ביד אחת כשכף היד פונה מטה, ויישרו את היד כלפי מעלה מעל הכתף.","תוך שמירה על הזרוע העליונה נייחת, הורידו את המשקולת באיטיות מאחורי הראש על ידי כיפוף המרפק.","עצרו לרגע בתחתית התנועה, ולאחר מכן יישרו את היד בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Lie flat on a bench with your back and head supported, and your feet flat on the ground.","Hold a dumbbell in one hand with your palm facing down, and extend your arm straight up above your shoulder.","Keeping your upper arm stationary, slowly lower the dumbbell behind your head by bending your elbow.","Pause for a moment at the bottom, then extend your arm back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"wyaqzOS"},{"id":"edb-0345","name":"הרחקת כתפיים לצדדים ביד אחת בשכיבה אחורי עם משקולות","name_en":"dumbbell lying one arm rear lateral raise","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","rhomboids"],"steps":["שכבו על הבטן על ספסל ישר כשמשקולת אחת ביד, תלויה לכיוון הרצפה.","שמרו על היד ישרה והרימו את המשקולת החוצה לצד, הרחק מהגוף.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות חזרה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ליד השנייה."],"steps_en":["Lie face down on a flat bench with a dumbbell in one hand, hanging towards the floor.","Keep your arm straight and lift the dumbbell out to the side, away from your body.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"mediaId":"KwFGiEP"},{"id":"edb-0346","name":"פשיטת מרפק ביד אחת בשכיבה עם משקולות","name_en":"dumbbell lying one arm supinated triceps extension","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שכבו ישר על ספסל כשהגב והראש נתמכים וכפות הרגליים שטוחות על הרצפה.","אחזו משקולת ביד אחת באחיזה תחתונה, ויישרו את היד ישר מעל הכתף.","תוך שמירה על הזרוע העליונה נייחת, הורידו את המשקולת באיטיות מאחורי הראש על ידי כיפוף המרפק.","עצרו לרגע בתחתית התנועה, ולאחר מכן יישרו את היד בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Lie flat on a bench with your back and head supported, and your feet flat on the ground.","Hold a dumbbell in one hand with an underhand grip, and extend your arm straight up above your shoulder.","Keeping your upper arm stationary, slowly lower the dumbbell behind your head by bending your elbow.","Pause for a moment at the bottom, then extend your arm back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"zZlORz6"},{"id":"edb-0347","name":"dumbbell lying pronation","name_en":"dumbbell lying pronation","muscle":"biceps","equipment":"dumbbell","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["biceps","shoulders"],"steps":["שכבו על ספסל כשהחזה פונה מטה והידיים ישרות כלפי מטה, כשאתם אוחזים משקולת בכל יד.","סובבו את כפות הידיים כך שיפנו מעלה.","תוך שמירה על הזרועות העליונות נייחות, נשפו וכופפו את המשקולות תוך כדי סיבוב כפות הידיים כך שיפנו מטה.","שאפו אוויר והורידו את המשקולות באיטיות בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your chest facing down and your arms extended straight down, holding a dumbbell in each hand.","Rotate your palms so they are facing up.","Keeping your upper arms stationary, exhale and curl the dumbbells as you rotate your palms to face down.","Inhale and slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"mym4hJo"},{"id":"edb-2705","name":"dumbbell lying pronation on floor","name_en":"dumbbell lying pronation on floor","muscle":"biceps","equipment":"dumbbell","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["biceps","triceps"],"steps":["שכבו ישר על הרצפה על הבטן כשהידיים ישרות לפניכם, ואתם אוחזים משקולת בכל יד.","סובבו את כפות הידיים כך שיפנו מטה לכיוון הרצפה.","תוך שמירה על הידיים ישרות, הרימו את המשקולות מהרצפה על ידי כיווץ אמות הידיים.","המשיכו להרים עד שאמות הידיים מכווצות לגמרי והמשקולות בגובה הכתפיים.","החזיקו לרגע, ולאחר מכן הורידו את המשקולות באיטיות בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on the floor with your face down and your arms extended straight out in front of you, holding a dumbbell in each hand.","Rotate your palms so they are facing down towards the floor.","Keeping your arms straight, lift the dumbbells off the floor by contracting your forearms.","Continue lifting until your forearms are fully contracted and the dumbbells are at shoulder level.","Hold for a moment, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"7RWNjiB"},{"id":"edb-1284","name":"פולאובר בשכיבה עם משקולות","name_en":"dumbbell lying pullover on exercise ball","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders","back"],"steps":["שבו על כדור פיטבול והתגלגלו קדימה עד שהגב העליון נשען על הכדור.","אחזו משקולת בשתי הידיים ויישרו את הידיים ישר מעל החזה.","הורידו את המשקולת באיטיות מאחורי הראש תוך שמירה על הידיים ישרות.","עצרו לרגע, ולאחר מכן הרימו את המשקולת בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on an exercise ball and roll forward until your upper back is resting on the ball.","Hold a dumbbell with both hands and extend your arms straight up over your chest.","Slowly lower the dumbbell behind your head while keeping your arms straight.","Pause for a moment, then raise the dumbbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"iK59oEA"},{"id":"edb-1328","name":"חתירת כתף אחורית בשכיבה עם משקולות","name_en":"dumbbell lying rear delt row","muscle":"back","equipment":"dumbbell","target":"upper back","bodyPart":"back","secondaryMuscles":["shoulders","biceps"],"steps":["שכבו על הבטן על ספסל ישר כשמשקולת בכל יד, כפות הידיים פונות פנימה.","יישרו את הידיים ישר לכיוון הרצפה, תוך שמירה על כיפוף קל במרפקים.","תוך הפעלת שרירי הגב, הרימו את המשקולות לכיוון החזה, וכווצו את השכמות זו לזו.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie face down on a flat bench with a dumbbell in each hand, palms facing inwards.","Extend your arms straight down towards the floor, keeping a slight bend in your elbows.","Engaging your back muscles, lift the dumbbells up towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"XUUD0Fs"},{"id":"edb-0348","name":"הרחקת כתפיים לצדדים בשכיבה אחורי עם משקולות","name_en":"dumbbell lying rear lateral raise","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","rhomboids"],"steps":["שכבו על הבטן על ספסל ישר כשמשקולת בכל יד, כפות הידיים פונות זו לזו.","יישרו את הידיים ישר לכיוון הרצפה, תוך שמירה על כיפוף קל במרפקים.","תוך הפעלת שרירי הכתפיים, הרימו את הידיים לצדדים עד שהן מקבילות לרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הידיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie face down on a flat bench with a dumbbell in each hand, palms facing each other.","Extend your arms straight down towards the floor, keeping a slight bend in your elbows.","Engaging your shoulder muscles, lift your arms out to the sides until they are parallel to the floor.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"53Ttlck"},{"id":"edb-1735","name":"פשיטה בשכיבה עם משקולות","name_en":"dumbbell lying single extension","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שכבו ישר על ספסל כשמשקולת אחת ביד והיד ישרה לגמרי מעל החזה.","הורידו את המשקולת באופן מבוקר לכיוון המצח, תוך שמירה על הזרוע העליונה נייחת.","עצרו לרגע קצר בתחתית התנועה, ולאחר מכן יישרו את היד בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Lie flat on a bench with a dumbbell in one hand and your arm fully extended above your chest.","Lower the dumbbell in a controlled manner towards your forehead, keeping your upper arm stationary.","Pause briefly at the bottom of the movement, then extend your arm back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"6MfS53i"},{"id":"edb-0349","name":"dumbbell lying supination","name_en":"dumbbell lying supination","muscle":"biceps","equipment":"dumbbell","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["biceps","shoulders"],"steps":["שכבו ישר על ספסל כשכפות הרגליים שטוחות על הרצפה.","אחזו משקולת בכל יד כשכפות הידיים פונות מעלה והידיים ישרות לגמרי.","תוך שמירה על הזרועות העליונות נייחות, כופפו את המשקולות לכיוון הכתפיים על ידי כיווץ אמות הידיים.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your feet flat on the ground.","Hold a dumbbell in each hand with your palms facing up and your arms fully extended.","Keeping your upper arms stationary, curl the dumbbells towards your shoulders by contracting your forearms.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"M2Pm3zj"},{"id":"edb-2706","name":"dumbbell lying supination on floor","name_en":"dumbbell lying supination on floor","muscle":"biceps","equipment":"dumbbell","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["biceps","shoulders"],"steps":["שכבו ישר על הגב על הרצפה כשהרגליים ישרות והידיים לצדי הגוף, ואתם אוחזים משקולת בכל יד.","סובבו את כפות הידיים כך שיפנו מעלה, תוך שמירה על המרפקים קרובים לגוף.","כופפו את המשקולות באיטיות לכיוון הכתפיים, תוך כיווץ אמות הידיים.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back on the floor with your legs extended and your arms by your sides, holding a dumbbell in each hand.","Rotate your palms to face up, keeping your elbows close to your sides.","Slowly curl the dumbbells towards your shoulders, squeezing your forearms.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"rEhi2o5"},{"id":"edb-1661","name":"כפיפת מרפק בשכיבה בשכיבה על הגב עם משקולות","name_en":"dumbbell lying supine biceps curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שכבו ישר על ספסל כשהגב והראש נתמכים וכפות הרגליים שטוחות על הרצפה.","אחזו משקולת בכל יד כשכפות הידיים פונות מעלה והידיים ישרות לגמרי.","תוך שמירה על הזרוע העליונה ללא תזוזה, נשפו החוצה וכופפו את המשקולות תוך כיווץ שרירי הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your back and head supported, and your feet flat on the ground.","Hold a dumbbell in each hand with your palms facing up and your arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"XVzF3iZ"},{"id":"edb-0350","name":"כפיפת מרפק בשכיבה בשכיבה על הגב עם משקולות","name_en":"dumbbell lying supine curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שכבו ישר על ספסל כשמשקולת בכל יד, כפות הידיים פונות מעלה והידיים ישרות לגמרי.","תוך שמירה על הזרוע העליונה ללא תזוזה, נשפו החוצה וכופפו את המשקולות תוך כיווץ שרירי הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with a dumbbell in each hand, palms facing up and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"KUaZst7"},{"id":"edb-0351","name":"פשיטת מרפק בשכיבה עם משקולות","name_en":"dumbbell lying triceps extension","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שכבו על ספסל כשבכל יד משקולת, כפות הידיים פונות זו לזו.","יישרו את הידיים ישר מעל החזה, תוך שמירה על המרפקים קרובים לגוף.","הורידו את המשקולות לכיוון המצח, תוך כיפוף המרפקים.","עצרו לרגע, ולאחר מכן יישרו את הידיים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with a dumbbell in each hand, palms facing each other.","Extend your arms straight up over your chest, keeping your elbows close to your body.","Lower the dumbbells down towards your forehead, bending your elbows.","Pause for a moment, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"mpKZGWz"},{"id":"edb-1662","name":"כפיפת מרפק בשכיבה רחב עם משקולות","name_en":"dumbbell lying wide curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שכבו ישר על ספסל כשמשקולת בכל יד, כפות הידיים פונות מעלה והידיים ישרות לגמרי.","תוך שמירה על הזרוע העליונה ללא תזוזה, נשפו החוצה וכופפו את המשקולות תוך כיווץ שרירי הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with a dumbbell in each hand, palms facing up and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"qm9veZw"},{"id":"edb-0352","name":"לחיצת חזה אחיזה ניטרלית עם משקולות","name_en":"dumbbell neutral grip bench press","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["שכבו על ספסל כשכפות הרגליים שטוחות על הרצפה והגב צמוד לספסל.","אחזו משקולת בכל יד באחיזה ניטרלית (כפות הידיים פונות זו לזו) והידיים ישרות מעל החזה.","הורידו את המשקולות באיטיות לכיוון החזה, תוך שמירה על המרפקים קרובים לגוף.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו את המשקולות בחזרה לתנוחת ההתחלה, תוך יישור מלא של הידיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Hold a dumbbell in each hand with a neutral grip (palms facing each other) and your arms extended straight up over your chest.","Slowly lower the dumbbells down towards your chest, keeping your elbows close to your body.","Pause for a moment at the bottom, then push the dumbbells back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"pP8wP2P"},{"id":"edb-1285","name":"פרפר ביד אחת עם משקולות","name_en":"dumbbell one arm bench fly","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders"],"steps":["שבו על ספסל ישר כשמשקולת אחת ביד, מונחת על הירך.","שכבו על הספסל, תוך שמירה על המשקולת צמודה לירך.","בעזרת היד הפנויה, סייעו בהרמת המשקולת לתנוחת ההתחלה.","אחזו את המשקולת ישירות מעל הכתף כשהיד ישרה וכף היד פונה פנימה.","הורידו את המשקולת החוצה לצד בקשת רחבה, תוך שמירה על כיפוף קל במרפק.","עצרו כשהיד מקבילה לרצפה, ולאחר מכן הפכו את התנועה והחזירו את המשקולת לתנוחת ההתחלה.","חזרו על התנועה למספר החזרות הרצוי, ולאחר מכן החליפו ידיים וחזרו שוב."],"steps_en":["Sit on a flat bench with a dumbbell in one hand, resting it on top of your thigh.","Lie back on the bench, keeping the dumbbell pressed against your thigh.","Using your free hand, help lift the dumbbell up to the starting position.","Hold the dumbbell directly above your shoulder with your arm extended and palm facing inward.","Lower the dumbbell out to the side in a wide arc, keeping a slight bend in your elbow.","Pause when your arm is parallel to the ground, then reverse the movement and bring the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms and repeat."],"mediaId":"o5Jsk92"},{"id":"edb-0292","name":"חתירה בהטיה ביד אחת עם משקולות","name_en":"dumbbell one arm bent-over row","muscle":"back","equipment":"dumbbell","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["עמדו כשכפות הרגליים ברוחב הכתפיים, ואחזו משקולת ביד אחת כשכף היד פונה לגוף.","כופפו את הברכיים מעט והטו את הגוף קדימה ממפרקי הירך, תוך שמירה על גב ישר והפעלת שרירי הליבה.","תנו למשקולת להיתלות ישר למטה לכיוון הרצפה, כשהיד ישרה לגמרי.","משכו את המשקולת כלפי מעלה לכיוון החזה, תוך שמירה על המרפק קרוב לגוף וכיווץ השכמות יחד.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות חזרה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in one hand with your palm facing your body.","Bend your knees slightly and hinge forward at the hips, keeping your back straight and your core engaged.","Let the dumbbell hang straight down towards the floor, with your arm fully extended.","Pull the dumbbell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"C0MA9bC"},{"id":"edb-1286","name":"פרפר ביד אחת עם משקולות","name_en":"dumbbell one arm chest fly on exercise ball","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["שבו על כדור פיטבול כשמשקולת אחת ביד וכפות הרגליים שטוחות על הרצפה.","צעדו עם הרגליים קדימה, גלגלו את הכדור עד שהגב העליון נשען עליו והראש, הצוואר והכתפיים מחוץ לכדור.","יישרו את היד עם המשקולת כלפי מעלה מעל החזה, כף היד פונה פנימה.","הורידו את המשקולת באיטיות החוצה לצד, תוך שמירה על כיפוף קל במרפק.","עצרו לרגע כשהיד מקבילה לרצפה.","הפעילו את שרירי החזה כדי להחזיר את המשקולת לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Sit on an exercise ball with a dumbbell in one hand and your feet flat on the ground.","Walk your feet forward, rolling the ball until your upper back is supported on the ball and your head, neck, and shoulders are off the ball.","Extend your arm with the dumbbell straight up above your chest, palm facing inward.","Slowly lower the dumbbell out to the side, keeping a slight bend in your elbow.","Pause for a moment when your arm is parallel to the ground.","Engage your chest muscles to bring the dumbbell back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"Bpkf41o"},{"id":"edb-0353","name":"כפיפת מרפק ביד אחת עם כדור פיזיו","name_en":"dumbbell one arm concentration curl (on stability ball)","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על כדור יציבות כשכפות הרגליים מונחות שטוח על הרצפה והברכיים כפופות בזווית של 90 מעלות.","אחזו משקולת ביד אחת כשכף היד פונה מעלה והיד ישרה כלפי מטה לכיוון הרצפה.","הניחו את המרפק על החלק הפנימי של הירך, ממש מעל הברך.","תוך שמירה על הזרוע העליונה נייחת, נשפו וכופפו את המשקולת כלפי מעלה לכיוון הכתף תוך כיווץ הביצפס.","עצרו לרגע בשיא התנועה, ולאחר מכן שאפו אוויר והורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה.","חזרו על התנועה למספר החזרות הרצוי, ולאחר מכן החליפו ידיים וחזרו שוב."],"steps_en":["Sit on a stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Hold a dumbbell in one hand with your palm facing up and your arm extended down towards the floor.","Rest your elbow on the inside of your thigh, just above the knee.","Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder while contracting your biceps.","Pause for a moment at the top of the movement, then inhale and slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch arms and repeat."],"mediaId":"k5IpyHg"},{"id":"edb-1287","name":"לחיצת חזה ביד אחת בשיפוע שלילי עם משקולות","name_en":"dumbbell one arm decline chest press","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["שכבו על ספסל בשיפוע שלילי כשמשקולת ביד אחת מונחת על החזה.","הניחו את כפות הרגליים שטוחות על הרצפה ושמרו על הגב צמוד לספסל.","יישרו את היד ודחפו את המשקולת כלפי מעלה לכיוון התקרה, תוך יישור מלא של המרפק.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות חזרה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ליד השנייה."],"steps_en":["Lie on a decline bench with a dumbbell in one hand, resting on your chest.","Place your feet flat on the ground and keep your back pressed against the bench.","Extend your arm and push the dumbbell up towards the ceiling, fully extending your elbow.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"mediaId":"REGM1dE"},{"id":"edb-1288","name":"פרפר ביד אחת עם משקולות","name_en":"dumbbell one arm fly on exercise ball","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["שבו על כדור פיטבול כשמשקולת אחת ביד וכפות הרגליים שטוחות על הרצפה.","צעדו עם הרגליים קדימה וגלגלו את הגוף למטה עד שהגב העליון נשען על כדור הפיטבול.","יישרו את היד עם המשקולת כלפי מעלה מעל החזה, כף היד פונה פנימה.","הורידו את המשקולת באיטיות החוצה לצד, תוך שמירה על כיפוף קל במרפק.","עצרו לרגע, ולאחר מכן כווצו את שרירי החזה כדי להחזיר את המשקולת לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Sit on an exercise ball with a dumbbell in one hand and your feet flat on the ground.","Walk your feet forward and roll your body down until your upper back is resting on the exercise ball.","Extend your arm with the dumbbell straight up above your chest, palm facing inwards.","Slowly lower the dumbbell out to the side, keeping a slight bend in your elbow.","Pause for a moment, then squeeze your chest muscles to bring the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"Am02iPd"},{"id":"edb-1736","name":"לחיצה ביד אחת עם משקולות","name_en":"dumbbell one arm french press on exercise ball","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שבו על כדור התעמלות כשכפות הרגליים שטוחות על הרצפה והגב ישר.","אחזו משקולת ביד אחת כשכף היד פונה מעלה והמרפק כפוף בזווית של 90 מעלות.","יישרו את היד כלפי מעלה לכיוון התקרה, תוך שמירה על המרפק נייח.","הורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in one hand with your palm facing up and your elbow bent at a 90-degree angle.","Extend your arm straight up towards the ceiling, keeping your elbow stationary.","Slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"ziFKQXP"},{"id":"edb-1663","name":"כפיפת מרפק בכיסא הטפה ביד אחת עם משקולות","name_en":"dumbbell one arm hammer preacher curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל סקוט כשמשקולת אחת ביד והזרוע העליונה מונחת על הכרית.","אחזו את המשקולת באחיזה ניטרלית (כף היד פונה לגוף).","תוך שמירה על הזרוע העליונה נייחת, נשפו וכופפו את המשקולת כלפי מעלה לכיוון הכתף.","עצרו לרגע בשיא התנועה, תוך כיווץ שרירי הביצפס.","שאפו אוויר והורידו לאט את המשקולת בחזרה לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Sit on a preacher bench with a dumbbell in one hand and your upper arm resting on the pad.","Hold the dumbbell with a neutral grip (palms facing your body).","Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"4dF3maG"},{"id":"edb-1621","name":"לחיצה ביד אחת עם משקולות","name_en":"dumbbell one arm hammer press on exercise ball","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders","chest"],"steps":["שבו על כדור התעמלות כשכפות הרגליים שטוחות על הרצפה והגב ישר.","אחזו משקולת ביד אחת כשכף היד פונה פנימה והמרפק כפוף בזווית של 90 מעלות.","הניחו את היד השנייה על הירך לשם יציבות.","דחפו את המשקולת כלפי מעלה, תוך יישור מלא של היד.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in one hand with your palm facing inwards and your elbow bent at a 90-degree angle.","Place your other hand on your hip for stability.","Press the dumbbell upwards, extending your arm fully.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"VYmYxK5"},{"id":"edb-1289","name":"לחיצת חזה ביד אחת בשיפוע עם משקולות","name_en":"dumbbell one arm incline chest press","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["כווננו את הספסל המשופע לזווית של 45 מעלות.","שבו על הספסל כשהגב נשען על הכרית וכפות הרגליים שטוחות על הרצפה.","אחזו משקולת ביד אחת באחיזה עליונה, כשהיא מונחת על הכתף.","דחפו את המשקולת למעלה והרחק מהגוף, תוך יישור מלא של היד.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות חזרה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ליד השנייה."],"steps_en":["Adjust the incline bench to a 45-degree angle.","Sit on the bench with your back against the pad and feet flat on the ground.","Hold a dumbbell in one hand with an overhand grip, resting it on your shoulder.","Push the dumbbell up and away from your body, extending your arm fully.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"mediaId":"PDaMuyV"},{"id":"edb-0354","name":"בעיטה אחורית ביד אחת עם משקולות","name_en":"dumbbell one arm kickback","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["עמדו כשכפות הרגליים ברוחב הכתפיים ואחזו משקולת ביד ימין.","כופפו מעט את הברכיים והטו את הגוף קדימה במפרקי הירך, תוך שמירה על גב ישר.","הביאו את המרפק הימני כלפי מעלה לצד הגוף, כשהוא כפוף בזווית של 90 מעלות.","יישרו את היד הימנית ישר לאחור, וכווצו את הטריצפס בשיא התנועה.","הורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Stand with your feet shoulder-width apart and hold a dumbbell in your right hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Bring your right elbow up to your side, keeping it bent at a 90-degree angle.","Extend your right arm straight back, squeezing your triceps at the top of the movement.","Slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"bQy2Eni"},{"id":"edb-0355","name":"הרחקת כתפיים לצדדים ביד אחת עם משקולות","name_en":"dumbbell one arm lateral raise","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","triceps"],"steps":["עמדו כשכפות הרגליים ברוחב הכתפיים, ואחזו משקולת ביד אחת כשכף היד פונה לגוף.","שמרו על הגב ישר ושרירי הליבה מופעלים לאורך כל התרגיל.","הרימו את המשקולת לצד, כשהיד ישרה וכף היד פונה מטה.","המשיכו להרים עד שהיד מקבילה לרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ליד השנייה."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in one hand with your palm facing your body.","Keep your back straight and your core engaged throughout the exercise.","Raise the dumbbell to the side, keeping your arm straight and your palm facing down.","Continue lifting until your arm is parallel to the ground.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"mediaId":"n5cWCsI"},{"id":"edb-0356","name":"הרחקת כתפיים לצדדים ביד אחת עם משקולות","name_en":"dumbbell one arm lateral raise with support","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","rotator cuff"],"steps":["עמדו כשכפות הרגליים ברוחב הכתפיים ואחזו משקולת ביד אחת, כף היד פונה לגוף.","הניחו את היד השנייה על משטח יציב, כגון ספסל או קיר, לתמיכה.","שמרו על גב ישר והפעילו את ליבת הגוף.","הרימו את המשקולת החוצה לצד, כשהיד ישרה וכף היד פונה מטה.","המשיכו להרים עד שהיד מקבילה לרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות חזרה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Stand with your feet shoulder-width apart and hold a dumbbell in one hand, with your palm facing your body.","Place your other hand on a stable surface, such as a bench or wall, for support.","Keep your back straight and engage your core.","Raise the dumbbell out to the side, keeping your arm straight and your palm facing down.","Continue lifting until your arm is parallel to the ground.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"Yg7MJAT"},{"id":"edb-1290","name":"לחיצה ביד אחת עם משקולות","name_en":"dumbbell one arm press on exercise ball","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps","core"],"steps":["שבו על כדור פיטבול כשכפות הרגליים שטוחות על הרצפה והברכיים כפופות בזווית של 90 מעלות.","אחזו משקולת ביד אחת ומקמו אותה בגובה הכתף, כשהמרפק כפוף וכף היד פונה קדימה.","דחפו את המשקולת באיטיות כלפי מעלה עד שהיד ישרה לגמרי, תוך שמירה על הליבה מופעלת ושמירה על שיווי המשקל על כדור הפיטבול.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ליד השנייה."],"steps_en":["Sit on an exercise ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Hold a dumbbell in one hand and position it at shoulder height, with your elbow bent and palm facing forward.","Slowly press the dumbbell upward until your arm is fully extended, while keeping your core engaged and maintaining balance on the exercise ball.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"mediaId":"QZFv5ui"},{"id":"edb-1665","name":"כפיפת מרפק ביד אחת בשכיבה על הבטן עם משקולות","name_en":"dumbbell one arm prone curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שכבו על הבטן על ספסל ישר כשמשקולת אחת ביד, כף היד פונה מטה.","יישרו את היד לגמרי, ותנו לה להיתלות ישר למטה לכיוון הרצפה.","תוך שמירה על הזרוע העליונה נייחת, כופפו את המשקולת כלפי מעלה לכיוון הכתף על ידי כיווץ הביצפס.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות חזרה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Lie face down on a flat bench with a dumbbell in one hand, palm facing down.","Extend your arm fully, letting it hang straight down towards the floor.","Keeping your upper arm stationary, curl the dumbbell up towards your shoulder by contracting your biceps.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"JWjujiY"},{"id":"edb-1666","name":"כפיפת פטיש ביד אחת בשכיבה על הבטן עם משקולות","name_en":"dumbbell one arm prone hammer curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שכבו על הבטן על ספסל ישר כשמשקולת אחת ביד, כף היד פונה לגוף והיד ישרה לגמרי.","שמרו על הזרוע העליונה נייחת וכופפו את המשקולת לכיוון הכתף, תוך כיווץ הביצפס.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Lie face down on a flat bench with a dumbbell in one hand, palm facing your body and arm fully extended.","Keep your upper arm stationary and curl the dumbbell towards your shoulder, contracting your biceps.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"LIGZSTA"},{"id":"edb-1291","name":"פולאובר ביד אחת עם משקולות","name_en":"dumbbell one arm pullover on exercise ball","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","latissimus dorsi","rhomboids"],"steps":["שבו על כדור פיטבול כשכפות הרגליים שטוחות על הרצפה והברכיים כפופות בזווית של 90 מעלות.","אחזו משקולת ביד אחת ויישרו את היד ישר מעל החזה.","הורידו את המשקולת באיטיות מאחורי הראש תוך שמירה על היד ישרה.","עצרו לרגע, ולאחר מכן הרימו את המשקולת בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Sit on an exercise ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Hold a dumbbell with one hand and extend your arm straight up above your chest.","Slowly lower the dumbbell behind your head while keeping your arm straight.","Pause for a moment, then raise the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"bQHPBU3"},{"id":"edb-0358","name":"כפיפת שורש כף היד ביד אחת הפוך עם משקולות","name_en":"dumbbell one arm reverse wrist curl","muscle":"biceps","equipment":"dumbbell","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["wrist extensors"],"steps":["שבו על ספסל או כיסא כשכפות הרגליים שטוחות על הרצפה.","אחזו משקולת ביד אחת באחיזה עליונה, כף היד פונה מטה.","הניחו את אמת היד על הירך, כששורש כף היד תלוי מעבר לקצה.","הורידו את המשקולת באיטיות לכיוון הרצפה על ידי כיפוף שורש כף היד.","עצרו לרגע בתחתית התנועה, ולאחר מכן כופפו את שורש כף היד באיטיות בחזרה כלפי מעלה לכיוון הגוף.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ליד השנייה."],"steps_en":["Sit on a bench or chair with your feet flat on the ground.","Hold a dumbbell in one hand with an overhand grip, palm facing down.","Rest your forearm on your thigh, with your wrist hanging off the edge.","Slowly lower the dumbbell towards the ground by flexing your wrist.","Pause for a moment at the bottom, then slowly curl your wrist back up towards your body.","Repeat for the desired number of repetitions, then switch to the other arm."],"mediaId":"BwSNDGt"},{"id":"edb-0359","name":"פרפר הפוך ביד אחת עם משקולות","name_en":"dumbbell one arm reverse fly (with support)","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","rhomboids"],"steps":["שבו על ספסל כשכפות הרגליים שטוחות על הרצפה והגב ישר.","אחזו משקולת ביד אחת כשכף היד פונה פנימה.","הישענו קדימה והניחו את היד הפנויה על הספסל לתמיכה.","שמרו על היד כפופה מעט והרימו אותה החוצה לצד עד שהיא מקבילה לרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את הזרוע לאט חזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Sit on a bench with your feet flat on the ground and your back straight.","Hold a dumbbell in one hand with your palm facing inwards.","Lean forward and place your free hand on the bench for support.","Keep your arm slightly bent and raise it out to the side until it is parallel to the ground.","Pause for a moment at the top, then slowly lower your arm back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"e25F58f"},{"id":"edb-1622","name":"לחיצה ביד אחת אחיזה הפוכה עם משקולות","name_en":"dumbbell one arm reverse grip press","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["שבו על ספסל ישר כשמשקולת אחת ביד, כף היד פונה לגוף.","הניחו את כפות הרגליים שטוחות על הרצפה ושמרו על הגב ישר.","הרימו את המשקולת לגובה הכתף, תוך שמירה על המרפק קרוב לגוף.","דחפו את המשקולת כלפי מעלה עד שהיד ישרה לגמרי.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ליד השנייה."],"steps_en":["Sit on a flat bench with a dumbbell in one hand, palm facing towards your body.","Place your feet flat on the ground and keep your back straight.","Raise the dumbbell to shoulder height, keeping your elbow close to your body.","Press the dumbbell upwards until your arm is fully extended.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"mediaId":"Ze7MoIb"},{"id":"edb-1414","name":"כפיפת מרפק בכיסא הטפה ביד אחת הפוך עם משקולות","name_en":"dumbbell one arm reverse preacher curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל סקוט כשהחזה צמוד לכרית והיד ישרה מעל קצה הספסל, ואתם אוחזים משקולת באחיזה תחתונה.","הורידו את המשקולת באיטיות עד שהיד ישרה לגמרי.","כופפו את המשקולת בחזרה כלפי מעלה לכיוון הכתף, תוך שמירה על הזרוע העליונה נייחת.","כווצו את הביצפס בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Sit on a preacher bench with your chest against the pad and your arm extended over the edge of the bench, holding a dumbbell with an underhand grip.","Lower the dumbbell slowly until your arm is fully extended.","Curl the dumbbell back up towards your shoulder, keeping your upper arm stationary.","Squeeze your biceps at the top of the movement, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"bWxq4op"},{"id":"edb-1667","name":"כפיפת מרפק ביד אחת הפוך עם משקולות","name_en":"dumbbell one arm reverse spider curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף כשמשקולת אחת ביד, כף היד פונה מטה והיד ישרה לגמרי.","תוך שמירה על הזרוע העליונה נייחת, כופפו את המשקולת לכיוון הכתף על ידי כיפוף המרפק.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Stand up straight with a dumbbell in one hand, palm facing down and arm fully extended.","Keeping your upper arm stationary, curl the dumbbell towards your shoulder by flexing your elbow.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"VdLZ3nB"},{"id":"edb-1668","name":"כפיפת מרפק ביד אחת בישיבה עם משקולות","name_en":"dumbbell one arm seated bicep curl on exercise ball","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על כדור התעמלות כשכפות הרגליים שטוחות על הרצפה והגב ישר.","אחזו משקולת ביד אחת כשכף היד פונה מעלה והיד ישרה לגמרי.","תוך שמירה על הזרוע העליונה נייחת, כופפו את המשקולת לכיוון הכתף על ידי כיווץ הביצפס.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in one hand with your palm facing up and your arm fully extended.","Keeping your upper arm stationary, curl the dumbbell towards your shoulder by contracting your biceps.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"s999Hdo"},{"id":"edb-1669","name":"כפיפת פטיש ביד אחת בישיבה עם משקולות","name_en":"dumbbell one arm seated hammer curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל עם גב ישר וכפות רגליים שטוחות על הרצפה.","אחזו משקולת ביד אחת באחיזה ניטרלית (כפות הידיים פונות זו לזו).","הניחו את המרפק על החלק הפנימי של הירך, ממש מעל הברך.","תוך שמירה על הזרוע העליונה נייחת, נשפו וכופפו את המשקולת כלפי מעלה לכיוון הכתף.","עצרו לרגע בשיא התנועה, תוך כיווץ שרירי הביצפס.","שאפו אוויר והורידו לאט את המשקולת בחזרה לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell in one hand with a neutral grip (palms facing each other).","Rest your elbow on the inside of your thigh, just above the knee.","Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"jK2hZ6n"},{"id":"edb-1415","name":"כפיפת שורש כף היד ביד אחת בישיבה עם משקולות","name_en":"dumbbell one arm seated neutral wrist curl","muscle":"biceps","equipment":"dumbbell","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["biceps","brachialis"],"steps":["שבו על ספסל כשכפות הרגליים שטוחות על הרצפה ואחזו משקולת ביד אחת, כף היד פונה מעלה.","הניחו את אמת היד על הירך, כך ששורש כף היד תלוי מעבר לקצה.","תוך שמירה על אמת היד נייחת, כופפו את שורש כף היד כלפי מעלה עד כמה שניתן.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את שורש כף היד באיטיות בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, לאחר מכן עברו ליד השנייה."],"steps_en":["Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand, palm facing up.","Rest your forearm on your thigh, allowing your wrist to hang off the edge.","Keeping your forearm stationary, curl your wrist upward as far as possible.","Pause for a moment at the top, then slowly lower your wrist back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other hand."],"mediaId":"YtaCTYl"},{"id":"edb-0361","name":"לחיצת כתפיים ביד אחת עם משקולות","name_en":"dumbbell one arm shoulder press","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["עמדו כשכפות הרגליים ברוחב הכתפיים ואחזו משקולת ביד אחת בגובה הכתף, כף היד פונה קדימה.","דחפו את המשקולת כלפי מעלה עד שהיד ישרה לגמרי מעל הראש.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ליד השנייה."],"steps_en":["Stand with your feet shoulder-width apart and hold a dumbbell in one hand at shoulder level, palm facing forward.","Press the dumbbell upward until your arm is fully extended overhead.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"mediaId":"84RyJf8"},{"id":"edb-0360","name":"לחיצת כתפיים ביד אחת עם משקולות","name_en":"dumbbell one arm shoulder press v. 2","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["עמדו כשכפות הרגליים ברוחב הכתפיים ואחזו משקולת ביד אחת בגובה הכתף, כף היד פונה קדימה.","הפעילו את הליבה ודחפו את המשקולת ישר כלפי מעלה מעל הראש, תוך יישור מלא של היד.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות בחזרה לגובה הכתף.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ליד השנייה."],"steps_en":["Stand with your feet shoulder-width apart and hold a dumbbell in one hand at shoulder level, palm facing forward.","Engage your core and press the dumbbell straight up overhead, fully extending your arm.","Pause for a moment at the top, then slowly lower the dumbbell back to shoulder level.","Repeat for the desired number of repetitions, then switch to the other arm."],"mediaId":"1TkiAFK"},{"id":"edb-3888","name":"סנאץ׳ ביד אחת עם משקולות","name_en":"dumbbell one arm snatch","muscle":"glutes","equipment":"dumbbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps","core"],"steps":["עמדו כשכפות הרגליים ברוחב הכתפיים, ואחזו משקולת ביד אחת באחיזה עליונה.","כופפו את הברכיים מעט והתכופפו קדימה מהירכיים, תוך שמירה על גב ישר וחזה מורם.","הורידו את המשקולת לכיוון הרצפה, תוך שמירה עליה קרובה לגוף.","יישרו בפיצוץ את הירכיים, הברכיים והקרסוליים, תוך הנעת המשקולת כלפי מעלה בקו ישר.","כשהמשקולת מגיעה לגובה הכתף, סובבו במהירות את היד ודחפו אותה מעל הראש, תוך יישור מלא של היד.","קלטו את המשקולת מעל הראש עם כיפוף קל בברכיים ובירכיים.","הורידו את המשקולת בחזרה לתנוחת ההתחלה באופן מבוקר.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ליד השנייה."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in one hand with an overhand grip.","Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up.","Lower the dumbbell towards the ground, keeping it close to your body.","Explosively extend your hips, knees, and ankles, driving the dumbbell upwards in a straight line.","As the dumbbell reaches shoulder height, quickly rotate your hand and punch it overhead, fully extending your arm.","Catch the dumbbell overhead with a slight bend in your knees and hips.","Lower the dumbbell back down to the starting position in a controlled manner.","Repeat for the desired number of repetitions, then switch to the other arm."],"mediaId":"6pTkI99"},{"id":"edb-1670","name":"כפיפת מרפק ביד אחת בעמידה עם משקולות","name_en":"dumbbell one arm standing curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף כשמשקולת אחת ביד, כף היד פונה קדימה והיד ישרה לגמרי.","תוך שמירה על הזרוע העליונה נייחת, נשפו וכופפו את המשקולת כלפי מעלה תוך כיווץ הביצפס.","המשיכו להרים את המשקולת עד שהביצפס מכווץ לגמרי והמשקולת בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והורידו לאט את המשקולת בחזרה לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Stand up straight with a dumbbell in one hand, palm facing forward and arm fully extended.","Keeping your upper arm stationary, exhale and curl the weight upward while contracting your biceps.","Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"ffQsyBj"},{"id":"edb-1671","name":"כפיפת פטיש ביד אחת בעמידה עם משקולות","name_en":"dumbbell one arm standing hammer curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף כשבכל יד משקולת, כפות הידיים פונות לגוף.","שמרו על המרפקים קרובים לגוף והזרוע העליונה ללא תנועה.","נשפו החוצה וכופפו את המשקולות תוך כיווץ הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand up straight with a dumbbell in each hand, palms facing your torso.","Keep your elbows close to your torso and your upper arms stationary.","Exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"2sQGZ5b"},{"id":"edb-0362","name":"פשיטת מרפק ביד אחת עם משקולות","name_en":"dumbbell one arm triceps extension (on bench)","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שבו על ספסל עם גב ישר וכפות רגליים שטוחות על הרצפה.","אחזו משקולת ביד אחת והניחו את היד השנייה על הספסל לתמיכה.","הרימו את המשקולת מעל הראש, תוך שמירה על הזרוע העליונה קרובה לראש והמרפק פונה קדימה.","הורידו את המשקולת מאחורי הראש על ידי כיפוף המרפק, תוך שמירה על הזרוע העליונה נייחת.","יישרו את היד בחזרה לתנוחת ההתחלה, תוך יישור מלא של המרפק.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell in one hand and place your other hand on the bench for support.","Raise the dumbbell overhead, keeping your upper arm close to your head and your elbow pointing forward.","Lower the dumbbell behind your head by bending your elbow, keeping your upper arm stationary.","Extend your arm back up to the starting position, fully straightening your elbow.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"nAuHPcD"},{"id":"edb-0363","name":"חתירה זקופה ביד אחת עם משקולות","name_en":"dumbbell one arm upright row","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","biceps"],"steps":["עמדו כשכפות הרגליים ברוחב הכתפיים, ואחזו משקולת ביד אחת באחיזה עליונה.","תנו למשקולת להיתלות באורך הזרוע לפני הירכיים, כשכף היד פונה לגוף.","תוך שמירה על הגב ישר והליבה מופעלת, נשפו והרימו את המשקולת ישר כלפי מעלה לכיוון הסנטר, כשהמרפק מוביל את התנועה.","עצרו לרגע בשיא התנועה, ולאחר מכן שאפו אוויר והורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ליד השנייה."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in one hand with an overhand grip.","Let the dumbbell hang at arm's length in front of your thighs, with your palm facing your body.","Keeping your back straight and your core engaged, exhale and lift the dumbbell straight up towards your chin, leading with your elbow.","Pause for a moment at the top, then inhale and slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"mediaId":"6cKQC5E"},{"id":"edb-0364","name":"כפיפת שורש כף היד ביד אחת עם משקולות","name_en":"dumbbell one arm wrist curl","muscle":"biceps","equipment":"dumbbell","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["biceps","brachialis"],"steps":["שבו על ספסל או כיסא כשכפות הרגליים שטוחות על הרצפה.","אחזו משקולת ביד אחת באחיזה תחתונה, כשאמת היד מונחת על הירך.","תנו לשורש כף היד להתרחב, כך שהמשקולת תתגלגל לכיוון האצבעות.","כופפו את שורש כף היד באיטיות בחזרה כלפי מעלה, תוך הבאת המשקולת לכיוון אמת היד.","חזרו למספר החזרות הרצוי, לאחר מכן עברו ליד השנייה."],"steps_en":["Sit on a bench or chair with your feet flat on the ground.","Hold a dumbbell in one hand with an underhand grip, resting your forearm on your thigh.","Allow your wrist to extend, letting the dumbbell roll down towards your fingers.","Slowly curl your wrist back up, bringing the dumbbell towards your forearm.","Repeat for the desired number of repetitions, then switch to the other hand."],"mediaId":"q8aHNoF"},{"id":"edb-1672","name":"כפיפת מרפק בכיסא הטפה ביד אחת עם משקולות","name_en":"dumbbell one arm zottman preacher curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל סקוט ואחזו משקולת ביד אחת באחיזה תחתונה.","הניחו את הזרוע העליונה על כרית ספסל הסקוט, כך שהיד תוכל להתיישר לגמרי.","כופפו את המשקולת כלפי מעלה לכיוון הכתף, תוך שמירה על הזרוע העליונה נייחת.","בשיא הכפיפה, סובבו את שורש כף היד כך שכף היד תפנה מעלה.","הורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה, תוך סיבוב שורש כף היד בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Sit on a preacher curl bench and hold a dumbbell in one hand with an underhand grip.","Rest your upper arm on the preacher bench pad, allowing your arm to fully extend.","Curl the dumbbell up towards your shoulder, keeping your upper arm stationary.","At the top of the curl, rotate your wrist so that your palm faces up.","Slowly lower the dumbbell back down to the starting position, rotating your wrist back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"sxY5Biu"},{"id":"edb-1292","name":"פרפר ברגל אחת עם משקולות","name_en":"dumbbell one leg fly on exercise ball","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["שבו על כדור פיטבול כשמשקולת בכל יד, כפות הידיים פונות זו לזו.","הניחו רגל אחת על הרצפה ויישרו את הרגל השנייה ישר לפניכם.","הישענו מעט קדימה והביאו את הידיים לצדדים, תוך שמירה על כיפוף קל במרפקים.","הורידו את המשקולות באיטיות למטה ולצדדים, תוך הרגשת מתיחה בחזה.","עצרו לרגע בתחתית התנועה, ולאחר מכן כווצו את שרירי החזה כדי להחזיר את המשקולות לתנוחת ההתחלה.","חזרו על התנועה למספר החזרות הרצוי, ולאחר מכן החליפו רגליים וחזרו שוב."],"steps_en":["Sit on an exercise ball with a dumbbell in each hand, palms facing each other.","Place one foot on the ground and extend the other leg straight out in front of you.","Lean forward slightly and bring your arms out to the sides, keeping a slight bend in your elbows.","Slowly lower the dumbbells down and out to the sides, feeling a stretch in your chest.","Pause for a moment at the bottom, then squeeze your chest muscles to bring the dumbbells back up to the starting position.","Repeat for the desired number of repetitions, then switch legs and repeat."],"mediaId":"pH2x2jj"},{"id":"edb-0365","name":"כפיפת שורש כף היד עם משקולות","name_en":"dumbbell over bench neutral wrist curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל כשכפות הרגליים שטוחות על הרצפה ואחזו משקולת בכל יד, כפות הידיים פונות מעלה.","הניחו את האמות על הספסל, כששורשי כף היד תלויים מעבר לקצה.","תוך שמירה על הזרועות העליונות נייחות, נשפו וכופפו את המשקולות כלפי מעלה לכיוון הכתפיים.","עצרו לרגע בשיא התנועה, לאחר מכן שאפו אוויר והורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing up.","Rest your forearms on the bench, allowing your wrists to hang off the edge.","Keeping your upper arms stationary, exhale and curl the dumbbells up towards your shoulders.","Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"BKa8dmT"},{"id":"edb-0366","name":"כפיפת שורש כף היד ביד אחת עם משקולות","name_en":"dumbbell over bench one arm neutral wrist curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל כשמשקולת אחת ביד והיד ישרה מעל הספסל, כף היד פונה מעלה.","שמרו על הזרוע העליונה נייחת וכופפו את המשקולת לכיוון הכתף, תוך שמירה על שורש כף היד בתנוחה ניטרלית.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Sit on a bench with a dumbbell in one hand and your arm extended over the bench, palm facing up.","Keep your upper arm stationary and curl the dumbbell towards your shoulder, keeping your wrist in a neutral position.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"IvV6C9M"},{"id":"edb-1441","name":"כפיפת שורש כף היד ביד אחת הפוך עם משקולות","name_en":"dumbbell over bench one arm reverse wrist curl","muscle":"biceps","equipment":"dumbbell","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["biceps","brachialis"],"steps":["שבו על ספסל כשכפות הרגליים שטוחות על הרצפה ואחזו משקולת ביד אחת, כף היד פונה מטה.","הניחו את אמת היד על הספסל כששורש כף היד תלוי מעבר לקצה.","כופפו את שורש כף היד באיטיות כלפי מעלה, תוך הבאת המשקולת לכיוון אמת היד.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות חזרה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ליד השנייה."],"steps_en":["Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand, palm facing down.","Rest your forearm on the bench with your wrist hanging off the edge.","Slowly curl your wrist upwards, bringing the dumbbell towards your forearm.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"mediaId":"4Jc36XM"},{"id":"edb-0367","name":"כפיפת שורש כף היד ביד אחת עם משקולות","name_en":"dumbbell over bench one arm wrist curl","muscle":"biceps","equipment":"dumbbell","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["biceps","shoulders"],"steps":["שבו על ספסל כשכפות הרגליים שטוחות על הרצפה ואחזו משקולת ביד אחת, כף היד פונה מטה.","הניחו את אמת היד על הספסל כששורש כף היד תלוי מעבר לקצה.","כופפו את שורש כף היד באיטיות כלפי מעלה, תוך הבאת המשקולת לכיוון אמת היד.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות חזרה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ליד השנייה."],"steps_en":["Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand, palm facing down.","Rest your forearm on the bench with your wrist hanging off the edge.","Slowly curl your wrist upwards, bringing the dumbbell towards your forearm.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"mediaId":"KI1DjNN"},{"id":"edb-0368","name":"כפיפת שורש כף היד עם משקולות","name_en":"dumbbell over bench revers wrist curl","muscle":"biceps","equipment":"dumbbell","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["biceps","brachialis"],"steps":["שבו על ספסל כשכפות הרגליים שטוחות על הרצפה ואחזו משקולת בכל יד, כפות הידיים פונות מטה.","הניחו את האמות על הספסל, כששורשי כף היד תלויים מעבר לקצה.","כופפו את שורשי כפות הידיים באיטיות כלפי מעלה, תוך הבאת המשקולות לכיוון הגוף.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing down.","Rest your forearms on the bench, allowing your wrists to hang off the edge.","Slowly curl your wrists upward, bringing the dumbbells towards your body.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"3tAXPQ6"},{"id":"edb-0369","name":"כפיפת שורש כף היד עם משקולות","name_en":"dumbbell over bench wrist curl","muscle":"biceps","equipment":"dumbbell","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["biceps","brachialis"],"steps":["שבו על ספסל כשאמות הידיים מונחות על הספסל וכפות הידיים פונות מעלה, ואתם אוחזים משקולת בכל יד.","תנו לשורשי כפות הידיים להיתלות מעבר לקצה הספסל.","כופפו את שורשי כפות הידיים באיטיות כלפי מעלה, תוך כיווץ אמות הידיים בשיא התנועה.","עצרו לרגע, ולאחר מכן הורידו את שורשי כפות הידיים באיטיות בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your forearms resting on the bench and your palms facing up, holding a dumbbell in each hand.","Allow your wrists to hang over the edge of the bench.","Slowly curl your wrists upward, squeezing your forearms at the top of the movement.","Pause for a moment, then slowly lower your wrists back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"D1xYJAU"},{"id":"edb-1329","name":"חתירה בהטיה עם משקולות","name_en":"dumbbell palm rotational bent over row","muscle":"back","equipment":"dumbbell","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשבכל יד משקולת באחיזה עליונה.","התכופפו קדימה מהירכיים, תוך שמירה על הגב ישר והברכיים כפופות מעט.","תנו לידיים להיתלות ישר למטה, כפות הידיים פונות לגוף.","הפעילו את הליבה ומשכו את המשקולות כלפי מעלה לכיוון החזה, תוך שמירה על המרפקים קרובים לגוף.","תוך כדי משיכת המשקולות כלפי מעלה, סובבו את כפות הידיים כך שיפנו הרחק מהגוף.","כווצו את השכמות זו לזו בשיא התנועה.","הורידו את המשקולות באיטיות בחזרה לתנוחת ההתחלה, תוך סיבוב כפות הידיים בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.","Bend forward at the hips, keeping your back straight and your knees slightly bent.","Let your arms hang straight down, palms facing your body.","Engage your core and pull the dumbbells up towards your chest, keeping your elbows close to your body.","As you pull the dumbbells up, rotate your palms so they face away from your body.","Squeeze your shoulder blades together at the top of the movement.","Slowly lower the dumbbells back down to the starting position, rotating your palms back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"wt6rwjk"},{"id":"edb-1623","name":"לחיצת חזה בשיפוע עם משקולות","name_en":"dumbbell palms in incline bench press","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["הציבו ספסל בשיפוע עולה בזווית של 45 מעלות.","שבו על הספסל כשהגב צמוד למשענת וכפות הרגליים שטוחות על הרצפה.","אחזו משקולת בכל יד באחיזה עליונה, כפות הידיים פונות פנימה.","יישרו את הידיים ישר מעל החזה, תוך שמירה על כיפוף קל במרפקים.","הורידו את המשקולות באיטיות לכיוון הכתפיים, תוך שמירה על המרפקים קרובים לגוף.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו את המשקולות בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up an incline bench at a 45-degree angle.","Sit on the bench with your back against the backrest and feet flat on the ground.","Hold a dumbbell in each hand with an overhand grip, palms facing inwards.","Extend your arms straight up above your chest, keeping a slight bend in your elbows.","Lower the dumbbells slowly towards your shoulders, keeping your elbows close to your body.","Pause for a moment at the bottom, then press the dumbbells back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"8eqjhOl"},{"id":"edb-0370","name":"כפיפת פטיש עם משקולות","name_en":"dumbbell peacher hammer curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף כשבכל יד משקולת, כפות הידיים פונות לגוף.","שמרו על המרפקים צמודים לגוף וסובבו את כפות הידיים עד שהן פונות קדימה.","זו תהיה עמדת ההתחלה שלכם.","כעת, כשהזרועות העליונות נייחות, נשפו החוצה וכופפו את המשקולות תוך כיווץ הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","לאחר מכן, שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התנועה למספר החזרות המומלץ."],"steps_en":["Stand up straight with a dumbbell in each hand, palms facing your torso.","Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward.","This will be your starting position.","Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Then, inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the recommended amount of repetitions."],"mediaId":"F1KxjBa"},{"id":"edb-0371","name":"סקוואט עם משקולות","name_en":"dumbbell plyo squat","muscle":"glutes","equipment":"dumbbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו כשכפות הרגליים ברוחב הכתפיים, ואחזו משקולת בכל יד לצד הגוף.","הורידו את הגוף לתנוחת סקוואט על ידי כפיפת הברכיים ודחיפת האגן אחורה.","כשאתם מגיעים לתחתית הסקוואט, התפרצו כלפי מעלה, תוך קפיצה מהרצפה.","באוויר, החליפו במהירות את מיקום הרגליים, ונחתו כשהרגל הנגדית קדימה.","הורידו מיד את הגוף בחזרה לתנוחת סקוואט וחזרו על הקפיצה, תוך החלפת הרגליים שוב.","המשיכו להחליף את מיקום הרגליים בכל קפיצה, למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at your sides.","Lower your body into a squat position by bending your knees and pushing your hips back.","As you reach the bottom of the squat, explode upward, jumping off the ground.","While in the air, quickly switch the position of your feet, landing with your opposite foot forward.","Immediately lower your body back into a squat position and repeat the jump, switching your feet again.","Continue alternating the position of your feet with each jump for the desired number of repetitions."],"mediaId":"S4pwGlc"},{"id":"edb-0372","name":"כפיפת מרפק בכיסא הטפה עם משקולות","name_en":"dumbbell preacher curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל סקוט כשהזרועות העליונות מונחות על הכרית והחזה צמוד אליה.","אחזו משקולת בכל יד כשכפות הידיים פונות מעלה והידיים ישרות לגמרי.","תוך שמירה על הזרוע העליונה ללא תזוזה, נשפו החוצה וכופפו את המשקולות תוך כיווץ שרירי הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a preacher curl bench with your upper arms resting on the pad and your chest against it.","Hold a dumbbell in each hand with your palms facing up and your arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"jivWf8n"},{"id":"edb-1673","name":"כפיפת מרפק בכיסא הטפה עם משקולות","name_en":"dumbbell preacher curl over exercise ball","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על כדור התעמלות כשכפות הרגליים שטוחות על הרצפה והגב ישר.","אחזו משקולת ביד אחת באחיזה תחתונה, כשהמרפק מונח על כדור הפיטבול.","תוך שמירה על הזרוע העליונה נייחת, נשפו וכופפו את המשקולת כלפי מעלה לכיוון הכתף.","עצרו לרגע בשיא התנועה, ולאחר מכן שאפו אוויר והורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in one hand with an underhand grip, resting your elbow on the exercise ball.","Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder.","Pause for a moment at the top, then inhale and slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"hwygydB"},{"id":"edb-1293","name":"לחיצה עם משקולות","name_en":"dumbbell press on exercise ball","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["שבו על כדור פיטבול כשכפות הרגליים שטוחות על הרצפה ומשקולות בכל יד, מונחות על הירכיים.","צעדו באיטיות עם הרגליים קדימה, גלגלו את כדור הפיטבול עד שהגב התחתון נשען עליו והברכיים בזווית של 90 מעלות.","הרימו את המשקולות לגובה הכתפיים, כפות הידיים פונות קדימה.","דחפו את המשקולות כלפי מעלה עד שהידיים ישרות לגמרי.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on an exercise ball with your feet flat on the ground and dumbbells in each hand, resting on your thighs.","Slowly walk your feet forward, rolling the exercise ball until your lower back is supported on the ball and your knees are at a 90-degree angle.","Raise the dumbbells to shoulder height, palms facing forward.","Press the dumbbells upward until your arms are fully extended.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"O8o7q4d"},{"id":"edb-0373","name":"פשיטת מרפק עם משקולות","name_en":"dumbbell pronate-grip triceps extension","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל או כיסא כשהגב ישר וכפות הרגליים שטוחות על הרצפה.","אחזו משקולת בשתי הידיים, כפות הידיים פונות מטה, ויישרו את הידיים ישר מעל הראש.","תוך שמירה על הזרועות העליונות קרובות לראש והמרפקים פונים קדימה, הורידו את המשקולת באיטיות מאחורי הראש על ידי כיפוף המרפקים.","עצרו לרגע, ולאחר מכן יישרו את הידיים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench or chair with your back straight and feet flat on the ground.","Hold a dumbbell with both hands, palms facing down, and extend your arms straight up overhead.","Keeping your upper arms close to your head and elbows pointing forward, slowly lower the dumbbell behind your head by bending your elbows.","Pause for a moment, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"bpJL2Qs"},{"id":"edb-0374","name":"כפיפת מרפק בשיפוע בשכיבה על הבטן עם משקולות","name_en":"dumbbell prone incline curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["כווננו את הספסל לשיפוע של 45 מעלות.","שכבו על הבטן על הספסל, כשהחזה והבטן נשענים עליו.","אחזו משקולת בכל יד כשכפות הידיים פונות מטה והידיים ישרות לגמרי.","תוך שמירה על הזרוע העליונה ללא תזוזה, נשפו החוצה וכופפו את המשקולות תוך כיווץ שרירי הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the bench to a 45-degree incline.","Lie face down on the bench with your chest and stomach resting against it.","Hold a dumbbell in each hand with your palms facing down and your arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"mwpPcr1"},{"id":"edb-1674","name":"כפיפת פטיש בשיפוע בשכיבה על הבטן עם משקולות","name_en":"dumbbell prone incline hammer curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["כווננו את הספסל לשיפוע של 45 מעלות.","שכבו על הבטן על הספסל כשמשקולת בכל יד, כפות הידיים פונות זו לזו.","תנו לידיים להיתלות ישר למטה לכיוון הרצפה, תוך שמירה על כיפוף קל במרפקים.","תוך שמירה על הזרוע העליונה ללא תזוזה, נשפו החוצה וכופפו את המשקולות תוך כיווץ שרירי הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the bench to a 45-degree incline.","Lie face down on the bench with a dumbbell in each hand, palms facing each other.","Allow your arms to hang straight down towards the floor, keeping your elbows slightly bent.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"cWemPG8"},{"id":"edb-0375","name":"פולאובר עם משקולות","name_en":"dumbbell pullover","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["latissimus dorsi","triceps"],"steps":["שכבו על הגב על ספסל, עם הראש בקצה אחד והרגליים על הרצפה.","אחזו משקולת בשתי הידיים ופשטו אותן ישר מעל החזה.","תוך שמירה על כיפוף קל במרפקים, הורידו את המשקולת באיטיות מאחורי הראש עד שתרגישו מתיחה בחזה ובכתפיים.","עצרו לרגע, ולאחר מכן הרימו את המשקולת בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your head at one end and your feet on the floor.","Hold a dumbbell with both hands and extend your arms straight above your chest.","Keeping a slight bend in your elbows, slowly lower the dumbbell behind your head until you feel a stretch in your chest and shoulders.","Pause for a moment, then raise the dumbbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"9XjtHvS"},{"id":"edb-1294","name":"פשיטה עם משקולות","name_en":"dumbbell pullover hip extension on exercise ball","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders","core"],"steps":["שבו על כדור פיטבול כשכפות הרגליים שטוחות על הרצפה והמשקולת מונחת על הירכיים.","הליכו לאט קדימה עם הרגליים תוך גלגול הכדור לאורך הגב, עד שהראש, הצוואר והגב העליון נשענים על הכדור.","אחזו במשקולת בשתי הידיים ומתחו את הזרועות ישר מעל החזה, תוך שמירה על כיפוף קל במרפקים.","הורידו את המשקולת מאחורי הראש, תוך שמירה על זרועות ישרות ושליטה מלאה בתנועה.","עצרו לרגע, ולאחר מכן הרימו את המשקולת בחזרה לתנוחת ההתחלה.","תוך שמירה על הזרועות מתוחות, הרימו את האגן מהרצפה, כווצו את הישבן והפעילו את שרירי הליבה.","הורידו את האגן חזרה למטה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on an exercise ball with your feet flat on the ground and the dumbbell resting on your thighs.","Slowly walk your feet forward, rolling the exercise ball down your back until your head, neck, and upper back are supported on the ball.","Hold the dumbbell with both hands and extend your arms straight up over your chest, keeping a slight bend in your elbows.","Lower the dumbbell behind your head, keeping your arms straight and maintaining control.","Pause for a moment, then raise the dumbbell back to the starting position.","While keeping your arms extended, lift your hips off the ground, squeezing your glutes and engaging your core.","Lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"lI7easp"},{"id":"edb-1295","name":"פולאובר עם משקולות","name_en":"dumbbell pullover on exercise ball","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","latissimus dorsi"],"steps":["שבו על כדור פיזיו ואחזו במשקולת בשתי הידיים מעל החזה, כשהזרועות מתוחות.","הורידו את המשקולת באיטיות מאחורי הראש תוך שמירה על הידיים ישרות.","עצרו לרגע, ולאחר מכן הרימו את המשקולת בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on an exercise ball and hold a dumbbell with both hands above your chest, arms extended.","Slowly lower the dumbbell behind your head while keeping your arms straight.","Pause for a moment, then raise the dumbbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"FSD6PGL"},{"id":"edb-1700","name":"פוש פרס עם משקולות","name_en":"dumbbell push press","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשבכל יד משקולת בגובה הכתפיים.","כופפו מעט את הברכיים והורידו את הגוף, ואז דחפו בחוזקה את הרגליים כלפי מעלה תוך לחיצת המשקולות מעל הראש.","נעלו את הזרועות בקצה העליון של התנועה, ואז הורידו את המשקולות בחזרה לגובה הכתפיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder level.","Bend your knees slightly and dip your body down, then explosively extend your legs and press the dumbbells overhead.","Lock out your arms at the top of the movement, then lower the dumbbells back to shoulder level.","Repeat for the desired number of repetitions."],"mediaId":"FS63wTN"},{"id":"edb-0376","name":"הרמה עם משקולות","name_en":"dumbbell raise","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","rhomboids"],"steps":["עמדו כשכפות הרגליים ברוחב הכתפיים ואחזו משקולת בכל יד, כפות הידיים פונות לגוף.","שמרו על גב ישר והפעילו את ליבת הגוף.","הרימו את הידיים לצדדים עד שהן מקבילות לרצפה, תוך שמירה על כיפוף קל במרפקים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הידיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body.","Keep your back straight and engage your core.","Raise your arms out to the sides until they are parallel to the floor, keeping a slight bend in your elbows.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"c9MnDRp"},{"id":"edb-2292","name":"הרמה אחורי עם משקולות","name_en":"dumbbell rear delt raise","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","rhomboids"],"steps":["עמדו כשכפות הרגליים ברוחב הכתפיים ואחזו משקולת בכל יד, כפות הידיים פונות לגוף.","כופפו מעט את הברכיים והטו את הגוף קדימה במפרקי הירך, תוך שמירה על גב ישר.","הרימו את הזרועות הצדה, תוך שמירה על כיפוף קל במרפקים, עד שהן מקבילות לרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הידיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the floor.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"mu5Guxt"},{"id":"edb-0377","name":"חתירת כתף אחורית עם משקולות","name_en":"dumbbell rear delt row_shoulder","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","rhomboids"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","אחזו משקולת בכל יד כשכפות הידיים פונות לגוף.","התכופפו קדימה מהמותניים, תוך שמירה על גב ישר ושרירי ליבה פעילים.","מתחו את הזרועות ישר כלפי מטה לכיוון הרצפה, עם כיפוף קל במרפקים.","הרימו את המשקולות הצדה, תוך כיווץ שכמות הגב זו לזו.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and knees slightly bent.","Hold a dumbbell in each hand with your palms facing your body.","Bend forward at the waist, keeping your back straight and your core engaged.","Extend your arms straight down towards the floor, with a slight bend in your elbows.","Raise the dumbbells out to the sides, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"EKXOMEh"},{"id":"edb-0378","name":"פרפר אחורי עם משקולות","name_en":"dumbbell rear fly","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","rhomboids"],"steps":["עמדו כשכפות הרגליים ברוחב הכתפיים ואחזו משקולת בכל יד.","כופפו מעט את הברכיים והטו את הגוף קדימה במפרקי הירך, תוך שמירה על גב ישר.","מתחו את הזרועות ישר כלפי מטה, כשכפות הידיים פונות זו לזו.","תוך שמירה על כיפוף קל במרפקים, הרימו את הזרועות הצדה וכווצו את שכמות הגב זו לזו.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הידיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Extend your arms straight down towards the ground, palms facing each other.","Keeping a slight bend in your elbows, lift your arms out to the sides and squeeze your shoulder blades together.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"8DiFDVA"},{"id":"edb-0380","name":"הרחקת כתפיים לצדדים אחורי עם משקולות","name_en":"dumbbell rear lateral raise","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","rhomboids"],"steps":["עמדו כשכפות הרגליים ברוחב הכתפיים ואחזו משקולת בכל יד, כפות הידיים פונות לגוף.","כופפו מעט את הברכיים והטו את הגוף קדימה מהמותניים, תוך שמירה על גב ישר וליבה מופעלת.","הרימו את הזרועות הצדה, תוך שמירה על כיפוף קל במרפקים, עד שהן מקבילות לרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הידיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body.","Bend your knees slightly and hinge forward at the hips, keeping your back straight and core engaged.","Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the floor.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"v1qBec9"},{"id":"edb-0379","name":"הרחקת כתפיים לצדדים אחורי עם משקולות","name_en":"dumbbell rear lateral raise (support head)","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","rhomboids"],"steps":["עמדו כשכפות הרגליים ברוחב הכתפיים ואחזו משקולת בכל יד.","כופפו מעט את הברכיים והטו את הגוף קדימה במפרקי הירך, תוך שמירה על גב ישר.","הרימו את הידיים הצידה, עם כיפוף קל במרפקים, עד שהן מקבילות לרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הידיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"UzkLrem"},{"id":"edb-0381","name":"לאנג׳ אחורי עם משקולות","name_en":"dumbbell rear lunge","muscle":"glutes","equipment":"dumbbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשבכל יד משקולת.","עשו צעד אחורה עם הרגל הימנית, תוך הורדת הגוף לתנוחת לאנג'.","כופפו את הברך השמאלית והורידו את הגוף עד שהירך השמאלית מקבילה לרצפה.","עצרו לרגע, ואז דחפו דרך העקב השמאלי כדי לחזור למצב ההתחלתי.","חזרו על התנועה בצד השני, עם צעד אחורה ברגל השמאלית."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand.","Take a step backward with your right foot, lowering your body into a lunge position.","Bend your left knee and lower your body until your left thigh is parallel to the ground.","Pause for a moment, then push through your left heel to return to the starting position.","Repeat on the other side, stepping back with your left foot."],"mediaId":"SSsBDwB"},{"id":"edb-0382","name":"כפיפת מרפק עם משקולות","name_en":"dumbbell revers grip biceps curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף כשבכל יד משקולת, כפות הידיים פונות מטה והידיים ישרות לגמרי.","תוך שמירה על הזרוע העליונה ללא תזוזה, נשפו החוצה וכופפו את המשקולות תוך כיווץ שרירי הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand up straight with a dumbbell in each hand, palms facing down and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"e4ojVhP"},{"id":"edb-1624","name":"לחיצת חזה הפוך עם משקולות","name_en":"dumbbell reverse bench press","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["שכבו ישר על ספסל כשהרגליים שטוחות על הרצפה והברכיים כפופות.","אחזו משקולת בכל יד באחיזה עליונה, כשכפות הידיים פונות לכיוון הרגליים.","מתחו את הזרועות ישר כלפי התקרה, תוך שמירה על כיפוף קל במרפקים.","הורידו לאט את המשקולות לכיוון החזה, תוך שהמרפקים נפתחים הצדה.","עצרו לרגע בתחתית התנועה, לאחר מכן דחפו את המשקולות בחזרה למעלה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your feet flat on the ground and your knees bent.","Hold a dumbbell in each hand with an overhand grip, palms facing towards your feet.","Extend your arms straight up towards the ceiling, keeping a slight bend in your elbows.","Slowly lower the dumbbells towards your chest, allowing your elbows to flare out to the sides.","Pause for a moment at the bottom, then push the dumbbells back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"UIbGx6H"},{"id":"edb-0383","name":"פרפר אחורי","name_en":"dumbbell reverse fly","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","rhomboids"],"steps":["עמדו כשכפות הרגליים ברוחב הכתפיים ואחזו משקולת בכל יד.","כופפו מעט את הברכיים והטו את הגוף קדימה במפרקי הירך, תוך שמירה על גב ישר.","מתחו את הזרועות ישר קדימה, כשכפות הידיים פונות זו לזו.","תוך שמירה על כיפוף קל במרפקים, הרימו את הידיים לצדדים עד שהן מקבילות לרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הידיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Extend your arms straight down in front of you, palms facing each other.","Keeping a slight bend in your elbows, raise your arms out to the sides until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"EAs3xL9"},{"id":"edb-1330","name":"חתירה ביד אחת אחיזה הפוכה בשיפוע עם משקולות","name_en":"dumbbell reverse grip incline bench one arm row","muscle":"back","equipment":"dumbbell","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","shoulders"],"steps":["הציבו ספסל בשיפוע עולה בזווית של 45 מעלות.","הניחו משקולת על הרצפה ליד הספסל.","עמדו מול הספסל כשהרגליים ברוחב הכתפיים.","התכופפו במותניים והניחו את הברך השמאלית והיד השמאלית על הספסל לתמיכה.","הרימו את המשקולת ביד הימנית באחיזה הפוכה (כף היד פונה למטה).","שמרו על גב ישר ושרירי ליבה מופעלים.","משכו את המשקולת כלפי מעלה לכיוון החזה, תוך שמירה על המרפק קרוב לגוף.","כווצו את שרירי הגב בקצה העליון של התנועה.","הורידו את המשקולת בחזרה לתנוחת ההתחלה באופן מבוקר.","חזרו על התרגיל למספר החזרות הרצוי.","החליפו צד וחזרו על התרגיל עם היד השמאלית."],"steps_en":["Set up an incline bench at a 45-degree angle.","Place a dumbbell on the floor next to the bench.","Stand facing the bench with your feet shoulder-width apart.","Bend at the waist and place your left knee and left hand on the bench for support.","Pick up the dumbbell with your right hand using a reverse grip (palm facing down).","Keep your back straight and your core engaged.","Pull the dumbbell up towards your chest, keeping your elbow close to your body.","Squeeze your back muscles at the top of the movement.","Lower the dumbbell back down to the starting position in a controlled manner.","Repeat for the desired number of repetitions.","Switch sides and repeat the exercise with your left arm."],"mediaId":"ZIViNh1"},{"id":"edb-1331","name":"חתירה בשתי ידיים אחיזה הפוכה בשיפוע עם משקולות","name_en":"dumbbell reverse grip incline bench two arm row","muscle":"back","equipment":"dumbbell","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["הציבו ספסל בשיפוע עולה בזווית של 45 מעלות.","שבו על הספסל כשהחזה נשען על המשענת והרגליים שטוחות על הרצפה.","אחזו משקולת בכל יד באחיזה תחתונה.","התכופפו קדימה ותנו לזרועות להשתלשל ישר כלפי מטה, במתיחה מלאה.","משכו את המשקולות כלפי מעלה לכיוון החזה, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up an incline bench at a 45-degree angle.","Sit on the bench with your chest against the backrest and your feet flat on the ground.","Hold a dumbbell in each hand with an underhand grip.","Lean forward and let your arms hang straight down, fully extended.","Pull the dumbbells up towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"9pQSkH8"},{"id":"edb-2327","name":"חתירה אחיזה הפוכה עם משקולות","name_en":"dumbbell reverse grip row (female)","muscle":"back","equipment":"dumbbell","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","אחזו משקולת בכל יד באחיזה עליונה, כשכפות הידיים פונות לגוף.","התכופפו קדימה מהמותניים, תוך שמירה על גב ישר ושרירי ליבה פעילים.","תנו לזרועות להשתלשל ישר כלפי מטה, במתיחה מלאה, עם כיפוף קל במרפקים.","משכו את המשקולות כלפי מעלה לכיוון החזה, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and knees slightly bent.","Hold a dumbbell in each hand with an overhand grip, palms facing your body.","Bend forward at the waist, keeping your back straight and your core engaged.","Let your arms hang straight down, fully extended, with a slight bend in your elbows.","Pull the dumbbells up towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Nh3mvOO"},{"id":"edb-0384","name":"כפיפת מרפק בכיסא הטפה הפוך עם משקולות","name_en":"dumbbell reverse preacher curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל פריצ'ר כשהזרוע העליונה נשענת על הכרית והחזה נשען על התומך.","אחזו משקולת בכל יד באחיזה תחתונה, כשכפות הידיים פונות למעלה.","תוך שמירה על הזרועות העליונות ללא תנועה, נשפו וכופפו את המשקולות תוך כיווץ שרירי הביצפס.","המשיכו לכופף את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והורידו את המשקולות באיטיות בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a preacher bench with your upper arms resting on the pad and your chest against the support.","Hold a dumbbell in each hand with an underhand grip, palms facing up.","Keeping your upper arms stationary, exhale and curl the dumbbells as you contract your biceps.","Continue to curl the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"O8Aq69u"},{"id":"edb-1675","name":"כפיפת מרפק הפוך עם משקולות","name_en":"dumbbell reverse spider curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף עם משקולת בכל יד, כשכפות הידיים פונות לגוף והזרועות מתוחות לגמרי.","תוך שמירה על הזרוע העליונה ללא תזוזה, נשפו החוצה וכופפו את המשקולות תוך כיווץ שרירי הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand up straight with a dumbbell in each hand, palms facing your body and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"6sMAmNv"},{"id":"edb-0385","name":"כפיפת שורש כף היד הפוך עם משקולות","name_en":"dumbbell reverse wrist curl","muscle":"biceps","equipment":"dumbbell","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["biceps","brachialis"],"steps":["שבו על ספסל או כיסא כשכפות הרגליים שטוחות על הרצפה.","אחזו משקולת בכל יד באחיזה עליונה, כשכפות הידיים פונות למטה.","הניחו את האמות על הירכיים כך שפרקי הידיים תלויים מעבר לקצה.","כופפו את שורשי כפות הידיים באיטיות כלפי מעלה, תוך הבאת המשקולות לכיוון הגוף.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench or chair with your feet flat on the ground.","Hold a dumbbell in each hand with an overhand grip, palms facing down.","Rest your forearms on your thighs, allowing your wrists to hang off the edge.","Slowly curl your wrists upward, bringing the dumbbells towards your body.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"BLCvwr2"},{"id":"edb-1459","name":"דדליפט רומני עם משקולות","name_en":"dumbbell romanian deadlift","muscle":"glutes","equipment":"dumbbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","lower back"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשבכל יד משקולת באחיזה עליונה.","תוך שמירה על גב ישר וליבה מופעלת, כופפו במותניים והורידו את המשקולות לכיוון הרצפה, תוך כיפוף קל בברכיים.","הורידו את המשקולות עד שתרגישו מתיחה בשרירי הירך האחוריים, ואז דחפו דרך העקבים והפעילו את הישבן כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.","Keeping your back straight and your core engaged, hinge at the hips and lower the dumbbells towards the ground, allowing your knees to bend slightly.","Lower the dumbbells until you feel a stretch in your hamstrings, then push through your heels and engage your glutes to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"rR0LJzx"},{"id":"edb-0386","name":"פרפר הפוך עם משקולות","name_en":"dumbbell rotation reverse fly","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","rhomboids"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו משקולת בכל יד, כשכפות הידיים פונות פנימה.","כופפו את הברכיים מעט והתכופפו קדימה מהירכיים, תוך שמירה על גב ישר וחזה מורם.","הרימו את הזרועות הצדה, תוך שמירה על כיפוף קל במרפקים, עד שהן מקבילות לרצפה.","סובבו את הזרועות כך שכפות הידיים יפנו כלפי מטה.","הורידו לאט את הידיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing inwards.","Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up.","Raise your arms out to the sides, keeping a slight bend in your elbows, until they are parallel to the floor.","Rotate your arms so that your palms are facing downwards.","Slowly lower your arms back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"prbWx1D"},{"id":"edb-2397","name":"לחיצה עם משקולות","name_en":"dumbbell scott press","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","chest"],"steps":["שבו על ספסל עם משקולת בכל יד, כשכפות הידיים פונות קדימה.","הרימו את המשקולות לגובה הכתפיים, כשהמרפקים כפופים וכפות הידיים פונות קדימה.","דחפו את המשקולות כלפי מעלה עד שהידיים ישרות לגמרי.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with a dumbbell in each hand, palms facing forward.","Raise the dumbbells to shoulder height, with your elbows bent and palms facing forward.","Press the dumbbells upward until your arms are fully extended.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"5vfAI0I"},{"id":"edb-0387","name":"הרמה קדמית בישיבה לסירוגין עם משקולות","name_en":"dumbbell seated alternate front raise","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","biceps"],"steps":["שבו על ספסל עם גב ישר וכפות רגליים שטוחות על הרצפה.","אחזו משקולת בכל יד כשכפות הידיים פונות לגוף והזרועות מתוחות לצדדים.","תוך שמירה על הזרועות ישרות, הרימו משקולת אחת לפניכם עד שהיא מקבילה לרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות חזרה למצב ההתחלתי.","חזרו עם הזרוע השנייה.","החליפו בין הזרועות למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell in each hand with your palms facing your body and arms extended down by your sides.","Keeping your arms straight, raise one dumbbell in front of you until it is parallel to the ground.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat with the other arm.","Alternate between arms for the desired number of repetitions."],"mediaId":"gH5fRsC"},{"id":"edb-1676","name":"כפיפת פטיש בישיבה לסירוגין עם משקולות","name_en":"dumbbell seated alternate hammer curl on exercise ball","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על כדור התעמלות כשכפות הרגליים שטוחות על הרצפה והגב ישר.","אחזו משקולת בכל יד כשכפות הידיים פונות לגוף והידיים ישרות לגמרי.","תוך שמירה על הזרוע העליונה ללא תנועה, נשפו וכופפו משקולת אחת כלפי הכתף, כשכף היד פונה לגוף.","המשיכו להרים את המשקולת עד שהביצפס מכווץ לגמרי והמשקולת בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והורידו לאט את המשקולת בחזרה לעמדת ההתחלה.","חזרו על התנועה עם היד השנייה.","המשיכו להחליף ידיים למספר החזרות הרצוי."],"steps_en":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in each hand with your palms facing your body and your arms fully extended.","Keeping your upper arms stationary, exhale and curl one dumbbell up towards your shoulder while keeping your palm facing your body.","Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat the movement with the opposite arm.","Continue alternating arms for the desired number of repetitions."],"mediaId":"QLRmNeT"},{"id":"edb-0388","name":"לחיצה בישיבה לסירוגין עם משקולות","name_en":"dumbbell seated alternate press","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","chest"],"steps":["שבו על ספסל עם משקולת בכל יד, כשכפות הידיים פונות קדימה.","הרימו את המשקולות לגובה הכתפיים, כשהמרפקים כפופים וכפות הידיים פונות קדימה.","לחצו משקולת אחת מעל הראש, תוך מתיחה מלאה של הזרוע.","הורידו את המשקולת בחזרה לגובה הכתפיים.","חזרו עם הזרוע השנייה.","המשיכו להחליף ידיים למספר החזרות הרצוי."],"steps_en":["Sit on a bench with a dumbbell in each hand, palms facing forward.","Raise the dumbbells to shoulder height, with your elbows bent and palms facing forward.","Press one dumbbell up overhead, fully extending your arm.","Lower the dumbbell back down to shoulder height.","Repeat with the other arm.","Continue alternating arms for the desired number of repetitions."],"mediaId":"QT5Q0nK"},{"id":"edb-3546","name":"dumbbell seated alternate shoulder","name_en":"dumbbell seated alternate shoulder","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["שבו על ספסל עם גב ישר וכפות רגליים שטוחות על הרצפה.","אחזו משקולת בכל יד, כשכפות הידיים פונות פנימה, והרימו אותן לגובה הכתפיים.","לחצו משקולת אחת מעל הראש תוך שמירה על המשקולת השנייה בגובה הכתפיים.","הורידו את המשקולת המורמת בחזרה לגובה הכתפיים תוך לחיצה בו-זמנית של המשקולת השנייה מעל הראש.","המשיכו להחליף בין הזרועות למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell in each hand, palms facing inwards, and raise them to shoulder height.","Press one dumbbell up overhead while keeping the other dumbbell at shoulder height.","Lower the raised dumbbell back to shoulder height while simultaneously pressing the other dumbbell up overhead.","Continue alternating between arms for the desired number of repetitions."],"mediaId":"q7qkONO"},{"id":"edb-0389","name":"פשיטה בישיבה עם משקולות","name_en":"dumbbell seated bench extension","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שבו על ספסל עם גב ישר וכפות רגליים שטוחות על הרצפה.","אחזו משקולת בשתי הידיים ומתחו את הזרועות ישר מעל הראש.","הורידו לאט את המשקולת מאחורי הראש, תוך שמירה על המרפקים קרובים לאוזניים.","עצרו לרגע, ואז הרימו את המשקולת בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell with both hands and extend your arms straight up above your head.","Slowly lower the dumbbell behind your head, keeping your elbows close to your ears.","Pause for a moment, then raise the dumbbell back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"JhYSVwT"},{"id":"edb-2317","name":"הרחקת כתפיים לצדדים בישיבה בהטיה עם משקולות","name_en":"dumbbell seated bent arm lateral raise","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","rhomboids"],"steps":["שבו על ספסל עם גב ישר וכפות רגליים שטוחות על הרצפה.","אחזו משקולת בכל יד כשכפות הידיים פונות לגוף והזרועות כפופות בזווית של 90 מעלות.","תוך שמירה על המרפקים כפופים, הרימו את הזרועות הצדה עד שהן מקבילות לרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הידיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell in each hand with your palms facing your body and your arms bent at a 90-degree angle.","Keeping your elbows bent, raise your arms out to the sides until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"JzQbv7J"},{"id":"edb-1730","name":"בעיטה אחורית בישיבה לסירוגין בהטיה עם משקולות","name_en":"dumbbell seated bent over alternate kickback","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders","back"],"steps":["שבו על ספסל עם משקולת בכל יד, כשכפות הידיים פונות פנימה.","התכופפו קדימה במותניים, תוך שמירה על גב ישר ומקביל לרצפה.","מתחו זרוע אחת ישר אחורה, קרוב לגוף, עד למתיחה מלאה.","עצרו לרגע, ואז הורידו לאט את המשקולת בחזרה למצב ההתחלתי.","חזרו עם הזרוע השנייה.","המשיכו להחליף ידיים למספר החזרות הרצוי."],"steps_en":["Sit on a bench with a dumbbell in each hand, palms facing inwards.","Bend forward at the waist, keeping your back straight and parallel to the ground.","Extend one arm straight back, keeping it close to your body, until your arm is fully extended.","Pause for a moment, then slowly lower the dumbbell back to the starting position.","Repeat with the other arm.","Continue alternating arms for the desired number of repetitions."],"mediaId":"x0lwvfq"},{"id":"edb-1737","name":"פשיטת מרפק בישיבה בהטיה עם משקולות","name_en":"dumbbell seated bent over triceps extension","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders","back"],"steps":["שבו על ספסל עם הרגליים שטוחות על הרצפה ואחזו משקולת בכל יד.","התכופפו קדימה במותניים, תוך שמירה על גב ישר וראש מורם.","מתחו את הזרועות ישר אחורה, תוך שמירה על המרפקים קרובים לראש.","עצרו לרגע, ולאחר מכן הורידו את המשקולות באיטיות בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand.","Bend forward at the waist, keeping your back straight and your head up.","Extend your arms straight back, keeping your elbows close to your head.","Pause for a moment, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"4ievMJ9"},{"id":"edb-1677","name":"כפיפת מרפק בישיבה עם משקולות","name_en":"dumbbell seated bicep curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל כשכפות הרגליים שטוחות על הרצפה ואחזו משקולת בכל יד, כפות הידיים פונות מעלה.","שמרו על גב ישר והמרפקים קרובים לגוף.","נשפו וכופפו את המשקולות כלפי הכתפיים, תוך כיווץ הביצפס.","עצרו לרגע בשיא התנועה, לאחר מכן שאפו אוויר והורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing up.","Keep your back straight and your elbows close to your torso.","Exhale and curl the dumbbells up towards your shoulders, contracting your biceps.","Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"xiA6lRr"},{"id":"edb-0390","name":"כפיפת מרפק בישיבה עם כדור פיזיו","name_en":"dumbbell seated biceps curl (on stability ball)","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על כדור פיזיו כשכפות הרגליים שטוחות על הרצפה והגב ישר.","אחזו משקולת בכל יד כשכפות הידיים פונות קדימה והידיים ישרות לגמרי.","כשהזרועות העליונות נייחות, נשפו החוצה וכופפו את המשקולות תוך כיווץ הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a stability ball with your feet flat on the ground and your back straight.","Hold a dumbbell in each hand with your palms facing forward and your arms fully extended.","Keeping your upper arms stationary, exhale and curl the dumbbells while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"WgJnBH5"},{"id":"edb-3547","name":"לחיצת כתפיים בישיבה עם משקולות","name_en":"dumbbell seated biceps curl to shoulder press","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שבו על ספסל עם גב ישר וכפות רגליים שטוחות על הרצפה.","אחזו משקולת בכל יד כשכפות הידיים פונות קדימה והזרועות מתוחות לגמרי.","תוך שמירה על המרפקים קרובים לגוף, כופפו את המשקולות כלפי הכתפיים.","כשהאמות שלכם אנכיות, סובבו את פרקי הידיים כך שכפות הידיים יפנו קדימה.","לחצו את המשקולות מעל הראש עד שהזרועות מתוחות לגמרי.","הורידו את המשקולות בחזרה לעמדת ההתחלה על ידי ביצוע התנועה ההפוכה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell in each hand with your palms facing forward and arms fully extended.","Keeping your elbows close to your sides, curl the dumbbells up towards your shoulders.","Once your forearms are vertical, rotate your wrists so that your palms are facing forward.","Press the dumbbells overhead until your arms are fully extended.","Lower the dumbbells back down to the starting position by reversing the movement.","Repeat for the desired number of repetitions."],"mediaId":"OeL23VY"},{"id":"edb-1379","name":"הרמת עקבים בישיבה עם משקולות","name_en":"dumbbell seated calf raise","muscle":"legs","equipment":"dumbbell","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings"],"steps":["שבו על ספסל או כיסא כשהרגליים שטוחות על הרצפה ומשקולת מונחת על הירכיים.","הניחו את כריות כפות הרגליים על משטח מוגבה, כגון מדרגה או בלוק, כשהעקבים תלויים מעבר לקצה.","אחזו במשקולת ליציבות.","הרימו את העקבים כמה שיותר גבוה, תוך העברת משקל הגוף לכריות כפות הרגליים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקבים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench or chair with your feet flat on the ground and a dumbbell resting on your thighs.","Place the balls of your feet on a raised surface such as a step or block, with your heels hanging off the edge.","Hold onto the dumbbell for stability.","Raise your heels as high as possible, lifting your body weight onto the balls of your feet.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"r29jP7S"},{"id":"edb-0391","name":"כפיפת מרפק בישיבה עם משקולות","name_en":"dumbbell seated curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל עם הרגליים שטוחות על הרצפה ומשקולת בכל יד, כשכפות הידיים פונות קדימה.","שמרו על גב ישר והמרפקים קרובים לגוף.","נשפו וכופפו את המשקולות כלפי הכתפיים, תוך כיווץ הביצפס.","עצרו לרגע בשיא התנועה, לאחר מכן שאפו אוויר והורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your feet flat on the ground and a dumbbell in each hand, palms facing forward.","Keep your back straight and your elbows close to your torso.","Exhale and curl the dumbbells up towards your shoulders, contracting your biceps.","Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"TiaZTxx"},{"id":"edb-0392","name":"הרמה קדמית בישיבה עם משקולות","name_en":"dumbbell seated front raise","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","biceps"],"steps":["שבו על ספסל עם הרגליים שטוחות על הרצפה ומשקולת בכל יד, מונחת על הירכיים.","שמרו על גב ישר ושרירי ליבה פעילים.","הרימו את המשקולות לפניכם, כשכפות הידיים פונות למטה, עד שהן בגובה הכתפיים.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your feet flat on the ground and a dumbbell in each hand, resting on your thighs.","Keep your back straight and core engaged.","Raise the dumbbells in front of you, with your palms facing down, until they are at shoulder level.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Ys97II0"},{"id":"edb-1678","name":"כפיפת פטיש בישיבה עם משקולות","name_en":"dumbbell seated hammer curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל עם משקולת בכל יד, כשכפות הידיים פונות לגו ף והזרועות מתוחות ישר כלפי מטה.","תוך שמירה על הזרוע העליונה ללא תזוזה, נשפו החוצה וכופפו את המשקולות תוך כיווץ שרירי הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with a dumbbell in each hand, palms facing your torso and arms extended straight down.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"IGtBdNT"},{"id":"edb-0393","name":"כפיפת מרפק בישיבה עם משקולות","name_en":"dumbbell seated inner biceps curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל כשכפות הרגליים שטוחות על הרצפה ואחזו משקולת בכל יד, כפות הידיים פונות מעלה.","הניחו את הזרועות העליונות על הירכיים, כשהמשקולות משתלשלות כלפי מטה.","תוך שמירה על הזרועות העליונות ללא תנועה, כופפו את המשקולות כלפי הכתפיים תוך כיווץ הביצפס.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing up.","Rest your upper arms on your thighs, allowing the dumbbells to hang down.","Keeping your upper arms stationary, curl the dumbbells up towards your shoulders by contracting your biceps.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"KXyoEtA"},{"id":"edb-0394","name":"בעיטה אחורית בישיבה עם משקולות","name_en":"dumbbell seated kickback","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שבו על ספסל עם הרגליים שטוחות על הרצפה ואחזו משקולת בכל יד.","כופפו מעט את הברכיים והטו את הגוף קדימה מהמותניים, תוך שמירה על גב ישר.","קרבו את הזרועות העליונות לצדי הגוף ושמרו על המרפקים כפופים בזווית של 90 מעלות.","יישרו את הידיים ישר לאחור, וכווצו את הטריצפס בשיא התנועה.","עצרו לרגע, ולאחר מכן הורידו את המשקולות באיטיות בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand.","Bend your knees slightly and lean forward from your hips, keeping your back straight.","Bring your upper arms close to your sides and keep your elbows bent at a 90-degree angle.","Extend your arms straight back, squeezing your triceps at the top of the movement.","Pause for a moment, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"en550rk"},{"id":"edb-0396","name":"הרחקת כתפיים לצדדים בישיבה עם משקולות","name_en":"dumbbell seated lateral raise","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","upper back"],"steps":["שבו על ספסל עם הרגליים שטוחות על הרצפה ומשקולת בכל יד, מונחת על הירכיים.","שמרו על גב ישר ושרירי ליבה פעילים.","הרימו את המשקולות הצדה עם כיפוף קל במרפקים, עד שהזרועות מקבילות לרצפה.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your feet flat on the ground and a dumbbell in each hand, resting on your thighs.","Keep your back straight and core engaged.","Raise the dumbbells to your sides with a slight bend in your elbows, until your arms are parallel to the ground.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"hxyTtWj"},{"id":"edb-0395","name":"הרחקת כתפיים לצדדים בישיבה עם משקולות","name_en":"dumbbell seated lateral raise v. 2","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","triceps"],"steps":["שבו על ספסל עם הרגליים שטוחות על הרצפה ומשקולת בכל יד, מונחת על הירכיים.","שמרו על גב ישר ושרירי ליבה פעילים.","הרימו את המשקולות הצדה עם כיפוף קל במרפקים, עד שהזרועות מקבילות לרצפה.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your feet flat on the ground and a dumbbell in each hand, resting on your thighs.","Keep your back straight and core engaged.","Raise the dumbbells to your sides with a slight bend in your elbows, until your arms are parallel to the ground.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"hrrS0Ed"},{"id":"edb-0397","name":"כפיפת שורש כף היד בישיבה עם משקולות","name_en":"dumbbell seated neutral wrist curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל עם הרגליים שטוחות על הרצפה ואחזו משקולת בכל יד, כשכפות הידיים פונות זו לזו.","הניחו את האמות על הירכיים, כשהמשקולות משתלשלות כלפי מטה.","תוך שמירה על פרקי הידיים בתנוחה ניטרלית, כופפו את המשקולות כלפי הכתפיים.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing each other.","Rest your forearms on your thighs, allowing the dumbbells to hang down.","Keeping your wrists in a neutral position, curl the dumbbells up towards your shoulders.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"uJmK7Z1"},{"id":"edb-1679","name":"כפיפת מרפק ביד אחת בישיבה עם משקולות","name_en":"dumbbell seated one arm bicep curl on exercise ball with leg raised","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms","shoulders"],"steps":["שבו על כדור התעמלות כשכפות הרגליים שטוחות על הרצפה והגב ישר.","אחזו משקולת ביד אחת כשכף היד פונה מעלה והיד ישרה לגמרי.","הניחו את היד השנייה על הירך לשם יציבות.","כופפו לאט את המשקולת כלפי הכתף, תוך שמירה על הזרוע העליונה ללא תנועה.","עצרו לרגע בשיא התנועה, תוך כיווץ הביצפס.","הורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי.","החליפו זרועות וחזרו על התרגיל."],"steps_en":["Sit on an exercise ball with your feet flat on the ground and your back straight.","Hold a dumbbell in one hand with your palm facing up and your arm fully extended.","Place your other hand on your hip for stability.","Slowly curl the dumbbell towards your shoulder, keeping your upper arm stationary.","Pause for a moment at the top of the movement, squeezing your bicep.","Slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions.","Switch arms and repeat the exercise."],"mediaId":"84sESNy"},{"id":"edb-0398","name":"בעיטה אחורית ביד אחת בישיבה עם משקולות","name_en":"dumbbell seated one arm kickback","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שבו על ספסל עם הרגליים שטוחות על הרצפה ואחזו משקולת ביד אחת.","הטו את פלג הגוף העליון קדימה במותניים, תוך שמירה על גב ישר ומקביל לרצפה.","מתחו את הזרוע ישר אחורה, תוך שמירה על המרפק קרוב לגוף.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand.","Bend your torso forward at the waist, keeping your back straight and parallel to the ground.","Extend your arm straight back, keeping your elbow close to your body.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"VQ3sNCn"},{"id":"edb-0399","name":"dumbbell seated one arm rotate","name_en":"dumbbell seated one arm rotate","muscle":"biceps","equipment":"dumbbell","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["shoulders","biceps"],"steps":["שבו על ספסל עם גב ישר ואחזו משקולת ביד אחת, הנחו אותה על הירך.","הרימו את המשקולת לגובה הכתף, תוך שמירה על המרפק קרוב לגוף.","סובבו את האמה החוצה, הרחק מהגוף, תוך שמירה על הזרוע העליונה ללא תנועה.","עצרו לרגע בקצה העליון, ואז סובבו לאט את האמה בחזרה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ליד השנייה."],"steps_en":["Sit on a bench with your back straight and hold a dumbbell in one hand, resting it on your thigh.","Raise the dumbbell up to shoulder height, keeping your elbow close to your body.","Rotate your forearm outward, away from your body, while keeping your upper arm stationary.","Pause for a moment at the top, then slowly rotate your forearm back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"mediaId":"7f2jsqP"},{"id":"edb-0400","name":"הרמת עקבים ברגל אחת בישיבה עם משקולות","name_en":"dumbbell seated one leg calf raise","muscle":"legs","equipment":"dumbbell","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings","glutes"],"steps":["שבו על ספסל או כיסא כשהרגליים שטוחות על הרצפה ומשקולת מונחת על הירך הימנית.","מתחו את הרגל השמאלית ישר לפנים, כשכף הרגל מכופפת כלפי מעלה.","הניחו את כרית כף הרגל הימנית על משטח מוגבה, כגון מדרגה או משקולת דיסקית.","בעזרת שרירי השוק, הרימו את העקב הימני כמה שיותר גבוה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקב בחזרה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו רגליים."],"steps_en":["Sit on a bench or chair with your feet flat on the ground and a dumbbell resting on your right thigh.","Extend your left leg straight out in front of you, keeping your foot flexed.","Place the ball of your right foot on an elevated surface, such as a step or weight plate.","Using your calf muscles, raise your right heel as high as possible.","Pause for a moment at the top, then slowly lower your heel back down to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"mediaId":"Ia7tumC"},{"id":"edb-1380","name":"הרמת עקבים ברגל אחת בישיבה עם משקולות","name_en":"dumbbell seated one leg calf raise - hammer grip","muscle":"legs","equipment":"dumbbell","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings","glutes"],"steps":["שבו על ספסל או כיסא כשהרגליים שטוחות על הרצפה ומשקולת מונחת על הירכיים.","הניחו רגל אחת על משטח מוגבה, כגון מדרגה או בלוק, כשהעקב תלוי מעבר לקצה.","אחזו במשקולת באחיזת פטיש, כלומר כפות הידיים פונות זו לזו והאצבעות עוטפות את הידית.","תוך שמירה על הליבה מופעלת והגב ישר, הרימו לאט את העקב כמה שיותר גבוה תוך דחיפה דרך כרית כף הרגל.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקב בחזרה למצב ההתחלתי.","חזרו על התנועה למספר החזרות הרצוי, ולאחר מכן עברו לרגל השנייה."],"steps_en":["Sit on a bench or chair with your feet flat on the ground and a dumbbell resting on your thighs.","Place one foot on a raised surface, such as a step or block, with your heel hanging off the edge.","Hold the dumbbell with a hammer grip, meaning your palms are facing each other and your fingers are wrapped around the handle.","Keeping your core engaged and your back straight, slowly raise your heel as high as possible by pushing through the ball of your foot.","Pause for a moment at the top, then slowly lower your heel back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other leg."],"mediaId":"FxhcxUW"},{"id":"edb-1381","name":"הרמת עקבים ברגל אחת בישיבה עם משקולות","name_en":"dumbbell seated one leg calf raise - palm up","muscle":"legs","equipment":"dumbbell","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings","glutes"],"steps":["שבו על ספסל או כיסא כשהגב ישר והרגליים שטוחות על הרצפה.","אחזו משקולת ביד אחת והניחו אותה על הירך, כשכף היד פונה כלפי מעלה.","הרימו רגל אחת מהרצפה ומתחו אותה קדימה, תוך שמירה על כיפוף קל בברך.","הרימו את העקב כמה שיותר גבוה תוך דחיפה דרך כרית כף הרגל.","עצרו לרגע בקצה העליון, ואז הורידו לאט את העקב בחזרה למטה.","חזרו על התנועה למספר החזרות הרצוי, ולאחר מכן החליפו רגליים וחזרו שוב."],"steps_en":["Sit on a bench or chair with your back straight and your feet flat on the ground.","Hold a dumbbell in one hand and place it on top of your thigh, palm facing up.","Lift one leg off the ground and extend it in front of you, keeping your knee slightly bent.","Raise your heel as high as possible by pushing through the ball of your foot.","Pause for a moment at the top, then slowly lower your heel back down.","Repeat for the desired number of repetitions, then switch legs and repeat."],"mediaId":"VW88JNd"},{"id":"edb-0401","name":"כפיפת שורש כף היד בישיבה עם משקולות","name_en":"dumbbell seated palms up wrist curl","muscle":"biceps","equipment":"dumbbell","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["biceps","shoulders"],"steps":["שבו על ספסל כשכפות הרגליים שטוחות על הרצפה ואחזו משקולת בכל יד, כפות הידיים פונות מעלה.","הניחו את האמות על הירכיים כך שפרקי הידיים תלויים מעבר לקצה.","כופפו את שורשי כפות הידיים באיטיות כלפי מעלה, תוך כיווץ אמות הידיים בשיא התנועה.","עצרו לרגע, ואז הורידו את פרקי הידיים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your feet flat on the ground and hold a dumbbell in each hand, palms facing up.","Rest your forearms on your thighs, allowing your wrists to hang off the edge.","Slowly curl your wrists upward, squeezing your forearms at the top of the movement.","Pause for a moment, then lower your wrists back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"2dImyQ8"},{"id":"edb-0402","name":"כפיפת מרפק בכיסא הטפה בישיבה עם משקולות","name_en":"dumbbell seated preacher curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל פריצ'ר כשהרגליים שטוחות על הרצפה.","אחזו משקולת ביד אחת באחיזה תחתונה, תוך הנחת הזרוע העליונה על כרית הפריצ'ר.","תוך שמירה על הזרוע העליונה נייחת, נשפו וכופפו את המשקולת כלפי מעלה לכיוון הכתף.","עצרו לרגע בשיא התנועה, ולאחר מכן שאפו אוויר והורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Sit on a preacher curl bench with your feet flat on the floor.","Hold a dumbbell in one hand with an underhand grip, resting your upper arm against the preacher pad.","Keeping your upper arm stationary, exhale and curl the dumbbell up towards your shoulder.","Pause for a moment at the top, then inhale and slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"7D5bgLT"},{"id":"edb-0403","name":"כפיפת מרפק בישיבה עם משקולות","name_en":"dumbbell seated revers grip concentration curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל כשכפות הרגליים שטוחות על הרצפה ואחזו משקולת ביד אחת, כף היד פונה מעלה.","הניחו את המרפק על החלק הפנימי של הירך, ממש מעל הברך.","תוך שמירה על הזרוע העליונה ללא תנועה, נשפו וכופפו את המשקולת כלפי הכתף.","עצרו לרגע בשיא התנועה, תוך כיווץ שרירי הביצפס.","שאפו אוויר והורידו לאט את המשקולת בחזרה לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Sit on a bench with your feet flat on the ground and hold a dumbbell in one hand, palm facing up.","Rest your elbow on the inside of your thigh, just above the knee.","Keeping your upper arm stationary, exhale and curl the dumbbell towards your shoulder.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"lyKCLmK"},{"id":"edb-1738","name":"פשיטת מרפק ביד אחת אחיזה הפוכה בישיבה מעל הראש עם משקולות","name_en":"dumbbell seated reverse grip one arm overhead tricep extension","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שבו על ספסל עם גב ישר וכפות רגליים שטוחות על הרצפה.","אחזו משקולת באחיזה תחתונה ומתחו את הזרוע ישר מעל הראש.","הורידו את המשקולת מאחורי הראש על ידי כיפוף המרפק, תוך שמירה על הזרוע העליונה נייחת.","עצרו לרגע, ואז מתחו את הזרוע בחזרה כלפי מעלה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell with an underhand grip and extend your arm straight up overhead.","Lower the dumbbell behind your head by bending your elbow, keeping your upper arm stationary.","Pause for a moment, then extend your arm back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"5fKX7wi"},{"id":"edb-0405","name":"לחיצת כתפיים בישיבה עם משקולות","name_en":"dumbbell seated shoulder press","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["שבו על ספסל כשבכל יד משקולת המונחת על הירכיים.","הרימו את המשקולות לגובה הכתפיים, כפות הידיים פונות קדימה.","לחצו את המשקולות כלפי מעלה עד שהזרועות מתוחות לגמרי מעל הראש.","עצרו לרגע בקצה העליון, ואז הורידו לאט את המשקולות בחזרה לגובה הכתפיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with a dumbbell in each hand, resting on your thighs.","Raise the dumbbells to shoulder height, palms facing forward.","Press the dumbbells upward until your arms are fully extended overhead.","Pause for a moment at the top, then slowly lower the dumbbells back to shoulder height.","Repeat for the desired number of repetitions."],"mediaId":"znQUdHY"},{"id":"edb-0404","name":"לחיצת כתפיים בישיבה עם משקולות","name_en":"dumbbell seated shoulder press (parallel grip)","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["שבו על ספסל עם משקולת בכל יד, כשכפות הידיים פונות פנימה.","הרימו את המשקולות לגובה הכתפיים, כשהמרפקים כפופים וכפות הידיים פונות קדימה.","לחצו את המשקולות כלפי מעלה עד שהזרועות מתוחות לגמרי מעל הראש.","עצרו לרגע בקצה העליון, ואז הורידו לאט את המשקולות בחזרה לגובה הכתפיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with a dumbbell in each hand, palms facing inward.","Raise the dumbbells to shoulder height, elbows bent and palms facing forward.","Press the dumbbells upward until your arms are fully extended overhead.","Pause for a moment at the top, then slowly lower the dumbbells back to shoulder height.","Repeat for the desired number of repetitions."],"mediaId":"f1jf47L"},{"id":"edb-2188","name":"פשיטת מרפק בישיבה עם משקולות","name_en":"dumbbell seated triceps extension","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שבו על ספסל עם גב ישר וכפות רגליים שטוחות על הרצפה.","אחזו במשקולת בשתי הידיים ומתחו את הזרועות ישר מעל הראש.","כופפו את המרפקים והורידו את המשקולת מאחורי הראש, תוך שמירה על הזרועות העליונות קרובות לאוזניים.","עצרו לרגע, ואז יישרו את הזרועות וחזרו למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell with both hands and extend your arms straight up overhead.","Bend your elbows and lower the dumbbell behind your head, keeping your upper arms close to your ears.","Pause for a moment, then straighten your arms and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"kont8Ut"},{"id":"edb-0406","name":"משיכת כתפיים עם משקולות","name_en":"dumbbell shrug","muscle":"back","equipment":"dumbbell","target":"traps","bodyPart":"back","secondaryMuscles":["shoulders"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו משקולת בכל יד, כשכפות הידיים פונות לגוף.","שמרו על הזרועות ישרות ותנו למשקולות להשתלשל לצדי הגוף.","הרימו את הכתפיים כמה שיותר גבוה, כאילו אתם מנסים לגעת באוזניים עם הכתפיים.","החזיקו את הכיווץ לשנייה, ואז הורידו לאט את הכתפיים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand with your palms facing your body.","Keep your arms straight and let the dumbbells hang by your sides.","Raise your shoulders as high as possible, as if you are trying to touch your ears with your shoulders.","Hold the contraction for a second, then slowly lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"NJzBsGJ"},{"id":"edb-0407","name":"כפיפה צדית עם משקולות","name_en":"dumbbell side bend","muscle":"core","equipment":"dumbbell","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques"],"steps":["עמדו זקוף עם הרגליים ברוחב הכתפיים ואחזו משקולת ביד אחת, כשהיא משתלשלת לצד הגוף.","תוך שמירה על גב ישר וליבה מופעלת, כופפו לאט הצדה במותניים לכיוון הצד הנגדי למשקולת, והורידו את המשקל עד כמה שנוח לכם.","עצרו לרגע, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו על התנועה למספר החזרות הרצוי, ואז החליפו צד וחזרו שוב."],"steps_en":["Stand up straight with your feet shoulder-width apart and hold a dumbbell in one hand, letting it hang down by your side.","Keeping your back straight and your core engaged, slowly bend sideways at the waist towards the opposite side of the dumbbell, lowering the weight as far as you comfortably can.","Pause for a moment, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch sides and repeat."],"mediaId":"IpONWYv"},{"id":"edb-0408","name":"הרמה בשכיבה צדי עם משקולות","name_en":"dumbbell side lying one hand raise","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","rhomboids"],"steps":["שכבו על הצד כאשר הרגליים ישרות והראש נתמך על ידי הזרוע.","אחזו במשקולת ביד העליונה כשכף היד פונה כלפי מטה.","תוך שמירה על הזרוע ישרה, הרימו את המשקולת לגובה הכתף.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות חזרה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Lie on your side with your legs extended and your head supported by your arm.","Hold a dumbbell in your top hand with your palm facing down.","Keeping your arm straight, raise the dumbbell up to shoulder height.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"fTlkJop"},{"id":"edb-3664","name":"פלאנק צדי אחורי עם משקולות","name_en":"dumbbell side plank with rear fly","muscle":"back","equipment":"dumbbell","target":"upper back","bodyPart":"back","secondaryMuscles":["shoulders","core"],"steps":["התחילו בשכיבה על הצד כאשר הרגליים ישרות ומונחות זו על גבי זו.","הניחו את האמה על הרצפה ישירות מתחת לכתף, תוך שמירה על המרפק כפוף בזווית של 90 מעלות.","אחזו במשקולת ביד העליונה, כשהזרוע מתוחה ישר כלפי הרצפה.","הפעילו את הליבה והרימו את האגן מהרצפה, כך שייווצר קו ישר מהראש עד העקבים.","תוך שמירה על תנוחת פלאנק צדי, הרימו את המשקולת כלפי התקרה תוך כיווץ שכמות הגב זו לזו.","הורידו את המשקולת חזרה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Start by lying on your side with your legs extended and stacked on top of each other.","Place your forearm on the ground directly below your shoulder, keeping your elbow bent at a 90-degree angle.","Hold a dumbbell in your top hand, with your arm extended straight down towards the ground.","Engage your core and lift your hips off the ground, creating a straight line from your head to your heels.","While maintaining the side plank position, lift the dumbbell up towards the ceiling, squeezing your shoulder blades together.","Lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"X6ytgYZ"},{"id":"edb-3548","name":"dumbbell single arm overhead carry","name_en":"dumbbell single arm overhead carry","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","core"],"steps":["עמדו זקוף עם הרגליים ברוחב הכתפיים ואחזו משקולת ביד אחת.","הרימו את המשקולת מעל הראש, תוך מתיחה מלאה של הזרוע.","הפעילו את הליבה ושמרו על גב ישר בזמן ההליכה קדימה, תוך שמירה על המשקולת מעל הראש.","המשיכו בהליכה למרחק או לזמן הרצוי.","החליפו ידיים וחזרו על התרגיל."],"steps_en":["Stand tall with your feet shoulder-width apart, holding a dumbbell in one hand.","Raise the dumbbell overhead, fully extending your arm.","Engage your core and keep your back straight as you walk forward, maintaining the dumbbell overhead.","Continue walking for the desired distance or time.","Switch hands and repeat the exercise."],"mediaId":"mWBtgmb"},{"id":"edb-0409","name":"הרמת עקבים ברגל אחת עם משקולות","name_en":"dumbbell single leg calf raise","muscle":"legs","equipment":"dumbbell","target":"calves","bodyPart":"lower legs","secondaryMuscles":["ankles"],"steps":["עמדו על קצה מדרגה או פלטפורמה כשהעקבים תלויים מחוץ למדרגה והבהונות עליה.","אחזו משקולת ביד אחת והניחו את היד השנייה על קיר או מעקה לתמיכה.","הרימו את העקב כמה שיותר גבוה, כך שהגוף עולה על קצות האצבעות.","עצרו לרגע בקצה העליון, ואז הורידו לאט את העקב בחזרה מתחת לגובה המדרגה.","חזרו על התנועה למספר החזרות הרצוי, ולאחר מכן עברו לרגל השנייה."],"steps_en":["Stand on the edge of a step or platform with your heels hanging off and your toes on the step.","Hold a dumbbell in one hand and place your other hand on a wall or railing for support.","Raise your heel as high as possible, lifting your body up onto your toes.","Pause for a moment at the top, then slowly lower your heel back down below the step.","Repeat for the desired number of repetitions, then switch to the other leg."],"mediaId":"1kB3Wmk"},{"id":"edb-1757","name":"דדליפט ברגל אחת עם משקולות","name_en":"dumbbell single leg deadlift","muscle":"glutes","equipment":"dumbbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","lower back"],"steps":["עמדו עם הרגליים ברוחב האגן ואחזו משקולת ביד הימנית.","העבירו את משקל הגוף לרגל השמאלית והרימו מעט את כף הרגל הימנית מהרצפה.","תוך שמירה על גב ישר, כופפו קדימה במותניים והורידו את המשקולת לכיוון הרצפה.","במקביל, מתחו את הרגל הימנית ישר אחוריכם, תוך שמירה על כיפוף קל בברך השמאלית.","הורידו את המשקולת עד שפלג הגוף והרגל הימנית מקבילים לרצפה.","עצרו לרגע, ואז הפעילו את הישבן ושרירי הירך האחוריים כדי לחזור למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Stand with your feet hip-width apart, holding a dumbbell in your right hand.","Shift your weight onto your left leg and lift your right foot slightly off the ground.","Keeping your back straight, hinge forward at the hips and lower the dumbbell towards the ground.","At the same time, extend your right leg straight behind you, maintaining a slight bend in your left knee.","Lower the dumbbell until your torso and right leg are parallel to the ground.","Pause for a moment, then engage your glutes and hamstrings to return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"gKozT8X"},{"id":"edb-2805","name":"דדליפט ברגל אחת עם משקולות","name_en":"dumbbell single leg deadlift with stepbox support","muscle":"glutes","equipment":"dumbbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","lower back"],"steps":["עמדו עם הרגליים ברוחב האגן ואחזו משקולת ביד הימנית.","הניחו את הרגל השמאלית על קופסת מדרגה או משטח מוגבה מאחוריכם.","תוך שמירה על גב ישר וליבה מופעלת, כופפו קדימה במותניים והורידו את המשקולת לכיוון הרצפה.","בזמן הורדת המשקולת, הרימו במקביל את הרגל השמאלית מאחוריכם, תוך שמירה על קו ישר מהראש ועד העקב.","הורידו את המשקולת עד שתרגישו מתיחה בירך האחורית הימנית, ואז חזרו למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Stand with your feet hip-width apart, holding a dumbbell in your right hand.","Place your left foot on a stepbox or elevated surface behind you.","Keeping your back straight and core engaged, hinge forward at the hips, lowering the dumbbell towards the ground.","As you lower the dumbbell, simultaneously lift your left leg behind you, maintaining a straight line from head to heel.","Lower the dumbbell until you feel a stretch in your right hamstring, then return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"daBmy1Y"},{"id":"edb-0410","name":"סקוואט מפוצל ברגל אחת עם משקולות","name_en":"dumbbell single leg split squat","muscle":"legs","equipment":"dumbbell","target":"quads","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשבכל יד משקולת.","עשו צעד קדימה עם רגל אחת ומקמו את הרגליים כך שהרגל הקדמית שטוחה על הרצפה והרגל האחורית מוגבהת על ספסל או מדרגה.","הורידו את הגוף על ידי כיפוף הברך והירך הקדמיים, תוך שמירה על הברך האחורית כפופה מעט והעקב האחורי מורם מהרצפה.","המשיכו להוריד עד שהירך הקדמית מקבילה לרצפה, ואז דחפו דרך העקב הקדמי כדי לחזור למצב ההתחלתי.","חזרו על התנועה למספר החזרות הרצוי, ולאחר מכן החליפו רגליים וחזרו שוב."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand.","Take a step forward with one foot and position your feet so that your front foot is flat on the ground and your back foot is elevated on a bench or step.","Lower your body by bending your front knee and hip, keeping your back knee slightly bent and your back heel off the ground.","Continue lowering until your front thigh is parallel to the ground, then push through your front heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs and repeat."],"mediaId":"qx4fgX7"},{"id":"edb-0411","name":"סקוואט ברגל אחת עם משקולות","name_en":"dumbbell single leg squat","muscle":"glutes","equipment":"dumbbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשבכל יד משקולת.","מתחו רגל אחת קדימה והשאירו אותה מורמת מהרצפה לאורך כל התרגיל.","כופפו את רגל העמידה והורידו את הגוף כאילו אתם יושבים אחורה על כיסא.","שמרו על החזה מורם והגב ישר.","עצרו לרגע בתחתית, ואז דחפו דרך העקב כדי לחזור למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו רגליים."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand.","Extend one leg forward and keep it off the ground throughout the exercise.","Bend your standing leg and lower your body down as if sitting back into a chair.","Keep your chest up and your back straight.","Pause for a moment at the bottom, then push through your heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"mediaId":"H6ybluc"},{"id":"edb-0413","name":"סקוואט עם משקולות","name_en":"dumbbell squat","muscle":"glutes","equipment":"dumbbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו כשכפות הרגליים ברוחב הכתפיים, ואחזו משקולת בכל יד לצד הגוף.","תוך שמירה על החזה מורם והליבה מופעלת, הורידו את הגוף כלפי מטה על ידי כיפוף הברכיים והירכיים, כאילו אתם יושבים אחורה על כיסא.","המשיכו לרדת עד שהירכיים מקבילות לרצפה, או עד למקסימום שנוח לכם.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at your sides.","Keeping your chest up and core engaged, lower your body down by bending at the knees and hips, as if sitting back into a chair.","Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"HsvHqgf"},{"id":"edb-3560","name":"כפיפת פטיש בעמידה לסירוגין עם משקולות","name_en":"dumbbell standing alternate hammer curl and press","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms","shoulders"],"steps":["עמדו זקוף כשבכל יד משקולת, כפות הידיים פונות לגוף.","שמרו על המרפקים קרובים לפלג הגוף והגב ישר.","נשפו החוצה וכופפו את המשקולת ביד הימנית לכיוון הכתף, כשהזרוע העליונה נייחת.","המשיכו להרים את המשקולת עד שהביצפס מכווץ לגמרי והמשקולת בגובה הכתפיים.","שאפו אוויר והורידו לאט את המשקולת בחזרה לעמדת ההתחלה.","חזרו על הכיפוף עם היד השמאלית.","לאחר סיום הכיפוף עם היד השמאלית, נשפו ולחצו את המשקולת ביד הימנית מעל הראש.","מתחו את הזרוע לגמרי והחזיקו לרגע בקצה העליון.","שאפו אוויר והורידו לאט את המשקולת בחזרה לעמדת ההתחלה.","חזרו על הלחיצה עם היד השמאלית.","המשיכו להחליף בין כיפופים ולחיצות למספר החזרות הרצוי."],"steps_en":["Stand up straight with a dumbbell in each hand, palms facing your body.","Keep your elbows close to your torso and your back straight.","Exhale and curl the dumbbell in your right hand towards your shoulder, keeping your upper arm stationary.","Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat the curl with your left hand.","After completing the curl with your left hand, exhale and press the dumbbell in your right hand overhead.","Extend your arm fully and hold for a moment at the top.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat the press with your left hand.","Continue alternating between curls and presses for the desired number of repetitions."],"mediaId":"LeaZOIz"},{"id":"edb-0414","name":"לחיצה מעל הראש בעמידה לסירוגין עם משקולות","name_en":"dumbbell standing alternate overhead press","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו משקולת בכל יד בגובה הכתפיים, כשכפות הידיים פונות קדימה.","לחצו משקולת אחת מעל הראש, תוך מתיחה מלאה של הזרוע.","הורידו את המשקולת בחזרה לגובה הכתפיים.","חזרו עם הזרוע השנייה.","המשיכו להחליף ידיים למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder level with your palms facing forward.","Press one dumbbell overhead, fully extending your arm.","Lower the dumbbell back to shoulder level.","Repeat with the other arm.","Continue alternating arms for the desired number of repetitions."],"mediaId":"bBi35y3"},{"id":"edb-0415","name":"הרמה בעמידה לסירוגין עם משקולות","name_en":"dumbbell standing alternate raise","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשבכל יד משקולת וכפות הידיים פונות לגוף.","שמרו על גב ישר ושרירי ליבה מופעלים.","הרימו משקולת אחת הצדה, תוך שמירה על הזרוע ישרה וכף היד פונה כלפי מטה.","המשיכו להרים עד שהיד מקבילה לרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה.","חזרו עם הזרוע השנייה.","החליפו בין הזרועות למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your body.","Keep your back straight and your core engaged.","Raise one dumbbell to the side, keeping your arm straight and your palm facing down.","Continue lifting until your arm is parallel to the ground.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat with the other arm.","Alternate between arms for the desired number of repetitions."],"mediaId":"SxHteRW"},{"id":"edb-1739","name":"בעיטה אחורית בעמידה לסירוגין עם משקולות","name_en":"dumbbell standing alternating tricep kickback","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשבכל יד משקולת.","כופפו מעט את הברכיים והטו את הגוף קדימה במפרקי הירך, תוך שמירה על גב ישר.","מתחו את הזרועות ישר אחורה, תוך שמירה על המרפקים קרובים לגוף.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו עם הזרוע השנייה, תוך החלפת צדדים בכל חזרה."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Extend your arms straight back, keeping your elbows close to your body.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat with the other arm, alternating sides with each repetition."],"mediaId":"Gi2BXfK"},{"id":"edb-2143","name":"dumbbell standing around world","name_en":"dumbbell standing around world","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","forearms"],"steps":["עמדו כשכפות הרגליים ברוחב הכתפיים ואחזו משקולת בכל יד.","מתחו את הזרועות ישר הצדה בגובה הכתפיים, כשכפות הידיים פונות כלפי מטה.","תוך שמירה על הזרועות ישרות, סובבו לאט את הזרועות בתנועה מעגלית, תוך הבאת המשקולות לפני הגוף ואז מעל הראש.","המשיכו בתנועה המעגלית, תוך החזרת המשקולות למטה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand.","Extend your arms straight out to the sides at shoulder height, palms facing down.","Keeping your arms straight, slowly rotate your arms in a circular motion, bringing the dumbbells in front of your body and then overhead.","Continue the circular motion, bringing the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"RSOsp5d"},{"id":"edb-1740","name":"פשיטת מרפק ביד אחת בעמידה בהטיה עם משקולות","name_en":"dumbbell standing bent over one arm triceps extension","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders","back"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו משקולת ביד אחת.","התכופפו קדימה במותניים, תוך שמירה על גב ישר ומקביל לרצפה.","מתחו את הזרוע ישר אחורה, תוך שמירה על המרפק קרוב לגוף.","הורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Stand with your feet shoulder-width apart and hold a dumbbell in one hand.","Bend forward at the waist, keeping your back straight and parallel to the ground.","Extend your arm straight back, keeping your elbow close to your body.","Slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"CJwa0vD"},{"id":"edb-1741","name":"פשיטת מרפק בשתי ידיים בעמידה בהטיה עם משקולות","name_en":"dumbbell standing bent over two arm triceps extension","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders","back"],"steps":["עמדו כשכפות הרגליים ברוחב הכתפיים ואחזו משקולת בכל יד.","התכופפו קדימה מהמותניים, תוך שמירה על גב ישר וברכיים כפופות מעט.","מתחו את הזרועות ישר אחורה, תוך שמירה על המרפקים קרובים לגוף.","הורידו לאט את המשקולות בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand.","Bend forward at the waist, keeping your back straight and your knees slightly bent.","Extend your arms straight back, keeping your elbows close to your body.","Slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"3T12T87"},{"id":"edb-0416","name":"כפיפת מרפק בעמידה עם משקולות","name_en":"dumbbell standing biceps curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף כשבכל יד משקולת, כפות הידיים פונות קדימה והידיים ישרות לגמרי.","תוך שמירה על הזרוע העליונה ללא תזוזה, נשפו החוצה וכופפו את המשקולות תוך כיווץ שרירי הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand up straight with a dumbbell in each hand, palms facing forward and arms fully extended.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"3s4NnTh"},{"id":"edb-0417","name":"הרמת עקבים בעמידה עם משקולות","name_en":"dumbbell standing calf raise","muscle":"legs","equipment":"dumbbell","target":"calves","bodyPart":"lower legs","secondaryMuscles":["ankles"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשבכל יד משקולת.","הרימו את העקבים מהרצפה כמה שיותר גבוה, תוך שימוש בשרירי השוק.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקבים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand.","Raise your heels off the ground as high as possible, using your calves.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"dPmaUaU"},{"id":"edb-0418","name":"כפיפת מרפק בעמידה עם משקולות","name_en":"dumbbell standing concentration curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו משקולת ביד אחת, כשהזרוע מתוחה לגמרי וכף היד פונה פנימה.","הניחו את היד הנגדית על הירך לתמיכה.","תוך שמירה על הזרוע העליונה ללא תנועה, נשפו וכופפו את המשקולת כלפי הכתף תוך כיווץ הביצפס.","המשיכו להרים את המשקולת עד שהביצפס מכווץ לגמרי והמשקולת בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והורידו לאט את המשקולת בחזרה לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Stand with your feet shoulder-width apart and hold a dumbbell in one hand, with your arm fully extended and palm facing inwards.","Place your opposite hand on your thigh for support.","Keeping your upper arm stationary, exhale and curl the dumbbell towards your shoulder by contracting your biceps.","Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"7inpWch"},{"id":"edb-0419","name":"הרמה קדמית בעמידה עם משקולות","name_en":"dumbbell standing front raise above head","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","biceps"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשבכל יד משקולת באחיזה עליונה.","שמרו על הזרועות ישרות והרימו את המשקולות לפניכם, עד מעל הראש.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.","Keep your arms straight and lift the dumbbells in front of you, raising them above your head.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"laVRfDf"},{"id":"edb-2321","name":"כפיפת מרפק בעמידה עם משקולות","name_en":"dumbbell standing inner biceps curl v. 2","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף כשבכל יד משקולת, כפות הידיים פונות לגוף.","שמרו על המרפקים צמודים לגוף וסובבו את כפות הידיים עד שהן פונות קדימה.","תוך שמירה על הזרועות העליונות ללא תנועה, כופפו את המשקולות תוך כיווץ הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","התחילו להחזיר לאט את המשקולות למצב ההתחלתי תוך שאיפת אוויר.","חזרו על התנועה למספר החזרות המומלץ."],"steps_en":["Stand up straight with a dumbbell in each hand, palms facing your torso.","Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward.","While holding your upper arms stationary, curl the weights while contracting your biceps.","Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Slowly begin to bring the dumbbells back to the starting position as your breathe in.","Repeat for the recommended amount of repetitions."],"mediaId":"vKilzz3"},{"id":"edb-0420","name":"בעיטה אחורית בעמידה עם משקולות","name_en":"dumbbell standing kickback","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["עמדו כשכפות הרגליים ברוחב הכתפיים ואחזו משקולת בכל יד.","כופפו מעט את הברכיים והטו את הגוף קדימה במפרקי הירך, תוך שמירה על גב ישר.","יישרו את הידיים ישר לאחור, וכווצו את הטריצפס בשיא התנועה.","עצרו לרגע, ולאחר מכן הורידו את המשקולות באיטיות בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Extend your arms straight back, squeezing your triceps at the top of the movement.","Pause for a moment, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"UmpPAAe"},{"id":"edb-0421","name":"כפיפת מרפק ביד אחת בעמידה עם משקולות","name_en":"dumbbell standing one arm concentration curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף עם הרגליים ברוחב הכתפיים ואחזו משקולת ביד אחת, כשכף היד פונה כלפי מעלה.","הניחו את היד הפנויה על הירך לתמיכה.","תוך שמירה על הזרוע העליונה ללא תנועה, נשפו וכופפו את המשקולת כלפי הכתף תוך כיווץ הביצפס.","המשיכו להרים את המשקולת עד שהביצפס מכווץ לגמרי והמשקולת בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והורידו לאט את המשקולת בחזרה לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Stand up straight with your feet shoulder-width apart and hold a dumbbell in one hand, palm facing up.","Place your free hand on your thigh for support.","Keeping your upper arm stationary, exhale and curl the dumbbell towards your shoulder by contracting your biceps.","Continue to raise the dumbbell until your biceps are fully contracted and the dumbbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"8fgqP5a"},{"id":"edb-0422","name":"כפיפת מרפק ביד אחת בשיפוע בעמידה עם משקולות","name_en":"dumbbell standing one arm curl (over incline bench)","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו משקולת ביד אחת, כשכף היד פונה קדימה.","הניחו את היד השנייה על ספסל משופע לתמיכה.","תוך שמירה על הזרוע העליונה ללא תנועה, נשפו וכופפו את המשקולת כלפי הכתף תוך כיווץ הביצפס.","עצרו לרגע בשיא התנועה, ולאחר מכן שאפו אוויר והורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in one hand with your palm facing forward.","Place your other hand on an incline bench for support.","Keeping your upper arm stationary, exhale and curl the dumbbell towards your shoulder by contracting your biceps.","Pause for a moment at the top, then inhale and slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"BIb1tGo"},{"id":"edb-1680","name":"כפיפת מרפק ביד אחת בשיפוע בעמידה עם משקולות","name_en":"dumbbell standing one arm curl over incline bench","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו משקולת ביד אחת.","הניחו את היד השנייה על ספסל משופע לתמיכה.","תוך שמירה על הזרוע העליונה נייחת, כופפו את המשקולת לכיוון הכתף על ידי כיווץ הביצפס.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in one hand.","Place your other hand on an incline bench for support.","Keeping your upper arm stationary, curl the dumbbell towards your shoulder by contracting your biceps.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"EmlJR2y"},{"id":"edb-0423","name":"פשיטה ביד אחת בעמידה עם משקולות","name_en":"dumbbell standing one arm extension","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו משקולת ביד אחת.","הרימו את המשקולת מעל הראש, תוך מתיחה מלאה של הזרוע.","שמרו על הזרוע העליונה קרובה לראש וניצבת לרצפה.","הורידו לאט את המשקולת מאחורי הראש תוך כיפוף המרפק.","עצרו לרגע, ולאחר מכן הרימו את המשקולת בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in one hand.","Raise the dumbbell overhead, fully extending your arm.","Keep your upper arm close to your head and perpendicular to the ground.","Slowly lower the dumbbell behind your head, bending your elbow.","Pause for a moment, then raise the dumbbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"BCUR88E"},{"id":"edb-0424","name":"לחיצה ביד אחת בעמידה עם משקולות","name_en":"dumbbell standing one arm palm in press","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו משקולת ביד אחת בגובה הכתף, כשכף היד פונה פנימה.","הפעילו את הליבה ושמרו על גב ישר.","דחפו את המשקולת כלפי מעלה עד שהיד ישרה לגמרי.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ליד השנייה."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in one hand at shoulder height with your palm facing inwards.","Engage your core and keep your back straight.","Press the dumbbell upwards until your arm is fully extended.","Pause for a moment at the top, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"mediaId":"ocYc6Db"},{"id":"edb-0425","name":"כפיפת מרפק ביד אחת בעמידה הפוך עם משקולות","name_en":"dumbbell standing one arm reverse curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף עם הרגליים ברוחב הכתפיים ואחזו משקולת ביד אחת באחיזה עליונה.","שמרו על הזרוע מתוחה לגמרי וקרובה לגוף, כשכף היד פונה כלפי מטה.","כופפו לאט את המשקולת כלפי הכתף, תוך שמירה על הזרוע העליונה ללא תנועה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות חזרה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ליד השנייה."],"steps_en":["Stand up straight with your feet shoulder-width apart and hold a dumbbell in one hand with an overhand grip.","Keep your arm fully extended and close to your body, with your palm facing down.","Slowly curl the dumbbell up towards your shoulder, keeping your upper arm stationary.","Pause for a moment at the top, then slowly lower the dumbbell back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"mediaId":"DU5Kkj2"},{"id":"edb-0426","name":"לחיצת כתפיים מעל הראש","name_en":"dumbbell standing overhead press","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו משקולת בכל יד בגובה הכתפיים, כשכפות הידיים פונות קדימה.","לחצו את המשקולות כלפי מעלה עד שהזרועות מתוחות לגמרי מעל הראש.","עצרו לרגע בקצה העליון, ואז הורידו לאט את המשקולות בחזרה לגובה הכתפיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder level with your palms facing forward.","Press the dumbbells upward until your arms are fully extended overhead.","Pause for a moment at the top, then slowly lower the dumbbells back down to shoulder level.","Repeat for the desired number of repetitions."],"mediaId":"A6wtbuL"},{"id":"edb-0427","name":"לחיצה בעמידה עם משקולות","name_en":"dumbbell standing palms in press","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","chest"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו משקולת בכל יד בגובה הכתפיים, כשכפות הידיים פונות פנימה.","תוך שמירה על הליבה מופעלת והגב ישר, לחצו את המשקולות כלפי מעלה עד שהזרועות מתוחות לגמרי מעל הראש.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at shoulder level with your palms facing inwards.","Keeping your core engaged and your back straight, press the dumbbells upwards until your arms are fully extended overhead.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"UilDHSs"},{"id":"edb-0428","name":"כפיפת מרפק בכיסא הטפה בעמידה עם משקולות","name_en":"dumbbell standing preacher curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף עם הרגליים ברוחב הכתפיים ואחזו משקולת בכל יד, כשכפות הידיים פונות קדימה.","הניחו את גב הזרועות העליונות על ספסל הפריצ'ר או ספסל משופע, כשהמרפקים כפופים מעט.","תוך שמירה על הזרוע העליונה ללא תזוזה, נשפו החוצה וכופפו את המשקולות תוך כיווץ שרירי הביצפס.","המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand upright with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward.","Rest the back of your upper arms against the preacher bench or an incline bench, with your elbows slightly bent.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the dumbbells until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"hq2hyDH"},{"id":"edb-0429","name":"כפיפת מרפק בעמידה הפוך עם משקולות","name_en":"dumbbell standing reverse curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף עם הרגליים ברוחב הכתפיים ואחזו משקולת בכל יד, כשכפות הידיים פונות לגוף.","תוך שמירה על הזרועות העליונות ללא תנועה, נשפו וכופפו את המשקולות תוך כיווץ הביצפס. המשיכו להרים את המשקולות עד שהביצפס מכווץ לגמרי והמשקולות בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand up straight with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing your body.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"0IgNjSM"},{"id":"edb-0430","name":"פשיטת מרפק בעמידה עם משקולות","name_en":"dumbbell standing triceps extension","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו משקולת ביד אחת.","הרימו את המשקולת מעל הראש, תוך שמירה על הזרוע ישרה.","כופפו את המרפק והורידו את המשקולת מאחורי הראש, תוך שמירה על הזרוע העליונה ללא תנועה.","מתחו את הזרוע בחזרה כלפי מעלה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a dumbbell in one hand.","Raise the dumbbell overhead, keeping your arm straight.","Bend your elbow and lower the dumbbell behind your head, keeping your upper arm stationary.","Extend your arm back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"PdmaD0N"},{"id":"edb-2293","name":"כפיפת מרפק בכיסא הטפה בעמידה עם משקולות","name_en":"dumbbell standing zottman preacher curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף כשבכל יד משקולת, כפות הידיים פונות קדימה.","הניחו את הזרועות העליונות על ספסל הפריצ'ר ושמרו על המרפקים כפופים מעט.","כופפו את המשקולות כלפי הכתפיים תוך שמירה על הזרועות העליונות ללא תנועה.","בקצה העליון של התנועה, סובבו את פרקי הידיים כך שכפות הידיים יפנו כלפי מטה.","הורידו לאט את המשקולות בחזרה למצב ההתחלתי, תוך סיבוב פרקי הידיים בחזרה למצב ההתחלתי גם כן.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand up straight with a dumbbell in each hand, palms facing forward.","Place your upper arms against the preacher bench and keep your elbows slightly bent.","Curl the dumbbells up towards your shoulders while keeping your upper arms stationary.","At the top of the movement, rotate your wrists so that your palms are facing downward.","Slowly lower the dumbbells back to the starting position, rotating your wrists back to the starting position as well.","Repeat for the desired number of repetitions."],"mediaId":"P2nRiUa"},{"id":"edb-1684","name":"כפיפת מרפק ברגל אחת עם משקולות","name_en":"dumbbell step up single leg balance with bicep curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["quadriceps","glutes","hamstrings"],"steps":["עמדו מול מדרגה או פלטפורמה עם משקולת בכל יד, כשכפות הידיים פונות לגוף.","הניחו את הרגל הימנית על המדרגה, תוך הקפדה שכל כף הרגל נוגעת במשטח.","הפעילו את הליבה ודחפו דרך העקב הימני כדי להרים את הגוף אל המדרגה, תוך הבאת הברך השמאלית לכיוון החזה.","בקצה העליון של התנועה, בצעו כיפוף ביצפס על ידי כיפוף המרפקים והבאת המשקולות לכיוון הכתפיים.","הורידו את המשקולות בחזרה למטה והורידו במקביל את כף הרגל השמאלית בחזרה לרצפה.","חזרו על התנועה בצד הנגדי, עם עלייה על הרגל השמאלית וכיפוף המשקולות.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Stand in front of a step or platform with a dumbbell in each hand, palms facing your body.","Place your right foot on the step, ensuring your entire foot is in contact with the surface.","Engage your core and push through your right heel to lift your body up onto the step, bringing your left knee up towards your chest.","At the top of the movement, perform a bicep curl by bending your elbows and bringing the dumbbells towards your shoulders.","Lower the dumbbells back down and simultaneously lower your left foot back to the ground.","Repeat the movement on the opposite side, stepping up with your left foot and curling the dumbbells.","Continue alternating sides for the desired number of repetitions."],"mediaId":"76vfTdU"},{"id":"edb-0431","name":"עלייה על ספסל עם משקולות","name_en":"dumbbell step-up","muscle":"glutes","equipment":"dumbbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו מול ספסל או מדרגה עם משקולת בכל יד, כשכפות הידיים פונות לגוף.","הניחו את הרגל הימנית על הספסל או המדרגה, תוך הקפדה שכל כף הרגל נוגעת במשטח.","דחפו דרך העקב הימני והרימו את הגוף אל הספסל או המדרגה, תוך יישור הרגל הימנית.","הביאו את הרגל השמאלית אל הספסל או המדרגה, כשאתם עומדים זקוף לגמרי.","רדו למטה עם הרגל השמאלית, ולאחריה הרגל הימנית, וחזרו למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו רגליים."],"steps_en":["Stand in front of a bench or step with a dumbbell in each hand, palms facing your body.","Place your right foot on the bench or step, ensuring your entire foot is in contact with the surface.","Push through your right heel and lift your body up onto the bench or step, straightening your right leg.","Bring your left foot up onto the bench or step, standing fully upright.","Step back down with your left foot, followed by your right foot, returning to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"mediaId":"aXtJhlg"},{"id":"edb-2796","name":"עלייה על ספסל עם משקולות","name_en":"dumbbell step-up lunge","muscle":"legs","equipment":"dumbbell","target":"quads","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings","calves"],"steps":["עמדו מול מדרגה או פלטפורמה עם משקולת בכל יד, כשכפות הידיים פונות לצדדים.","הניחו את הרגל הימנית על המדרגה, תוך הקפדה שכל כף הרגל על המשטח.","דחפו דרך העקב הימני והרימו את הגוף אל המדרגה, תוך הבאת הרגל השמאלית גם היא.","כששתי הרגליים על המדרגה, הורידו את הרגל השמאלית בחזרה למצב ההתחלתי, תוך שמירה על הרגל הימנית על המדרגה.","חזרו על התנועה, תוך החלפת הרגל שאיתה אתם עולים בכל פעם.","המשיכו למספר החזרות הרצוי."],"steps_en":["Stand in front of a step or platform with a dumbbell in each hand, palms facing your sides.","Place your right foot on the step, ensuring your entire foot is on the surface.","Push through your right heel and lift your body up onto the step, bringing your left foot up as well.","Once both feet are on the step, lower your left foot back down to the starting position, keeping your right foot on the step.","Repeat the movement, alternating which foot you step up with each time.","Continue for the desired number of repetitions."],"mediaId":"gFyFj9z"},{"id":"edb-2812","name":"סקוואט מפוצל עם משקולות","name_en":"dumbbell step-up split squat","muscle":"legs","equipment":"dumbbell","target":"quads","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings","calves"],"steps":["עמדו מול ספסל או מדרגה עם משקולת בכל יד, כשכפות הידיים פונות לגוף.","הניחו את הרגל הימנית על הספסל או המדרגה, תוך הקפדה שכל כף הרגל נוגעת במשטח.","עלו על הספסל או המדרגה עם הרגל הימנית, תוך דחיפה דרך העקב כדי להרים את הגוף.","בזמן העלייה, הרימו במקביל את הברך השמאלית לכיוון החזה.","עצרו בקצה העליון של התנועה, ואז הורידו לאט את הרגל השמאלית בחזרה לרצפה תוך שמירה על הרגל הימנית על הספסל או המדרגה.","חזרו על התנועה עם הרגל השמאלית על הספסל או המדרגה.","המשיכו להחליף בין הרגל הימנית לשמאלית למספר החזרות הרצוי."],"steps_en":["Stand in front of a bench or step with a dumbbell in each hand, palms facing your body.","Place your right foot on the bench or step, ensuring your entire foot is in contact with the surface.","Step up onto the bench or step with your right foot, pushing through your heel to lift your body up.","As you step up, simultaneously lift your left knee towards your chest.","Pause at the top of the movement, then slowly lower your left foot back to the ground while keeping your right foot on the bench or step.","Repeat the movement with your left foot on the bench or step.","Continue alternating between your right and left foot for the desired number of repetitions."],"mediaId":"QjE2DcA"},{"id":"edb-0432","name":"דדליפט רגליים ישרות עם משקולות","name_en":"dumbbell stiff leg deadlift","muscle":"glutes","equipment":"dumbbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","lower back"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשבכל יד משקולת באחיזה עליונה.","תוך שמירה על גב ישר וליבה מופעלת, כופפו במותניים והורידו את המשקולות לכיוון הרצפה, תוך כיפוף קל בברכיים.","הורידו את המשקולות עד שתרגישו מתיחה בשרירי הירך האחוריים, ואז כווצו את הישבן ודחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.","Keeping your back straight and your core engaged, hinge at the hips and lower the dumbbells towards the ground, allowing a slight bend in your knees.","Lower the dumbbells until you feel a stretch in your hamstrings, then squeeze your glutes and push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"5eLRITT"},{"id":"edb-0433","name":"פולאובר עם משקולות","name_en":"dumbbell straight arm pullover","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["latissimus dorsi","triceps"],"steps":["שכבו ישר על ספסל כשהראש בקצה אחד והרגליים נטועות היטב על הרצפה.","אחזו משקולת בשתי הידיים ופשטו אותן ישר מעל החזה.","תוך שמירה על הזרועות ישרות, הורידו לאט את המשקולת מאחורי הראש בתנועה קשתית.","עצרו לרגע, ולאחר מכן הרימו את המשקולת בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your head at one end and your feet planted firmly on the ground.","Hold a dumbbell with both hands and extend your arms straight above your chest.","Keeping your arms straight, slowly lower the dumbbell behind your head in an arc-like motion.","Pause for a moment, then raise the dumbbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"i8BdLTK"},{"id":"edb-0434","name":"דדליפט עם משקולות","name_en":"dumbbell straight leg deadlift","muscle":"glutes","equipment":"dumbbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","lower back"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשבכל יד משקולת באחיזה עליונה.","תוך שמירה על גב ישר וליבה מופעלת, כופפו במותניים והורידו את המשקולות לכיוון הרצפה, תוך הטיית פלג הגוף קדימה.","המשיכו להוריד את המשקולות עד שתרגישו מתיחה בשרירי הירך האחוריים, תוך שמירה על כיפוף קל בברכיים.","עצרו לרגע בתחתית התנועה, ולאחר מכן הפעילו את שרירי הישבן והירך האחוריים כדי להרים את פלג הגוף העליון חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.","Keeping your back straight and your core engaged, hinge at the hips and lower the dumbbells towards the ground, allowing your torso to lean forward.","Continue lowering the dumbbells until you feel a stretch in your hamstrings, keeping your knees slightly bent.","Pause for a moment at the bottom, then engage your glutes and hamstrings to lift your torso back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"oom75KC"},{"id":"edb-2808","name":"dumbbell sumo pull through","name_en":"dumbbell sumo pull through","muscle":"glutes","equipment":"dumbbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps","core"],"steps":["עמדו עם הרגליים רחבות יותר מרוחב הכתפיים, כשהבהונות פונות החוצה.","אחזו במשקולת בשתי הידיים לפני הגוף, כשהזרועות מתוחות.","כופפו את הברכיים והורידו את האגן לתנוחת סקוואט, תוך שמירה על גב ישר.","הורידו את המשקולת בין הרגליים, תוך שמירה על הזרועות ישרות.","דחפו דרך העקבים ומתחו את הירכיים קדימה, תוך משיכת המשקולת כלפי מעלה ולפני הגוף.","כווצו את הישבן בקצה העליון של התנועה, ואז הורידו את המשקולת בחזרה בין הרגליים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet wider than shoulder-width apart, toes pointed outwards.","Hold a dumbbell with both hands in front of your body, arms extended.","Bend your knees and lower your hips down into a squat position, keeping your back straight.","Lower the dumbbell down between your legs, keeping your arms straight.","Drive through your heels and extend your hips forward, pulling the dumbbell up and in front of your body.","Squeeze your glutes at the top of the movement, then lower the dumbbell back down between your legs.","Repeat for the desired number of repetitions."],"mediaId":"BmrwWzo"},{"id":"edb-2803","name":"סקוואט עם משקולות","name_en":"dumbbell supported squat","muscle":"legs","equipment":"dumbbell","target":"quads","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings","calves"],"steps":["עמדו כשכפות הרגליים ברוחב הכתפיים, ואחזו משקולת בכל יד לצד הגוף.","תוך שמירה על החזה מורם והליבה מופעלת, הורידו לאט את הגוף על ידי כיפוף הברכיים ודחיפת האגן אחורה.","המשיכו לרדת עד שהירכיים מקבילות לרצפה, או עד למקסימום שנוח לכם.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand at your sides.","Keeping your chest up and core engaged, slowly lower your body down by bending your knees and pushing your hips back.","Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"r5DgrW9"},{"id":"edb-0436","name":"לחיצה עם משקולות","name_en":"dumbbell tate press","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שבו על ספסל ישר עם משקולת בכל יד, כשכפות הידיים פונות זו לזו.","הרימו את המשקולות לגובה הכתפיים, ואז סובבו את פרקי הידיים כך שכפות הידיים יפנו הרחק מכם.","לחצו את המשקולות כלפי מעלה עד שהזרועות מתוחות לגמרי, ואז הורידו אותן בחזרה לגובה הכתפיים.","סובבו את פרקי הידיים בחזרה למצב ההתחלתי וחזרו למספר החזרות הרצוי."],"steps_en":["Sit on a flat bench with a dumbbell in each hand, palms facing each other.","Raise the dumbbells to shoulder height, then rotate your wrists so that your palms are facing away from you.","Press the dumbbells up until your arms are fully extended, then lower them back down to shoulder height.","Rotate your wrists back to the starting position and repeat for the desired number of repetitions."],"mediaId":"s5PdDyY"},{"id":"edb-1742","name":"בעיטה אחורית עם משקולות","name_en":"dumbbell tricep kickback with stork stance","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["עמדו כשכפות הרגליים ברוחב הכתפיים ואחזו משקולת ביד ימין.","כופפו מעט את הברכיים והטו את הגוף קדימה במפרקי הירך, תוך שמירה על גב ישר.","הביאו את המרפק הימני כלפי מעלה לצד הגוף, כשהוא כפוף בזווית של 90 מעלות.","מתחו את הזרוע הימנית ישר אחורה, תוך כיווץ שריר הטריצפס.","עצרו לרגע, ואז הורידו לאט את המשקולת בחזרה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Stand with your feet shoulder-width apart and hold a dumbbell in your right hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Bring your right elbow up to your side, keeping it bent at a 90-degree angle.","Extend your right arm straight back, squeezing your triceps.","Pause for a moment, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"wOLmCXc"},{"id":"edb-1743","name":"לחיצת חזה עם משקולות","name_en":"dumbbell twisting bench press","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["שכבו על ספסל כשכפות הרגליים שטוחות על הרצפה והגב צמוד לספסל.","אחזו משקולת בכל יד באחיזה עליונה, כשכפות הידיים פונות הרחק מכם.","יישרו את הידיים ישר מעל החזה, תוך שמירה על כיפוף קל במרפקים.","הורידו את המשקולות לכיוון החזה, תוך שמירה על המרפקים קרובים לגוף.","בזמן הורדת המשקולות, סובבו את פרקי הידיים כך שכפות הידיים יפנו אליכם בתחתית התנועה.","עצרו לרגע בתחתית, ואז היפכו את התנועה על ידי לחיצת המשקולות בחזרה כלפי מעלה למצב ההתחלתי.","בזמן לחיצת המשקולות כלפי מעלה, סובבו את פרקי הידיים בחזרה למצב ההתחלתי כשכפות הידיים פונות הרחק מכם.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Hold a dumbbell in each hand with an overhand grip, palms facing away from you.","Extend your arms straight up over your chest, keeping a slight bend in your elbows.","Lower the dumbbells down towards your chest, keeping your elbows close to your body.","As you lower the dumbbells, twist your wrists so that your palms face towards you at the bottom of the movement.","Pause for a moment at the bottom, then reverse the movement by pressing the dumbbells back up to the starting position.","As you press the dumbbells up, twist your wrists back to the starting position with palms facing away from you.","Repeat for the desired number of repetitions."],"mediaId":"z6TAHoT"},{"id":"edb-0437","name":"חתירה זקופה עם משקולות","name_en":"dumbbell upright row","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","biceps"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשבכל יד משקולת באחיזה עליונה.","תנו למשקולות להשתלשל לפני הירכיים, כשהזרועות מתוחות לגמרי.","תוך שמירה על גב ישר וליבה מופעלת, נשפו והרימו את המשקולות ישר כלפי הסנטר, תוך הובלה עם המרפקים.","עצרו לרגע בשיא התנועה, לאחר מכן שאפו אוויר והורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.","Let the dumbbells hang in front of your thighs, with your arms fully extended.","Keeping your back straight and your core engaged, exhale and lift the dumbbells straight up towards your chin, leading with your elbows.","Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ainizkb"},{"id":"edb-1765","name":"חתירה זקופה עם משקולות","name_en":"dumbbell upright row (back pov)","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","biceps"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשבכל יד משקולת באחיזה עליונה.","תנו למשקולות להשתלשל לפני הירכיים, כשהזרועות מתוחות לגמרי וכפות הידיים פונות לגוף.","תוך שמירה על גב ישר וליבה מופעלת, נשפו והרימו את המשקולות ישר כלפי הסנטר, תוך הובלה עם המרפקים.","המשיכו להרים עד שהמשקולות בגובה הכתפיים, כשהמרפקים פונים הצדה.","עצרו לרגע בשיא התנועה, לאחר מכן שאפו אוויר והורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with an overhand grip.","Let the dumbbells hang in front of your thighs, with your arms fully extended and your palms facing your body.","Keeping your back straight and your core engaged, exhale and lift the dumbbells straight up towards your chin, leading with your elbows.","Continue lifting until the dumbbells are at shoulder height, with your elbows pointing out to the sides.","Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Iptlv6x"},{"id":"edb-0864","name":"dumbbell upright shoulder external rotation","name_en":"dumbbell upright shoulder external rotation","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["rotator cuff","trapezius"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו משקולת בכל יד, כשכפות הידיים פונות לגוף.","הרימו את הזרועות הצדה עד שהן מקבילות לרצפה, תוך שמירה על כיפוף קל במרפקים.","סובבו את הזרועות החוצה, תוך הבאת המשקולות כלפי הראש, תוך שמירה על המרפקים באותה תנוחה.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand with your palms facing your body.","Raise your arms out to the sides until they are parallel to the ground, keeping your elbows slightly bent.","Rotate your arms externally, bringing the dumbbells up towards your head while keeping your elbows in the same position.","Pause for a moment at the top, then slowly lower the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"x306lCW"},{"id":"edb-5201","name":"כפיפת מרפק עם משקולות","name_en":"dumbbell waiter biceps curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms","shoulders"],"steps":["עמדו זקוף כשבכל יד משקולת, כפות הידיים פונות קדימה.","שמרו על הזרועות העליונות קרובות לגוף והמרפקים צמודים.","כופפו לאט את המשקולות כלפי הכתפיים, תוך שמירה על פרקי הידיים ישרים.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand up straight with a dumbbell in each hand, palms facing forward.","Keep your upper arms close to your body and your elbows tucked in.","Slowly curl the dumbbells up towards your shoulders, keeping your wrists straight.","Pause for a moment at the top, then slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"KOpzGBL"},{"id":"edb-0438","name":"לחיצה עם משקולות","name_en":"dumbbell w-press","muscle":"shoulders","equipment":"dumbbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","chest"],"steps":["שבו על ספסל עם משקולת בכל יד, כשכפות הידיים פונות קדימה.","הרימו את המשקולות לגובה הכתפיים, כשהמרפקים כפופים וכפות הידיים פונות קדימה.","לחצו את המשקולות כלפי מעלה עד שהזרועות מתוחות לגמרי מעל הראש.","הורידו את המשקולות בחזרה לגובה הכתפיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with a dumbbell in each hand, palms facing forward.","Raise the dumbbells to shoulder height, elbows bent and palms facing forward.","Press the dumbbells upward until your arms are fully extended overhead.","Lower the dumbbells back to shoulder height.","Repeat for the desired number of repetitions."],"mediaId":"vmwLyCg"},{"id":"edb-0439","name":"כפיפת מרפק עם משקולות","name_en":"dumbbell zottman curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף כשבכל יד משקולת, כפות הידיים פונות לגוף.","שמרו על המרפקים קרובים לפלג הגוף וסובבו את כפות הידיים כך שיפנו קדימה.","כופפו את המשקולות כלפי הכתפיים תוך שמירה על הזרועות העליונות ללא תנועה.","בקצה העליון של התנועה, סובבו את פרקי הידיים כך שכפות הידיים יפנו הרחק מהגוף.","הורידו לאט את המשקולות בחזרה למצב ההתחלתי, תוך סיבוב כפות הידיים בחזרה לפנות לגוף.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand up straight with a dumbbell in each hand, palms facing your body.","Keep your elbows close to your torso and rotate your palms to face forward.","Curl the dumbbells up to your shoulders while keeping your upper arms stationary.","At the top of the movement, rotate your wrists so that your palms are facing away from your body.","Slowly lower the dumbbells back to the starting position, rotating your palms back to facing your body.","Repeat for the desired number of repetitions."],"mediaId":"kXaIn5A"},{"id":"edb-2294","name":"כפיפת מרפק בכיסא הטפה עם משקולות","name_en":"dumbbell zottman preacher curl","muscle":"biceps","equipment":"dumbbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל פריצ'ר עם משקולת בכל יד, כשכפות הידיים פונות כלפי מעלה והמרפקים נשענים על הכרית.","כופפו את המשקולות כלפי הכתפיים, תוך שמירה על הזרועות העליונות ללא תנועה וכפות הידיים פונות כלפי מעלה.","בקצה העליון של הכיפוף, סובבו את פרקי הידיים כך שכפות הידיים יפנו כלפי מטה.","הורידו לאט את המשקולות בחזרה למצב ההתחלתי, תוך סיבוב פרקי הידיים בחזרה למצב ההתחלתי במקביל.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a preacher bench with a dumbbell in each hand, palms facing up and elbows resting on the pad.","Curl the dumbbells up towards your shoulders, keeping your upper arms stationary and your palms facing up.","At the top of the curl, rotate your wrists so that your palms are facing down.","Slowly lower the dumbbells back down to the starting position, rotating your wrists back to the starting position as you do so.","Repeat for the desired number of repetitions."],"mediaId":"y5U5B9Y"},{"id":"edb-2189","name":"פשיטת מרפק בישיבה","name_en":"dumbbells seated triceps extension","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שבו על ספסל עם גב ישר וכפות רגליים שטוחות על הרצפה.","אחזו משקולת בשתי הידיים באחיזה עליונה, והרימו אותה מעל הראש.","כופפו את המרפקים והורידו את המשקולת מאחורי הראש, תוך שמירה על הזרועות העליונות קרובות לאוזניים.","מתחו את הזרועות והרימו את המשקולת בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your back straight and feet flat on the ground.","Hold a dumbbell in both hands with an overhand grip, and raise it above your head.","Bend your elbows and lower the dumbbell behind your head, keeping your upper arms close to your ears.","Extend your arms and raise the dumbbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"FQXdXzY"},{"id":"edb-1167","name":"מתיחה","name_en":"dynamic chest stretch (male)","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["עמדו זקוף עם הרגליים ברוחב הכתפיים.","הושיטו את הידיים ישר הצידה, במקביל לרצפה.","הביאו לאט את הזרועות קדימה, תוך הצלבתן לפני הגוף.","הרגישו את המתיחה בשרירי החזה.","החזיקו את המתיחה במשך 10-30 שניות.","חזרו למצב ההתחלתי וחזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand tall with your feet shoulder-width apart.","Extend your arms straight out to the sides, parallel to the ground.","Slowly bring your arms forward, crossing them in front of your body.","Feel the stretch in your chest muscles.","Hold the stretch for 10-30 seconds.","Return to the starting position and repeat for the desired number of repetitions."],"mediaId":"3uj0Ozg"},{"id":"edb-3287","name":"elbow dips","name_en":"elbow dips","muscle":"triceps","equipment":"body weight","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["שבו על קצה הספסל או הכיסא כאשר הידיים אוחזות בקצה ליד הירכיים.","החליקו את האגן קדימה מהספסל ויישרו את הרגליים, תוך שמירה על העקבים על הרצפה.","כופפו את המרפקים והורידו את הגוף לכיוון הרצפה, תוך שמירה על הגב קרוב לספסל.","עצרו לרגע בתחתית, ואז דחפו דרך הידיים כדי ליישר את הזרועות ולהרים את הגוף בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the edge of a bench or chair with your hands gripping the edge next to your hips.","Slide your hips forward off the bench and straighten your legs, keeping your heels on the ground.","Bend your elbows and lower your body towards the ground, keeping your back close to the bench.","Pause for a moment at the bottom, then push through your hands to straighten your arms and lift your body back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"LkoAWAE"},{"id":"edb-1772","name":"שכיבת סמיכה הפוך","name_en":"elbow lift - reverse push-up","muscle":"back","equipment":"body weight","target":"upper back","bodyPart":"back","secondaryMuscles":["triceps","shoulders"],"steps":["התחילו בשכיבה על הבטן על הרצפה, כשהרגליים מתוחות והידיים מונחות ישירות מתחת לכתפיים.","הפעילו את הליבה ולחצו דרך כפות הידיים כדי להרים את פלג הגוף העליון מהרצפה, תוך שמירה על המרפקים קרובים לצדדים.","עצרו בקצה העליון לרגע, תוך כיווץ שרירי הגב העליון.","הורידו לאט את הגוף בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by lying face down on the ground with your legs extended and your hands placed directly under your shoulders.","Engage your core and press through your palms to lift your upper body off the ground, keeping your elbows close to your sides.","Pause at the top for a moment, squeezing your upper back muscles.","Slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"wbUYILZ"},{"id":"edb-0443","name":"elbow-to-knee","name_en":"elbow-to-knee","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques"],"steps":["התחילו בשכיבה על הגב, כשהברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו את הידיים מאחורי הראש כשהמרפקים פונים החוצה.","הפעילו את שרירי הבטן והרימו את פלג הגוף העליון מהרצפה, תוך הבאת המרפק הימני לכיוון הברך השמאלית.","במקביל, הביאו את הברך השמאלית לכיוון המרפק הימני, תוך יצירת תנועת סיבוב.","עצרו לרגע בקצה העליון, ואז הורידו לאט את פלג הגוף העליון ומתחו את הרגליים בחזרה למצב ההתחלתי.","חזרו על התנועה, הפעם תוך הבאת המרפק השמאלי לכיוון הברך הימנית והברך הימנית לכיוון המרפק השמאלי.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Start by lying flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engage your abs and lift your upper body off the ground, bringing your right elbow towards your left knee.","At the same time, bring your left knee towards your right elbow, creating a twisting motion.","Pause for a moment at the top, then slowly lower your upper body and extend your legs back to the starting position.","Repeat the movement, this time bringing your left elbow towards your right knee and your right knee towards your left elbow.","Continue alternating sides for the desired number of repetitions."],"mediaId":"jvp6DiD"},{"id":"edb-3292","name":"elevator","name_en":"elevator","muscle":"back","equipment":"body weight","target":"upper back","bodyPart":"back","secondaryMuscles":["shoulders","trapezius"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","הניחו את הידיים על הירכיים או הצליבו אותן לפני החזה.","תוך שמירה על גב ישר, כופפו לאט קדימה במותניים, תוך הורדת פלג הגוף העליון לכיוון הרצפה.","עצרו לרגע בתחתית, ואז הרימו לאט את פלג הגוף העליון בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your knees slightly bent.","Place your hands on your hips or cross them in front of your chest.","Keeping your back straight, slowly bend forward at the waist, lowering your upper body towards the ground.","Pause for a moment at the bottom, then slowly raise your upper body back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"zYmNaoY"},{"id":"edb-1332","name":"exercise ball alternating arm ups","name_en":"exercise ball alternating arm ups","muscle":"back","equipment":"stability ball","target":"lats","bodyPart":"back","secondaryMuscles":["shoulders","core"],"steps":["שבו על כדור הפיזיו כשכפות הרגליים שטוחות על הרצפה והגב ישר.","אחזו משקולת בכל יד כשכפות הידיים פונות פנימה והזרועות מתוחות לצדי הגוף.","הפעילו את הליבה והרימו לאט זרוע אחת לכיוון הכתף, תוך שמירה על כיפוף קל במרפק.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את הזרוע לאט חזרה לתנוחת ההתחלה.","חזרו על התנועה עם הזרוע השנייה.","המשיכו להחליף ידיים למספר החזרות הרצוי."],"steps_en":["Sit on the stability ball with your feet flat on the ground and your back straight.","Hold a dumbbell in each hand with your palms facing inwards and your arms extended down by your sides.","Engage your core and slowly lift one arm up towards your shoulder, keeping your elbow slightly bent.","Pause for a moment at the top, then slowly lower your arm back down to the starting position.","Repeat the movement with the other arm.","Continue alternating arms for the desired number of repetitions."],"mediaId":"EyLrNC2"},{"id":"edb-1333","name":"פשיטת גב","name_en":"exercise ball back extension with arms extended","muscle":"back","equipment":"stability ball","target":"spine","bodyPart":"back","secondaryMuscles":["glutes","hamstrings"],"steps":["הניחו את כדור היציבות על הרצפה ושכבו עליו על הבטן, כשהאגן נשען על הכדור וכפות הרגליים נשענות על קיר ליציבות.","מתחו את הזרועות ישר לפניכם, כשכפות הידיים פונות כלפי מטה.","הפעילו את הליבה והרימו לאט את פלג הגוף העליון מהכדור, תוך שמירה על גב ישר וצוואר בקו אחד עם עמוד השדרה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Place the stability ball on the ground and lie face down on top of it, with your hips resting on the ball and your feet against a wall for stability.","Extend your arms straight out in front of you, with your palms facing down.","Engage your core and slowly lift your upper body off the ball, keeping your back straight and your neck in line with your spine.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"PERjVm8"},{"id":"edb-1334","name":"פשיטת גב מאחורי העורף","name_en":"exercise ball back extension with hands behind head","muscle":"back","equipment":"stability ball","target":"spine","bodyPart":"back","secondaryMuscles":["glutes","hamstrings"],"steps":["הניחו את כדור היציבות על הרצפה ושכבו עליו על הבטן, כשהאגן נשען על הכדור.","מקמו את כפות הרגליים כנגד קיר או משטח יציב אחר לתמיכה.","הצליבו את הזרועות מאחורי הראש, כשהידיים נוגעות בעורף.","הפעילו את הליבה והרימו לאט את פלג הגוף העליון מהכדור, תוך יישור הגב עד שהגוף יוצר קו ישר מהראש עד האגן.","עצרו לרגע בשיא התנועה, לאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Place the stability ball on the ground and lie face down on top of it with your hips resting on the ball.","Position your feet against a wall or other stable surface for support.","Cross your arms behind your head, with your hands touching the back of your head.","Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line from your head to your hips.","Pause for a moment at the top of the movement, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"o1HGDSq"},{"id":"edb-1335","name":"פשיטת גב","name_en":"exercise ball back extension with knees off ground","muscle":"back","equipment":"stability ball","target":"spine","bodyPart":"back","secondaryMuscles":["glutes","hamstrings"],"steps":["הניחו את כדור היציבות על הרצפה ושכבו עליו על הבטן, כשהאגן נשען על הכדור וכפות הרגליים נשענות על קיר ליציבות.","הניחו את הידיים מאחורי הראש או משוכלות על החזה.","הפעילו את ליבת הגוף והרימו לאט את פלג הגוף העליון מהכדור, תוך יישור הגב עד שהגוף יוצר קו ישר מהראש ועד העקבים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Place the stability ball on the ground and lie face down on top of it, with your hips resting on the ball and your feet against a wall for stability.","Position your hands behind your head or crossed over your chest.","Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line from your head to your heels.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"WME869U"},{"id":"edb-1336","name":"פשיטת גב","name_en":"exercise ball back extension with rotation","muscle":"back","equipment":"stability ball","target":"spine","bodyPart":"back","secondaryMuscles":["glutes","hamstrings"],"steps":["התחילו בשכיבה על הבטן על כדור היציבות, כשהאגן נשען על הכדור וכפות הרגליים נטועות היטב על הרצפה.","הניחו את הידיים מאחורי הראש או שלבו אותן על החזה.","הפעילו את ליבת הגוף והרימו לאט את פלג הגוף העליון מהכדור, תוך יישור הגב עד שהגוף יוצר קו ישר מהראש ועד העקבים.","עצרו לרגע בקצה העליון, ואז סובבו לאט את פלג הגוף לצד אחד, תוך שמירה על האגן והרגליים יציבים.","חזרו למרכז וחזרו על הסיבוב לצד השני.","הורידו את פלג הגוף העליון בחזרה למצב ההתחלתי וחזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by lying face down on the stability ball with your hips resting on the ball and your feet firmly planted on the ground.","Place your hands behind your head or cross them over your chest.","Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line from your head to your heels.","Pause for a moment at the top, then slowly rotate your torso to one side, keeping your hips and legs stable.","Return to the center and repeat the rotation to the other side.","Lower your upper body back down to the starting position and repeat for the desired number of repetitions."],"mediaId":"WVD66ff"},{"id":"edb-1744","name":"מקבילים","name_en":"exercise ball dip","muscle":"triceps","equipment":"stability ball","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["שבו על כדור הפיזיו כשכפות הרגליים שטוחות על הרצפה והברכיים כפופות בזווית של 90 מעלות.","הניחו את הידיים על הכדור לצד האגן, כשהאצבעות פונות קדימה.","הפעילו את שרירי הטריצפס ודחפו דרך הידיים כדי להרים את הגוף מהכדור, תוך יישור הזרועות.","הורידו את הגוף בחזרה למטה על ידי כיפוף המרפקים, תוך שמירה עליהם קרובים לצדדים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Place your hands on the ball beside your hips, fingers pointing forward.","Engage your triceps and push through your hands to lift your body off the ball, straightening your arms.","Lower your body back down by bending your elbows, keeping them close to your sides.","Repeat for the desired number of repetitions."],"mediaId":"kprile3"},{"id":"edb-1559","name":"מתיחה","name_en":"exercise ball hip flexor stretch","muscle":"glutes","equipment":"stability ball","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings"],"steps":["הניחו את כדור היציבות על הרצפה וכרעו לפניו.","הניחו את כף הרגל הימנית על כדור היציבות, כשהברך כפופה בזווית של 90 מעלות.","יישרו את הרגל השמאלית מאחוריכם, כשהיא נשארת ישרה.","התכופפו קדימה, תוך דחיפת האגן לכיוון כדור היציבות, עד שתרגישו מתיחה בכופף הירך הימני.","החזיקו את המתיחה 20-30 שניות, ואז החליפו צד וחזרו על התרגיל."],"steps_en":["Place the stability ball on the ground and kneel in front of it.","Place your right foot on top of the stability ball, with your knee bent at a 90-degree angle.","Extend your left leg behind you, keeping it straight.","Lean forward, pushing your hips towards the stability ball, until you feel a stretch in your right hip flexor.","Hold the stretch for 20-30 seconds, then switch sides and repeat."],"mediaId":"2LQkNPW"},{"id":"edb-1338","name":"exercise ball hug","name_en":"exercise ball hug","muscle":"back","equipment":"stability ball","target":"spine","bodyPart":"back","secondaryMuscles":["shoulders","chest"],"steps":["שבו על כדור הפיזיו כשכפות הרגליים שטוחות על הרצפה והגב ישר.","אחזו בכדור היציבות בשתי הידיים, תוך חיבוקו קרוב לחזה.","הפעילו את שרירי הליבה והיטו לאט את הגוף אחורה, תוך שמירה על גב ישר וכפות הרגליים נטועות ברצפה.","המשיכו להיטות אחורה עד שתרגישו מתיחה בשרירי הגב.","החזיקו את התנוחה לכמה שניות, ואז חזרו לאט למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the stability ball with your feet flat on the ground and your back straight.","Hold the stability ball with both hands, hugging it close to your chest.","Engage your core muscles and slowly lean back, keeping your back straight and your feet planted on the ground.","Continue leaning back until you feel a stretch in your back muscles.","Hold the position for a few seconds, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"d7z1Y7V"},{"id":"edb-1339","name":"מתיחה","name_en":"exercise ball lat stretch","muscle":"back","equipment":"stability ball","target":"lats","bodyPart":"back","secondaryMuscles":["shoulders","triceps"],"steps":["שבו על כדור פיזיו כשכפות הרגליים שטוחות על הרצפה והגב ישר.","אחזו משקולת ביד אחת ומתחו את הזרוע ישר מעל הראש.","היטו לאט לצד הנגדי, תוך הרגשת מתיחה בשריר הרחב הגבי.","החזיקו את המתיחה 20-30 שניות, ואז חזרו למצב ההתחלתי.","חזרו על התרגיל בצד השני."],"steps_en":["Sit on a stability ball with your feet flat on the ground and your back straight.","Hold a dumbbell in one hand and extend your arm straight up overhead.","Slowly lean to the opposite side, feeling a stretch in your lat muscle.","Hold the stretch for 20-30 seconds, then return to the starting position.","Repeat on the other side."],"mediaId":"sM84pE4"},{"id":"edb-1341","name":"מתיחה","name_en":"exercise ball lower back stretch (pyramid)","muscle":"back","equipment":"stability ball","target":"lats","bodyPart":"back","secondaryMuscles":["glutes","hamstrings"],"steps":["שבו על כדור הפיזיו כשכפות הרגליים שטוחות על הרצפה והברכיים כפופות בזווית של 90 מעלות.","הליכו לאט קדימה עם הרגליים תוך גלגול הכדור לאורך הגב, עד שהגב התחתון נשען על הכדור.","הניחו את הידיים מאחורי הראש או שלבו אותן על החזה.","הפעילו את שרירי הליבה והורידו לאט את פלג הגוף העליון לכיוון הרצפה, תוך מתיחת הגב התחתון מעל הכדור.","החזיקו את המתיחה למספר שניות, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Slowly walk your feet forward, rolling the ball down your back until your lower back is resting on the ball.","Place your hands behind your head or cross them over your chest.","Engage your core and slowly lower your upper body towards the ground, allowing your lower back to stretch over the ball.","Hold the stretch for a few seconds, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"yU7w7CA"},{"id":"edb-1342","name":"מתיחה בשכיבה צדי","name_en":"exercise ball lying side lat stretch","muscle":"back","equipment":"stability ball","target":"lats","bodyPart":"back","secondaryMuscles":["shoulders","triceps"],"steps":["שכבו על הצד עם הרגליים ישרות והראש נשען על כדור היציבות.","הניחו את היד העליונה על הכדור לייצוב.","שלחו את היד העליונה מעל הראש ואפשרו לפלג הגוף להסתובב מעט.","הרגישו את המתיחה בשרירי הגב הרחב בצד הגוף.","החזיקו את המתיחה 20-30 שניות, ואז החליפו צד וחזרו על התרגיל."],"steps_en":["Lie on your side with your legs extended and your head supported by the stability ball.","Place your top arm on the ball for stability.","Reach your top arm overhead and allow your torso to rotate slightly.","Feel the stretch in your lat muscles on the side of your body.","Hold the stretch for 20-30 seconds, then switch sides and repeat."],"mediaId":"rTbyBYV"},{"id":"edb-1382","name":"הרמת עקבים","name_en":"exercise ball on the wall calf raise","muscle":"legs","equipment":"dumbbell","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings","quadriceps"],"steps":["עמדו כשהגב שלכם צמוד לקיר, והניחו כדור התעמלות בין הגב התחתון לקיר.","מקמו את הרגליים ברוחב הכתפיים, עם האצבעות פונות קדימה.","אחזו משקולת יד בכל יד, כשהזרועות ישרות לצד הגוף.","הרימו את העקבים מהרצפה, והעבירו את משקל הגוף לכריות כפות הרגליים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקבים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your back against a wall and place an exercise ball between your lower back and the wall.","Position your feet shoulder-width apart, with your toes pointing forward.","Hold a dumbbell in each hand, with your arms extended by your sides.","Raise your heels off the ground, lifting your body weight onto the balls of your feet.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"xo6sENf"},{"id":"edb-3241","name":"הרמת עקבים","name_en":"exercise ball on the wall calf raise (tennis ball between ankles)","muscle":"legs","equipment":"dumbbell","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings","quadriceps"],"steps":["עמדו מול קיר עם הרגליים ברוחב הכתפיים.","הניחו כדור התעמלות בין הקיר לגב התחתון.","אחזו משקולת יד בכל יד, כשהזרועות ישרות לצד הגוף.","הניחו כדור טניס בין הקרסוליים.","הרימו את העקבים מהרצפה, והתרוממו על קצות האצבעות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקבים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand facing a wall with your feet shoulder-width apart.","Place an exercise ball between the wall and your lower back.","Hold a dumbbell in each hand, with your arms extended by your sides.","Place a tennis ball between your ankles.","Raise your heels off the ground, lifting your body up onto your toes.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"FY3UdNT"},{"id":"edb-3240","name":"הרמת עקבים","name_en":"exercise ball on the wall calf raise (tennis ball between knees)","muscle":"legs","equipment":"dumbbell","target":"calves","bodyPart":"lower legs","secondaryMuscles":["quadriceps","hamstrings"],"steps":["עמדו כשהגב שלכם צמוד לקיר, והניחו כדור התעמלות בין הגב התחתון לקיר.","מקמו את הרגליים ברוחב הכתפיים ומעט לפניכם.","אחזו משקולת יד בכל יד, כשהזרועות ישרות לצד הגוף.","הניחו כדור טניס בין הברכיים.","הרימו את העקבים מהרצפה, והתרוממו על קצות האצבעות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקבים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your back against a wall and place an exercise ball between your lower back and the wall.","Position your feet shoulder-width apart and slightly in front of you.","Hold a dumbbell in each hand, with your arms extended by your sides.","Place a tennis ball between your knees.","Raise your heels off the ground, lifting your body up onto your toes.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"j74M6Zn"},{"id":"edb-1416","name":"exercise ball one leg prone lower body rotation","name_en":"exercise ball one leg prone lower body rotation","muscle":"glutes","equipment":"stability ball","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps","core"],"steps":["שכבו על הבטן על כדור היציבות כשהאגן נשען על הכדור והרגליים ישרות מאחוריכם.","הניחו את הידיים על הרצפה לפניכם לתמיכה.","הפעילו את שרירי הישבן והליבה כדי לייצב את הגוף.","הרימו לאט רגל אחת מהרצפה, תוך שמירה עליה ישרה ומקבילה לרצפה.","סובבו את הרגל החוצה, הרחק מהגוף, תוך שמירה על יציבות האגן ופלג הגוף העליון.","עצרו לרגע בסוף הסיבוב, ואז החזירו לאט את הרגל למצב ההתחלתי.","חזרו על הסיבוב עם הרגל השנייה.","המשיכו להחליף רגליים למספר החזרות הרצוי."],"steps_en":["Lie face down on the stability ball with your hips resting on the ball and your legs extended straight behind you.","Place your hands on the ground in front of you for support.","Engage your glutes and core muscles to stabilize your body.","Slowly lift one leg off the ground, keeping it straight and parallel to the floor.","Rotate your leg outward, away from your body, while keeping your hips and upper body stable.","Pause for a moment at the end of the rotation, then slowly return your leg to the starting position.","Repeat the rotation with the other leg.","Continue alternating legs for the desired number of repetitions."],"mediaId":"M72BExt"},{"id":"edb-1417","name":"כפיפת מרפק","name_en":"exercise ball one legged diagonal kick hamstring curl","muscle":"glutes","equipment":"stability ball","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","calves"],"steps":["התחילו בשכיבה על הגב עם הרגליים ישרות והעקבים מונחים על כדור היציבות.","הניחו את הידיים לצדי הגוף לייצוב.","הפעילו את שרירי הישבן והליבה כדי להרים את האגן מהרצפה, וליצור קו ישר מהכתפיים ועד העקבים.","כופפו את הברך הימנית והביאו אותה לכיוון החזה, תוך שמירה על הרגל השמאלית ישרה וכף הרגל מכופפת כלפי מעלה.","בעטו ברגל הימנית באלכסון על פני הגוף, ישרו אותה לחלוטין תוך הפעלת שרירי הירך האחוריים.","החזירו לאט את הרגל הימנית למצב ההתחלתי, תוך שמירה על שליטה ויציבות.","חזרו על התנועה עם הרגל השמאלית, תוך החלפת צדדים למספר החזרות הרצוי."],"steps_en":["Start by lying on your back with your legs extended and your heels resting on top of the stability ball.","Place your arms by your sides for stability.","Engage your glutes and core muscles to lift your hips off the ground, creating a straight line from your shoulders to your heels.","Bend your right knee and bring it towards your chest, keeping your left leg extended and your foot flexed.","Kick your right leg diagonally across your body, extending it fully and engaging your hamstrings.","Slowly return your right leg to the starting position, maintaining control and stability.","Repeat the movement with your left leg, alternating sides for the desired number of repetitions."],"mediaId":"GOJKFfO"},{"id":"edb-1296","name":"שכיבת סמיכה","name_en":"exercise ball pike push up","muscle":"chest","equipment":"stability ball","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps","core"],"steps":["התחילו בעמדת שכיבת סמיכה עם הידיים על הרצפה והשוקיים מונחות על כדור היציבות.","הפעילו את שרירי הליבה והרימו את האגן לכיוון התקרה, תוך גלגול הכדור לכיוון הידיים.","שמרו על הרגליים ישרות והגוף בעמדת פייק, ביצירת צורת V הפוכה.","כופפו את המרפקים והורידו את פלג הגוף העליון לכיוון הרצפה, תוך שמירה על הראש בקו אחד עם הידיים.","דחפו דרך הידיים וישרו את הזרועות כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a push-up position with your hands on the floor and your shins resting on the stability ball.","Engage your core and lift your hips up towards the ceiling, rolling the ball towards your hands.","Keep your legs straight and your body in a pike position, forming an inverted V shape.","Bend your elbows and lower your upper body towards the floor, keeping your head in line with your hands.","Push through your hands and extend your arms to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"sVvXT5J"},{"id":"edb-1343","name":"הרמת רגליים בשכיבה על הבטן","name_en":"exercise ball prone leg raise","muscle":"back","equipment":"stability ball","target":"spine","bodyPart":"back","secondaryMuscles":["abdominals","glutes"],"steps":["שכבו על הבטן על מזרן עם הרגליים ישרות ואצבעות כפות הרגליים מונחות על כדור היציבות.","הניחו את הידיים על הרצפה, ברוחב הכתפיים, והפעילו את שרירי הליבה.","כשהרגליים ישרות, הרימו אותן לאט מהרצפה, תוך שימוש בגב התחתון ובישבן כדי להרים אותן גבוה ככל האפשר.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie face down on a mat with your legs extended and your toes resting on top of the stability ball.","Place your hands on the ground, shoulder-width apart, and engage your core muscles.","Keeping your legs straight, slowly lift them off the ground, using your lower back and glutes to raise them as high as possible.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"lCKm4Rs"},{"id":"edb-1560","name":"מתיחה בישיבה","name_en":"exercise ball seated hamstring stretch","muscle":"legs","equipment":"stability ball","target":"hamstrings","bodyPart":"upper legs","secondaryMuscles":["glutes","lower back"],"steps":["שבו על כדור הפיזיו כשכפות הרגליים שטוחות על הרצפה והברכיים כפופות בזווית של 90 מעלות.","גלגלו את הכדור לאט קדימה, תוך הליכה עם הרגליים החוצה עד שהגב העליון נשען על הכדור והרגליים ישרות לפניכם.","הניחו את הידיים על המותניים לתמיכה.","הפעילו את שרירי הליבה והורידו לאט את פלג הגוף העליון לכיוון הרצפה, תוך שמירה על הגב ישר והחזה מורם.","עצרו כשאתם מרגישים מתיחה בשרירי הירך האחוריים, והחזיקו את התנוחה במשך 20-30 שניות.","חזרו לאט למצב ההתחלתי על ידי דחיפה דרך העקבים ושימוש בשרירי הירך האחוריים כדי למשוך את עצמכם בחזרה למעלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Slowly roll the ball forward, walking your feet out until your upper back is resting on the ball and your legs are extended straight in front of you.","Place your hands on your hips for support.","Engage your core and slowly lower your upper body towards the ground, keeping your back straight and your chest lifted.","Stop when you feel a stretch in your hamstrings, and hold the position for 20-30 seconds.","Slowly return to the starting position by pushing through your heels and using your hamstrings to pull yourself back up.","Repeat for the desired number of repetitions."],"mediaId":"yRYyfdA"},{"id":"edb-1745","name":"מתיחה בישיבה","name_en":"exercise ball seated triceps stretch","muscle":"triceps","equipment":"stability ball","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שבו על כדור פיזיו כשכפות הרגליים שטוחות על הרצפה והגב ישר.","אחזו משקולת יד ביד אחת וישרו את הזרוע מעלה מעל הראש.","כופפו את המרפק והורידו את המשקולת מאחורי הראש, תוך שמירה על הזרוע העליונה קרוב לאוזן.","החזיקו את המתיחה למספר שניות, ואז חזרו למצב ההתחלתי.","חזרו עם הזרוע השנייה."],"steps_en":["Sit on a stability ball with your feet flat on the ground and your back straight.","Hold a dumbbell in one hand and extend your arm straight up above your head.","Bend your elbow and lower the dumbbell behind your head, keeping your upper arm close to your ear.","Hold the stretch for a few seconds, then return to the starting position.","Repeat with the other arm."],"mediaId":"7ePTw4B"},{"id":"edb-1746","name":"פשיטת מרפק בשכיבה על הגב","name_en":"exercise ball supine triceps extension","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שבו על כדור פיטבול כשכפות הרגליים שטוחות על הרצפה והברכיים כפופות בזווית של 90 מעלות.","אחזו משקולת בשתי הידיים וישרו את הזרועות מעלה לכיוון התקרה.","הורידו לאט את המשקולת מאחורי הראש, תוך שמירה על המרפקים קרובים לאוזניים.","עצרו לרגע, ואז הרימו את המשקולת בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on an exercise ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Hold a dumbbell with both hands and extend your arms straight up towards the ceiling.","Slowly lower the dumbbell behind your head, keeping your elbows close to your ears.","Pause for a moment, then raise the dumbbell back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Gm2Uv1z"},{"id":"edb-1747","name":"לחיצה","name_en":"ez bar french press on exercise ball","muscle":"triceps","equipment":"ez barbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שבו על כדור התעמלות ואחזו מוט EZ באחיזה עליונה.","ישרו את הזרועות מעלה, תוך שמירה על המרפקים קרוב לראש.","הורידו לאט את המוט מאחורי הראש על ידי כיפוף המרפקים.","עצרו לרגע, ולאחר מכן יישרו את הידיים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on an exercise ball and hold an EZ barbell with an overhand grip.","Extend your arms straight up, keeping your elbows close to your head.","Slowly lower the barbell behind your head by bending your elbows.","Pause for a moment, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"CFN9P8G"},{"id":"edb-3010","name":"פולאובר בשכיבה בהטיה","name_en":"ez bar lying bent arms pullover","muscle":"back","equipment":"ez barbell","target":"lats","bodyPart":"back","secondaryMuscles":["triceps","chest"],"steps":["שכבו על הגב על ספסל, עם הראש בקצה אחד והרגליים על הרצפה.","אחזו את מוט ה-EZ באחיזה פרונטית (כפות הידיים פונות הרחק מכם) והידיים ברוחב הכתפיים.","ישרו את הזרועות מעל החזה, תוך שמירה על כיפוף קל במרפקים.","הורידו את המוט בתנועת קשת מאחורי הראש, תוך שמירה על הכיפוף הקל במרפקים.","עצרו לרגע, ואז החזירו את המוט למצב ההתחלתי על ידי היפוך תנועת הקשת.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your head at one end and your feet on the floor.","Hold the EZ barbell with a pronated grip (palms facing away from you) and your hands shoulder-width apart.","Extend your arms straight above your chest, keeping a slight bend in your elbows.","Lower the barbell in an arc motion behind your head, maintaining the slight bend in your elbows.","Pause for a moment, then return the barbell to the starting position by reversing the arc motion.","Repeat for the desired number of repetitions."],"mediaId":"nDK1HJ0"},{"id":"edb-1748","name":"פשיטת מרפק אחיזה צרה מאחורי העורף בשכיבה","name_en":"ez bar lying close grip triceps extension behind head","muscle":"triceps","equipment":"ez barbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שכבו על הגב על ספסל, כשכפות הרגליים שטוחות על הרצפה והראש בקצה הספסל.","אחזו את מוט ה-EZ באחיזה צרה, כפות הידיים פונות למעלה, וישרו את הזרועות מעל החזה.","תוך שמירה על הזרוע העליונה ללא תזוזה, הורידו לאט את המוט מאחורי הראש על ידי כפיפת המרפקים.","עצרו לרגע, ולאחר מכן יישרו את הידיים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Hold the ez barbell with a close grip, palms facing up, and extend your arms straight up over your chest.","Keeping your upper arms stationary, slowly lower the barbell behind your head by bending your elbows.","Pause for a moment, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"6CKUx7o"},{"id":"edb-1344","name":"חתירה בהטיה אחיזה הפוכה","name_en":"ez bar reverse grip bent over row","muscle":"back","equipment":"ez barbell","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","אחזו את מוט ה-EZ באחיזה תחתונה, כפות הידיים פונות למעלה, והידיים ברוחב הכתפיים.","התכופפו קדימה מהירכיים, תוך שמירה על גב ישר וחזה מורם, עד שפלג הגוף העליון כמעט מקביל לרצפה.","משכו את מוט ה-EZ לכיוון החזה התחתון, תוך כיווץ שכמות הכתפיים יחד.","עצרו לרגע בשיא התנועה, ואז הורידו לאט את מוט ה-EZ בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and knees slightly bent.","Hold the ez barbell with an underhand grip, palms facing up, and hands shoulder-width apart.","Bend forward at the hips, keeping your back straight and chest up, until your torso is almost parallel to the floor.","Pull the ez barbell towards your lower chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the ez barbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"G8dXpNG"},{"id":"edb-1682","name":"כפיפת מרפק אחיזה צרה בישיבה","name_en":"ez bar seated close grip concentration curl","muscle":"biceps","equipment":"ez barbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל עם כפות הרגליים שטוחות על הרצפה ואחזו מוט EZ באחיזה תחתונה.","הניחו את המרפק על החלק הפנימי של הירך, ממש מעל הברך.","כופפו את המוט למעלה לכיוון הכתף תוך שמירה על הזרוע העליונה קבועה.","כווצו את שריר הביצפס בשיא התנועה, ואז הורידו לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your feet flat on the ground and hold an EZ barbell with an underhand grip.","Rest your elbow on the inside of your thigh, just above the knee.","Curl the barbell up towards your shoulder while keeping your upper arm stationary.","Squeeze your biceps at the top of the movement, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Dsfz0Id"},{"id":"edb-1749","name":"לחיצה בעמידה","name_en":"ez bar standing french press","muscle":"triceps","equipment":"ez barbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו את מוט ה-EZ באחיזה עליונה.","הרימו את המוט מעל הראש, תוך יישור מלא של הזרועות.","תוך שמירה על הזרועות העליונות קרובות לראש, הורידו את המוט באיטיות מאחורי הראש על ידי כיפוף המרפקים.","עצרו לרגע, ולאחר מכן יישרו את הזרועות חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold the ez barbell with an overhand grip.","Raise the barbell above your head, fully extending your arms.","Keeping your upper arms close to your head, slowly lower the barbell behind your head by bending your elbows.","Pause for a moment, then extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"1cTf2Ux"},{"id":"edb-0445","name":"לחיצה עם מוט EZ","name_en":"ez barbell anti gravity press","muscle":"shoulders","equipment":"ez barbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","chest"],"steps":["התחילו בעמידה עם הרגליים ברוחב הכתפיים תוך אחיזת מוט ה-EZ באחיזה עליונה.","הרימו את המוט לגובה הכתפיים, תוך שמירה על המרפקים כפופים מעט וכפות הידיים פונות קדימה.","דחפו את המוט מעל הראש, תוך יישור מלא של הזרועות.","הורידו את המוט חזרה לגובה הכתפיים וחזרו על התנועה למספר החזרות הרצוי."],"steps_en":["Start by standing with your feet shoulder-width apart and holding the ez barbell with an overhand grip.","Raise the barbell to shoulder height, keeping your elbows slightly bent and your palms facing forward.","Press the barbell overhead, extending your arms fully.","Lower the barbell back to shoulder height and repeat for the desired number of repetitions."],"mediaId":"fprd84i"},{"id":"edb-1627","name":"כפיפת מרפק בכיסא הטפה אחיזה צרה עם מוט EZ","name_en":"ez barbell close grip preacher curl","muscle":"biceps","equipment":"ez barbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל פריצ'ר והניחו את הזרועות העליונות על הכרית, תוך אחיזת מוט ה-EZ באחיזה תחתונה.","הניחו את שריר הטריצפס על הכרית וישרו את הזרועות לחלוטין, תוך שמירה על הגב ישר.","כופפו לאט את המוט לכיוון הכתפיים, תוך כיווץ שריר הביצפס.","עצרו לרגע בשיא התנועה, תוך כיווץ שרירי הביצפס.","הורידו את המוט בחזרה למצב ההתחלתי, תוך יישור מלא של הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a preacher curl bench and place your upper arms on the pad, gripping the ez barbell with an underhand grip.","Rest your triceps on the pad and fully extend your arms, keeping your back straight.","Slowly curl the barbell towards your shoulders, contracting your biceps.","Pause for a moment at the top, squeezing your biceps.","Lower the barbell back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"hacCyUv"},{"id":"edb-0446","name":"כפיפת מרפק אחיזה צרה עם מוט EZ","name_en":"ez barbell close-grip curl","muscle":"biceps","equipment":"ez barbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף עם הרגליים ברוחב הכתפיים ואחזו את מוט ה-EZ באחיזה תחתונה, הידיים ברוחב הכתפיים.","שמרו על המרפקים קרובים לגוף והזרוע העליונה ללא תנועה לאורך כל התנועה.","כופפו את המוט למעלה לכיוון הכתפיים, תוך כיווץ שריר הביצפס.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand up straight with your feet shoulder-width apart and hold the ez barbell with an underhand grip, hands shoulder-width apart.","Keep your elbows close to your torso and your upper arms stationary throughout the movement.","Curl the barbell up towards your shoulders, contracting your biceps.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"V4ryaZa"},{"id":"edb-0447","name":"כפיפת מרפק עם מוט EZ","name_en":"ez barbell curl","muscle":"biceps","equipment":"ez barbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף עם הרגליים ברוחב הכתפיים ואחזו את מוט ה-EZ באחיזה תחתונה, כפות הידיים פונות למעלה.","שמרו על המרפקים קרובים לגוף והזרוע העליונה ללא תנועה לאורך כל התנועה.","נשפו החוצה תוך כיפוף המוט למעלה לכיוון הכתפיים, וכיווץ שריר הביצפס.","עצרו לרגע בשיא התנועה, ולאחר מכן שאפו אוויר תוך כדי הורדת המוט באיטיות חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand up straight with your feet shoulder-width apart and hold the ez barbell with an underhand grip, palms facing up.","Keep your elbows close to your torso and your upper arms stationary throughout the movement.","Exhale as you curl the barbell up towards your shoulders, contracting your biceps.","Pause for a moment at the top, then inhale as you slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"6TG6x2w"},{"id":"edb-0448","name":"לחיצה אחיזה צרה בשיפוע שלילי עם מוט EZ","name_en":"ez barbell decline close grip face press","muscle":"triceps","equipment":"ez barbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["שכבו על ספסל שיפוע שלילי כשהראש נמוך מהרגליים.","אחזו את מוט ה-EZ באחיזה צרה, כפות הידיים פונות זו לזו.","ישרו את הזרועות מעלה מעל החזה, תוך שמירה על המרפקים קרוב לגוף.","הורידו את המוט לכיוון המצח על ידי כיפוף המרפקים.","עצרו לרגע, ואז דחפו את המוט בחזרה למעלה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie on a decline bench with your head lower than your feet.","Grasp the ez barbell with a close grip, palms facing each other.","Extend your arms straight up above your chest, keeping your elbows close to your body.","Lower the barbell towards your forehead by bending your elbows.","Pause for a moment, then press the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"DgZQ11d"},{"id":"edb-2186","name":"פשיטת מרפק בשיפוע שלילי עם מוט EZ","name_en":"ez barbell decline triceps extension","muscle":"triceps","equipment":"ez barbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שכבו על ספסל שיפוע שלילי כשהראש נמוך מהרגליים והרגליים מקובעות.","אחזו את מוט ה-EZ באחיזה עליונה, הידיים ברוחב הכתפיים.","פשטו את הידיים לגמרי, כשהמרפקים קרובים לראש.","הורידו את המוט לאט לכיוון המצח, תוך כיפוף המרפקים.","עצרו לרגע, ולאחר מכן יישרו את הזרועות חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie on a decline bench with your head lower than your feet and your feet secured.","Hold the ez barbell with an overhand grip, hands shoulder-width apart.","Extend your arms fully, keeping your elbows close to your head.","Lower the barbell slowly towards your forehead, bending your elbows.","Pause for a moment, then extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"CQHoDm0"},{"id":"edb-0449","name":"פשיטת מרפק בשיפוע עם מוט EZ","name_en":"ez barbell incline triceps extension","muscle":"triceps","equipment":"ez barbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["הציבו ספסל בשיפוע עולה בזווית של 45 מעלות.","שבו על הספסל כשהגב צמוד לכרית ואחזו את מוט ה-EZ באחיזה עליונה.","יישרו את הידיים לגמרי מעל הראש, כשהמרפקים קרובים לראש.","הורידו את המוט מאחורי הראש על ידי כיפוף המרפקים, תוך שמירה על הזרועות העליונות קבועות.","עצרו לרגע, ולאחר מכן יישרו את הזרועות חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up an incline bench at a 45-degree angle.","Sit on the bench with your back against the pad and hold the ez barbell with an overhand grip.","Extend your arms fully overhead, keeping your elbows close to your head.","Lower the barbell behind your head by bending your elbows, keeping your upper arms stationary.","Pause for a moment, then extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"KyLtiLT"},{"id":"edb-0450","name":"לחיצת חזה עם מוט EZ","name_en":"ez barbell jm bench press","muscle":"triceps","equipment":"ez barbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["שכבו על ספסל כשכפות הרגליים שטוחות על הרצפה והגב צמוד לספסל.","אחזו את מוט ה-EZ באחיזה עליונה, מעט רחב יותר מרוחב הכתפיים.","הורידו את המוט לכיוון החזה, כשהמרפקים צמודים לגוף.","דחפו את המוט בחזרה למצב ההתחלתי, תוך יישור מלא של הידיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the ez barbell with an overhand grip, slightly wider than shoulder-width apart.","Lower the barbell to your chest, keeping your elbows tucked in close to your body.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"hnOYgH3"},{"id":"edb-0451","name":"כפיפת מרפק אחיזה הפוכה עם מוט EZ","name_en":"ez barbell reverse grip curl","muscle":"biceps","equipment":"ez barbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף עם הרגליים ברוחב הכתפיים ואחזו את מוט ה-EZ באחיזה תחתונה.","שמרו על המרפקים קרוב לגו ועל הזרועות העליונות קבועות לאורך כל התרגיל.","כופפו את המוט כלפי מעלה על ידי כיווץ שריר הביצפס, תוך נשיפה.","המשיכו להרים את המוט עד ששריר הביצפס מכווץ במלואו והמוט נמצא בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","התחילו להחזיר לאט את המוט למצב ההתחלתי תוך שאיפה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand up straight with your feet shoulder-width apart and hold the ez barbell with an underhand grip.","Keep your elbows close to your torso and your upper arms stationary throughout the exercise.","Curl the barbell upwards by contracting your biceps, while exhaling.","Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Slowly begin to bring the barbell back to the starting position as you inhale.","Repeat for the desired number of repetitions."],"mediaId":"Y5X65IB"},{"id":"edb-0452","name":"כפיפת מרפק בכיסא הטפה אחיזה הפוכה עם מוט EZ","name_en":"ez barbell reverse grip preacher curl","muscle":"biceps","equipment":"ez barbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל פריצ'ר עם החזה צמוד לכרית וכפות הרגליים שטוחות על הרצפה.","אחזו את מוט ה-EZ באחיזה תחתונה, הידיים ברוחב הכתפיים.","הניחו את הזרועות העליונות על הכרית, ואפשרו לאמות הידיים לתלות כלפי מטה.","תוך שמירה על הזרוע העליונה ללא תזוזה, נשפו החוצה וכופפו את המוט כלפי מעלה לכיוון הכתפיים.","עצרו לרגע בשיא התנועה, ולאחר מכן שאפו אוויר והורידו את המוט באיטיות חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a preacher bench with your chest against the pad and your feet flat on the floor.","Grasp the ez barbell with an underhand grip, hands shoulder-width apart.","Rest your upper arms on the pad, allowing your forearms to hang down.","Keeping your upper arms stationary, exhale and curl the barbell up towards your shoulders.","Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"vBNyir7"},{"id":"edb-1458","name":"ez barbell seated curls","name_en":"ez barbell seated curls","muscle":"biceps","equipment":"ez barbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על ספסל כשכפות הרגליים שטוחות על הרצפה והגב ישר.","אחזו את מוט ה-EZ באחיזה תחתונה, כפות הידיים פונות למעלה, והידיים ברוחב הכתפיים.","הניחו את הזרועות העליונות על הירכיים, ואפשרו למוט ה-EZ לתלות לפניכם.","כשהזרועות העליונות קבועות, נשפו וכופפו את מוט ה-EZ כלפי מעלה לכיוון הכתפיים.","עצרו לרגע בשיא התנועה, תוך כיווץ שרירי הביצפס.","שאפו והורידו לאט את מוט ה-EZ בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your feet flat on the ground and your back straight.","Hold the ez barbell with an underhand grip, palms facing up, and your hands shoulder-width apart.","Rest your upper arms on your thighs, allowing the ez barbell to hang down in front of you.","Keeping your upper arms stationary, exhale and curl the ez barbell upwards towards your shoulders.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the ez barbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"jtFKbt5"},{"id":"edb-0453","name":"פשיטת מרפק בישיבה עם מוט EZ","name_en":"ez barbell seated triceps extension","muscle":"triceps","equipment":"ez barbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["שבו על ספסל עם גב ישר וכפות רגליים שטוחות על הרצפה.","אחזו את מוט ה-EZ באחיזה עליונה, הידיים ברוחב הכתפיים.","הרימו את המוט מעל הראש, תוך יישור מלא של הזרועות.","כשהזרועות העליונות קבועות, הורידו את המוט מאחורי הראש על ידי כיפוף המרפקים.","עצרו לרגע, ולאחר מכן הרימו את המוט חזרה למצב ההתחלתי על ידי יישור הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your back straight and feet flat on the ground.","Hold the ez barbell with an overhand grip, hands shoulder-width apart.","Raise the barbell overhead, fully extending your arms.","Keeping your upper arms stationary, lower the barbell behind your head by bending your elbows.","Pause for a moment, then raise the barbell back to the starting position by extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"iaapw0g"},{"id":"edb-0454","name":"כפיפת מרפק עם מוט EZ","name_en":"ez barbell spider curl","muscle":"biceps","equipment":"ez barbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו את מוט ה-EZ באחיזה תחתונה, כפות הידיים פונות למעלה.","הניחו את הזרועות העליונות על ספסל פריצ'ר או כדור יציבות, ואפשרו למרפקים לתלות כלפי מטה.","תוך שמירה על הזרוע העליונה ללא תזוזה, נשפו החוצה וכופפו את המוט כלפי מעלה לכיוון הכתפיים.","עצרו לרגע בשיא התנועה, תוך כיווץ שרירי הביצפס.","שאפו אוויר והורידו את המוט באיטיות חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold the ez barbell with an underhand grip, palms facing up.","Rest your upper arms on a preacher bench or stability ball, allowing your elbows to hang down.","Keeping your upper arms stationary, exhale and curl the barbell up towards your shoulders.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Ye5Qxb0"},{"id":"edb-1628","name":"כפיפת מרפק עם מוט EZ","name_en":"ez barbell spider curl","muscle":"biceps","equipment":"ez barbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו את מוט ה-EZ באחיזה תחתונה, כפות הידיים פונות למעלה.","הניחו את הזרועות העליונות על ספסל פריצ'ר או כדור יציבות, ואפשרו למרפקים לתלות כלפי מטה.","תוך שמירה על הזרוע העליונה ללא תזוזה, נשפו החוצה וכופפו את המוט כלפי מעלה לכיוון הכתפיים.","עצרו לרגע בשיא התנועה, תוך כיווץ שרירי הביצפס.","שאפו אוויר והורידו את המוט באיטיות חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold the ez barbell with an underhand grip, palms facing up.","Rest your upper arms on a preacher bench or stability ball, allowing your elbows to hang down.","Keeping your upper arms stationary, exhale and curl the barbell up towards your shoulders.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"2kattbR"},{"id":"edb-2404","name":"כפיפת מרפק","name_en":"ez-bar biceps curl (with arm blaster)","muscle":"biceps","equipment":"ez barbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף עם הרגליים ברוחב הכתפיים ואחזו את מוט ה-EZ באחיזה תחתונה, כפות הידיים פונות למעלה.","הניחו את הזרועות העליונות על ארם בלאסטר, תוך שמירה עליהן קבועות לאורך כל התרגיל.","כשהמרפקים קרוב לגוף, נשפו וכופפו את המוט למעלה לכיוון הכתפיים.","עצרו לרגע בשיא התנועה, תוך כיווץ שרירי הביצפס.","שאפו אוויר והורידו את המוט באיטיות חזרה למצב ההתחלתי, תוך יישור מלא של הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand up straight with your feet shoulder-width apart and hold the ez barbell with an underhand grip, palms facing up.","Place your upper arms against the arm blaster, keeping them stationary throughout the exercise.","Keeping your elbows close to your body, exhale and curl the barbell up towards your shoulders.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the barbell back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"tJ5nYqo"},{"id":"edb-2432","name":"לחיצת חזה אחיזה צרה","name_en":"ez-bar close-grip bench press","muscle":"triceps","equipment":"ez barbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["שכבו על ספסל כשכפות הרגליים שטוחות על הרצפה והגב צמוד לספסל.","אחזו את מוט ה-EZ באחיזה צרה, הידיים ברוחב הכתפיים, כפות הידיים פונות קדימה.","הרימו את המוט מהמעמד והחזיקו אותו ישר מעל החזה כשהידיים מיושרות לגמרי.","הורידו לאט את המוט לכיוון החזה, כשהמרפקים צמודים לגוף.","עצרו לרגע כשהמוט נוגע בחזה.","דחפו את המוט בחזרה למצב ההתחלתי, תוך יישור מלא של הידיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the ez barbell with a close grip, hands shoulder-width apart, palms facing forward.","Lift the barbell off the rack and hold it directly above your chest with your arms fully extended.","Slowly lower the barbell towards your chest, keeping your elbows close to your body.","Pause for a moment when the barbell touches your chest.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"da4cXST"},{"id":"edb-2741","name":"כפיפת מרפק אחיזה רחבה בעמידה עם מוט EZ","name_en":"ez-barbell standing wide grip biceps curl","muscle":"biceps","equipment":"ez barbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף עם הרגליים ברוחב הכתפיים ואחזו את מוט ה-EZ באחיזה תחתונה, הידיים רחבות יותר מרוחב הכתפיים.","שמרו על המרפקים קרובים לגוף והזרוע העליונה ללא תנועה לאורך כל התנועה.","כופפו את המוט למעלה לכיוון הכתפיים על ידי כיווץ שריר הביצפס.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand up straight with your feet shoulder-width apart and hold the ez barbell with an underhand grip, hands wider than shoulder-width apart.","Keep your elbows close to your torso and your upper arms stationary throughout the movement.","Curl the barbell up towards your shoulders by contracting your biceps.","Pause for a moment at the top, then slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"OVTZ65k"},{"id":"edb-2133","name":"farmers walk","name_en":"farmers walk","muscle":"legs","equipment":"dumbbell","target":"quads","bodyPart":"upper legs","secondaryMuscles":["calves","forearms","core"],"steps":["עמדו זקוף עם משקולת יד בכל יד, כפות הידיים פונות לצדדים.","שמרו על הגב ישר והכתפיים לאחור.","בצעו צעדים קטנים ומבוקרים קדימה, תוך שמירה על יציבה זקופה.","המשיכו בהליכה למרחק או לזמן הרצוי.","לסיום, הפסיקו ללכת והורידו בזהירות את המשקולות לצדי הגוף."],"steps_en":["Stand up straight with a dumbbell in each hand, palms facing your sides.","Keep your back straight and your shoulders back.","Take small, controlled steps forward, maintaining an upright posture.","Continue walking for the desired distance or time.","To finish, stop walking and carefully lower the dumbbells to your sides."],"mediaId":"qPEzJjA"},{"id":"edb-0455","name":"finger curls","name_en":"finger curls","muscle":"biceps","equipment":"barbell","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["wrist flexors","grip muscles"],"steps":["שבו על ספסל כשכפות הרגליים שטוחות על הרצפה ואחזו במוט באחיזה תחתונה, כשכפות הידיים פונות למעלה.","הניחו את האמות על הירכיים כך שפרקי הידיים תלויים מעבר לקצה.","כופפו לאט את האצבעות לכיוון כפות הידיים, תוך לחיצה חזקה על המוט.","החזיקו את הכיווץ לרגע, ואז שחררו לאט את האצבעות בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your feet flat on the ground and hold a barbell with an underhand grip, palms facing up.","Rest your forearms on your thighs, allowing your wrists to hang off the edge.","Slowly curl your fingers towards your palms, squeezing the barbell tightly.","Hold the contraction for a moment, then slowly release your fingers back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"awG04cF"},{"id":"edb-3303","name":"flag","name_en":"flag","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","shoulders"],"steps":["התחילו באחיזת עמוד אנכי בשתי הידיים, כפות הידיים פונות זו לזו, והזרועות ישרות לחלוטין.","הפעילו את ליבת הגוף והרימו את הרגליים מהרצפה, תוך שמירה עליהן ישרות.","באמצעות כוח הליבה ופלג הגוף העליון, הרימו את הרגליים עד שהן מקבילות לרצפה.","החזיקו בתנוחה זו כמה שיותר זמן, תוך שמירה על קו גוף ישר.","הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by gripping a vertical pole with both hands, palms facing each other, and arms fully extended.","Engage your core and lift your legs off the ground, keeping them straight.","Using your core and upper body strength, raise your legs until they are parallel to the ground.","Hold this position for as long as you can, maintaining a straight body line.","Slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"pQ0Mx1Z"},{"id":"edb-0456","name":"כפיפת בטן מלאה בהטיה","name_en":"flexion leg sit up (bent knee)","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו את הידיים מאחורי הראש כשהמרפקים פונים החוצה.","תוך הפעלת שרירי הבטן, הרימו לאט את פלג הגוף העליון מהרצפה, בכיפוף קדימה עד שהגו נמצא בזווית של 45 מעלות.","במקביל, הרימו את הרגליים מהרצפה, כופפו את הברכיים והביאו אותן לכיוון החזה.","עצרו לרגע בשיא התנועה, ואז הורידו לאט את פלג הגוף העליון והרגליים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","At the same time, lift your legs off the ground, bending your knees and bringing them towards your chest.","Pause for a moment at the top, then slowly lower your upper body and legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"AR0ig3o"},{"id":"edb-0457","name":"כפיפת בטן מלאה","name_en":"flexion leg sit up (straight arm)","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors","quadriceps"],"steps":["שכבו שטוח על הגב עם הרגליים ישרות והזרועות ישרות מעל הראש.","תוך הפעלת שרירי הבטן, הרימו את פלג הגוף העליון מהרצפה תוך הרמת הרגליים בו-זמנית לכיוון החזה.","שלחו את הידיים לכיוון האצבעות תוך הרמת פלג הגוף העליון והרגליים.","עצרו לרגע בשיא התנועה, ואז הורידו לאט את פלג הגוף העליון והרגליים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your legs extended and arms straight above your head.","Engaging your abs, lift your upper body off the ground while simultaneously lifting your legs towards your chest.","Reach your hands towards your toes as you lift your upper body and legs.","Pause for a moment at the top, then slowly lower your upper body and legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"KZn52RC"},{"id":"edb-0458","name":"פרפר עם מוט","name_en":"floor fly (with barbell)","muscle":"chest","equipment":"barbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["deltoids","triceps"],"steps":["שכבו על הגב על הרצפה, כשהברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","אחזו מוט באחיזה עליונה, הזרועות ישרות מעל החזה.","הורידו לאט את המוט הצידה, תוך שמירה על כיפוף קל במרפקים.","הורידו את המוט עד שהזרועות מקבילות לרצפה, תוך הרגשת מתיחה בחזה.","עצרו לרגע, ואז כווצו את שרירי החזה כדי להחזיר את המוט למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back on the floor with your knees bent and feet flat on the ground.","Hold a barbell with an overhand grip, arms extended straight up over your chest.","Slowly lower the barbell out to the sides, keeping a slight bend in your elbows.","Lower the barbell until your arms are parallel to the floor, feeling a stretch in your chest.","Pause for a moment, then squeeze your chest muscles to bring the barbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"neonEDL"},{"id":"edb-0459","name":"flutter kicks","name_en":"flutter kicks","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hip flexors","lower abs"],"steps":["שכבו שטוח על הגב עם הרגליים ישרות והידיים לצדי הגוף.","הפעילו את שרירי הליבה והרימו את הרגליים מהרצפה כ-6 אינץ'.","כשהרגליים ישרות, החליפו הרמת רגל אחת מעט גבוה יותר מהשנייה.","המשיכו בתנועת המספריים למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your legs extended and your hands by your sides.","Engage your core and lift your legs off the ground about 6 inches.","Keeping your legs straight, alternate lifting one leg slightly higher than the other.","Continue this fluttering motion for the desired number of repetitions."],"mediaId":"UVo2Qs2"},{"id":"edb-1472","name":"forward jump","name_en":"forward jump","muscle":"legs","equipment":"body weight","target":"quads","bodyPart":"upper legs","secondaryMuscles":["calves","hamstrings","glutes"],"steps":["עמדו עם הרגליים ברוחב הכתפיים.","כופפו את הברכיים והורידו את הגוף לתנוחת סקוואט.","נופפו את הזרועות לאחור לצבירת מומנטום.","קפצו קדימה בפיצוץ כוח, תוך יישור האגן, הברכיים והקרסוליים.","נחתו ברכות על כריות כפות הרגליים ועברו מיד לקפיצה הבאה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart.","Bend your knees and lower your body into a squat position.","Swing your arms back for momentum.","Jump forward explosively, extending your hips, knees, and ankles.","Land softly on the balls of your feet and immediately go into the next jump.","Repeat for the desired number of repetitions."],"mediaId":"uZKq7lo"},{"id":"edb-3470","name":"לאנג׳","name_en":"forward lunge (male)","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב האגן והידיים על המותניים.","בצעו צעד גדול קדימה עם הרגל הימנית, והורידו את הגוף לתנוחת לאנג'.","כופפו את הברך הימנית לכ-90 מעלות, תוך שמירה על הברך בקו אחד עם הקרסול.","דחפו עם הרגל הימנית וחזרו למצב ההתחלתי.","חזרו עם הרגל השמאלית, תוך החלפת צדדים למספר החזרות הרצוי."],"steps_en":["Stand with your feet hip-width apart and hands on your hips.","Take a big step forward with your right foot, lowering your body into a lunge position.","Bend your right knee to about 90 degrees, keeping your knee aligned with your ankle.","Push off with your right foot and return to the starting position.","Repeat with your left leg, alternating sides for the desired number of repetitions."],"mediaId":"kMzUs9Y"},{"id":"edb-3194","name":"סקוואט","name_en":"frankenstein squat","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו את המוט לפני הגוף עם זרועות ישרות.","כשהגב ישר, הורידו את הגוף על ידי כיפוף הברכיים והאגן, כאילו אתם יושבים על כיסא.","המשיכו לרדת עד שהירכיים מקבילות לרצפה, או עד למקסימום שנוח לכם.","עצרו לרגע, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold the barbell in front of your body with straight arms.","Keeping your back straight, lower your body by bending at the knees and hips, as if sitting back into a chair.","Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"bdWcbaU"},{"id":"edb-2429","name":"כפיפת בטן","name_en":"frog crunch","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו את הידיים מאחורי הראש כשהמרפקים פונים החוצה.","תוך הפעלת שרירי הבטן, הרימו את פלג הגוף העליון מהרצפה, וכופפו קדימה עד שהגו נמצא בזווית של 45 מעלות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"FFRP97T"},{"id":"edb-3301","name":"frog planche","name_en":"frog planche","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["shoulders","chest","triceps"],"steps":["התחילו בעמדת שכיבת סמיכה עם הידיים ברוחב הכתפיים והרגליים צמודות.","כופפו את המרפקים והורידו את הגוף לכיוון הרצפה, תוך שמירה על הגב ישר.","תוך כדי הורדת הגוף, הרימו את הרגליים מהרצפה והביאו את הברכיים לכיוון החזה.","החזיקו בתנוחה זו למספר שניות, ואז ישרו את הרגליים בחזרה החוצה ודחפו את עצמכם בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a push-up position with your hands shoulder-width apart and your feet together.","Bend your elbows and lower your body towards the ground, keeping your back straight.","As you lower your body, lift your feet off the ground and bring your knees towards your chest.","Hold this position for a few seconds, then extend your legs back out and push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"rQhGcin"},{"id":"edb-3296","name":"front lever","name_en":"front lever","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["lats","shoulders","forearms"],"steps":["התחילו בתלייה ממוט מתח באחיזה עליונה, הידיים ברוחב הכתפיים.","הפעילו את ליבת הגוף ומשכו את השכמות מטה ואחורה.","כופפו את הברכיים וקרבו אותן לכיוון החזה.","במקביל, הרימו את הרגליים וישרו אותן לפניכם, תוך שמירה על הגוף מקביל לרצפה.","החזיקו בתנוחה זו כמה שיותר זמן, בשאיפה להגיע לתנוחת פרונט לוור מלאה.","לשחרור, הורידו לאט את הרגליים בחזרה וחזרו למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by hanging from a pull-up bar with an overhand grip, hands shoulder-width apart.","Engage your core and pull your shoulder blades down and back.","Bend your knees and tuck them towards your chest.","Simultaneously, lift your legs up and extend them straight out in front of you, keeping your body parallel to the ground.","Hold this position for as long as you can, aiming for a full front lever position.","To release, slowly lower your legs back down and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"PkCN2lv"},{"id":"edb-3295","name":"front lever reps","name_en":"front lever reps","muscle":"back","equipment":"body weight","target":"upper back","bodyPart":"back","secondaryMuscles":["core","shoulders"],"steps":["היתלו ממוט מתח באחיזה עליונה, כפות הידיים פונות הרחק מכם.","הפעילו את ליבת הגוף ומשכו את השכמות מטה ואחורה.","כשהגוף ישר, הרימו את הרגליים עד שהן מקבילות לרצפה.","החזיקו בתנוחה זו כמה שיותר זמן, בשאיפה ל-10-20 שניות.","הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Hang from a pull-up bar with an overhand grip, palms facing away from you.","Engage your core and pull your shoulder blades down and back.","Keeping your body straight, lift your legs up until they are parallel to the ground.","Hold this position for as long as you can, aiming for 10-20 seconds.","Slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"hbY9wqG"},{"id":"edb-0464","name":"פיתול קדמי","name_en":"front plank with twist","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","shoulders"],"steps":["התחילו בתנוחת פלאנק גבוה עם הידיים ישר מתחת לכתפיים והגוף בקו ישר מהראש ועד כפות הרגליים.","הפעילו את שרירי הליבה והישבן כדי לשמור על תנוחה יציבה.","סובבו את הגו ימינה, הרימו את היד הימנית וישרו אותה לכיוון התקרה.","שמרו על האגן והרגליים יציבים תוך כדי הסיבוב.","החזיקו לרגע, ואז חזרו למצב ההתחלתי.","חזרו על הסיבוב בצד השמאלי.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Start in a high plank position with your hands directly under your shoulders and your body in a straight line from head to toe.","Engage your core and glutes to maintain a stable position.","Rotate your torso to the right, lifting your right arm and extending it towards the ceiling.","Keep your hips and legs stable as you twist.","Hold for a moment, then return to the starting position.","Repeat the twist on the left side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"CosupLu"},{"id":"edb-3315","name":"full maltese","name_en":"full maltese","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["shoulders","chest"],"steps":["התחילו בעמידה עם הרגליים ברוחב הכתפיים והזרועות ישרות הצדה.","התכופפו לאט קדימה, תוך שמירה על הזרועות ישרות, עד שפלג הגוף העליון מקביל לרצפה.","הפעילו את שרירי הליבה והחזיקו בתנוחה זו למספר שניות.","חזרו למצב ההתחלתי על ידי דחיפה דרך הרגליים וחזרה לעמידה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by standing with your feet shoulder-width apart and your arms extended straight out to the sides.","Slowly lean forward, keeping your arms straight, until your upper body is parallel to the ground.","Engage your core and hold this position for a few seconds.","Return to the starting position by pushing through your feet and standing back up.","Repeat for the desired number of repetitions."],"mediaId":"YRaCa5Y"},{"id":"edb-3299","name":"full planche","name_en":"full planche","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["shoulders","chest","triceps"],"steps":["התחילו בעמדת שכיבת סמיכה עם הידיים ברוחב הכתפיים והאצבעות פונות קדימה.","הפעילו את שרירי הליבה והעבירו לאט את המשקל קדימה, תוך הרמת הרגליים מהרצפה.","המשיכו להעביר את המשקל קדימה עד שהגוף מקביל לרצפה, תוך איזון על הידיים.","החזיקו בתנוחה זו כמה שיותר זמן, תוך שמירה על קו גוף ישר.","הורידו לאט את הרגליים בחזרה לרצפה וחזרו למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a push-up position with your hands shoulder-width apart and your fingers pointing forward.","Engage your core and slowly shift your weight forward, lifting your feet off the ground.","Continue shifting your weight forward until your body is parallel to the ground, balancing on your hands.","Hold this position for as long as you can, maintaining a straight body line.","Slowly lower your feet back to the ground and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"YZ4961r"},{"id":"edb-3327","name":"שכיבת סמיכה","name_en":"full planche push-up","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps","core"],"steps":["התחילו בעמדת שכיבת סמיכה עם הידיים ממוקמות מעט רחב יותר מרוחב הכתפיים.","הפעילו את שרירי הליבה והורידו את הגוף לכיוון הרצפה, תוך שמירה על המרפקים קרוב לגוף.","תוך כדי הורדת הגוף, הטו את הגוף קדימה והרימו את הרגליים מהרצפה, תוך איזון על הידיים.","המשיכו להוריד את הגוף עד שהחזה נמצא ממש מעל הרצפה.","דחפו דרך הידיים וישרו את הזרועות כדי להרים את הגוף בחזרה למצב ההתחלתי.","שמרו על קו ישר מהראש ועד העקבים לאורך כל התנועה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a push-up position with your hands placed slightly wider than shoulder-width apart.","Engage your core and lower your body down towards the ground, keeping your elbows close to your sides.","As you lower yourself, lean your body forward and lift your feet off the ground, balancing on your hands.","Continue to lower your body until your chest is just above the ground.","Push through your hands and extend your arms to lift your body back up to the starting position.","Maintain a straight line from your head to your heels throughout the movement.","Repeat for the desired number of repetitions."],"mediaId":"gw9PqGk"},{"id":"edb-0466","name":"gironda sternum chin","name_en":"gironda sternum chin","muscle":"back","equipment":"body weight","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","rhomboids","rear deltoids"],"steps":["עמדו מול מוט גבוה עם הרגליים ברוחב הכתפיים.","הושיטו יד למעלה ואחזו את המוט באחיזה עליונה, מעט רחב יותר מרוחב הכתפיים.","היתלו מהמוט עם הזרועות ישרות לחלוטין והגוף ישר.","הפעילו את שרירי הגב הרחב והביצפס כדי למשוך את החזה למעלה לכיוון המוט, תוך הובלה עם עצם החזה.","עצרו לרגע בשיא התנועה, ולאחר מכן רדו באיטיות חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand facing a high bar with your feet shoulder-width apart.","Reach up and grab the bar with an overhand grip, slightly wider than shoulder-width apart.","Hang from the bar with your arms fully extended and your body straight.","Engage your lats and biceps to pull your chest up towards the bar, leading with your sternum.","Pause for a moment at the top, then slowly lower yourself back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"IL0JUxR"},{"id":"edb-3561","name":"גשר ישבן","name_en":"glute bridge march","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הפעילו את שרירי הישבן והרימו את האגן מהרצפה, ביצירת קו ישר מהברכיים ועד הכתפיים.","תוך שמירה על האגן מורם, הרימו רגל אחת מהרצפה והביאו את הברך לכיוון החזה.","הורידו את הרגל בחזרה לרצפה וחזרו על התנועה עם הרגל השנייה.","המשיכו להחליף רגליים בתנועת צעידה תוך שמירה על תנוחת הגשר.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your knees bent and feet flat on the ground.","Engage your glutes and lift your hips off the ground, forming a straight line from your knees to your shoulders.","While keeping your hips lifted, lift one foot off the ground and bring your knee towards your chest.","Lower your foot back to the ground and repeat the movement with the other leg.","Continue alternating legs in a marching motion while maintaining the bridge position.","Repeat for the desired number of repetitions."],"mediaId":"GibBPPg"},{"id":"edb-3523","name":"גשר ישבן","name_en":"glute bridge two legs on bench (male)","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","core"],"steps":["שבו על קצה הספסל כשהגב צמוד אליו וכפות הרגליים שטוחות על הרצפה.","הניחו את הידיים על הספסל לצד המותניים לתמיכה.","הפעילו את שרירי הישבן והירך האחוריים, ולאחר מכן הרימו את הירכיים מהספסל עד שהגוף יוצר קו ישר מהברכיים ועד הכתפיים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הירכיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the edge of a bench with your back against it and your feet flat on the ground.","Place your hands on the bench beside your hips for support.","Engage your glutes and hamstrings, then lift your hips off the bench until your body forms a straight line from your knees to your shoulders.","Pause for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"aWedzZX"},{"id":"edb-3193","name":"הרמה","name_en":"glute-ham raise","muscle":"legs","equipment":"body weight","target":"hamstrings","bodyPart":"upper legs","secondaryMuscles":["glutes","lower back"],"steps":["כיוונו את מכונת ה-glute-ham raise כך שתתאים לגוף שלכם.","מקמו את עצמכם על הבטן על המכונה כשהקרסוליים מקובעים.","הניחו את הידיים על החזה או שלבו אותן על החזה.","הפעילו את שרירי הירך האחוריים והישבן כדי להרים את פלג הגוף העליון לכיוון התקרה.","המשיכו להרים עד שהגוף נמצא בקו ישר מהראש ועד העקבים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הגוף בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the glute-ham raise machine to fit your body.","Position yourself face down on the machine with your ankles secured.","Place your hands on your chest or cross them over your chest.","Engage your hamstrings and glutes to lift your upper body up towards the ceiling.","Continue lifting until your body is in a straight line from your head to your heels.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Vvwjz6N"},{"id":"edb-0467","name":"gorilla chin","name_en":"gorilla chin","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["forearms","biceps"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","אחזו מוט מתח באחיזה עליונה, מעט רחב יותר מרוחב הכתפיים.","היתלו מהמוט עם הזרועות ישרות לחלוטין וכפות הידיים פונות הרחק מכם.","הפעילו את שרירי הליבה ומשכו את הגוף למעלה לכיוון המוט, עד שהסנטר מעל המוט.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הגוף בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your knees slightly bent.","Grasp a pull-up bar with an overhand grip, slightly wider than shoulder-width apart.","Hang from the bar with your arms fully extended and your palms facing away from you.","Engage your core and pull your body up towards the bar, bringing your chin above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"bmwlYvD"},{"id":"edb-0469","name":"כפיפת בטן","name_en":"groin crunch","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors","inner thighs"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו את הידיים מאחורי הראש כשהמרפקים פונים החוצה.","תוך הפעלת שרירי הבטן, הרימו את הרגליים מהרצפה וקרבו את הברכיים לחזה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, lift your legs off the ground, bringing your knees towards your chest.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"mWppALS"},{"id":"edb-1383","name":"הרמת עקבים","name_en":"hack calf raise","muscle":"legs","equipment":"sled machine","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings","glutes"],"steps":["כיוונו את מכונת הסלד למשקל נוח.","עמדו על מכונת הסלד כשקצות האצבעות על הפלטפורמה והעקבים תלויים מחוצה לה.","אחזו בידיות לייצוב.","הרימו את העקבים גבוה ככל האפשר על ידי דחיפה דרך כריות כפות הרגליים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקבים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the sled machine to a comfortable weight.","Stand on the sled machine with your toes on the platform and your heels hanging off.","Hold onto the handles for stability.","Raise your heels as high as possible by pushing through the balls of your feet.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"2ORFMoR"},{"id":"edb-1384","name":"הרמת עקבים ברגל אחת","name_en":"hack one leg calf raise","muscle":"legs","equipment":"sled machine","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings","glutes"],"steps":["כיוונו את מכונת הסלד למשקל מתאים.","עמדו על מכונת הסלד עם רגל אחת, תוך שמירה על הרגל השנייה מורמת מהרצפה.","אחזו בידיות לייצוב.","הרימו את העקב גבוה ככל האפשר, תוך הרמת הגוף על כרית כף הרגל.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקב בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי.","החליפו רגליים וחזרו על התרגיל."],"steps_en":["Adjust the sled machine to an appropriate weight.","Stand on the sled machine with one foot, keeping the other foot off the ground.","Hold onto the handles for stability.","Raise your heel as high as possible, lifting your body up on the ball of your foot.","Pause for a moment at the top, then slowly lower your heel back down to the starting position.","Repeat for the desired number of repetitions.","Switch legs and repeat the exercise."],"mediaId":"AxFoqAD"},{"id":"edb-3221","name":"half knee bends (male)","name_en":"half knee bends (male)","muscle":"core","equipment":"body weight","target":"cardiovascular system","bodyPart":"cardio","secondaryMuscles":["quadriceps","hamstrings","glutes"],"steps":["עמדו עם הרגליים ברוחב הכתפיים.","כופפו את הברכיים והורידו את הגוף כאילו אתם יושבים על כיסא.","שמרו על החזה מורם ועל המשקל בעקבים.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart.","Bend your knees and lower your body down as if you were sitting back into a chair.","Keep your chest up and your weight in your heels.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ia6kIIl"},{"id":"edb-3202","name":"כפיפת בטן מלאה","name_en":"half sit-up (male)","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו את הידיים מאחורי הראש כשהמרפקים פונים החוצה.","תוך הפעלת שרירי הבטן, הרימו לאט את פלג הגוף העליון מהרצפה, בכיפוף קדימה עד שהגו נמצא בזווית של 45 מעלות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"iQ241UP"},{"id":"edb-1511","name":"מתיחה","name_en":"hamstring stretch","muscle":"legs","equipment":"body weight","target":"hamstrings","bodyPart":"upper legs","secondaryMuscles":["glutes"],"steps":["עמדו עם הרגליים ברוחב הכתפיים.","צעדו קדימה עם הרגל הימנית והעבירו את המשקל לרגל הימנית.","כשהגב ישר, התכופפו לאט קדימה מהאגן, תוך שליחת שתי הידיים לכיוון כף הרגל הימנית.","החזיקו את המתיחה 20-30 שניות, ואז חזרו למצב ההתחלתי.","חזרו על התרגיל בצד השני."],"steps_en":["Stand with your feet shoulder-width apart.","Step forward with your right foot and shift your weight onto your right leg.","Keeping your back straight, slowly bend forward at the hips, reaching towards your right foot with both hands.","Hold the stretch for 20-30 seconds, then return to the starting position.","Repeat on the other side."],"mediaId":"99rWm7w"},{"id":"edb-2139","name":"hands bike","name_en":"hands bike","muscle":"chest","equipment":"upper body ergometer","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["כיוונו את גובה המושב ומיקום הידית לרמה נוחה.","שבו על הארגומטר עם הגב ישר והרגליים על הדוושות.","אחזו בידיות עם הידיים ומקמו את הזרועות בזווית של 90 מעלות.","התחילו לדוושש עם הידיים, תוך דחיפה ומשיכה של הידיות בתנועה מבוקרת.","המשיכו לדווש למשך הזמן הרצוי או למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and handlebar position to a comfortable level.","Sit on the ergometer with your back straight and feet on the pedals.","Grasp the handles with your hands and position your arms at a 90-degree angle.","Start pedaling with your hands, pushing and pulling the handles in a controlled motion.","Continue pedaling for the desired duration or number of repetitions."],"mediaId":"pAIWRGu"},{"id":"edb-3218","name":"hands clasped circular toe touch (male)","name_en":"hands clasped circular toe touch (male)","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והידיים שלובות לפני החזה.","כופפו מעט את הברכיים והטו את הגוף קדימה במפרקי הירך, תוך שמירה על גב ישר.","הורידו את הידיים לכיוון האצבעות בתנועה מעגלית, תוך הגעה רחוק ככל האפשר ללא מאמץ יתר.","עצרו לרגע בתחתית התנועה, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your hands clasped together in front of your chest.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Lower your hands towards your toes in a circular motion, reaching as far as you can without straining.","Pause for a moment at the bottom, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"B5xca8s"},{"id":"edb-3215","name":"hands reversed clasped circular toe touch (male)","name_en":"hands reversed clasped circular toe touch (male)","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והזרועות ישרות הצדה.","התכופפו קדימה מהמותניים, תוך שמירה על גב ישר וברכיים כפופות מעט.","הושיטו את הידיים למטה ושלבו אותן מאחורי הרגליים.","הרימו לאט את הידיים למעלה ומעל הראש בתנועה מעגלית, תוך שמירה על הרגליים ישרות.","המשיכו בתנועה המעגלית עד שהידיים נוגעות באצבעות הרגליים.","הפכו את כיוון התנועה והחזירו את הידיים למטה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your arms extended to the sides.","Bend forward at the waist, keeping your back straight and your knees slightly bent.","Reach down with your hands and clasp them together behind your legs.","Slowly raise your hands up and over your head in a circular motion, keeping your legs straight.","Continue the circular motion until your hands touch your toes.","Reverse the motion and bring your hands back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"yq3GAJX"},{"id":"edb-3302","name":"handstand","name_en":"handstand","muscle":"triceps","equipment":"body weight","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders","core"],"steps":["מצאו מרחב פתוח עם מספיק מקום לביצוע עמידת ידיים.","הניחו את הידיים על הרצפה ברוחב הכתפיים, האצבעות פונות קדימה.","בעטו ברגליים למעלה לכיוון הקיר, תוך שימוש בליבה ובכתפיים לשמירה על שיווי משקל.","לאחר הגעה לעמידת ידיים, הפעילו את שריר הטריצפס כדי לתמוך במשקל הגוף.","החזיקו את עמידת הידיים כמה זמן שאתם מצליחים לשמור על שיווי משקל.","לירידה, הורידו לאט את הרגליים בחזרה לרצפה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Find an open space with enough room to perform a handstand.","Place your hands on the ground shoulder-width apart, fingers pointing forward.","Kick your legs up towards the wall, using your core and shoulders to maintain balance.","Once in a handstand position, engage your triceps to support your body weight.","Hold the handstand for as long as you can maintain balance.","To come down, slowly lower your legs back to the ground.","Repeat for the desired number of repetitions."],"mediaId":"XooAdhl"},{"id":"edb-0471","name":"שכיבת סמיכה","name_en":"handstand push-up","muscle":"triceps","equipment":"body weight","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders","chest","core"],"steps":["מצאו קיר ועמדו כשגבכם פונה אליו, במרחק של כמה צעדים ממנו.","הניחו את הידיים על הרצפה ברוחב הכתפיים ובעטו ברגליים למעלה אל הקיר, עד להגעה לעמידת ידיים.","כופפו את המרפקים והורידו את הראש לכיוון הרצפה, תוך שמירה על הגוף בקו ישר.","דחפו דרך הידיים וישרו את הזרועות כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Find a wall and face away from it, standing a few feet away.","Place your hands on the ground shoulder-width apart and kick your feet up against the wall, coming into a handstand position.","Bend your elbows and lower your head towards the ground, keeping your body in a straight line.","Push through your hands and extend your arms to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"rQxwMxO"},{"id":"edb-1764","name":"הרמת אגן","name_en":"hanging leg hip raise","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors","lower back"],"steps":["התלו ממתקן מתח כשהידיים מיושרות לגמרי וכפות הידיים פונות הרחק מכם.","הפעילו את שרירי הליבה והרימו את הרגליים על ידי כיפוף האגן והברכיים עד שהירכיים מקבילות לרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Hang from a pull-up bar with your arms fully extended and your palms facing away from you.","Engage your core and lift your legs up by flexing your hips and knees until your thighs are parallel to the ground.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"VEcJRo2"},{"id":"edb-0472","name":"הרמת רגליים בתלייה","name_en":"hanging leg raise","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["התלו ממתקן מתח כשהידיים מיושרות לגמרי וכפות הידיים פונות הרחק מכם.","הפעילו את שרירי הליבה והרימו את הרגליים לפניכם, תוך שמירה עליהן ישרות.","המשיכו להרים עד שהרגליים מקבילות לרצפה או עד לגובה הנוח לכם.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Hang from a pull-up bar with your arms fully extended and your palms facing away from you.","Engage your core and lift your legs up in front of you, keeping them straight.","Continue lifting until your legs are parallel to the ground or as high as you can comfortably go.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"I3tsCnC"},{"id":"edb-1761","name":"הרמה","name_en":"hanging oblique knee raise","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques"],"steps":["התלו ממתקן מתח כשהידיים מיושרות לגמרי וכפות הידיים פונות הרחק מכם.","הפעילו את שרירי הליבה והרימו את הברכיים לכיוון החזה, תוך סיבוב הגו הצידה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו בצד השני, תוך סיבוב הגו לכיוון ההפוך.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Hang from a pull-up bar with your arms fully extended and your palms facing away from you.","Engage your core and lift your knees towards your chest, twisting your torso to the side as you do so.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat on the other side, twisting your torso in the opposite direction.","Continue alternating sides for the desired number of repetitions."],"mediaId":"BaE7O6U"},{"id":"edb-0473","name":"hanging pike","name_en":"hanging pike","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors","shoulders"],"steps":["התלו ממתקן מתח כשהידיים מיושרות לגמרי וכפות הידיים פונות הרחק מכם.","הפעילו את שרירי הליבה והרימו את הרגליים לכיוון המוט, תוך שמירה עליהן ישרות.","המשיכו להרים עד שהגוף יוצר צורת V, כשהרגליים מקבילות לרצפה.","החזיקו בתנוחה לרגע, ואז הורידו לאט את הרגליים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Hang from a pull-up bar with your arms fully extended and your palms facing away from you.","Engage your core and lift your legs up towards the bar, keeping them straight.","Continue lifting until your body forms a 'V' shape, with your legs parallel to the ground.","Hold the position for a moment, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"nuBF9MO"},{"id":"edb-0474","name":"הרמת אגן","name_en":"hanging straight leg hip raise","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["התלו ממתקן מתח כשהידיים מיושרות לגמרי וכפות הידיים פונות הרחק מכם.","הפעילו את ליבת הגוף והרימו את הרגליים לפנים עד שהן מקבילות לרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Hang from a pull-up bar with your arms fully extended and your palms facing away from you.","Engage your core and lift your legs up in front of you until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"pj0X0tF"},{"id":"edb-0475","name":"הרמת רגליים","name_en":"hanging straight leg raise","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["התלו ממתקן מתח כשהידיים מיושרות לגמרי וכפות הידיים פונות הרחק מכם.","הפעילו את שרירי הליבה והרימו את הרגליים לפניכם, תוך שמירה עליהן ישרות.","המשיכו להרים עד שהרגליים מקבילות לרצפה או עד לגובה הנוח לכם.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Hang from a pull-up bar with your arms fully extended and your palms facing away from you.","Engage your core and lift your legs up in front of you, keeping them straight.","Continue lifting until your legs are parallel to the ground or as high as you can comfortably go.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"4Ml7QFO"},{"id":"edb-0476","name":"הרמת אגן","name_en":"hanging straight twisting leg hip raise","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","hip flexors"],"steps":["היתלו ממוט מתח עם הזרועות ישרות לחלוטין והרגליים ישרות.","הפעילו את שרירי הליבה והרימו את הרגליים לכיוון החזה, תוך שמירה עליהן ישרות.","כשהרגליים מקבילות לרצפה, סובבו את האגן לצד אחד, תוך הבאת הרגליים לכיוון אותו צד.","עצרו לרגע, ולאחר מכן חזרו למצב ההתחלתי.","חזרו על התנועה, אך הפעם סובבו את האגן לצד ההפוך.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Hang from a pull-up bar with your arms fully extended and your legs straight.","Engage your core and lift your legs up towards your chest, keeping them straight.","Once your legs are parallel to the ground, twist your hips to one side, bringing your legs towards that side.","Pause for a moment, then return to the starting position.","Repeat the movement, but this time twist your hips to the opposite side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"Q6bvyen"},{"id":"edb-3636","name":"high knee against wall","name_en":"high knee against wall","muscle":"core","equipment":"body weight","target":"cardiovascular system","bodyPart":"cardio","secondaryMuscles":["quadriceps","hamstrings","glutes","calves"],"steps":["עמדו מול קיר עם הרגליים ברוחב האגן.","הניחו את הידיים על הקיר לתמיכה.","הפעילו את שרירי הליבה והרימו את הברך הימנית לכיוון החזה, תוך שמירה על הרגל השמאלית על הרצפה.","החליפו רגליים במהירות, תוך הבאת הברך השמאלית לכיוון החזה והורדת הרגל הימנית בחזרה למטה.","המשיכו להחליף רגליים בתנועת ריצה, תוך הבאת הברכיים גבוה ככל האפשר.","שמרו על קצב מהיר ועל פלג הגוף העליון יציב לאורך כל התרגיל.","חזרו למשך הזמן או מספר החזרות הרצוי."],"steps_en":["Stand facing a wall with your feet hip-width apart.","Place your hands on the wall for support.","Engage your core and lift your right knee up towards your chest, while keeping your left foot on the ground.","Quickly switch legs, bringing your left knee up towards your chest and lowering your right foot back down.","Continue alternating legs in a running motion, bringing your knees up as high as possible.","Maintain a fast pace and keep your upper body stable throughout the exercise.","Repeat for the desired duration or number of repetitions."],"mediaId":"ealLwvX"},{"id":"edb-0484","name":"הרמת אגן בהטיה","name_en":"hip raise (bent knee)","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["glutes","hamstrings"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו את הידיים לצדי הגוף, כפות הידיים פונות למטה.","הפעילו את שרירי הליבה והישבן, ואז הרימו את האגן מהרצפה עד שהגוף יוצר קו ישר מהברכיים ועד הכתפיים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הירכיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands by your sides, palms facing down.","Engage your core and glutes, then lift your hips off the ground until your body forms a straight line from your knees to your shoulders.","Pause for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"196HJGw"},{"id":"edb-1418","name":"hug keens to chest","name_en":"hug keens to chest","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps"],"steps":["התחילו בעמידה עם הרגליים ברוחב הכתפיים.","כופפו את הברכיים והורידו את הגוף לתנוחת סקוואט.","תוך כדי הירידה לסקוואט, הביאו את הברכיים לכיוון החזה וחבקו אותן עם הזרועות.","החזיקו בתנוחה זו לרגע, ואז חזרו לאט למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by standing with your feet shoulder-width apart.","Bend your knees and lower your body down into a squat position.","As you squat down, bring your knees up towards your chest and hug them with your arms.","Hold this position for a moment, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"znP9SIh"},{"id":"edb-3234","name":"פרפר עם משקולות","name_en":"hyght dumbbell fly","muscle":"chest","equipment":"dumbbell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders"],"steps":["שכבו על ספסל כשבכל יד משקולת, כפות הידיים פונות זו לזו.","פשטו את הידיים ישר מעל החזה, עם כיפוף קל במרפקים.","תוך שמירה על כיפוף קל במרפקים, הורידו את המשקולות הצדה בתנועת קשת רחבה עד שאתם מרגישים מתיחה בחזה.","עצרו לרגע, ואז הפכו את כיוון התנועה והחזירו את המשקולות למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a bench with a dumbbell in each hand, palms facing each other.","Extend your arms straight up over your chest, with a slight bend in your elbows.","Keeping a slight bend in your elbows, lower the dumbbells out to the sides in a wide arc until you feel a stretch in your chest.","Pause for a moment, then reverse the movement and bring the dumbbells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"P9ZRyLT"},{"id":"edb-0489","name":"פשיטת גב","name_en":"hyperextension","muscle":"back","equipment":"body weight","target":"spine","bodyPart":"back","secondaryMuscles":["glutes","hamstrings"],"steps":["כיוונו את ספסל ההיפראקסטנשן כך שהירכיים העליונות נשענות על הכרית והרגליים מקובעות.","שלבו את הזרועות על החזה או הניחו את הידיים מאחורי הראש.","הורידו את פלג הגוף העליון לכיוון הרצפה תוך שמירה על הגב ישר.","עצרו לרגע בתחתית התנועה, ואז הרימו את פלג הגוף העליון בחזרה עד שהוא בקו אחד עם הרגליים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the hyperextension bench so that your upper thighs are resting on the pad and your feet are secured.","Cross your arms over your chest or place your hands behind your head.","Lower your upper body towards the ground while keeping your back straight.","Pause for a moment at the bottom, then raise your upper body back up until it is in line with your legs.","Repeat for the desired number of repetitions."],"mediaId":"zhMwOwE"},{"id":"edb-0488","name":"פשיטת גב","name_en":"hyperextension (on bench)","muscle":"back","equipment":"body weight","target":"spine","bodyPart":"back","secondaryMuscles":["glutes","hamstrings"],"steps":["כיוונו את ספסל ההיפראקסטנשן כך שהאגן נשען בנוחות על הכרית והרגליים מקובעות.","שלבו את הזרועות על החזה או הניחו את הידיים מאחורי הראש.","הורידו לאט את פלג הגוף העליון לכיוון הרצפה תוך שמירה על הגב ישר.","עצרו לרגע בתחתית התנועה, ואז הרימו את פלג הגוף העליון בחזרה עד שהוא בקו אחד עם הרגליים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the hyperextension bench so that your hips are resting comfortably on the pad and your feet are secured.","Cross your arms over your chest or place your hands behind your head.","Slowly lower your upper body towards the ground while keeping your back straight.","Pause for a moment at the bottom, then raise your upper body back up until it is in line with your legs.","Repeat for the desired number of repetitions."],"mediaId":"zkgRrbK"},{"id":"edb-3289","name":"impossible dips","name_en":"impossible dips","muscle":"triceps","equipment":"body weight","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["מקמו את עצמכם בין שני מקבילים עם הזרועות ישרות לחלוטין והגוף מרחף באוויר.","כופפו את הברכיים ושלבו את הקרסוליים.","הורידו את הגוף על ידי כיפוף המרפקים עד שהזרועות העליונות מקבילות לרצפה.","עצרו לרגע, ואז דחפו את עצמכם בחזרה למצב ההתחלתי על ידי יישור הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Position yourself between two parallel bars with your arms fully extended and your body suspended in the air.","Bend your knees and cross your ankles.","Lower your body by bending your elbows until your upper arms are parallel to the ground.","Pause for a moment, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"mediaId":"05Cf2v8"},{"id":"edb-1471","name":"inchworm","name_en":"inchworm","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["shoulders","hamstrings"],"steps":["התחילו בעמידה עם הרגליים ברוחב האגן.","התכופפו קדימה מהמותניים והניחו את הידיים על הרצפה לפניכם.","צעדו עם הידיים קדימה עד שאתם בתנוחת פלאנק גבוה, עם הגוף בקו ישר מהראש ועד כפות הרגליים.","עצרו לרגע, ואז צעדו עם הידיים בחזרה לכיוון הרגליים, תוך שמירה על הרגליים ישרות ככל האפשר.","כשהידיים מגיעות לרגליים, חזרו לעמידה במצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a standing position with your feet hip-width apart.","Bend forward at the waist and place your hands on the ground in front of you.","Walk your hands forward until you are in a high plank position, with your body in a straight line from head to toe.","Pause for a moment, then walk your hands back towards your feet, keeping your legs as straight as possible.","Once your hands reach your feet, stand back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ZgsNQ6d"},{"id":"edb-3698","name":"inchworm v. 2","name_en":"inchworm v. 2","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["shoulders","hamstrings"],"steps":["התחילו בעמידה עם הרגליים ברוחב האגן.","התכופפו קדימה מהמותניים והניחו את הידיים על הרצפה לפניכם.","צעדו עם הידיים קדימה עד שאתם בתנוחת פלאנק גבוה, עם הגוף בקו ישר מהראש ועד כפות הרגליים.","כשהרגליים ישרות, צעדו עם הרגליים לכיוון הידיים, תוך הבאת האגן למעלה לכיוון התקרה.","המשיכו לצעוד עם הידיים קדימה, תוך חזרה על התנועה למספר החזרות הרצוי."],"steps_en":["Start in a standing position with your feet hip-width apart.","Bend forward at the waist and place your hands on the ground in front of you.","Walk your hands forward until you are in a high plank position, with your body in a straight line from head to toe.","Keeping your legs straight, walk your feet towards your hands, bringing your hips up towards the ceiling.","Continue walking your hands forward, repeating the movement for the desired number of repetitions."],"mediaId":"TV87DNB"},{"id":"edb-0490","name":"שכיבת סמיכה אחיזה צרה בשיפוע","name_en":"incline close-grip push-up","muscle":"triceps","equipment":"body weight","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["הניחו את הידיים על משטח מוגבה, כגון ספסל או מדרגה, מעט רחב יותר מרוחב הכתפיים.","ישרו את הרגליים מאחוריכם, תוך הישענות על כריות כפות הרגליים, כשהגוף יוצר קו ישר מהראש ועד העקבים.","הורידו את החזה לכיוון המשטח המוגבה על ידי כיפוף המרפקים, תוך שמירה עליהם קרוב לגוף.","עצרו לרגע בתחתית התנועה, ואז דחפו את עצמכם בחזרה למצב ההתחלתי על ידי יישור הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Place your hands on an elevated surface, such as a bench or step, slightly wider than shoulder-width apart.","Extend your legs behind you, resting on the balls of your feet, with your body forming a straight line from head to heels.","Lower your chest towards the elevated surface by bending your elbows, keeping them close to your sides.","Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"mediaId":"1YB40kg"},{"id":"edb-0491","name":"הרמת אגן בשיפוע","name_en":"incline leg hip raise (leg straight)","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שכבו על ספסל שיפוע חיובי עם הגב שטוח על הספסל והרגליים ישרות לפניכם.","הניחו את הידיים על צידי הספסל לתמיכה.","תוך הפעלת שרירי הבטן, הרימו את הרגליים מהספסל, גבוה ככל האפשר תוך שמירה עליהן ישרות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie on an incline bench with your back flat against the bench and your legs extended straight out in front of you.","Place your hands on the sides of the bench for support.","Engaging your abs, lift your legs off the bench, raising them as high as you can while keeping them straight.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"eVxAzgz"},{"id":"edb-0492","name":"שכיבת סמיכה בשיפוע","name_en":"incline push up depth jump","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders","core"],"steps":["מצאו משטח מוגבה, כגון ספסל או מדרגה, והניחו את הידיים ברוחב הכתפיים על הקצה.","צעדו עם הרגליים לאחור, תוך שמירה על הגוף בקו ישר מהראש ועד העקבים.","הורידו את החזה לכיוון קצה המשטח, כופפו את המרפקים ושמרו על הגוף מיושר.","דחפו דרך כפות הידיים כדי ליישר את הידיים ולחזור לעמדת ההתחלה.","קפצו מקצה המשטח, ונחתו ברכות עם הברכיים כפופות מעט.","חזרו על שכיבת הסמיכה וקפיצת העומק למספר החזרות הרצוי."],"steps_en":["Find an elevated surface, such as a bench or step, and place your hands shoulder-width apart on the edge.","Step your feet back, keeping your body in a straight line from head to heels.","Lower your chest towards the edge of the surface, bending your elbows and keeping your body aligned.","Push through your palms to extend your arms and return to the starting position.","Jump off the edge of the surface, landing softly with your knees slightly bent.","Repeat the push-up and depth jump for the desired number of repetitions."],"mediaId":"CB8WET1"},{"id":"edb-0493","name":"שכיבת סמיכה בשיפוע","name_en":"incline push-up","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["הניחו את הידיים על משטח מוגבה, כגון ספסל או מדרגה, מעט רחב יותר מרוחב הכתפיים.","ישרו את הרגליים מאחוריכם, תוך הישענות על כריות כפות הרגליים, ביצירת קו ישר מהראש ועד העקבים.","הורידו את החזה לכיוון המשטח המוגבה על ידי כיפוף המרפקים, תוך שמירה על הגוף בקו ישר.","עצרו לרגע בתחתית התנועה, ואז דחפו את עצמכם בחזרה למצב ההתחלתי על ידי יישור הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Place your hands on an elevated surface, such as a bench or step, slightly wider than shoulder-width apart.","Extend your legs behind you, resting on the balls of your feet, creating a straight line from your head to your heels.","Lower your chest towards the elevated surface by bending your elbows, keeping your body in a straight line.","Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"mediaId":"B1EVP9F"},{"id":"edb-3785","name":"שכיבת סמיכה בשיפוע","name_en":"incline push-up (on box)","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["הניחו את הידיים על קצה קופסה או משטח מוגבה, מעט רחב יותר מרוחב הכתפיים.","ישרו את הרגליים מאחוריכם, תוך הישענות על כריות כפות הרגליים, ביצירת קו ישר מהראש ועד העקבים.","הורידו את החזה לכיוון הקופסה על ידי כיפוף המרפקים, תוך שמירה על הגוף בקו ישר.","עצרו לרגע בתחתית התנועה, ואז דחפו את עצמכם בחזרה למצב ההתחלתי על ידי יישור הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Place your hands on the edge of a box or elevated surface, slightly wider than shoulder-width apart.","Extend your legs behind you, resting on the balls of your feet, creating a straight line from your head to your heels.","Lower your chest towards the box by bending your elbows, keeping your body in a straight line.","Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"mediaId":"F7vjXqT"},{"id":"edb-0494","name":"שכיבת סמיכה אחיזה הפוכה בשיפוע","name_en":"incline reverse grip push-up","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["הניחו את הידיים על קצה ספסל או משטח מוגבה, מעט רחב יותר מרוחב הכתפיים.","ישרו את הרגליים מאחוריכם, תוך הישענות על כריות כפות הרגליים, ביצירת קו ישר מהראש ועד העקבים.","הורידו את החזה לכיוון הספסל על ידי כיפוף המרפקים, תוך שמירה עליהם קרוב לגוף.","עצרו לרגע בתחתית התנועה, ואז דחפו את עצמכם בחזרה למצב ההתחלתי על ידי יישור הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Place your hands on the edge of a bench or elevated surface, slightly wider than shoulder-width apart.","Extend your legs behind you, resting on the balls of your feet, creating a straight line from your head to your heels.","Lower your chest towards the bench by bending your elbows, keeping them close to your sides.","Pause for a moment at the bottom, then push yourself back up to the starting position by extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"XaaRnRn"},{"id":"edb-3011","name":"שכיבת סמיכה בשיפוע","name_en":"incline scapula push up","muscle":"chest","equipment":"body weight","target":"serratus anterior","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["הציבו ספסל בשיפוע עולה בזווית של 45 מעלות.","הניחו את הידיים על הספסל מעט רחב יותר מרוחב הכתפיים.","מקמו את הרגליים על הרצפה, ברוחב האגן.","הורידו את החזה לכיוון הספסל, תוך שמירה על המרפקים צמודים לגוף.","תוך כדי הירידה, משכו את שכמות הכתפיים לאחור, וכווצו אותן יחד.","דחפו דרך כפות הידיים כדי ליישר את הידיים ולחזור לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up an incline bench at a 45-degree angle.","Place your hands on the bench slightly wider than shoulder-width apart.","Position your feet on the ground, hip-width apart.","Lower your chest towards the bench, keeping your elbows tucked in.","As you lower, retract your shoulder blades, squeezing your scapulae together.","Push through your palms to extend your arms and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"GdMa1ET"},{"id":"edb-0495","name":"כפיפת בטן מלאה בשיפוע","name_en":"incline twisting sit-up","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques"],"steps":["הציבו ספסל בשיפוע עולה בזווית של 45 מעלות.","שכבו על הספסל כשהרגליים מקובעות מתחת לכריות הרגליים.","הניחו את הידיים מאחורי הראש או לרוחב החזה.","הפעילו את שרירי הבטן והרימו את פלג הגוף העליון מהספסל, תוך כיפוף קדימה.","תוך כדי ההרמה, סובבו את הגו לצד אחד, תוך הבאת המרפק לכיוון הברך הנגדית.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התנועה, הפעם תוך סיבוב הגו לצד השני.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Set up an incline bench at a 45-degree angle.","Lie down on the bench with your feet secured under the foot pads.","Place your hands behind your head or across your chest.","Engage your abs and lift your upper body off the bench, curling forward.","As you curl up, twist your torso to one side, bringing your elbow towards the opposite knee.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat the movement, this time twisting your torso to the other side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"9ZGZuOD"},{"id":"edb-1564","name":"מתיחה","name_en":"intermediate hip flexor and quad stretch","muscle":"legs","equipment":"rope","target":"quads","bodyPart":"upper legs","secondaryMuscles":["hamstrings","glutes"],"steps":["עמדו זקוף עם הרגליים ברוחב הכתפיים.","אחזו בעצם יציב לתמיכה.","כופפו את הברך הימנית והביאו את כף הרגל הימנית לכיוון הישבן, תוך אחיזת החבל ביד הימנית.","משכו לאט את כף הרגל הימנית לכיוון הישבן, תוך הרגשת מתיחה בשריר הארבע-ראשי הימני.","החזיקו את המתיחה במשך 20-30 שניות.","שחררו את המתיחה וחזרו בצד השמאלי."],"steps_en":["Stand upright with your feet shoulder-width apart.","Hold onto a stable object for support.","Bend your right knee and bring your right foot towards your glutes, grabbing the rope with your right hand.","Slowly pull your right foot towards your glutes, feeling a stretch in your right quad.","Hold the stretch for 20-30 seconds.","Release the stretch and repeat on the left side."],"mediaId":"tFGKm99"},{"id":"edb-0496","name":"כפיפת ברך","name_en":"inverse leg curl (bench support)","muscle":"legs","equipment":"body weight","target":"hamstrings","bodyPart":"upper legs","secondaryMuscles":["glutes","calves"],"steps":["שכבו על הבטן על ספסל כשהאגן בקצה והרגליים ישרות מאחוריכם.","אחזו בספסל לתמיכה.","כשפלג הגוף העליון נייח, כופפו את הברכיים והביאו את הרגליים לכיוון הישבן.","עצרו לרגע בשיא התנועה, ואז ישרו לאט את הרגליים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie face down on a bench with your hips at the edge and your legs extended straight behind you.","Hold onto the bench for support.","Keeping your upper body still, bend your knees and curl your legs towards your glutes.","Pause for a moment at the top, then slowly extend your legs back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ms7tjSG"},{"id":"edb-2400","name":"מתח בפולי","name_en":"inverse leg curl (on pull-up cable machine)","muscle":"legs","equipment":"body weight","target":"hamstrings","bodyPart":"upper legs","secondaryMuscles":["glutes","calves"],"steps":["כיוונו את מכונת הפולי כך שרצועות הקרסול נמצאות בהגדרה הנמוכה ביותר.","שכבו על הבטן על הספסל עם הרגליים ישרות ורצועות הקרסול מחוברות לרגליים.","אחזו בידיות הספסל לשם יציבות.","כופפו את הברכיים והביאו את הרגליים לכיוון הישבן, תוך כיווץ שרירי הירך האחוריים.","עצרו לרגע בשיא התנועה, ואז הורידו לאט את הרגליים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the cable machine so that the ankle straps are at the lowest setting.","Lie face down on the bench with your legs extended and the ankle straps attached to your feet.","Hold onto the handles of the bench for stability.","Bend your knees and curl your legs towards your glutes, squeezing your hamstrings.","Pause for a moment at the top of the movement, then slowly lower your legs back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"0rHfvy9"},{"id":"edb-0499","name":"חתירה","name_en":"inverted row","muscle":"back","equipment":"body weight","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["הציבו מוט בגובה המותניים או השתמשו ברצועות אימון תלויות (TRX).","עמדו מול המוט או רצועות האימון, עם הרגליים ברוחב הכתפיים.","אחזו את המוט או הידיות באחיזה עליונה, מעט רחב יותר מרוחב הכתפיים.","הטו את הגוף לאחור, תוך שמירה עליו ישר והעקבים על הרצפה.","משכו את החזה לכיוון המוט או הידיות, תוך כיווץ שכמות הכתפיים יחד.","עצרו לרגע בשיא התנועה, ואז הורידו את עצמכם לאט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up a bar at waist height or use a suspension trainer.","Stand facing the bar or suspension trainer, with your feet shoulder-width apart.","Grab the bar or handles with an overhand grip, slightly wider than shoulder-width apart.","Lean back, keeping your body straight and your heels on the ground.","Pull your chest towards the bar or handles, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower yourself back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"bZGHsAZ"},{"id":"edb-2300","name":"חתירה בהטיה","name_en":"inverted row bent knees","muscle":"back","equipment":"body weight","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["הציבו מוט בגובה המותניים ושכבו מתחתיו.","אחזו את המוט באחיזה עליונה, מעט רחב יותר מרוחב הכתפיים.","מקמו את הגוף כך שהעקבים על הרצפה והגוף ישר.","משכו את החזה למעלה לכיוון המוט על ידי כיווץ שכמות הכתפיים יחד.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הגוף בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up a bar at waist height and lie underneath it.","Grab the bar with an overhand grip, slightly wider than shoulder-width apart.","Position your body so that your heels are on the ground and your body is straight.","Pull your chest up towards the bar by squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"VPPtusI"},{"id":"edb-2298","name":"חתירה","name_en":"inverted row on bench","muscle":"back","equipment":"body weight","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["הציבו ספסל בגובה שמאפשר לגוף להיתלות באופן חופשי מתחתיו.","שכבו על הגב על הרצפה כשהראש לכיוון הספסל.","הושיטו יד למעלה ואחזו בספסל באחיזה עליונה, מעט רחב יותר מרוחב הכתפיים.","מקמו את הגוף כך שהעקבים על הרצפה והזרועות ישרות לחלוטין.","הפעילו את שרירי הליבה וכווצו את שכמות הכתפיים יחד תוך משיכת החזה למעלה לכיוון הספסל.","עצרו לרגע בשיא התנועה, ואז הורידו לאט את הגוף בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up a bench at a height that allows your body to hang freely underneath it.","Lie face up on the ground with your head towards the bench.","Reach up and grab the bench with an overhand grip, slightly wider than shoulder-width apart.","Position your body so that your heels are on the ground and your arms are fully extended.","Engage your core and squeeze your shoulder blades together as you pull your chest up towards the bench.","Pause for a moment at the top of the movement, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Mxa7Cr8"},{"id":"edb-0497","name":"חתירה","name_en":"inverted row v. 2","muscle":"back","equipment":"body weight","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["הציבו מוט בגובה המותניים על מכונת סמית' או השתמשו ברצועות אימון תלויות.","עמדו מול המוט או רצועות האימון ואחזו בו באחיזה עליונה, הידיים ברוחב הכתפיים.","צעדו עם הרגליים קדימה, תוך הטיה לאחור עד שהגוף בזווית קלה.","שמרו על הגוף ישר ומשכו את החזה למעלה לכיוון המוט או הידיות, תוך כיווץ שכמות הכתפיים יחד.","עצרו לרגע בשיא התנועה, ולאחר מכן רדו באיטיות חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up a bar at waist height on a Smith machine or use a suspension trainer.","Stand facing the bar or suspension trainer and grab it with an overhand grip, hands shoulder-width apart.","Walk your feet forward, leaning back until your body is at a slight angle.","Keep your body straight and pull your chest up towards the bar or handles, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower yourself back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"uX3sUBz"},{"id":"edb-0498","name":"חתירה","name_en":"inverted row with straps","muscle":"back","equipment":"body weight","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["הציבו רצועות אימון תלויות בגובה החזה.","עמדו מול נקודת העיגון ואחזו בידיות באחיזה עליונה.","צעדו עם הרגליים קדימה, תוך הטיה לאחור עד שהגוף בזווית.","שמרו על הגוף ישר והפעילו את שרירי הליבה.","משכו את החזה לכיוון הידיות, תוך כיווץ שכמות הכתפיים יחד.","עצרו לרגע בשיא התנועה, ואז הורידו את עצמכם לאט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up a suspension trainer or straps at chest height.","Stand facing the anchor point and grab the handles with an overhand grip.","Walk your feet forward, leaning back until your body is at an angle.","Keep your body straight and engage your core.","Pull your chest towards the handles, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower yourself back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"jdiExfW"},{"id":"edb-1419","name":"מתיחה","name_en":"iron cross stretch","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps"],"steps":["שכבו שטוח על הגב עם הזרועות ישרות הצדה.","הרימו את הרגליים כלפי התקרה, תוך שמירה עליהן ישרות.","הורידו לאט את הרגליים לצד אחד, בניסיון לגעת ברצפה עם כפות הרגליים.","החזיקו את המתיחה למשך מספר שניות, ולאחר מכן החזירו את הרגליים לעמדת ההתחלה.","חזרו על המתיחה בצד השני.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your arms extended out to the sides.","Raise your legs up towards the ceiling, keeping them straight.","Slowly lower your legs to one side, aiming to touch the floor with your feet.","Hold the stretch for a few seconds, then return your legs to the starting position.","Repeat the stretch on the other side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"pZwUsKB"},{"id":"edb-1297","name":"isometric chest squeeze","name_en":"isometric chest squeeze","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","שלחו את הידיים ישר לפניכם, במקביל לקרקע, כשכפות הידיים פונות זו לזו.","כווצו את שרירי החזה בחוזקה ככל האפשר, תוך שמירה על הידיים ישרות.","החזיקו בעמדה זו למספר שניות, תוך התמקדות בכיווץ שרירי החזה.","שחררו את הכיווץ והרפו את שרירי החזה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your knees slightly bent.","Extend your arms straight out in front of you, parallel to the ground, with your palms facing each other.","Squeeze your chest muscles together as hard as you can, while keeping your arms straight.","Hold this position for a few seconds, focusing on contracting your chest muscles.","Release the squeeze and relax your chest muscles.","Repeat for the desired number of repetitions."],"mediaId":"HbSG1Pw"},{"id":"edb-0500","name":"isometric wipers","name_en":"isometric wipers","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps","core"],"steps":["התחילו בשכיבה על הגב על מזרן או ספסל.","שלחו את הידיים ישר הצדה, בניצב לגוף.","הפעילו את שרירי הליבה והרימו את שתי הרגליים מהקרקע, תוך שמירה עליהן צמודות וישרות.","הורידו לאט את הרגליים לצד אחד, בניסיון לגעת בקרקע עם כפות הרגליים תוך שמירה על שליטה.","עצרו לרגע, ולאחר מכן השתמשו בשרירי הליבה כדי להרים את הרגליים חזרה לעמדת ההתחלה.","חזרו על התנועה, הפעם תוך הורדת הרגליים לצד הנגדי.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Start by lying flat on your back on a mat or bench.","Extend your arms straight out to the sides, perpendicular to your body.","Engage your core and lift both legs off the ground, keeping them together and straight.","Slowly lower your legs to one side, aiming to touch the ground with your feet while maintaining control.","Pause for a moment, then use your core to lift your legs back to the starting position.","Repeat the movement, this time lowering your legs to the opposite side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"11wrviz"},{"id":"edb-0501","name":"jack burpee","name_en":"jack burpee","muscle":"core","equipment":"body weight","target":"cardiovascular system","bodyPart":"cardio","secondaryMuscles":["quadriceps","hamstrings","calves","shoulders","triceps","core"],"steps":["התחילו בעמידה כשרגליכם ברוחב הכתפיים.","הורידו את הגוף לעמדת סקוואט, והניחו את הידיים על הקרקע לפניכם.","בעטו את הרגליים אחורה, ונחתו בעמדת שכיבת סמיכה.","בצעו שכיבת סמיכה, הורידו את החזה לכיוון הקרקע ולאחר מכן דחפו חזרה למעלה.","קפצו עם הרגליים קדימה, ונחתו בעמדת סקוואט.","קפצו למעלה בפיצוץ כוח, תוך הושטת הידיים מעל הראש.","נחתו ברכות ומיד רדו חזרה לעמדת הסקוואט כדי להתחיל את החזרה הבאה."],"steps_en":["Start in a standing position with your feet shoulder-width apart.","Lower your body into a squat position, placing your hands on the ground in front of you.","Kick your feet back, landing in a push-up position.","Perform a push-up, lowering your chest to the ground and then pushing back up.","Jump your feet forward, landing in a squat position.","Jump up explosively, reaching your arms overhead.","Land softly and immediately lower back into the squat position to begin the next repetition."],"mediaId":"mr7pkqP"},{"id":"edb-3224","name":"jack jump (male)","name_en":"jack jump (male)","muscle":"core","equipment":"body weight","target":"cardiovascular system","bodyPart":"cardio","secondaryMuscles":["quadriceps","calves"],"steps":["עמדו עם הרגליים צמודות והידיים לצד הגוף.","קפצו למעלה, פסקו את הרגליים והרימו את הידיים מעל הראש.","בעת הנחיתה, קפצו מהר חזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet together and your arms by your sides.","Jump up, spreading your feet apart and raising your arms above your head.","As you land, quickly jump back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"1g5bPpA"},{"id":"edb-0507","name":"כפיפת בטן מלאה","name_en":"jackknife sit-up","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שכבו על הגב עם הרגליים שלוחות והידיים מעל הראש.","הפעילו את שרירי הליבה והרימו את הרגליים ואת פלג הגוף העליון בו-זמנית, תוך הושטת הידיים לכיוון האצבעות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגליים ואת פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your legs extended and your arms overhead.","Engage your core and lift your legs and upper body simultaneously, reaching your hands towards your toes.","Pause for a moment at the top, then slowly lower your legs and upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"mbkgB44"},{"id":"edb-0508","name":"כפיפת בטן מלאה","name_en":"janda sit-up","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors","lower back"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו את הידיים מאחורי הראש כשהמרפקים פונים החוצה.","תוך הפעלת שרירי הבטן, הרימו לאט את פלג הגוף העליון מהרצפה, בכיפוף קדימה עד שהגו נמצא בזווית של 45 מעלות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"1GPHRyK"},{"id":"edb-2612","name":"jump rope","name_en":"jump rope","muscle":"core","equipment":"rope","target":"cardiovascular system","bodyPart":"cardio","secondaryMuscles":["calves","quadriceps","hamstrings","glutes"],"steps":["אחזו בידיות חבל הקפיצה, כשכפות הידיים פונות פנימה.","עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","הניפו את החבל מעל הראש וקפצו מעליו כשהוא מגיע לכיוון הרגליים.","נחתו ברכות על כריות כפות הרגליים וחזרו על הקפיצה כשהחבל חוזר שוב.","המשיכו לקפוץ למשך הזמן הרצוי או למספר החזרות הרצוי."],"steps_en":["Hold the handles of the jump rope with your hands, palms facing inward.","Stand with your feet shoulder-width apart and knees slightly bent.","Swing the rope over your head and jump over it as it comes towards your feet.","Land softly on the balls of your feet and repeat the jump as the rope comes around again.","Continue jumping for the desired duration or number of repetitions."],"mediaId":"e1e76I2"},{"id":"edb-0514","name":"סקוואט","name_en":"jump squat","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים.","הורידו את הגוף לתנוחת סקוואט על ידי כפיפת הברכיים ודחיפת האגן אחורה.","קפצו באופן נפיץ מהקרקע, תוך יישור הירכיים, הברכיים והקרסוליים.","באוויר, הביאו את הידיים קדימה במהירות לשמירה על שיווי המשקל.","נחתו ברכות על כריות כפות הרגליים ועברו מיד לחזרה הבאה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart.","Lower your body into a squat position by bending your knees and pushing your hips back.","Jump explosively off the ground, extending your hips, knees, and ankles.","While in mid-air, quickly bring your arms forward for balance.","Land softly on the balls of your feet and immediately go into the next repetition.","Repeat for the desired number of repetitions."],"mediaId":"LIlE5Tn"},{"id":"edb-0513","name":"סקוואט","name_en":"jump squat v. 2","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים.","הורידו את הגוף לתנוחת סקוואט על ידי כפיפת הברכיים ודחיפת האגן אחורה.","קפצו באופן נפיץ, תוך יישור מלא של הירכיים והברכיים.","נחתו ברכות על כריות כפות הרגליים ומיד רדו חזרה לעמדת סקוואט.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart.","Lower your body into a squat position by bending your knees and pushing your hips back.","Jump explosively, extending your hips and knees fully.","Land softly on the balls of your feet and immediately lower your body back into a squat position.","Repeat for the desired number of repetitions."],"mediaId":"TDYiji6"},{"id":"edb-0517","name":"kettlebell advanced windmill","name_en":"kettlebell advanced windmill","muscle":"core","equipment":"kettlebell","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","shoulders"],"steps":["עמדו עם הרגליים רחבות יותר מרוחב הכתפיים, אצבעות הרגליים פונות מעט החוצה.","אחזו קטלבל ביד ימין, כשהיד שלוחה מעל הראש וכף היד פונה קדימה.","סובבו את כף רגל שמאל מעט ימינה, והעבירו את משקל הגוף לרגל שמאל.","כופפו את ברך שמאל ורכנו במפרק הירך, תוך הורדת פלג הגוף העליון לכיוון הצד השמאלי.","שמרו על יד ימין שלוחה מעל הראש והביטו בקטלבל.","בעת הורדת פלג הגוף, אפשרו לרגל ימין להתיישר ולכף רגל ימין לסובב מעט.","הורידו את פלג הגוף העליון עד שתרגישו מתיחה בשריר הירך האחורי השמאלי ויד ימין מכוונת לכיוון הקרקע.","עצרו לרגע, ולאחר מכן הפעילו את שרירי הליבה ודחפו דרך עקב שמאל כדי לחזור לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Stand with your feet wider than shoulder-width apart, toes pointing slightly outward.","Hold a kettlebell in your right hand, with your arm extended overhead and your palm facing forward.","Rotate your left foot slightly to the right, and shift your weight onto your left leg.","Bend your left knee and hinge at the hip, lowering your torso towards the left side.","Keep your right arm extended overhead and your eyes on the kettlebell.","As you lower your torso, allow your right leg to straighten and your right foot to pivot slightly.","Lower your torso until you feel a stretch in your left hamstring and your right arm is pointing towards the ground.","Pause for a moment, then engage your core and push through your left heel to return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"Kal9cQQ"},{"id":"edb-0518","name":"קלין לסירוגין עם קטלבל","name_en":"kettlebell alternating hang clean","muscle":"biceps","equipment":"kettlebell","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["shoulders","traps","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים קטלבל בכל יד באחיזה עליונה.","כופפו את הברכיים מעט והתכופפו קדימה מהירכיים, תוך שמירה על גב ישר וחזה מורם.","אפשרו לקטלבלים להיתלות לפני הגוף כשהידיים שלוחות לגמרי.","בתנועה זורמת אחת, יישרו באופן נפיץ את הירכיים, משכו את הכתפיים כלפי מעלה, ומשכו את הקטלבלים כלפי הכתפיים.","כשהקטלבלים מגיעים לגובה הכתפיים, סובבו את פרקי הידיים ותפסו את הקטלבלים בעמדת המנוחה, כשכפות הידיים פונות פנימה והקטלבלים נשענים על החלק החיצוני של האמות.","הורידו את הקטלבלים חזרה לעמדת ההתחלה וחזרו על התנועה עם היד הנגדית.","המשיכו להחליף ידיים למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a kettlebell in each hand with an overhand grip.","Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up.","Allow the kettlebells to hang in front of your body with your arms fully extended.","In one fluid motion, explosively extend your hips, shrug your shoulders, and pull the kettlebells up towards your shoulders.","As the kettlebells reach shoulder height, rotate your wrists and catch the kettlebells in the rack position, with your palms facing inward and the kettlebells resting on the outside of your forearms.","Lower the kettlebells back down to the starting position and repeat the movement with the opposite arm.","Continue alternating arms for the desired number of repetitions."],"mediaId":"I4tibZG"},{"id":"edb-0520","name":"לחיצה לסירוגין עם קטלבל","name_en":"kettlebell alternating press","muscle":"shoulders","equipment":"kettlebell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים קטלבל בכל יד בגובה הכתפיים.","דחפו קטלבל אחד מעל הראש, תוך יישור מלא של היד.","הורידו את הקטלבל חזרה לגובה הכתפיים.","חזרו עם הזרוע השנייה.","המשיכו להחליף ידיים למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder height.","Press one kettlebell overhead, fully extending your arm.","Lower the kettlebell back to shoulder height.","Repeat with the other arm.","Continue alternating arms for the desired number of repetitions."],"mediaId":"5KLbZWx"},{"id":"edb-0519","name":"לחיצה לסירוגין עם קטלבל","name_en":"kettlebell alternating press on floor","muscle":"chest","equipment":"kettlebell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["התחילו בשכיבה על הגב על הרצפה כשהברכיים כפופות וכפות הרגליים שטוחות על הקרקע.","אחזו קטלבל בכל יד, כשכפות הידיים פונות לכיוון הרגליים והידיים שלוחות ישר כלפי התקרה.","הורידו קטלבל אחד לכיוון הכתף תוך שמירה על הקטלבל השני שלוח ישר למעלה.","דחפו את הקטלבל שהורד חזרה למעלה לעמדת ההתחלה, תוך הורדת הקטלבל השני בו-זמנית לכיוון הכתף.","המשיכו להחליף את תנועת הדחיפה בין הקטלבלים למספר החזרות הרצוי."],"steps_en":["Start by lying on your back on the floor with your knees bent and feet flat on the ground.","Hold a kettlebell in each hand, with your palms facing towards your feet and your arms extended straight up towards the ceiling.","Lower one kettlebell down towards your shoulder while keeping the other kettlebell extended straight up.","Press the lowered kettlebell back up to the starting position while simultaneously lowering the other kettlebell down towards your shoulder.","Continue alternating the press motion with each kettlebell for the desired number of repetitions."],"mediaId":"7w6i0vE"},{"id":"edb-0521","name":"חתירה לסירוגין עם קטלבל","name_en":"kettlebell alternating renegade row","muscle":"back","equipment":"kettlebell","target":"upper back","bodyPart":"back","secondaryMuscles":["core","shoulders"],"steps":["התחילו בעמדת פלאנק גבוה כשהידיים אוחזות בקטלבלים והרגליים ברוחב הירכיים.","הפעילו את שרירי הליבה ושמרו על קו ישר מהראש ועד העקבים.","משכו קטלבל אחד כלפי החזה, תוך שמירה על המרפק קרוב לגוף.","הורידו את הקטלבל חזרה לעמדת ההתחלה וחזרו עם היד השנייה.","המשיכו להחליף ידיים למספר החזרות הרצוי."],"steps_en":["Start in a high plank position with your hands gripping the kettlebells and your feet hip-width apart.","Engage your core and keep your body in a straight line from head to heels.","Pull one kettlebell up towards your chest, keeping your elbow close to your body.","Lower the kettlebell back down to the starting position and repeat with the other arm.","Continue alternating arms for the desired number of repetitions."],"mediaId":"b9kqlBy"},{"id":"edb-0522","name":"חתירה לסירוגין עם קטלבל","name_en":"kettlebell alternating row","muscle":"back","equipment":"kettlebell","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, הברכיים כפופות מעט, ואחזו קטלבל בכל יד כשכפות הידיים פונות לגוף.","התכופפו קדימה מהירכיים, תוך שמירה על גב ישר ושרירי ליבה פעילים.","משכו קטלבל אחד כלפי החזה, תוך שמירה על המרפק קרוב לגוף וכיווץ השכמות זו לזו.","הורידו את הקטלבל חזרה לעמדת ההתחלה וחזרו עם היד השנייה.","המשיכו להחליף ידיים למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, knees slightly bent, and hold a kettlebell in each hand with your palms facing your body.","Bend forward at the hips, keeping your back straight and your core engaged.","Pull one kettlebell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together.","Lower the kettlebell back down to the starting position and repeat with the other arm.","Continue alternating arms for the desired number of repetitions."],"mediaId":"Ca76jUE"},{"id":"edb-0523","name":"לחיצה עם קטלבל","name_en":"kettlebell arnold press","muscle":"shoulders","equipment":"kettlebell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים קטלבל בכל יד בגובה הכתפיים וכפות הידיים פונות אליכם.","הפעילו את שרירי הליבה ודחפו את הקטלבלים מעל הראש, תוך סיבוב כפות הידיים לפנות קדימה ככל שהידיים מתיישרות.","עצרו בשיא התנועה, ולאחר מכן הורידו לאט את הקטלבלים חזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder height with your palms facing towards you.","Engage your core and press the kettlebells overhead, rotating your palms to face forward as you extend your arms.","Pause at the top of the movement, then slowly lower the kettlebells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"UM8mgyG"},{"id":"edb-0524","name":"לחיצה בהטיה עם קטלבל","name_en":"kettlebell bent press","muscle":"core","equipment":"kettlebell","target":"abs","bodyPart":"waist","secondaryMuscles":["shoulders","triceps","obliques"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים קטלבל ביד ימין.","כופפו מעט את הברכיים ודחפו את הקטלבל מעל הראש עם יד ימין, תוך שמירה על המרפק נעול.","סובבו את פלג הגוף העליון שמאלה, תוך העברת המשקל לכף רגל שמאל.","כופפו את ברך שמאל והורידו את פלג הגוף העליון לכיוון הקרקע, תוך שמירה על יד ימין שלוחה מעל הראש.","בעת הירידה, הביטו בקטלבל ושמרו על החזה מורם.","ברגע שיד שמאל נוגעת בקרקע, דחפו דרך כף רגל שמאל ויישרו את רגל שמאל, תוך דחיפת הירכיים קדימה.","בעת דחיפת הירכיים קדימה, השתמשו בשרירי הליבה וביד ימין כדי לדחוף את הקטלבל חזרה למעלה לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Stand with your feet shoulder-width apart, holding a kettlebell in your right hand.","Bend your knees slightly and press the kettlebell overhead with your right arm, keeping your elbow locked.","Rotate your torso to the left, shifting your weight onto your left foot.","Bend your left knee and lower your torso towards the ground, keeping your right arm extended overhead.","As you lower, keep your eyes on the kettlebell and your chest lifted.","Once your left hand touches the ground, push through your left foot and straighten your left leg, driving your hips forward.","As you drive your hips forward, use your core and right arm to press the kettlebell back up to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"kjE55n5"},{"id":"edb-0525","name":"קלין עם קטלבל","name_en":"kettlebell bottoms up clean from the hang position","muscle":"biceps","equipment":"kettlebell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms","shoulders"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים קטלבל ביד אחת באחיזה עליונה.","כופפו את הברכיים מעט והתכופפו קדימה מהירכיים, תוך שמירה על גב ישר וחזה מורם.","אפשרו לקטלבל להיתלות בין הרגליים, כשהיד שלוחה לגמרי.","בתנועה זורמת אחת, יישרו באופן נפיץ את הירכיים והברכיים תוך משיכת הקטלבל כלפי הכתף.","כשהקטלבל מגיע לגובה הכתפיים, סובבו את פרק היד כך שתחתית הקטלבל פונה כלפי מעלה.","תפסו את הקטלבל בגובה הכתפיים כשהמרפק כפוף וכף היד פונה כלפי מעלה.","הורידו את הקטלבל חזרה לעמדת ההתחלה על ידי היפוך התנועה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Stand with your feet shoulder-width apart, holding a kettlebell in one hand with an overhand grip.","Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up.","Allow the kettlebell to hang down between your legs, with your arm fully extended.","In one fluid motion, explosively extend your hips and knees while pulling the kettlebell up towards your shoulder.","As the kettlebell reaches shoulder height, rotate your wrist so that the bottom of the kettlebell is facing up.","Catch the kettlebell at shoulder height with your elbow bent and your palm facing up.","Lower the kettlebell back down to the starting position by reversing the movement.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"4KJEpzb"},{"id":"edb-0526","name":"קלין לסירוגין עם קטלבל","name_en":"kettlebell double alternating hang clean","muscle":"biceps","equipment":"kettlebell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms","shoulders"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים קטלבל בכל יד באחיזה עליונה.","כופפו את הברכיים מעט והתכופפו קדימה מהירכיים, תוך שמירה על גב ישר וחזה מורם.","אפשרו לקטלבלים להיתלות ישר כלפי מטה לפני הגוף.","בתנועה זורמת אחת, יישרו באופן נפיץ את הירכיים והברכיים תוך משיכת הכתפיים כלפי מעלה.","כשהקטלבלים עולים, משכו אותם כלפי הכתפיים, תוך שמירה על המרפקים גבוהים ומופשלים הצדה.","תפסו את הקטלבלים בגובה הכתפיים, כשכפות הידיים פונות פנימה והמרפקים מכוונים קדימה.","הורידו את הקטלבלים חזרה לעמדת ההתחלה וחזרו למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a kettlebell in each hand with an overhand grip.","Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up.","Allow the kettlebells to hang straight down in front of your body.","In one fluid motion, explosively extend your hips and knees while shrugging your shoulders.","As the kettlebells rise, pull them up towards your shoulders, keeping your elbows high and out to the sides.","Catch the kettlebells at shoulder height, with your palms facing inward and your elbows pointing forward.","Lower the kettlebells back down to the starting position and repeat for the desired number of repetitions."],"mediaId":"a4F9Oyc"},{"id":"edb-0527","name":"kettlebell double jerk","name_en":"kettlebell double jerk","muscle":"shoulders","equipment":"kettlebell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים קטלבל בכל יד בגובה הכתפיים.","כופפו מעט את הברכיים והפעילו את שרירי הליבה.","דחפו את הקטלבלים מעל הראש, תוך יישור מלא של הידיים.","כופפו את הברכיים ורדו מהר לסקוואט חלקי.","יישרו באופן נפיץ את הירכיים והברכיים, תוך דחיפת הקטלבלים מעל הראש.","נעלו את הידיים ותפסו את הקטלבלים מעל הראש כשהברכיים כפופות מעט.","התייצבו זקוף וחזרו לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder height.","Bend your knees slightly and engage your core.","Press the kettlebells overhead, fully extending your arms.","Bend your knees and quickly drop into a partial squat.","Explosively extend your hips and knees, driving the kettlebells overhead.","Lock out your arms and catch the kettlebells overhead with your knees slightly bent.","Stand up straight and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"tznL2Ad"},{"id":"edb-0528","name":"פוש פרס עם קטלבל","name_en":"kettlebell double push press","muscle":"shoulders","equipment":"kettlebell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","core"],"steps":["התחילו בעמידה עם הרגליים ברוחב הכתפיים, כשאתם אוחזים קטלבל בכל יד בגובה הכתפיים.","כופפו מעט את הברכיים והפעילו את שרירי הליבה.","התחילו את התנועה על ידי יישור נפיץ של הירכיים, הברכיים והקרסוליים, תוך דחיפת הקטלבלים מעל הראש.","כשהקטלבלים מגיעים לשיא, דחפו אותם לגמרי מעל הראש, תוך נעילת הידיים.","הורידו את הקטלבלים חזרה לעמדת ההתחלה על ידי כיפוף המרפקים והבאתם חזרה לגובה הכתפיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by standing with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder height.","Bend your knees slightly and engage your core.","Initiate the movement by explosively extending your hips, knees, and ankles, driving the kettlebells overhead.","As the kettlebells reach the top, press them fully overhead, locking out your arms.","Lower the kettlebells back to the starting position by bending your elbows and bringing them back down to shoulder height.","Repeat for the desired number of repetitions."],"mediaId":"I4KkPdl"},{"id":"edb-0529","name":"סנאץ׳ עם קטלבל","name_en":"kettlebell double snatch","muscle":"shoulders","equipment":"kettlebell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","forearms","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים קטלבל בכל יד באורך יד מלא לפני הירכיים.","כופפו מעט את הברכיים ורכנו קדימה במפרק הירך, תוך שמירה על הגב ישר והחזה מורם.","בתנועה נפיצה אחת, יישרו את הירכיים, הברכיים והקרסוליים, ובו-זמנית משכו את הקטלבלים כלפי הכתפיים.","כשהקטלבלים מגיעים לגובה הכתפיים, סובבו את פרקי הידיים ודחפו את הקטלבלים מעל הראש, תוך יישור מלא של הידיים.","הורידו את הקטלבלים חזרה לעמדת ההתחלה וחזרו למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a kettlebell in each hand at arm's length in front of your thighs.","Bend your knees slightly and hinge forward at the hips, keeping your back flat and chest up.","In one explosive motion, extend your hips, knees, and ankles, and simultaneously pull the kettlebells up towards your shoulders.","As the kettlebells reach shoulder level, rotate your wrists and punch the kettlebells overhead, fully extending your arms.","Lower the kettlebells back down to the starting position and repeat for the desired number of repetitions."],"mediaId":"M74kdvm"},{"id":"edb-0530","name":"kettlebell double windmill","name_en":"kettlebell double windmill","muscle":"core","equipment":"kettlebell","target":"abs","bodyPart":"waist","secondaryMuscles":["shoulders","hamstrings"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים קטלבל ביד ימין.","שלחו את יד ימין מעל הראש, והביטו בקטלבל.","סובבו את כף רגל שמאל 45 מעלות שמאלה ואת כף רגל ימין 90 מעלות ימינה.","כופפו במותניים לכיוון שמאל, תוך שמירה על יד ימין שלוחה מעל הראש.","הורידו את הקטלבל לכיוון הקרקע, תוך הושטה לכיוון כף רגל שמאל.","עצרו לרגע, ולאחר מכן הפעילו את שרירי הליבה ודחפו דרך כף רגל ימין כדי לחזור לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Stand with your feet shoulder-width apart, holding a kettlebell in your right hand.","Extend your right arm overhead, keeping your eyes on the kettlebell.","Rotate your left foot 45 degrees to the left and your right foot 90 degrees to the right.","Bend at the waist to the left, keeping your right arm extended overhead.","Lower the kettlebell towards the ground, reaching towards your left foot.","Pause for a moment, then engage your core and push through your right foot to return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"OaE7CpD"},{"id":"edb-0531","name":"לחיצה ביד אחת עם קטלבל","name_en":"kettlebell extended range one arm press on floor","muscle":"chest","equipment":"kettlebell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["התחילו בשכיבה על הגב על הרצפה כשהברכיים כפופות וכפות הרגליים שטוחות על הקרקע.","אחזו קטלבל ביד אחת, כשכף היד פונה לכיוון הרגליים.","שלחו את היד ישר כלפי התקרה, תוך שמירה על המרפק נעול ופרק היד ישר.","הורידו לאט את הקטלבל חזרה לעמדת ההתחלה, תוך שמירה על שליטה לאורך כל התנועה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ליד השנייה."],"steps_en":["Start by lying on your back on the floor with your knees bent and feet flat on the ground.","Hold a kettlebell in one hand, with your palm facing towards your feet.","Extend your arm straight up towards the ceiling, keeping your elbow locked and your wrist straight.","Slowly lower the kettlebell back down to the starting position, maintaining control throughout the movement.","Repeat for the desired number of repetitions, then switch to the other arm."],"mediaId":"rseLfH3"},{"id":"edb-0532","name":"kettlebell figure 8","name_en":"kettlebell figure 8","muscle":"core","equipment":"kettlebell","target":"abs","bodyPart":"waist","secondaryMuscles":["shoulders","forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים קטלבל ביד אחת.","כופפו מעט את הברכיים והטו את הגוף קדימה במפרקי הירך, תוך שמירה על גב ישר.","העבירו את הקטלבל בין הרגליים, תוך החלפת ידיים כשהוא מגיע לחלק האחורי של הרגליים.","כשהקטלבל מגיע קדימה, העבירו אותו ליד השנייה בין הרגליים.","המשיכו להעביר את הקטלבל בין הרגליים בתנועת דמוי ספרה 8.","שמרו על קצב קבוע והפעילו את שרירי הליבה לאורך כל התרגיל.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a kettlebell in one hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Pass the kettlebell between your legs, switching hands as it reaches the back of your legs.","As the kettlebell comes forward, pass it to the other hand between your legs.","Continue passing the kettlebell between your legs in a figure 8 motion.","Maintain a steady pace and engage your core throughout the exercise.","Repeat for the desired number of repetitions."],"mediaId":"L4ay0PW"},{"id":"edb-0533","name":"סקוואט קדמי עם קטלבל","name_en":"kettlebell front squat","muscle":"glutes","equipment":"kettlebell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והבהונות פונות מעט החוצה.","אחזו את הקטלבל בשתי הידיים לפני החזה, קרוב לגוף.","הפעילו את שרירי הליבה ושמרו על החזה מורם בעת הורדת הירכיים למטה ואחורה, כאילו אתם יושבים על כיסא.","רדו עד שהירכיים מקבילות לרצפה, או עד למקסימום שנוח לכם.","דחפו דרך העקבים כדי לחזור לעמידה, תוך כיווץ שרירי הישבן בשיא התנועה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, toes slightly turned out.","Hold the kettlebell with both hands in front of your chest, close to your body.","Engage your core and keep your chest up as you lower your hips down and back, as if sitting into a chair.","Lower until your thighs are parallel to the ground, or as low as you can comfortably go.","Drive through your heels to stand back up, squeezing your glutes at the top.","Repeat for the desired number of repetitions."],"mediaId":"DB0n8AG"},{"id":"edb-0534","name":"סקוואט גובלט עם קטלבל","name_en":"kettlebell goblet squat","muscle":"glutes","equipment":"kettlebell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים קטלבל קרוב לחזה בשתי הידיים.","תוך שמירה על החזה מורם ושרירי הליבה מופעלים, הורידו את הגוף לעמדת סקוואט על ידי כיפוף הברכיים והירכיים.","המשיכו לרדת עד שהירכיים מקבילות לרצפה, או עד למקסימום שנוח לכם.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a kettlebell close to your chest with both hands.","Keeping your chest up and core engaged, lower your body down into a squat position by bending at the knees and hips.","Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ZA8b5hc"},{"id":"edb-0535","name":"קלין עם קטלבל","name_en":"kettlebell hang clean","muscle":"legs","equipment":"kettlebell","target":"hamstrings","bodyPart":"upper legs","secondaryMuscles":["glutes","quadriceps","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים קטלבל לפני הירכיים.","כופפו מעט את הברכיים והטו את הגוף קדימה במפרקי הירך, תוך שמירה על גב ישר.","הורידו את הקטלבל לכיוון הקרקע, ואפשרו לו להתנדנד בין הרגליים.","יישרו במהירות את הירכיים והברכיים, תוך שימוש בתנופה כדי להניף את הקטלבל לגובה הכתפיים.","כשהקטלבל מגיע לגובה הכתפיים, סובבו את פרקי הידיים ותפסו את הקטלבל בעמדת המנוחה, כשהמרפק צמוד לגוף והקטלבל נשען על האמה.","הורידו את הקטלבל חזרה לעמדת ההתחלה בין הרגליים, וחזרו למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a kettlebell in front of your thighs.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Lower the kettlebell towards the ground, allowing it to swing between your legs.","Quickly extend your hips and knees, using the momentum to swing the kettlebell up to shoulder height.","As the kettlebell reaches shoulder height, rotate your wrists and catch the kettlebell in the rack position, with your elbow tucked in and the kettlebell resting on your forearm.","Lower the kettlebell back down to the starting position between your legs, and repeat for the desired number of repetitions."],"mediaId":"LHWF7us"},{"id":"edb-0536","name":"לאנג׳ עם קטלבל","name_en":"kettlebell lunge pass through","muscle":"glutes","equipment":"kettlebell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים קטלבל לפני החזה בשתי הידיים.","צעדו קדימה עם הרגל הימנית, תוך הורדת הגוף לעמדת לאנג'.","בעת ביצוע לאנג' קדימה, העבירו את הקטלבל מתחת לירך ימין והעבירו אותו ליד שמאל.","דחפו עם כף רגל ימין כדי לחזור לעמדת ההתחלה, תוך העברת הקטלבל בו-זמנית חזרה ליד ימין.","חזרו על הלאנג' בצד הנגדי, תוך העברת הקטלבל מתחת לירך שמאל.","המשיכו להחליף בין לאנג'ים והעברת הקטלבל בין הידיים למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a kettlebell in front of your chest with both hands.","Take a step forward with your right foot, lowering your body into a lunge position.","As you lunge forward, pass the kettlebell under your right thigh and transfer it to your left hand.","Push off with your right foot to return to the starting position, while simultaneously passing the kettlebell back to your right hand.","Repeat the lunge on the opposite side, passing the kettlebell under your left thigh.","Continue alternating lunges and passing the kettlebell between hands for the desired number of repetitions."],"mediaId":"WKMQzCD"},{"id":"edb-0537","name":"קלין ביד אחת עם קטלבל","name_en":"kettlebell one arm clean and jerk","muscle":"shoulders","equipment":"kettlebell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים קטלבל ביד אחת באחיזה עליונה.","כופפו מעט את הברכיים ורכנו במפרק הירך, תוך הורדת הקטלבל בין הרגליים.","יישרו באופן נפיץ את הירכיים, הברכיים והקרסוליים, תוך שימוש בתנופה כדי להניף את הקטלבל לגובה הכתפיים.","כשהקטלבל מגיע לגובה הכתפיים, סובבו את פרק היד ודחפו את היד ישר כלפי מעלה, תוך נעילת היד מעל הראש.","הורידו את הקטלבל חזרה לעמדת ההתחלה וחזרו למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a kettlebell in one hand with an overhand grip.","Bend your knees slightly and hinge at the hips, lowering the kettlebell between your legs.","Explosively extend your hips, knees, and ankles, using the momentum to swing the kettlebell up to shoulder height.","As the kettlebell reaches shoulder height, rotate your wrist and punch your hand straight up, locking out your arm overhead.","Lower the kettlebell back down to the starting position and repeat for the desired number of repetitions."],"mediaId":"vzAxBtt"},{"id":"edb-1298","name":"לחיצה מהרצפה ביד אחת עם קטלבל","name_en":"kettlebell one arm floor press","muscle":"chest","equipment":"kettlebell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["שכבו על הגב על הרצפה, כשהברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","אחזו את הקטלבל ביד אחת כשכף היד פונה לכיוון הרגליים והיד שלוחה ישר כלפי התקרה.","הורידו לאט את הקטלבל לכיוון החזה על ידי כיפוף המרפק, תוך שמירה על הזרוע העליונה קרובה לגוף.","עצרו לרגע כשהקטלבל נמצא ממש מעל החזה, ולאחר מכן דחפו אותו חזרה למעלה לעמדת ההתחלה על ידי יישור המרפק.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ליד השנייה."],"steps_en":["Lie flat on your back on the floor with your knees bent and feet flat on the ground.","Hold the kettlebell in one hand with your palm facing towards your feet and your arm extended straight up towards the ceiling.","Slowly lower the kettlebell towards your chest by bending your elbow, keeping your upper arm close to your body.","Pause for a moment when the kettlebell is just above your chest, then push it back up to the starting position by extending your elbow.","Repeat for the desired number of repetitions, then switch to the other arm."],"mediaId":"rg59QCH"},{"id":"edb-0538","name":"kettlebell one arm jerk","name_en":"kettlebell one arm jerk","muscle":"shoulders","equipment":"kettlebell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים קטלבל ביד אחת בגובה הכתף.","כופפו מעט את הברכיים והפעילו את שרירי הליבה.","דחפו את הקטלבל מעל הראש בקו ישר, תוך יישור מלא של היד.","בעת דחיפת הקטלבל מעל הראש, כופפו בו-זמנית מעט את הברכיים ויישרו אותן מהר כדי ליצור תנופה.","כשהקטלבל מגיע לנקודה הגבוהה ביותר, רדו מהר מתחתיו על ידי כיפוף הברכיים והירכיים.","תפסו את הקטלבל כשהברכיים והירכיים כפופות מעט, והיד שלוחה לגמרי מעל הראש.","התייצבו זקוף, תוך יישור מלא של הברכיים והירכיים, וייצבו את הקטלבל מעל הראש.","הורידו את הקטלבל חזרה לעמדת ההתחלה על ידי כיפוף הברכיים והירכיים, וחזרו למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a kettlebell in one hand at shoulder height.","Bend your knees slightly and engage your core.","Press the kettlebell overhead in a straight line, fully extending your arm.","As you press the kettlebell overhead, simultaneously dip your knees and quickly straighten them to generate momentum.","As the kettlebell reaches its highest point, quickly drop underneath it by bending your knees and hips.","Catch the kettlebell with a slight bend in your knees and hips, and your arm fully extended overhead.","Stand up straight, fully extending your knees and hips, and stabilize the kettlebell overhead.","Lower the kettlebell back to the starting position by bending your knees and hips, and repeat for the desired number of repetitions."],"mediaId":"S37C94C"},{"id":"edb-0539","name":"לחיצה צבאית ביד אחת צדי עם קטלבל","name_en":"kettlebell one arm military press to the side","muscle":"shoulders","equipment":"kettlebell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים קטלבל ביד אחת בגובה הכתף.","הפעילו את הליבה ושמרו על גב ישר.","דחפו את הקטלבל מעל הראש, תוך יישור מלא של היד.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הקטלבל חזרה לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Stand with your feet shoulder-width apart, holding a kettlebell in one hand at shoulder height.","Engage your core and keep your back straight.","Press the kettlebell overhead, extending your arm fully.","Pause for a moment at the top, then slowly lower the kettlebell back to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"yCvYdi7"},{"id":"edb-0540","name":"פוש פרס ביד אחת עם קטלבל","name_en":"kettlebell one arm push press","muscle":"shoulders","equipment":"kettlebell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים קטלבל ביד אחת בגובה הכתף.","כופפו מעט את הברכיים והפעילו את שרירי הליבה.","דחפו את הקטלבל מעל הראש על ידי יישור היד ויישור מלא של הרגליים.","הורידו את הקטלבל חזרה לעמדת ההתחלה על ידי כיפוף הברכיים והבאת הקטלבל חזרה לכתף.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Stand with your feet shoulder-width apart, holding a kettlebell in one hand at shoulder level.","Bend your knees slightly and engage your core.","Press the kettlebell overhead by extending your arm and fully extending your legs.","Lower the kettlebell back to the starting position by bending your knees and bringing the kettlebell back to your shoulder.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"osdXT3K"},{"id":"edb-0541","name":"חתירה ביד אחת עם קטלבל","name_en":"kettlebell one arm row","muscle":"back","equipment":"kettlebell","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים קטלבל ביד אחת באחיזה עליונה.","כופפו את הברכיים מעט והטו את הגוף קדימה ממפרקי הירך, תוך שמירה על גב ישר והפעלת שרירי הליבה.","משכו את הקטלבל כלפי החזה, תוך שמירה על המרפק קרוב לגוף וכיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הקטלבל חזרה לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צד וחזרו עם היד השנייה."],"steps_en":["Stand with your feet shoulder-width apart, holding a kettlebell in one hand with an overhand grip.","Bend your knees slightly and hinge forward at the hips, keeping your back straight and your core engaged.","Pull the kettlebell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the kettlebell back down to the starting position.","Repeat for the desired number of repetitions, then switch sides and repeat with the other arm."],"mediaId":"g9AsZ8P"},{"id":"edb-0542","name":"סנאץ׳ ביד אחת עם קטלבל","name_en":"kettlebell one arm snatch","muscle":"shoulders","equipment":"kettlebell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","forearms","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים קטלבל ביד אחת בין הרגליים.","כופפו מעט את הברכיים ורכנו במפרק הירך, תוך הורדת הקטלבל לכיוון הקרקע.","יישרו באופן נפיץ את הירכיים והברכיים, תוך שימוש בתנופה כדי להניף את הקטלבל כלפי הכתף.","כשהקטלבל מגיע לגובה הכתף, סובבו את היד ודחפו אותה ישר כלפי מעלה מעל הראש, תוך יישור מלא של היד.","הורידו את הקטלבל חזרה בין הרגליים וחזרו למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a kettlebell in one hand between your legs.","Bend your knees slightly and hinge at the hips, lowering the kettlebell towards the ground.","Explosively extend your hips and knees, using the momentum to swing the kettlebell up towards your shoulder.","As the kettlebell reaches shoulder height, rotate your hand and punch it straight up overhead, fully extending your arm.","Lower the kettlebell back down between your legs and repeat for the desired number of repetitions."],"mediaId":"aXcUyKb"},{"id":"edb-0543","name":"kettlebell pirate supper legs","name_en":"kettlebell pirate supper legs","muscle":"shoulders","equipment":"kettlebell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים קטלבל ביד אחת.","כופפו מעט את הברכיים והטו את הגוף קדימה במפרקי הירך, תוך שמירה על גב ישר.","הרימו את הקטלבל לגובה הכתף, תוך שמירה על המרפק קרוב לגוף.","שלחו את היד לגמרי מעל הראש, תוך יישור המרפק.","הורידו את הקטלבל חזרה לגובה הכתף, ולאחר מכן חזרו לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Stand with your feet shoulder-width apart, holding a kettlebell in one hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Raise the kettlebell up to shoulder height, keeping your elbow close to your body.","Extend your arm fully overhead, straightening your elbow.","Lower the kettlebell back down to shoulder height, then return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"kuXhl0o"},{"id":"edb-0544","name":"סקוואט עם קטלבל","name_en":"kettlebell pistol squat","muscle":"glutes","equipment":"kettlebell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים קטלבל לפני החזה בשתי הידיים.","הרימו את כף רגל שמאל מהקרקע ושלחו אותה קדימה, תוך שמירה עליה מקבילה לקרקע.","הורידו לאט את הגוף לעמדת סקוואט, תוך שמירה על כף רגל ימין שטוחה על הקרקע ורגל שמאל שלוחה.","עצרו לרגע בתחתית הסקוואט, ולאחר מכן דחפו דרך עקב ימין כדי לחזור לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו רגליים."],"steps_en":["Stand with your feet shoulder-width apart, holding a kettlebell in front of your chest with both hands.","Lift your left foot off the ground and extend it forward, keeping it parallel to the ground.","Slowly lower your body down into a squat position, keeping your right foot flat on the ground and your left leg extended.","Pause for a moment at the bottom of the squat, then push through your right heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"mediaId":"5bpPTHv"},{"id":"edb-0545","name":"שכיבת סמיכה עם קטלבל","name_en":"kettlebell plyo push-up","muscle":"chest","equipment":"kettlebell","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders","core"],"steps":["התחילו בעמדת פלאנק גבוה כשהידיים על הקטלבלים, ברוחב הכתפיים.","הורידו את החזה לכיוון הרצפה, כשהמרפקים צמודים לגוף.","דחפו דרך הידיים באופן נפיץ, תוך הרמת הידיים מהקטלבלים ויישור מלא שלהן.","נחתו ברכות חזרה על הקטלבלים ומיד הורידו את החזה חזרה למטה לחזרה הבאה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a high plank position with your hands on the kettlebells, shoulder-width apart.","Lower your chest towards the ground, keeping your elbows close to your body.","Push through your hands explosively, lifting your hands off the kettlebells and extending your arms fully.","Land softly back on the kettlebells and immediately lower your chest back down for the next repetition.","Repeat for the desired number of repetitions."],"mediaId":"ktf3nvW"},{"id":"edb-0546","name":"לחיצה בישיבה עם קטלבל","name_en":"kettlebell seated press","muscle":"shoulders","equipment":"kettlebell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","core"],"steps":["שבו על ספסל עם גב ישר וכפות רגליים שטוחות על הרצפה.","אחזו קטלבל בכל יד בגובה הכתפיים, כשכפות הידיים פונות קדימה.","דחפו את הקטלבלים מעל הראש, תוך יישור מלא של הידיים.","הורידו את הקטלבלים חזרה לגובה הכתפיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your back straight and feet flat on the ground.","Hold a kettlebell in each hand at shoulder height, palms facing forward.","Press the kettlebells overhead, fully extending your arms.","Lower the kettlebells back to shoulder height.","Repeat for the desired number of repetitions."],"mediaId":"BkxB8LW"},{"id":"edb-1438","name":"לחיצה צבאית בשתי ידיים בישיבה עם קטלבל","name_en":"kettlebell seated two arm military press","muscle":"shoulders","equipment":"kettlebell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["שבו על ספסל עם גב ישר וכפות רגליים שטוחות על הרצפה.","אחזו קטלבל בכל יד בגובה הכתפיים כשכפות הידיים פונות קדימה.","דחפו את הקטלבלים מעל הראש על ידי יישור מלא של הידיים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הקטלבלים חזרה לגובה הכתפיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your back straight and feet flat on the ground.","Hold a kettlebell in each hand at shoulder level with your palms facing forward.","Press the kettlebells overhead by extending your arms fully.","Pause for a moment at the top, then slowly lower the kettlebells back to shoulder level.","Repeat for the desired number of repetitions."],"mediaId":"ZEkjZDi"},{"id":"edb-0547","name":"לחיצה עם קטלבל","name_en":"kettlebell seesaw press","muscle":"shoulders","equipment":"kettlebell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים קטלבל בכל יד בגובה הכתפיים.","דחפו קטלבל אחד מעל הראש תוך שמירה על הקטלבל השני בגובה הכתף.","הורידו את הקטלבל שנדחף חזרה לגובה הכתף, תוך דחיפת הקטלבל השני מעל הראש בו-זמנית.","המשיכו להחליף את תנועת הדחיפה, ויצרו תנועה דמוית נדנדה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder height.","Press one kettlebell overhead while keeping the other kettlebell at shoulder height.","Lower the pressed kettlebell back to shoulder height while simultaneously pressing the other kettlebell overhead.","Continue alternating the pressing motion, creating a seesaw-like movement.","Repeat for the desired number of repetitions."],"mediaId":"UDm6cGl"},{"id":"edb-0548","name":"kettlebell sumo high pull","name_en":"kettlebell sumo high pull","muscle":"back","equipment":"kettlebell","target":"traps","bodyPart":"back","secondaryMuscles":["shoulders","glutes","hamstrings"],"steps":["עמדו עם הרגליים רחבות יותר מרוחב הכתפיים, אצבעות הרגליים פונות החוצה.","אחזו קטלבל בשתי הידיים לפני הגוף, כשהידיים שלוחות כלפי מטה.","כופפו את הברכיים והורידו את הירכיים לעמדת סקוואט, תוך שמירה על הגב ישר.","דחפו דרך העקבים ויישרו באופן נפיץ את הירכיים והברכיים, תוך משיכת הקטלבל כלפי הסנטר.","בעת משיכת הקטלבל למעלה, שמרו על המרפקים גבוהים ורחבים, וכווצו את השכמות זו לזו.","הורידו את הקטלבל חזרה לעמדת ההתחלה וחזרו למספר החזרות הרצוי."],"steps_en":["Stand with your feet wider than shoulder-width apart, toes pointing outwards.","Hold a kettlebell with both hands in front of your body, arms extended downwards.","Bend your knees and lower your hips into a squat position, keeping your back straight.","Drive through your heels and explosively extend your hips and knees, pulling the kettlebell up towards your chin.","As you pull the kettlebell up, keep your elbows high and wide, and squeeze your shoulder blades together.","Lower the kettlebell back down to the starting position and repeat for the desired number of repetitions."],"mediaId":"8ARQ9Hw"},{"id":"edb-0549","name":"kettlebell swing","name_en":"kettlebell swing","muscle":"glutes","equipment":"kettlebell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשהאצבעות מכוונות מעט החוצה.","אחזו את הקטלבל בשתי הידיים לפני הגוף, כשהידיים שלוחות.","כופפו מעט את הברכיים ורכנו במפרק הירך, תוך דחיפת האגן אחורה.","הניפו את הקטלבל אחורה בין הרגליים, תוך שמירה על הידיים ישרות והגב שטוח.","דחפו את הירכיים קדימה והניפו את הקטלבל למעלה לגובה הכתפיים, תוך שימוש בתנופה שנוצרת מהירכיים.","אפשרו לקטלבל להתנדנד חזרה למטה בין הרגליים וחזרו על התנועה למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, toes pointed slightly outward.","Hold the kettlebell with both hands in front of your body, arms extended.","Bend your knees slightly and hinge at the hips, pushing your butt back.","Swing the kettlebell back between your legs, keeping your arms straight and maintaining a flat back.","Drive your hips forward and swing the kettlebell up to shoulder height, using the momentum generated by your hips.","Allow the kettlebell to swing back down between your legs and repeat the movement for the desired number of repetitions."],"mediaId":"UHJlbu3"},{"id":"edb-0550","name":"תראסטר עם קטלבל","name_en":"kettlebell thruster","muscle":"shoulders","equipment":"kettlebell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["quadriceps","glutes","core"],"steps":["התחילו בעמידה עם הרגליים ברוחב הכתפיים, כשאתם אוחזים קטלבל לפני החזה בשתי הידיים, כשכפות הידיים פונות זו לזו.","רדו לעמדת סקוואט על ידי כיפוף הברכיים ודחיפת הירכיים אחורה, תוך שמירה על החזה מורם והגב ישר.","כשאתם מגיעים לתחתית הסקוואט, דחפו באופן נפיץ דרך העקבים כדי לקום, תוך דחיפת הקטלבל מעל הראש בו-זמנית.","נעלו את הידיים בשיא התנועה, תוך יישור מלא של המרפקים.","הורידו את הקטלבל חזרה לעמדת ההתחלה על ידי היפוך התנועה, כיפוף המרפקים והורדת המשקל חזרה לחזה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by standing with your feet shoulder-width apart, holding a kettlebell in front of your chest with both hands, palms facing each other.","Lower into a squat position by bending your knees and pushing your hips back, keeping your chest up and your back straight.","As you reach the bottom of the squat, explosively drive through your heels to stand up, simultaneously pressing the kettlebell overhead.","Lock out your arms at the top of the movement, fully extending your elbows.","Lower the kettlebell back to the starting position by reversing the movement, bending your elbows and lowering the weight back to your chest.","Repeat for the desired number of repetitions."],"mediaId":"yWxMvB5"},{"id":"edb-0551","name":"סקוואט עם קטלבל","name_en":"kettlebell turkish get up (squat style)","muscle":"glutes","equipment":"kettlebell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","core"],"steps":["התחילו בשכיבה על הגב עם הרגליים שלוחות והקטלבל אחוז ביד ימין, כשהיד שלוחה לגמרי מעל הכתף.","כופפו את ברך ימין והניחו את כף רגל ימין שטוחה על הקרקע, תוך שמירה על רגל שמאל שלוחה.","תוך דחיפה דרך כף רגל ימין, הרימו את הירכיים מהקרקע, ועברו לעמדת גשר.","החליקו את רגל שמאל מתחת לגוף, כופפו את ברך שמאל והניחו את כף רגל שמאל שטוחה על הקרקע.","סובבו את פלג הגוף העליון שמאלה, והביאו את יד שמאל לקרקע לתמיכה.","תוך דחיפה דרך כף רגל ימין ויד שמאל, הרימו את פלג הגוף העליון מהקרקע, ועברו לעמדת כריעה.","מעמדת הכריעה, קומו, תוך שמירה על הקטלבל שלוח מעל הראש.","הפכו את התנועה כדי לחזור לעמדת ההתחלה.","חזרו על התרגיל בצד השני, החל עם הקטלבל ביד שמאל."],"steps_en":["Start by lying on your back with your legs extended and the kettlebell held in your right hand, arm fully extended above your shoulder.","Bend your right knee and place your right foot flat on the ground, keeping your left leg extended.","Pressing through your right foot, lift your hips off the ground, coming into a bridge position.","Slide your left leg underneath your body, bending your left knee and placing your left foot flat on the ground.","Rotate your torso to the left, bringing your left hand to the ground for support.","Pressing through your right foot and left hand, lift your torso off the ground, coming into a kneeling position.","From the kneeling position, stand up, keeping the kettlebell extended overhead.","Reverse the movement to return to the starting position.","Repeat the exercise on the other side, starting with the kettlebell in your left hand."],"mediaId":"Ha7SZ3y"},{"id":"edb-0552","name":"קלין בשתי ידיים עם קטלבל","name_en":"kettlebell two arm clean","muscle":"shoulders","equipment":"kettlebell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים קטלבל לפני הירכיים בשתי הידיים, כשכפות הידיים פונות אליכם.","כופפו מעט את הברכיים ורכנו במפרק הירך, תוך הורדת הקטלבל לכיוון הקרקע.","יישרו באופן נפיץ את הירכיים והברכיים, תוך שימוש בתנופה כדי למשוך את הקטלבל כלפי הכתפיים.","כשהקטלבל מגיע לגובה הכתפיים, סובבו את פרקי הידיים ותפסו את הקטלבל בעמדת המנוחה, כשהמרפקים צמודים לגוף והקטלבל נשען על גב האמה.","הורידו את הקטלבל חזרה לעמדת ההתחלה וחזרו למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a kettlebell in front of your thighs with both hands, palms facing towards you.","Bend your knees slightly and hinge at the hips, lowering the kettlebell towards the ground.","Explosively extend your hips and knees, using the momentum to pull the kettlebell up towards your shoulders.","As the kettlebell reaches shoulder height, rotate your wrists and catch the kettlebell in the rack position, with your elbows tucked in and the kettlebell resting on the back of your forearm.","Lower the kettlebell back down to the starting position and repeat for the desired number of repetitions."],"mediaId":"7Ba7bQ2"},{"id":"edb-0553","name":"לחיצה צבאית בשתי ידיים עם קטלבל","name_en":"kettlebell two arm military press","muscle":"shoulders","equipment":"kettlebell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים קטלבל בכל יד בגובה הכתפיים כשכפות הידיים פונות קדימה.","הפעילו את שרירי הליבה ודחפו את הקטלבלים מעל הראש, תוך יישור מלא של הידיים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הקטלבלים חזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a kettlebell in each hand at shoulder level with your palms facing forward.","Engage your core and press the kettlebells overhead, fully extending your arms.","Pause for a moment at the top, then slowly lower the kettlebells back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"blBXysN"},{"id":"edb-1345","name":"חתירה בשתי ידיים עם קטלבל","name_en":"kettlebell two arm row","muscle":"back","equipment":"kettlebell","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, הברכיים כפופות מעט, ואחזו קטלבל בכל יד כשכפות הידיים פונות לגוף.","התכופפו קדימה מהירכיים, תוך שמירה על גב ישר ושרירי ליבה פעילים.","משכו את הקטלבלים כלפי החזה, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הקטלבלים חזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, knees slightly bent, and hold a kettlebell in each hand with your palms facing your body.","Bend forward at the hips, keeping your back straight and your core engaged.","Pull the kettlebells up towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the kettlebells back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"wf24o8S"},{"id":"edb-0554","name":"kettlebell windmill","name_en":"kettlebell windmill","muscle":"core","equipment":"kettlebell","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","shoulders"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים קטלבל ביד ימין מעל הראש.","סובבו את כף רגל שמאל החוצה בכ-45 מעלות ושמרו על כף רגל ימין מכוונת קדימה.","כופפו את פלג הגוף העליון לצד שמאל, תוך שמירה על יד ימין שלוחה מעל הראש והמבט על הקטלבל.","הורידו את פלג הגוף העליון עד כמה שתוכלו תוך שמירה על יד ימין ישרה ויד שמאל שלוחה הצדה.","עצרו לרגע, ולאחר מכן חזרו לעמדת ההתחלה על ידי דחיפה דרך כף רגל ימין והפעלת שרירי הבטן האלכסוניים.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Stand with your feet shoulder-width apart, holding a kettlebell in your right hand overhead.","Rotate your left foot outwards about 45 degrees and keep your right foot pointing forward.","Bend your torso to the left side, keeping your right arm extended overhead and your eyes on the kettlebell.","Lower your torso as far as you can while keeping your right arm straight and your left arm extended to the side.","Pause for a moment, then return to the starting position by pushing through your right foot and engaging your obliques.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"9Tkqa9O"},{"id":"edb-0555","name":"kick out sit","name_en":"kick out sit","muscle":"legs","equipment":"body weight","target":"hamstrings","bodyPart":"upper legs","secondaryMuscles":["quadriceps","glutes"],"steps":["שבו על קצה ספסל או כיסא כשכפות הרגליים שטוחות על הקרקע והברכיים כפופות בזווית של 90 מעלות.","הישענו מעט אחורה והניחו את הידיים על קצה הספסל או הכיסא לתמיכה.","תוך הפעלת שרירי הירך האחוריים, הרימו את כפות הרגליים מהקרקע ושלחו את הרגליים ישר לפניכם.","עצרו לרגע בשיא התנועה, ולאחר מכן כופפו לאט את הברכיים והביאו את כפות הרגליים חזרה לכיוון הגוף.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the edge of a bench or chair with your feet flat on the ground and your knees bent at a 90-degree angle.","Lean back slightly and place your hands on the edge of the bench or chair for support.","Engaging your hamstrings, lift your feet off the ground and extend your legs straight out in front of you.","Pause for a moment at the top, then slowly bend your knees and bring your feet back towards your body.","Repeat for the desired number of repetitions."],"mediaId":"v7p5bYl"},{"id":"edb-0558","name":"kipping muscle up","name_en":"kipping muscle up","muscle":"back","equipment":"body weight","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","triceps","shoulders","core"],"steps":["התחילו בתלייה ממתקן מתח באחיזה עליונה, כשהידיים ברוחב מעט גדול מרוחב הכתפיים.","הפעילו את שרירי הליבה והשתמשו בתנועת נדנוד כדי ליצור תנופה.","בעת התנדנדות קדימה, משכו את החזה לכיוון המוט, תוך שימוש בשרירי הגב הרחבים והביצפס להתחלת התנועה.","המשיכו בתנועה כלפי מעלה עד שהחזה מגיע למוט, ולאחר מכן עברו לעמדת דיפ על ידי דחיפה כלפי מטה על המוט ויישור הידיים.","רדו חזרה לעמדת ההתחלה על ידי כיפוף הידיים ושליטה בירידה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by hanging from a pull-up bar with an overhand grip, hands slightly wider than shoulder-width apart.","Engage your core and use a swinging motion to generate momentum.","As you swing forward, pull your chest towards the bar, using your lats and biceps to initiate the movement.","Continue the upward motion until your chest reaches the bar, then transition into a dip position by pushing down on the bar and extending your arms.","Lower yourself back down to the starting position by bending your arms and controlling the descent.","Repeat for the desired number of repetitions."],"mediaId":"pM07UxU"},{"id":"edb-3640","name":"כפיפת בטן","name_en":"knee touch crunch","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו את הידיים מאחורי הראש כשהמרפקים פונים החוצה.","תוך הפעלת שרירי הבטן, הרימו את השכמות מהקרקע ושלחו את יד ימין לכיוון ברך שמאל.","חזרו לעמדת ההתחלה וחזרו על התרגיל, הפעם תוך הושטת יד שמאל לכיוון ברך ימין.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, lift your shoulder blades off the ground and reach your right hand towards your left knee.","Return to the starting position and repeat, this time reaching your left hand towards your right knee.","Continue alternating sides for the desired number of repetitions."],"mediaId":"dTg95eZ"},{"id":"edb-1420","name":"סקוואט בכריעה","name_en":"kneeling jump squat","muscle":"glutes","equipment":"barbell","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["התחילו בכריעה על הקרקע כשהרגליים ברוחב הירכיים והאצבעות מכוונות קדימה.","אחזו מוט לרוחב הגב העליון, כשהוא נשען על הכתפיים.","הפעילו את שרירי הליבה והישבן, ולאחר מכן קפצו באופן נפיץ לאוויר, תוך יישור הירכיים והברכיים.","בעת הקפיצה, דחפו דרך האצבעות ויישרו לגמרי את הקרסוליים, הברכיים והירכיים.","נחתו ברכות חזרה על הקרקע, תוך כיפוף הברכיים לספיגת הזעזוע.","עברו מיד לחזרה הבאה, תוך חזרה על תנועת קפיצת הסקוואט."],"steps_en":["Start by kneeling on the ground with your feet hip-width apart and your toes pointing forward.","Hold a barbell across your upper back, resting it on your shoulders.","Engage your core and glutes, then explosively jump up into the air, extending your hips and knees.","As you jump, push through your toes and fully extend your ankles, knees, and hips.","Land softly back on the ground, bending your knees to absorb the impact.","Immediately go into the next repetition, repeating the jump squat motion."],"mediaId":"UgDm3oy"},{"id":"edb-1346","name":"מתיחה בכריעה","name_en":"kneeling lat stretch","muscle":"back","equipment":"body weight","target":"lats","bodyPart":"back","secondaryMuscles":["shoulders","triceps"],"steps":["כרעו על הקרקע כשהברכיים ברוחב הירכיים והאצבעות מכוונות אחורה.","שלחו את הידיים מעל הראש ושזרו את האצבעות.","תוך שמירה על הגב ישר, הישענו לאט לצד ימין, והרגישו מתיחה בשריר הגב הרחב השמאלי.","החזיקו את המתיחה 20-30 שניות, ואז חזרו למצב ההתחלתי.","חזרו על המתיחה בצד שמאל, תוך הישענות שמאלה והרגשת מתיחה בשריר הגב הרחב הימני.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Kneel on the ground with your knees hip-width apart and your toes pointing back.","Extend your arms overhead and interlace your fingers.","Keeping your back straight, slowly lean to the right side, feeling a stretch in your left lat muscle.","Hold the stretch for 20-30 seconds, then return to the starting position.","Repeat the stretch on the left side, leaning to the left and feeling a stretch in your right lat muscle.","Continue alternating sides for the desired number of repetitions."],"mediaId":"f38OEuO"},{"id":"edb-3239","name":"פלאנק בכריעה","name_en":"kneeling plank tap shoulder (male)","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["shoulders","triceps"],"steps":["התחילו בעמדת כריעה כשהידיים על הקרקע, ברוחב הכתפיים.","שלחו את הרגליים אחוריכם, תוך הישענות על האצבעות, והרימו את הגוף לעמדת פלאנק.","תוך שמירה על שרירי הליבה מופעלים והירכיים יציבות, הרימו יד אחת מהקרקע והקישו על הכתף הנגדית.","החזירו את היד לקרקע וחזרו עם היד השנייה.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Start in a kneeling position with your hands on the ground, shoulder-width apart.","Extend your legs behind you, resting on your toes, and lift your body into a plank position.","Keeping your core engaged and your hips stable, lift one hand off the ground and tap the opposite shoulder.","Return the hand to the ground and repeat with the other hand.","Continue alternating sides for the desired number of repetitions."],"mediaId":"h1ezqSu"},{"id":"edb-3211","name":"שכיבת סמיכה בכריעה","name_en":"kneeling push-up (male)","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["התחילו בכריעה על הקרקע כשהידיים ברוחב הכתפיים, האצבעות מכוונות קדימה.","שלחו את הרגליים אחוריכם, תוך הישענות על כריות כפות הרגליים, כך שהגוף יוצר קו ישר מהראש ועד העקבים.","הפעילו את שרירי הליבה והורידו את הגוף לכיוון הקרקע על ידי כיפוף המרפקים, תוך שמירה עליהם קרובים לגוף.","המשיכו לרדת עד שהחזה נמצא ממש מעל הקרקע, ולאחר מכן דחפו חזרה למעלה לעמדת ההתחלה על ידי יישור הידיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by kneeling on the ground with your hands shoulder-width apart, fingers pointing forward.","Extend your legs behind you, resting on the balls of your feet, so that your body forms a straight line from head to heels.","Engage your core and lower your body towards the ground by bending your elbows, keeping them close to your sides.","Continue lowering until your chest is just above the ground, then push back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"mediaId":"ZOuKWir"},{"id":"edb-3288","name":"korean dips","name_en":"korean dips","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["התמקמו בין שני מוטות מקבילים כשהידיים שלוחות ותומכות במשקל הגוף.","הורידו את הגוף על ידי כיפוף המרפקים עד שהזרועות העליונות מקבילות לרצפה.","עצרו לרגע, ואז דחפו את עצמכם בחזרה למצב ההתחלתי על ידי יישור הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Position yourself between two parallel bars with your arms extended and supporting your body weight.","Lower your body by bending your elbows until your upper arms are parallel to the ground.","Pause for a moment, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"mediaId":"rWoBmi5"},{"id":"edb-3418","name":"מתח","name_en":"l-pull-up","muscle":"back","equipment":"body weight","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["אחזו במוט המתח באחיזה עליונה, מעט רחב יותר מרוחב הכתפיים.","היתלו כאשר הזרועות ישרות לחלוטין והגוף ישר.","הפעילו את שרירי הגב הרחבים והביצפס כדי למשוך את הגוף כלפי המוט, תוך שמירה על המרפקים קרובים לגוף.","המשיכו למשוך עד שהסנטר מעל המוט.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הגוף בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Grab the pull-up bar with an overhand grip, slightly wider than shoulder-width apart.","Hang with your arms fully extended and your body straight.","Engage your lats and biceps to pull your body up towards the bar, keeping your elbows close to your body.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"d1GgzTU"},{"id":"edb-3419","name":"l-sit on floor","name_en":"l-sit on floor","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שבו על הרצפה כשהרגליים מושטות לפניכם.","הניחו את הידיים על הרצפה לצד הירכיים, כשהאצבעות מכוונות קדימה.","הפעילו את ליבת הגוף והרימו את הרגליים מהרצפה, תוך שמירה עליהן ישרות.","נסו להביא את הרגליים למקביל לרצפה, תוך יצירת צורת 'L' עם הגוף.","החזיקו בעמדה זו כמה שיותר זמן.","הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the floor with your legs extended in front of you.","Place your hands on the floor beside your hips, fingers pointing forward.","Engage your core and lift your legs off the ground, keeping them straight.","Try to bring your legs parallel to the floor, forming an 'L' shape with your body.","Hold this position for as long as you can.","Slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"UpWmA5E"},{"id":"edb-0562","name":"landmine 180","name_en":"landmine 180","muscle":"core","equipment":"barbell","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","quadriceps"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו את המוט בשתי הידיים לפני החזה.","כופפו מעט את הברכיים וסובבו את פלג הגוף העליון ימינה, תוך הנפת המוט כלפי מטה לכיוון הירך הימנית.","כשאתם מגיעים לתחתית התנועה, הפכו במהירות את הכיוון וסובבו את פלג הגוף העליון שמאלה, תוך הנפת המוט למעלה ולרוחב הגוף לכיוון הכתף השמאלית.","המשיכו בתנועת הפיתול הזו, תוך החלפת צדדים, למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold the barbell with both hands in front of your chest.","Bend your knees slightly and rotate your torso to the right, swinging the barbell down towards your right hip.","As you reach the bottom of the movement, quickly reverse the motion and rotate your torso to the left, swinging the barbell up and across your body towards your left shoulder.","Continue this twisting motion, alternating sides, for the desired number of repetitions."],"mediaId":"QYysSLV"},{"id":"edb-3237","name":"הרחקת כתפיים לצדדים","name_en":"landmine lateral raise","muscle":"shoulders","equipment":"barbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","upper back"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","אחזו את המוט באחיזה עליונה, כשהוא נשען על חזית הכתפיים.","תוך שמירה על שרירי הליבה מופעלים והגב ישר, הרימו את המוט למעלה והרחק מהגוף, עד לגובה הכתפיים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and knees slightly bent.","Hold the barbell with an overhand grip, resting it on the front of your shoulders.","Keeping your core engaged and back straight, lift the barbell up and away from your body, raising it to shoulder height.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"eXMFHww"},{"id":"edb-3300","name":"lean planche","name_en":"lean planche","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["shoulders","chest","triceps"],"steps":["התחילו בעמדת שכיבת סמיכה כשהידיים ברוחב הכתפיים והגוף ישר.","הפעילו את שרירי הליבה והעבירו לאט את משקל הגוף קדימה, תוך הבאת הכתפיים מעבר לידיים.","שמרו על המרפקים כפופים מעט והגוף ישר בעת ההטיה קדימה.","החזיקו בעמדה זו למספר שניות, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a push-up position with your hands shoulder-width apart and your body straight.","Engage your core and slowly shift your weight forward, bringing your shoulders past your hands.","Keep your elbows slightly bent and your body straight as you lean forward.","Hold this position for a few seconds, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"LYJodFS"},{"id":"edb-2271","name":"left hook. boxing","name_en":"left hook. boxing","muscle":"shoulders","equipment":"body weight","target":"delts","bodyPart":"shoulders","secondaryMuscles":["biceps","triceps","forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","שמרו על יד שמאל מורמת להגנה על הפנים ויד ימין ליד הסנטר.","סובבו את הירכיים וסובבו על כף רגל שמאל בעת שליחת יד שמאל קדימה בתנועת אגרוף.","פתלו את פלג הגוף העליון והפעילו את שרירי הליבה כדי ליצור כוח באגרוף.","החזירו את היד במהירות לעמדת ההתחלה וחזרו למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your knees slightly bent.","Keep your left hand up to protect your face and your right hand by your chin.","Rotate your hips and pivot on your left foot as you extend your left arm forward in a punching motion.","Twist your torso and engage your core muscles to generate power in the punch.","Snap your arm back to the starting position and repeat for the desired number of repetitions."],"mediaId":"hoXt6wv"},{"id":"edb-0570","name":"leg pull in flat bench","name_en":"leg pull in flat bench","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors","lower back"],"steps":["שבו על ספסל שטוח כשהרגליים שלוחות ישר לפניכם.","הניחו את הידיים על הספסל לצד המותניים לתמיכה.","הפעילו את שרירי הבטן והרימו את הרגליים מהקרקע, תוך הבאת הברכיים לכיוון החזה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a flat bench with your legs extended straight out in front of you.","Place your hands on the bench beside your hips for support.","Engage your abs and lift your legs off the ground, bringing your knees towards your chest.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"OyoZ3Pu"},{"id":"edb-1576","name":"מתיחה","name_en":"leg up hamstring stretch","muscle":"legs","equipment":"body weight","target":"hamstrings","bodyPart":"upper legs","secondaryMuscles":["glutes"],"steps":["שכבו על הגב עם הרגליים שלוחות.","כופפו ברך אחת והביאו אותה לכיוון החזה, תוך אחיזה בירך או בשוק.","יישרו את הרגל עד כמה שניתן תוך שמירה עליה מורמת.","החזיקו את המתיחה במשך 20-30 שניות.","חזרו עם הרגל השנייה."],"steps_en":["Lie flat on your back with your legs extended.","Bend one knee and bring it towards your chest, holding onto your thigh or shin.","Straighten your leg as much as possible while keeping it elevated.","Hold the stretch for 20-30 seconds.","Repeat with the other leg."],"mediaId":"sU5BrfP"},{"id":"edb-2287","name":"לחיצת רגליים לסירוגין","name_en":"lever alternate leg press","muscle":"legs","equipment":"leverage machine","target":"quads","bodyPart":"upper legs","secondaryMuscles":["hamstrings","glutes"],"steps":["כווננו את המושב ואת משטח כפות הרגליים של מכשיר המנוף לעמדה הרצויה.","שבו על המכשיר כשהגב צמוד למשענת וכפות הרגליים על משטח כפות הרגליים.","הניחו את הידיים על הידיות או צידי המכשיר ליציבות.","דחפו כף רגל אחת כנגד משטח כפות הרגליים, תוך יישור הרגל עד שהיא כמעט ישרה לחלוטין.","עצרו לרגע, ולאחר מכן כופפו לאט את הרגל וחזרו לעמדת ההתחלה.","חזרו עם הרגל השנייה.","המשיכו להחליף רגליים למספר החזרות הרצוי."],"steps_en":["Adjust the seat and foot platform of the leverage machine to your desired position.","Sit on the machine with your back against the backrest and your feet on the foot platform.","Place your hands on the handles or sides of the machine for stability.","Push one foot against the foot platform, extending your leg until it is almost fully straight.","Pause for a moment, then slowly bend your leg and return to the starting position.","Repeat with the other leg.","Continue alternating legs for the desired number of repetitions."],"mediaId":"V07qpXy"},{"id":"edb-0571","name":"חתירה בישיבה לסירוגין צר","name_en":"lever alternating narrow grip seated row","muscle":"back","equipment":"leverage machine","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["כווננו את גובה המושב ואת מיקום משטח כפות הרגליים כדי להבטיח יישור נכון.","שבו על המכשיר כשהגב ישר וכפות הרגליים שטוחות על משטח הרגליים.","אחזו בידיות באחיזה צרה, כשכפות הידיים פונות זו לזו.","שמרו על החזה מורם והכתפיים לאחור לאורך כל התרגיל.","משכו ידית אחת לכיוון פלג הגוף העליון תוך שמירה על הידית השנייה ללא תזוזה.","כווצו את השכמות זו לזו בסיום התנועה.","החזירו לאט את הידית לעמדת ההתחלה וחזרו עם הצד השני.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and footplate position to ensure proper alignment.","Sit on the machine with your back straight and feet flat on the footplate.","Grasp the handles with a narrow grip, palms facing each other.","Keep your chest up and shoulders back throughout the exercise.","Pull one handle towards your torso while keeping the other handle stationary.","Squeeze your shoulder blades together at the end of the movement.","Slowly return the handle to the starting position and repeat with the other side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"w2oRpuH"},{"id":"edb-0572","name":"מתח אחיזה תחתית בסיוע","name_en":"lever assisted chin-up","muscle":"back","equipment":"leverage machine","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["כווננו את מכשיר המנוף לרמת ההתנגדות הרצויה.","עמדו על משטח הרגליים ואחזו בידיות באחיזה עליונה, ברוחב מעט גדול מרוחב הכתפיים.","היתלו כשהידיים שלוחות לגמרי, תוך שמירה על הגוף ישר.","הפעילו את שרירי הגב ומשכו את הגוף למעלה לכיוון הידיות, תוך הובלה עם החזה.","המשיכו למשוך עד שהסנטר מעל הידיות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הגוף בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the leverage machine to your desired resistance level.","Stand on the foot platform and grip the handles with an overhand grip, slightly wider than shoulder-width apart.","Hang with your arms fully extended, keeping your body straight.","Engage your back muscles and pull your body up towards the handles, leading with your chest.","Continue pulling until your chin is above the handles.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"MaMuGH6"},{"id":"edb-0573","name":"פשיטת גב","name_en":"lever back extension","muscle":"back","equipment":"leverage machine","target":"spine","bodyPart":"back","secondaryMuscles":["glutes","hamstrings"],"steps":["כווננו את המכשיר כך שיתאים לגודל הגוף וטווח התנועה שלכם.","שבו על המכשיר כשהגב צמוד לכרית וכפות הרגליים מאובטחות.","הניחו את הידיים על הידיות או מוטות האחיזה.","הפעילו את שרירי הליבה והישענו לאט קדימה, תוך אפשור לגב לעגל מעט.","עצרו לרגע בעמדה התחתונה, והרגישו מתיחה בגב התחתון.","באמצעות שרירי הגב, הרימו לאט את פלג הגוף העליון חזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the machine to fit your body size and range of motion.","Sit on the machine with your back against the pad and your feet secured.","Place your hands on the handles or grip bars.","Engage your core and slowly lean forward, allowing your back to round slightly.","Pause for a moment at the bottom position, feeling a stretch in your lower back.","Using your back muscles, slowly raise your torso back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"rUXfn3R"},{"id":"edb-0574","name":"חתירה בהטיה","name_en":"lever bent over row","muscle":"back","equipment":"barbell","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","אחזו במוט באחיזה עליונה, כשהידיים מעט רחבות יותר מרוחב הכתפיים.","התכופפו קדימה מהירכיים, תוך שמירה על גב ישר וחזה מורם.","משכו את המוט לכיוון החלק התחתון של החזה, תוך כיווץ השכמות יחד.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and knees slightly bent.","Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Bend forward at the hips, keeping your back straight and chest up.","Pull the barbell towards your lower chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"X3cqyXz"},{"id":"edb-3200","name":"חתירה בהטיה עם ידית V","name_en":"lever bent-over row with v-bar","muscle":"back","equipment":"leverage machine","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["כווננו את גובה המושב והתמקמו כשאתם פונים אל המכשיר.","אחזו במוט ה-V באחיזה עליונה, תוך שמירה על הגב ישר והברכיים כפופות מעט.","משכו את מוט ה-V לכיוון הבטן, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה, ולאחר מכן שחררו לאט את המשקל חזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself facing the machine.","Grasp the v-bar with an overhand grip, keeping your back straight and your knees slightly bent.","Pull the v-bar towards your abdomen, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly release the weight back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"LuBEORI"},{"id":"edb-0575","name":"כפיפת מרפק","name_en":"lever bicep curl","muscle":"biceps","equipment":"leverage machine","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["כווננו את גובה המושב והתמקמו על המכשיר כשהגב צמוד לכרית.","אחזו בידיות באחיזה תחתונה, כשכפות הידיים פונות כלפי מעלה, ושמרו על המרפקים קרובים לגוף.","נשפו וכופפו את הידיות כלפי מעלה, תוך כיווץ הביצפס.","עצרו לרגע בשיא התנועה, תוך כיווץ שריר הביצפס.","שאפו והורידו את הידיות באיטיות בחזרה לנקודת ההתחלה, תוך יישור מלא של הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself on the machine with your back against the pad.","Grasp the handles with an underhand grip, palms facing up, and keep your elbows close to your sides.","Exhale and curl the handles upward, contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the handles back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"q6y3OhV"},{"id":"edb-2289","name":"לחיצת שוקיים","name_en":"lever calf press","muscle":"legs","equipment":"leverage machine","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings"],"steps":["כווננו את מושב מכשיר המנוף כך שהכתפיים מיושרות עם כרית המנוף.","הניחו את אצבעות הרגליים על כרית המנוף, כשהעקבים תלויים מעבר לקצה.","אחזו בידיות או בתמיכות הצדדיות ליציבות.","דחפו את כרית המנוף למטה על ידי יישור הקרסוליים, תוך כיווץ שרירי השוק.","עצרו לרגע בתחתית התנועה.","חזרו לאט לעמדת ההתחלה על ידי אפשור לעקבים לעלות בחזרה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat of the leverage machine so that your shoulders are aligned with the lever pad.","Place your toes on the lever pad, with your heels hanging off the edge.","Grasp the handles or side supports for stability.","Push the lever pad down by extending your ankles, contracting your calf muscles.","Pause for a moment at the bottom of the movement.","Slowly return to the starting position by allowing your heels to rise back up.","Repeat for the desired number of repetitions."],"mediaId":"7B4F5nZ"},{"id":"edb-0577","name":"לחיצת חזה","name_en":"lever chest press","muscle":"chest","equipment":"leverage machine","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["כווננו את גובה המושב והתמקמו על המכשיר כשהגב שטוח וצמוד לכרית.","אחזו בידיות באחיזה עליונה ומקמו את המרפקים בזווית של 90 מעלות.","דחפו את הידיות קדימה עד שהידיים שלוחות לגמרי, תוך נשיפה במהלך התנועה.","עצרו לרגע קצר בסיום התנועה, ולאחר מכן חזרו לאט לעמדת ההתחלה, תוך שאיפה בעת החזרה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself on the machine with your back flat against the pad.","Grasp the handles with an overhand grip and position your elbows at a 90-degree angle.","Push the handles forward until your arms are fully extended, exhaling during the movement.","Pause briefly at the end of the movement, then slowly return to the starting position, inhaling as you do so.","Repeat for the desired number of repetitions."],"mediaId":"T0yTjgW"},{"id":"edb-0576","name":"לחיצת חזה","name_en":"lever chest press","muscle":"chest","equipment":"leverage machine","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["כווננו את גובה המושב והתמקמו על המכשיר כשהגב שטוח וצמוד לכרית.","אחזו בידיות באחיזה עליונה ומקמו את המרפקים בזווית של 90 מעלות.","דחפו את הידיות קדימה עד שהידיים שלוחות לגמרי, תוך נשיפה במהלך התנועה.","עצרו לרגע קצר בסיום התנועה, ולאחר מכן חזרו לאט לעמדת ההתחלה, תוך שאיפה בעת החזרה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself on the machine with your back flat against the pad.","Grasp the handles with an overhand grip and position your elbows at a 90-degree angle.","Push the handles forward until your arms are fully extended, exhaling during the movement.","Pause briefly at the end of the movement, then slowly return to the starting position, inhaling as you do so.","Repeat for the desired number of repetitions."],"mediaId":"DOoWcnA"},{"id":"edb-0578","name":"דדליפט","name_en":"lever deadlift","muscle":"glutes","equipment":"leverage machine","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps"],"steps":["כווננו את גובה המושב ומשטח כפות הרגליים לעמדה הרצויה.","שבו על המכשיר כשהגב צמוד לכרית וכפות הרגליים שטוחות על משטח כפות הרגליים.","אחזו בידיות או בצידי המושב ליציבות.","הפעילו את שרירי הישבן והירך האחורית, ודחפו דרך העקבים כדי להרים את המשקל.","שמרו על הגב ישר והימנעו מעיגול הכתפיים.","יישרו את הירכיים לגמרי בשיא התנועה, תוך כיווץ שרירי הישבן.","הורידו את המשקל חזרה באופן מבוקר, תוך שמירה על מתח בשרירי הישבן והירך האחורית.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and foot platform to your desired position.","Sit on the machine with your back against the pad and your feet flat on the foot platform.","Grasp the handles or the sides of the seat for stability.","Engage your glutes and hamstrings, and push through your heels to lift the weight up.","Keep your back straight and avoid rounding your shoulders.","Extend your hips fully at the top of the movement, squeezing your glutes.","Lower the weight back down in a controlled manner, keeping tension on your glutes and hamstrings.","Repeat for the desired number of repetitions."],"mediaId":"GUT8I22"},{"id":"edb-1300","name":"לחיצת חזה בשיפוע שלילי","name_en":"lever decline chest press","muscle":"chest","equipment":"leverage machine","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["כווננו את גובה המושב ומשענת הגב של מכשיר המנוף לעמדה נוחה.","שבו על המכשיר כשהגב צמוד למשענת וכפות הרגליים שטוחות על הרצפה.","אחזו בידיות באחיזה עליונה ומקמו את הידיים מעט רחב יותר מרוחב הכתפיים.","דחפו את הידיות קדימה והרחק מהגוף עד שהידיים שלוחות לגמרי.","הורידו לאט את הידיות חזרה לכיוון החזה, תוך שמירה על המרפקים כפופים מעט.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו את הידיות חזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and backrest of the leverage machine to a comfortable position.","Sit on the machine with your back against the backrest and your feet flat on the floor.","Grasp the handles with an overhand grip and position your hands slightly wider than shoulder-width apart.","Push the handles forward and away from your body until your arms are fully extended.","Slowly lower the handles back towards your chest, keeping your elbows slightly bent.","Pause for a moment at the bottom, then push the handles back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"vsVoPHt"},{"id":"edb-1253","name":"הרמת עקבים","name_en":"lever donkey calf raise","muscle":"legs","equipment":"leverage machine","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings","glutes"],"steps":["כווננו את מכשיר המנוף לגובה המתאים לגוף שלכם.","התמקמו כשאתם פונים אל המכשיר, כשאצבעות הרגליים על משטח כפות הרגליים והעקבים תלויים מעבר לקצה.","הניחו את הידיים על הידיות או מוטות התמיכה ליציבות.","הפעילו את שרירי השוק והרימו את העקבים גבוה ככל האפשר, תוך שימוש בכריות כפות הרגליים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקבים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the leverage machine to the appropriate height for your body.","Position yourself facing the machine, with your toes on the foot platform and your heels hanging off the edge.","Place your hands on the handles or the support bars for stability.","Engage your calves and lift your heels as high as possible, using the balls of your feet.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"C9LuR4A"},{"id":"edb-0579","name":"משיכת פולי קדמי","name_en":"lever front pulldown","muscle":"back","equipment":"leverage machine","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","rhomboids","rear deltoids"],"steps":["כווננו את גובה המושב והתמקמו על המכשיר כשהברכיים מתחת לכריות וכפות הרגליים שטוחות על הקרקע.","אחזו בידיות באחיזה עליונה, ברוחב מעט גדול מרוחב הכתפיים.","שבו זקוף כשהחזה מורם והכתפיים לאחור, תוך שמירה על קמרור קל בגב התחתון.","הפעילו את שרירי הגב הרחבים ומשכו את הידיות כלפי מטה לכיוון החזה, תוך כיווץ השכמות זו לזו.","עצרו לרגע בתחתית התנועה, ולאחר מכן שחררו לאט את הידיות חזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself on the machine with your knees under the pads and your feet flat on the ground.","Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.","Sit upright with your chest lifted and your shoulders back, maintaining a slight arch in your lower back.","Engage your lats and pull the handles down towards your chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the handles back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"7F1DVzn"},{"id":"edb-0580","name":"משיכת כתפיים","name_en":"lever gripless shrug","muscle":"back","equipment":"leverage machine","target":"traps","bodyPart":"back","secondaryMuscles":["shoulders","forearms"],"steps":["כווננו את גובה המושב והתמקמו על מכשיר המנוף.","אחזו בידיות כשכפות הידיים פונות פנימה והידיים שלוחות לגמרי.","תוך שמירה על הגב ישר, נשפו והרימו את הכתפיים גבוה ככל האפשר.","החזיקו את הכיווץ לרגע קצר, ולאחר מכן שאפו והורידו לאט את הכתפיים חזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself on the leverage machine.","Grasp the handles with your palms facing inwards and your arms fully extended.","Keeping your back straight, exhale and elevate your shoulders as high as possible.","Hold the contraction for a brief moment, then inhale and slowly lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"f91FwXG"},{"id":"edb-1439","name":"משיכת כתפיים","name_en":"lever gripless shrug v. 2","muscle":"back","equipment":"leverage machine","target":"traps","bodyPart":"back","secondaryMuscles":["shoulders","forearms"],"steps":["כווננו את גובה המושב והתמקמו על המכשיר כשהגב צמוד לכרית.","אחזו בידיות או במוטות באחיזה עליונה, תוך שמירה על הידיים ישרות.","תוך שמירה על הגב ישר, הרימו את הכתפיים לכיוון האוזניים גבוה ככל האפשר.","החזיקו את הכיווץ לרגע, ולאחר מכן הורידו לאט את הכתפיים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself on the machine with your back against the pad.","Grasp the handles or bars with an overhand grip, keeping your arms straight.","Keeping your back straight, lift your shoulders up towards your ears as high as possible.","Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"cbuFJrn"},{"id":"edb-2288","name":"lever gripper hands","name_en":"lever gripper hands","muscle":"biceps","equipment":"leverage machine","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["biceps","triceps"],"steps":["כווננו את גובה המושב ואחזו בידיות של מכשיר המנוף.","שמרו על הגב ישר וכפות הרגליים שטוחות על הקרקע.","נשפו וכווצו את הידיות, תוך כיווץ האמות.","החזיקו את הכיווץ לשנייה אחת, ואז שחררו לאט וחזרו למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and grip the handles of the leverage machine.","Keep your back straight and your feet flat on the ground.","Exhale and squeeze the handles, contracting your forearms.","Hold the contraction for a second, then slowly release and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"mKwcrHn"},{"id":"edb-1615","name":"כפיפת מרפק בכיסא הטפה עם פטיש","name_en":"lever hammer grip preacher curl","muscle":"biceps","equipment":"leverage machine","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["כווננו את גובה המושב והתמקמו על מכשיר המנוף.","הניחו את הזרועות העליונות על משטח הפריצ'ר, כשהחזה צמוד אליו.","אחזו בידיות באחיזת פטיש (כפות הידיים פונות זו לזו).","תוך שמירה על הזרועות העליונות ללא תזוזה, נשפו וכופפו את הידיות כלפי הכתפיים.","עצרו לרגע בשיא התנועה, תוך כיווץ שרירי הביצפס.","שאפו והורידו לאט את הידיות בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself on the leverage machine.","Place your upper arms on the preacher pad, ensuring your chest is pressed against it.","Grasp the handles with a hammer grip (palms facing each other).","Keeping your upper arms stationary, exhale and curl the handles towards your shoulders.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the handles back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"OAguZoG"},{"id":"edb-0581","name":"חתירה גבוה","name_en":"lever high row","muscle":"back","equipment":"leverage machine","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","rear deltoids"],"steps":["כווננו את גובה המושב ואת משטח הרגליים למצב נוח.","שבו על המכשיר כשהחזה צמוד לכרית ורגליכם שטוחות על משטח הרגליים.","אחזו בידיות באחיזה עליונה, ברוחב מעט גדול מרוחב הכתפיים.","שמרו על גב ישר והפעילו את ליבת הגוף.","משכו את הידיות לכיוון הגוף, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה, ולאחר מכן שחררו לאט את הידיות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and foot platform to a comfortable position.","Sit on the machine with your chest against the pad and your feet flat on the foot platform.","Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.","Keep your back straight and engage your core.","Pull the handles towards your body, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"nZZZy9m"},{"id":"edb-2286","name":"פשיטה","name_en":"lever hip extension v. 2","muscle":"glutes","equipment":"leverage machine","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings"],"steps":["כווננו את המכשיר להתאמה לגוף ושבו עליו כשהגב צמוד למשענת.","הניחו את הרגליים על משעני הרגליים ואחזו בידיות לייצוב.","הפעילו את שרירי הישבן והירך האחורית, ואז דחפו כנגד משעני הרגליים כדי ליישר את הירכיים ולהרים את הרגליים אחורה.","עצרו לרגע בשיא התנועה, ואז הורידו לאט את הרגליים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the machine to fit your body and sit on it with your back against the backrest.","Place your feet on the footrests and grip the handles for stability.","Engage your glutes and hamstrings, then push against the footrests to extend your hips and raise your legs backward.","Pause for a moment at the top, then slowly lower your legs back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"OPqShYN"},{"id":"edb-2611","name":"לחיצת רגליים","name_en":"lever horizontal one leg press","muscle":"glutes","equipment":"leverage machine","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["כווננו את מושב המכשיר כך שהברכיים יהיו בזווית של 90 מעלות כשהרגליים על משטח הדריכה.","שבו על המכשיר כשהגב צמוד למשענת והרגליים ברוחב הכתפיים על משטח הדריכה.","הניחו את הידיים על הידיות או צידי המכשיר ליציבות.","דחפו את משטח הדריכה הרחק מהגוף על ידי יישור הרגל, כשהגב נשאר צמוד למשענת.","עצרו לרגע במצב היישור המלא, ואז כופפו לאט את הרגל כדי לחזור למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו רגליים."],"steps_en":["Adjust the seat of the machine so that your knees are at a 90-degree angle when your feet are on the footplate.","Sit on the machine with your back against the backrest and your feet shoulder-width apart on the footplate.","Place your hands on the handles or sides of the machine for stability.","Push the footplate away from your body by extending your leg, keeping your back against the backrest.","Pause for a moment at the fully extended position, then slowly bend your leg to return to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"mediaId":"9KU9TYF"},{"id":"edb-1299","name":"לחיצת חזה בשיפוע","name_en":"lever incline chest press","muscle":"chest","equipment":"leverage machine","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["כווננו את המושב והמשענת של מכשיר המנוף למצב נוח.","שבו על המכשיר כשהגב צמוד למשענת וכפות הרגליים שטוחות על הרצפה.","אחזו בידיות באחיזה עליונה ומקמו את הידיים מעט רחב יותר מרוחב הכתפיים.","דחפו את הידיות קדימה והרחק מהגוף עד שהידיים שלוחות לגמרי.","עצרו לרגע, ואז כופפו לאט את המרפקים והורידו את הידיות בחזרה לכיוון החזה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat and backrest of the leverage machine to a comfortable position.","Sit on the machine with your back against the backrest and your feet flat on the floor.","Grasp the handles with an overhand grip and position your hands slightly wider than shoulder-width apart.","Push the handles forward and away from your body until your arms are fully extended.","Pause for a moment, then slowly bend your elbows and lower the handles back towards your chest.","Repeat for the desired number of repetitions."],"mediaId":"jHAnWmT"},{"id":"edb-1479","name":"לחיצת חזה בשיפוע","name_en":"lever incline chest press v. 2","muscle":"chest","equipment":"leverage machine","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["כווננו את גובה המושב וזווית המשענת במכשיר המנוף למצב נוח.","שבו על המכשיר כשהגב צמוד למשענת וכפות הרגליים שטוחות על הרצפה.","אחזו בידיות באחיזה עליונה ומקמו את הידיים מעט רחב יותר מרוחב הכתפיים.","דחפו את הידיות קדימה והרחק מהגוף עד שהזרועות יהיו ישרות לגמרי, מבלי לנעול את המרפקים.","עצרו לרגע במצב היישור המלא, ואז כופפו לאט את המרפקים והורידו את הידיות בחזרה לכיוון החזה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and backrest angle on the leverage machine to a comfortable position.","Sit on the machine with your back against the backrest and your feet flat on the floor.","Grasp the handles with an overhand grip and position your hands slightly wider than shoulder-width apart.","Push the handles forward and away from your body until your arms are fully extended, but without locking your elbows.","Pause for a moment at the fully extended position, then slowly bend your elbows and lower the handles back towards your chest.","Repeat for the desired number of repetitions."],"mediaId":"o17Jfkt"},{"id":"edb-0582","name":"כפיפת ברך בכריעה","name_en":"lever kneeling leg curl","muscle":"legs","equipment":"leverage machine","target":"hamstrings","bodyPart":"upper legs","secondaryMuscles":["glutes"],"steps":["כווננו את המכשיר להתאמה לגוף ובחרו את המשקל הרצוי.","כרעו על המכשיר כשפניכם למטה, הברכיים נשענות על הכרית והרגליים מקובעות מתחת למשעני כף הרגל.","אחזו בידיות או בצדי המכשיר לייצוב.","תוך שמירה על פלג הגוף העליון קבוע, נשפו וכופפו את הרגליים כלפי מעלה לכיוון הישבן על ידי כיפוף הברכיים.","עצרו לרגע בשיא התנועה, תוך כיווץ שרירי הירך האחוריים.","שאפו והורידו לאט את הרגליים בחזרה למצב ההתחלתי, תוך יישור מלא של הברכיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the machine to fit your body and select the desired weight.","Kneel on the machine facing downwards, with your knees resting on the pad and your feet secured under the footpads.","Grasp the handles or the sides of the machine for stability.","Keeping your upper body stationary, exhale and curl your legs up towards your glutes by flexing your knees.","Pause for a moment at the top of the movement, squeezing your hamstrings.","Inhale and slowly lower your legs back to the starting position, fully extending your knees.","Repeat for the desired number of repetitions."],"mediaId":"nnmCTLN"},{"id":"edb-0583","name":"פיתול בכריעה","name_en":"lever kneeling twist","muscle":"core","equipment":"leverage machine","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","lower back"],"steps":["כווננו את גובה המושב והתמקמו על המכשיר כשהברכיים נשענות על הכריות והגו העליון פונה קדימה.","אחזו בידיות או בצדי המכשיר לייצוב.","תוך שמירה על שרירי הליבה מכווצים, סובבו את הגו הצידה עד כמה שנוח.","עצרו לרגע, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו על הסיבוב לצד הנגדי.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself on the machine with your knees resting on the pads and your upper body facing forward.","Grasp the handles or the sides of the machine for stability.","Keeping your core engaged, twist your torso to one side as far as comfortably possible.","Pause for a moment, then slowly return to the starting position.","Repeat the twist to the opposite side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"sZOR9EV"},{"id":"edb-0584","name":"הרחקת כתפיים לצדדים","name_en":"lever lateral raise","muscle":"shoulders","equipment":"leverage machine","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","upper back"],"steps":["כווננו את גובה המושב והתמקמו על המכשיר כשהגב צמוד לכרית.","אחזו בידיות באחיזת יד עליונה ושמרו על הזרועות ישרות.","נשפו והרימו את הזרועות הצידה עד שיהיו מקבילות לרצפה.","עצרו לרגע בשיא התנועה, ואז שאפו והורידו לאט את הזרועות בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself on the machine with your back against the pad.","Grasp the handles with an overhand grip and keep your arms straight.","Exhale and raise your arms out to the sides until they are parallel to the floor.","Pause for a moment at the top, then inhale and slowly lower your arms back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"dRTfGZT"},{"id":"edb-0585","name":"פשיטת ברך","name_en":"lever leg extension","muscle":"legs","equipment":"leverage machine","target":"quads","bodyPart":"upper legs","secondaryMuscles":["hamstrings"],"steps":["כווננו את גובה המושב ומשענת הגב של המכשיר להתאמה לגוף.","שבו על המכשיר כשהגב צמוד למשענת והרגליים על משטח כף הרגל.","אחזו בידיות או במוטות הצד לייצוב.","יישרו את הרגליים קדימה על ידי פשיטת הברכיים, תוך הרמת המשקל.","עצרו לרגע בשיא התנועה, ואז הורידו לאט את המשקל בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and backrest of the machine to fit your body.","Sit on the machine with your back against the backrest and your feet on the footpad.","Grasp the handles or sidebars for stability.","Extend your legs forward by straightening your knees, lifting the weight.","Pause for a moment at the top, then slowly lower the weight back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"my33uHU"},{"id":"edb-0586","name":"כפיפת ברך","name_en":"lever lying leg curl","muscle":"legs","equipment":"leverage machine","target":"hamstrings","bodyPart":"upper legs","secondaryMuscles":["calves"],"steps":["כווננו את המכשיר להתאמה לגוף ובחרו את המשקל הרצוי.","שכבו על הבטן על המכשיר כשהרגליים ישרות והעקבים צמודים למנוף המרופד.","אחזו בידיות או בצדי המכשיר לייצוב.","תוך שמירה על הגו העליון ללא תזוזה, נשפו וכופפו את הרגליים כלפי מעלה עד כמה שניתן מבלי להרים את הירכיים מהכרית.","החזיקו את מצב הכיווץ לרגע קצר תוך כדי לחיצת שרירי הירך האחורית.","שאפו והורידו לאט את המנוף בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the machine to fit your body and select the desired weight.","Lie face down on the machine with your legs straight and your heels against the padded lever.","Grasp the handles or the sides of the machine for stability.","Keeping your upper body stationary, exhale and curl your legs up as far as possible without lifting your hips off the pad.","Hold the contracted position for a brief pause as you squeeze your hamstrings.","Inhale and slowly lower the lever back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"17lJ1kr"},{"id":"edb-3195","name":"כפיפת ברך בשכיבה","name_en":"lever lying two-one leg curl","muscle":"legs","equipment":"leverage machine","target":"hamstrings","bodyPart":"upper legs","secondaryMuscles":["glutes"],"steps":["כווננו את המכשיר להתאמה לגוף ושבו עליו כשהגב צמוד למשענת.","הניחו את הרגליים על כרית המנוף, ממש מעל הקרסוליים.","אחזו בידיות בצדי המכשיר לתמיכה.","תוך שמירה על הגו העליון קבוע, נשפו וכופפו את הרגליים כלפי הישבן.","עצרו לרגע בשיא התנועה, ואז שאפו והורידו לאט את הרגליים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the machine to fit your body and sit on it with your back against the backrest.","Place your legs on the lever pad, just above your ankles.","Grasp the handles on the sides of the machine for support.","Keeping your upper body still, exhale and curl your legs up towards your glutes.","Pause for a moment at the top, then inhale and slowly lower your legs back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"UXpKJoq"},{"id":"edb-0587","name":"לחיצה צבאית","name_en":"lever military press","muscle":"shoulders","equipment":"leverage machine","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper chest"],"steps":["כווננו את גובה המושב והתמקמו על המכשיר כשהגב צמוד למשענת.","אחזו בידיות באחיזה עליונה ומקמו את הידיים מעט רחב יותר מרוחב הכתפיים.","דחפו את הידיות כלפי מעלה עד שהזרועות ישרות לגמרי, אך אל תנעלו את המרפקים.","עצרו לרגע בשיא התנועה, ואז הורידו לאט את הידיות בחזרה למטה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself on the machine with your back against the backrest.","Grasp the handles with an overhand grip and position your hands slightly wider than shoulder-width apart.","Push the handles upward until your arms are fully extended, but do not lock your elbows.","Pause for a moment at the top, then slowly lower the handles back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"CggQhII"},{"id":"edb-0588","name":"חתירה בישיבה צר","name_en":"lever narrow grip seated row","muscle":"back","equipment":"leverage machine","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["כווננו את גובה המושב ומשעני הרגליים כדי להבטיח תנוחה נכונה.","שבו על המכונה כשכפות הרגליים שטוחות על משעני הרגליים והברכיים כפופות מעט.","אחזו בידיות באחיזה צרה, כשכפות הידיים פונות זו לזו.","שמרו על הגב ישר והטו את הגוף מעט קדימה.","משכו את הידיות לכיוון הגו, תוך לחיצת השכמות זו לזו.","עצרו לרגע בשיא התנועה.","שחררו לאט את הידיות וחזרו למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and footrests to ensure proper form.","Sit on the machine with your feet flat on the footrests and your knees slightly bent.","Grasp the handles with a narrow grip, palms facing each other.","Keep your back straight and lean slightly forward.","Pull the handles towards your torso, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement.","Slowly release the handles and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"IGjKj1v"},{"id":"edb-0589","name":"חתירה בהטיה ביד אחת","name_en":"lever one arm bent over row","muscle":"back","equipment":"barbell","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, הברכיים כפופות מעט, ואחזו במוט באחיזת יד עליונה.","הרכינו את הגוף קדימה מהירכיים, תוך שמירה על הגב ישר והראש מורם.","תנו למוט לתלות לפניכם כשהזרועות ישרות לגמרי.","משכו את המוט כלפי מעלה לכיוון החזה, תוך שמירה על המרפקים קרובים לגוף.","כווצו את השכמות זו לזו בשיא התנועה.","הורידו את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, knees slightly bent, and hold a barbell with an overhand grip.","Bend forward at the hips, keeping your back straight and your head up.","Let the barbell hang in front of you with your arms fully extended.","Pull the barbell up towards your chest, keeping your elbows close to your body.","Squeeze your shoulder blades together at the top of the movement.","Lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Fhdtwf3"},{"id":"edb-1356","name":"חתירה ביד אחת לצדדים גבוה","name_en":"lever one arm lateral high row","muscle":"back","equipment":"leverage machine","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","shoulders"],"steps":["כווננו את גובה המושב והתמקמו כשאתם פונים אל המכשיר.","אחזו בידית ביד אחת ושמרו על הגב ישר.","משכו את הידית לכיוון הגוף, תוך שמירה על המרפק קרוב לצד הגוף.","כווצו את שרירי הגב בקצה העליון של התנועה.","שחררו את הידית לאט חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself facing the machine.","Grasp the handle with one hand and keep your back straight.","Pull the handle towards your body, keeping your elbow close to your side.","Squeeze your back muscles at the top of the movement.","Slowly release the handle back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"OIFMAp1"},{"id":"edb-1347","name":"משיכת פולי ביד אחת רחב לצדדים","name_en":"lever one arm lateral wide pulldown","muscle":"back","equipment":"leverage machine","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","rhomboids","rear deltoids"],"steps":["כווננו את גובה המושב והתמקמו על המכשיר כשהחזה צמוד לכרית והרגליים שטוחות על הרצפה.","אחזו בידית באחיזת יד עליונה ויישרו את הזרוע לגמרי, עם כיפוף קל במרפק.","משכו את הידית מטה ולרוחב הגוף לכיוון הירך הנגדית, תוך לחיצת שריר ה'לאט' בתחתית התנועה.","החזירו לאט את הידית למצב ההתחלתי, תוך יישור מלא של הזרוע.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Adjust the seat height and position yourself on the machine with your chest against the pad and your feet flat on the floor.","Grasp the handle with an overhand grip and fully extend your arm, keeping a slight bend in your elbow.","Pull the handle down and across your body towards your opposite hip, squeezing your lat muscle at the bottom of the movement.","Slowly return the handle to the starting position, fully extending your arm.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"tTuZSDT"},{"id":"edb-0590","name":"לחיצת כתפיים ביד אחת","name_en":"lever one arm shoulder press","muscle":"shoulders","equipment":"leverage machine","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["כווננו את גובה המושב והתמקמו על המכשיר כשהגב צמוד לכרית.","אחזו בידית המנוף ביד אחת ומקמו את המרפק בזווית של 90 מעלות.","דחפו את המנוף כלפי מעלה עד שהזרוע ישרה לגמרי מעל הראש.","עצרו לרגע בשיא התנועה, ואז הורידו לאט את המנוף בחזרה למטה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ליד השנייה."],"steps_en":["Adjust the seat height and position yourself on the machine with your back against the pad.","Grasp the lever handle with one hand and position your elbow at a 90-degree angle.","Press the lever upward until your arm is fully extended overhead.","Pause for a moment at the top, then slowly lower the lever back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"mediaId":"2KGnL6M"},{"id":"edb-0591","name":"מקבילים","name_en":"lever overhand triceps dip","muscle":"triceps","equipment":"leverage machine","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["כווננו את המכשיר לגובה המתאים וקבעו את הגוף בתנוחה.","אחזו בידיות באחיזת יד עליונה ומקמו את הגוף כך שהזרועות ישרות לגמרי.","הורידו את הגוף על ידי כיפוף המרפקים, תוך שמירה על הזרועות העליונות קרובות לצדדים.","המשיכו להוריד עד שהזרועות העליונות מקבילות לרצפה.","עצרו לרגע, ואז דחפו את עצמכם בחזרה למעלה למצב ההתחלתי על ידי יישור המרפקים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the machine to the appropriate height and secure your body in position.","Grasp the handles with an overhand grip and position your body so that your arms are fully extended.","Lower your body by bending your elbows, keeping your upper arms close to your sides.","Continue lowering until your upper arms are parallel to the floor.","Pause for a moment, then push yourself back up to the starting position by extending your elbows.","Repeat for the desired number of repetitions."],"mediaId":"D5yqP2p"},{"id":"edb-0592","name":"כפיפת מרפק בכיסא הטפה","name_en":"lever preacher curl","muscle":"biceps","equipment":"leverage machine","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["כווננו את גובה המושב והתמקמו על מכשיר המנוף.","הניחו את הזרועות העליונות על הכרית ואחזו בידיות באחיזת יד תחתונה.","שמרו על הגב ישר והמרפקים ממוקמים על הכרית.","נשפו וכופפו את האמות כלפי הזרועות העליונות, תוך כיווץ שרירי הביצפס.","עצרו לרגע בשיא התנועה, תוך כיווץ שריר הביצפס.","שאפו והורידו לאט את הידיות בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself on the leverage machine.","Place your upper arms on the pad and grip the handles with an underhand grip.","Keep your back straight and your elbows positioned on the pad.","Exhale and curl your forearms towards your upper arms, contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the handles back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"b6hQYMb"},{"id":"edb-1614","name":"כפיפת מרפק בכיסא הטפה","name_en":"lever preacher curl v. 2","muscle":"biceps","equipment":"leverage machine","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["כווננו את גובה המושב והתמקמו על המכשיר כשהזרועות העליונות נשענות על הכרית והחזה צמוד לתמיכה.","אחזו בידיות באחיזת יד תחתונה, ברוחב מעט גדול מרוחב הכתפיים.","שמרו על הזרועות העליונות ללא תזוזה ונשפו תוך כיפוף הידיות כלפי הכתפיים, תוך כיווץ הביצפס.","עצרו לרגע בשיא התנועה, תוך כיווץ שריר הביצפס.","שאפו תוך הורדה לאטה של הידיות בחזרה למצב ההתחלתי, עם יישור מלא של הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself on the machine with your upper arms resting on the pad and your chest against the support.","Grasp the handles with an underhand grip, slightly wider than shoulder-width apart.","Keep your upper arms stationary and exhale as you curl the handles towards your shoulders, contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale as you slowly lower the handles back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"ye84CTU"},{"id":"edb-2285","name":"פולאובר","name_en":"lever pullover","muscle":"back","equipment":"leverage machine","target":"lats","bodyPart":"back","secondaryMuscles":["triceps","shoulders"],"steps":["כווננו את המושב והידיות של מכשיר המנוף למצב נוח.","שבו על המכשיר כשהגב צמוד לכרית ואחזו בידיות באחיזת יד עליונה.","שמרו על הזרועות כפופות מעט ועל שרירי הליבה מכווצים.","משכו לאט את הידיות לכיוון החזה, תוך לחיצת שרירי ה'לאט'.","עצרו לרגע בשיא הכיווץ, ואז חזרו לאט למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat and handles of the leverage machine to a comfortable position.","Sit on the machine with your back against the pad and grasp the handles with an overhand grip.","Keep your arms slightly bent and your core engaged.","Slowly pull the handles towards your chest, squeezing your lats.","Pause for a moment at the peak contraction, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"4U7iLb5"},{"id":"edb-2736","name":"משיכת פולי אחיזה הפוכה לצדדים","name_en":"lever reverse grip lateral pulldown","muscle":"back","equipment":"leverage machine","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","rhomboids","rear deltoids"],"steps":["כווננו את גובה המושב והתמקמו על המכשיר כשהברכיים מתחת לכריות וכפות הרגליים שטוחות על הקרקע.","אחזו בידיות באחיזה עליונה, ברוחב מעט גדול מרוחב הכתפיים.","שבו בישיבה זקופה עם החזה קדימה והכתפיים לאחור, תוך שמירה על קשת קלה בגב התחתון.","משכו את הידיות מטה לכיוון החזה, תוך הובלה עם המרפקים ולחיצת השכמות זו לזו.","עצרו לרגע בתחתית התנועה, ולאחר מכן שחררו לאט את הידיות חזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself on the machine with your knees under the pads and your feet flat on the ground.","Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.","Sit upright with your chest out and shoulders back, maintaining a slight arch in your lower back.","Pull the handles down towards your chest, leading with your elbows and squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the handles back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ky8FLU8"},{"id":"edb-1616","name":"כפיפת מרפק בכיסא הטפה אחיזה הפוכה","name_en":"lever reverse grip preacher curl","muscle":"biceps","equipment":"leverage machine","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["כווננו את גובה המושב והתמקמו על מכשיר המנוף.","אחזו בידיות באחיזת יד תחתונה, כשכפות הידיים פונות כלפי מעלה.","הניחו את הזרועות העליונות על משטח הפריצ'ר, תוך יישור מלא של המרפקים.","תוך שמירה על הזרועות העליונות ללא תזוזה, נשפו וכופפו את הידיות כלפי הכתפיים.","עצרו לרגע בשיא התנועה, תוך כיווץ שריר הביצפס.","שאפו והורידו את הידיות באיטיות בחזרה לנקודת ההתחלה, תוך יישור מלא של המרפקים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself on the leverage machine.","Grasp the handles with an underhand grip, palms facing up.","Rest your upper arms on the preacher pad, ensuring your elbows are fully extended.","Keeping your upper arms stationary, exhale and curl the handles towards your shoulders.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the handles back to the starting position, fully extending your elbows.","Repeat for the desired number of repetitions."],"mediaId":"kj3hy6W"},{"id":"edb-1348","name":"חתירה אחיזה הפוכה","name_en":"lever reverse grip vertical row","muscle":"back","equipment":"leverage machine","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["כווננו את גובה המושב ואת מיקום משטח כפות הרגליים כדי להבטיח יישור נכון.","שבו על המכשיר כשהחזה צמוד לכרית והרגליים שטוחות על משטח הדריכה.","אחזו בידיות באחיזת יד תחתונה, כשכפות הידיים פונות כלפי מעלה.","שמרו על גב ישר והפעילו את ליבת הגוף.","משכו את הידיות לכיוון החזה, תוך לחיצת השכמות זו לזו.","עצרו לרגע בשיא התנועה, ואז שחררו לאט ויישרו את הזרועות בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and footplate position to ensure proper alignment.","Sit on the machine with your chest against the pad and your feet flat on the footplate.","Grasp the handles with an underhand grip, palms facing up.","Keep your back straight and engage your core.","Pull the handles towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly release and extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ZqNOWQ6"},{"id":"edb-0593","name":"פשיטת גב הפוך","name_en":"lever reverse hyperextension","muscle":"glutes","equipment":"leverage machine","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","lower back"],"steps":["כווננו את מכשיר המנוף להתאמה לגוף וקבעו את הרגליים במשעני כף הרגל.","שכבו על הבטן על המכשיר כשהגו העליון תלוי מעבר לקצה והירכיים נשענות על הכרית.","שלבו את הזרועות על החזה או הניחו אותן מאחורי הראש.","הפעילו את שרירי הישבן והירך האחורית כדי להרים את הרגליים כלפי מעלה עד שיהיו מקבילות לרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the leverage machine to fit your body and secure your feet in the foot pads.","Lie face down on the machine with your upper body hanging off the edge and your hips resting on the pad.","Cross your arms over your chest or place them behind your head.","Engage your glutes and hamstrings to lift your legs upward until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Krmb3cB"},{"id":"edb-1349","name":"חתירה הפוך","name_en":"lever reverse t-bar row","muscle":"back","equipment":"leverage machine","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["כווננו את גובה המושב ומיקום משטח הדריכה במכשיר המנוף.","שבו על המכשיר כשהחזה צמוד לכרית והרגליים שטוחות על משטח הדריכה.","אחזו בידיות באחיזה עליונה, ברוחב מעט גדול מרוחב הכתפיים.","שמרו על גב ישר והפעילו את ליבת הגוף.","משכו את הידיות לכיוון החזה, תוך לחיצת השכמות זו לזו.","עצרו לרגע בשיא התנועה, ואז שחררו לאט ויישרו את הזרועות בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and footplate position on the leverage machine.","Sit on the machine with your chest against the pad and your feet flat on the footplate.","Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.","Keep your back straight and engage your core.","Pull the handles towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly release and extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"BgljGjd"},{"id":"edb-2315","name":"lever rotary calf","name_en":"lever rotary calf","muscle":"legs","equipment":"leverage machine","target":"calves","bodyPart":"lower legs","secondaryMuscles":["soleus","ankle stabilizers"],"steps":["כווננו את גובה המושב כך שהברכיים כפופות מעט והרגליים שטוחות על משטח הדריכה.","הניחו את קצות האצבעות על משטח הדריכה, כשהעקבים תלויים מעבר לקצה.","אחזו בידיות או בצדי המכשיר לייצוב.","דחפו דרך כריות כפות הרגליים והרימו את העקבים גבוה ככל האפשר.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקבים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height so that your knees are slightly bent and your feet are flat on the footplate.","Place your toes on the footplate, with your heels hanging off the edge.","Grasp the handles or the sides of the machine for stability.","Push through the balls of your feet, raising your heels as high as possible.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"MrgP9L6"},{"id":"edb-2335","name":"לחיצת שוקיים בישיבה","name_en":"lever seated calf press","muscle":"legs","equipment":"leverage machine","target":"calves","bodyPart":"lower legs","secondaryMuscles":["soleus","hamstrings"],"steps":["כווננו את מושב המכשיר כך שהכתפיים יהיו מיושרות עם כרית המנוף.","הניחו את קצות האצבעות בחלק התחתון של המשטח ומקמו את הברכיים מתחת לכרית המנוף.","אחזו בידיות בצדי המושב לייצוב.","דחפו את כרית המנוף מטה על ידי יישור הקרסוליים, תוך הרמת העקבים גבוה ככל האפשר.","עצרו לרגע בשיא התנועה, ואז הורידו לאט את העקבים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat of the machine so that your shoulders are aligned with the lever pad.","Place your toes on the lower portion of the platform and position your knees under the lever pad.","Grasp the handles on the sides of the seat for stability.","Press the lever pad down by extending your ankles, lifting your heels as high as possible.","Pause for a moment at the top of the movement, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Ie9UGty"},{"id":"edb-0594","name":"הרמת עקבים בישיבה","name_en":"lever seated calf raise","muscle":"legs","equipment":"leverage machine","target":"calves","bodyPart":"lower legs","secondaryMuscles":["soleus","ankle stabilizers"],"steps":["כווננו את גובה המושב כך שהברכיים כפופות מעט והרגליים שטוחות על משטח הדריכה.","הניחו את קצות האצבעות על משטח הדריכה כשהעקבים תלויים מעבר לקצה.","אחזו בידיות או בצידי המושב ליציבות.","דחפו דרך כריות כפות הרגליים כדי להרים את העקבים גבוה ככל האפשר.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקבים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height so that your knees are slightly bent and your feet are flat on the footplate.","Place your toes on the footplate with your heels hanging off the edge.","Grasp the handles or the sides of the seat for stability.","Push through the balls of your feet to raise your heels as high as possible.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"bOOdeyc"},{"id":"edb-1452","name":"כפיפת בטן בישיבה","name_en":"lever seated crunch","muscle":"core","equipment":"leverage machine","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques"],"steps":["שבו על מכשיר המנוף כשהגב צמוד לכרית והרגליים שטוחות על הרצפה.","אחזו בידיות או הניחו את הידיים על כריות הצד לתמיכה.","הפעילו את שרירי הבטן והטו לאט את הגוף אחורה, תוך שהכרית נעה יחד איתכם.","כשהגו העליון מגיע לזווית של 45 מעלות, כווצו את שרירי הבטן והתכופפו קדימה, תוך קירוב החזה לברכיים.","עצרו לרגע בשיא התנועה, ואז שחררו לאט וחזרו למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the leverage machine with your back against the pad and your feet flat on the floor.","Grasp the handles or place your hands on the side pads for support.","Engage your abs and slowly lean back, allowing the pad to move with you.","Once your upper body is at a 45-degree angle, contract your abs and crunch forward, bringing your chest towards your knees.","Pause for a moment at the top, then slowly release and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Wgaz7pm"},{"id":"edb-0595","name":"כפיפת בטן בישיבה","name_en":"lever seated crunch (chest pad)","muscle":"core","equipment":"leverage machine","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques"],"steps":["כווננו את גובה המושב ומיקום כרית החזה לפי הנוחות שלכם.","שבו על המכשיר כשהגב צמוד לכרית החזה והרגליים שטוחות על הרצפה.","אחזו בידיות או במוטות הצד לייצוב.","הפעילו את שרירי הבטן והטו לאט את הגוף אחורה, תוך שכרית החזה נעה יחד איתכם.","עצרו לרגע בשיא הכיווץ, תוך תחושת המתח בשרירי הבטן.","חזרו לאט למצב ההתחלתי על ידי כיווץ שרירי הבטן ומשיכת עצמכם למעלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and chest pad position according to your comfort.","Sit on the machine with your back against the chest pad and your feet flat on the floor.","Grasp the handles or side bars for stability.","Engage your abs and slowly lean back, allowing the chest pad to move with you.","Pause for a moment at the maximum contraction, feeling the tension in your abs.","Slowly return to the starting position by contracting your abs and pulling yourself back up.","Repeat for the desired number of repetitions."],"mediaId":"ZnJHhMk"},{"id":"edb-3760","name":"כפיפת בטן בישיבה","name_en":"lever seated crunch v. 2","muscle":"core","equipment":"leverage machine","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","hip flexors"],"steps":["שבו על מכשיר המנוף כשהגב צמוד לכרית והרגליים מקובעות מתחת למשעני כף הרגל.","הניחו את הידיים על הידיות או בצדי המושב לתמיכה.","הפעילו את שרירי הבטן והתכופפו לאט קדימה, תוך קירוב החזה לברכיים.","עצרו לרגע בשיא התנועה, תוך כיווץ שרירי הבטן.","חזרו לאט למצב ההתחלתי, תוך אפשרות לגב להתעגל מעט.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the leverage machine with your back against the pad and your feet secured under the footpads.","Place your hands on the handles or the sides of the seat for support.","Engage your abs and slowly crunch forward, bringing your chest towards your knees.","Pause for a moment at the top of the movement, squeezing your abs.","Slowly return to the starting position, allowing your back to round slightly.","Repeat for the desired number of repetitions."],"mediaId":"eXFXCY0"},{"id":"edb-1451","name":"מקבילים בישיבה","name_en":"lever seated dip","muscle":"triceps","equipment":"leverage machine","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["כווננו את גובה המושב כך שהרגליים שטוחות על הרצפה והברכיים בזווית של 90 מעלות.","אחזו בידיות מכשיר המנוף כשכפות הידיים פונות מטה והזרועות ישרות לגמרי.","הורידו לאט את הגוף על ידי כיפוף המרפקים עד שהזרועות העליונות מקבילות לרצפה.","עצרו לרגע, ואז דחפו את עצמכם בחזרה למצב ההתחלתי על ידי יישור הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height so that your feet are flat on the ground and your knees are at a 90-degree angle.","Grasp the handles of the leverage machine with your palms facing down and your arms fully extended.","Slowly lower your body by bending your elbows until your upper arms are parallel to the ground.","Pause for a moment, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"mediaId":"BRImeP8"},{"id":"edb-0596","name":"פרפר במכונה","name_en":"lever seated fly","muscle":"chest","equipment":"leverage machine","target":"pectorals","bodyPart":"chest","secondaryMuscles":["deltoids","trapezius"],"steps":["כווננו את גובה המושב והתמקמו על המכשיר כשהגב צמוד לכרית.","אחזו בידיות באחיזה פרונטית ושמרו על המרפקים כפופים מעט.","נשפו ודחפו את הידיות קדימה, תוך קירובן זו לזו מול החזה.","עצרו לרגע, תוך לחיצת שרירי החזה.","שאפו וחזרו לאט למצב ההתחלתי, תוך אפשרות לשרירי החזה להימתח.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself on the machine with your back against the pad.","Grasp the handles with a pronated grip and keep your elbows slightly bent.","Exhale and push the handles forward, bringing them together in front of your chest.","Pause for a moment, squeezing your chest muscles.","Inhale and slowly return to the starting position, allowing your chest muscles to stretch.","Repeat for the desired number of repetitions."],"mediaId":"v3xmPAR"},{"id":"edb-3759","name":"גוד מורנינג בישיבה","name_en":"lever seated good morning","muscle":"glutes","equipment":"leverage machine","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","lower back"],"steps":["כווננו את גובה המושב כך שהירכיים גבוהות מעט מהברכיים.","שבו על המכשיר כשהגב צמוד לכרית והרגליים שטוחות על משעני הרגליים.","אחזו בידיות או בצידי המושב ליציבות.","תוך שמירה על הגב ישר, הרכינו לאט את הגוף קדימה מהירכיים עד שהגו העליון מקביל לרצפה.","עצרו לרגע, ואז חזרו לאט למצב ההתחלתי על ידי דחיפה דרך שרירי הישבן והירך האחורית.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height so that your hips are slightly higher than your knees.","Sit on the machine with your back against the pad and your feet flat on the footrests.","Grasp the handles or the sides of the seat for stability.","Keeping your back straight, slowly lean forward from your hips until your upper body is parallel to the ground.","Pause for a moment, then slowly return to the starting position by pushing through your glutes and hamstrings.","Repeat for the desired number of repetitions."],"mediaId":"XsCcxCC"},{"id":"edb-0597","name":"lever seated hip abduction","name_en":"lever seated hip abduction","muscle":"glutes","equipment":"leverage machine","target":"abductors","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings"],"steps":["כווננו את גובה המושב כך שהברכיים בזווית של 90 מעלות.","שבו על המכשיר כשהגב צמוד למשענת והרגליים על משעני הרגליים.","הניחו את הידיים על ידיות הצד לייצוב.","הפעילו את שרירי החטיפה והפרידו לאט את הרגליים, הרחק מקו האמצע של הגוף.","עצרו לרגע בסוף התנועה, ואז החזירו לאט את הרגליים יחד למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height so that your knees are at a 90-degree angle.","Sit on the machine with your back against the backrest and your feet on the footrests.","Place your hands on the side handles for stability.","Engage your abductors and slowly push your legs apart, away from the midline of your body.","Pause for a moment at the end of the movement, then slowly bring your legs back together to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"CHpahtl"},{"id":"edb-0598","name":"lever seated hip adduction","name_en":"lever seated hip adduction","muscle":"legs","equipment":"leverage machine","target":"adductors","bodyPart":"upper legs","secondaryMuscles":["hamstrings","glutes"],"steps":["כווננו את גובה המושב והתמקמו על המכשיר כשהגב צמוד למשענת.","הניחו את הרגליים על משעני הרגליים ואחזו בידיות לייצוב.","הפעילו את שרירי הקירוב וקרבו לאט את הרגליים יחד, תוך לחיצת הירכיים הפנימיות.","עצרו לרגע בשיא הכיווץ, ואז חזרו לאט למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself on the machine with your back against the backrest.","Place your feet on the footrests and grasp the handles for stability.","Engage your adductor muscles and slowly bring your legs together, squeezing your inner thighs.","Pause for a moment at the peak contraction, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"oHsrypV"},{"id":"edb-0599","name":"כפיפת ברך בישיבה","name_en":"lever seated leg curl","muscle":"legs","equipment":"leverage machine","target":"hamstrings","bodyPart":"upper legs","secondaryMuscles":["calves"],"steps":["כווננו את המכשיר להתאמה לגוף ושבו עליו כשהגב צמוד למשענת.","הניחו את שוקי הרגליים מתחת למנוף המרופד, ממש מעל הקרסוליים.","אחזו בידיות בצדי המכשיר לתמיכה.","תוך שמירה על ירכי הרגליים ללא תזוזה, נשפו וכופפו את הרגליים כלפי מעלה עד כמה שניתן.","החזיקו את מצב הכיווץ לרגע קצר תוך כדי לחיצת שרירי הירך האחורית.","שאפו והורידו לאט את המנוף בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the machine to fit your body and sit on it with your back against the backrest.","Place your lower legs under the padded lever, just above your ankles.","Grasp the handles on the sides of the machine for support.","Keeping your upper legs stationary, exhale and curl your legs up as far as possible.","Hold the contracted position for a brief pause as you squeeze your hamstrings.","Inhale and slowly lower the lever back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Zg3XY7P"},{"id":"edb-0600","name":"הרמת רגליים בישיבה","name_en":"lever seated leg raise crunch","muscle":"core","equipment":"leverage machine","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שבו על מכשיר המנוף כשהגב צמוד למשענת והרגליים על משעני הרגליים.","אחזו בידיות או במוטות הצד לייצוב.","הפעילו את שרירי הבטן והרימו לאט את הרגליים לכיוון החזה, תוך כיפוף הגו קדימה בו זמנית.","עצרו לרגע בשיא התנועה, ואז הורידו לאט את הרגליים והגו בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the leverage machine with your back against the backrest and your feet on the footrests.","Grasp the handles or sidebars for stability.","Engage your abs and slowly raise your legs up towards your chest, curling your torso forward at the same time.","Pause for a moment at the top, then slowly lower your legs and torso back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"PQ2AtC3"},{"id":"edb-0602","name":"פרפר הפוך בישיבה","name_en":"lever seated reverse fly","muscle":"shoulders","equipment":"leverage machine","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","rhomboids"],"steps":["כווננו את גובה המושב והתמקמו על המכשיר כשהחזה צמוד לכרית והרגליים שטוחות על הרצפה.","אחזו בידיות באחיזת יד עליונה ושמרו על הזרועות כפופות מעט.","נשפו ולחצו את השכמות זו לזו תוך משיכת הידיות אחורה והחוצה, הרחק מהגוף.","עצרו לרגע בשיא הכיווץ, ולאחר מכן שאפו וחזרו לאט לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself on the machine with your chest against the pad and your feet flat on the floor.","Grasp the handles with an overhand grip and keep your arms slightly bent.","Exhale and squeeze your shoulder blades together as you pull the handles back and outward, away from your body.","Pause for a moment at the peak contraction, then inhale and slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"myfUsKf"},{"id":"edb-0601","name":"פרפר הפוך בישיבה","name_en":"lever seated reverse fly (parallel grip)","muscle":"shoulders","equipment":"leverage machine","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","rhomboids"],"steps":["כווננו את גובה המושב והתמקמו על המכשיר כשהחזה צמוד לכרית והרגליים שטוחות על הרצפה.","אחזו בידיות באחיזה מקבילה, כשכפות הידיים פונות זו לזו, ושמרו על הזרועות כפופות מעט.","נשפו ולחצו את השכמות זו לזו תוך משיכת הידיות אחורה והחוצה, הרחק מהגוף.","עצרו לרגע בשיא הכיווץ, ולאחר מכן שאפו וחזרו לאט לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself on the machine with your chest against the pad and your feet flat on the floor.","Grasp the handles with a parallel grip, palms facing each other, and keep your arms slightly bent.","Exhale and squeeze your shoulder blades together as you pull the handles back and outward, away from your body.","Pause for a moment at the peak contraction, then inhale and slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"xiHiJcA"},{"id":"edb-1350","name":"חתירה בישיבה","name_en":"lever seated row","muscle":"back","equipment":"leverage machine","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["כווננו את גובה המושב ומשעני הרגליים למצב נוח.","שבו על המכשיר כשהחזה צמוד לכרית והרגליים על משעני הרגליים.","אחזו בידיות באחיזת יד עליונה, ברוחב הכתפיים.","שמרו על גב ישר ושרירי ליבה מופעלים.","משכו את הידיות לכיוון הגוף, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה.","שחררו לאט את הידיות וחזרו למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and footrests to a comfortable position.","Sit on the machine with your chest against the pad and your feet on the footrests.","Grasp the handles with an overhand grip, shoulder-width apart.","Keep your back straight and your core engaged.","Pull the handles towards your body, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement.","Slowly release the handles and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"7I6LNUG"},{"id":"edb-1385","name":"לחיצת רגליים בישיבה","name_en":"lever seated squat calf raise on leg press machine","muscle":"legs","equipment":"leverage machine","target":"calves","bodyPart":"lower legs","secondaryMuscles":["quadriceps","hamstrings","glutes"],"steps":["כווננו את מושב מכשיר לחיצת הרגליים כך שהברכיים כפופות מעט כשהרגליים על משטח הדריכה.","שבו על המכשיר כשהגב צמוד למשענת והרגליים שטוחות על משטח הדריכה, ברוחב הכתפיים.","הניחו את קצות האצבעות וכריות כפות הרגליים על משטח הדריכה, תוך שמירה על העקבים מחוץ לקצה.","שחררו את ידיות הביטחון ודחפו את משטח הדריכה הרחק מכם על ידי יישור הברכיים.","כשהברכיים ישרות לגמרי, הורידו לאט את העקבים על ידי כיפוף השוקיים.","עצרו לרגע בתחתית התנועה, ואז דחפו את משטח הדריכה בחזרה למעלה על ידי יישור השוקיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat of the leg press machine so that your knees are slightly bent when your feet are on the footplate.","Sit on the machine with your back against the backrest and your feet flat on the footplate, shoulder-width apart.","Place your toes and the balls of your feet on the footplate, keeping your heels off the edge.","Release the safety handles and push the footplate away from you by extending your knees.","Once your knees are fully extended, slowly lower your heels by flexing your calves.","Pause for a moment at the bottom, then push the footplate back up by extending your calves.","Repeat for the desired number of repetitions."],"mediaId":"IeDEXTe"},{"id":"edb-0603","name":"לחיצת כתפיים","name_en":"lever shoulder press","muscle":"shoulders","equipment":"leverage machine","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","chest"],"steps":["כווננו את גובה המושב והתמקמו על המכשיר כשהגב צמוד למשענת.","אחזו בידיות באחיזת יד עליונה ומקמו את הידיים בגובה הכתפיים.","דחפו את הידיות כלפי מעלה עד שהזרועות ישרות לגמרי, אך אל תנעלו את המרפקים.","עצרו לרגע בשיא התנועה, ואז הורידו לאט את הידיות בחזרה למטה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself on the machine with your back against the backrest.","Grasp the handles with an overhand grip and position your hands at shoulder level.","Push the handles upward until your arms are fully extended, but do not lock your elbows.","Pause for a moment at the top, then slowly lower the handles back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"67n3r98"},{"id":"edb-0869","name":"לחיצת כתפיים","name_en":"lever shoulder press v. 2","muscle":"shoulders","equipment":"leverage machine","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","chest"],"steps":["כווננו את גובה המושב ומשענת הגב של מכשיר המנוף לעמדה נוחה.","שבו על המכשיר כשהגב צמוד למשענת וכפות הרגליים שטוחות על הרצפה.","אחזו בידיות המכשיר באחיזת יד עליונה, ברוחב מעט גדול מרוחב הכתפיים.","דחפו את הידיות כלפי מעלה וקדימה עד שהזרועות ישרות לגמרי, אך לא נעולות.","עצרו לרגע בשיא התנועה, ואז הורידו לאט את הידיות בחזרה למטה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and backrest of the leverage machine to a comfortable position.","Sit on the machine with your back against the backrest and your feet flat on the floor.","Grasp the handles of the machine with an overhand grip, slightly wider than shoulder-width apart.","Push the handles upward and forward until your arms are fully extended, but not locked.","Pause for a moment at the top, then slowly lower the handles back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"vqsbmL0"},{"id":"edb-2318","name":"לחיצת כתפיים","name_en":"lever shoulder press v. 3","muscle":"shoulders","equipment":"leverage machine","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","chest"],"steps":["כווננו את גובה המושב ומשענת הגב של מכשיר המנוף לעמדה נוחה.","שבו על המכשיר כשהגב צמוד למשענת וכפות הרגליים שטוחות על הרצפה.","אחזו בידיות המכשיר באחיזת יד עליונה, ברוחב מעט גדול מרוחב הכתפיים.","דחפו את הידיות כלפי מעלה וקדימה עד שהזרועות ישרות לגמרי, אך לא נעולות.","עצרו לרגע בשיא התנועה, ואז הורידו לאט את הידיות בחזרה למטה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and backrest of the leverage machine to a comfortable position.","Sit on the machine with your back against the backrest and your feet flat on the floor.","Grasp the handles of the machine with an overhand grip, slightly wider than shoulder-width apart.","Push the handles upward and forward until your arms are fully extended, but not locked.","Pause for a moment at the top, then slowly lower the handles back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"dNFYIU1"},{"id":"edb-0604","name":"משיכת כתפיים","name_en":"lever shrug","muscle":"back","equipment":"leverage machine","target":"traps","bodyPart":"back","secondaryMuscles":["shoulders"],"steps":["כווננו את גובה המושב והתמקמו על מכשיר המנוף כשהגב צמוד לכרית.","אחזו בידיות באחיזת יד עליונה ושמרו על הזרועות ישרות.","תוך שמירה על הגב ישר, הרימו את הכתפיים לכיוון האוזניים גבוה ככל האפשר.","החזיקו את הכיווץ לרגע, ולאחר מכן הורידו לאט את הכתפיים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself on the leverage machine with your back against the pad.","Grasp the handles with an overhand grip and keep your arms straight.","Keeping your back straight, lift your shoulders up towards your ears as high as possible.","Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ZZKbeMw"},{"id":"edb-0605","name":"הרמת עקבים","name_en":"lever standing calf raise","muscle":"legs","equipment":"leverage machine","target":"calves","bodyPart":"lower legs","secondaryMuscles":["soleus","ankle stabilizers"],"steps":["כווננו את המכשיר לגובה שלכם ועמדו עם הרגליים ברוחב הכתפיים.","הניחו את הכתפיים מתחת לכריות ואחזו בידיות לייצוב.","הרימו את העקבים גבוה ככל האפשר על ידי יישור הקרסוליים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקבים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the machine to your height and stand with your feet shoulder-width apart.","Place your shoulders under the pads and hold onto the handles for stability.","Raise your heels as high as possible by extending your ankles.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ykUOVze"},{"id":"edb-3758","name":"לחיצת חזה בעמידה","name_en":"lever standing chest press","muscle":"chest","equipment":"leverage machine","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["כווננו את גובה המושב והתמקמו על המכשיר כשהרגליים שטוחות על הרצפה.","אחזו בידיות באחיזת יד עליונה ומקמו את הידיים בגובה החזה.","דחפו את הידיות קדימה עד שהזרועות ישרות לגמרי, תוך שמירה על המרפקים כפופים מעט.","עצרו לרגע, ואז החזירו לאט את הידיות לכיוון החזה, תוך שמירה על שליטה לאורך כל התנועה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself on the machine with your feet flat on the ground.","Grasp the handles with an overhand grip and position your hands at chest level.","Push the handles forward until your arms are fully extended, keeping your elbows slightly bent.","Pause for a moment, then slowly bring the handles back towards your chest, maintaining control throughout the movement.","Repeat for the desired number of repetitions."],"mediaId":"WbNq5Xu"},{"id":"edb-0606","name":"חתירה","name_en":"lever t bar row","muscle":"back","equipment":"leverage machine","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["כווננו את גובה המושב ואת מיקום משטח כפות הרגליים כדי להבטיח יישור נכון.","שבו על המכשיר כשהחזה צמוד לכרית והרגליים שטוחות על משטח הדריכה.","אחזו בידיות באחיזה עליונה, ברוחב מעט גדול מרוחב הכתפיים.","שמרו על גב ישר והפעילו את ליבת הגוף.","משכו את הידיות לכיוון הגו, תוך לחיצת השכמות זו לזו.","עצרו לרגע בשיא הכיווץ, ואז שחררו לאט את הידיות בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and footplate position to ensure proper alignment.","Sit on the machine with your chest against the pad and your feet flat on the footplate.","Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.","Keep your back straight and engage your core.","Pull the handles towards your torso, squeezing your shoulder blades together.","Pause for a moment at the peak contraction, then slowly release the handles back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"aaXr7ld"},{"id":"edb-1351","name":"חתירה אחיזה הפוכה","name_en":"lever t-bar reverse grip row","muscle":"back","equipment":"leverage machine","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["כווננו את גובה המושב והתמקמו על המכשיר כשהחזה צמוד לכרית והרגליים שטוחות על הרצפה.","אחזו בידיות באחיזה עליונה, ברוחב מעט גדול מרוחב הכתפיים.","שמרו על גב ישר והפעילו את ליבת הגוף.","משכו את הידיות לכיוון החזה, תוך לחיצת השכמות זו לזו.","עצרו לרגע בשיא התנועה, ואז שחררו לאט ויישרו את הזרועות בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself on the machine with your chest against the pad and your feet flat on the floor.","Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.","Keep your back straight and engage your core.","Pull the handles towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly release and extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"FVM1AUZ"},{"id":"edb-0607","name":"פשיטת מרפק","name_en":"lever triceps extension","muscle":"triceps","equipment":"leverage machine","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["כווננו את גובה המושב והתמקמו על המכשיר כשהגב צמוד לכרית.","אחזו בידיות באחיזת יד עליונה ויישרו את הזרועות לגמרי לפניכם.","תוך שמירה על הזרועות העליונות ללא תזוזה, הורידו לאט את הידיות לכיוון המצח על ידי כיפוף המרפקים.","עצרו לרגע בתחתית התנועה, ואז דחפו את הידיות בחזרה למעלה למצב ההתחלתי על ידי יישור הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself on the machine with your back against the pad.","Grasp the handles with an overhand grip and fully extend your arms in front of you.","Keeping your upper arms stationary, slowly lower the handles towards your forehead by bending your elbows.","Pause for a moment at the bottom, then push the handles back up to the starting position by extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"Ser9eQp"},{"id":"edb-1313","name":"חתירה","name_en":"lever unilateral row","muscle":"back","equipment":"leverage machine","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["כווננו את גובה המושב והתמקמו כשאתם פונים אל המכשיר.","אחזו בידיות באחיזת יד עליונה ושמרו על הגב ישר.","משכו את הידיות לכיוון הגוף, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה, ואז שחררו לאט ויישרו את הזרועות בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself facing the machine.","Grasp the handles with an overhand grip and keep your back straight.","Pull the handles towards your body, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release and extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"oROuvrX"},{"id":"edb-0609","name":"גשר","name_en":"london bridge","muscle":"back","equipment":"rope","target":"upper back","bodyPart":"back","secondaryMuscles":["shoulders","biceps","forearms"],"steps":["חברו את החבל לנקודת עיגון גבוהה.","עמדו כשגבכם לנקודת העיגון, עם הרגליים ברוחב הכתפיים.","אחזו בחבל באחיזה עילית, כפות הידיים פונות מטה.","הטו את הגוף מעט קדימה, תוך שמירה על הגב ישר ושרירי הליבה מופעלים.","משכו את החבל לכיוון הגוף, תוך לחיצת השכמות זו לזו.","עצרו לרגע בשיא התנועה, ולאחר מכן שחררו את המתח באיטיות וחזרו לנקודת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach the rope to a high anchor point.","Stand facing away from the anchor point with your feet shoulder-width apart.","Grasp the rope with an overhand grip, palms facing down.","Lean forward slightly, keeping your back straight and core engaged.","Pull the rope towards your body, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"bLyQokI"},{"id":"edb-3013","name":"גשר ישבן נמוך","name_en":"low glute bridge on floor","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","core"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו את הזרועות לצדי הגוף, כפות הידיים פונות מטה.","הפעילו את שרירי הישבן והליבה, ואז הרימו את הירכיים מהרצפה עד שהגוף יוצר קו ישר מהברכיים לכתפיים.","עצרו לרגע בשיא התנועה, תוך כיווץ שרירי הישבן.","הורידו לאט את האגן בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your arms by your sides, palms facing down.","Engage your glutes and core, then lift your hips off the ground until your body forms a straight line from your knees to your shoulders.","Pause for a moment at the top, squeezing your glutes.","Slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"u0cNiij"},{"id":"edb-1352","name":"כפיפת מרפק","name_en":"lower back curl","muscle":"back","equipment":"body weight","target":"spine","bodyPart":"back","secondaryMuscles":["glutes","hamstrings"],"steps":["שכבו על הבטן כשהרגליים ישרות והזרועות לצדי הגוף.","הפעילו את שרירי הישבן והירך האחורית, והרימו לאט את הגו העליון מהרצפה, תוך כיפוף הגב כלפי מעלה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your stomach with your legs extended and your arms by your sides.","Engage your glutes and hamstrings, and slowly lift your upper body off the ground, curling your back upwards.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ANbbry2"},{"id":"edb-3582","name":"לאנג׳","name_en":"lunge with jump","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["התחילו בעמידה עם הרגליים ברוחב הכתפיים.","צעדו קדימה עם הרגל הימנית, תוך הורדת הגוף לעמדת לאנג'.","דחפו עם כף הרגל הימנית וקפצו לאוויר, תוך החלפת מיקום הרגליים באוויר.","נחתו בעדינות עם הרגל השמאלית קדימה והורידו מיד את הגוף לתנוחת מכרעה.","המשיכו להתחלף בין מכרעות לקפיצות במספר החזרות הרצוי."],"steps_en":["Start by standing with your feet shoulder-width apart.","Take a step forward with your right foot, lowering your body into a lunge position.","Push off with your right foot and jump into the air, switching the position of your feet mid-air.","Land softly with your left foot forward and immediately lower your body into a lunge position.","Continue alternating between lunges and jumps for the desired number of repetitions."],"mediaId":"PM1PZjg"},{"id":"edb-1688","name":"פיתול","name_en":"lunge with twist","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["quadriceps","glutes","hamstrings"],"steps":["התחילו בעמידה עם הרגליים ברוחב הכתפיים.","צעדו קדימה עם הרגל הימנית, תוך הורדת הגוף לעמדת לאנג'.","תוך כדי המכרעה, סובבו את הגו ימינה, תוך קירוב המרפק השמאלי לברך הימנית.","עצרו לרגע, ולאחר מכן חזרו למצב ההתחלתי.","חזרו על התנועה בצד השני, תוך צעד קדימה עם הרגל השמאלית וסיבוב הגו שמאלה.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Start by standing with your feet shoulder-width apart.","Take a step forward with your right foot, lowering your body into a lunge position.","As you lunge, twist your torso to the right, bringing your left elbow towards your right knee.","Pause for a moment, then return to the starting position.","Repeat on the other side, stepping forward with your left foot and twisting your torso to the left.","Continue alternating sides for the desired number of repetitions."],"mediaId":"K9VL0Jq"},{"id":"edb-0613","name":"מתיחה בשכיבה צדי","name_en":"lying (side) quads stretch","muscle":"legs","equipment":"body weight","target":"quads","bodyPart":"upper legs","secondaryMuscles":["hamstrings"],"steps":["שכבו על הצד כשהרגליים ישרות.","כופפו את הרגל העליונה ואחזו בקרסול או בכף הרגל עם היד.","משכו בעדינות את הקרסול או כף הרגל לכיוון הישבן עד שתחושו מתיחה בשריר הארבע-ראשי.","החזיקו את המתיחה במשך 20-30 שניות.","שחררו את המתיחה וחזרו על התרגיל בצד השני."],"steps_en":["Lie on your side with your legs straight.","Bend your top leg and grab your ankle or foot with your hand.","Gently pull your ankle or foot towards your glutes until you feel a stretch in your quads.","Hold the stretch for 20-30 seconds.","Release the stretch and repeat on the other side."],"mediaId":"BWnJR72"},{"id":"edb-2312","name":"lying elbow to knee","name_en":"lying elbow to knee","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors","lower back"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו את הידיים מאחורי הראש כשהמרפקים פונים החוצה.","הפעילו את שרירי הבטן והרימו את פלג הגוף העליון מהרצפה, תוך הבאת המרפק הימני לכיוון הברך השמאלית.","במקביל, יישרו את הרגל הימנית קדימה והרימו אותה מהרצפה.","עצרו לרגע, ולאחר מכן חזרו למצב ההתחלתי.","חזרו על התנועה, הפעם תוך קירוב המרפק השמאלי לברך הימנית ויישור הרגל השמאלית.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engage your abs and lift your upper body off the ground, bringing your right elbow towards your left knee.","At the same time, extend your right leg straight out and lift it off the ground.","Pause for a moment, then return to the starting position.","Repeat the movement, this time bringing your left elbow towards your right knee and extending your left leg.","Continue alternating sides for the desired number of repetitions."],"mediaId":"AQIhRjM"},{"id":"edb-0620","name":"הרמת רגליים בשכיבה","name_en":"lying leg raise flat bench","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שכבו על ספסל ישר כשהגב צמוד אליו.","הניחו את הידיים מתחת לישבן לתמיכה.","שמרו על הרגליים ישרות וצמודות, והרימו אותן לכיוון התקרה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a flat bench with your back pressed against it.","Place your hands under your glutes for support.","Keep your legs straight and together, and lift them up towards the ceiling.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"WhuFnR7"},{"id":"edb-0865","name":"הרמת אגן בשכיבה","name_en":"lying leg-hip raise","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שכבו על הגב עם הרגליים מושטות והידיים לצידי הגוף.","הניחו את הידיים מתחת לישבן לתמיכה.","הפעילו את שרירי הליבה והרימו את הרגליים מהרצפה לכיוון התקרה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your legs extended and your arms by your sides.","Place your hands under your glutes for support.","Engage your core and lift your legs off the ground, raising them towards the ceiling.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"9IxJdtC"},{"id":"edb-1301","name":"לחיצת חזה","name_en":"machine inner chest press","muscle":"chest","equipment":"leverage machine","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["כווננו את גובה המושב והתמקמו על המכשיר כשהגב שטוח וצמוד לכרית.","אחזו בידיות באחיזה עליונה ומקמו את המרפקים בזווית של 90 מעלות.","דחפו את הידיות קדימה עד שהידיים שלוחות לגמרי, תוך נשיפה במהלך התנועה.","עצרו לרגע בסוף התנועה, ואז חזרו לאט למצב ההתחלתי, תוך שאיפה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself on the machine with your back flat against the pad.","Grasp the handles with an overhand grip and position your elbows at a 90-degree angle.","Push the handles forward until your arms are fully extended, exhaling during the movement.","Pause for a moment at the end of the movement, then slowly return to the starting position, inhaling as you do so.","Repeat for the desired number of repetitions."],"mediaId":"wDN97Ca"},{"id":"edb-0624","name":"march sit (wall)","name_en":"march sit (wall)","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הגב צמוד לקיר והרגליים ברוחב האגן.","החליקו לאט את הגב במורד הקיר עד שהברכיים כפופות בזווית של 90 מעלות.","הרימו את כף הרגל הימנית מהרצפה וקרבו את הברך לכיוון החזה.","הורידו את כף הרגל הימנית בחזרה והרימו את כף הרגל השמאלית מהרצפה, תוך קירוב הברך לכיוון החזה.","המשיכו להתחלף בין הרמת כף הרגל הימנית והשמאלית במספר החזרות הרצוי."],"steps_en":["Stand with your back against a wall and your feet hip-width apart.","Slowly slide your back down the wall until your knees are bent at a 90-degree angle.","Lift your right foot off the ground and bring your knee towards your chest.","Lower your right foot back down and lift your left foot off the ground, bringing your knee towards your chest.","Continue alternating between lifting your right and left foot for the desired number of repetitions."],"mediaId":"sVQCCeG"},{"id":"edb-1353","name":"medicine ball catch and overhead throw","name_en":"medicine ball catch and overhead throw","muscle":"back","equipment":"medicine ball","target":"lats","bodyPart":"back","secondaryMuscles":["shoulders","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים בכדור רפואי בשתי הידיים בגובה החזה.","כופפו מעט את הברכיים והפעילו את שרירי הליבה.","הורידו את הגוף לתנוחת סקוואט, תוך שמירה על הגב ישר והחזה מורם.","יישרו בפיצוץ כוח את הירכיים והרגליים, ובו זמנית זרקו את כדור הרפואי מעל הראש.","שחררו את הכדור בשיא התנועה ותפסו אותו בדרך למטה.","הורידו את הגוף בחזרה לתנוחת הסקוואט וחזרו במספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a medicine ball in both hands at chest level.","Bend your knees slightly and engage your core.","Lower your body into a squat position, keeping your back straight and chest up.","Explosively extend your hips and legs, while simultaneously throwing the medicine ball overhead.","Release the ball at the top of the movement and catch it on the way down.","Lower your body back into the squat position and repeat for the desired number of repetitions."],"mediaId":"PsVS1QP"},{"id":"edb-1302","name":"medicine ball chest pass","name_en":"medicine ball chest pass","muscle":"chest","equipment":"medicine ball","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים בכדור הרפואי בגובה החזה.","יישרו את הזרועות קדימה, תוך דחיפת כדור הרפואי הרחק מהחזה בכוח.","בזמן שחרור הכדור, המשיכו את התנועה עם הזרועות והגו, תוך העברת המשקל מהרגל האחורית לרגל הקדמית.","תפסו את הכדור כשהוא חוזר מהקיר או מבן הזוג, ומיד חזרו על התנועה.","המשיכו למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding the medicine ball at chest level.","Extend your arms forward, pushing the medicine ball away from your chest with force.","As you release the ball, follow through with your arms and torso, transferring your weight from your back foot to your front foot.","Catch the ball as it rebounds off the wall or partner, and immediately repeat the movement.","Continue for the desired number of repetitions."],"mediaId":"aDoFKrE"},{"id":"edb-1303","name":"medicine ball chest push from 3 point stance","name_en":"medicine ball chest push from 3 point stance","muscle":"chest","equipment":"medicine ball","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["התחילו בתנוחת שלוש נקודות, יד אחת על כדור הרפואי והיד השנייה על הרצפה.","יישרו את הרגליים ומקמו את הגוף בקו ישר.","הורידו את החזה לכיוון הרצפה תוך שמירה על הגב ישר.","דחפו את כדור הרפואי הרחק מהגוף, תוך יישור מלא של הזרוע.","חזרו למצב ההתחלתי וחזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a 3 point stance with one hand on the medicine ball and the other hand on the ground.","Extend your legs and position your body in a straight line.","Lower your chest towards the ground while keeping your back straight.","Push the medicine ball away from your body, extending your arm fully.","Return to the starting position and repeat for the desired number of repetitions."],"mediaId":"dCJnuVq"},{"id":"edb-1304","name":"medicine ball chest push multiple response","name_en":"medicine ball chest push multiple response","muscle":"chest","equipment":"medicine ball","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים בכדור רפואי בגובה החזה.","יישרו את הזרועות קדימה, תוך דחיפת כדור הרפואי הרחק מהחזה.","עצרו לרגע, ואז החזירו לאט את כדור הרפואי לחזה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a medicine ball at chest level.","Extend your arms forward, pushing the medicine ball away from your chest.","Pause for a moment, then slowly bring the medicine ball back to your chest.","Repeat for the desired number of repetitions."],"mediaId":"7aolH9D"},{"id":"edb-1305","name":"medicine ball chest push single response","name_en":"medicine ball chest push single response","muscle":"chest","equipment":"medicine ball","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים בכדור הרפואי בגובה החזה.","יישרו את הזרועות קדימה, תוך דחיפת כדור הרפואי הרחק מהחזה.","עצרו לרגע, ואז החזירו לאט את כדור הרפואי לחזה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding the medicine ball at chest level.","Extend your arms forward, pushing the medicine ball away from your chest.","Pause for a moment, then slowly bring the medicine ball back to your chest.","Repeat for the desired number of repetitions."],"mediaId":"jeHtrlO"},{"id":"edb-1312","name":"medicine ball chest push with run release","name_en":"medicine ball chest push with run release","muscle":"chest","equipment":"medicine ball","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים בכדור רפואי בגובה החזה.","צעדו קדימה עם הרגל הימנית ובו זמנית דחפו את כדור הרפואי קדימה, תוך יישור מלא של הזרועות.","תוך כדי דחיפת הכדור קדימה, שחררו אותו ותנו לו להתגלגל קדימה.","רוצו קדימה במהירות ותפסו את הכדור לפני שהוא נוגע ברצפה.","לאחר שתפסתם את הכדור, החזירו אותו לחזה וחזרו על התנועה עם הרגל השמאלית קדימה.","המשיכו להחליף רגליים ולחזור על התרגיל במספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a medicine ball at chest level.","Step forward with your right foot and simultaneously push the medicine ball forward, extending your arms fully.","As you push the ball forward, release it and let it roll forward.","Quickly run forward and catch the ball before it hits the ground.","Once you catch the ball, bring it back to your chest and repeat the movement with your left foot forward.","Continue alternating legs and repeating the exercise for the desired number of repetitions."],"mediaId":"pX9Elbe"},{"id":"edb-1701","name":"שכיבת סמיכה אחיזה צרה עם כדור כוח","name_en":"medicine ball close grip push up","muscle":"triceps","equipment":"medicine ball","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["התחילו בתנוחת פלאנק גבוה עם הידיים על כדור הרפואי, ברוחב הכתפיים.","הורידו את הגוף לכיוון הרצפה על ידי כיפוף המרפקים, כשהם צמודים לגוף.","דחפו בחזרה למעלה למצב ההתחלתי, תוך יישור מלא של הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a high plank position with your hands on the medicine ball, shoulder-width apart.","Lower your body towards the ground by bending your elbows, keeping them close to your sides.","Push back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"8K7m2SS"},{"id":"edb-1354","name":"medicine ball overhead slam","name_en":"medicine ball overhead slam","muscle":"back","equipment":"medicine ball","target":"upper back","bodyPart":"back","secondaryMuscles":["shoulders","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים בכדור רפואי בשתי הידיים מעל הראש.","הפעילו את הליבה ושמרו על גב ישר.","כופפו את הברכיים מעט וטרקו בכוח את כדור הרפואי לרצפה לפניכם.","תוך כדי טריקת הכדור, השתמשו בכל הגוף כדי לייצר כוח, כולל הכתפיים והליבה.","תפסו את הכדור בקפיצה וחזרו על התרגיל במספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a medicine ball with both hands above your head.","Engage your core and keep your back straight.","Bend your knees slightly and forcefully slam the medicine ball down to the ground in front of you.","As you slam the ball down, use your entire body to generate power, including your shoulders and core.","Catch the ball on the bounce and repeat for the desired number of repetitions."],"mediaId":"oHg8eop"},{"id":"edb-1750","name":"medicine ball supine chest throw","name_en":"medicine ball supine chest throw","muscle":"triceps","equipment":"medicine ball","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["שכבו על הגב על ספסל, כשהברכיים כפופות והרגליים שטוחות על הרצפה.","אחזו בכדור הרפואי בשתי הידיים, תוך יישור מלא של הזרועות מעל החזה.","הורידו את כדור הרפואי לכיוון החזה, תוך שמירה על המרפקים קרובים לגוף.","דחפו בפיצוץ כוח את כדור הרפואי כלפי מעלה, תוך יישור מלא של הזרועות וזריקת הכדור גבוה ככל האפשר.","תפסו את כדור הרפואי וחזרו על התרגיל במספר החזרות הרצוי."],"steps_en":["Lie flat on your back on a bench with your knees bent and feet flat on the ground.","Hold the medicine ball with both hands, extending your arms straight up above your chest.","Lower the medicine ball towards your chest, keeping your elbows close to your body.","Explosively push the medicine ball upwards, extending your arms fully and throwing the ball as high as possible.","Catch the medicine ball and repeat for the desired number of repetitions."],"mediaId":"Al3tP0D"},{"id":"edb-0627","name":"מתח אחיזה תחתית","name_en":"mixed grip chin-up","muscle":"back","equipment":"body weight","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["אחזו במוט המתח באחיזת יד תחתונה (כפות הידיים פונות אליכם) כשהידיים ברוחב מעט גדול מרוחב הכתפיים.","היתלו על המוט כשהידיים ישרות לגמרי וכפות הרגליים באוויר.","הפעילו את שרירי הגב ומשכו את הגוף כלפי מעלה לכיוון המוט, תוך הובלה עם החזה.","המשיכו למשוך עד שהסנטר מעל המוט.","עצרו לרגע בשיא התנועה, ואז הורידו לאט ובשליטה את הגוף בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Grab the pull-up bar with an underhand grip (palms facing towards you) and your hands slightly wider than shoulder-width apart.","Hang from the bar with your arms fully extended and your feet off the ground.","Engage your back muscles and pull your body up towards the bar, leading with your chest.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position with control.","Repeat for the desired number of repetitions."],"mediaId":"T8UpLkb"},{"id":"edb-3217","name":"שכיבת סמיכה","name_en":"modified hindu push-up (male)","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders","core"],"steps":["התחילו בתנוחת שכיבת סמיכה עם הידיים ברוחב מעט גדול מרוחב הכתפיים והרגליים ברוחב האגן.","הורידו את הגוף לכיוון הרצפה, תוך כיפוף המרפקים ושמירה על שרירי הליבה מכווצים.","תוך כדי הורדת הגוף, העבירו את המשקל אחורה והרימו את הירכיים כלפי מעלה, ליצירת צורת V הפוכה עם הגוף.","המשיכו להוריד את הגוף עד שהחזה ממש מעל הרצפה, ואז הפכו את התנועה, דחפו את הירכיים בחזרה מטה ויישרו את הזרועות כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet hip-width apart.","Lower your body towards the ground, bending your elbows and keeping your core engaged.","As you lower your body, shift your weight back and lift your hips up towards the ceiling, creating an inverted V shape with your body.","Continue to lower your body until your chest is just above the ground, then reverse the movement, pushing your hips back down and extending your arms to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"epOSYUZ"},{"id":"edb-1421","name":"שכיבת סמיכה","name_en":"modified push up to lower arms","muscle":"biceps","equipment":"body weight","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["triceps","chest","shoulders"],"steps":["התחילו בתנוחת שכיבת סמיכה עם הידיים ישר מתחת לכתפיים והגוף בקו ישר.","הורידו את הגוף לכיוון הרצפה על ידי כיפוף המרפקים, תוך שמירתם קרובים לצדדים.","כשהמרפקים בזווית של 90 מעלות, הורידו את האמות לרצפה, תוך שמירה על המרפקים ישר מתחת לכתפיים.","עצרו לרגע, ואז דחפו דרך כפות הידיים כדי להרים את האמות בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a push-up position with your hands directly under your shoulders and your body in a straight line.","Lower your body down towards the ground by bending your elbows, keeping them close to your sides.","Once your elbows are at a 90-degree angle, lower your forearms to the ground, keeping your elbows directly under your shoulders.","Pause for a moment, then push through your palms to lift your forearms back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"arvaszz"},{"id":"edb-0628","name":"monster walk","name_en":"monster walk","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps"],"steps":["הניחו גומיית התנגדות סביב הקרסוליים.","עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","עשו צעד הצידה עם הרגל הימנית, תוך שמירה על מתח בגומיית ההתנגדות.","המשיכו עם הרגל השמאלית, תוך צעד הצידה כדי לחזור למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Place a resistance band around your ankles.","Stand with your feet shoulder-width apart and slightly bend your knees.","Take a step to the side with your right foot, maintaining tension on the resistance band.","Follow with your left foot, stepping to the side to return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"O95afRA"},{"id":"edb-0630","name":"mountain climber","name_en":"mountain climber","muscle":"core","equipment":"body weight","target":"cardiovascular system","bodyPart":"cardio","secondaryMuscles":["core","shoulders","triceps"],"steps":["התחילו בתנוחת פלאנק גבוה כשהידיים ישירות מתחת לכתפיים והגוף בקו ישר.","הפעילו את שרירי הליבה וקרבו את הברך הימנית לכיוון החזה, ואז החליפו במהירות וקרבו את הברך השמאלית לכיוון החזה.","המשיכו להחליף רגליים בתנועת ריצה, תוך שמירה על הירכיים נמוכות ושרירי הליבה מכווצים.","שמרו על קצב יציב ונשמו באופן שווה לאורך כל התרגיל.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a high plank position with your hands directly under your shoulders and your body in a straight line.","Engage your core and bring your right knee towards your chest, then quickly switch and bring your left knee towards your chest.","Continue alternating legs in a running motion, keeping your hips low and your core engaged.","Maintain a steady pace and breathe evenly throughout the exercise.","Repeat for the desired number of repetitions."],"mediaId":"RJgzwny"},{"id":"edb-0631","name":"muscle up","name_en":"muscle up","muscle":"back","equipment":"body weight","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","triceps","shoulders","chest"],"steps":["התחילו בתלייה ממוט מתח, כפות הידיים פונות ממכם והזרועות ישרות לגמרי.","הפעילו את שרירי הליבה ומשכו את הגוף כלפי מעלה לכיוון המוט, כשהחזה מוביל את התנועה.","כשאתם מגיעים לשיא התנועה, שנו את האחיזה כך שכפות הידיים יפנו אליכם.","המשיכו למשוך את עצמכם למעלה עד שהחזה מעל המוט והזרועות כפופות לגמרי.","הפכו את התנועה על ידי הורדה איטית של עצמכם בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by hanging from a pull-up bar with your palms facing away from you and your arms fully extended.","Engage your core and pull your body up towards the bar, leading with your chest.","As you reach the top of the movement, transition your grip so that your palms are facing towards you.","Continue pulling yourself up until your chest is above the bar and your arms are fully flexed.","Reverse the movement by slowly lowering yourself back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"yJUHKTn"},{"id":"edb-1401","name":"muscle-up (on vertical bar)","name_en":"muscle-up (on vertical bar)","muscle":"back","equipment":"body weight","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","triceps","forearms"],"steps":["התחילו בתלייה ממוט אנכי, כפות הידיים פונות ממכם והזרועות ישרות לגמרי.","הפעילו את שרירי הליבה ומשכו את הגוף כלפי מעלה לכיוון המוט, כשהחזה מוביל את התנועה.","תוך כדי משיכת עצמכם למעלה, הטו את הגוף מעט אחורה וקרבו את המרפקים לצדדים.","המשיכו למשוך עד שהחזה מגיע למוט והמרפקים כפופים לגמרי.","עצרו לרגע בשיא התנועה, ולאחר מכן רדו באיטיות חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by hanging from a vertical bar with your palms facing away from you and your arms fully extended.","Engage your core and pull your body up towards the bar, leading with your chest.","As you pull yourself up, lean back slightly and bring your elbows towards your sides.","Continue pulling until your chest reaches the bar and your elbows are fully bent.","Pause for a moment at the top, then slowly lower yourself back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Af0EW2I"},{"id":"edb-2328","name":"שכיבת סמיכה צר","name_en":"narrow push-up on exercise ball","muscle":"triceps","equipment":"stability ball","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["הניחו את כדור היציבות על הרצפה ומקמו את עצמכם בתנוחת שכיבת סמיכה עם הידיים על הכדור, ברוחב מעט קטן מרוחב הכתפיים.","הפעילו את שרירי הליבה ושמרו על הגוף בקו ישר מהראש עד לכפות הרגליים.","הורידו את החזה לכיוון הכדור על ידי כיפוף המרפקים, תוך שמירתם קרובים לגוף.","עצרו לרגע בתחתית התנועה, ואז דחפו את עצמכם בחזרה למצב ההתחלתי על ידי יישור הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Place the stability ball on the ground and position yourself in a push-up position with your hands on the ball, slightly narrower than shoulder-width apart.","Engage your core and keep your body in a straight line from head to toe.","Lower your chest towards the ball by bending your elbows, keeping them close to your body.","Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"mediaId":"4cWjYEN"},{"id":"edb-1403","name":"מתיחה צדי","name_en":"neck side stretch","muscle":"shoulders","equipment":"body weight","target":"levator scapulae","bodyPart":"neck","secondaryMuscles":["trapezius","sternocleidomastoid"],"steps":["עמדו או שבו בישיבה זקופה עם הכתפיים רפויות.","הטו את הראש לצד אחד, תוך קירוב האוזן לכתף.","החזיקו את המתיחה למשך 15-30 שניות.","חזרו על התרגיל בצד השני.","בצעו 2-4 סטים לכל צד."],"steps_en":["Stand or sit up straight with your shoulders relaxed.","Tilt your head to one side, bringing your ear towards your shoulder.","Hold the stretch for 15-30 seconds.","Repeat on the other side.","Perform 2-4 sets on each side."],"mediaId":"x2chWLO"},{"id":"edb-0634","name":"כפיפת בטן","name_en":"negative crunch","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו את הידיים מאחורי הראש כשהמרפקים פונים החוצה.","תוך הפעלת שרירי הבטן, הרימו לאט את פלג הגוף העליון מהרצפה, בכיפוף קדימה עד שהגו נמצא בזווית של 45 מעלות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"szIn2UK"},{"id":"edb-1495","name":"כפיפת בטן","name_en":"oblique crunch v. 2","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו את הידיים מאחורי הראש או שלבו אותן על החזה.","הפעילו את שרירי הבטן והרימו את השכמות מהרצפה, תוך סיבוב הגו לצד אחד.","עצרו לרגע, ואז הורידו את השכמות בחזרה למצב ההתחלתי.","חזרו על התרגיל בצד השני.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Lie on your back with your knees bent and feet flat on the ground.","Place your hands behind your head or cross them over your chest.","Engage your abs and lift your shoulder blades off the ground, rotating your torso to one side.","Pause for a moment, then lower your shoulder blades back down to the starting position.","Repeat on the other side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"cJgSTmh"},{"id":"edb-0635","name":"oblique crunches floor","name_en":"oblique crunches floor","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques"],"steps":["שכבו על הגב כשהברכיים כפופות והרגליים שטוחות על הרצפה.","הניחו את הידיים מאחורי הראש או שלבו אותן על החזה.","הפעילו את שרירי הבטן והרימו את השכמות מהרצפה, תוך סיבוב הגו לצד אחד.","עצרו לרגע, ואז הורידו את השכמות בחזרה לרצפה.","חזרו על התנועה בצד השני, תוך החלפת צדדים בכל חזרה."],"steps_en":["Lie on your back with your knees bent and feet flat on the floor.","Place your hands behind your head or cross them over your chest.","Engage your abs and lift your shoulder blades off the floor, rotating your torso to one side.","Pause for a moment, then lower your shoulder blades back down to the floor.","Repeat on the other side, alternating sides with each repetition."],"mediaId":"QUDd8WS"},{"id":"edb-0636","name":"כפיפת פטיש עם מוט אולימפי","name_en":"olympic barbell hammer curl","muscle":"biceps","equipment":"olympic barbell","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו זקוף עם הרגליים ברוחב הכתפיים ואחזו במוט אולימפי באחיזת יד עליונה.","תנו למוט לתלות באורך הזרוע לפני הירכיים, כשכפות הידיים פונות לגוף.","תוך שמירה על הזרוע העליונה ללא תזוזה, נשפו החוצה וכופפו את המשקולות תוך כיווץ שרירי הביצפס.","המשיכו להרים את המוט עד ששריר הביצפס מכווץ במלואו והמוט נמצא בגובה הכתפיים.","החזיקו את התנוחה המכווצת לרגע קצר תוך כיווץ שרירי הביצפס.","שאפו אוויר והתחילו להוריד לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand up straight with your feet shoulder-width apart and hold an Olympic barbell with an overhand grip.","Let the barbell hang at arm's length in front of your thighs, with your palms facing your body.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"o1ntciW"},{"id":"edb-0637","name":"פשיטת מרפק עם מוט אולימפי","name_en":"olympic barbell triceps extension","muscle":"triceps","equipment":"olympic barbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["התחילו בעמידה עם הרגליים ברוחב הכתפיים ואחיזת המוט באחיזת יד עליונה.","הרימו את המוט מעל הראש, תוך יישור מלא של הזרועות.","תוך שמירה על הזרועות העליונות קרובות לראש, הורידו את המוט באיטיות מאחורי הראש על ידי כיפוף המרפקים.","עצרו לרגע, ולאחר מכן יישרו את הזרועות חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by standing with your feet shoulder-width apart and holding the barbell with an overhand grip.","Raise the barbell above your head, fully extending your arms.","Keeping your upper arms close to your head, slowly lower the barbell behind your head by bending your elbows.","Pause for a moment, then extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"wu5LXwz"},{"id":"edb-1355","name":"one arm against wall","name_en":"one arm against wall","muscle":"back","equipment":"body weight","target":"lats","bodyPart":"back","secondaryMuscles":["shoulders","triceps"],"steps":["עמדו מול קיר עם הרגליים ברוחב הכתפיים.","יישרו זרוע אחת ישר לפניכם והניחו את כף היד על הקיר.","הפעילו את שרירי הליבה והטו את הגוף קדימה, תוך שמירה על הזרוע ישרה והגב שטוח.","דחפו לאט על הקיר עם כף היד, תוך הפעלת שרירי ה'לאט'.","החזיקו את התנוחה למספר שניות, ואז שחררו וחזרו על כך עם הזרוע השנייה."],"steps_en":["Stand facing a wall with your feet shoulder-width apart.","Extend one arm straight out in front of you and place your palm against the wall.","Engage your core and lean your body forward, keeping your arm straight and your back flat.","Slowly push against the wall with your palm, activating your lat muscles.","Hold the position for a few seconds, then release and repeat with the other arm."],"mediaId":"ZZTGMKh"},{"id":"edb-0638","name":"מתח אחיזה תחתית ביד אחת","name_en":"one arm chin-up","muscle":"back","equipment":"body weight","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["עמדו מול מוט מתח עם הרגליים ברוחב הכתפיים.","הושיטו יד ואחזו במוט באחיזת יד תחתונה, כשיד אחת אוחזת במוט והשנייה תומכת בפרק כף היד.","היתלו מהמוט כשהזרוע ישרה לגמרי, תוך שמירה על הגוף ישר ושרירי הליבה מכווצים.","משכו את עצמכם כלפי מעלה לכיוון המוט על ידי כיפוף המרפק ולחיצת שרירי הגב.","המשיכו למשוך עד שהסנטר מעל המוט, ולאחר מכן הורידו את עצמכם לאט בחזרה לעמדת ההתחלה.","חזרו על התנועה למספר החזרות הרצוי, ולאחר מכן החליפו ידיים וחזרו שוב."],"steps_en":["Stand facing a pull-up bar with your feet shoulder-width apart.","Reach up and grab the bar with an underhand grip, with one hand gripping the bar and the other hand holding your wrist for support.","Hang from the bar with your arm fully extended, keeping your body straight and your core engaged.","Pull yourself up towards the bar by bending your elbow and squeezing your back muscles.","Continue pulling until your chin is above the bar, then slowly lower yourself back down to the starting position.","Repeat for the desired number of repetitions, then switch arms and repeat."],"mediaId":"HjdqmZa"},{"id":"edb-0639","name":"מקבילים ביד אחת","name_en":"one arm dip","muscle":"triceps","equipment":"body weight","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["עמדו כשגבכם פונה לספסל או כיסא, הרגליים ברוחב הכתפיים.","הניחו יד אחת על הספסל או הכיסא מאחוריכם, האצבעות פונות לכיוון הגוף.","יישרו את הרגליים לפניכם, תוך שמירה על העקבים על הרצפה.","כופפו את המרפקים והורידו את הגוף לכיוון הרצפה, תוך שמירה על הגב קרוב לספסל או לכיסא.","עצרו לרגע בתחתית התנועה, ואז דחפו דרך כפות הידיים כדי ליישר את הזרועות ולחזור למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צד וחזרו עם היד השנייה."],"steps_en":["Stand facing away from a bench or chair, with your feet shoulder-width apart.","Place one hand on the bench or chair behind you, fingers pointing towards your body.","Extend your legs out in front of you, keeping your heels on the ground.","Bend your elbows and lower your body towards the ground, keeping your back close to the bench or chair.","Pause for a moment at the bottom, then push through your palms to straighten your arms and return to the starting position.","Repeat for the desired number of repetitions, then switch sides and repeat with the other arm."],"mediaId":"FAoIFMw"},{"id":"edb-0640","name":"one arm slam (with medicine ball)","name_en":"one arm slam (with medicine ball)","muscle":"core","equipment":"medicine ball","target":"abs","bodyPart":"waist","secondaryMuscles":["shoulders","back"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשאתם אוחזים בכדור הרפואי ביד אחת לפני המותניים.","כופפו מעט את הברכיים והפעילו את שרירי הליבה.","הרימו את כדור הרפואי מעל הראש, תוך יישור מלא של הזרוע.","טרקו בכוח את כדור הרפואי לרצפה, תוך שימוש בשרירי הליבה והכתפיים לייצור כוח.","תפסו את כדור הרפואי בקפיצה וחזרו על התרגיל במספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding the medicine ball with one hand in front of your waist.","Bend your knees slightly and engage your core.","Raise the medicine ball above your head, fully extending your arm.","Forcefully slam the medicine ball down to the ground, using your core and shoulders to generate power.","Catch the medicine ball on the bounce and repeat for the desired number of repetitions."],"mediaId":"jCrtE9b"},{"id":"edb-1773","name":"חתירה ביד אחת","name_en":"one arm towel row","muscle":"back","equipment":"body weight","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים, הברכיים כפופות מעט, ואחזו מגבת ביד אחת.","התכופפו קדימה מהמותניים, תוך שמירה על גב ישר ושרירי ליבה פעילים.","יישרו את הזרוע לגמרי, כך שהמגבת תלויה לפניכם.","משכו את המגבת לכיוון החזה, תוך כיווץ השכמות יחד.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המגבת באיטיות חזרה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ידיים."],"steps_en":["Stand with your feet shoulder-width apart, knees slightly bent, and hold a towel with one hand.","Bend forward at the waist, keeping your back straight and your core engaged.","Extend your arm fully, allowing the towel to hang in front of you.","Pull the towel towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the towel back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"mediaId":"bKWbrTA"},{"id":"edb-1386","name":"הרמת עקבים ברגל אחת","name_en":"one leg donkey calf raise","muscle":"legs","equipment":"body weight","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings","glutes"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים, אצבעות הרגליים פונות קדימה.","הניחו את הידיים על משטח יציב לתמיכה, כמו קיר או מוט.","הרימו רגל אחת מהרצפה, תוך שמירה על הברך כפופה מעט.","הרימו את העקב גבוה ככל האפשר, תוך שימוש בשרירי השוק.","עצרו לרגע בקצה העליון, ואז הורידו לאט את העקב בחזרה למטה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו רגליים."],"steps_en":["Stand with your feet shoulder-width apart, toes pointing forward.","Place your hands on a stable surface for support, such as a wall or a bar.","Lift one leg off the ground, keeping your knee slightly bent.","Raise your heel as high as possible, using your calf muscles.","Pause for a moment at the top, then slowly lower your heel back down.","Repeat for the desired number of repetitions, then switch legs."],"mediaId":"A2upspL"},{"id":"edb-1387","name":"הרמת עקבים ברגל אחת","name_en":"one leg floor calf raise","muscle":"legs","equipment":"body weight","target":"calves","bodyPart":"lower legs","secondaryMuscles":["ankles","feet"],"steps":["עמדו עם הרגליים ברוחב האגן והניחו את הידיים על קיר או עצם יציב לאיזון.","הרימו כף רגל אחת מהרצפה ושמרו על איזון על הרגל השנייה.","הרימו לאט את העקב מהרצפה, תוך הרמת הגוף על כרית כף הרגל.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקב בחזרה למצב ההתחלתי.","חזרו על התנועה למספר החזרות הרצוי, ולאחר מכן החליפו רגליים וחזרו שוב."],"steps_en":["Stand with your feet hip-width apart and place your hands on a wall or sturdy object for balance.","Lift one foot off the ground and balance on the other foot.","Slowly raise your heel off the ground, lifting your body up onto the ball of your foot.","Pause for a moment at the top, then slowly lower your heel back down to the starting position.","Repeat for the desired number of repetitions, then switch legs and repeat."],"mediaId":"0jp9Rlz"},{"id":"edb-1476","name":"סקוואט ברגל אחת","name_en":"one leg squat","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים.","יישרו רגל אחת קדימה, תוך שמירתה מעל הרצפה.","כופפו את רגל העמידה והורידו את הגוף כאילו אתם יושבים אחורה על כיסא.","שמרו על החזה מורם והגב ישר.","דחפו דרך העקב כדי לחזור לעמדת ההתחלה.","חזרו עם הרגל השנייה."],"steps_en":["Stand with your feet shoulder-width apart.","Extend one leg forward, keeping it off the ground.","Bend your standing leg and lower your body down as if sitting back into a chair.","Keep your chest up and your back straight.","Push through your heel to return to the starting position.","Repeat with the other leg."],"mediaId":"C31LMnP"},{"id":"edb-0641","name":"otis up","name_en":"otis up","muscle":"core","equipment":"weighted","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors","lower back"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו את הידיים מאחורי הראש כשהמרפקים פונים החוצה.","תוך הפעלת שרירי הבטן, הרימו לאט את פלג הגוף העליון מהרצפה, בכיפוף קדימה עד שהגו נמצא בזווית של 45 מעלות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"UVL20oz"},{"id":"edb-0642","name":"שכיבת סמיכה","name_en":"outside leg kick push-up","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["התחילו בתנוחת שכיבת סמיכה עם הידיים ברוחב מעט גדול מרוחב הכתפיים והרגליים צמודות.","הורידו את הגוף לכיוון הרצפה על ידי כיפוף המרפקים, תוך שמירה על הגב ישר ושרירי הליבה מכווצים.","תוך כדי דחיפה בחזרה למעלה, בעטו רגל אחת הצידה, תוך יישור מלא והפעלת שרירי הישבן.","החזירו את הרגל למצב ההתחלתי וחזרו על שכיבת הסמיכה, תוך החלפת רגליים בכל חזרה.","המשיכו להחליף בין בעיטות רגליים ושכיבות סמיכה במספר החזרות הרצוי."],"steps_en":["Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together.","Lower your body towards the ground by bending your elbows, keeping your back straight and core engaged.","As you push back up, kick one leg out to the side, extending it fully and engaging your glutes.","Return your leg to the starting position and repeat the push-up, alternating legs with each repetition.","Continue alternating leg kicks and push-ups for the desired number of repetitions."],"mediaId":"jNU1gFQ"},{"id":"edb-0643","name":"מתיחה מעל הראש","name_en":"overhead triceps stretch","muscle":"triceps","equipment":"body weight","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["עמדו או שבו בישיבה זקופה עם הרגליים ברוחב הכתפיים.","הרימו זרוע אחת מעל הראש, תוך כיפוף במרפק כך שהיד מגיעה לכיוון השכמה הנגדית.","עם היד השנייה, משכו בעדינות את מרפק הזרוע המורמת לכיוון הצד הנגדי של הראש, תוך תחושת מתיחה בטריצפס.","החזיקו את המתיחה במשך 15-30 שניות, ולאחר מכן שחררו.","חזרו על התרגיל בצד השני."],"steps_en":["Stand or sit upright with your feet shoulder-width apart.","Extend one arm overhead, bending at the elbow so that your hand reaches towards the opposite shoulder blade.","With your other hand, gently pull the elbow of the extended arm towards the opposite side of your head, feeling a stretch in your triceps.","Hold the stretch for 15-30 seconds, then release.","Repeat on the other side."],"mediaId":"Z5YStHW"},{"id":"edb-3147","name":"pelvic tilt","name_en":"pelvic tilt","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["lower back"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו את הידיים לצדי הגוף.","הפעילו את שרירי הבטן והטו את האגן כלפי מעלה, תוך לחיצת הגב התחתון לרצפה.","החזיקו תנוחה זו למספר שניות, תוך התמקדות בכיווץ שרירי הבטן.","שחררו את ההטיה וחזרו למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands by your sides.","Engage your abs and tilt your pelvis upward, pressing your lower back into the ground.","Hold this position for a few seconds, focusing on contracting your abs.","Release the tilt and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"NKJ8o6x"},{"id":"edb-1422","name":"גשר","name_en":"pelvic tilt into bridge","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","core"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו את הזרועות לצדי הגוף, כפות הידיים פונות מטה.","הפעילו את שרירי הישבן וליבת הגוף.","הטו את האגן כלפי מעלה, תוך הרמת הירכיים מהרצפה.","החזיקו את תנוחת הגשר למספר שניות.","הורידו לאט את האגן בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie on your back with your knees bent and feet flat on the ground.","Place your arms by your sides with your palms facing down.","Engage your glutes and core muscles.","Tilt your pelvis upward, lifting your hips off the ground.","Hold the bridge position for a few seconds.","Slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"D9qe7CM"},{"id":"edb-1388","name":"מתיחה","name_en":"peroneals stretch","muscle":"legs","equipment":"rope","target":"calves","bodyPart":"lower legs","secondaryMuscles":["ankles","feet"],"steps":["שבו על הרצפה עם הרגליים מושטות לפניכם.","כרכו את החבל סביב כרית כף הרגל ואחזו בקצות החבל בידיים.","משכו בעדינות את החבל לכיוונכם, תוך כיפוף כף הרגל ומתיחת שריר השוק.","החזיקו את המתיחה למשך 15-30 שניות.","שחררו את המתח בחבל וחזרו על המתיחה ברגל השנייה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the ground with your legs extended in front of you.","Loop the rope around the ball of your foot and hold the ends of the rope with your hands.","Gently pull the rope towards you, flexing your foot and stretching your calf muscles.","Hold the stretch for 15-30 seconds.","Release the tension on the rope and repeat the stretch on the other leg.","Repeat for the desired number of repetitions."],"mediaId":"XhfS1DZ"},{"id":"edb-3662","name":"שכיבת סמיכה","name_en":"pike-to-cobra push-up","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["core","shoulders","triceps"],"steps":["התחילו בתנוחת שכיבת סמיכה עם הידיים ברוחב מעט גדול מרוחב הכתפיים והרגליים צמודות.","הפעילו את שרירי הליבה והרימו את הירכיים לכיוון התקרה, ליצירת צורת V הפוכה עם הגוף.","הורידו את הגו העליון לכיוון הרצפה על ידי כיפוף המרפקים, תוך שמירתם קרובים לגוף.","תוך כדי הירידה, העבירו את המשקל קדימה ועברו לתנוחת קוברה על ידי יישור הזרועות והרמת החזה כלפי מעלה.","הפכו את התנועה על ידי כיפוף המרפקים והורדת החזה בחזרה לכיוון הרצפה.","דחפו דרך הידיים כדי לחזור לתנוחת ה-V ההפוכה.","המשיכו את התנועה על ידי הורדת הירכיים בחזרה לכיוון הרצפה, תוך חזרה לתנוחת שכיבת הסמיכה ההתחלתית.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together.","Engage your core and lift your hips up towards the ceiling, forming an inverted V shape with your body.","Lower your upper body towards the ground by bending your elbows, keeping them close to your body.","As you lower down, shift your weight forward and transition into a cobra pose by straightening your arms and lifting your chest up.","Reverse the movement by bending your elbows and lowering your chest back down towards the ground.","Push through your hands to return to the inverted V position.","Continue the movement by lowering your hips back down towards the ground, returning to the starting push-up position.","Repeat for the desired number of repetitions."],"mediaId":"XPUDTt7"},{"id":"edb-1306","name":"שכיבת סמיכה","name_en":"plyo push up","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders","core"],"steps":["התחילו בעמדת פלאנק גבוה כשהידיים מעט רחבות יותר מרוחב הכתפיים.","הורידו את החזה לכיוון הרצפה על ידי כיפוף המרפקים, תוך שמירה על הגוף בקו ישר.","דחפו בפיצוץ כוח מהרצפה, תוך שימוש בשרירי החזה כדי להעיף את הגו העליון מהרצפה.","נחתו בעדינות עם הידיים בחזרה במצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a high plank position with your hands slightly wider than shoulder-width apart.","Lower your chest towards the ground by bending your elbows, keeping your body in a straight line.","Push explosively off the ground, using your chest muscles to propel your upper body off the ground.","Land softly with your hands back in the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Snj1wSv"},{"id":"edb-1687","name":"posterior step to overhead reach","name_en":"posterior step to overhead reach","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["glutes","hamstrings","quadriceps","shoulders"],"steps":["עמדו עם הרגליים ברוחב האגן והזרועות לצדי הגוף.","עשו צעד אחורה עם הרגל הימנית, תוך נחיתה על כרית כף הרגל.","כופפו את הברך השמאלית והורידו את הגוף לתנוחת לאנג'.","תוך כדי הירידה ללאנג', הושיטו את הידיים מעל הראש בו-זמנית.","עצרו לרגע בתחתית הלאנג', ולאחר מכן חזרו לתנוחת ההתחלה על ידי דחיפה דרך העקב השמאלי והבאת הרגל הימנית קדימה.","חזרו על התנועה בצד השני, צעדו אחורה עם הרגל השמאלית וכופפו את הברך הימנית.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Stand with your feet hip-width apart and your arms by your sides.","Take a step back with your right foot, landing on the ball of your foot.","Bend your left knee and lower your body into a lunge position.","As you lower into the lunge, simultaneously reach your arms overhead.","Pause for a moment at the bottom of the lunge, then return to the starting position by pushing through your left heel and bringing your right foot forward.","Repeat the movement on the other side, stepping back with your left foot and bending your right knee.","Continue alternating sides for the desired number of repetitions."],"mediaId":"ErqK3UL"},{"id":"edb-1389","name":"מתיחה","name_en":"posterior tibialis stretch","muscle":"legs","equipment":"rope","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings","quadriceps"],"steps":["שבו על הרצפה עם הרגליים מושטות לפניכם.","כרכו את החבל סביב כרית כף הרגל ואחזו בקצות החבל בידיים.","משכו בעדינות את החבל לכיוונכם, תוך כיפוף כף הרגל ומתיחת שריר השוק.","החזיקו את המתיחה במשך 20-30 שניות.","שחררו את המתח בחבל והרפו את כף הרגל.","חזרו על המתיחה ברגל השנייה."],"steps_en":["Sit on the ground with your legs extended in front of you.","Loop the rope around the ball of your foot and hold the ends of the rope with your hands.","Gently pull the rope towards you, flexing your foot and stretching your calf muscles.","Hold the stretch for 20-30 seconds.","Release the tension on the rope and relax your foot.","Repeat the stretch on the other leg."],"mediaId":"DEEqoI2"},{"id":"edb-3119","name":"סקוואט","name_en":"potty squat","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["quadriceps","glutes"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשהבהונות פונות מעט החוצה.","הורידו את הגוף על ידי כיפוף הברכיים ודחיפת האגן אחורה כאילו אתם יושבים על כיסא.","שמרו על החזה מורם והגב ישר לאורך כל התנועה.","רדו עד שהירכיים מקבילות לרצפה, או עד כמה שנוח לכם.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, toes pointing slightly outward.","Lower your body down by bending your knees and pushing your hips back as if you were sitting on a chair.","Keep your chest up and your back straight throughout the movement.","Lower yourself until your thighs are parallel to the ground or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"75Bgtjy"},{"id":"edb-3132","name":"סקוואט","name_en":"potty squat with support","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשהבהונות פונות מעט החוצה.","אחזו במשטח יציב, כמו כיסא או קיר, לצורך שיווי משקל.","הורידו את הגוף לתנוחת סקוואט על ידי כיפוף הברכיים ודחיפת האגן אחורה.","שמרו על החזה מורם והגב ישר לאורך כל התנועה.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, toes pointing slightly outward.","Hold onto a stable support, such as a chair or wall, for balance.","Lower your body down into a squat position by bending your knees and pushing your hips back.","Keep your chest up and your back straight throughout the movement.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"b63ZzGe"},{"id":"edb-0648","name":"קלין","name_en":"power clean","muscle":"legs","equipment":"barbell","target":"hamstrings","bodyPart":"upper legs","secondaryMuscles":["glutes","quadriceps","calves"],"steps":["התחילו כאשר המוט מונח על הרצפה לפניכם, והרגליים ברוחב הכתפיים.","התכופפו ואחזו את המוט באחיזה עליונה, מעט רחבה יותר מרוחב הכתפיים.","שמרו על הגב ישר והחזה מורם תוך כדי הרמת המוט מהרצפה, תוך יישור האגן והברכיים.","כאשר המוט מגיע לאמצע הירך, משכו אותו כלפי מעלה בפיצוץ כוח, תוך הרמת הכתפיים ומשיכת המרפקים גבוה הצידה.","כאשר המוט מגיע לנקודה הגבוהה ביותר שלו, צללו במהירות מתחתיו, סובבו את המרפקים ותפסו את המוט על הכתפיים בתנוחת סקוואט קדמי.","קומו עם המוט, תוך יישור מלא של האגן והברכיים.","הורידו את המוט בחזרה לתנוחת ההתחלה, תוך שמירה על שליטה במשקל לאורך כל התנועה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start with the barbell on the ground in front of you, with your feet shoulder-width apart.","Bend down and grip the barbell with an overhand grip, slightly wider than shoulder-width apart.","Keep your back straight and chest up as you lift the barbell off the ground, extending your hips and knees.","As the barbell reaches your mid-thigh, explosively pull it upwards, shrugging your shoulders and pulling your elbows high and to the sides.","As the barbell reaches its highest point, quickly drop underneath it, rotating your elbows around and catching the barbell on your shoulders in a front squat position.","Stand up with the barbell, fully extending your hips and knees.","Lower the barbell back down to the starting position, keeping control of the weight throughout the movement.","Repeat for the desired number of repetitions."],"mediaId":"SiWCcTN"},{"id":"edb-3665","name":"פלאנק","name_en":"power point plank","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["shoulders","triceps","glutes"],"steps":["התחילו בתנוחת פלאנק גבוה עם הידיים ישר מתחת לכתפיים והגוף בקו ישר מהראש ועד כפות הרגליים.","הפעילו את שרירי הליבה וכווצו את שרירי הישבן כדי לשמור על תנוחה יציבה.","הורידו את הגוף על האמות, יד אחת בכל פעם, תוך שמירה על קו ישר מהראש ועד לכפות הרגליים.","החזיקו בתנוחה זו למשך הזמן הרצוי, תוך שמירה על הפעלת שרירי הליבה והישבן.","כדי לחזור לתנוחת ההתחלה, דחפו דרך האמות והרימו את הגוף בחזרה לתנוחת פלאנק גבוה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a high plank position with your hands directly under your shoulders and your body in a straight line from head to toe.","Engage your core and squeeze your glutes to maintain a stable position.","Lower your body down onto your forearms, one arm at a time, maintaining a straight line from head to toe.","Hold this position for the desired amount of time, keeping your core and glutes engaged.","To return to the starting position, push through your forearms and lift your body back up into a high plank position.","Repeat for the desired number of repetitions."],"mediaId":"hCjGsRQ"},{"id":"edb-3203","name":"כפיפת בטן מלאה","name_en":"prisoner half sit-up (male)","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו את הידיים מאחורי הראש כשהמרפקים פונים החוצה.","תוך הפעלת שרירי הבטן, הרימו לאט את פלג הגוף העליון מהרצפה, בכיפוף קדימה עד שהגו נמצא בזווית של 45 מעלות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"mgejmGP"},{"id":"edb-1707","name":"פיתול בשכיבה על הבטן עם כדור פיזיו","name_en":"prone twist on stability ball","muscle":"core","equipment":"stability ball","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","lower back"],"steps":["התחילו בשכיבה על הבטן על כדור יציבות, כשהרגליים ברוחב הכתפיים והבהונות נוגעות ברצפה.","הניחו את הידיים מאחורי הראש או שלבו אותן על החזה.","הפעילו את שרירי הליבה והרימו לאט את פלג הגוף העליון מהכדור, תוך שמירה על הגב ישר.","סובבו את פלג הגוף העליון לצד אחד, תוך קירוב הכתף לאגן. שמרו על האגן והרגליים יציבים לאורך כל התנועה.","עצרו לרגע, ולאחר מכן חזרו למצב ההתחלתי.","חזרו על הסיבוב לצד השני.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Start by lying face down on a stability ball with your feet shoulder-width apart and your toes touching the ground.","Place your hands behind your head or cross them over your chest.","Engage your core muscles and slowly lift your upper body off the ball, keeping your back straight.","Rotate your torso to one side, bringing your shoulder towards your hip. Keep your hips and legs stable throughout the movement.","Pause for a moment, then return to the starting position.","Repeat the rotation to the other side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"1IG6gVF"},{"id":"edb-0651","name":"מתח אחיזה ניטרלית","name_en":"pull up (neutral grip)","muscle":"back","equipment":"body weight","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["הישארו תלויים ממתקן מתח באחיזה ניטרלית (כפות הידיים מופנות זו לזו) והידיים ישרות לגמרי.","הפעילו את ליבת הגוף וכווצו את השכמות זו לזו.","משכו את הגוף כלפי מעלה לכיוון המוט על ידי כיפוף המרפקים והורדתם לכיוון האגן.","המשיכו למשוך עד שהסנטר מעל המוט.","עצרו לרגע בשיא התנועה, ואז הורידו לאט ובשליטה את הגוף בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Hang from a pull-up bar with a neutral grip (palms facing each other) and your arms fully extended.","Engage your core and squeeze your shoulder blades together.","Pull your body up towards the bar by bending your elbows and driving your elbows down towards your hips.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position with control.","Repeat for the desired number of repetitions."],"mediaId":"0V2YQjW"},{"id":"edb-0650","name":"pull-in (on stability ball)","name_en":"pull-in (on stability ball)","muscle":"core","equipment":"stability ball","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["התחילו בישיבה על כדור היציבות כשכפות הרגליים שטוחות על הרצפה והברכיים כפופות בזווית של 90 מעלות.","הניחו את הידיים בצדי כדור היציבות לתמיכה.","הפעילו את שרירי הבטן וגלגלו לאט את האגן קדימה, תוך קירוב הברכיים לחזה.","עצרו לרגע בשיא התנועה, ולאחר מכן יישרו לאט את הרגליים בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by sitting on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Place your hands on the sides of the stability ball for support.","Engage your abs and slowly roll your hips forward, bringing your knees towards your chest.","Pause for a moment at the top of the movement, then slowly extend your legs back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"UQr48Oi"},{"id":"edb-0652","name":"מתח","name_en":"pull-up","muscle":"back","equipment":"body weight","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["הישארו תלויים ממתקן מתח כשכפות הידיים פונות הרחק מכם והידיים ישרות לגמרי.","הפעילו את ליבת הגוף וכווצו את השכמות זו לזו.","משכו את הגוף כלפי מעלה לכיוון המוט על ידי כיפוף המרפקים וקירוב החזה למוט.","עצרו בשיא התנועה, ולאחר מכן הורידו לאט את הגוף בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Hang from a pull-up bar with your palms facing away from you and your arms fully extended.","Engage your core and squeeze your shoulder blades together.","Pull your body up towards the bar by bending your elbows and bringing your chest towards the bar.","Pause at the top of the movement, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"lBDjFxJ"},{"id":"edb-1689","name":"push and pull bodyweight","name_en":"push and pull bodyweight","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","deltoids"],"steps":["התחילו בתנוחת שכיבת סמיכה עם הידיים מעט רחבות יותר מרוחב הכתפיים והגוף בקו ישר.","הורידו את החזה לכיוון הרצפה על ידי כיפוף המרפקים, תוך שמירה על הגוף ישר.","דחפו דרך כפות הידיים כדי ליישר את הידיים ולחזור לעמדת ההתחלה.","מתנוחת שכיבת הסמיכה, משכו את החזה לכיוון הרצפה על ידי כיפוף המרפקים, תוך שמירה על הגוף ישר.","דחפו דרך כפות הידיים כדי ליישר את הידיים ולחזור לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a push-up position with your hands slightly wider than shoulder-width apart and your body in a straight line.","Lower your chest towards the ground by bending your elbows, keeping your body straight.","Push through your palms to extend your arms and return to the starting position.","From the push-up position, pull your chest towards the ground by bending your elbows, keeping your body straight.","Push through your palms to extend your arms and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"wXvUZC8"},{"id":"edb-3638","name":"push to run","name_en":"push to run","muscle":"core","equipment":"body weight","target":"cardiovascular system","bodyPart":"cardio","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["התחילו בתנוחת שכיבת סמיכה עם הידיים ברוחב הכתפיים והגוף בקו ישר.","הורידו את החזה לכיוון הרצפה על ידי כיפוף המרפקים, תוך שמירה על הגוף ישר.","דחפו דרך הידיים כדי ליישר את הזרועות ולחזור לתנוחת ההתחלה.","הביאו במהירות ברך אחת לכיוון החזה, ולאחר מכן החליפו במהירות והביאו את הברך השנייה לכיוון החזה.","המשיכו להחליף ברכיים במהירות האפשרית תוך שמירה על טכניקה נכונה.","המשיכו למשך הזמן או מספר החזרות הרצוי."],"steps_en":["Start in a push-up position with your hands shoulder-width apart and your body in a straight line.","Lower your chest towards the ground by bending your elbows, keeping your body straight.","Push through your hands to extend your arms and return to the starting position.","Quickly bring one knee towards your chest, then quickly switch and bring the other knee towards your chest.","Continue alternating knees as fast as you can while maintaining good form.","Continue for the desired duration or number of repetitions."],"mediaId":"PrQbjvB"},{"id":"edb-1307","name":"שכיבת סמיכה על בוסו","name_en":"push up on bosu ball","muscle":"chest","equipment":"bosu ball","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders","core"],"steps":["הניחו את כדור הבוסו על הרצפה כשהצד השטוח פונה כלפי מעלה.","הכנסו לתנוחת שכיבת סמיכה עם הידיים על הקצוות החיצוניים של כדור הבוסו.","הפעילו את שרירי הליבה והורידו את הגוף לכיוון כדור הבוסו על ידי כיפוף המרפקים.","דחפו את עצמכם בחזרה לעמדת ההתחלה על ידי יישור הידיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Place the bosu ball on the ground with the flat side facing up.","Position yourself in a push-up position with your hands on the outer edges of the bosu ball.","Engage your core and lower your body down towards the bosu ball by bending your elbows.","Push yourself back up to the starting position by extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"wVompEp"},{"id":"edb-0662","name":"שכיבות סמיכה","name_en":"push-up","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","deltoids","core"],"steps":["התחילו בתנוחת פלאנק גבוה עם הידיים מעט רחבות יותר מרוחב הכתפיים והרגליים צמודות.","הפעילו את שרירי הליבה והורידו את הגוף לכיוון הרצפה על ידי כיפוף המרפקים, תוך שמירה על קו ישר.","עצרו לרגע כשהחזה קרוב לרצפה, ולאחר מכן דחפו את עצמכם בחזרה לתנוחת ההתחלה על ידי יישור הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a high plank position with your hands slightly wider than shoulder-width apart and your feet together.","Engage your core and lower your body towards the ground by bending your elbows, keeping your body in a straight line.","Pause for a moment when your chest is just above the ground, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"mediaId":"I4hDWkc"},{"id":"edb-0653","name":"שכיבת סמיכה על בוסו","name_en":"push-up (bosu ball)","muscle":"chest","equipment":"bosu ball","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders","core"],"steps":["הניחו את כדור הבוסו על הרצפה כשהצד השטוח פונה כלפי מעלה.","הכנסו לתנוחת שכיבת סמיכה עם הידיים על הקצוות החיצוניים של כדור הבוסו.","הפעילו את שרירי הליבה והורידו את הגוף לכיוון כדור הבוסו על ידי כיפוף המרפקים.","דחפו את עצמכם בחזרה לעמדת ההתחלה על ידי יישור הידיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Place the bosu ball on the ground with the flat side facing up.","Position yourself in a push-up position with your hands on the outer edges of the bosu ball.","Engage your core and lower your body down towards the bosu ball by bending your elbows.","Push yourself back up to the starting position by extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"2kr2lWy"},{"id":"edb-0655","name":"שכיבת סמיכה עם כדור פיזיו","name_en":"push-up (on stability ball)","muscle":"chest","equipment":"stability ball","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders","core"],"steps":["הניחו את כדור היציבות על הרצפה והתמקמו כשפניכם כלפי מטה והידיים על הכדור, ברוחב הכתפיים.","יישרו את הרגליים אחורה, תוך איזון על קצות האצבעות.","הפעילו את שרירי הליבה והורידו את החזה לכיוון הכדור על ידי כיפוף המרפקים, תוך שמירה על קו ישר.","עצרו לרגע בתחתית התנועה, ואז דחפו את עצמכם בחזרה למצב ההתחלתי על ידי יישור הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Place the stability ball on the ground and position yourself facing down with your hands on the ball, shoulder-width apart.","Extend your legs straight out behind you, balancing on your toes.","Engage your core and lower your chest towards the ball by bending your elbows, keeping your body in a straight line.","Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"mediaId":"Y4BRNQF"},{"id":"edb-0656","name":"שכיבת סמיכה עם כדור פיזיו","name_en":"push-up (on stability ball)","muscle":"chest","equipment":"stability ball","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders","core"],"steps":["הניחו את כדור היציבות על הרצפה והתמקמו כשפניכם כלפי מטה והידיים על הכדור, ברוחב הכתפיים.","יישרו את הרגליים אחורה, תוך איזון על קצות האצבעות.","הפעילו את שרירי הליבה והורידו את החזה לכיוון הכדור על ידי כיפוף המרפקים, תוך שמירה על קו ישר.","עצרו לרגע בתחתית התנועה, ואז דחפו את עצמכם בחזרה למצב ההתחלתי על ידי יישור הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Place the stability ball on the ground and position yourself facing down with your hands on the ball, shoulder-width apart.","Extend your legs straight out behind you, balancing on your toes.","Engage your core and lower your chest towards the ball by bending your elbows, keeping your body in a straight line.","Pause for a moment at the bottom, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"mediaId":"tgryw5Y"},{"id":"edb-0659","name":"שכיבת סמיכה","name_en":"push-up (wall)","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","deltoids"],"steps":["עמדו מול קיר, במרחק של אורך זרוע בערך.","הניחו את הידיים על הקיר בגובה הכתפיים, מעט רחבות יותר מרוחב הכתפיים.","צעדו אחורה מספר צעדים, תוך שמירה על הגוף ישר והרגליים ברוחב האגן.","כופפו את המרפקים והורידו את החזה לכיוון הקיר, תוך שמירה על קו ישר.","דחפו בחזרה לתנוחת ההתחלה, תוך יישור הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand facing a wall, about arm's length away.","Place your hands on the wall at shoulder height, slightly wider than shoulder-width apart.","Step back a few feet, keeping your body straight and your feet hip-width apart.","Bend your elbows and lower your chest towards the wall, keeping your body in a straight line.","Push back up to the starting position, straightening your arms.","Repeat for the desired number of repetitions."],"mediaId":"LEH9jxP"},{"id":"edb-0658","name":"שכיבת סמיכה","name_en":"push-up (wall) v. 2","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["עמדו מול קיר, במרחק של אורך זרוע בערך.","הניחו את הידיים על הקיר בגובה הכתפיים, מעט רחבות יותר מרוחב הכתפיים.","צעדו אחורה עם הרגליים, תוך שמירה עליהן ברוחב האגן.","הפעילו את שרירי הליבה ושמרו על קו ישר מהראש ועד העקבים.","כופפו את המרפקים והורידו את החזה לכיוון הקיר, תוך שמירה על הגוף ישר.","עצרו לרגע, ולאחר מכן דחפו את עצמכם בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand facing a wall, about arm's length away.","Place your hands on the wall at shoulder height, slightly wider than shoulder-width apart.","Step back with your feet, keeping them hip-width apart.","Engage your core and keep your body in a straight line from head to heels.","Bend your elbows and lower your chest towards the wall, keeping your body straight.","Pause for a moment, then push yourself back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"NCmbLCw"},{"id":"edb-0660","name":"שכיבת סמיכה אחיזה צרה עם משקולות","name_en":"push-up close-grip off dumbbell","muscle":"triceps","equipment":"dumbbell","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["התחילו בתנוחת שכיבת סמיכה עם הידיים קרובות זו לזו, ישר מתחת לכתפיים.","אחזו משקולת יד בכל יד, כשהן מונחות על הרצפה.","הורידו את הגוף לכיוון הרצפה על ידי כיפוף המרפקים, כשהם צמודים לגוף.","דחפו דרך כפות הידיים כדי ליישר את הידיים ולחזור לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a push-up position with your hands placed close together, directly under your shoulders.","Hold a dumbbell in each hand, resting them on the ground.","Lower your body towards the ground by bending your elbows, keeping them close to your sides.","Push through your palms to extend your arms and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"KZXAtKQ"},{"id":"edb-0661","name":"שכיבת סמיכה","name_en":"push-up inside leg kick","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves","core"],"steps":["התחילו בתנוחת שכיבת סמיכה עם הידיים ברוחב מעט גדול מרוחב הכתפיים והרגליים צמודות.","הורידו את הגוף לכיוון הרצפה על ידי כיפוף המרפקים, תוך שמירה על הגב ישר ושרירי הליבה מופעלים.","תוך כדי הדחיפה חזרה למעלה, הרימו רגל אחת מהרצפה ובעטו אותה הצידה, תוך שמירה עליה ישרה.","הורידו את הרגל בחזרה וחזרו על שכיבת הסמיכה, ולאחר מכן החליפו לרגל השנייה.","המשיכו להחליף בעיטות רגליים עם כל חזרה של שכיבת סמיכה."],"steps_en":["Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together.","Lower your body towards the ground by bending your elbows, keeping your back straight and your core engaged.","As you push back up, lift one leg off the ground and kick it out to the side, keeping it straight.","Lower your leg back down and repeat the push-up, then switch to the other leg.","Continue alternating leg kicks with each push-up repetition."],"mediaId":"0br45wL"},{"id":"edb-0663","name":"שכיבת סמיכה עם כדור כוח","name_en":"push-up medicine ball","muscle":"chest","equipment":"medicine ball","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders","core"],"steps":["התחילו בתנוחת פלאנק גבוה עם הידיים על כדור הרפואי, ברוחב הכתפיים.","הפעילו את שרירי הליבה והורידו את הגוף לכיוון הרצפה על ידי כיפוף המרפקים, תוך שמירה על הגב ישר.","דחפו דרך כפות הידיים כדי ליישר את הידיים ולחזור לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a high plank position with your hands on the medicine ball, shoulder-width apart.","Engage your core and lower your body towards the ground by bending your elbows, keeping your back straight.","Push through your palms to extend your arms and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"W8KAlkI"},{"id":"edb-1467","name":"שכיבת סמיכה","name_en":"push-up on lower arms","muscle":"triceps","equipment":"body weight","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["התחילו בתנוחת פלאנק עם האמות על הרצפה והמרפקים ישר מתחת לכתפיים.","הפעילו את שרירי הליבה ושמרו על הגוף בקו ישר מהראש עד לכפות הרגליים.","הורידו את החזה לכיוון הרצפה על ידי כיפוף המרפקים, כשהם צמודים לגוף.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו את עצמכם בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a plank position with your forearms on the ground and elbows directly below your shoulders.","Engage your core and keep your body in a straight line from head to toe.","Lower your chest towards the ground by bending your elbows, keeping them close to your body.","Pause for a moment at the bottom, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"4Jt8QsQ"},{"id":"edb-3145","name":"שכיבת סמיכה","name_en":"push-up plus","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["התחילו בתנוחת פלאנק גבוה עם הידיים מעט רחבות יותר מרוחב הכתפיים והגוף בקו ישר מהראש ועד העקבים.","הורידו את הגוף לכיוון הרצפה על ידי כיפוף המרפקים, כשהם צמודים לגוף.","כאשר החזה קרוב לרצפה, דחפו דרך הידיים כדי ליישר את הזרועות ולהרים את פלג הגוף העליון.","בשיא התנועה, הרחיקו את השכמות זו מזו על ידי דחיפת הגב העליון לכיוון התקרה.","עצרו לרגע, ולאחר מכן הפכו את התנועה על ידי קירוב השכמות זו לזו והורדת הגוף בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a high plank position with your hands slightly wider than shoulder-width apart and your body in a straight line from head to heels.","Lower your body towards the ground by bending your elbows, keeping them close to your sides.","Once your chest is just above the ground, push through your hands to extend your arms and lift your upper body up.","At the top of the movement, protract your shoulder blades by pushing your upper back towards the ceiling.","Pause for a moment, then reverse the movement by retracting your shoulder blades and lowering your body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"pvBMLHA"},{"id":"edb-0664","name":"שכיבת סמיכה צדי","name_en":"push-up to side plank","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["shoulders","chest","triceps"],"steps":["התחילו בתנוחת שכיבת סמיכה עם הידיים ברוחב הכתפיים והגוף בקו ישר.","הורידו את הגוף לכיוון הרצפה על ידי כיפוף המרפקים, תוך הפעלת שרירי הליבה.","דחפו בחזרה למעלה לעמדת ההתחלה.","העבירו את המשקל ליד השמאלית וסובבו את הגוף ימינה, תוך הרמת הזרוע הימנית לכיוון התקרה.","החזיקו את תנוחת הפלאנק הצידי למספר שניות, ולאחר מכן חזרו לתנוחת ההתחלה.","חזרו על שכיבת הסמיכה והפלאנק הצידי בצד הנגדי.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Start in a push-up position with your hands shoulder-width apart and your body in a straight line.","Lower your body towards the ground by bending your elbows, keeping your core engaged.","Push back up to the starting position.","Shift your weight onto your left hand and rotate your body to the right, lifting your right arm towards the ceiling.","Hold the side plank position for a few seconds, then return to the starting position.","Repeat the push-up and side plank on the opposite side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"KhHJ338"},{"id":"edb-3533","name":"quads","name_en":"quads","muscle":"legs","equipment":"body weight","target":"quads","bodyPart":"upper legs","secondaryMuscles":["hamstrings","glutes"],"steps":["עמדו עם הרגליים ברוחב הכתפיים.","הורידו את הגוף על ידי כיפוף הברכיים ודחיפת האגן אחורה כאילו אתם יושבים על כיסא.","שמרו על החזה מורם והגב ישר.","רדו עד שהירכיים מקבילות לרצפה.","דחפו דרך העקבים כדי לחזור לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart.","Lower your body by bending your knees and pushing your hips back as if sitting on a chair.","Keep your chest up and your back straight.","Lower yourself until your thighs are parallel to the ground.","Push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"6YUfHPL"},{"id":"edb-3201","name":"כפיפת בטן מלאה","name_en":"quarter sit-up","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו את הידיים מאחורי הראש כשהמרפקים פונים החוצה.","תוך הפעלת שרירי הבטן, הרימו לאט את פלג הגוף העליון מהרצפה, בכיפוף קדימה עד שהגו נמצא בזווית של 45 מעלות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"enxnJcM"},{"id":"edb-3552","name":"quick feet v. 2","name_en":"quick feet v. 2","muscle":"legs","equipment":"body weight","target":"quads","bodyPart":"upper legs","secondaryMuscles":["calves","hamstrings"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים והזרועות לצידי הגוף.","התחילו על ידי הזזת הרגליים במהירות למעלה ולמטה, כאילו אתם רצים במקום.","שמרו על תנועות מהירות וקלילות, תוך התמקדות בהישארות על קצות כפות הרגליים.","המשיכו למשך הזמן או מספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your arms by your sides.","Begin by rapidly moving your feet up and down, as if you were running in place.","Keep your movements quick and light, focusing on staying on the balls of your feet.","Continue for the desired duration or number of repetitions."],"mediaId":"mweqJin"},{"id":"edb-0666","name":"שכיבת סמיכה ביד אחת","name_en":"raise single arm push-up","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders","core"],"steps":["התחילו בתנוחת שכיבת סמיכה עם הידיים ברוחב מעט גדול מרוחב הכתפיים והרגליים צמודות.","הושיטו יד אחת ישר הצידה, במקביל לרצפה.","הורידו את הגוף לכיוון הרצפה על ידי כיפוף המרפקים, תוך שמירה על הגב ישר ושרירי הליבה מכווצים.","דחפו בחזרה לתנוחת ההתחלה, תוך שימוש בשרירי החזה כדי להרים את הגוף.","חזרו כשהזרוע השנייה מושטת."],"steps_en":["Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together.","Extend one arm straight out to the side, parallel to the ground.","Lower your body towards the ground by bending your elbows, keeping your back straight and core engaged.","Push back up to the starting position, using your chest muscles to lift your body.","Repeat with the other arm extended."],"mediaId":"13TpY4H"},{"id":"edb-0668","name":"גשר בשיפוע שלילי אחורי","name_en":"rear decline bridge","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","lower back"],"steps":["שכבו על הגב עם כפות הרגליים שטוחות על הרצפה והברכיים כפופות.","הניחו את הזרועות לצדי הגוף, כפות הידיים פונות מטה.","הפעילו את שרירי הישבן והירך האחורית, והרימו את האגן מהרצפה עד שהגוף יוצר קו ישר מהברכיים ועד הכתפיים.","החזיקו בתנוחה זו למספר שניות, ולאחר מכן הורידו לאט את האגן בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie on your back with your feet flat on the ground and your knees bent.","Place your arms by your sides with your palms facing down.","Engage your glutes and hamstrings, and lift your hips off the ground until your body forms a straight line from your knees to your shoulders.","Hold this position for a few seconds, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"UpAlold"},{"id":"edb-0669","name":"מתיחה אחורי","name_en":"rear deltoid stretch","muscle":"shoulders","equipment":"body weight","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","rhomboids"],"steps":["עמדו זקוף עם הרגליים ברוחב הכתפיים.","יישרו את הזרוע הימנית לרוחב החזה, והניחו את היד השמאלית על המרפק הימני.","משכו בעדינות את הזרוע הימנית לכיוון הכתף השמאלית, תוך הרגשת מתיחה בכתף הימנית.","החזיקו את המתיחה במשך 15-30 שניות, ולאחר מכן שחררו.","חזרו על התרגיל בצד השני."],"steps_en":["Stand tall with your feet shoulder-width apart.","Extend your right arm across your chest, placing your left hand on your right elbow.","Gently pull your right arm towards your left shoulder, feeling a stretch in your right shoulder.","Hold the stretch for 15-30 seconds, then release.","Repeat on the other side."],"mediaId":"xifhB5W"},{"id":"edb-0670","name":"מתח אחורי","name_en":"rear pull-up","muscle":"back","equipment":"body weight","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["אחזו במוט המתח באחיזה עליונה, מעט רחב יותר מרוחב הכתפיים.","היתלו מהמוט עם הזרועות ישרות לחלוטין והגוף ישר.","הפעילו את שרירי הגב ומשכו את הגוף כלפי מעלה לכיוון המוט, כשהמרפקים צמודים לגוף.","המשיכו למשוך עד שהסנטר מעל המוט.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הגוף בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Grab the pull-up bar with an overhand grip, slightly wider than shoulder-width apart.","Hang from the bar with your arms fully extended and your body straight.","Engage your back muscles and pull your body up towards the bar, keeping your elbows close to your body.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"CbFSYC1"},{"id":"edb-1582","name":"reclining big toe pose with rope","name_en":"reclining big toe pose with rope","muscle":"legs","equipment":"rope","target":"hamstrings","bodyPart":"upper legs","secondaryMuscles":["calves","glutes"],"steps":["שכבו על הגב עם הרגליים ישרות והידיים לצדי הגוף.","כרכו את החבל סביב כרית כף הרגל הימנית ואחזו את קצות החבל בידיים.","הרימו לאט את הרגל הימנית לכיוון החזה, תוך שמירה על הברך ישרה וכף הרגל כפופה כלפי מעלה.","החזיקו את המתיחה למספר שניות, ולאחר מכן הורידו לאט את הרגל בחזרה לתנוחת ההתחלה.","חזרו על התנועה עם הרגל השמאלית.","המשיכו להחליף רגליים למספר החזרות הרצוי."],"steps_en":["Lie on your back with your legs extended and your arms by your sides.","Loop the rope around the ball of your right foot and hold the ends of the rope with your hands.","Slowly raise your right leg towards your chest, keeping your knee straight and your foot flexed.","Hold the stretch for a few seconds, then slowly lower your leg back down to the starting position.","Repeat with your left leg.","Continue alternating legs for the desired number of repetitions."],"mediaId":"K5xgdvI"},{"id":"edb-3236","name":"resistance band hip thrusts on knees (female)","name_en":"resistance band hip thrusts on knees (female)","muscle":"glutes","equipment":"resistance band","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps"],"steps":["התחילו בכריעה על הרצפה עם הברכיים ברוחב האגן וכפות הרגליים כפופות.","כרכו את גומיית ההתנגדות סביב הירכיים, ממש מעל הברכיים.","הניחו את הידיים על האגן או הושיטו אותן לפניכם לשם שיווי משקל.","הפעילו את שרירי הישבן וליבת הגוף.","דחפו את האגן קדימה וכווצו את שרירי הישבן תוך הרמת הברכיים מהרצפה, יישור האגן עד שהירכיים מקבילות לרצפה.","החזיקו בתנוחה לרגע, ולאחר מכן הורידו לאט את הברכיים בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by kneeling on the ground with your knees hip-width apart and your feet flexed.","Wrap the resistance band around your thighs, just above your knees.","Place your hands on your hips or extend them out in front of you for balance.","Engage your glutes and core muscles.","Push your hips forward and squeeze your glutes as you lift your knees off the ground, extending your hips until your thighs are parallel to the ground.","Hold the position for a moment, then slowly lower your knees back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Pjbc0Kt"},{"id":"edb-3007","name":"פשיטת ברך עם גומיית התנגדות","name_en":"resistance band leg extension","muscle":"legs","equipment":"resistance band","target":"quads","bodyPart":"upper legs","secondaryMuscles":["hamstrings"],"steps":["חברו את גומיית ההתנגדות לנקודת עיגון יציבה והדקו אותה סביב הקרסול.","עמדו מול נקודת העיגון עם הרגליים ברוחב הכתפיים.","תוך שמירה על שרירי הליבה מופעלים ופלג הגוף העליון יציב, יישרו את הרגל קדימה.","עצרו לרגע בשיא התנועה, ולאחר מכן החזירו לאט את הרגל לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו רגליים."],"steps_en":["Attach the resistance band to a sturdy anchor point and secure it around your ankle.","Stand facing the anchor point with your feet shoulder-width apart.","Keeping your core engaged and your upper body stable, extend your leg straight out in front of you.","Pause for a moment at the top, then slowly return your leg to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"mediaId":"Y1MsI1l"},{"id":"edb-3123","name":"כפיפת מרפק בישיבה עם גומיית התנגדות","name_en":"resistance band seated biceps curl","muscle":"biceps","equipment":"resistance band","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על כיסא או ספסל כשהגב ישר וכפות הרגליים שטוחות על הרצפה.","אחזו את גומיית ההתנגדות באחיזה תחתונה, כפות הידיים פונות כלפי מעלה, והזרועות ישרות לצדי הגוף.","תוך שמירה על הזרועות העליונות ללא תנועה, נשפו והרימו את גומיית ההתנגדות כלפי מעלה לכיוון הכתפיים.","עצרו לרגע בשיא התנועה, תוך כיווץ שרירי הביצפס.","שאפו והורידו לאט את גומיית ההתנגדות בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a chair or bench with your back straight and feet flat on the ground.","Hold the resistance band with an underhand grip, palms facing up, and arms extended down by your sides.","Keeping your upper arms stationary, exhale and curl the resistance band up towards your shoulders.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the resistance band back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"XFc3vpY"},{"id":"edb-3124","name":"לחיצת חזה בישיבה עם גומיית התנגדות","name_en":"resistance band seated chest press","muscle":"chest","equipment":"resistance band","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["שבו על כיסא או ספסל כשהגב ישר וכפות הרגליים שטוחות על הרצפה.","אחזו את ידיות גומיית ההתנגדות בכל יד, כשכפות הידיים פונות כלפי מטה והמרפקים כפופים בזווית של 90 מעלות.","יישרו את הזרועות קדימה, תוך דחיפת גומיית ההתנגדות הרחק מהחזה.","עצרו לרגע בסוף התנועה, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a chair or bench with your back straight and feet flat on the ground.","Hold the resistance band handles in each hand, with your palms facing down and elbows bent at a 90-degree angle.","Extend your arms forward, pushing the resistance band away from your chest.","Pause for a moment at the end of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"4x5Okof"},{"id":"edb-3006","name":"resistance band seated hip abduction","name_en":"resistance band seated hip abduction","muscle":"glutes","equipment":"resistance band","target":"abductors","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings"],"steps":["שבו על כיסא או ספסל כשהגב ישר וכפות הרגליים שטוחות על הרצפה.","כרכו את גומיית ההתנגדות סביב הירכיים, ממש מעל הברכיים.","הניחו את הידיים בצדי הכיסא או הספסל לתמיכה.","הפעילו את שרירי המפשק (שרירי הירך החיצוניים) ודחפו לאט את הברכיים החוצה, כנגד ההתנגדות של הגומייה.","עצרו לרגע בסוף התנועה, ולאחר מכן קרבו לאט את הברכיים בחזרה זו לזו.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a chair or bench with your back straight and feet flat on the ground.","Wrap the resistance band around your thighs, just above your knees.","Place your hands on the sides of the chair or bench for support.","Engage your abductors (outer thigh muscles) and slowly push your knees apart, against the resistance of the band.","Pause for a moment at the end of the movement, then slowly bring your knees back together.","Repeat for the desired number of repetitions."],"mediaId":"0xDpB4L"},{"id":"edb-3122","name":"לחיצת כתפיים בישיבה עם גומיית התנגדות","name_en":"resistance band seated shoulder press","muscle":"shoulders","equipment":"resistance band","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["שבו על כיסא או ספסל כשהגב ישר וכפות הרגליים שטוחות על הרצפה.","אחזו את גומיית ההתנגדות בשתי הידיים, כפות הידיים פונות קדימה, והביאו אותה לגובה הכתפיים.","לחצו את הגומייה מעל הראש, תוך יישור מלא של הזרועות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הגומייה בחזרה לגובה הכתפיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a chair or bench with your back straight and feet flat on the ground.","Hold the resistance band with both hands, palms facing forward, and bring it up to shoulder level.","Press the band overhead, extending your arms fully.","Pause for a moment at the top, then slowly lower the band back down to shoulder level.","Repeat for the desired number of repetitions."],"mediaId":"S93zLTG"},{"id":"edb-3144","name":"חתירה בישיבה עם גומיית התנגדות","name_en":"resistance band seated straight back row","muscle":"back","equipment":"resistance band","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","shoulders"],"steps":["שבו על הרצפה עם הרגליים ישרות וכרכו את גומיית ההתנגדות סביב כפות הרגליים.","אחזו את קצות גומיית ההתנגדות בידיים, כשכפות הידיים פונות זו לזו.","שמרו על הגב ישר והישענו מעט לאחור, תוך הפעלת שרירי הליבה.","משכו את גומיית ההתנגדות לכיוון החזה, תוך כיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה, ולאחר מכן שחררו לאט את המתח וחזרו למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the floor with your legs extended and loop the resistance band around your feet.","Hold the ends of the resistance band with your hands, palms facing each other.","Keep your back straight and lean slightly back, engaging your core.","Pull the resistance band towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Nu7jqFE"},{"id":"edb-0872","name":"כפיפת בטן הפוכה","name_en":"reverse crunch","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שכבו שטוח על הגב עם הזרועות ישרות לצדי הגוף.","כופפו את הברכיים והרימו את כפות הרגליים מהרצפה, תוך הבאת הירכיים למאונך לרצפה.","כווצו את שרירי הבטן וגלגלו את האגן מהרצפה, תוך קירוב הברכיים לחזה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הירכיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your arms extended along your sides.","Bend your knees and lift your feet off the ground, bringing your thighs perpendicular to the floor.","Contract your abs and curl your hips off the floor, bringing your knees towards your chest.","Pause for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"nCU1Ekp"},{"id":"edb-0672","name":"מקבילים הפוך","name_en":"reverse dip","muscle":"triceps","equipment":"body weight","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["התמקמו בין שני מוטות מקבילים עם הזרועות ישרות לגמרי והגוף ישר.","הורידו את הגוף על ידי כיפוף המרפקים עד שהזרועות העליונות מקבילות לרצפה.","עצרו לרגע, ואז דחפו את עצמכם בחזרה למצב ההתחלתי על ידי יישור הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Position yourself between two parallel bars with your arms fully extended and your body straight.","Lower your body by bending your elbows until your upper arms are parallel to the ground.","Pause for a moment, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"mediaId":"NZ5Qqkz"},{"id":"edb-0673","name":"פולי עליון אחיזה הפוכה","name_en":"reverse grip machine lat pulldown","muscle":"back","equipment":"leverage machine","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["כווננו את גובה המושב והתמקמו על המכשיר כשהברכיים מתחת לכריות וכפות הרגליים שטוחות על הקרקע.","אחזו בידיות באחיזת יד תחתונה, ברוחב מעט גדול מרוחב הכתפיים.","שבו בישיבה זקופה עם החזה קדימה והכתפיים לאחור, תוך שמירה על קשת קלה בגב התחתון.","משכו את הידיות כלפי מטה לכיוון החזה, תוך כיווץ השכמות זו לזו.","עצרו לרגע בתחתית התנועה, ולאחר מכן שחררו לאט את הידיות חזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself on the machine with your knees under the pads and your feet flat on the ground.","Grasp the handles with an underhand grip, slightly wider than shoulder-width apart.","Sit upright with your chest out and shoulders back, maintaining a slight arch in your lower back.","Pull the handles down towards your chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the handles back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ecpY0rH"},{"id":"edb-0674","name":"מתח אחיזה הפוכה","name_en":"reverse grip pull-up","muscle":"back","equipment":"body weight","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["אחזו את מתקן המתח באחיזה תחתונה, כשהידיים ברוחב הכתפיים.","היתלו מהמוט עם הזרועות ישרות לחלוטין והגוף ישר.","הפעילו את שרירי הגב ומשכו את הגוף כלפי מעלה לכיוון המוט, תוך הובלה עם החזה.","המשיכו למשוך עד שהסנטר מעל המוט.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הגוף בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Grab the pull-up bar with an underhand grip, hands shoulder-width apart.","Hang from the bar with your arms fully extended and your body straight.","Engage your back muscles and pull your body up towards the bar, leading with your chest.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"YAk5dIw"},{"id":"edb-0675","name":"פשיטה הפוך עם כדור פיזיו","name_en":"reverse hyper extension (on stability ball)","muscle":"glutes","equipment":"stability ball","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","lower back"],"steps":["שכבו על הבטן על כדור יציבות כשהאגן נשען על הכדור והרגליים ישרות מאחור.","הניחו את הידיים על הרצפה לפניכם לשם יציבות.","תוך הפעלת שרירי הישבן והירך האחורית, הרימו את הרגליים כלפי התקרה כמה שיותר גבוה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie face down on a stability ball with your hips resting on the ball and your legs extended straight behind you.","Place your hands on the ground in front of you for stability.","Engaging your glutes and hamstrings, lift your legs up towards the ceiling as high as you can.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"vM5YS2g"},{"id":"edb-1423","name":"reverse hyper on flat bench","name_en":"reverse hyper on flat bench","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","lower back"],"steps":["שכבו על הבטן על ספסל שטוח כשהאגן בקצה והרגליים תלויות מהספסל.","אחזו בספסל לשם יציבות.","תוך שמירה על הרגליים ישרות, הרימו אותן כלפי התקרה כמה שיותר גבוה.","כווצו את שרירי הישבן בשיא התנועה.","הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie face down on a flat bench with your hips at the edge and your legs hanging off the bench.","Hold onto the bench for stability.","Keeping your legs straight, raise them up towards the ceiling as high as you can.","Squeeze your glutes at the top of the movement.","Slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"OrETs32"},{"id":"edb-3663","name":"פלאנק הפוך","name_en":"reverse plank with leg lift","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["glutes","hamstrings","shoulders"],"steps":["שבו על הרצפה עם הרגליים ישרות לפניכם והידיים נשענות על הרצפה מאחור, כשהאצבעות פונות לכיוון הרגליים.","לחצו דרך הידיים והרימו את האגן מהרצפה, תוך כניסה לתנוחת פלאנק הפוך.","הפעילו את שרירי הליבה והרימו רגל אחת מהרצפה, תוך יישורה כלפי מעלה לכיוון התקרה.","החזיקו לרגע, ולאחר מכן הורידו את הרגל בחזרה.","חזרו עם הרגל השנייה.","המשיכו להחליף רגליים למספר החזרות הרצוי."],"steps_en":["Sit on the ground with your legs extended in front of you and your hands resting on the ground behind you, fingers pointing towards your feet.","Press through your hands and lift your hips off the ground, coming into a reverse plank position.","Engage your core and lift one leg off the ground, extending it straight up towards the ceiling.","Hold for a moment, then lower your leg back down.","Repeat with the other leg.","Continue alternating legs for the desired number of repetitions."],"mediaId":"tFToB7l"},{"id":"edb-0677","name":"ring dips","name_en":"ring dips","muscle":"triceps","equipment":"body weight","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["התחילו בתלייה מהטבעות עם הזרועות ישרות לגמרי והגוף ישר.","הורידו את הגוף על ידי כיפוף המרפקים עד שהכתפיים מתחת למרפקים.","דחפו את עצמכם חזרה למצב ההתחלתי על ידי יישור הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by hanging from the rings with your arms fully extended and your body straight.","Lower your body by bending your elbows until your shoulders are below your elbows.","Push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"mediaId":"ezTvXcr"},{"id":"edb-2571","name":"מתיחה","name_en":"rocking frog stretch","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps"],"steps":["התחילו בכריעה על הרצפה עם הברכיים ברוחב האגן.","הניחו את הידיים על הרצפה לפניכם לתמיכה.","הישענו לאט קדימה, תוך העברת המשקל לידיים ויישור הרגליים מאחור.","שמרו על הגב ישר והפעילו את שרירי הישבן תוך דחיפת האגן אחורה ולמעלה לכיוון התקרה.","החזיקו בתנוחה זו למספר שניות, תוך הרגשת מתיחה בשרירי הישבן.","חזרו לאט לתנוחת ההתחלה על ידי כיפוף הברכיים והורדת האגן בחזרה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by kneeling on the ground with your knees hip-width apart.","Place your hands on the ground in front of you for support.","Slowly lean forward, shifting your weight onto your hands and extending your legs behind you.","Keep your back straight and engage your glutes as you push your hips back and up towards the ceiling.","Hold this position for a few seconds, feeling a stretch in your glutes.","Slowly return to the starting position by bending your knees and lowering your hips back down.","Repeat for the desired number of repetitions."],"mediaId":"2Dk4xQV"},{"id":"edb-0678","name":"מתח","name_en":"rocky pull-up pulldown","muscle":"back","equipment":"body weight","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["עמדו מול מתקן מתח עם הרגליים ברוחב הכתפיים.","הושיטו יד למעלה ואחזו את המוט באחיזה עליונה, מעט רחב יותר מרוחב הכתפיים.","היתלו מהמוט עם הזרועות ישרות לחלוטין והגוף ישר.","הפעילו את שרירי הגב ומשכו את הגוף כלפי מעלה לכיוון המוט, תוך הובלה עם החזה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הגוף בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand in front of a pull-up bar with your feet shoulder-width apart.","Reach up and grab the bar with an overhand grip, slightly wider than shoulder-width apart.","Hang from the bar with your arms fully extended and your body straight.","Engage your back muscles and pull your body up towards the bar, leading with your chest.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"cQ19bBP"},{"id":"edb-2208","name":"מתיחה עם גלגלת","name_en":"roller back stretch","muscle":"back","equipment":"roller","target":"spine","bodyPart":"back","secondaryMuscles":["hamstrings","glutes"],"steps":["התחילו בישיבה על הרצפה עם הרגליים ישרות לפניכם.","הניחו את הגליל בניצב לגוף, ממש מתחת לישבן.","גלגלו לאט את הגוף אחורה, תוך שהגליל נע כלפי מעלה על הגב.","המשיכו לגלגל עד שהגליל מגיע לחלק העליון של הגב.","עצרו לרגע, ולאחר מכן גלגלו לאט בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by sitting on the ground with your legs extended in front of you.","Place the roller perpendicular to your body, just below your glutes.","Slowly roll your body backwards, allowing the roller to move up your back.","Continue rolling until the roller reaches your upper back.","Pause for a moment, then slowly roll back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"isofgzg"},{"id":"edb-2204","name":"roller body saw","name_en":"roller body saw","muscle":"core","equipment":"roller","target":"abs","bodyPart":"waist","secondaryMuscles":["shoulders","triceps","core"],"steps":["התחילו בתנוחת פלאנק עם האמות על הגליל והגוף בקו ישר.","הפעילו את שרירי הליבה וגלגלו לאט את הגליל קדימה, תוך יישור הגוף כמה שיותר רחוק תוך שמירה על שליטה.","עצרו לרגע בנקודה הרחוקה ביותר, ולאחר מכן גלגלו לאט את הגליל בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a plank position with your forearms on the roller and your body in a straight line.","Engage your core and slowly roll the roller forward, extending your body as far as you can while maintaining control.","Pause for a moment at the furthest point, then slowly roll the roller back towards your starting position.","Repeat for the desired number of repetitions."],"mediaId":"XeMvLgE"},{"id":"edb-2205","name":"מתיחה עם גלגלת","name_en":"roller hip lat stretch","muscle":"glutes","equipment":"roller","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps"],"steps":["התחילו בכריעה על הרצפה כשהגליל ממוקם מתחת לאגן.","הניחו את הידיים על הגליל לתמיכה.","גלגלו לאט את הגליל קדימה, תוך יישור האגן ומתיחת שרירי הישבן.","החזיקו את המתיחה למספר שניות, ולאחר מכן גלגלו בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by kneeling on the ground with the roller positioned under your hips.","Place your hands on the roller for support.","Slowly roll the roller forward, extending your hips and stretching your glutes.","Hold the stretch for a few seconds, then roll back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"0L2KwtI"},{"id":"edb-2202","name":"מתיחה עם גלגלת","name_en":"roller hip stretch","muscle":"glutes","equipment":"roller","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps"],"steps":["התחילו בישיבה על הרצפה עם הרגליים ישרות לפניכם.","הניחו את הגליל מתחת לישבן, ממש מעל הברכיים.","הישענו לאחור והניחו את הידיים על הרצפה מאחור לתמיכה.","הפעילו את שרירי הישבן וגלגלו לאט את הגליל קדימה, תוך כיפוף הברכיים וקירובן לחזה.","עצרו לרגע בסוף התנועה, תוך הרגשת מתיחה בשרירי הישבן.","גלגלו לאט את הגליל בחזרה לתנוחת ההתחלה, תוך יישור הרגליים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by sitting on the ground with your legs extended in front of you.","Place the roller under your glutes, just above your knees.","Lean back and place your hands on the ground behind you for support.","Engage your glutes and slowly roll the roller forward, bending your knees and bringing them towards your chest.","Pause for a moment at the end of the movement, feeling a stretch in your glutes.","Slowly roll the roller back to the starting position, extending your legs.","Repeat for the desired number of repetitions."],"mediaId":"oMypNrz"},{"id":"edb-2206","name":"כפיפת בטן הפוכה עם גלגלת","name_en":"roller reverse crunch","muscle":"core","equipment":"roller","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שכבו שטוח על הגב עם הזרועות ישרות מעל הראש והרגליים ישרות לפניכם.","הניחו את הגליל בין כפות הרגליים ואחזו אותו עם האצבעות.","תוך הפעלת שרירי הבטן, הרימו את הרגליים מהרצפה וקפלו את הברכיים לכיוון החזה, תוך גלגול הגליל לכיוון הגוף.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגליים בחזרה לתנוחת ההתחלה, תוך גלגול הגליל הרחק מהגוף.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your arms extended straight above your head and your legs straight out in front of you.","Place the roller between your feet and grip it with your toes.","Engaging your abs, lift your legs off the ground and curl your knees towards your chest, rolling the roller towards your body.","Pause for a moment at the top, then slowly lower your legs back down to the starting position, rolling the roller away from your body.","Repeat for the desired number of repetitions."],"mediaId":"SKXQAx3"},{"id":"edb-2203","name":"roller seated shoulder flexor depresor retractor","name_en":"roller seated shoulder flexor depresor retractor","muscle":"chest","equipment":"roller","target":"pectorals","bodyPart":"chest","secondaryMuscles":["deltoids","triceps"],"steps":["שבו על משטח שטוח עם הרגליים ישרות לפניכם.","אחזו את הגליל בשתי הידיים, כשכפות הידיים פונות כלפי מטה, והניחו אותו על הירכיים.","הישענו מעט קדימה וגלגלו את הגליל הרחק מהגוף, תוך יישור הזרועות לפניכם.","עצרו לרגע, ולאחר מכן גלגלו לאט את הגליל בחזרה לכיוון הגוף, תוך כיפוף הזרועות והחזרת הגליל לירכיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a flat surface with your legs extended in front of you.","Hold the roller with both hands, palms facing down, and place it on your thighs.","Lean forward slightly and roll the roller away from your body, extending your arms straight in front of you.","Pause for a moment, then slowly roll the roller back towards your body, bending your arms and bringing the roller back to your thighs.","Repeat for the desired number of repetitions."],"mediaId":"8coXSYU"},{"id":"edb-2209","name":"roller seated single leg shoulder flexor depresor retractor","name_en":"roller seated single leg shoulder flexor depresor retractor","muscle":"chest","equipment":"roller","target":"pectorals","bodyPart":"chest","secondaryMuscles":["deltoids","triceps"],"steps":["שבו על משטח שטוח עם הרגליים ישרות לפניכם.","אחזו את הגליל בשתי הידיים, כשכפות הידיים פונות כלפי מטה, והניחו אותו על הירכיים.","הישענו מעט לאחור והפעילו את שרירי הליבה.","הרימו את הגליל לגובה הכתפיים, תוך שמירה על הזרועות ישרות.","הורידו לאט את הגליל בחזרה לירכיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a flat surface with your legs extended in front of you.","Hold the roller with both hands, palms facing down, and place it on your thighs.","Lean back slightly and engage your core muscles.","Raise the roller up to shoulder level, keeping your arms straight.","Slowly lower the roller back down to your thighs.","Repeat for the desired number of repetitions."],"mediaId":"CjETvlw"},{"id":"edb-2207","name":"מתיחה צדי עם גלגלת","name_en":"roller side lat stretch","muscle":"back","equipment":"roller","target":"lats","bodyPart":"back","secondaryMuscles":["shoulders","triceps"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו את הגליל בשתי הידיים לפני הגוף.","כופפו מעט את הברכיים והטו את הגוף קדימה במפרקי הירך, תוך שמירה על גב ישר.","יישרו את הזרועות קדימה וגלגלו את הגליל כלפי מטה לכיוון הרגליים, תוך הרגשת מתיחה בשרירי הגב הרחביים.","החזיקו את המתיחה למספר שניות, ולאחר מכן גלגלו לאט את הגליל בחזרה למעלה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold the roller with both hands in front of your body.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Extend your arms forward and roll the roller down towards your feet, feeling a stretch in your lats.","Hold the stretch for a few seconds, then slowly roll the roller back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"c3Pfhti"},{"id":"edb-0680","name":"rope climb","name_en":"rope climb","muscle":"back","equipment":"rope","target":"upper back","bodyPart":"back","secondaryMuscles":["forearms","biceps","shoulders"],"steps":["עמדו מול החבל עם הרגליים ברוחב הכתפיים.","אחזו את החבל בשתי הידיים, כשכפות הידיים פונות אליכם.","כופפו מעט את הברכיים והפעילו את שרירי הליבה.","התחילו למשוך את עצמכם במעלה החבל על ידי תנועות סירוגין של יד מעל יד.","השתמשו ברגליים כדי לסייע בתנועה כלפי מעלה.","המשיכו לטפס עד שתגיעו לגובה הרצוי או לראש החבל.","כדי לרדת, הפכו את תנועת היד מעל יד תוך שליטה בירידה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand facing the rope with your feet shoulder-width apart.","Grab the rope with both hands, palms facing towards you.","Bend your knees slightly and engage your core.","Begin pulling yourself up the rope by alternating hand-over-hand movements.","Use your legs to assist in the upward movement.","Continue climbing until you reach the desired height or the top of the rope.","To descend, reverse the hand-over-hand movement while controlling your descent.","Repeat for the desired number of repetitions."],"mediaId":"yaAxcQr"},{"id":"edb-0685","name":"run","name_en":"run","muscle":"core","equipment":"body weight","target":"cardiovascular system","bodyPart":"cardio","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["התחילו בעמידה זקופה עם הרגליים ברוחב האגן.","הפעילו את שרירי הליבה ושמרו על פלג הגוף העליון רגוע.","התחילו לרוץ קלות במקום, תוך הרמת הברכיים לכיוון החזה ונחיתה רכה על קצות כפות הרגליים.","שמרו על קצב קבוע והמשיכו לרוץ קלות למשך הזמן או המרחק הרצוי.","זכרו לנשום עמוק ולשמור על יציבה נכונה לאורך כל התרגיל."],"steps_en":["Start by standing upright with your feet hip-width apart.","Engage your core and keep your upper body relaxed.","Begin jogging in place, lifting your knees up towards your chest and landing softly on the balls of your feet.","Maintain a steady pace and continue jogging for the desired duration or distance.","Remember to breathe deeply and maintain good posture throughout the exercise."],"mediaId":"oLrKqDH"},{"id":"edb-0684","name":"run (equipment)","name_en":"run (equipment)","muscle":"core","equipment":"body weight","target":"cardiovascular system","bodyPart":"cardio","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["התחילו בעמידה זקופה עם הרגליים ברוחב האגן.","הפעילו את שרירי הליבה ושמרו על פלג הגוף העליון רגוע.","התחילו לרוץ קלות במקום, תוך הרמת הברכיים לכיוון החזה ונחיתה רכה על קצות כפות הרגליים.","שמרו על קצב קבוע והמשיכו לרוץ קלות למשך הזמן או המרחק הרצוי.","זכרו לנשום עמוק ולשמור על יציבה נכונה לאורך כל התרגיל."],"steps_en":["Start by standing upright with your feet hip-width apart.","Engage your core and keep your upper body relaxed.","Begin jogging in place, lifting your knees up towards your chest and landing softly on the balls of your feet.","Maintain a steady pace and continue jogging for the desired duration or distance.","Remember to breathe deeply and maintain good posture throughout the exercise."],"mediaId":"y5p0H8a"},{"id":"edb-1585","name":"מתיחה","name_en":"runners stretch","muscle":"legs","equipment":"body weight","target":"hamstrings","bodyPart":"upper legs","secondaryMuscles":["calves","quadriceps"],"steps":["עמדו עם הרגליים ברוחב האגן.","צעדו קדימה עם הרגל הימנית, תוך שמירה על הרגל השמאלית נטועה במקום.","כופפו את הברך הימנית והורידו את הגוף, תוך שמירה על הרגל השמאלית ישרה.","הניחו את הידיים על הירך הימנית לתמיכה.","החזיקו את המתיחה 20-30 שניות, ואז החליפו צד וחזרו על התרגיל."],"steps_en":["Stand with your feet hip-width apart.","Take a step forward with your right foot, keeping your left foot planted.","Bend your right knee and lower your body down, keeping your left leg straight.","Place your hands on your right thigh for support.","Hold the stretch for 20-30 seconds, then switch sides and repeat."],"mediaId":"0mB6wHO"},{"id":"edb-0687","name":"פיתול רוסי","name_en":"russian twist","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques"],"steps":["שבו על הרצפה עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הטו את הגוף מעט אחורה, תוך שמירה על גב ישר והפעלת שרירי הליבה.","אחזו את הידיים יחד מול החזה או אחזו משקולת אם תרצו.","הרימו את כפות הרגליים מהרצפה, תוך איזון על עצמות הישיבה.","סובבו את פלג הגוף העליון ימינה, תוך קירוב הידיים או המשקולת לצד הימני של הגוף.","עצרו לרגע, ולאחר מכן סובבו את פלג הגוף העליון שמאלה, תוך קירוב הידיים או המשקולת לצד השמאלי של הגוף.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Sit on the ground with your knees bent and feet flat on the floor.","Lean back slightly while keeping your back straight and your core engaged.","Hold your hands together in front of your chest or hold a weight if desired.","Lift your feet off the ground, balancing on your sit bones.","Twist your torso to the right, bringing your hands or weight towards the right side of your body.","Pause for a moment, then twist your torso to the left, bringing your hands or weight towards the left side of your body.","Continue alternating sides for the desired number of repetitions."],"mediaId":"XVDdcoj"},{"id":"edb-3012","name":"scapula dips","name_en":"scapula dips","muscle":"back","equipment":"body weight","target":"traps","bodyPart":"back","secondaryMuscles":["rhomboids","deltoids"],"steps":["התחילו בעמידה עם הרגליים ברוחב הכתפיים והזרועות ישרות לפניכם.","כופפו מעט את הברכיים והטו את הגוף קדימה במפרקי הירך, תוך שמירה על גב ישר.","הורידו את הגוף על ידי כיפוף המרפקים וקירוב השכמות זו לזו, כאילו אתם מנסים לסחוט עיפרון ביניהן.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו דרך הידיים כדי ליישר את המרפקים ולחזור לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by standing with your feet shoulder-width apart and your arms extended in front of you.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Lower your body by bending your elbows and retracting your shoulder blades, as if you are trying to squeeze a pencil between them.","Pause for a moment at the bottom, then push through your hands to extend your elbows and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"7xeukSt"},{"id":"edb-3021","name":"שכיבת סמיכה","name_en":"scapula push-up","muscle":"chest","equipment":"body weight","target":"serratus anterior","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["התחילו בתנוחת פלאנק גבוה כשהידיים ישירות מתחת לכתפיים והגוף בקו ישר.","הורידו את החזה לכיוון הרצפה, כשהמרפקים צמודים לגוף.","תוך כדי הירידה, כווצו את השכמות זו לזו ודחפו את החזה קדימה.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a high plank position with your hands directly under your shoulders and your body in a straight line.","Lower your chest towards the ground, keeping your elbows close to your body.","As you lower, squeeze your shoulder blades together and push your chest forward.","Pause for a moment at the bottom, then push back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"jV65tKx"},{"id":"edb-0688","name":"מתח","name_en":"scapular pull-up","muscle":"back","equipment":"body weight","target":"traps","bodyPart":"back","secondaryMuscles":["biceps","rhomboids","rear deltoids"],"steps":["התחילו בתלייה ממוט מתח, כפות הידיים פונות ממכם והזרועות ישרות לגמרי.","קרבו את השכמות זו לזו על ידי משיכתן כלפי מטה ואחורה.","הפעילו את שרירי הגב ומשכו את הגוף כלפי מעלה לכיוון המוט, תוך התמקדות בכיווץ השכמות זו לזו.","עצרו לרגע בשיא התנועה, ואז הורידו לאט את הגוף בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by hanging from a pull-up bar with your palms facing away from you and your arms fully extended.","Retract your shoulder blades by pulling them down and back.","Engage your back muscles and pull your body up towards the bar, focusing on squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"uTBt1HV"},{"id":"edb-3219","name":"scissor jumps (male)","name_en":"scissor jumps (male)","muscle":"core","equipment":"body weight","target":"cardiovascular system","bodyPart":"cardio","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים.","קפצו מהרצפה והצליבו בו-זמנית את הרגל הימנית לפני הרגל השמאלית.","בעת הנחיתה, החליפו במהירות רגליים, תוך הצלבת הרגל השמאלית לפני הרגל הימנית.","המשיכו להחליף רגליים ולקפוץ במהירות האפשרית.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart.","Jump off the ground and simultaneously cross your right leg in front of your left leg.","As you land, quickly switch legs, crossing your left leg in front of your right leg.","Continue alternating legs and jumping as quickly as possible.","Repeat for the desired number of repetitions."],"mediaId":"Eh2v5Iu"},{"id":"edb-1390","name":"מתיחה בישיבה","name_en":"seated calf stretch (male)","muscle":"legs","equipment":"body weight","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings"],"steps":["שבו על קצה כיסא או ספסל עם כפות הרגליים שטוחות על הרצפה.","פשטו רגל אחת ישר קדימה, כשהעקב נשאר על הרצפה.","הישענו מעט קדימה, תוך הרגשת מתיחה בשריר השוק.","החזיקו את המתיחה במשך 20-30 שניות.","החליפו רגליים וחזרו על המתיחה."],"steps_en":["Sit on the edge of a chair or bench with your feet flat on the ground.","Extend one leg straight out in front of you, keeping your heel on the ground.","Lean forward slightly, feeling a stretch in your calf muscle.","Hold the stretch for 20-30 seconds.","Switch legs and repeat the stretch."],"mediaId":"17bqEXD"},{"id":"edb-1424","name":"מתיחה בישיבה","name_en":"seated glute stretch","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings"],"steps":["שבו על הרצפה עם הרגליים מושטות לפניכם.","כופפו את הברך הימנית והצליבו את הקרסול הימני מעל הירך השמאלית.","הניחו את היד הימנית על הרצפה מאחור לתמיכה.","עם היד השמאלית, לחצו בעדינות על הברך הימנית כדי להעמיק את המתיחה.","החזיקו את המתיחה 30 שניות עד דקה.","החליפו צדדים וחזרו על התרגיל."],"steps_en":["Sit on the ground with your legs extended in front of you.","Bend your right knee and cross your right ankle over your left thigh.","Place your right hand on the ground behind you for support.","With your left hand, gently press down on your right knee to deepen the stretch.","Hold the stretch for 30 seconds to 1 minute.","Switch sides and repeat."],"mediaId":"DeDThfG"},{"id":"edb-0689","name":"הרמת רגליים בישיבה","name_en":"seated leg raise","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שבו על ספסל שטוח עם הגב ישר וכפות הרגליים שטוחות על הרצפה.","הניחו את הידיים על צידי הספסל לתמיכה.","תוך שמירה על הרגליים ישרות, הרימו אותן לאט לפניכם עד שהן מקבילות לרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a flat bench with your back straight and your feet flat on the ground.","Place your hands on the sides of the bench for support.","Keeping your legs straight, slowly raise them up in front of you until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Hgs6Nl1"},{"id":"edb-0690","name":"מתיחה בישיבה","name_en":"seated lower back stretch","muscle":"back","equipment":"body weight","target":"lats","bodyPart":"back","secondaryMuscles":["glutes","hamstrings"],"steps":["שבו על קצה כיסא עם כפות הרגליים שטוחות על הרצפה.","הניחו את הידיים על הירכיים או בצדי הכיסא לתמיכה.","הישענו לאט קדימה מהאגן, תוך שמירה על הגב ישר.","הרגישו את המתיחה בגב התחתון והחזיקו 20-30 שניות.","חזרו לאט לעמדת ההתחלה וחזרו למספר החזרות הרצוי."],"steps_en":["Sit on the edge of a chair with your feet flat on the ground.","Place your hands on your thighs or on the sides of the chair for support.","Slowly lean forward from your hips, keeping your back straight.","Feel the stretch in your lower back and hold for 20-30 seconds.","Slowly return to the starting position and repeat for the desired number of repetitions."],"mediaId":"QFmz6ch"},{"id":"edb-2567","name":"מתיחה בישיבה","name_en":"seated piriformis stretch","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings"],"steps":["שבו על הרצפה עם הרגליים מושטות לפניכם.","כופפו את הברך הימנית והניחו את כף הרגל הימנית בצד החיצוני של הברך השמאלית.","הניחו את המרפק השמאלי בצד החיצוני של הברך הימנית וסובבו בעדינות את פלג הגוף העליון ימינה.","החזיקו את המתיחה 20-30 שניות, ואז החליפו צד וחזרו על התרגיל."],"steps_en":["Sit on the ground with your legs extended in front of you.","Bend your right knee and place your right foot on the outside of your left knee.","Place your left elbow on the outside of your right knee and gently twist your torso to the right.","Hold the stretch for 20-30 seconds, then switch sides and repeat."],"mediaId":"QY39eBr"},{"id":"edb-0691","name":"כפיפת בטן בישיבה צדי","name_en":"seated side crunch (wall)","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques"],"steps":["שבו על הרצפה עם הגב צמוד לקיר והרגליים ישרות לפניכם.","כופפו את הברכיים והניחו את כפות הרגליים שטוחות על הרצפה, ברוחב האגן.","הניחו את הידיים מאחורי הראש כשהמרפקים פונים החוצה.","הפעילו את שרירי הבטן והישענו לצד אחד, תוך קירוב המרפק לאגן.","עצרו לרגע, ולאחר מכן חזרו למצב ההתחלתי.","חזרו על התרגיל בצד השני.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Sit on the floor with your back against a wall and your legs extended in front of you.","Bend your knees and place your feet flat on the floor, hip-width apart.","Place your hands behind your head with your elbows pointing outwards.","Engage your abs and lean to one side, bringing your elbow towards your hip.","Pause for a moment, then return to the starting position.","Repeat on the other side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"Y9hNPcN"},{"id":"edb-1587","name":"seated wide angle pose sequence","name_en":"seated wide angle pose sequence","muscle":"legs","equipment":"body weight","target":"hamstrings","bodyPart":"upper legs","secondaryMuscles":["quadriceps","calves"],"steps":["שבו על הרצפה עם הרגליים ישרות בזווית רחבה.","כופפו את כפות הרגליים כלפי מעלה והפעילו את שרירי הארבע ראשי.","הניחו את הידיים על הרצפה מאחור לתמיכה.","תוך שמירה על הגב ישר, הישענו קדימה מהאגן.","המשיכו להישען קדימה עד שתרגישו מתיחה בירך האחורית.","החזיקו בתנוחה זו למשך כמה נשימות.","שחררו לאט את המתיחה וחזרו לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the ground with your legs extended in a wide angle.","Flex your feet and engage your quadriceps.","Place your hands on the ground behind you for support.","Keeping your back straight, lean forward from your hips.","Continue leaning forward until you feel a stretch in your hamstrings.","Hold this position for a few breaths.","Slowly release the stretch and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"HIgYKAB"},{"id":"edb-0697","name":"כפיפת ברך בסיוע","name_en":"self assisted inverse leg curl","muscle":"legs","equipment":"body weight","target":"hamstrings","bodyPart":"upper legs","secondaryMuscles":["glutes","calves"],"steps":["שכבו שטוח על הגב על מזרן או ספסל עם הרגליים ישרות.","הניחו את הידיים לצדי הגוף או מתחת לישבן לתמיכה.","כופפו את הברכיים והרימו את כפות הרגליים מהרצפה, תוך קירוב הירכיים לחזה.","עצרו לרגע בשיא התנועה, ואז הורידו לאט את הרגליים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back on a mat or bench with your legs extended.","Place your hands by your sides or under your glutes for support.","Bend your knees and lift your feet off the ground, bringing your thighs towards your chest.","Pause for a moment at the top, then slowly lower your legs back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"GwYwElT"},{"id":"edb-1766","name":"כפיפת ברך בסיוע","name_en":"self assisted inverse leg curl","muscle":"legs","equipment":"body weight","target":"hamstrings","bodyPart":"upper legs","secondaryMuscles":["glutes","calves"],"steps":["שכבו על הבטן על מכשיר כפיפת רגליים כשהרגליים ישרות והקרסוליים מוצמדים מתחת למוט המרופד.","הניחו את הידיים על ידיות הצד של המכשיר לתמיכה.","תוך שמירה על פלג הגוף העליון ללא תנועה, נשפו וכופפו את הרגליים כלפי מעלה כמה שיותר.","החזיקו את מצב הכיווץ לרגע קצר תוך כדי לחיצת שרירי הירך האחורית.","הורידו לאט את הרגליים בחזרה לתנוחת ההתחלה תוך שאיפה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie face down on a leg curl machine with your legs extended and your ankles hooked under the padded lever.","Place your hands on the side handles of the machine for support.","Keeping your upper body stationary, exhale and curl your legs upward as far as possible.","Hold the contracted position for a brief pause as you squeeze your hamstrings.","Slowly lower your legs back to the starting position while inhaling.","Repeat for the desired number of repetitions."],"mediaId":"ZSY3MsL"},{"id":"edb-0696","name":"כפיפת ברך בסיוע","name_en":"self assisted inverse leg curl (on floor)","muscle":"legs","equipment":"body weight","target":"hamstrings","bodyPart":"upper legs","secondaryMuscles":["glutes","calves"],"steps":["שכבו על הגב עם הרגליים מושטות והידיים לצידי הגוף.","כופפו את הברכיים והניחו את כפות הרגליים שטוחות על הרצפה, ברוחב האגן.","הרימו את האגן מהרצפה, תוך הפעלת שרירי הישבן והירך האחורית.","כופפו לאט את הרגליים לכיוון הישבן, תוך שמירה על האגן מורם.","עצרו לרגע בשיא התנועה, ואז ישרו לאט את הרגליים בחזרה למצב ההתחלתי.","הורידו את האגן בחזרה לרצפה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your legs extended and your arms by your sides.","Bend your knees and place your feet flat on the ground, hip-width apart.","Lift your hips off the ground, engaging your glutes and hamstrings.","Slowly curl your legs towards your glutes, keeping your hips lifted.","Pause for a moment at the top, then slowly extend your legs back to the starting position.","Lower your hips back down to the ground.","Repeat for the desired number of repetitions."],"mediaId":"E4PwJqI"},{"id":"edb-3222","name":"סקוואט","name_en":"semi squat jump (male)","muscle":"core","equipment":"body weight","target":"cardiovascular system","bodyPart":"cardio","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים.","כופפו את הברכיים והורידו את הגוף לתנוחת סקוואט.","קפצו בפיצוץ כוח, תוך יישור האגן והברכיים והנפת הזרועות לצבירת תנע.","נחתו ברכות על כריות כפות הרגליים ועברו מיד לחזרה הבאה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart.","Bend your knees and lower your body into a squat position.","Jump explosively, extending your hips and knees while swinging your arms for momentum.","Land softly on the balls of your feet and immediately go into the next repetition.","Repeat for the desired number of repetitions."],"mediaId":"6FMU51h"},{"id":"edb-3656","name":"short stride run","name_en":"short stride run","muscle":"core","equipment":"body weight","target":"cardiovascular system","bodyPart":"cardio","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["מצאו מרחב פתוח או הליכון לביצוע התרגיל.","עמדו זקוף עם הרגליים ברוחב האגן.","התחילו לרוץ קלות במקום, תוך הרמת הברכיים גבוה והנפת הזרועות.","לאחר מספר שניות, התחילו לצעוד צעדים קצרים קדימה, תוך שמירה על קצב מהיר.","המשיכו לרוץ בצעדים קצרים למשך הזמן או המרחק הרצוי."],"steps_en":["Find an open space or a treadmill to perform the exercise.","Stand tall with your feet hip-width apart.","Start jogging in place, lifting your knees high and pumping your arms.","After a few seconds, start taking short strides forward, maintaining a quick pace.","Continue running with short strides for the desired duration or distance."],"mediaId":"CcWEoWV"},{"id":"edb-1763","name":"מתח","name_en":"shoulder grip pull-up","muscle":"back","equipment":"body weight","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["אחזו את מתקן המתח באחיזה ברוחב הכתפיים, כשכפות הידיים פונות הרחק מכם.","הישארו תלויים בחופשיות עם הזרועות ישרות לגמרי.","הפעילו את שרירי הגב ומשכו את הגוף כלפי מעלה לכיוון המוט עד שהסנטר מעל המוט.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הגוף בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Grab the pull-up bar with a shoulder-width grip, palms facing away from you.","Hang freely with your arms fully extended.","Engage your back muscles and pull your body up towards the bar until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"YtgD7Xq"},{"id":"edb-3699","name":"shoulder tap","name_en":"shoulder tap","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["shoulders","triceps"],"steps":["התחילו בתנוחת פלאנק גבוה כשהידיים ישירות מתחת לכתפיים והגוף בקו ישר.","הפעילו את שרירי הליבה והרימו את היד הימנית מהרצפה, תוך הושטתה לכיוון הכתף השמאלית לנגיעה בה.","החזירו את היד הימנית לרצפה וחזרו על התנועה כשהיד השמאלית נוגעת בכתף הימנית.","המשיכו להחליף נגיעות בכתפיים תוך שמירה על האגן ופלג הגוף העליון יציבים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a high plank position with your hands directly under your shoulders and your body in a straight line.","Engage your core and lift your right hand off the ground, reaching across to tap your left shoulder.","Place your right hand back on the ground and repeat with your left hand tapping your right shoulder.","Continue alternating shoulder taps while keeping your hips and torso stable.","Repeat for the desired number of repetitions."],"mediaId":"yRpV5TC"},{"id":"edb-0699","name":"שכיבת סמיכה","name_en":"shoulder tap push-up","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","core"],"steps":["התחילו בתנוחת פלאנק גבוה עם הידיים מעט רחבות יותר מרוחב הכתפיים והגוף בקו ישר מהראש ועד העקבים.","הורידו את הגוף לכיוון הרצפה על ידי כיפוף המרפקים, כשהם צמודים לגוף.","תוך כדי הדחיפה חזרה למעלה, הרימו את היד הימנית מהרצפה ונגעו בכתף השמאלית.","החזירו את היד הימנית לרצפה וחזרו על שכיבת הסמיכה, הפעם תוך הרמת היד השמאלית ונגיעה בכתף הימנית.","המשיכו להחליף נגיעות בכתפיים עם כל חזרה של שכיבת סמיכה.","שמרו על ליבה יציבה והימנעו מסיבוב אגן מוגזם לאורך כל התרגיל.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a high plank position with your hands slightly wider than shoulder-width apart and your body in a straight line from head to heels.","Lower your body towards the ground by bending your elbows, keeping them close to your sides.","As you push back up, lift your right hand off the ground and tap your left shoulder.","Return your right hand to the ground and repeat the push-up, this time lifting your left hand and tapping your right shoulder.","Continue alternating shoulder taps with each push-up repetition.","Maintain a stable core and avoid excessive hip rotation throughout the exercise.","Repeat for the desired number of repetitions."],"mediaId":"qEse6fe"},{"id":"edb-1774","name":"גשר צדי","name_en":"side bridge hip abduction","muscle":"glutes","equipment":"body weight","target":"abductors","bodyPart":"upper legs","secondaryMuscles":["glutes","obliques"],"steps":["שכבו על הצד עם הרגליים ישרות ומונחות זו על גבי זו.","הישענו על האמה, תוך שמירה על המרפק ישר מתחת לכתף.","הפעילו את שרירי הליבה והרימו את הירכיים מהרצפה, כך שייווצר קו ישר מהראש ועד הרגליים.","תוך שמירה על שרירי הליבה מופעלים, הרימו את הרגל העליונה כמה שיותר גבוה מבלי לסובב את האגן.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את הרגל בחזרה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Lie on your side with your legs extended and stacked on top of each other.","Prop yourself up on your forearm, keeping your elbow directly below your shoulder.","Engage your core and lift your hips off the ground, creating a straight line from your head to your feet.","While keeping your core engaged, lift your top leg as high as possible without rotating your hips.","Pause for a moment at the top, then lower your leg back down.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"WL4EmxJ"},{"id":"edb-0705","name":"גשר צדי","name_en":"side bridge v. 2","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","glutes"],"steps":["שכבו על הצד עם הרגליים ישרות ומונחות זו על גבי זו.","הניחו את האמה על הרצפה ישירות מתחת לכתף, כאשר המרפק כפוף בזווית של 90 מעלות.","הפעילו את שרירי הליבה והרימו את הירכיים מהרצפה, כך שייווצר קו ישר מהראש ועד הרגליים.","החזיקו את התנוחה למשך הזמן הרצוי.","הורידו את האגן חזרה למטה למצב ההתחלתי.","חזרו על התרגיל בצד השני."],"steps_en":["Lie on your side with your legs extended and stacked on top of each other.","Place your forearm on the ground directly below your shoulder, with your elbow bent at a 90-degree angle.","Engage your core and lift your hips off the ground, creating a straight line from your head to your feet.","Hold this position for the desired amount of time.","Lower your hips back down to the starting position.","Repeat on the other side."],"mediaId":"RKjH6Lt"},{"id":"edb-0709","name":"side hip (on parallel bars)","name_en":"side hip (on parallel bars)","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","hip flexors"],"steps":["עמדו בין שני מוטות מקבילים עם הרגליים ברוחב הכתפיים.","הניחו את הידיים על המוטות והרימו את הגוף מהרצפה, תוך תמיכת המשקל על הזרועות.","הפעילו את שרירי הבטן והרימו לאט את הרגליים הצידה, תוך שמירה עליהן ישרות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand between two parallel bars with your feet shoulder-width apart.","Place your hands on the bars and lift your body off the ground, supporting your weight on your arms.","Engage your abs and slowly lift your legs to the side, keeping them straight.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"jTkSc6o"},{"id":"edb-0710","name":"side hip abduction","name_en":"side hip abduction","muscle":"glutes","equipment":"body weight","target":"abductors","bodyPart":"upper legs","secondaryMuscles":["glutes","quadriceps"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והידיים על המותניים.","העבירו את המשקל לרגל אחת והרימו את הרגל הנגדית הצידה, תוך שמירה עליה ישרה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגל בחזרה לתנוחת ההתחלה.","חזרו על התרגיל בצד השני.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your hands on your hips.","Shift your weight to one leg and lift the opposite leg out to the side, keeping it straight.","Pause for a moment at the top, then slowly lower your leg back down to the starting position.","Repeat on the other side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"7WaDzyL"},{"id":"edb-1358","name":"מתיחה בשכיבה צדי","name_en":"side lying floor stretch","muscle":"back","equipment":"body weight","target":"lats","bodyPart":"back","secondaryMuscles":["obliques","glutes"],"steps":["שכבו על הצד עם הרגליים ישרות והזרוע התחתונה ישרה מעל הראש.","כופפו את הברך העליונה והניחו את כף הרגל על הרצפה לפני הרגל התחתונה.","הושיטו את הזרוע העליונה מעל הראש ואחזו במשהו יציב, כמו קיר או רהיט.","הרימו לאט את הרגל התחתונה מהרצפה, תוך שמירה עליה ישרה, עד שתרגישו מתיחה בצד הגוף.","החזיקו את המתיחה 20-30 שניות, ולאחר מכן הורידו לאט את הרגל בחזרה.","חזרו על התרגיל בצד השני."],"steps_en":["Lie on your side with your legs straight and your bottom arm extended straight overhead.","Bend your top knee and place your foot on the ground in front of your bottom leg.","Reach your top arm over your head and grab onto something stable, like a wall or a piece of furniture.","Slowly lift your bottom leg off the ground, keeping it straight, until you feel a stretch in your side.","Hold the stretch for 20-30 seconds, then slowly lower your leg back down.","Repeat on the other side."],"mediaId":"jDOKRM5"},{"id":"edb-3667","name":"side lying hip adduction (male)","name_en":"side lying hip adduction (male)","muscle":"legs","equipment":"body weight","target":"adductors","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings"],"steps":["שכבו על הצד עם הרגליים ישרות ומונחות זו על גבי זו.","הניחו את הזרוע התחתונה מתחת לראש לתמיכה.","הפעילו את שרירי המקרבים והרימו את הרגל העליונה כמה שיותר גבוה מבלי לסובב את האגן או להישען אחורה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגל בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Lie on your side with your legs straight and stacked on top of each other.","Place your bottom arm under your head for support.","Engage your adductors and lift your top leg as high as possible without rotating your hips or leaning backward.","Pause for a moment at the top, then slowly lower your leg back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"c8f5cSY"},{"id":"edb-1775","name":"פלאנק צדי","name_en":"side plank hip adduction","muscle":"legs","equipment":"body weight","target":"adductors","bodyPart":"upper legs","secondaryMuscles":["obliques","glutes"],"steps":["התחילו בשכיבה על הצד כאשר הרגליים ישרות ומונחות זו על גבי זו.","הישענו על האמה, תוך שמירה על המרפק ישר מתחת לכתף.","הפעילו את שרירי הליבה והרימו את הירכיים מהרצפה, כך שייווצר קו ישר מהראש ועד הרגליים.","תוך שמירה על תנוחת הפלאנק הצידי, הרימו את הרגל העליונה לכיוון התקרה, תוך שמירה עליה ישרה.","הורידו לאט את הרגל בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Start by lying on your side with your legs extended and stacked on top of each other.","Prop yourself up on your forearm, keeping your elbow directly below your shoulder.","Engage your core and lift your hips off the ground, creating a straight line from your head to your feet.","While maintaining the side plank position, lift your top leg towards the ceiling, keeping it straight.","Slowly lower your leg back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"VO2qeJg"},{"id":"edb-0716","name":"מתיחה צדי","name_en":"side push neck stretch","muscle":"shoulders","equipment":"body weight","target":"levator scapulae","bodyPart":"neck","secondaryMuscles":["trapezius","sternocleidomastoid"],"steps":["עמדו או שבו בישיבה זקופה עם הכתפיים רפויות.","הטו את הראש ימינה, תוך קירוב האוזן הימנית לכתף הימנית.","הניחו את היד הימנית בצד השמאלי של הראש והפעילו לחץ עדין להגברת המתיחה.","החזיקו את המתיחה למשך 15-30 שניות.","חזרו על התרגיל בצד השני, תוך הטיית הראש שמאלה והפעלת לחץ עם היד השמאלית.","חזרו על המתיחה 2-3 פעמים בכל צד."],"steps_en":["Stand or sit up straight with your shoulders relaxed.","Tilt your head to the right, bringing your right ear towards your right shoulder.","Place your right hand on the left side of your head and gently apply pressure to increase the stretch.","Hold the stretch for 15-30 seconds.","Repeat on the other side, tilting your head to the left and applying pressure with your left hand.","Repeat the stretch 2-3 times on each side."],"mediaId":"oQRJYkC"},{"id":"edb-0717","name":"שכיבת סמיכה צדי","name_en":"side push-up","muscle":"triceps","equipment":"body weight","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders","chest","core"],"steps":["התחילו בשכיבה על הצד כאשר הרגליים ישרות ומונחות זו על גבי זו.","הניחו את היד התחתונה על הרצפה ישר מתחת לכתף, כשהאצבעות פונות קדימה.","לחצו דרך היד התחתונה כדי להרים את הגוף מהרצפה, תוך שמירה על הרגליים ישרות ושרירי הליבה מופעלים.","יישרו את הזרוע העליונה כלפי מעלה לכיוון התקרה, תוך יצירת קו ישר מהראש ועד העקבים.","הורידו את הגוף בחזרה לתנוחת ההתחלה בשליטה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Start by lying on your side with your legs extended and stacked on top of each other.","Place your bottom hand on the ground directly under your shoulder, fingers pointing forward.","Press through your bottom hand to lift your body off the ground, keeping your legs straight and your core engaged.","Extend your top arm straight up towards the ceiling, creating a straight line from your head to your heels.","Lower your body back down to the starting position with control.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"wpbD28t"},{"id":"edb-0721","name":"מתיחה צדי","name_en":"side wrist pull stretch","muscle":"biceps","equipment":"body weight","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["wrists","hands"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והזרועות ישרות לפניכם.","יישרו את הזרוע הימנית הצידה, במקביל לרצפה, כשכף היד פונה כלפי מטה.","עם היד השמאלית, אחזו את היד הימנית ומשכו אותה בעדינות לכיוון הגוף, תוך הרגשת מתיחה באמה הימנית.","החזיקו את המתיחה במשך 15-30 שניות, ולאחר מכן שחררו.","חזרו על התרגיל בצד השני."],"steps_en":["Stand with your feet shoulder-width apart and your arms extended in front of you.","Extend your right arm out to the side, parallel to the ground, with your palm facing down.","With your left hand, grab your right hand and gently pull it towards your body, feeling a stretch in your right forearm.","Hold the stretch for 15-30 seconds, then release.","Repeat on the other side."],"mediaId":"UtmIqcI"},{"id":"edb-0720","name":"side-to-side chin","name_en":"side-to-side chin","muscle":"back","equipment":"body weight","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","אחזו את מתקן המתח באחיזה עליונה, כשהידיים מעט רחבות יותר מרוחב הכתפיים.","הישארו תלויים מהמוט עם הזרועות ישרות לגמרי והגוף רגוע.","משכו את עצמכם למעלה על ידי כיפוף המרפקים וקירוב הסנטר למוט, תוך שמירה על הגוף ישר.","כאשר הסנטר מעל המוט, הורידו את עצמכם בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your knees slightly bent.","Grasp a pull-up bar with an overhand grip, hands slightly wider than shoulder-width apart.","Hang from the bar with your arms fully extended and your body relaxed.","Pull yourself up by bending your elbows and bringing your chin towards the bar, while keeping your body straight.","Once your chin is above the bar, lower yourself back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"isAAZWA"},{"id":"edb-3213","name":"side-to-side toe touch (male)","name_en":"side-to-side toe touch (male)","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","hip flexors"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והזרועות ישרות הצדה.","כופפו במותניים ימינה, תוך הושטת היד הימנית לכיוון כף הרגל הימנית ושמירה על היד השמאלית מושטת הצידה.","חזרו לתנוחת ההתחלה ולאחר מכן כופפו במותניים שמאלה, תוך הושטת היד השמאלית לכיוון כף הרגל השמאלית ושמירה על היד הימנית מושטת הצידה.","חזרו על תנועת הכיפוף מצד לצד למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your arms extended to the sides.","Bend at the waist to the right, reaching your right hand towards your right foot while keeping your left hand extended to the side.","Return to the starting position and then bend at the waist to the left, reaching your left hand towards your left foot while keeping your right hand extended to the side.","Repeat the side-to-side bending motion for the desired number of repetitions."],"mediaId":"WCAvOfC"},{"id":"edb-0725","name":"שכיבת סמיכה ביד אחת","name_en":"single arm push-up","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders","core"],"steps":["התחילו בתנוחת שכיבת סמיכה עם הידיים ברוחב הכתפיים ויד אחת ממוקמת מעט רחבה יותר מהשנייה.","הפעילו את שרירי הליבה והורידו את הגוף לכיוון הרצפה על ידי כיפוף המרפקים, תוך שמירה על הגב ישר.","תוך כדי הירידה, העבירו את המשקל לצד אחד והרימו את הזרוע הנגדית מהרצפה, תוך יישורה הצידה.","דחפו דרך החזה והזרוע האחורית כדי להרים את הגוף בחזרה לתנוחת ההתחלה, תוך הורדת הזרוע המושטת בחזרה לרצפה במקביל.","חזרו על התנועה, תוך החלפת הזרוע המושטת בכל חזרה."],"steps_en":["Start in a push-up position with your hands shoulder-width apart and one hand placed slightly wider than the other.","Engage your core and lower your body towards the ground by bending your elbows, keeping your back straight.","As you lower yourself, shift your weight to one side and lift the opposite arm off the ground, extending it straight out to the side.","Push through your chest and triceps to raise your body back up to the starting position, while simultaneously lowering your extended arm back to the ground.","Repeat the movement, alternating the arm you extend with each repetition."],"mediaId":"MUic5zN"},{"id":"edb-3645","name":"גשר ברגל אחת","name_en":"single leg bridge with outstretched leg","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","יישרו רגל אחת לפניכם.","הפעילו את שרירי הישבן והרימו את האגן מהרצפה, ביצירת קו ישר מהברכיים ועד הכתפיים.","החזיקו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את האגן בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו רגליים."],"steps_en":["Lie on your back with your knees bent and feet flat on the ground.","Extend one leg straight out in front of you.","Engage your glutes and lift your hips off the ground, forming a straight line from your knees to your shoulders.","Hold for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"mediaId":"rmEukuS"},{"id":"edb-0727","name":"הרמת עקבים ברגל אחת עם משקולות","name_en":"single leg calf raise (on a dumbbell)","muscle":"legs","equipment":"dumbbell","target":"calves","bodyPart":"lower legs","secondaryMuscles":["ankles","feet"],"steps":["עמדו עם הרגליים ברוחב האגן ואחזו משקולת יד ביד אחת.","הרימו כף רגל אחת מהרצפה ושמרו על איזון על הרגל השנייה.","הרימו לאט את העקב כמה שיותר גבוה, תוך שימוש בשרירי השוק.","עצרו לרגע בקצה העליון, ואז הורידו לאט את העקב בחזרה למטה.","חזרו על התנועה למספר החזרות הרצוי, ולאחר מכן עברו לרגל השנייה."],"steps_en":["Stand with your feet hip-width apart and hold a dumbbell in one hand.","Lift one foot off the ground and balance on the other foot.","Slowly raise your heel as high as possible, using your calf muscles.","Pause for a moment at the top, then slowly lower your heel back down.","Repeat for the desired number of repetitions, then switch to the other leg."],"mediaId":"fKZgDEO"},{"id":"edb-0730","name":"single leg platform slide","name_en":"single leg platform slide","muscle":"legs","equipment":"body weight","target":"hamstrings","bodyPart":"upper legs","secondaryMuscles":["glutes","quadriceps"],"steps":["התחילו בעמידה עם רגל אחת על משטח או לוח החלקה.","כופפו מעט את הברך והחליקו את כף הרגל שעל המשטח אחורה, תוך יישור הרגל.","שמרו על שרירי הליבה מופעלים ועל יציבה ישרה לאורך כל התנועה.","חזרו לאט לתנוחת ההתחלה על ידי החלקת כף הרגל בחזרה למיקום ההתחלתי.","חזרו על התנועה למספר החזרות הרצוי, ולאחר מכן החליפו רגליים."],"steps_en":["Start by standing with one foot on a platform or slide board.","Bend your knee slightly and slide the foot on the platform backward, extending your leg.","Keep your core engaged and maintain a straight posture throughout the movement.","Slowly return to the starting position by sliding your foot back to the initial position.","Repeat the movement for the desired number of repetitions, then switch legs."],"mediaId":"LNE3wfo"},{"id":"edb-1759","name":"סקוואט ברגל אחת","name_en":"single leg squat (pistol) male","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והזרועות ישרות לפניכם.","הרימו את כף הרגל הימנית מהרצפה ויישרו אותה קדימה.","הורידו לאט את הגוף על ידי כיפוף הברך השמאלית ודחיפת האגן אחורה.","שמרו על החזה מורם והגב ישר תוך כדי הירידה.","רדו עד שהירך השמאלית מקבילה לרצפה, או עד כמה שנוח לכם.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו דרך העקב השמאלי כדי לחזור לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו רגליים."],"steps_en":["Stand with your feet shoulder-width apart and arms extended in front of you.","Lift your right foot off the ground and extend it forward.","Slowly lower your body down by bending your left knee and pushing your hips back.","Keep your chest up and your back straight as you lower yourself down.","Lower until your left thigh is parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your left heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"mediaId":"nqs5HGV"},{"id":"edb-1489","name":"סקוואט","name_en":"sissy squat","muscle":"legs","equipment":"body weight","target":"quads","bodyPart":"upper legs","secondaryMuscles":["calves","glutes"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והבהונות פונות מעט החוצה.","אחזו בעצם יציב לשמירה על שיווי משקל במידת הצורך.","הורידו לאט את הגוף על ידי כיפוף הברכיים והישענות מעט לאחור, תוך שמירה על פלג הגוף העליון זקוף.","המשיכו לרדת עד שהירכיים מקבילות לרצפה, או עד כמה שנוח לכם.","עצרו לרגע, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your toes pointing slightly outward.","Hold onto a stable object for balance if needed.","Slowly lower your body by bending your knees and leaning back, keeping your torso upright.","Continue lowering until your thighs are parallel to the ground or as far as you can comfortably go.","Pause for a moment, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"xdYPUtE"},{"id":"edb-0735","name":"כפיפת בטן מלאה","name_en":"sit-up v. 2","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו את הידיים מאחורי הראש כשהמרפקים פונים החוצה.","תוך הפעלת שרירי הבטן, הרימו לאט את פלג הגוף העליון מהרצפה, בכיפוף קדימה עד שהגו נמצא בזווית של 45 מעלות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Bn6TXyO"},{"id":"edb-3679","name":"כפיפת בטן מלאה","name_en":"sit-up with arms on chest","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הצליבו את הזרועות על החזה.","תוך הפעלת שרירי הבטן, הרימו את פלג הגוף העליון מהרצפה לכיוון הברכיים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your knees bent and feet flat on the ground.","Cross your arms over your chest.","Engaging your abs, lift your upper body off the ground towards your knees.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"6ZCiYWQ"},{"id":"edb-3361","name":"skater hops","name_en":"skater hops","muscle":"core","equipment":"body weight","target":"cardiovascular system","bodyPart":"cardio","secondaryMuscles":["quadriceps","hamstrings","glutes","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים.","כופפו מעט את הברכיים וקפצו ימינה, תוך נחיתה על כף הרגל הימנית.","בעת הנחיתה, הניפו את הרגל השמאלית מאחורי הרגל הימנית ונגעו ברצפה עם אצבעות כף הרגל השמאלית.","קפצו מיד שמאלה, תוך נחיתה על כף הרגל השמאלית.","בעת הנחיתה, הניפו את הרגל הימנית מאחורי הרגל השמאלית ונגעו ברצפה עם אצבעות כף הרגל הימנית.","המשיכו להחליף צדדים, תוך קפיצה ונגיעה ברצפה עם כל רגל.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart.","Bend your knees slightly and jump to the right, landing on your right foot.","As you land, swing your left leg behind your right leg and tap the ground with your left toes.","Immediately jump to the left, landing on your left foot.","As you land, swing your right leg behind your left leg and tap the ground with your right toes.","Continue alternating sides, jumping and tapping the ground with each leg.","Repeat for the desired number of repetitions."],"mediaId":"zfNHMN9"},{"id":"edb-2142","name":"ski ergometer","name_en":"ski ergometer","muscle":"triceps","equipment":"skierg machine","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders","forearms"],"steps":["כווננו את גובה המושב ומשעני הרגליים למצב נוח.","אחזו בידיות באחיזה עליונה, כשכפות הידיים פונות למטה.","שבו זקוף עם כפות הרגליים שטוחות על משענות הרגליים.","יישרו את הזרועות לפניכם, תוך שמירה על המרפקים מעט כפופים.","הפעילו את שרירי הזרוע האחוריים ודחפו את הידיות כלפי מטה לכיוון הירכיים.","עצרו לרגע בתחתית התנועה, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and footrests to a comfortable position.","Grasp the handles with an overhand grip, palms facing down.","Sit up straight with your feet flat on the footrests.","Extend your arms straight out in front of you, keeping your elbows slightly bent.","Engage your triceps and push the handles down towards your thighs.","Pause for a moment at the bottom, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"vpQaQkH"},{"id":"edb-3671","name":"ski step","name_en":"ski step","muscle":"core","equipment":"body weight","target":"cardiovascular system","bodyPart":"cardio","secondaryMuscles":["quadriceps","hamstrings","glutes","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים.","כופפו מעט את הברכיים ושמרו על הגב ישר.","קפצו ימינה, תוך נחיתה על כף הרגל הימנית והנפת הרגל השמאלית מאחורי הרגל הימנית.","קפצו מיד שמאלה, תוך נחיתה על כף הרגל השמאלית והנפת הרגל הימנית מאחורי הרגל השמאלית.","המשיכו להחליף קפיצות מצד לצד, תוך חיקוי תנועת סקי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart.","Bend your knees slightly and keep your back straight.","Jump to the right, landing on your right foot while swinging your left leg behind your right leg.","Immediately jump to the left, landing on your left foot while swinging your right leg behind your left leg.","Continue alternating jumps from side to side, mimicking a skiing motion.","Repeat for the desired number of repetitions."],"mediaId":"5MRH8H2"},{"id":"edb-3304","name":"skin the cat","name_en":"skin the cat","muscle":"back","equipment":"body weight","target":"upper back","bodyPart":"back","secondaryMuscles":["shoulders","core"],"steps":["התחילו בתלייה על מוט כשהזרועות שלכם מתוחות לגמרי והגוף רפוי.","הפעילו את שרירי הליבה והרימו את הרגליים כלפי מעלה, תוך קירוב הברכיים לחזה.","המשיכו להרים את הרגליים מעל הראש, תוך מעבר הגוף בין הזרועות.","לאחר שהרגליים מתוחות לגמרי מעל הראש, התחילו להוריד אותן חזרה למצב ההתחלתי.","תוך כדי הורדת הרגליים, אפשרו לגוף לעבור חזרה בין הזרועות עד שאתם תלויים שוב עם הזרועות מתוחות לגמרי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by hanging from a bar with your arms fully extended and your body relaxed.","Engage your core and lift your legs up, bringing your knees towards your chest.","Continue to lift your legs up and over your head, allowing your body to pass through the arms.","Once your legs are fully extended over your head, begin to lower them back down towards the starting position.","As you lower your legs, allow your body to pass back through the arms until you are hanging with your arms fully extended again.","Repeat for the desired number of repetitions."],"mediaId":"MSfvriJ"},{"id":"edb-1425","name":"לחיצת רגליים 45 עם מזחלת","name_en":"sled 45 degrees one leg press","muscle":"glutes","equipment":"sled machine","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["כוונו את מכונת הסלד לזווית של 45 מעלות.","שבו על מכונת הסלד כשהגב צמוד לכרית והרגליים על משטח הרגליים.","הניחו רגל אחת על משטח הרגליים ויישרו את הרגל, תוך דחיפת הסלד הרחק מכם.","כופפו לאט את הברך והורידו את הסלד חזרה למצב ההתחלתי.","חזרו עם הרגל השנייה.","המשיכו להחליף רגליים למספר החזרות הרצוי."],"steps_en":["Adjust the sled machine to a 45-degree angle.","Sit on the sled machine with your back against the pad and your feet on the footplate.","Place one foot on the footplate and extend your leg, pushing the sled away from you.","Slowly bend your knee and lower the sled back to the starting position.","Repeat with the other leg.","Continue alternating legs for the desired number of repetitions."],"mediaId":"WWD6FzI"},{"id":"edb-0738","name":"לחיצת שוקיים 45 עם מזחלת","name_en":"sled 45в° calf press","muscle":"legs","equipment":"sled machine","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings"],"steps":["כוונו את מכונת הסלד לזווית של 45 מעלות.","הניחו את הרגליים על משטח הסלד כשהבהונות מופנות קדימה.","דחפו את משטח הסלד הרחק מכם על ידי יישור הקרסוליים ושרירי השוק.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את משטח הסלד חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the sled machine to a 45-degree angle.","Place your feet on the sled platform with your toes pointing forward.","Push the sled platform away from you by extending your ankles and calves.","Pause for a moment at the top, then slowly lower the sled platform back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"qCNVnaU"},{"id":"edb-0739","name":"לחיצת רגליים","name_en":"sled 45в° leg press","muscle":"glutes","equipment":"sled machine","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["כוונו את המושב ואת משטח הרגליים של מכונת הסלד למצב נוח.","שבו על מכונת הסלד כשהגב צמוד למשענת והרגליים ברוחב הכתפיים על משטח הרגליים.","אחזו בידיות בצדי המושב לצורך יציבות.","דחפו את משטח הרגליים הרחק מהגוף על ידי יישור הרגליים, תוך השארת העקבים על משטח הרגליים.","המשיכו לדחוף עד שהרגליים כמעט מתוחות לגמרי, אך מבלי לנעול את הברכיים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את משטח הרגליים חזרה לכיוון הגוף על ידי כיפוף הברכיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat and footplate of the sled machine to a comfortable position.","Sit on the sled machine with your back against the backrest and your feet shoulder-width apart on the footplate.","Grip the handles on the sides of the seat for stability.","Push the footplate away from your body by extending your legs, keeping your heels on the footplate.","Continue pushing until your legs are almost fully extended, but without locking your knees.","Pause for a moment at the top of the movement, then slowly lower the footplate back towards your body by bending your knees.","Repeat for the desired number of repetitions."],"mediaId":"10Z2DXU"},{"id":"edb-1464","name":"לחיצת רגליים 45 עם מזחלת","name_en":"sled 45в° leg press (back pov)","muscle":"glutes","equipment":"sled machine","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["כוונו את מושב מכונת הסלד כך שהברכיים יהיו בזווית של 45 מעלות.","שבו על מכונת הסלד כשהגב צמוד למשענת והרגליים ברוחב הכתפיים על משטח הרגליים.","אחזו בידיות בצדי המושב לצורך יציבות.","דחפו את משטח הרגליים הרחק מהגוף על ידי יישור הרגליים, תוך השארת העקבים על משטח הרגליים.","עצרו לרגע במצב הישור המלא.","כופפו לאט את הברכיים והורידו את משטח הרגליים חזרה לכיוון הגוף, תוך שליטה בתנועה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat of the sled machine so that your knees are at a 45-degree angle.","Sit on the sled machine with your back against the backrest and your feet shoulder-width apart on the footplate.","Grip the handles on the sides of the seat for stability.","Push the footplate away from your body by extending your legs, keeping your heels on the footplate.","Pause for a moment at the fully extended position.","Slowly bend your knees and lower the footplate back towards your body, controlling the movement.","Repeat for the desired number of repetitions."],"mediaId":"yn2lLSI"},{"id":"edb-1463","name":"לחיצת רגליים 45° עם מזחלת","name_en":"sled 45° leg press (side pov)","muscle":"glutes","equipment":"sled machine","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["כוונו את מושב מכונת הסלד כך שהברכיים יהיו בזווית של 90 מעלות כשהרגליים על משטח הרגליים.","שבו על מכונת הסלד כשהגב שטוח וצמוד למשענת והרגליים ברוחב הכתפיים על משטח הרגליים.","אחזו בידיות בצדי המושב לצורך יציבות.","דחפו את משטח הרגליים כדי ליישר את הרגליים לגמרי.","עצרו לרגע בשיא התנועה, ולאחר מכן כופפו לאט את הברכיים כדי להוריד את משטח הרגליים חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat of the sled machine so that your knees are at a 90-degree angle when your feet are on the footplate.","Sit on the sled machine with your back flat against the backrest and your feet shoulder-width apart on the footplate.","Grip the handles on the sides of the seat for stability.","Push against the footplate to extend your legs, straightening them completely.","Pause for a moment at the top, then slowly bend your knees to lower the footplate back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"2Qh2J1e"},{"id":"edb-0740","name":"לחיצה רחב 45 עם מזחלת","name_en":"sled 45в° leg wide press","muscle":"glutes","equipment":"sled machine","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["כוונו את מכונת הסלד לזווית של 45 מעלות.","שבו על מכונת הסלד כשהגב צמוד לכרית והרגליים על משטח הרגליים.","הניחו את הרגליים ברוחב רחב יותר מהכתפיים.","דחפו את משטח הרגליים כדי ליישר את הרגליים וליישר את הברכיים.","עצרו לרגע בסיום התנועה, ולאחר מכן כופפו לאט את הברכיים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the sled machine to a 45-degree angle.","Sit on the sled machine with your back against the pad and your feet on the foot platform.","Position your feet wider than shoulder-width apart.","Push against the foot platform to extend your legs and straighten your knees.","Pause for a moment at the end of the movement, then slowly bend your knees to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"tj41Nu6"},{"id":"edb-1391","name":"לחיצת רגליים עם מזחלת","name_en":"sled calf press on leg press","muscle":"legs","equipment":"sled machine","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings","quadriceps"],"steps":["כוונו את מושב מכשיר לחיצת הרגליים כך שהברכיים כפופות מעט כשהרגליים על הסלד.","הניחו את הרגליים ברוחב הכתפיים על הסלד, כשהבהונות מופנות קדימה.","שחררו את ידיות הביטחון ודחפו את הסלד הרחק מכם על ידי יישור הברכיים והקרסוליים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הסלד חזרה על ידי כיפוף הברכיים והקרסוליים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat of the leg press machine so that your knees are slightly bent when your feet are on the sled.","Place your feet shoulder-width apart on the sled, with your toes pointing forward.","Release the safety handles and push the sled away from you by extending your knees and ankles.","Pause for a moment at the top of the movement, then slowly lower the sled back down by bending your knees and ankles.","Repeat for the desired number of repetitions."],"mediaId":"ykHcWme"},{"id":"edb-0741","name":"האק סקוואט עם מזחלת","name_en":"sled closer hack squat","muscle":"glutes","equipment":"sled machine","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["כוונו את מכונת הסלד למשקל נוח והתמקמו כשהגב צמוד לכרית.","הניחו את הרגליים ברוחב הכתפיים על המשטח, כשהבהונות מופנות מעט החוצה.","אחזו בידיות בצדי המכונה לצורך יציבות.","הפעילו את שרירי הליבה והורידו לאט את הגוף על ידי כיפוף הברכיים והירכיים, תוך שמירה על גב ישר.","המשיכו לרדת עד שהירכיים מקבילות לרצפה או מעט מתחת לכך.","עצרו לרגע בתחתית, ולאחר מכן דחפו דרך העקבים כדי ליישר את הרגליים ולחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the sled machine to a comfortable weight and position yourself with your back against the pad.","Place your feet shoulder-width apart on the platform, toes slightly pointed outwards.","Grip the handles on the sides of the machine for stability.","Engage your core and slowly lower your body by bending your knees and hips, keeping your back straight.","Continue lowering until your thighs are parallel to the ground or slightly below.","Pause for a moment at the bottom, then push through your heels to extend your legs and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"gf3ZjB9"},{"id":"edb-0742","name":"הרמת עקבים עם מזחלת","name_en":"sled forward angled calf raise","muscle":"legs","equipment":"sled machine","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings","glutes"],"steps":["כוונו את מכונת הסלד למשקל נוח והתמקמו על המכונה כשקצות כפות הרגליים על המשטח והעקבים תלויים באוויר.","הניחו את הידיים על הידיות או בצדי המכונה לתמיכה.","הפעילו את שרירי השוק והרימו לאט את העקבים כמה שיותר גבוה, תוך דחיפה נגד ההתנגדות של הסלד.","עצרו לרגע בשיא התנועה, ואז הורידו לאט את העקבים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the sled machine to a comfortable weight and position yourself on the machine with your toes on the platform and your heels hanging off.","Place your hands on the handles or the sides of the machine for support.","Engage your calves and slowly raise your heels as high as possible, pushing against the resistance of the sled.","Pause for a moment at the top of the movement, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"XDOiFns"},{"id":"edb-0743","name":"האק סקוואט עם מזחלת","name_en":"sled hack squat","muscle":"glutes","equipment":"sled machine","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["כוונו את מכונת הסלד למצב נוח לגובה שלכם.","עמדו כשהרגליים ברוחב הכתפיים על המשטח, כשהבהונות מופנות מעט החוצה.","אחזו בידיות או במוטות לצורך יציבות.","הורידו את הגוף על ידי כיפוף הברכיים והירכיים, תוך שמירה על גב ישר וחזה מורם.","המשיכו לרדת עד שהירכיים מקבילות לרצפה או מעט מתחת לכך.","עצרו לרגע, ולאחר מכן דחפו דרך העקבים כדי להרים את הגוף חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the sled machine to a comfortable position for your height.","Stand with your feet shoulder-width apart on the platform, toes slightly pointed outwards.","Hold onto the handles or bars for stability.","Lower your body by bending your knees and hips, keeping your back straight and chest up.","Continue lowering until your thighs are parallel to the ground or slightly below.","Pause for a moment, then push through your heels to raise your body back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Qa55kX1"},{"id":"edb-2334","name":"לחיצת שוקיים בשכיבה עם מזחלת","name_en":"sled lying calf press","muscle":"legs","equipment":"sled machine","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings","glutes"],"steps":["כיוונו את מכונת הסלד למשקל נוח.","שבו על מכונת הסלד כשהגב צמוד לכרית והרגליים על המשטח.","הניחו את הבהונות וכריות כפות הרגליים על קצה המשטח, כשהעקבים תלויים באוויר.","דחפו את המשטח הרחק מכם על ידי יישור הקרסוליים, תוך שמירה על כיפוף קל בברכיים.","המשיכו לדחוף עד ששרירי השוק מכווצים לגמרי.","החזיקו את הכיווץ לרגע, ולאחר מכן הורידו לאט את המשטח חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the sled machine to a comfortable weight.","Sit on the sled machine with your back against the pad and your feet on the platform.","Place your toes and the balls of your feet on the edge of the platform, with your heels hanging off.","Push the platform away from you by extending your ankles, keeping your knees slightly bent.","Continue pushing until your calves are fully contracted.","Hold the contraction for a moment, then slowly lower the platform back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"g376LuL"},{"id":"edb-0744","name":"סקוואט בשכיבה עם מזחלת","name_en":"sled lying squat","muscle":"glutes","equipment":"sled machine","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["כיוונו את מכונת הסלד למשקל נוח.","שכבו על הגב על מכונת הסלד כשהרגליים על משטח הרגליים.","הניחו את הרגליים ברוחב הכתפיים ובזווית קלה החוצה.","אחזו בידיות מכונת הסלד לצורך יציבות.","הפעילו את שרירי הישבן וליבת הגוף.","דחפו דרך העקבים ויישרו את הרגליים כדי להרים את הסלד.","הורידו את הסלד חזרה על ידי כיפוף הברכיים והירכיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the sled machine to a comfortable weight.","Lie on your back on the sled machine with your feet on the footplate.","Position your feet shoulder-width apart and slightly angled outwards.","Grip the handles of the sled machine for stability.","Engage your glutes and core muscles.","Push through your heels and extend your legs to lift the sled.","Lower the sled back down by bending your knees and hips.","Repeat for the desired number of repetitions."],"mediaId":"9n2149Z"},{"id":"edb-1392","name":"לחיצת רגליים ברגל אחת עם מזחלת","name_en":"sled one leg calf press on leg press","muscle":"legs","equipment":"sled machine","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings","glutes"],"steps":["כוונו את מושב מכשיר לחיצת הרגליים כך שהברכיים כפופות מעט כשהרגליים על הסלד.","שבו על המכונה כשהגב צמוד למשענת והרגליים על הסלד, ברוחב הכתפיים.","הניחו את הבהונות וכריות כפות הרגליים על הסלד, כשהעקבים מורמים.","דחפו את הסלד קדימה על ידי יישור הקרסוליים, תוך שמירה על כיפוף קל בברכיים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הסלד חזרה על ידי כיפוף הקרסוליים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat of the leg press machine so that your knees are slightly bent when your feet are on the sled.","Sit on the machine with your back against the backrest and your feet on the sled, shoulder-width apart.","Place your toes and the balls of your feet on the sled, keeping your heels off.","Push the sled forward by extending your ankles, keeping your knees slightly bent.","Pause for a moment at the top, then slowly lower the sled back down by flexing your ankles.","Repeat for the desired number of repetitions."],"mediaId":"u0pLNgz"},{"id":"edb-1496","name":"sledge hammer","name_en":"sledge hammer","muscle":"core","equipment":"hammer","target":"abs","bodyPart":"waist","secondaryMuscles":["forearms","shoulders"],"steps":["עמדו כשהרגליים ברוחב הכתפיים ואחזו בפטיש הכבד בשתי הידיים.","הפעילו את הליבה ושמרו על גב ישר.","הניפו את הפטיש הכבד כלפי מטה לכיוון הרצפה, תוך שימוש בכוח הליבה ופלג הגוף העליון.","תוך כדי ההנפה כלפי מטה, סובבו את הירכיים והעבירו את הכוח לפטיש.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold the sledge hammer with both hands.","Engage your core and keep your back straight.","Swing the sledge hammer down towards the ground, using your core and upper body strength.","As you swing down, pivot your hips and transfer the force to the hammer.","Repeat for the desired number of repetitions."],"mediaId":"REXmfVC"},{"id":"edb-0746","name":"משיכת כתפיים","name_en":"smith back shrug","muscle":"back","equipment":"smith machine","target":"traps","bodyPart":"back","secondaryMuscles":["shoulders"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","אחזו במוט באחיזה עליונה, כשהידיים מעט רחבות יותר מרוחב הכתפיים.","שמרו על הזרועות ישרות ואפשרו למוט להישאר תלוי מול הירכיים.","הרימו את הכתפיים ישר כלפי האוזניים, תוך כיווץ שרירי הטרפז בשיא התנועה.","החזיקו לרגע, ולאחר מכן הורידו את הכתפיים חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your knees slightly bent.","Grasp the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Keep your arms straight and allow the barbell to hang in front of your thighs.","Lift your shoulders straight up towards your ears, squeezing your traps at the top.","Hold for a moment, then lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"MzNnwx9"},{"id":"edb-0747","name":"לחיצה מאחורי העורף","name_en":"smith behind neck press","muscle":"shoulders","equipment":"smith machine","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["כוונו את גובה המושב של מכונת הסמית' כך שהמוט יהיה בגובה הכתפיים.","עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","אחזו במוט באחיזה עליונה, ברוחב מעט גדול מרוחב הכתפיים.","הרימו את המוט מהמעמד וקחו צעד אחורה, תוך שמירה על עמידה יציבה.","הורידו את המוט לעורף, תוך שמירה על המרפקים פונים קדימה.","דחפו את המוט כלפי מעלה עד שהזרועות מתוחות לגמרי.","עצרו לרגע בשיא, ולאחר מכן הורידו לאט את המוט חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height of the smith machine so that the bar is at shoulder level.","Stand with your feet shoulder-width apart and your knees slightly bent.","Grasp the bar with an overhand grip, slightly wider than shoulder-width apart.","Lift the bar off the rack and step back, maintaining a stable stance.","Lower the bar down to the back of your neck, keeping your elbows pointing forward.","Press the bar up overhead until your arms are fully extended.","Pause for a moment at the top, then slowly lower the bar back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Gpn4ADc"},{"id":"edb-0748","name":"לחיצת חזה","name_en":"smith bench press","muscle":"chest","equipment":"smith machine","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["כוונו את גובה מוט מכונת הסמית' לגובה החזה.","שכבו ישר על הספסל כשהרגליים נטועות היטב על הרצפה.","אחזו במוט באחיזה עליונה, ברוחב מעט רחב יותר מהכתפיים.","שחררו את המוט מהמעמד והורידו אותו לכיוון החזה, תוך שמירה על המרפקים קרובים לגוף.","עצרו לרגע כאשר המוט נוגע בחזה.","דחפו את המוט חזרה למעלה למצב ההתחלתי, תוך יישור מלא של הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the height of the smith machine bar to chest level.","Lie flat on the bench with your feet firmly planted on the ground.","Grip the bar with an overhand grip slightly wider than shoulder-width apart.","Unrack the bar and lower it towards your chest, keeping your elbows tucked in.","Pause for a moment when the bar touches your chest.","Push the bar back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"trqKQv2"},{"id":"edb-0749","name":"גוד מורנינג בהטיה","name_en":"smith bent knee good morning","muscle":"glutes","equipment":"smith machine","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","lower back"],"steps":["התחילו בעמידה כשהרגליים ברוחב הכתפיים, הבהונות מופנות קדימה.","הניחו את המוט על פלג הגוף העליון, כך שהוא נשען על שרירי הטרפז.","כופפו מעט את הברכיים והטו את הגוף קדימה במפרקי הירך, תוך שמירה על גב ישר.","הורידו את הגו עד שהוא מקביל לרצפה, תוך הרגשת מתיחה בשרירי הירך האחוריים.","הפעילו את שרירי הישבן והירך האחורית כדי להרים את פלג הגוף העליון חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by standing with your feet shoulder-width apart, toes pointing forward.","Place the barbell across your upper back, resting it on your traps.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Lower your torso until it is parallel to the ground, feeling a stretch in your hamstrings.","Engage your glutes and hamstrings to raise your torso back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"1bQkKZK"},{"id":"edb-1359","name":"חתירה בהטיה","name_en":"smith bent over row","muscle":"back","equipment":"smith machine","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["כוונו את מכונת הסמית' כך שהמוט יהיה בגובה הירכיים.","עמדו מול המוט כשהרגליים ברוחב הכתפיים.","כופפו מעט את הברכיים והטו את הגוף קדימה במפרקי הירך, תוך שמירה על גב ישר.","אחזו במוט באחיזה עליונה, כשהידיים ברוחב מעט גדול מרוחב הכתפיים.","משכו את המוט לכיוון החלק התחתון של החזה, תוך כיווץ שכמות הכתפיים זו לזו.","עצרו לרגע בשיא, ולאחר מכן הורידו לאט את המוט חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up the smith machine with the bar at hip height.","Stand facing the bar with your feet shoulder-width apart.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Grasp the bar with an overhand grip, hands slightly wider than shoulder-width apart.","Pull the bar towards your lower chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the bar back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ZX9UZmj"},{"id":"edb-0750","name":"סקוואט","name_en":"smith chair squat","muscle":"legs","equipment":"smith machine","target":"quads","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings","calves"],"steps":["כוונו את גובה מוט מכונת הסמית' למצב נוח.","עמדו עם הרגליים ברוחב הכתפיים והבהונות פונות מעט החוצה.","הניחו את המוט על פלג הגוף העליון, כך שהוא נשען על שרירי הטרפז.","הפעילו את שרירי הליבה ושמרו על החזה מורם תוך הורדה לאטה של הגוף על ידי כיפוף הברכיים והירכיים.","המשיכו לרדת עד שהירכיים מקבילות לרצפה, או עד למקסימום שנוח לכם.","עצרו לרגע, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the height of the smith machine bar to a comfortable position.","Stand with your feet shoulder-width apart, toes slightly turned out.","Place the barbell across your upper back, resting it on your traps.","Engage your core and keep your chest up as you slowly lower your body by bending your knees and hips.","Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Gu2rNJd"},{"id":"edb-0751","name":"לחיצת חזה אחיזה צרה","name_en":"smith close-grip bench press","muscle":"triceps","equipment":"smith machine","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["כוונו את גובה המושב והתמקמו על הספסל כשהרגליים שטוחות על הרצפה.","אחזו במוט באחיזה צרה, מעט צרה יותר מרוחב הכתפיים.","הורידו את המוט לכיוון החזה, תוך שמירה על המרפקים קרובים לגוף.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself on the bench with your feet flat on the ground.","Grasp the barbell with a close grip, slightly narrower than shoulder-width apart.","Lower the barbell towards your chest, keeping your elbows close to your body.","Pause for a moment at the bottom, then push the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"WcHl7ru"},{"id":"edb-0752","name":"דדליפט","name_en":"smith deadlift","muscle":"glutes","equipment":"smith machine","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps","lower back"],"steps":["כוונו את מכונת הסמית' כך שהמוט יהיה בגובה הירכיים.","עמדו עם הרגליים ברוחב הכתפיים, כשהבהונות פונות מעט החוצה.","כופפו בירכיים ובברכיים, תוך שמירה על גב ישר וחזה מורם, ואחזו במוט באחיזה עליונה ברוחב מעט רחב יותר מהכתפיים.","הפעילו את שרירי הליבה והרימו את המוט על ידי יישור הירכיים והברכיים, תוך שמירה על המוט קרוב לגוף.","עמדו זקוף, תוך יישור מלא של הירכיים והברכיים.","הורידו את המוט חזרה על ידי כיפוף בירכיים ובברכיים, תוך שמירה על שליטה וגב ישר.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up the smith machine with the bar at hip height.","Stand with your feet shoulder-width apart, toes pointing slightly outward.","Bend at the hips and knees, keeping your back straight and chest up, and grip the bar with an overhand grip slightly wider than shoulder-width apart.","Engage your core and lift the bar by extending your hips and knees, keeping the bar close to your body.","Stand up straight, fully extending your hips and knees.","Lower the bar back down by bending at the hips and knees, maintaining control and keeping your back straight.","Repeat for the desired number of repetitions."],"mediaId":"UfePqpx"},{"id":"edb-0753","name":"לחיצת חזה בשיפוע שלילי","name_en":"smith decline bench press","muscle":"chest","equipment":"smith machine","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["כוונו את הספסל המשופע כלפי מטה לזווית הרצויה.","שכבו על הספסל כשהרגליים מקובעות מתחת לכריות הרגליים.","אחזו במוט באחיזה עליונה מעט רחבה יותר מרוחב הכתפיים.","הרימו את המוט מהמעמד והורידו אותו לאט לכיוון החזה, כשהמרפקים צמודים לגוף.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the decline bench to the desired angle.","Lie down on the bench with your feet secured under the foot pads.","Grasp the barbell with an overhand grip slightly wider than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in.","Pause for a moment at the bottom, then push the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ETZfAbZ"},{"id":"edb-0754","name":"לחיצה אחיזה הפוכה בשיפוע שלילי","name_en":"smith decline reverse-grip press","muscle":"chest","equipment":"smith machine","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["כוונו את מכונת הסמית' למצב שיפוע כלפי מטה.","שכבו על הספסל כשהרגליים מקובעות מתחת לכריות הרגליים.","אחזו את המוט באחיזה הפוכה, כאשר הידיים מעט רחבות יותר מרוחב הכתפיים.","שחררו את המוט מהמעמד והורידו אותו לכיוון החזה, תוך שמירה על המרפקים קרובים לגוף.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the smith machine to a decline position.","Lie down on the bench with your feet secured under the foot pads.","Grasp the barbell with a reverse grip, hands slightly wider than shoulder-width apart.","Unrack the barbell and lower it towards your chest, keeping your elbows tucked in.","Pause for a moment at the bottom, then push the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"MY9P1WA"},{"id":"edb-1433","name":"סקוואט קדמי","name_en":"smith front squat (clean grip)","muscle":"glutes","equipment":"smith machine","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves","core"],"steps":["כוונו את מכונת הסמית' כך שהמוט יהיה בגובה הכתפיים.","עמדו מול המוט כשהרגליים ברוחב הכתפיים.","אחזו במוט באחיזה עליונה, מעט רחבה יותר מרוחב הכתפיים.","קחו צעד אחורה והניחו את המוט על הכתפיים הקדמיות, כך שהוא נשען על עצם הבריח ושרירי הכתף.","שמרו על החזה מורם, הגב ישר ושרירי הליבה מופעלים.","הורידו את הגוף על ידי כיפוף בברכיים ובירכיים, כאילו אתם יושבים אחורה על כיסא.","המשיכו לרדת עד שהירכיים מקבילות לרצפה או מעט מתחת לכך.","עצרו לרגע, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up the smith machine with the barbell at shoulder height.","Stand facing the barbell with your feet shoulder-width apart.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Step back and position the barbell on your front shoulders, resting it on your collarbone and deltoids.","Keep your chest up, back straight, and core engaged.","Lower your body by bending at the knees and hips, as if sitting back into a chair.","Continue lowering until your thighs are parallel to the ground or slightly below.","Pause for a moment, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"lFhb2Rw"},{"id":"edb-3281","name":"סקוואט","name_en":"smith full squat","muscle":"glutes","equipment":"smith machine","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["כוונו את מכונת הסמית' כך שהמוט יהיה בגובה הכתפיים.","עמדו עם הרגליים ברוחב הכתפיים והבהונות פונות מעט החוצה.","עברו מתחת למוט והניחו אותו על פלג הגוף העליון, כך שהוא נשען על שרירי הטרפז.","אחזו במוט כשהידיים מעט רחבות יותר מרוחב הכתפיים.","שחררו את המוט מהמעמד וקחו צעד אחורה, תוך שמירה על עמידה יציבה.","תוך שמירה על החזה מורם ושרירי הליבה מופעלים, התחילו את הכפיפה על ידי דחיפת הירכיים אחורה וכיפוף הברכיים.","הורידו את הגוף עד שהירכיים מקבילות לרצפה, או עד כמה שהגמישות שלכם מאפשרת.","עצרו לרגע בתחתית, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up the smith machine with the barbell at shoulder height.","Stand with your feet shoulder-width apart, toes slightly turned out.","Step under the bar and position it across your upper back, resting on your traps.","Grip the bar with your hands slightly wider than shoulder-width apart.","Unrack the bar and take a step back, maintaining a stable stance.","Keeping your chest up and core engaged, initiate the squat by pushing your hips back and bending your knees.","Lower your body until your thighs are parallel to the ground, or as low as your flexibility allows.","Pause for a moment at the bottom, then drive through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"NNoHCEA"},{"id":"edb-0755","name":"האק סקוואט","name_en":"smith hack squat","muscle":"glutes","equipment":"smith machine","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["כוונו את המוט על מכונת הסמית' לגובה מתאים לגוף שלכם.","עמדו כשהרגליים ברוחב הכתפיים, הבהונות מופנות מעט החוצה.","התמקמו מתחת למוט, כך שהוא נשען על שרירי הטרפז העליונים והכתפיים.","אחזו במוט באחיזה עליונה, מעט רחבה יותר מרוחב הכתפיים.","הפעילו את שרירי הליבה ושמרו על החזה מורם בזמן שחרור המוט מהמעמד.","קחו צעד אחורה והניחו את הרגליים ברוחב מעט רחב יותר מהכתפיים.","כופפו את הברכיים והורידו את הגוף, תוך שמירה על החזה מורם והגב ישר.","המשיכו לרדת עד שהירכיים מקבילות לרצפה או מעט מתחת לכך.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the barbell on the smith machine to an appropriate height for your body.","Stand with your feet shoulder-width apart, toes slightly pointed outwards.","Position yourself under the barbell, resting it on your upper traps and shoulders.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Engage your core and keep your chest up as you unrack the barbell.","Take a step back and position your feet slightly wider than shoulder-width apart.","Bend your knees and lower your body down, keeping your chest up and back straight.","Continue descending until your thighs are parallel to the ground or slightly below.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ZuPXtCK"},{"id":"edb-0756","name":"הרמת אגן","name_en":"smith hip raise","muscle":"core","equipment":"smith machine","target":"abs","bodyPart":"waist","secondaryMuscles":["glutes","hamstrings"],"steps":["התמקמו על מכונת הסמית' כשהגב צמוד לכרית והרגליים ברוחב הכתפיים.","הניחו את הידיים על המוט, ברוחב מעט רחב יותר מהכתפיים.","הפעילו את שרירי הליבה והישבן, ולאחר מכן דחפו דרך העקבים כדי להרים את הירכיים מהרצפה.","המשיכו להרים עד שהגוף יוצר קו ישר מהברכיים ועד לכתפיים.","החזיקו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את האגן בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Position yourself on the smith machine with your back against the pad and your feet shoulder-width apart.","Place your hands on the barbell, slightly wider than shoulder-width apart.","Engage your core and glutes, then push through your heels to raise your hips off the ground.","Continue lifting until your body forms a straight line from your knees to your shoulders.","Hold for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"CqhoytW"},{"id":"edb-0757","name":"לחיצת חזה בשיפוע","name_en":"smith incline bench press","muscle":"chest","equipment":"smith machine","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["כוונו את הספסל לשיפוע של 30-45 מעלות.","שבו על הספסל כשהגב שטוח וצמוד לכרית והרגליים נטועות היטב על הרצפה.","אחזו במוט באחיזה עליונה מעט רחבה יותר מרוחב הכתפיים.","שחררו את המוט מהמעמד והורידו אותו לאט לכיוון החלק העליון של החזה, תוך שמירה על המרפקים מכונסים מעט פנימה.","עצרו לרגע בתחתית, ולאחר מכן דחפו את המוט חזרה למעלה למצב ההתחלתי, תוך יישור מלא של הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the bench to a 30-45 degree incline.","Sit on the bench with your back flat against the pad and feet firmly on the ground.","Grasp the barbell with an overhand grip slightly wider than shoulder-width apart.","Unrack the barbell and lower it slowly towards your upper chest, keeping your elbows slightly tucked in.","Pause for a moment at the bottom, then push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"5v7KYld"},{"id":"edb-0758","name":"לחיצה אחיזה הפוכה בשיפוע","name_en":"smith incline reverse-grip press","muscle":"chest","equipment":"smith machine","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["כוונו את מושב מכונת הסמית' לזווית שיפוע נוחה.","שבו על המכונה כשהגב צמוד לכרית והרגליים שטוחות על הרצפה.","אחזו במוט באחיזה עליונה ברוחב מעט רחב יותר מהכתפיים.","שחררו את המוט מהמעמד והורידו אותו לאט לכיוון החזה, תוך שמירה על המרפקים מכונסים פנימה.","עצרו לרגע כאשר המוט קרוב מעל החזה.","דחפו את המוט חזרה למעלה למצב ההתחלתי, תוך יישור מלא של הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat of the smith machine to a comfortable incline angle.","Sit on the machine with your back against the pad and your feet flat on the ground.","Grasp the bar with an overhand grip that is slightly wider than shoulder-width apart.","Unrack the bar and lower it slowly towards your chest, keeping your elbows tucked in.","Pause for a moment when the bar is just above your chest.","Push the bar back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"78VqWQK"},{"id":"edb-0759","name":"smith incline shoulder raises","name_en":"smith incline shoulder raises","muscle":"chest","equipment":"smith machine","target":"serratus anterior","bodyPart":"chest","secondaryMuscles":["deltoids","trapezius"],"steps":["כוונו את מכונת הסמית' למצב שיפוע כלפי מעלה.","עמדו מול המכונה עם הרגליים ברוחב הכתפיים.","אחזו במוט באחיזה עליונה, ברוחב מעט גדול מרוחב הכתפיים.","שמרו על גב ישר ושרירי ליבה פעילים.","הרימו את המוט כלפי התקרה, תוך הובלת התנועה עם המרפקים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the smith machine to an incline position.","Stand facing the machine with your feet shoulder-width apart.","Grasp the bar with an overhand grip, slightly wider than shoulder-width apart.","Keep your back straight and core engaged.","Raise the barbell up towards the ceiling, leading with your elbows.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ayAHcEm"},{"id":"edb-0760","name":"לחיצת רגליים","name_en":"smith leg press","muscle":"glutes","equipment":"smith machine","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["כוונו את המושב ואת משטח הרגליים של מכונת הסמית' למצב נוח.","שבו על המכשיר כשהגב צמוד למשענת והרגליים ברוחב הכתפיים על משטח הדריכה.","אחזו בידיות או בצדי המכונה לצורך יציבות.","דחפו את משטח הרגליים הרחק מכם על ידי יישור הרגליים, תוך שמירה על הגב צמוד למשענת.","עצרו לרגע במצב הישור המלא.","כופפו לאט את הברכיים והורידו את משטח הרגליים חזרה אליכם, לחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat and footplate of the smith machine to a comfortable position.","Sit on the machine with your back against the backrest and your feet shoulder-width apart on the footplate.","Grasp the handles or sides of the machine for stability.","Push the footplate away from you by extending your legs, keeping your back against the backrest.","Pause for a moment at the fully extended position.","Slowly bend your knees and lower the footplate back towards you, returning to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"7zdxRTl"},{"id":"edb-1434","name":"סקוואט נמוך","name_en":"smith low bar squat","muscle":"glutes","equipment":"smith machine","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["כוונו את מכונת הסמית' כך שהמוט יהיה בגובה שמאפשר לכם להניח אותו בנוחות על פלג הגוף העליון.","עמדו כשהרגליים ברוחב הכתפיים, הבהונות מעט מופנות החוצה.","עברו מתחת למוט והניחו אותו על פלג הגוף העליון, כך שהוא נשען על שרירי הטרפז.","אחזו במוט כשהידיים מעט רחבות יותר מרוחב הכתפיים.","שחררו את המוט מהמעמד על ידי יישור הרגליים וצעד אחורה מהמעמד.","שאפו אוויר עמוק והדקו את שרירי הליבה.","התחילו את הכפיפה על ידי דחיפת הירכיים אחורה וכיפוף הברכיים.","הורידו את הגוף עד שהירכיים מקבילות לרצפה או מעט מתחת לכך.","שמרו על החזה מורם והגב ישר לאורך כל התנועה.","דחפו דרך העקבים כדי לחזור לעמידה, תוך יישור האגן והברכיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up the smith machine with the barbell at a height that allows you to comfortably rest it on your upper back.","Stand with your feet shoulder-width apart, toes slightly turned outwards.","Step under the bar and position it across your upper back, resting it on your traps.","Grip the bar with your hands slightly wider than shoulder-width apart.","Unrack the bar by straightening your legs and stepping back from the rack.","Take a deep breath and brace your core.","Initiate the squat by pushing your hips back and bending your knees.","Lower your body until your thighs are parallel to the ground or slightly below.","Keep your chest up and your back straight throughout the movement.","Drive through your heels to stand back up, extending your hips and knees.","Repeat for the desired number of repetitions."],"mediaId":"RGLscZM"},{"id":"edb-1683","name":"כפיפת מרפק במכונת סמית'","name_en":"smith machine bicep curl","muscle":"biceps","equipment":"smith machine","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["כוונו את גובה מוט מכונת הסמית' לגובה המותניים.","עמדו מול מכונת הסמית' כשהרגליים ברוחב הכתפיים.","אחזו במוט באחיזה תחתית, כשהידיים מעט רחבות יותר מהכתפיים.","שמרו על המרפקים צמודים לגוף והזרועות העליונות קבועות.","נשפו וכופפו את המוט כלפי מעלה לכיוון הכתפיים, תוך כיווץ שריר הביצפס.","עצרו לרגע בשיא התנועה, תוך כיווץ שריר הביצפס.","שאפו אוויר והורידו לאט את המוט חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the height of the smith machine bar to be at waist level.","Stand facing the smith machine with your feet shoulder-width apart.","Grasp the bar with an underhand grip, hands slightly wider than shoulder-width apart.","Keep your elbows close to your sides and your upper arms stationary.","Exhale and curl the bar up towards your shoulders, contracting your biceps.","Pause for a moment at the top of the movement, squeezing your biceps.","Inhale and slowly lower the bar back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"zILLZ98"},{"id":"edb-1625","name":"לחיצת חזה אחיזה צרה בשיפוע שלילי במכונת סמית'","name_en":"smith machine decline close grip bench press","muscle":"triceps","equipment":"smith machine","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["כוונו את הספסל על מכונת הסמית' למצב שיפוע כלפי מטה.","שכבו על הספסל כשהרגליים נטועות היטב על הרצפה.","אחזו במוט באחיזה צרה, מעט צרה יותר מרוחב הכתפיים.","הרימו את המוט מהמעמד והורידו אותו לאט לכיוון החזה, כשהמרפקים צמודים לגוף.","עצרו לרגע כאשר המוט נמצא ממש מעל החזה.","דחפו את המוט בחזרה למצב ההתחלתי, תוך יישור מלא של הידיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the bench on the smith machine to a decline position.","Lie down on the bench with your feet firmly planted on the ground.","Grasp the barbell with a close grip, slightly narrower than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows close to your body.","Pause for a moment when the barbell is just above your chest.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"yB9SvIF"},{"id":"edb-1752","name":"פשיטת מרפק בשיפוע במכונת סמית'","name_en":"smith machine incline tricep extension","muscle":"triceps","equipment":"smith machine","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["כוונו את מושב מכונת הסמית' כך שהמוט יהיה בגובה הכתפיים.","שבו על הספסל כשהגב צמוד לכרית והרגליים שטוחות על הרצפה.","אחזו במוט באחיזה עליונה, ברוחב מעט גדול מרוחב הכתפיים.","יישרו את הזרועות לגמרי, הרימו את המוט מהמעמד והחזיקו אותו ישר מעל החזה.","הורידו לאט את המוט לכיוון המצח, תוך שמירה על המרפקים קרובים לראש.","עצרו לרגע בתחתית, ולאחר מכן דחפו את המוט חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat of the smith machine so that the bar is at shoulder height.","Sit on the bench with your back against the pad and your feet flat on the ground.","Grasp the bar with an overhand grip, slightly wider than shoulder-width apart.","Extend your arms fully, lifting the bar off the rack and holding it directly above your chest.","Lower the bar slowly towards your forehead, keeping your elbows close to your head.","Pause for a moment at the bottom, then push the bar back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"o8aOcrz"},{"id":"edb-1626","name":"לחיצת חזה אחיזה צרה בשיפוע שלילי הפוך במכונת סמית'","name_en":"smith machine reverse decline close grip bench press","muscle":"chest","equipment":"smith machine","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["כוונו את מכונת הסמית' למצב שיפוע כלפי מטה.","שכבו על הספסל כשהרגליים מקובעות מתחת לכריות הרגליים.","אחזו במוט באחיזה צרה, מעט צרה יותר מרוחב הכתפיים.","הרימו את המוט מהמעמד והורידו אותו לאט לכיוון החזה, כשהמרפקים צמודים לגוף.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the smith machine to a decline position.","Lie down on the bench with your feet secured under the foot pads.","Grasp the barbell with a close grip, slightly narrower than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in.","Pause for a moment at the bottom, then push the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"QyO6Uma"},{"id":"edb-0761","name":"חתירה צר","name_en":"smith narrow row","muscle":"back","equipment":"smith machine","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","rear deltoids"],"steps":["כוונו את גובה המושב והתמקמו על המכונה כשהרגליים שטוחות על הרצפה.","אחזו בידיות באחיזה עליונה, ברוחב מעט צר יותר מרוחב הכתפיים.","שמרו על גב ישר וחזה מורם תוך משיכת הידיות לכיוון הגוף, תוך כיווץ שכמות הכתפיים זו לזו.","עצרו לרגע בשיא התנועה, ולאחר מכן שחררו לאט את הידיות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself on the machine with your feet flat on the floor.","Grasp the handles with an overhand grip, slightly narrower than shoulder-width apart.","Keep your back straight and your chest up as you pull the handles towards your body, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"JGKowMS"},{"id":"edb-1360","name":"חתירה ביד אחת","name_en":"smith one arm row","muscle":"back","equipment":"smith machine","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["כוונו את גובה מוט מכונת הסמית' לגובה המותניים.","עמדו מול מכונת הסמית' כשהרגליים ברוחב הכתפיים.","כופפו מעט את הברכיים והטו את הגוף קדימה במפרקי הירך, תוך שמירה על גב ישר.","אחזו במוט ביד אחת באחיזה עליונה, כשכף היד פונה כלפי מטה.","שמרו על המרפק קרוב לגוף ומשכו את המוט לכיוון המותניים, תוך כיווץ שכמות הכתפיים זו לזו.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את המוט חזרה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו ליד השנייה."],"steps_en":["Adjust the height of the smith machine bar to waist level.","Stand facing the smith machine with your feet shoulder-width apart.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Grasp the bar with one hand using an overhand grip, with your palm facing down.","Keep your elbow close to your body and pull the bar towards your waist, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly lower the bar back to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"mediaId":"Q4DSJPC"},{"id":"edb-1393","name":"הרמת עקבים ברגל אחת","name_en":"smith one leg floor calf raise","muscle":"legs","equipment":"smith machine","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings","glutes"],"steps":["התמקמו על הרצפה מתחת למוט מכונת הסמית', כשהגב שלכם פונה הרחק מהמכונה.","הניחו את כריות כפות הרגליים על משטח מוגבה, כמו דיסקית משקולת או בלוק.","הניחו את מוט מכונת הסמית' על השוקיים, מעט מעל הקרסוליים.","אחזו במוט בידיים לצורך יציבות.","הרימו את העקבים מהרצפה על ידי יישור הקרסוליים, תוך הרמת הגוף כלפי מעלה.","עצרו בשיא התנועה, ולאחר מכן הורידו לאט את העקבים חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Position yourself on the floor under the smith machine bar, facing away from the machine.","Place the balls of your feet on a raised surface, such as a weight plate or block.","Position the smith machine bar across your lower legs, just above your ankles.","Hold onto the bar with your hands for stability.","Raise your heels off the ground by extending your ankles, lifting your body up.","Pause at the top of the movement, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"9GXrTE6"},{"id":"edb-0762","name":"חתירת כתף אחורית","name_en":"smith rear delt row","muscle":"shoulders","equipment":"smith machine","target":"delts","bodyPart":"shoulders","secondaryMuscles":["trapezius","rhomboids","biceps"],"steps":["כוונו את גובה המושב והתמקמו על המכונה כשהחזה צמוד לכרית והרגליים שטוחות על הרצפה.","אחזו בידיות באחיזה עליונה, ברוחב מעט גדול מרוחב הכתפיים.","שמרו על גב ישר ושרירי ליבה מופעלים תוך משיכת הידיות לכיוון החזה, תוך כיווץ שכמות הכתפיים זו לזו.","עצרו לרגע בשיא התנועה, ולאחר מכן שחררו לאט את הידיות חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself on the machine with your chest against the pad and your feet flat on the ground.","Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.","Keep your back straight and your core engaged as you pull the handles towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly release the handles back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"nFUwqG6"},{"id":"edb-0763","name":"smith reverse calf raises","name_en":"smith reverse calf raises","muscle":"legs","equipment":"smith machine","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings"],"steps":["כוונו את מוט מכונת הסמית' לגובה מעט מתחת לכתפיים.","עמדו מול המוט כשהרגליים ברוחב הירכיים והבהונות מופנות קדימה.","הניחו את כריות כפות הרגליים על קצה מדרגה או פלטפורמה, כשהעקבים תלויים באוויר.","אחזו במוט לתמיכה, תוך שמירה על גב ישר ושרירי ליבה מופעלים.","הרימו את העקבים כמה שיותר גבוה, תוך העברת משקל הגוף לכריות כפות הרגליים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקבים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the smith machine bar to a height just below your shoulders.","Stand facing the bar with your feet hip-width apart and toes pointing forward.","Place the balls of your feet on the edge of a step or platform, with your heels hanging off.","Hold onto the bar for support, keeping your back straight and core engaged.","Raise your heels as high as possible, lifting your body weight onto the balls of your feet.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ywaNfuh"},{"id":"edb-1394","name":"smith reverse calf raises","name_en":"smith reverse calf raises","muscle":"legs","equipment":"smith machine","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings"],"steps":["כוונו את מוט מכונת הסמית' לגובה מעט מתחת לכתפיים.","עמדו מול המוט כשהרגליים ברוחב הירכיים והבהונות מופנות קדימה.","הניחו את כריות כפות הרגליים על קצה מדרגה או פלטפורמה, כשהעקבים תלויים באוויר.","אחזו במוט לתמיכה.","הרימו את העקבים כמה שיותר גבוה, תוך הרמת הגוף על קצות הבהונות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקבים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the smith machine bar to a height just below your shoulders.","Stand facing the bar with your feet hip-width apart and toes pointing forward.","Place the balls of your feet on the edge of a step or platform, with your heels hanging off.","Hold onto the bar for support.","Raise your heels as high as possible, lifting your body up onto your toes.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Lsqrgh4"},{"id":"edb-1361","name":"חתירה בהטיה אחיזה הפוכה","name_en":"smith reverse grip bent over row","muscle":"back","equipment":"smith machine","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["כוונו את מכונת הסמית' כך שהמוט יהיה בגובה הירכיים.","עמדו מול המוט כשהרגליים ברוחב הכתפיים.","כופפו מעט את הברכיים והטו את הגוף קדימה במפרקי הירך, תוך שמירה על גב ישר.","אחזו במוט באחיזה תחתונה, כשהידיים ברוחב הכתפיים.","משכו את המוט לכיוון החלק התחתון של החזה, תוך כיווץ שכמות הכתפיים זו לזו.","עצרו לרגע בשיא, ולאחר מכן הורידו לאט את המוט חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up the smith machine with the bar at hip height.","Stand facing the bar with your feet shoulder-width apart.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Grasp the bar with an underhand grip, hands shoulder-width apart.","Pull the bar towards your lower chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the bar back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"aaxA3cm"},{"id":"edb-0764","name":"לחיצה אחיזה הפוכה","name_en":"smith reverse-grip press","muscle":"chest","equipment":"smith machine","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["כוונו את גובה מוט מכונת הסמית' לגובה החזה.","עמדו מול המוט כשהרגליים ברוחב הכתפיים.","אחזו במוט באחיזה עליונה, כשהידיים ברוחב מעט גדול מרוחב הכתפיים.","קחו צעד אחורה והתמקמו עם כיפוף קל בברכיים.","שמרו על החזה מורם ושרירי הליבה מופעלים לאורך כל התרגיל.","הורידו את המוט לכיוון החזה, תוך שמירה על המרפקים מכונסים פנימה.","עצרו לרגע בתחתית, ולאחר מכן דחפו את המוט חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the height of the smith machine bar to chest level.","Stand facing the bar with your feet shoulder-width apart.","Grasp the bar with an overhand grip, hands slightly wider than shoulder-width apart.","Step back and position yourself with a slight bend in your knees.","Keep your chest up and core engaged throughout the exercise.","Lower the bar towards your chest, keeping your elbows tucked in.","Pause for a moment at the bottom, then push the bar back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"zK8Fu1W"},{"id":"edb-1395","name":"הרמת עקבים ברגל אחת בישיבה","name_en":"smith seated one leg calf raise","muscle":"legs","equipment":"smith machine","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings"],"steps":["שבו על המכונה כשהגב צמוד לכרית והרגליים על משענת הרגליים.","הניחו רגל אחת על משענת הרגליים והשאירו את הרגל השנייה מחוץ למשענת.","באמצעות שרירי השוק, הרימו את העקב כמה שיותר גבוה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקב בחזרה למצב ההתחלתי.","חזרו על התנועה למספר החזרות הרצוי, ולאחר מכן החליפו רגליים וחזרו שוב."],"steps_en":["Sit on the machine with your back against the pad and your feet on the footrest.","Place one leg on the footrest and keep the other leg off the footrest.","Using your calf muscles, raise your heel as high as possible.","Pause for a moment at the top, then slowly lower your heel back down to the starting position.","Repeat for the desired number of repetitions, then switch legs and repeat."],"mediaId":"0S75mYG"},{"id":"edb-0765","name":"לחיצת כתפיים בישיבה","name_en":"smith seated shoulder press","muscle":"shoulders","equipment":"smith machine","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["כוונו את גובה המושב כך שהידיות יהיו בגובה הכתפיים.","שבו על המכונה כשהגב צמוד לכרית והרגליים שטוחות על הרצפה.","אחזו בידיות באחיזה עליונה והרימו אותן מהתמיכות, תוך יישור מלא של הזרועות.","הורידו את הידיות לגובה הכתפיים, תוך שמירה על כיפוף קל במרפקים.","דחפו את הידיות כלפי מעלה עד שהזרועות מתוחות לגמרי.","עצרו לרגע למעלה, ולאחר מכן הורידו את הידיות באיטיות בחזרה לגובה הכתפיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height so that the handles are at shoulder level.","Sit on the machine with your back against the pad and your feet flat on the floor.","Grasp the handles with an overhand grip and lift them off the supports, extending your arms fully.","Lower the handles down to shoulder level, keeping your elbows slightly bent.","Press the handles up overhead until your arms are fully extended.","Pause for a moment at the top, then slowly lower the handles back down to shoulder level.","Repeat for the desired number of repetitions."],"mediaId":"xUwnBMT"},{"id":"edb-1426","name":"כפיפת שורש כף היד בישיבה","name_en":"smith seated wrist curl","muscle":"biceps","equipment":"smith machine","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["biceps","brachialis"],"steps":["שבו על ספסל מול מכונת סמית' כשהרגליים שטוחות על הרצפה.","אחזו במוט באחיזה תחתית, כשהידיים ברוחב הכתפיים.","הניחו את האמות על הירכיים, כך שפרקי כף היד תלויים מחוץ להן.","כופפו את פרקי הידיים כלפי מעלה באיטיות, תוך קירוב המוט לאמות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench in front of a Smith machine with your feet flat on the ground.","Grasp the barbell with an underhand grip, hands shoulder-width apart.","Rest your forearms on your thighs, allowing your wrists to hang off.","Slowly curl your wrists upward, bringing the barbell towards your forearms.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"B6dAO1t"},{"id":"edb-0766","name":"לחיצת כתפיים","name_en":"smith shoulder press","muscle":"shoulders","equipment":"smith machine","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["כוונו את גובה המושב והתמקמו על מכונת הסמית' כשהרגליים ברוחב הכתפיים.","אחזו במוט באחיזה עליונה, ברוחב מעט גדול מרוחב הכתפיים.","הרימו את המוט מהמעמד ומקמו אותו בגובה הכתפיים, כשהמרפקים כפופים וכפות הידיים פונות קדימה.","דחפו את המוט כלפי מעלה עד שהזרועות מתוחות לגמרי מעל הראש.","עצרו לרגע בשיא, ולאחר מכן הורידו לאט את המוט חזרה לגובה הכתפיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself on the smith machine with your feet shoulder-width apart.","Grasp the bar with an overhand grip, slightly wider than shoulder-width apart.","Lift the bar off the rack and position it at shoulder level, with your elbows bent and palms facing forward.","Press the bar upward until your arms are fully extended overhead.","Pause for a moment at the top, then slowly lower the bar back down to shoulder level.","Repeat for the desired number of repetitions."],"mediaId":"903mzG8"},{"id":"edb-0767","name":"משיכת כתפיים","name_en":"smith shrug","muscle":"back","equipment":"smith machine","target":"traps","bodyPart":"back","secondaryMuscles":["shoulders"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","אחזו במוט באחיזה עליונה, כשהידיים מעט רחבות יותר מרוחב הכתפיים.","שמרו על הזרועות ישרות והכתפיים רפויות.","הרימו את הכתפיים כלפי האוזניים, תוך כיווץ שרירי הטרפז בשיא התנועה.","החזיקו לרגע, ולאחר מכן הורידו את הכתפיים באיטיות חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your knees slightly bent.","Grasp the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Keep your arms straight and your shoulders relaxed.","Lift your shoulders up towards your ears, squeezing your traps at the top.","Hold for a moment, then slowly lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"OUQ0ZyW"},{"id":"edb-0768","name":"סקוואט מפוצל ברגל אחת","name_en":"smith single leg split squat","muscle":"legs","equipment":"smith machine","target":"quads","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings"],"steps":["עמדו מול מכונת הסמית' כשהרגליים ברוחב הכתפיים.","הניחו רגל אחת מאחוריכם על ספסל או מדרגה, כשהבהונות מופנות קדימה.","אחזו במוט מכונת הסמית' לצורך יציבות.","כופפו את הברך הקדמית והורידו את הגוף למצב לאנג', תוך שמירה על גב ישר.","עצרו לרגע בתחתית, ולאחר מכן דחפו דרך העקב הקדמי כדי לחזור למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו רגליים."],"steps_en":["Stand in front of the smith machine with your feet shoulder-width apart.","Place one foot behind you on a bench or step, with your toes pointing forward.","Hold onto the smith machine bar for stability.","Bend your front knee and lower your body down into a lunge position, keeping your back straight.","Pause for a moment at the bottom, then push through your front heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"mediaId":"wWFspEi"},{"id":"edb-0769","name":"לאנג׳","name_en":"smith sprint lunge","muscle":"glutes","equipment":"smith machine","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["כוונו את מכונת הסמית' כך שהמוט יהיה בגובה הירכיים.","עמדו כשגבכם למכונה ורגליכם ברוחב הכתפיים.","קחו צעד אחורה עם הרגל הימנית והניחו אותה על המוט, כך שגב כף הרגל נשען על המוט.","כופפו את הברך השמאלית והורידו את הגוף למצב לאנג', תוך שמירה על גב ישר.","דחפו דרך העקב השמאלי כדי לחזור למצב ההתחלתי.","חזרו על התנועה בצד השני, עם צעד אחורה ברגל השמאלית.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Set up the smith machine with the barbell at hip height.","Stand facing away from the machine with your feet shoulder-width apart.","Step back with your right foot and place it on the barbell, resting the top of your foot on the bar.","Bend your left knee and lower your body into a lunge position, keeping your back straight.","Push through your left heel to return to the starting position.","Repeat on the other side, stepping back with your left foot.","Continue alternating sides for the desired number of repetitions."],"mediaId":"HsjbB1z"},{"id":"edb-0770","name":"סקוואט","name_en":"smith squat","muscle":"glutes","equipment":"smith machine","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["כוונו את מכונת הסמית' כך שהמוט יהיה בגובה מתאים לסקוואט שלכם.","עמדו עם הרגליים ברוחב הכתפיים והבהונות פונות מעט החוצה.","התמקמו מתחת למוט, כך שהוא נשען על שרירי הטרפז העליונים והכתפיים.","אחזו במוט באחיזה רחבה, מעט רחבה יותר מרוחב הכתפיים.","הפעילו את שרירי הליבה ושחררו את המוט מהמעמד, תוך צעד אחורה כדי להתרחק מהמעמד.","תוך שמירה על החזה מורם והגב ישר, התחילו את הכפיפה על ידי כיפוף בירכיים ובברכיים.","הורידו את הגוף עד שהירכיים מקבילות לרצפה או מעט מתחת לכך.","עצרו לרגע בתחתית, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up the smith machine with the barbell at an appropriate height for your squat.","Stand with your feet shoulder-width apart, toes slightly turned out.","Position yourself under the barbell, resting it on your upper traps and shoulders.","Grip the barbell with a wide grip, slightly wider than shoulder-width apart.","Engage your core and unrack the barbell, stepping back to clear the rack.","Keeping your chest up and back straight, initiate the squat by bending at the hips and knees.","Lower your body until your thighs are parallel to the ground or slightly below.","Pause for a moment at the bottom, then drive through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"jFtipLl"},{"id":"edb-0771","name":"כפיפת שורש כף היד בעמידה","name_en":"smith standing back wrist curl","muscle":"biceps","equipment":"smith machine","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["biceps","triceps"],"steps":["עמדו מול מכונת הסמית' כשהרגליים ברוחב הכתפיים.","אחזו במוט באחיזה עליונה, כשהידיים ברוחב הכתפיים.","שמרו על גב ישר והמרפקים קרובים לגוף.","כופפו לאט את פרקי כפות הידיים כלפי מעלה, תוך קירוב המוט לגוף.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand facing the smith machine with your feet shoulder-width apart.","Grasp the barbell with an overhand grip, hands shoulder-width apart.","Keep your back straight and your elbows close to your body.","Slowly curl your wrists upwards, bringing the barbell towards your body.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"hfmQ0Tz"},{"id":"edb-0772","name":"לחיצה צבאית מאחורי העורף בעמידה","name_en":"smith standing behind head military press","muscle":"shoulders","equipment":"smith machine","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["כוונו את גובה המושב של מכונת הסמית' כך שהמוט יהיה בגובה הכתפיים.","עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","אחזו במוט באחיזה עליונה, ברוחב מעט גדול מרוחב הכתפיים.","הרימו את המוט מהמעמד וקחו צעד אחורה, תוך שמירה על עמידה יציבה.","הניחו את המוט מאחורי הראש, כך שהוא נשען על שרירי הטרפז העליונים.","שמרו על שרירי הליבה מופעלים והחזה מורם לאורך כל התרגיל.","דחפו את המוט מעל הראש על ידי יישור הזרועות, עד ליישור מלא.","עצרו לרגע קצר בשיא התנועה, ולאחר מכן הורידו לאט את המוט חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height of the smith machine so that the bar is at shoulder level.","Stand with your feet shoulder-width apart and your knees slightly bent.","Grasp the bar with an overhand grip, slightly wider than shoulder-width apart.","Lift the bar off the rack and step back, maintaining a stable stance.","Position the bar behind your head, resting on your upper traps.","Keep your core engaged and your chest lifted throughout the exercise.","Press the bar overhead by extending your arms, fully straightening them.","Pause briefly at the top of the movement, then slowly lower the bar back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ht8xDrP"},{"id":"edb-0773","name":"הרמת עקבים בעמידה","name_en":"smith standing leg calf raise","muscle":"legs","equipment":"smith machine","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings","glutes"],"steps":["כוונו את מוט מכונת הסמית' לגובה שמאפשר לכם לעמוד עם הרגליים שטוחות על הרצפה והכתפיים מתחת למוט.","התמקמו מתחת למוט כשהרגליים ברוחב הכתפיים והבהונות מופנות קדימה.","הניחו את הידיים על המוט לצורך יציבות.","הפעילו את שרירי השוק והרימו לאט את העקבים מהרצפה, תוך הרמת הגוף על קצות הבהונות.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקבים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the smith machine bar to a height that allows you to stand with your feet flat on the ground and your shoulders under the bar.","Position yourself under the bar with your feet shoulder-width apart and your toes pointing forward.","Place your hands on the bar for stability.","Engage your calves and slowly raise your heels off the ground, lifting your body up onto your toes.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"6MaEjVA"},{"id":"edb-0774","name":"לחיצה צבאית בעמידה","name_en":"smith standing military press","muscle":"shoulders","equipment":"smith machine","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","אחזו במוט באחיזה עליונה, מעט רחבה יותר מרוחב הכתפיים.","הרימו את המוט מהמעמד והורידו אותו לגובה הכתפיים, כשכפות הידיים פונות קדימה.","דחפו את המוט כלפי מעלה עד שהזרועות מתוחות לגמרי מעל הראש.","עצרו לרגע בשיא, ולאחר מכן הורידו לאט את המוט חזרה לגובה הכתפיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your knees slightly bent.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lift the barbell off the rack and bring it down to shoulder level, with your palms facing forward.","Press the barbell upward until your arms are fully extended overhead.","Pause for a moment at the top, then slowly lower the barbell back down to shoulder level.","Repeat for the desired number of repetitions."],"mediaId":"jjUPrze"},{"id":"edb-3142","name":"סקוואט","name_en":"smith sumo squat","muscle":"glutes","equipment":"smith machine","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["כוונו את מכונת הסמית' כך שהמוט יהיה בגובה הירכיים.","עמדו עם הרגליים רחבות יותר מרוחב הכתפיים, אצבעות הרגליים פונות החוצה.","התמקמו מתחת למוט, כך שהוא נשען על פלג הגוף העליון והכתפיים.","הפעילו את שרירי הליבה ושמרו על החזה זקוף תוך הורדת הגוף לתנוחת סקוואט, דחיפת האגן אחורה וכפיפת הברכיים.","רדו עד שהירכיים מקבילות לרצפה, או עד למקסימום שנוח לכם.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up the smith machine with the barbell at hip height.","Stand with your feet wider than shoulder-width apart, toes pointing outwards.","Position yourself under the barbell, resting it on your upper back and shoulders.","Engage your core and keep your chest up as you lower your body down into a squat position, pushing your hips back and bending your knees.","Lower yourself until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"dzz6BiV"},{"id":"edb-1396","name":"הרמה","name_en":"smith toe raise","muscle":"legs","equipment":"smith machine","target":"calves","bodyPart":"lower legs","secondaryMuscles":["ankles","shins"],"steps":["כוונו את מוט מכונת הסמית' לגובה שמאפשר לכם לעמוד בנוחות עם הרגליים שטוחות על הרצפה.","התמקמו מתחת למוט כך שהכתפיים ישירות מתחתיו והרגליים ברוחב הכתפיים.","הניחו את כריות כפות הרגליים על פלטפורמה מוגבהת או דיסקיות משקולת, כשהעקבים תלויים מחוץ לקצה.","אחזו במוט באחיזה עליונה, ברוחב מעט גדול מרוחב הכתפיים.","הפעילו את שרירי הליבה ושמרו על גב ישר לאורך כל התרגיל.","הרימו לאט את העקבים כמה שיותר גבוה, תוך העברת משקל הגוף לכריות כפות הרגליים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקבים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the smith machine bar to a height that allows you to comfortably stand with your feet flat on the ground.","Position yourself under the bar with your shoulders directly below it and your feet shoulder-width apart.","Place the balls of your feet on a raised platform or weight plates, with your heels hanging off the edge.","Grasp the bar with an overhand grip, slightly wider than shoulder-width apart.","Engage your core and keep your back straight throughout the exercise.","Slowly raise your heels as high as possible, lifting your body weight onto the balls of your feet.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Y4QlY8z"},{"id":"edb-0775","name":"חתירה זקופה","name_en":"smith upright row","muscle":"shoulders","equipment":"smith machine","target":"delts","bodyPart":"shoulders","secondaryMuscles":["traps","biceps"],"steps":["עמדו כשהרגליים ברוחב הכתפיים, מול מכונת הסמית'.","אחזו במוט באחיזה עליונה, כשהידיים מעט רחבות יותר מרוחב הכתפיים.","שמרו על גב ישר ושרירי ליבה מופעלים.","משכו את המוט כלפי מעלה לכיוון הסנטר, תוך הובלת התנועה עם המרפקים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, facing the smith machine.","Grasp the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Keep your back straight and your core engaged.","Pull the barbell up towards your chin, leading with your elbows.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"1DN3iz4"},{"id":"edb-1308","name":"לחיצת חזה אחיזה רחבה","name_en":"smith wide grip bench press","muscle":"chest","equipment":"smith machine","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["כוונו את הספסל למצב נוח על מכונת הסמית'.","שכבו על הספסל עם כפות הרגליים שטוחות על הרצפה.","אחזו במוט באחיזה רחבה, מעט רחבה יותר מרוחב הכתפיים.","שחררו את המוט מהמעמד והורידו אותו לאט לכיוון החזה, תוך שמירה על המרפקים פתוחים לצדדים.","עצרו לרגע כשהמוט נוגע בחזה.","דחפו את המוט בחזרה למצב ההתחלתי, תוך יישור מלא של הידיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the bench to a comfortable position on the smith machine.","Lie down on the bench with your feet flat on the ground.","Grasp the barbell with a wide grip, slightly wider than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows out to the sides.","Pause for a moment when the barbell touches your chest.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"zoOvPcx"},{"id":"edb-1309","name":"לחיצת חזה בשיפוע שלילי אחיזה רחבה","name_en":"smith wide grip decline bench press","muscle":"chest","equipment":"smith machine","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["כוונו את הספסל המשופע כלפי מטה לזווית הרצויה.","שכבו על הספסל כשהרגליים מקובעות מתחת לכריות הרגליים.","אחזו במוט באחיזה רחבה, מעט רחבה יותר מרוחב הכתפיים.","שחררו את המוט מהמעמד והורידו אותו לאט לכיוון החזה, תוך שמירה על המרפקים מופנים החוצה.","עצרו לרגע כשהמוט נוגע בחזה.","דחפו את המוט בחזרה למצב ההתחלתי, תוך יישור מלא של הידיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the decline bench to the desired angle.","Lie down on the bench with your feet secured under the foot pads.","Grasp the barbell with a wide grip, slightly wider than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows pointed outwards.","Pause for a moment when the barbell touches your chest.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"wi2H9QX"},{"id":"edb-0776","name":"סנאץ׳","name_en":"snatch pull","muscle":"legs","equipment":"barbell","target":"quads","bodyPart":"upper legs","secondaryMuscles":["hamstrings","glutes","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והמוט על הרצפה לפניכם.","כופפו את הברכיים והטו את הירכיים לרדת למצב סקוואט, תוך אחיזת המוט באחיזה עליונה.","שמרו על גב ישר וחזה מורם תוך דחיפה דרך העקבים כדי להרים את המוט מהרצפה, תוך יישור הירכיים והברכיים.","כאשר המוט מגיע לגובה הירכיים, משכו אותו כלפי מעלה בפיצוץ כוח, תוך הרמת הכתפיים ומשיכת המרפקים גבוה לצדדים.","כאשר המוט מגיע לנקודה הגבוהה ביותר, צללו במהירות מתחתיו לתוך מצב סקוואט עמוק.","תפסו את המוט מעל הראש כשהזרועות מתוחות לגמרי והברכיים כפופות.","עמדו זקוף על ידי יישור הירכיים והברכיים, תוך שמירה על המוט מעל הראש.","הורידו את המוט חזרה למצב ההתחלתי על ידי היפוך התנועה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and the barbell on the ground in front of you.","Bend your knees and hinge at the hips to lower into a squat position, gripping the barbell with an overhand grip.","Keep your back straight and chest up as you drive through your heels to lift the barbell off the ground, extending your hips and knees.","As the barbell reaches hip level, explosively pull it upwards, shrugging your shoulders and pulling your elbows high and to the sides.","As the barbell reaches its highest point, quickly drop underneath it, pulling yourself into a deep squat position.","Catch the barbell overhead with your arms fully extended and your knees bent.","Stand up by extending your hips and knees, keeping the barbell overhead.","Lower the barbell back down to the starting position by reversing the movement.","Repeat for the desired number of repetitions."],"mediaId":"dG5Smob"},{"id":"edb-0777","name":"spell caster","name_en":"spell caster","muscle":"core","equipment":"dumbbell","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","lower back"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו משקולת ביד אחת.","כופפו מעט את הברכיים והטו את הגוף קדימה מהמותניים, תוך שמירה על גב ישר.","יישרו את הזרוע עם המשקולת לכיוון כף הרגל הנגדית, תוך סיבוב פלג הגוף.","חזרו לעמדת ההתחלה וחזרו על התרגיל בצד השני.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a dumbbell in one hand.","Bend your knees slightly and hinge forward at the waist, keeping your back straight.","Extend your arm with the dumbbell towards the opposite foot, rotating your torso as you do so.","Return to the starting position and repeat on the other side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"p9cCe2r"},{"id":"edb-1362","name":"sphinx","name_en":"sphinx","muscle":"back","equipment":"body weight","target":"spine","bodyPart":"back","secondaryMuscles":["glutes","hamstrings"],"steps":["שכבו על הבטן על הרצפה כשהאמות שטוחות על הרצפה, המרפקים ישירות מתחת לכתפיים.","הפעילו את שרירי הליבה והרימו את החזה מהרצפה, תוך שמירה על האמות והבהונות על הרצפה.","החזיקו את התנוחה למספר שניות, תוך הקפדה על שמירת הצוואר במצב נייטרלי.","הורידו לאט את החזה חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie face down on the ground with your forearms flat on the floor, elbows directly under your shoulders.","Engage your core and lift your chest off the ground, keeping your forearms and toes on the floor.","Hold this position for a few seconds, making sure to keep your neck in a neutral position.","Slowly lower your chest back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"DIVyqrU"},{"id":"edb-0778","name":"שכיבת סמיכה","name_en":"spider crawl push up","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["core","chest","shoulders"],"steps":["התחילו בתנוחת שכיבת סמיכה עם הידיים ברוחב מעט גדול מרוחב הכתפיים והרגליים צמודות.","קרבו את הברך הימנית למרפק הימני, תוך שמירה עליה מחוץ לרצפה.","תוך כדי החזרת הברך הימנית אחורה, הורידו במקביל את הגוף לכיוון הרצפה על ידי כיפוף המרפקים.","דחפו חזרה למעלה למצב ההתחלתי וחזרו על התנועה עם הברך השמאלית למרפק השמאלי.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Start in a push-up position with your hands slightly wider than shoulder-width apart and your feet together.","Bring your right knee towards your right elbow, keeping it off the ground.","As you bring your right knee back, simultaneously lower your body towards the ground by bending your elbows.","Push back up to the starting position and repeat with your left knee towards your left elbow.","Continue alternating sides for the desired number of repetitions."],"mediaId":"P9GFBME"},{"id":"edb-1363","name":"מתיחה","name_en":"spine stretch","muscle":"back","equipment":"body weight","target":"spine","bodyPart":"back","secondaryMuscles":["hamstrings","glutes"],"steps":["שבו על הרצפה עם הרגליים מושטות לפניכם.","הניחו את הידיים על הרצפה מאחוריכם, כשהאצבעות מופנות לכיוון הגוף.","הפעילו את שרירי הליבה ונטו לאט אחורה, תוך שמירה על גב ישר.","המשיכו לנטות אחורה עד שאתם מרגישים מתיחה בעמוד השדרה.","החזיקו את המתיחה למספר שניות, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the ground with your legs extended in front of you.","Place your hands on the ground behind you, fingers pointing towards your body.","Engage your core and slowly lean back, keeping your back straight.","Continue leaning back until you feel a stretch in your spine.","Hold the stretch for a few seconds, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"JbC2iaV"},{"id":"edb-2329","name":"פיתול","name_en":"spine twist","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","lower back"],"steps":["שבו על הרצפה עם הרגליים מושטות לפניכם.","כופפו את הברכיים והניחו את כפות הרגליים שטוחות על הרצפה, ברוחב האגן.","הניחו את הידיים מאחורי הראש כשהמרפקים פונים החוצה.","הפעילו את שרירי הבטן וסובבו לאט את פלג הגוף ימינה, תוך קירוב המרפק הימני לברך השמאלית.","עצרו לרגע בסוף הסיבוב, ולאחר מכן חזרו לאט למצב ההתחלתי.","חזרו על הסיבוב לצד שמאל, תוך קירוב המרפק השמאלי לברך הימנית.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Sit on the ground with your legs extended in front of you.","Bend your knees and place your feet flat on the ground, hip-width apart.","Place your hands behind your head with your elbows pointing outwards.","Engage your abs and slowly twist your torso to the right, bringing your right elbow towards your left knee.","Pause for a moment at the end of the twist, then slowly return to the starting position.","Repeat the twist to the left side, bringing your left elbow towards your right knee.","Continue alternating sides for the desired number of repetitions."],"mediaId":"2jl9K55"},{"id":"edb-2368","name":"split squats","name_en":"split squats","muscle":"legs","equipment":"body weight","target":"quads","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים.","קחו צעד קדימה עם רגל אחת והניחו אותה כשני צעדים לפני הרגל השנייה.","הורידו את הגוף על ידי כיפוף הברכיים והירכיים, תוך שמירה על גב ישר.","המשיכו לרדת עד שהירך הקדמית מקבילה לרצפה, והברך האחורית מרחפת ממש מעל הרצפה.","עצרו לרגע, ולאחר מכן דחפו דרך העקב הקדמי כדי לחזור למצב ההתחלתי.","חזרו על התנועה למספר החזרות הרצוי, ולאחר מכן החליפו רגליים וחזרו שוב."],"steps_en":["Stand with your feet shoulder-width apart.","Take a step forward with one foot and place it about two feet in front of the other foot.","Lower your body by bending your knees and hips, keeping your back straight.","Continue lowering until your front thigh is parallel to the ground, and your back knee is hovering just above the ground.","Pause for a moment, then push through your front heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs and repeat."],"mediaId":"9E25EOx"},{"id":"edb-0786","name":"סקוואט","name_en":"squat jerk","muscle":"legs","equipment":"barbell","target":"quads","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings","calves","core"],"steps":["התחילו כשהמוט מונח על הכתפיים, והרגליים ברוחב הכתפיים.","הורידו את הגוף למצב סקוואט, תוך שמירה על החזה מורם והברכיים בקו עם הבהונות.","כשאתם מגיעים לתחתית הסקוואט, דחפו בפיצוץ כוח דרך הרגליים ודחפו את המוט מעל הראש.","כאשר המוט מגיע לשיא, צללו במהירות למצב פיצול, כשרגל אחת קדימה ואחת אחורה.","תפסו את המוט מעל הראש כשהזרועות מתוחות לגמרי והברך האחורית נוגעת קלות ברצפה.","עמדו ממצב הפיצול, תוך החזרת הרגליים יחד.","הורידו את המוט חזרה לכתפיים וחזרו על התנועה למספר החזרות הרצוי."],"steps_en":["Start with the barbell resting on your shoulders, with your feet shoulder-width apart.","Lower your body into a squat position, keeping your chest up and your knees tracking over your toes.","As you reach the bottom of the squat, explosively drive through your legs and push the barbell overhead.","As the barbell reaches its peak, quickly drop into a split position, with one foot forward and one foot back.","Catch the barbell overhead with your arms fully extended and your back knee slightly touching the ground.","Stand up from the split position, bringing your feet back together.","Lower the barbell back to your shoulders and repeat for the desired number of repetitions."],"mediaId":"IMRsOCn"},{"id":"edb-1705","name":"סקוואט על בוסו","name_en":"squat on bosu ball","muscle":"legs","equipment":"bosu ball","target":"quads","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings","calves"],"steps":["הניחו את כדור הבוסו על הרצפה כשהצד השטוח כלפי מעלה.","עמדו כשהרגליים ברוחב הכתפיים והתמקמו על גבי כדור הבוסו.","הורידו את הגוף על ידי כיפוף הברכיים והירכיים, כאילו אתם יושבים אחורה על כיסא.","שמרו על החזה מורם והמשקל על העקבים.","רדו עד שהירכיים מקבילות לרצפה.","עצרו לרגע, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Place the bosu ball on the ground with the flat side up.","Stand with your feet shoulder-width apart and position yourself on top of the bosu ball.","Lower your body down by bending your knees and hips, as if sitting back into a chair.","Keep your chest up and your weight on your heels.","Lower yourself until your thighs are parallel to the ground.","Pause for a moment, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"T2fA5Ir"},{"id":"edb-1685","name":"סקוואט מעל הראש","name_en":"squat to overhead reach","muscle":"legs","equipment":"body weight","target":"quads","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והבהונות פונות מעט החוצה.","הורידו את הגוף לתנוחת סקוואט על ידי כיפוף הברכיים ודחיפת האגן אחורה.","תוך כדי עלייה מהסקוואט, יישרו את הזרועות מעל הראש, כשהן שואפות כלפי התקרה.","חזרו למצב ההתחלתי על ידי הורדת הזרועות וכיפוף הברכיים לסקוואט נוסף.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and toes slightly turned out.","Lower your body down into a squat position by bending your knees and pushing your hips back.","As you come up from the squat, extend your arms overhead, reaching towards the ceiling.","Return to the starting position by lowering your arms and bending your knees to squat down again.","Repeat for the desired number of repetitions."],"mediaId":"QChZi3x"},{"id":"edb-1686","name":"פיתול מעל הראש","name_en":"squat to overhead reach with twist","muscle":"legs","equipment":"body weight","target":"quads","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והבהונות פונות מעט החוצה.","הורידו את הגוף לתנוחת סקוואט על ידי כפיפת הברכיים ודחיפת האגן אחורה.","תוך כדי עלייה מהסקוואט, הרימו את הזרועות מעל הראש וסובבו את פלג הגוף לצד אחד.","חזרו למצב ההתחלתי וחזרו על הסקוואט, הפעם תוך סיבוב פלג הגוף לצד הנגדי.","המשיכו להחליף צדדים בכל חזרת סקוואט."],"steps_en":["Stand with your feet shoulder-width apart and toes slightly turned out.","Lower your body into a squat position by bending your knees and pushing your hips back.","As you come up from the squat, raise your arms overhead and twist your torso to one side.","Return to the starting position and repeat the squat, this time twisting your torso to the opposite side.","Continue alternating sides with each squat repetition."],"mediaId":"5BZHW9s"},{"id":"edb-2297","name":"כפיפת בטן מאחורי העורף עם כדור פיזיו","name_en":"stability ball crunch (full range hands behind head)","muscle":"core","equipment":"stability ball","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שבו על כדור הפיזיו כשכפות הרגליים שטוחות על הרצפה והברכיים כפופות בזווית של 90 מעלות.","הניחו את הידיים מאחורי הראש כשהמרפקים פונים החוצה.","תוך הפעלת שרירי הבטן, כופפו לאט את פלג הגוף העליון קדימה, תוך קירוב החזה לברכיים.","עצרו לרגע בשיא, ולאחר מכן הורידו לאט את פלג הגוף העליון חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly curl your upper body forward, bringing your chest towards your knees.","Pause for a moment at the top, then slowly lower your upper body back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Gn5FwYT"},{"id":"edb-3291","name":"לחיצה","name_en":"stalder press","muscle":"triceps","equipment":"body weight","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders","core"],"steps":["התחילו בעמידה כשהרגליים ברוחב הכתפיים והזרועות מתוחות מעל הראש.","כופפו מעט את הברכיים והפעילו את שרירי הליבה.","הורידו את הגוף למצב סקוואט תוך שמירה על הזרועות מתוחות מעל הראש.","תוך כדי הסקוואט, דחפו את הזרועות כלפי מטה לכיוון הרצפה, תוך הפעלת שריר הזרוע האחורית.","עצרו לרגע בתחתית הסקוואט, ולאחר מכן דחפו דרך העקבים כדי לעמוד חזרה תוך הרמת הזרועות בו-זמנית חזרה מעל הראש.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by standing with your feet shoulder-width apart and your arms extended overhead.","Bend your knees slightly and engage your core.","Lower your body down into a squat position while keeping your arms extended overhead.","As you squat down, press your arms down towards the ground, engaging your triceps.","Pause for a moment at the bottom of the squat, then push through your heels to stand back up while simultaneously raising your arms back overhead.","Repeat for the desired number of repetitions."],"mediaId":"zd4P4B2"},{"id":"edb-3669","name":"standing archer","name_en":"standing archer","muscle":"back","equipment":"body weight","target":"upper back","bodyPart":"back","secondaryMuscles":["shoulders","biceps","forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","יישרו את הזרועות ישר לפניכם בגובה הכתפיים, במקביל לרצפה.","סובבו את פלג הגוף ימינה, תוך שמירה על הזרועות מתוחות והגב ישר.","תוך כדי הסיבוב, יישרו את הזרוע הימנית קדימה ואת השמאלית אחורה, בחיקוי תנועת מתיחת קשת.","החזיקו בתנוחה לרגע, ולאחר מכן חזרו למצב ההתחלתי.","חזרו על התנועה, הפעם תוך סיבוב פלג הגוף שמאלה ויישור הזרוע השמאלית קדימה והימנית אחורה.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your knees slightly bent.","Extend your arms straight out in front of you at shoulder height, parallel to the ground.","Rotate your torso to the right, keeping your arms extended and your back straight.","As you rotate, extend your right arm forward and your left arm back, mimicking the motion of drawing a bowstring.","Hold the position for a moment, then return to the starting position.","Repeat the motion, this time rotating your torso to the left and extending your left arm forward and your right arm back.","Continue alternating sides for the desired number of repetitions."],"mediaId":"JF8AkMX"},{"id":"edb-0788","name":"לחיצה מאחורי העורף בעמידה","name_en":"standing behind neck press","muscle":"shoulders","equipment":"barbell","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["עמדו כשהרגליים ברוחב הכתפיים ואחזו במוט מאחורי הצוואר באחיזה עליונה.","שמרו על גב ישר ושרירי ליבה פעילים.","דחפו את המוט מעל הראש על ידי יישור הזרועות, עד ליישור מלא של המרפקים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את המוט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold the barbell behind your neck with an overhand grip.","Keep your back straight and core engaged.","Press the barbell overhead by extending your arms, fully extending your elbows.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"xDh0lJr"},{"id":"edb-1490","name":"הרמת עקבים בעמידה","name_en":"standing calf raise (on a staircase)","muscle":"legs","equipment":"body weight","target":"calves","bodyPart":"lower legs","secondaryMuscles":["ankles","feet"],"steps":["עמדו על קצה מדרגה או פלטפורמה יציבה, כשהעקבים תלויים באוויר והבהונות על המדרגה.","אחזו במעקה או בקיר לשמירה על שיווי משקל במידת הצורך.","הרימו לאט את העקבים כמה שיותר גבוה, תוך העברת משקל הגוף לכריות כפות הרגליים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקבים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand on the edge of a step or a sturdy platform with your heels hanging off and your toes on the step.","Hold onto a railing or wall for balance if needed.","Slowly raise your heels as high as possible, lifting your body weight onto the balls of your feet.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"6HmFgmx"},{"id":"edb-1397","name":"standing calves","name_en":"standing calves","muscle":"legs","equipment":"body weight","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings","glutes"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים, אצבעות הרגליים פונות קדימה.","הרימו את העקבים מהרצפה כמה שיותר גבוה, תוך עמידה על קצות הבהונות.","החזיקו בתנוחה לרגע, ולאחר מכן הורידו לאט את העקבים חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, toes pointing forward.","Raise your heels off the ground as high as possible, standing on your toes.","Hold the position for a moment, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"XIHEoCG"},{"id":"edb-1398","name":"מתיחה בעמידה","name_en":"standing calves calf stretch","muscle":"legs","equipment":"body weight","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings","glutes"],"steps":["עמדו מול קיר או חפץ יציב, במרחק אורך זרוע בערך.","הניחו את הידיים על הקיר או החפץ בגובה הכתפיים.","קחו צעד אחורה עם רגל אחת, תוך שמירה על העקב שטוח על הרצפה.","כופפו מעט את הברך הקדמית והטו את הגוף קדימה, תוך שמירה על הרגל האחורית ישרה.","אתם אמורים להרגיש מתיחה בשריר השוק.","החזיקו את המתיחה במשך 20-30 שניות.","חזרו על הרגל השנייה."],"steps_en":["Stand facing a wall or sturdy object, about an arm's length away.","Place your hands on the wall or object at shoulder height.","Step back with one foot, keeping your heel flat on the ground.","Bend your front knee slightly and lean forward, keeping your back leg straight.","You should feel a stretch in your calf muscle.","Hold the stretch for 20-30 seconds.","Repeat on the other leg."],"mediaId":"qOKcgVP"},{"id":"edb-1599","name":"מתיחה בעמידה","name_en":"standing hamstring and calf stretch with strap","muscle":"legs","equipment":"rope","target":"hamstrings","bodyPart":"upper legs","secondaryMuscles":["calves"],"steps":["עמדו זקוף עם הרגליים ברוחב הכתפיים.","אחזו ברצועה בשתי הידיים והניחו אותה סביב כרית כף הרגל.","שמרו על הרגל ישרה והטו לאט את הגוף קדימה מהירכיים, תוך שמירה על גב ישר.","הרגישו את המתיחה בירך האחורית ובשריר השוק.","החזיקו את המתיחה במשך 20-30 שניות.","שחררו את המתיחה וחזרו על התרגיל עם הרגל השנייה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand upright with your feet shoulder-width apart.","Hold the strap with both hands and place it around the ball of your foot.","Keep your leg straight and slowly lean forward from your hips, keeping your back straight.","Feel the stretch in your hamstring and calf muscles.","Hold the stretch for 20-30 seconds.","Release the stretch and repeat with the other leg.","Repeat for the desired number of repetitions."],"mediaId":"xTjr103"},{"id":"edb-0794","name":"מתיחה בעמידה לצדדים","name_en":"standing lateral stretch","muscle":"back","equipment":"body weight","target":"lats","bodyPart":"back","secondaryMuscles":["shoulders","obliques"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","הושיטו את הידיים ישר הצידה, במקביל לרצפה.","הטו לאט את פלג הגוף העליון לצד אחד, תוך הרגשת מתיחה בצד הגוף ובשרירי הגב הרחב.","החזיקו את המתיחה למשך 15-30 שניות.","חזרו לעמדת ההתחלה וחזרו על התרגיל בצד השני.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your knees slightly bent.","Extend your arms straight out to the sides, parallel to the ground.","Slowly lean your upper body to one side, feeling a stretch in your side and lats.","Hold the stretch for 15-30 seconds.","Return to the starting position and repeat on the other side.","Repeat for the desired number of repetitions."],"mediaId":"1jXLYEw"},{"id":"edb-1364","name":"standing pelvic tilt","name_en":"standing pelvic tilt","muscle":"back","equipment":"body weight","target":"spine","bodyPart":"back","secondaryMuscles":["abdominals"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","הניחו את הידיים על הירכיים או אפשרו להן לתלות לצדדים.","הפעילו את שרירי הליבה והטו את האגן קדימה, תוך דחיפת הגב התחתון לכיוון הקיר מאחוריכם.","החזיקו בתנוחה למספר שניות, ולאחר מכן שחררו וחזרו למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your knees slightly bent.","Place your hands on your hips or let them hang by your sides.","Engage your core muscles and tilt your pelvis forward, pushing your lower back towards the wall behind you.","Hold the position for a few seconds, then release and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"cuKYxhu"},{"id":"edb-0795","name":"כפיפת ברך בעמידה","name_en":"standing single leg curl","muscle":"legs","equipment":"body weight","target":"hamstrings","bodyPart":"upper legs","secondaryMuscles":["glutes"],"steps":["עמדו כשהרגליים ברוחב הירכיים והידיים על הירכיים.","העבירו את המשקל לרגל השמאלית והרימו את כף הרגל הימנית מהרצפה, תוך כיפוף הברך.","כופפו לאט את העקב הימני לכיוון הישבן, תוך כיווץ הירך האחורית.","עצרו לרגע בשיא, ולאחר מכן הורידו לאט את כף הרגל הימנית חזרה למצב ההתחלתי.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו רגליים."],"steps_en":["Stand with your feet hip-width apart and your hands on your hips.","Shift your weight onto your left leg and lift your right foot off the ground, bending your knee.","Slowly curl your right heel towards your glutes, squeezing your hamstring.","Pause for a moment at the top, then slowly lower your right foot back down to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"mediaId":"C5jncD2"},{"id":"edb-0796","name":"standing wheel rollerout","name_en":"standing wheel rollerout","muscle":"core","equipment":"wheel roller","target":"abs","bodyPart":"waist","secondaryMuscles":["lower back","shoulders"],"steps":["התחילו בעמידה זקופה כשהרגליים ברוחב הכתפיים וגלגלת הבטן לפניכם.","כופפו מהמותניים וגלגלו לאט את הגלגלת קדימה, תוך שמירה על גב ישר ושרירי ליבה מופעלים.","המשיכו לגלגל קדימה עד שאתם מרגישים מתיחה בבטן והגוף מתוח ככל האפשר.","עצרו לרגע, ולאחר מכן גלגלו לאט את הגלגלת חזרה לכיוון הגוף, לחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by standing tall with your feet shoulder-width apart and the wheel roller in front of you.","Bend at your waist and slowly roll the wheel forward, keeping your back straight and your core engaged.","Continue rolling forward until you feel a stretch in your abs and your body is extended as far as possible.","Pause for a moment, then slowly roll the wheel back towards your body, returning to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"KtRomty"},{"id":"edb-3223","name":"star jump (male)","name_en":"star jump (male)","muscle":"core","equipment":"body weight","target":"cardiovascular system","bodyPart":"cardio","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים במרחק רוחב הכתפיים והזרועות לצידי הגוף.","כופפו מעט את הברכיים וקפצו כלפי מעלה בפיצוץ כוח.","תוך כדי הקפיצה, פשקו את הרגליים ויישרו את הזרועות לצדדים, ליצירת צורת כוכב עם הגוף.","נחתו ברכות על כריות כפות הרגליים כשהברכיים כפופות מעט.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your arms by your sides.","Bend your knees slightly and jump up explosively.","As you jump, spread your legs and extend your arms out to the sides, forming a star shape with your body.","Land softly on the balls of your feet with your knees slightly bent.","Repeat for the desired number of repetitions."],"mediaId":"HtfCpfi"},{"id":"edb-2138","name":"stationary bike run v. 3","name_en":"stationary bike run v. 3","muscle":"core","equipment":"stationary bike","target":"cardiovascular system","bodyPart":"cardio","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["כוונו את גובה המושב ואת המיקום כדי להבטיח יישור נכון.","הניחו את הרגליים על הדוושות והדקו אותן עם הרצועות אם קיימות.","התחילו לדווש בקצב נוח.","שמרו על קצב יציב והגבירו את ההתנגדות כרצונכם.","הפעילו את שרירי הליבה כדי לשמור על יציבות ויציבה נכונה.","המשיכו לדווש למשך הזמן הרצוי של האימון.","הפחיתו בהדרגה את ההתנגדות והאטו לפני עצירה מוחלטת.","מתחו את הרגליים והירגעו לאחר האימון."],"steps_en":["Adjust the seat height and position to ensure proper alignment.","Place your feet on the pedals and secure them with the straps if available.","Start pedaling at a comfortable pace.","Maintain a steady rhythm and increase the resistance as desired.","Engage your core muscles to maintain stability and proper posture.","Continue pedaling for the desired duration of your workout.","Gradually decrease the resistance and slow down before coming to a complete stop.","Stretch your legs and cool down after the workout."],"mediaId":"H1PESYI"},{"id":"edb-0798","name":"stationary bike walk","name_en":"stationary bike walk","muscle":"core","equipment":"leverage machine","target":"cardiovascular system","bodyPart":"cardio","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["כוונו את גובה המושב והמיקום על האופניים הנייחים כדי להבטיח יישור נכון.","הניחו את הרגליים על הדוושות והדקו אותן עם הרצועות אם קיימות.","התחילו לדווש בקצב נוח, תוך שמירה על גב ישר ושרירי ליבה מופעלים.","שמרו על קצב יציב והגבירו את רמת ההתנגדות אם תרצו.","המשיכו לדווש למשך הזמן הרצוי של אימון הקרדיו.","הירגעו על ידי הפחתה הדרגתית של הקצב ורמת ההתנגדות.","מתחו את שרירי הרגליים לאחר האימון כדי למנוע נוקשות ולקדם התאוששות."],"steps_en":["Adjust the seat height and position on the stationary bike to ensure proper alignment.","Place your feet on the pedals and secure them with the straps if available.","Start pedaling at a comfortable pace, keeping your back straight and core engaged.","Maintain a steady rhythm and increase the resistance level if desired.","Continue pedaling for the desired duration of your cardio workout.","Cool down by gradually reducing your pace and resistance level.","Stretch your leg muscles after the workout to prevent tightness and promote recovery."],"mediaId":"a8VDgLw"},{"id":"edb-3314","name":"straddle maltese","name_en":"straddle maltese","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["shoulders","chest"],"steps":["התחילו בתלייה על זוג טבעות כאשר הידיים ישרות לגמרי והגוף בקו ישר.","פשקו את הרגליים לרווחה, ליצירת תנוחת פישוק.","הפעילו את שרירי הליבה והורידו את הגוף באיטיות עד שהזרועות מקבילות לרצפה.","החזיקו בתנוחה זו למשך מספר שניות, ולאחר מכן דחפו את עצמכם חזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by hanging from a pair of rings with your arms fully extended and your body in a straight line.","Spread your legs wide apart, forming a straddle position.","Engage your core and slowly lower your body until your arms are parallel to the ground.","Hold this position for a few seconds, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"HfqciZF"},{"id":"edb-3298","name":"straddle planche","name_en":"straddle planche","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["shoulders","triceps","chest"],"steps":["התחילו בתנוחת שכיבת סמיכה כאשר הידיים ברוחב הכתפיים והרגליים פשוקות לרווחה.","הפעילו את שרירי הליבה והעבירו את משקל הגוף קדימה באיטיות, כך שהכתפיים יגיעו מעל הידיים.","כופפו את המרפקים והורידו את הגוף לכיוון הרצפה, תוך שמירה על המרפקים קרובים לגוף.","עצרו לרגע בתחתית, ואז דחפו דרך הידיים כדי ליישר את הזרועות ולהרים את הגוף בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a push-up position with your hands shoulder-width apart and your feet spread wide apart.","Engage your core and slowly shift your weight forward, bringing your shoulders over your hands.","Bend your elbows and lower your body towards the ground, keeping your elbows close to your sides.","Pause for a moment at the bottom, then push through your hands to straighten your arms and lift your body back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"BL3GHeY"},{"id":"edb-1427","name":"straight leg outer hip abductor","name_en":"straight leg outer hip abductor","muscle":"glutes","equipment":"body weight","target":"abductors","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings"],"steps":["שכבו על הצד עם הרגליים ישרות ומונחות זו על גבי זו.","הניחו את הזרוע התחתונה מתחת לראש לתמיכה.","הפעילו את שרירי הליבה והרימו את הרגל העליונה גבוה ככל האפשר מבלי לסובב את האגן או להישען אחורה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגל בחזרה לתנוחת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Lie on your side with your legs straight and stacked on top of each other.","Place your bottom arm under your head for support.","Engage your core and lift your top leg as high as possible without rotating your hips or leaning backward.","Pause for a moment at the top, then slowly lower your leg back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"mQ1tBXn"},{"id":"edb-0803","name":"שכיבת סמיכה","name_en":"superman push-up","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["core","shoulders"],"steps":["התחילו בתנוחת פלאנק גבוה עם הידיים מעט רחבות יותר מרוחב הכתפיים והרגליים צמודות.","הפעילו את שרירי הליבה והורידו את הגוף לכיוון הרצפה, כשהמרפקים צמודים לגוף.","תוך כדי הורדת הגוף, הרימו בו-זמנית את היד הימנית והרגל השמאלית מהרצפה, והושיטו אותן ישר.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את היד והרגל בחזרה תוך דחיפת עצמכם לתנוחת ההתחלה.","חזרו על התנועה, הפעם תוך הרמת היד השמאלית והרגל הימנית.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Start in a high plank position with your hands slightly wider than shoulder-width apart and your feet together.","Engage your core and lower your body towards the ground, keeping your elbows close to your sides.","As you lower your body, simultaneously lift your right arm and left leg off the ground, extending them straight out.","Pause for a moment at the top, then lower your arm and leg back down while pushing yourself back up to the starting position.","Repeat the movement, this time lifting your left arm and right leg.","Continue alternating sides for the desired number of repetitions."],"mediaId":"4GqRrAk"},{"id":"edb-0805","name":"suspended abdominal fallout","name_en":"suspended abdominal fallout","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","hip flexors"],"steps":["חברו רצועות אימון תלויות (TRX) לנקודת עיגון גבוהה וכוונו את הרצועות לגובה המותניים.","עמדו כשגבכם לנקודת העיגון ואחזו בידיות כאשר הידיים מושטות לפניכם.","הטו את הגוף קדימה מהמותניים, תוך שמירה על גוף ישר והפעלת שרירי הליבה.","הורידו את הגוף עד כמה שתוכלו תוך שמירה על שליטה ומתח בשרירי הבטן.","עצרו לרגע בנקודה התחתונה, ולאחר מכן הרימו את הגוף באיטיות בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a suspension trainer to a high anchor point and adjust the straps to waist height.","Stand facing away from the anchor point and hold the handles with your arms extended in front of you.","Lean forward at the waist, keeping your body straight and your core engaged.","Lower your body as far as you can while maintaining control and tension in your abs.","Pause for a moment at the bottom, then slowly raise your body back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"X3TCNEU"},{"id":"edb-0806","name":"שכיבת סמיכה","name_en":"suspended push-up","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders","core"],"steps":["אתרו רצועות אימון תלויות וכוונו אותן לגובה המתאים.","עמדו כשגבכם לנקודת העיגון ואחזו בידיות באחיזה עליונה.","צעדו עם הרגליים קדימה, תוך הטיית הגוף קדימה עד שמשקלכם נתמך על ידי רצועות האימון.","שמרו על גוף ישר מהראש ועד העקבים, הפעילו את שרירי הליבה, והורידו את החזה לכיוון הידיות.","דחפו באמצעות החזה והזרועות כדי לחזור לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Find a suspension trainer and adjust it to an appropriate height.","Stand facing away from the anchor point and hold the handles with an overhand grip.","Walk your feet forward, leaning your body forward until your weight is supported by the suspension trainer.","Keep your body straight from head to heels, engage your core, and lower your chest towards the handles.","Push through your chest and arms to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"IaGQCrC"},{"id":"edb-0807","name":"כפיפת בטן הפוכה","name_en":"suspended reverse crunch","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["התלו ממתקן מתח כשהידיים מיושרות לגמרי וכפות הידיים פונות הרחק מכם.","הפעילו את שרירי הליבה והרימו את הברכיים לכיוון החזה, תוך כיפוף האגן לכיוון בית החזה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את הברכיים באיטיות בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Hang from a pull-up bar with your arms fully extended and your palms facing away from you.","Engage your core and lift your knees up towards your chest, curling your pelvis towards your ribcage.","Pause for a moment at the top, then slowly lower your knees back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"R1WYG5D"},{"id":"edb-0808","name":"חתירה","name_en":"suspended row","muscle":"back","equipment":"body weight","target":"upper back","bodyPart":"back","secondaryMuscles":["biceps","shoulders"],"steps":["הציבו רצועות אימון תלויות בגובה המתאים.","עמדו מול נקודת העיגון עם הרגליים ברוחב הכתפיים.","אחזו בידיות באחיזה עליונה, כאשר כפות הידיים פונות זו לזו.","הטו את הגוף לאחור, תוך שמירה עליו ישר והעקבים על הרצפה.","משכו את החזה לכיוון הידיות, תוך כיווץ שכמות הכתפיים יחד.","עצרו לרגע בשיא התנועה, ואז הורידו את עצמכם לאט בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Set up a suspension trainer at an appropriate height.","Stand facing the anchor point with your feet shoulder-width apart.","Hold the handles with an overhand grip, palms facing each other.","Lean back, keeping your body straight and your heels on the ground.","Pull your chest towards the handles, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower yourself back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"4OaumBr"},{"id":"edb-0809","name":"סקוואט מפוצל","name_en":"suspended split squat","muscle":"legs","equipment":"body weight","target":"quads","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings","calves"],"steps":["עמדו כשגבכם לרצועות האימון והרגליים ברוחב הכתפיים.","הושיטו רגל אחת קדימה והניחו את גב כף הרגל ברצועת התמיכה של רצועות האימון.","כופפו את רגל התמיכה והורידו את הגוף לתנוחת לאנג', תוך שמירה על החזה מורם והברך בקו אחד עם אצבעות הרגל.","דחפו דרך העקב כדי לחזור לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו רגליים."],"steps_en":["Stand facing away from a suspension trainer with your feet shoulder-width apart.","Extend one leg forward and place the top of your foot in the foot cradle of the suspension trainer.","Bend your standing leg and lower your body down into a lunge position, keeping your chest up and your knee in line with your toes.","Push through your heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"mediaId":"QpXqiq8"},{"id":"edb-3433","name":"swimmer kicks v. 2 (male)","name_en":"swimmer kicks v. 2 (male)","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps","calves"],"steps":["שכבו על הבטן על גבי מזרן כאשר הידיים מושטות מעל הראש.","הפעילו את שרירי הליבה והרימו את החזה והרגליים מהרצפה בו-זמנית.","בעטו ברגליים למעלה ולמטה בתנועה מפרפרת, כאילו אתם שוחים.","המשיכו לבעוט למספר החזרות הרצוי.","הורידו את החזה והרגליים בחזרה לתנוחת ההתחלה."],"steps_en":["Lie face down on a mat with your arms extended overhead.","Engage your core and lift your chest and legs off the ground simultaneously.","Kick your legs up and down in a fluttering motion, as if you were swimming.","Continue kicking for the desired number of repetitions.","Lower your chest and legs back down to the starting position."],"mediaId":"SP3hUez"},{"id":"edb-3318","name":"swing 360","name_en":"swing 360","muscle":"core","equipment":"body weight","target":"cardiovascular system","bodyPart":"cardio","secondaryMuscles":["shoulders","core"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","החזיקו את הידיים ישרות לפניכם, במקביל לרצפה.","הפעילו את שרירי הליבה והניעו את הידיים בתנועה מעגלית, תוך סיבוב פלג הגוף העליון.","המשיכו בתנועה המעגלית, תוך הנעת הידיים וסיבוב פלג הגוף העליון למספר החזרות הרצוי.","זכרו לנשום לאורך כל התרגיל."],"steps_en":["Stand with your feet shoulder-width apart and knees slightly bent.","Hold your arms straight out in front of you, parallel to the ground.","Engage your core and swing your arms in a circular motion, rotating your torso as you do so.","Continue the circular motion, swinging your arms and rotating your torso for the desired number of repetitions.","Remember to breathe throughout the exercise."],"mediaId":"tnaj0mT"},{"id":"edb-1753","name":"מקבילים","name_en":"three bench dip","muscle":"triceps","equipment":"body weight","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["שבו על ספסל כאשר הידיים אוחזות בקצה, והאצבעות פונות קדימה.","החליקו את הישבן מהספסל, תוך תמיכת המשקל בידיים.","כופפו את המרפקים והורידו את הגוף עד שהזרועות העליונות מקבילות לרצפה.","דחפו את עצמכם בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your hands gripping the edge, fingers pointing forward.","Slide your butt off the bench, supporting your weight with your hands.","Bend your elbows and lower your body until your upper arms are parallel to the ground.","Push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"DQ0cqkT"},{"id":"edb-2459","name":"tire flip","name_en":"tire flip","muscle":"glutes","equipment":"tire","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps","core"],"steps":["עמדו כשהרגליים ברוחב הכתפיים, מול הצמיג.","כופפו את הברכיים והטו את הגוף מהמותניים, לתנוחת סקוואט.","השיטו את הידיים למטה ואחזו בקצה התחתון של הצמיג בשתי הידיים, כאשר האצבעות פונות אליכם.","הפעילו את שרירי הישבן והרגליים, ודחפו בעוצמה דרך הרגליים כדי להרים את הצמיג מהקרקע.","תוך כדי היפוך הצמיג, השתמשו בכוח פלג הגוף העליון כדי לכוון אותו ולשמור על שליטה.","לאחר שהצמיג התהפך לגמרי, צעדו אחורה במהירות וחזרו לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, facing the tire.","Bend your knees and hinge at the hips, lowering into a squat position.","Reach down and grab the bottom edge of the tire with both hands, fingers facing towards you.","Engage your glutes and leg muscles, and explosively drive through your legs to lift the tire off the ground.","As the tire flips over, use your upper body strength to guide it and maintain control.","Once the tire is fully flipped, quickly step back and reset your stance.","Repeat for the desired number of repetitions."],"mediaId":"oZjMu1t"},{"id":"edb-0811","name":"דדליפט עם מוט טרפ","name_en":"trap bar deadlift","muscle":"glutes","equipment":"trap bar","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["hamstrings","quadriceps","lower back"],"steps":["עמדו כשהרגליים ברוחב הכתפיים ומוט הטראפ מונח על הקרקע לפניכם.","כופפו את המותניים והברכיים כדי לרדת ולאחוז בידיות מוט הטראפ באחיזה עליונה.","שמרו על גב ישר וחזה מורם תוך שאתם מתחילים להרים את מוט הטראפ מהקרקע על ידי יישור המותניים והברכיים.","תוך כדי ההרמה, התמקדו בדחיפה דרך העקבים ובכיווץ שרירי הישבן בשיא התנועה.","הורידו את מוט הטראפ בחזרה לקרקע על ידי כיפוף המותניים והברכיים, תוך שמירה על גב ישר לאורך כל התנועה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and the trap bar on the ground in front of you.","Bend at the hips and knees to lower yourself down and grip the handles of the trap bar with an overhand grip.","Keep your back straight and chest up as you begin to lift the trap bar off the ground by extending your hips and knees.","As you lift, focus on driving through your heels and squeezing your glutes at the top of the movement.","Lower the trap bar back down to the ground by bending at the hips and knees, keeping your back straight throughout the movement.","Repeat for the desired number of repetitions."],"mediaId":"jQGwmxN"},{"id":"edb-0814","name":"מקבילים","name_en":"triceps dip","muscle":"triceps","equipment":"body weight","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["שבו על קצה הספסל או הכיסא כאשר הידיים אוחזות בקצה, האצבעות פונות קדימה.","החליקו את הישבן מהספסל, תוך תמיכת המשקל בידיים.","כופפו את המרפקים והורידו את הגוף לכיוון הרצפה, תוך שמירה על הגב קרוב לספסל.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו את עצמכם בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the edge of a bench or chair with your hands gripping the edge, fingers pointing forward.","Slide your butt off the bench, supporting your weight with your hands.","Bend your elbows and lower your body towards the ground, keeping your back close to the bench.","Pause for a moment at the bottom, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"X6C6i5Y"},{"id":"edb-0812","name":"מקבילים","name_en":"triceps dip (bench leg)","muscle":"triceps","equipment":"body weight","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["שבו על קצה הספסל כאשר הידיים אוחזות בקצה, והאצבעות פונות קדימה.","צעדו עם הרגליים קדימה, החליקו את הישבן מהספסל, ויישרו את הידיים.","כופפו את המרפקים והורידו את הגוף לכיוון הרצפה, תוך שמירה על הגב קרוב לספסל.","דחפו דרך כפות הידיים כדי ליישר את הידיים ולחזור לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the edge of a bench with your hands gripping the edge, fingers pointing forward.","Walk your feet forward, sliding your butt off the bench, and straighten your arms.","Bend your elbows and lower your body towards the ground, keeping your back close to the bench.","Push through your palms to straighten your arms and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"VuoerH0"},{"id":"edb-0813","name":"מקבילים","name_en":"triceps dip (between benches)","muscle":"triceps","equipment":"body weight","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["שבו על ספסל כאשר הידיים אוחזות בקצה הספסל, והאצבעות פונות קדימה.","החליקו את הישבן מהספסל, תוך תמיכת המשקל בידיים.","כופפו את המרפקים והורידו את הגוף לכיוון הרצפה, תוך שמירה על הגב קרוב לספסל.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו את עצמכם בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your hands gripping the edge of the bench, fingers pointing forward.","Slide your butt off the bench, supporting your weight with your hands.","Bend your elbows and lower your body towards the ground, keeping your back close to the bench.","Pause for a moment at the bottom, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"Wgbn9qo"},{"id":"edb-0815","name":"triceps dips floor","name_en":"triceps dips floor","muscle":"triceps","equipment":"body weight","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["שבו על קצה כיסא או ספסל כאשר הידיים לצד הירכיים, והאצבעות פונות קדימה.","החליקו את הישבן מקדמת הכיסא כאשר הרגליים מושטות לפניכם.","יישרו את הידיים, תוך שמירה על כיפוף קל במרפקים כדי לשמור על המתח בשריר התלת-ראשי ולהפחית עומס ממפרקי המרפק.","כופפו את המרפקים באיטיות כדי להוריד את הגוף לכיוון הרצפה עד שהמרפקים בזווית של כ-90 מעלות.","כאשר תגיעו לתחתית התנועה, לחצו כלפי מטה על הכיסא כדי ליישר את המרפקים ולחזור לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the edge of a chair or bench with your hands next to your hips, fingers pointing forward.","Slide your butt off the front of the chair with your legs extended in front of you.","Straighten your arms, keeping a little bend in your elbows to keep tension on your triceps and off your elbow joints.","Slowly bend your elbows to lower your body toward the floor until your elbows are at about a 90-degree angle.","Once you reach the bottom of the movement, press down into the chair to straighten your elbows, returning to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"7aVz15j"},{"id":"edb-0816","name":"לחיצה","name_en":"triceps press","muscle":"triceps","equipment":"body weight","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והברכיים כפופות מעט.","הושיטו את הידיים ישר לפניכם, במקביל לרצפה.","כופפו את המרפקים והורידו את הגוף לכיוון הרצפה, תוך שמירה על הזרועות העליונות קרובות לגוף.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו את עצמכם בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your knees slightly bent.","Extend your arms straight out in front of you, parallel to the ground.","Bend your elbows and lower your body towards the ground, keeping your upper arms close to your sides.","Pause for a moment at the bottom, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"fSrPP6B"},{"id":"edb-0817","name":"מתיחה","name_en":"triceps stretch","muscle":"triceps","equipment":"body weight","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["shoulders"],"steps":["עמדו או שבו זקוף עם גב ישר.","הושיטו יד אחת מעל הראש, תוך כיפופה במרפק.","הניחו את היד השנייה על המרפק הכפוף ומשכו אותו בעדינות לכיוון הראש.","החזיקו את המתיחה למשך 15-30 שניות, תוך הרגשת מתיחה עדינה בשריר התלת-ראשי.","שחררו את המתיחה וחזרו על התרגיל ביד השנייה."],"steps_en":["Stand or sit upright with your back straight.","Extend one arm overhead, bending it at the elbow.","Place your opposite hand on the bent elbow and gently pull it towards your head.","Hold the stretch for 15-30 seconds, feeling a gentle stretch in your triceps.","Release the stretch and repeat on the other arm."],"mediaId":"uOV3Itw"},{"id":"edb-0871","name":"כפיפת בטן","name_en":"tuck crunch","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו את הידיים מאחורי הראש כשהמרפקים פונים החוצה.","תוך הפעלת שרירי הבטן, הרימו את השכמות מהרצפה וקרבו את הברכיים לכיוון החזה, תוך כיפוף פלג הגוף העליון לכיוון הברכיים בו-זמנית.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את השכמות באיטיות ויישרו את הרגליים בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, lift your shoulder blades off the ground and bring your knees towards your chest, simultaneously curling your upper body towards your knees.","Pause for a moment at the top, then slowly lower your shoulder blades and extend your legs back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"BMMolZ3"},{"id":"edb-0818","name":"פולי עליון","name_en":"twin handle parallel grip lat pulldown","muscle":"back","equipment":"cable","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","rhomboids","rear deltoids"],"steps":["כוונו את גובה המושב והתמקמו מול מכונת הפולי.","אחזו בידיות באחיזה עליונה, כאשר הידיים ברוחב הכתפיים.","שבו ומקמו את הירכיים מתחת לכריות הירכיים, תוך שמירה על כפות הרגליים שטוחות על הרצפה.","הטו את הגוף מעט אחורה ושמרו על החזה מורם, תוך שמירה על עמוד שדרה נייטרלי.","משכו את הידיות כלפי מטה לכיוון החזה העליון, תוך כיווץ השכמות זו לעבר זו.","עצרו לרגע בתחתית התנועה, תוך הרגשת הכיווץ בשרירי הגב הרחבים.","שחררו לאט את הידיות וחזרו למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Adjust the seat height and position yourself facing the cable machine.","Grasp the handles with an overhand grip, hands shoulder-width apart.","Sit down and position your thighs under the thigh pads, keeping your feet flat on the floor.","Lean back slightly and keep your chest up, maintaining a neutral spine.","Pull the handles down towards your upper chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, feeling the contraction in your lats.","Slowly release the handles and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"rkg41Fb"},{"id":"edb-1466","name":"פיתול","name_en":"twist hip lift","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["obliques","hamstrings"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","הניחו את הידיים לצדי הגוף לתמיכה.","הפעילו את שרירי הישבן והרימו את האגן מהרצפה, ביצירת קו ישר מהברכיים ועד הכתפיים.","תוך שמירה על האגן מורם, סובבו את פלג הגוף התחתון לצד ימין, וקרבו את הברכיים לכיוון הרצפה.","חזרו לתנוחת ההתחלה וחזרו על הסיבוב לצד שמאל.","המשיכו לסובב לסירוגין למספר החזרות הרצוי."],"steps_en":["Lie on your back with your knees bent and feet flat on the ground.","Place your hands by your sides for support.","Engage your glutes and lift your hips off the ground, forming a straight line from your knees to your shoulders.","While keeping your hips lifted, twist your lower body to the right side, bringing your knees towards the ground.","Return to the starting position and repeat the twist to the left side.","Continue alternating twists for the desired number of repetitions."],"mediaId":"AX1kB0o"},{"id":"edb-2802","name":"הרמת רגליים","name_en":"twisted leg raise","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","hip flexors"],"steps":["שכבו על הגב עם הרגליים מושטות והידיים לצידי הגוף.","הניחו את הידיים מתחת לישבן לתמיכה.","הפעילו את שרירי הבטן והרימו את שתי הרגליים מהרצפה, תוך שמירה עליהן ישרות.","תוך כדי הרמת הרגליים, סובבו את האגן לצד אחד, וקרבו את הרגליים לכיוון הכתף הנגדית.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התנועה, הפעם תוך סיבוב האגן לצד השני.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your legs extended and your arms by your sides.","Place your hands under your glutes for support.","Engage your abs and lift both legs off the ground, keeping them straight.","As you lift your legs, twist your hips to one side, bringing your legs towards your opposite shoulder.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat the movement, this time twisting your hips to the other side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"C0eCeEt"},{"id":"edb-2801","name":"הרמת רגליים","name_en":"twisted leg raise (female)","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","hip flexors"],"steps":["שכבו על הגב עם הרגליים מושטות והידיים לצידי הגוף.","כופפו את הברכיים והרימו את הרגליים מהרצפה, וקרבו אותן לכיוון החזה.","תוך כדי הרמת הרגליים, סובבו את האגן לצד אחד, וקרבו את הברכיים לכיוון הכתף הנגדית.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התנועה, הפעם תוך סיבוב האגן לצד השני.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your legs extended and your arms by your sides.","Bend your knees and lift your legs off the ground, bringing them towards your chest.","As you lift your legs, twist your hips to one side, bringing your knees towards your opposite shoulder.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat the movement, this time twisting your hips to the other side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"yT9tk17"},{"id":"edb-3231","name":"two toe touch (male)","name_en":"two toe touch (male)","muscle":"back","equipment":"body weight","target":"spine","bodyPart":"back","secondaryMuscles":["hamstrings","glutes"],"steps":["עמדו כשהרגליים ברוחב הכתפיים והידיים מושטות הצידה.","התכופפו קדימה מהמותניים, תוך שמירה על גב ישר וברכיים כפופות מעט.","השיטו את שתי הידיים לכיוון אצבעות הרגליים, תוך שמירה על הרגליים ישרות.","עצרו לרגע בתחתית התנועה, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your arms extended out to the sides.","Bend forward at the waist, keeping your back straight and your knees slightly bent.","Reach down towards your toes with both hands, keeping your legs straight.","Pause for a moment at the bottom, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"p195zsJ"},{"id":"edb-1365","name":"מתיחה","name_en":"upper back stretch","muscle":"back","equipment":"body weight","target":"upper back","bodyPart":"back","secondaryMuscles":["shoulders"],"steps":["עמדו זקוף כשהרגליים ברוחב הכתפיים.","הושיטו את הידיים ישר לפניכם, במקביל לרצפה.","שזרו את האצבעות וסובבו את כפות הידיים החוצה מהגוף.","הרימו את הידיים באיטיות מעל הראש, תוך שמירה עליהן ישרות ומקבילות זו לזו.","תוך כדי הרמת הידיים, כווצו את השכמות זו לעבר זו.","החזיקו את המתיחה למשך 15-30 שניות, ולאחר מכן שחררו וחזרו על התרגיל."],"steps_en":["Stand up straight with your feet shoulder-width apart.","Extend your arms straight in front of you, parallel to the ground.","Interlace your fingers and rotate your palms away from your body.","Slowly raise your arms overhead, keeping them straight and parallel to each other.","As you raise your arms, squeeze your shoulder blades together.","Hold the stretch for 15-30 seconds, then release and repeat."],"mediaId":"GSDioYu"},{"id":"edb-1366","name":"upward facing dog","name_en":"upward facing dog","muscle":"back","equipment":"body weight","target":"spine","bodyPart":"back","secondaryMuscles":["shoulders","chest"],"steps":["שכבו על הבטן על הרצפה כאשר הרגליים מושטות מאחור.","הניחו את הידיים על הרצפה לצד הצלעות התחתונות, כאשר האצבעות פונות קדימה.","לחצו את הידיים בחוזקה על הרצפה ויישרו את הידיים, תוך הרמת פלג הגוף העליון והירכיים מהרצפה.","סובבו את הכתפיים אחורה ומטה, פתחו את החזה והרימו את המבט לכיוון התקרה.","החזיקו בתנוחה זו למשך מספר נשימות, ולאחר מכן הורידו את הגוף באיטיות בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie face down on the floor with your legs extended behind you.","Place your hands on the floor next to your lower ribs, fingers pointing forward.","Press your hands firmly into the floor and straighten your arms, lifting your torso and thighs off the ground.","Roll your shoulders back and down, opening your chest and lifting your gaze towards the ceiling.","Hold this position for a few breaths, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"01qpYSe"},{"id":"edb-3420","name":"v-sit on floor","name_en":"v-sit on floor","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["שבו על הרצפה כשהרגליים מושטות לפניכם.","הטו את הגוף מעט אחורה והרימו את הרגליים מהרצפה, תוך שמירה עליהן ישרות.","בו-זמנית, הרימו את פלג הגוף העליון מהרצפה והושיטו את הידיים לכיוון הרגליים.","החזיקו בתנוחה זו למשך מספר שניות, ולאחר מכן הורידו באיטיות את פלג הגוף העליון והרגליים בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the floor with your legs extended in front of you.","Lean back slightly and lift your legs off the ground, keeping them straight.","Simultaneously, lift your upper body off the ground and reach your arms towards your legs.","Hold this position for a few seconds, then slowly lower your upper body and legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ZuXu4Eq"},{"id":"edb-0826","name":"הרמת רגליים","name_en":"vertical leg raise (on parallel bars)","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors"],"steps":["התלו על המקבילים כאשר הידיים ישרות לגמרי והגוף ישר.","הפעילו את שרירי הליבה והרימו את הרגליים לפניכם, תוך שמירה עליהן ישרות.","המשיכו להרים עד שהרגליים מקבילות לרצפה או מעט מעל.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Hang from the parallel bars with your arms fully extended and your body straight.","Engage your core and lift your legs up in front of you, keeping them straight.","Continue lifting until your legs are parallel to the ground or slightly higher.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"ZNgOYQU"},{"id":"edb-2141","name":"walk elliptical cross trainer","name_en":"walk elliptical cross trainer","muscle":"core","equipment":"elliptical machine","target":"cardiovascular system","bodyPart":"cardio","secondaryMuscles":["quadriceps","hamstrings","glutes","calves"],"steps":["כוונו את רמת ההתנגדות ואת השיפוע של מכונת האליפטיקל להגדרות הרצויות.","עלו על הדוושות של המכונה ואחזו בידיות באחיזה קלה.","התחילו על ידי דחיפה כלפי מטה עם הרגליים ומשיכת הידיות לכיוון הגוף.","המשיכו בתנועה זו, תוך החלפה בין דחיפה למשיכה, כדי לחקות תנועת הליכה או ריצה.","שמרו על קצב יציב והפעילו את שרירי הליבה לאורך כל התרגיל.","המשיכו למשך הזמן הרצוי של אימון הקרדיו.","הפחיתו בהדרגה את העצימות והמהירות של המכונה לפני הירידה ממנה."],"steps_en":["Adjust the resistance level and incline of the elliptical machine to your desired settings.","Step onto the pedals of the machine and grip the handles lightly.","Begin by pushing down with your feet and pulling the handles towards your body.","Continue this motion, alternating between pushing and pulling, to simulate a walking or running motion.","Maintain a steady pace and keep your core engaged throughout the exercise.","Continue for the desired duration of your cardio workout.","Gradually decrease the intensity and speed of the machine before stepping off."],"mediaId":"rjtuP6X"},{"id":"edb-3655","name":"לאנג׳ גבוה","name_en":"walking high knees lunge","muscle":"core","equipment":"body weight","target":"cardiovascular system","bodyPart":"cardio","secondaryMuscles":["quadriceps","hamstrings","glutes","calves"],"steps":["עמדו עם הרגליים ברוחב האגן.","הרימו את הברך הימנית לכיוון החזה גבוה ככל האפשר תוך שמירה על שיווי משקל על הרגל השמאלית.","צעדו קדימה עם הרגל הימנית והורידו את הגוף לתנוחת לאנג', תוך כיפוף שתי הברכיים לזווית של 90 מעלות.","דחפו עם הרגל הימנית וקרבו את הברך השמאלית לכיוון החזה.","צעדו קדימה עם הרגל השמאלית והורידו את הגוף לתנוחת לאנג'.","המשיכו להחליף רגליים ולהתקדם בתנועת לאנג', תוך הפעלת שרירי הליבה ושמירה על קצב יציב.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet hip-width apart.","Lift your right knee up towards your chest as high as you can while balancing on your left leg.","Step forward with your right foot and lower your body into a lunge position, bending both knees to a 90-degree angle.","Push off with your right foot and bring your left knee up towards your chest.","Step forward with your left foot and lower your body into a lunge position.","Continue alternating legs and lunging forward, keeping your core engaged and maintaining a steady pace.","Repeat for the desired number of repetitions."],"mediaId":"J9zIWig"},{"id":"edb-1460","name":"לאנג׳","name_en":"walking lunge","muscle":"glutes","equipment":"body weight","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים.","צעדו קדימה עם הרגל הימנית, תוך הורדת הגוף לתנוחת לאנג'.","שמרו על פלג הגוף העליון זקוף ועל הברך הקדמית בקו אחד עם הקרסול.","דחפו עם הרגל הימנית והביאו את הרגל השמאלית קדימה, תוך כניסה לתנוחת לאנג' עם הרגל השמאלית.","המשיכו להחליף רגליים ולהתקדם בהליכה, תוך שמירה על קצב מבוקר ויציב.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart.","Take a step forward with your right leg, lowering your body into a lunge position.","Keep your torso upright and your front knee aligned with your ankle.","Push off with your right foot and bring your left foot forward, stepping into a lunge position with your left leg.","Continue alternating legs and walking forward, maintaining a controlled and steady pace.","Repeat for the desired number of repetitions."],"mediaId":"IZVHb27"},{"id":"edb-3666","name":"walking on incline treadmill","name_en":"walking on incline treadmill","muscle":"core","equipment":"leverage machine","target":"cardiovascular system","bodyPart":"cardio","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["כוונו את רמת השיפוע במסילון להגדרת העצימות הרצויה.","עמדו על המסילון כשהרגליים ברוחב הכתפיים.","התחילו ללכת בקצב נוח, תוך הקפדה על שמירה על טכניקה נכונה.","הפעילו את שרירי הליבה ושמרו על גב ישר לאורך כל התרגיל.","המשיכו ללכת על המסילון המשופע למשך הזמן הרצוי של אימון הקרדיו.","הפחיתו בהדרגה את השיפוע והמהירות של המסילון כדי להירגע לפני העצירה."],"steps_en":["Adjust the incline level on the treadmill to your desired intensity.","Stand on the treadmill with your feet shoulder-width apart.","Start walking at a comfortable pace, ensuring that you maintain proper form.","Engage your core muscles and keep your back straight throughout the exercise.","Continue walking on the incline treadmill for the desired duration of your cardio workout.","Gradually decrease the incline and speed of the treadmill to cool down before stopping."],"mediaId":"rjiM4L3"},{"id":"edb-2311","name":"walking on stepmill","name_en":"walking on stepmill","muscle":"core","equipment":"stepmill machine","target":"cardiovascular system","bodyPart":"cardio","secondaryMuscles":["quadriceps","hamstrings","glutes","calves"],"steps":["כוונו את מכונת המדרגות לרמה נוחה.","עלו על המכונה והניחו את הידיים על המעקות לתמיכה.","התחילו ללכת על ידי הנחת רגל אחת על מדרגה ולאחר מכן את השנייה, תוך החלפה בין הרגליים.","שמרו על יציבה זקופה והפעילו את שרירי הליבה.","המשיכו ללכת למשך הזמן או המרחק הרצוי.","הגבירו בהדרגה את העצימות או המהירות ככל שתתרגלו לתרגיל.","זכרו להירגע ולמתוח לאחר סיום התרגיל."],"steps_en":["Adjust the stepmill machine to a comfortable level.","Step onto the machine and place your hands on the handrails for support.","Start walking by placing one foot on a step and then the other, alternating between legs.","Maintain an upright posture and engage your core muscles.","Continue walking for the desired duration or distance.","Gradually increase the intensity or speed as you become more comfortable with the exercise.","Remember to cool down and stretch after completing the exercise."],"mediaId":"j9Q5crt"},{"id":"edb-0830","name":"מקבילים עם משקל","name_en":"weighted bench dip","muscle":"triceps","equipment":"weighted","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["שבו על ספסל כאשר הידיים אוחזות בקצה, והאצבעות פונות קדימה.","החליקו את הישבן מהספסל, תוך תמיכת המשקל בידיים.","הורידו את הגוף על ידי כיפוף המרפקים עד שהזרועות מקבילות לרצפה.","דחפו את עצמכם חזרה למצב ההתחלתי על ידי יישור הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a bench with your hands gripping the edge, fingers pointing forward.","Slide your butt off the bench, supporting your weight with your hands.","Lower your body by bending your elbows until your upper arms are parallel to the floor.","Push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"mediaId":"MU9HnE7"},{"id":"edb-2987","name":"מתח אחיזה תחתית אחיזה צרה עם משקל","name_en":"weighted close grip chin-up on dip cage","muscle":"back","equipment":"weighted","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["עמדו מול מתקן הדיפים ואחזו במקבילים באחיזה תחתונה, כאשר הידיים ברוחב הכתפיים.","התלו על המוטות כאשר הידיים ישרות לגמרי, הרגליים מורמות מהקרקע, והגוף ישר.","הפעילו את שרירי הגב ומשכו את הגוף כלפי מעלה לכיוון המוטות, תוך שמירה על המרפקים קרובים לגוף.","המשיכו למשוך עד שהסנטר מעל המוטות, ולאחר מכן עצרו לרגע.","הורידו את הגוף באיטיות בחזרה לתנוחת ההתחלה, תוך יישור מלא של הידיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand in front of the dip cage and grab the parallel bars with an underhand grip, hands shoulder-width apart.","Hang from the bars with your arms fully extended, feet off the ground, and body straight.","Engage your back muscles and pull your body up towards the bars, keeping your elbows close to your sides.","Continue pulling until your chin is above the bars, then pause for a moment.","Slowly lower your body back down to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"mediaId":"Gk1r408"},{"id":"edb-3643","name":"weighted cossack squats (male)","name_en":"weighted cossack squats (male)","muscle":"glutes","equipment":"weighted","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו כשהרגליים פשוקות מעבר לרוחב הכתפיים והבהונות פונות מעט החוצה.","אחזו במשקולת מול החזה בשתי הידיים.","העבירו את משקל הגוף לצד אחד והורידו את הגוף על ידי כיפוף הברך של הצד אליו הטיתם את המשקל, תוך שמירה על הרגל השנייה ישרה.","רדו נמוך ככל שתוכלו תוך שמירה על שיווי משקל וחזה מורם.","דחפו דרך העקב של הרגל הכפופה כדי לחזור לתנוחת ההתחלה.","חזרו על התרגיל בצד השני, תוך החלפה בין הרגליים."],"steps_en":["Stand with your feet wider than shoulder-width apart and toes pointing slightly outward.","Hold a weight in front of your chest with both hands.","Shift your weight to one side and lower your body by bending the knee of the side you shifted towards, while keeping the other leg straight.","Go as low as you can while maintaining balance and keeping your chest up.","Push through the heel of the bent leg to return to the starting position.","Repeat on the other side, alternating between legs."],"mediaId":"GWoKnIm"},{"id":"edb-0832","name":"כפיפת בטן עם משקל","name_en":"weighted crunch","muscle":"core","equipment":"weighted","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques"],"steps":["שכבו על הגב עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","אחזו בפלטת משקולת או בדמבל על החזה.","הפעילו את שרירי הבטן והרימו את פלג הגוף העליון מהרצפה, תוך כיפוף קדימה עד שהשכמות מורמות מהרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on your back with your knees bent and feet flat on the ground.","Hold a weight plate or dumbbell on your chest.","Engage your abs and lift your upper body off the ground, curling forward until your shoulder blades are off the ground.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"s8nrDXF"},{"id":"edb-3670","name":"כפיפת בטן מלאה בשיפוע שלילי עם משקל","name_en":"weighted decline sit-up","muscle":"core","equipment":"weighted","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors","lower back"],"steps":["שכבו על ספסל שיפוע שלילי כאשר הרגליים מקובעות מתחת לכריות הרגליים.","הניחו את הידיים מאחורי הראש או לרוחב החזה.","הפעילו את שרירי הבטן והרימו באיטיות את פלג הגוף העליון מהספסל, תוך כיפוף קדימה עד שפלג הגוף מאונך לרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Lie flat on a decline bench with your feet secured under the foot pads.","Place your hands behind your head or across your chest.","Engage your abs and slowly lift your upper body off the bench, curling forward until your torso is perpendicular to the ground.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"EZeDVzO"},{"id":"edb-0833","name":"הרמת עקבים עם משקל","name_en":"weighted donkey calf raise","muscle":"legs","equipment":"weighted","target":"calves","bodyPart":"lower legs","secondaryMuscles":["hamstrings","glutes"],"steps":["עמדו על משטח מוגבה כשהבהונות על הקצה והעקבים תלויים מחוצה לו.","אחזו בעצם יציב לתמיכה.","הרימו את העקבים גבוה ככל האפשר על ידי יישור הקרסוליים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את העקבים בחזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand on a raised platform with your toes on the edge and your heels hanging off.","Hold onto a stable object for support.","Raise your heels as high as possible by extending your ankles.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"LmaFNZS"},{"id":"edb-1310","name":"שכיבת סמיכה עם משקל","name_en":"weighted drop push up","muscle":"chest","equipment":"weighted","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["התחילו בתנוחת פלאנק גבוה עם הידיים מעט רחבות יותר מרוחב הכתפיים והרגליים צמודות.","הורידו את החזה לכיוון הרצפה, כשהמרפקים צמודים לגוף.","כאשר החזה קרוב מאוד לרצפה, דחפו את עצמכם למעלה בפיצוץ כוח, תוך הרמת הידיים מהרצפה.","תוך כדי הדחיפה למעלה, הזיזו את הידיים במהירות הצידה ומעט קדימה, כדי לאפשר לגוף לרדת לכיוון הרצפה.","תפסו את עצמכם עם הידיים בתנוחה הרחבה יותר והורידו מיד את החזה לכיוון הרצפה שוב.","חזרו על תנועת שכיבת הסמיכה, תוך ירידה ותפיסת עצמכם עם הידיים בתנוחה הצרה יותר.","המשיכו להחליף בין תנוחות הידיים הרחבה והצרה למספר החזרות הרצוי."],"steps_en":["Start in a high plank position with your hands slightly wider than shoulder-width apart and your feet together.","Lower your chest towards the ground, keeping your elbows close to your body.","Once your chest is just above the ground, explosively push yourself up, lifting your hands off the ground.","As you push up, quickly move your hands out to the sides and slightly forward, allowing your body to drop down towards the ground.","Catch yourself with your hands in the wider position and immediately lower your chest towards the ground again.","Repeat the push-up motion, dropping down and catching yourself with your hands in the narrower position.","Continue alternating between the wider and narrower hand positions for the desired number of repetitions."],"mediaId":"PSlvNMs"},{"id":"edb-2135","name":"פלאנק קדמי עם משקל","name_en":"weighted front plank","muscle":"core","equipment":"weighted","target":"abs","bodyPart":"waist","secondaryMuscles":["shoulders","lower back"],"steps":["התחילו בשכיבה על הבטן על הרצפה.","הניחו את האמות על הרצפה, כאשר המרפקים ישירות מתחת לכתפיים.","הושיטו את הרגליים ישר מאחור, כאשר הבהונות נוגעות ברצפה.","הפעילו את שרירי הליבה והרימו את הגוף מהרצפה, תוך שיווי משקל על האמות והבהונות.","שמרו על הגוף בקו ישר מהראש ועד העקבים.","החזיקו את התנוחה למשך הזמן הרצוי.","הורידו את הגוף בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by lying face down on the floor.","Place your forearms on the ground, with your elbows directly under your shoulders.","Extend your legs straight out behind you, with your toes on the ground.","Engage your core and lift your body off the ground, balancing on your forearms and toes.","Keep your body in a straight line from your head to your heels.","Hold this position for the desired amount of time.","Lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"VBAWRPG"},{"id":"edb-0834","name":"הרמה קדמית עם משקל","name_en":"weighted front raise","muscle":"shoulders","equipment":"weighted","target":"delts","bodyPart":"shoulders","secondaryMuscles":["biceps","forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשבכל יד משקולת וכפות הידיים פונות לירכיים.","כשהידיים ישרות, נשפו החוצה והרימו את המשקולות לפניכם עד לגובה הכתפיים.","עצרו לרגע בשיא התנועה, לאחר מכן שאפו אוויר והורידו לאט את המשקולות בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a dumbbell in each hand with your palms facing your thighs.","Keeping your arms straight, exhale and lift the dumbbells in front of you until they are at shoulder level.","Pause for a moment at the top, then inhale and slowly lower the dumbbells back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"e4aFmFY"},{"id":"edb-0866","name":"הרמת אגן עם משקל","name_en":"weighted hanging leg-hip raise","muscle":"core","equipment":"weighted","target":"abs","bodyPart":"waist","secondaryMuscles":["hip flexors","lower back"],"steps":["התלו ממתקן מתח כשהידיים מיושרות לגמרי וכפות הידיים פונות הרחק מכם.","הפעילו את שרירי הליבה והרימו את הרגליים לפניכם, תוך שמירה עליהן ישרות.","המשיכו להרים עד שהרגליים מקבילות לרצפה או מעט מעל.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הרגליים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Hang from a pull-up bar with your arms fully extended and your palms facing away from you.","Engage your core and lift your legs up in front of you, keeping them straight.","Continue lifting until your legs are parallel to the ground or slightly higher.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"QOA0FD0"},{"id":"edb-0835","name":"פשיטת גב עם כדור פיזיו","name_en":"weighted hyperextension (on stability ball)","muscle":"back","equipment":"weighted","target":"spine","bodyPart":"back","secondaryMuscles":["glutes","hamstrings"],"steps":["התמקמו על הבטן על גבי כדור יציבות כאשר האגן נשען על הכדור והרגליים נשענות על קיר לייצוב.","הניחו את הידיים מאחורי הראש או שלבו אותן על החזה.","הפעילו את שרירי הליבה והרימו באיטיות את פלג הגוף העליון מהכדור, תוך יישור הגב עד שהגוף יוצר קו ישר.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את פלג הגוף העליון בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Position yourself face down on a stability ball with your hips resting on the ball and your feet against a wall for stability.","Place your hands behind your head or cross them over your chest.","Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"8urJS9b"},{"id":"edb-3641","name":"weighted kneeling step with swing","name_en":"weighted kneeling step with swing","muscle":"shoulders","equipment":"weighted","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","core"],"steps":["התחילו בתנוחת כריעה כשהברכיים ברוחב הירכיים והגב ישר.","אחזו במשקולת בכל יד, כאשר הידיים מושטות ישר כלפי מטה לפניכם.","הפעילו את שרירי הליבה והניפו את המשקולות למעלה ומעל הראש, תוך שמירה על הידיים ישרות.","הורידו את המשקולות בחזרה לתנוחת ההתחלה וחזרו למספר החזרות הרצוי."],"steps_en":["Start in a kneeling position with your knees hip-width apart and your back straight.","Hold a weight in each hand, with your arms extended straight down in front of you.","Engage your core and swing the weights up and overhead, keeping your arms straight.","Lower the weights back down to the starting position and repeat for the desired number of repetitions."],"mediaId":"7uFJuXp"},{"id":"edb-3644","name":"לאנג׳ עם משקל","name_en":"weighted lunge with swing","muscle":"glutes","equipment":"weighted","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו כשהרגליים ברוחב הכתפיים, כאשר אתם אוחזים במשקולת בכל יד.","צעדו קדימה עם הרגל הימנית, תוך הורדת הגוף לעמדת לאנג'.","תוך כדי צעידת לאנג' קדימה, הניפו את המשקולות קדימה ומעלה, תוך שמירה על הידיים ישרות.","דחפו עם הרגל הימנית וחזרו לתנוחת ההתחלה, תוך הנפת המשקולות בחזרה למטה.","חזרו עם הרגל השמאלית והמשיכו להחליף רגליים למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, holding a weight in each hand.","Take a step forward with your right foot, lowering your body into a lunge position.","As you lunge forward, swing the weights forward and upward, keeping your arms straight.","Push off with your right foot and return to the starting position, swinging the weights back down.","Repeat with your left foot and continue alternating legs for the desired number of repetitions."],"mediaId":"5WiFcYk"},{"id":"edb-3286","name":"weighted muscle up","name_en":"weighted muscle up","muscle":"back","equipment":"weighted","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","triceps","shoulders","chest"],"steps":["התחילו בתלייה על מוט מתח כאשר כפות הידיים פונות ממכם והידיים מעט רחבות יותר מרוחב הכתפיים.","הפעילו את שרירי הליבה ומשכו את הגוף כלפי מעלה לכיוון המוט, כשהחזה מוביל את התנועה.","כשאתם מגיעים לשיא התנועה, שנו את האחיזה כך שכפות הידיים יפנו אליכם.","המשיכו למשוך את עצמכם למעלה עד שהחזה מגיע למוט, ולאחר מכן עצרו לרגע.","הורידו את עצמכם באיטיות בחזרה לתנוחת ההתחלה, תוך שמירה על שליטה לאורך כל התנועה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by hanging from a pull-up bar with your palms facing away from you and your hands slightly wider than shoulder-width apart.","Engage your core and pull your body up towards the bar, leading with your chest.","As you reach the top of the movement, transition your grip so that your palms are facing towards you.","Continue pulling yourself up until your chest reaches the bar, then pause for a moment.","Slowly lower yourself back down to the starting position, maintaining control throughout the movement.","Repeat for the desired number of repetitions."],"mediaId":"JsOV1SU"},{"id":"edb-3312","name":"weighted muscle up (on bar)","name_en":"weighted muscle up (on bar)","muscle":"back","equipment":"weighted","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","triceps","shoulders","forearms"],"steps":["התחילו בתלייה על מוט מתח כאשר כפות הידיים פונות ממכם והידיים מעט רחבות יותר מרוחב הכתפיים.","הפעילו את ליבת הגוף ומשכו את השכמות מטה ואחורה.","כופפו את המרפקים ומשכו את החזה לכיוון המוט, תוך שמירה על גוף ישר.","כאשר החזה מגיע למוט, דחפו כלפי מטה עם הידיים והניעו את המרפקים אחורה, תוך הרמת הגוף מעל המוט.","עצרו בשיא התנועה, ולאחר מכן רדו באיטיות חזרה למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start by hanging from a pull-up bar with your palms facing away from you and your hands slightly wider than shoulder-width apart.","Engage your core and pull your shoulder blades down and back.","Bend your elbows and pull your chest towards the bar, keeping your body straight.","Once your chest reaches the bar, push down with your hands and drive your elbows back, lifting your body above the bar.","Pause at the top of the movement, then slowly lower yourself back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"MCkqdKE"},{"id":"edb-3290","name":"מתח עם משקל","name_en":"weighted one hand pull up","muscle":"back","equipment":"weighted","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["אחזו במוט המתח באחיזה עליונה, מעט רחב יותר מרוחב הכתפיים.","התלו על המוט כאשר היד ישרה לגמרי והגוף ישר.","הפעילו את שרירי הליבה ומשכו את הגוף כלפי מעלה לכיוון המוט על ידי כיפוף המרפק וכיווץ שרירי הגב.","המשיכו למשוך עד שהסנטר מעל המוט.","הורידו את הגוף בחזרה לתנוחת ההתחלה בשליטה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Grab the pull-up bar with an overhand grip, slightly wider than shoulder-width apart.","Hang from the bar with your arm fully extended and your body straight.","Engage your core and pull your body up towards the bar by bending your elbow and squeezing your back muscles.","Continue pulling until your chin is above the bar.","Lower your body back down to the starting position with control.","Repeat for the desired number of repetitions."],"mediaId":"fXfqg1E"},{"id":"edb-0840","name":"כפיפת בטן מעל הראש עם כדור פיזיו","name_en":"weighted overhead crunch (on stability ball)","muscle":"core","equipment":"weighted","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","lower back"],"steps":["שבו על כדור יציבות כשכפות הרגליים מונחות שטוח על הרצפה והברכיים כפופות בזווית של 90 מעלות.","אחזו בפלטת משקולת או בדמבל בשתי הידיים והושיטו את הידיים מעל הראש.","הפעילו את שרירי הבטן וכופפו באיטיות את פלג הגוף העליון קדימה, וקרבו את החזה לכיוון הברכיים.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו באיטיות את פלג הגוף העליון בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Hold a weight plate or dumbbell with both hands and extend your arms overhead.","Engage your abs and slowly curl your torso forward, bringing your chest towards your knees.","Pause for a moment at the top, then slowly lower your torso back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"xmM75XG"},{"id":"edb-0841","name":"מתח עם משקל","name_en":"weighted pull-up","muscle":"back","equipment":"weighted","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["אחזו במוט המתח באחיזה עליונה, מעט רחב יותר מרוחב הכתפיים.","היתלו מהמוט עם הזרועות ישרות לחלוטין והגוף ישר.","הפעילו את שרירי הגב ומשכו את הגוף כלפי מעלה לכיוון המוט, כשהמרפקים צמודים לגוף.","המשיכו למשוך עד שהסנטר מעל המוט.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הגוף בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Grab the pull-up bar with an overhand grip, slightly wider than shoulder-width apart.","Hang from the bar with your arms fully extended and your body straight.","Engage your back muscles and pull your body up towards the bar, keeping your elbows close to your body.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"HMzLjXx"},{"id":"edb-0844","name":"weighted round arm","name_en":"weighted round arm","muscle":"shoulders","equipment":"weighted","target":"delts","bodyPart":"shoulders","secondaryMuscles":["triceps","upper back"],"steps":["עמדו כשכפות הרגליים ברוחב הכתפיים ואחזו משקולת בכל יד.","כופפו מעט את הברכיים והטו את הגוף קדימה במפרקי הירך, תוך שמירה על גב ישר.","הרימו את הידיים הצידה, תוך שמירה על כיפוף קל במרפקים.","המשיכו להרים את הידיים עד שהן מקבילות לרצפה.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הידיים בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Raise your arms out to the sides, keeping a slight bend in your elbows.","Continue lifting your arms until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"VLYXo8S"},{"id":"edb-0846","name":"פיתול רוסי עם משקל","name_en":"weighted russian twist","muscle":"core","equipment":"weighted","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","lower back"],"steps":["שבו על הרצפה כאשר הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","אחזו במשקולת או בכדור כוח בשתי הידיים מול החזה.","הטו את הגוף מעט אחורה, תוך שמירה על הגב ישר ושרירי הליבה מופעלים.","סובבו את פלג הגוף העליון באיטיות לצד ימין, וקרבו את המשקולת או כדור הכוח לכיוון הרצפה בצד ימין.","עצרו לרגע, ולאחר מכן סובבו את פלג הגוף העליון לצד שמאל, וקרבו את המשקולת או כדור הכוח לכיוון הרצפה בצד שמאל.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Sit on the ground with your knees bent and your feet flat on the floor.","Hold a weight or medicine ball with both hands in front of your chest.","Lean back slightly, keeping your back straight and your core engaged.","Slowly twist your torso to the right, bringing the weight or medicine ball towards the floor on your right side.","Pause for a moment, then twist your torso to the left, bringing the weight or medicine ball towards the floor on your left side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"fZFZ704"},{"id":"edb-0845","name":"פיתול רוסי עם משקל","name_en":"weighted russian twist (legs up)","muscle":"core","equipment":"weighted","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","hip flexors"],"steps":["שבו על הרצפה כאשר הברכיים כפופות והרגליים מורמות מהרצפה, תוך שמירה על הרגליים צמודות.","אחזו במשקולת בשתי הידיים מול החזה, תוך שמירה על כיפוף קל במרפקים.","הטו את הגוף מעט אחורה כדי להפעיל את שרירי הליבה.","סובבו את פלג הגוף העליון לצד ימין, וקרבו את המשקולת לכיוון הרצפה בצד ימין.","עצרו לרגע, ולאחר מכן סובבו את פלג הגוף העליון לצד שמאל, וקרבו את המשקולת לכיוון הרצפה בצד שמאל.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Sit on the ground with your knees bent and feet lifted off the ground, keeping your legs together.","Hold the weight with both hands in front of your chest, keeping your elbows slightly bent.","Lean back slightly to engage your core muscles.","Twist your torso to the right, bringing the weight towards the ground on your right side.","Pause for a moment, then twist your torso to the left, bringing the weight towards the ground on your left side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"WU9BLIs"},{"id":"edb-2371","name":"פיתול רוסי עם משקל","name_en":"weighted russian twist v. 2","muscle":"core","equipment":"weighted","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","lower back"],"steps":["שבו על הרצפה עם הברכיים כפופות וכפות הרגליים שטוחות על הרצפה.","אחזו במשקולת בשתי הידיים מול החזה.","הטו את הגוף מעט אחורה כדי להפעיל את שרירי הליבה.","סובבו את פלג הגוף העליון לצד ימין, וקרבו את המשקולת לצד הימני של הגוף.","עצרו לרגע, ולאחר מכן סובבו את פלג הגוף העליון לצד שמאל, וקרבו את המשקולת לצד השמאלי של הגוף.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Sit on the ground with your knees bent and feet flat on the floor.","Hold the weight with both hands in front of your chest.","Lean back slightly to engage your core muscles.","Twist your torso to the right, bringing the weight towards the right side of your body.","Pause for a moment, then twist your torso to the left, bringing the weight towards the left side of your body.","Continue alternating sides for the desired number of repetitions."],"mediaId":"YIUAtYf"},{"id":"edb-0847","name":"כפיפת מרפק בישיבה עם כדור פיזיו","name_en":"weighted seated bicep curl (on stability ball)","muscle":"biceps","equipment":"medicine ball","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["שבו על כדור פיזיו כשכפות הרגליים שטוחות על הרצפה והגב ישר.","אחזו בכדור כוח באחיזה תחתונה, כאשר כפות הידיים פונות למעלה, והניחו לידיים להשתלשל לצדי הגוף.","תוך שמירה על הזרועות העליונות נייחות, נשפו וכופפו את כדור הכוח כלפי מעלה לכיוון הכתפיים.","עצרו לרגע בשיא התנועה, תוך כיווץ שרירי הביצפס.","שאפו והורידו באיטיות את כדור הכוח בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on a stability ball with your feet flat on the ground and your back straight.","Hold a medicine ball with an underhand grip, palms facing up, and let your arms hang down by your sides.","Keeping your upper arms stationary, exhale and curl the medicine ball up towards your shoulders.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the medicine ball back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"b4b6afT"},{"id":"edb-0849","name":"פיתול בישיבה עם כדור פיזיו","name_en":"weighted seated twist (on stability ball)","muscle":"core","equipment":"weighted","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","lower back"],"steps":["שבו על כדור יציבות כשכפות הרגליים מונחות שטוח על הרצפה והברכיים כפופות בזווית של 90 מעלות.","אחזו בפלטת משקולת או בדמבל בשתי הידיים קרוב לחזה.","הפעילו את שרירי הליבה וסובבו באיטיות את פלג הגוף העליון לצד אחד, תוך שמירה על האגן יציב.","עצרו לרגע בסוף הסיבוב, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו על הסיבוב לצד השני.","המשיכו להחליף צדדים למספר החזרות הרצוי."],"steps_en":["Sit on a stability ball with your feet flat on the ground and your knees bent at a 90-degree angle.","Hold a weight plate or dumbbell with both hands close to your chest.","Engage your core and slowly rotate your torso to one side, keeping your hips stable.","Pause for a moment at the end of the rotation, then slowly return to the starting position.","Repeat the rotation to the other side.","Continue alternating sides for the desired number of repetitions."],"mediaId":"s34Y4LR"},{"id":"edb-0850","name":"כפיפה צדית עם כדור פיזיו","name_en":"weighted side bend (on stability ball)","muscle":"core","equipment":"weighted","target":"abs","bodyPart":"waist","secondaryMuscles":["obliques","lower back"],"steps":["שבו על כדור יציבות כאשר הרגליים ברוחב הכתפיים ושטוחות על הרצפה.","אחזו במשקולת ביד אחת והניחו את היד השנייה על הירך.","הפעילו את שרירי הליבה והטו את הגוף באיטיות הצידה לכיוון הצד עם המשקולת, תוך שמירה על גב ישר.","עצרו לרגע בתחתית התנועה, ולאחר מכן חזרו לאט לעמדת ההתחלה.","חזרו למספר החזרות הרצוי, ולאחר מכן החליפו צדדים."],"steps_en":["Sit on a stability ball with your feet shoulder-width apart and flat on the ground.","Hold a weight in one hand and place your other hand on your hip.","Engage your core and slowly bend sideways towards the weighted side, keeping your back straight.","Pause for a moment at the bottom, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"mediaId":"6bOA1Oi"},{"id":"edb-0851","name":"סקוואט עם משקל","name_en":"weighted sissy squat","muscle":"legs","equipment":"weighted","target":"quads","bodyPart":"upper legs","secondaryMuscles":["glutes","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים והבהונות פונות מעט החוצה.","אחזו במשקולת מול החזה בשתי הידיים, או הניחו מוט על הגב העליון.","תוך שמירה על החזה מורם והפעלת שרירי הליבה, הורידו את הגוף באיטיות על ידי כיפוף הברכיים והמותניים.","המשיכו לרדת עד שהירכיים מקבילות לרצפה או עד לעומק המקסימלי הנוח לכם.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו דרך העקבים כדי לחזור למצב ההתחלתי.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and your toes pointing slightly outward.","Hold a weight in front of your chest with both hands, or place a barbell across your upper back.","Keeping your chest up and your core engaged, slowly lower your body down by bending at the knees and hips.","Continue lowering until your thighs are parallel to the ground or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"0lQnxMZ"},{"id":"edb-0852","name":"סקוואט עם משקל","name_en":"weighted squat","muscle":"glutes","equipment":"weighted","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים, כשהבהונות פונות מעט החוצה.","אחזו במשקולת מול החזה או על הכתפיים.","הפעילו את שרירי הליבה ושמרו על החזה מורם בעת הורדת הירכיים למטה ואחורה, כאילו אתם יושבים על כיסא.","רדו עד שהירכיים מקבילות לרצפה, או עד למקסימום שנוח לכם.","דחפו דרך העקבים כדי לחזור לעמידה, תוך כיווץ שרירי הישבן בשיא התנועה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart, toes pointing slightly outward.","Hold a weight in front of your chest or on your shoulders.","Engage your core and keep your chest up as you lower your hips down and back, as if sitting into a chair.","Lower until your thighs are parallel to the ground, or as low as you can comfortably go.","Push through your heels to stand back up, squeezing your glutes at the top.","Repeat for the desired number of repetitions."],"mediaId":"JZuApnB"},{"id":"edb-0853","name":"כפיפת מרפק בעמידה עם משקל","name_en":"weighted standing curl","muscle":"biceps","equipment":"weighted","target":"biceps","bodyPart":"upper arms","secondaryMuscles":["forearms"],"steps":["עמדו עם הרגליים ברוחב הכתפיים ואחזו משקולת בכל יד, כשכפות הידיים פונות קדימה.","שמרו על המרפקים קרובים לגוף ונשפו תוך כדי כיפוף המשקולות כלפי מעלה לגובה הכתפיים.","עצרו לרגע בשיא התנועה, ולאחר מכן שאפו תוך כדי הורדת המשקולות באיטיות בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a dumbbell in each hand, palms facing forward.","Keep your elbows close to your torso and exhale as you curl the weights up to shoulder level.","Pause for a moment at the top, then inhale as you slowly lower the weights back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"M5Y7GPg"},{"id":"edb-0854","name":"weighted standing hand squeeze","name_en":"weighted standing hand squeeze","muscle":"biceps","equipment":"weighted","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["biceps","triceps"],"steps":["עמדו כשהרגליים ברוחב הכתפיים ואחזו במשקולת בכל יד.","הושיטו את הידיים ישר לפניכם, כאשר כפות הידיים פונות זו לזו.","כווצו את הידיים זו לעבר זו בחוזקה ככל שתוכלו, תוך הפעלת האמות.","החזיקו את הכיווץ למשך מספר שניות, ולאחר מכן שחררו.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a weight in each hand.","Extend your arms straight in front of you, palms facing each other.","Squeeze your hands together as hard as you can, engaging your forearms.","Hold the squeeze for a few seconds, then release.","Repeat for the desired number of repetitions."],"mediaId":"bjqbauy"},{"id":"edb-3313","name":"מקבילים עם משקל","name_en":"weighted straight bar dip","muscle":"chest","equipment":"weighted","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["התמקמו בין המקבילים כאשר הידיים ישרות לגמרי והגוף ישר.","הורידו את הגוף על ידי כיפוף המרפקים עד שהזרועות העליונות מקבילות לרצפה.","עצרו לרגע, ואז דחפו את עצמכם בחזרה למצב ההתחלתי על ידי יישור הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Position yourself between parallel bars with your arms fully extended and your body straight.","Lower your body by bending your elbows until your upper arms are parallel to the ground.","Pause for a moment, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"mediaId":"Ff18ItA"},{"id":"edb-3642","name":"לאנג׳ עם משקל","name_en":"weighted stretch lunge","muscle":"glutes","equipment":"weighted","target":"glutes","bodyPart":"upper legs","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["עמדו עם הרגליים ברוחב הכתפיים.","צעדו קדימה עם הרגל הימנית, תוך שמירה על גב ישר.","הורידו את הגוף על ידי כיפוף הברכיים עד שהירך הימנית מקבילה לרצפה.","דחפו דרך העקב הימני כדי לחזור למצב ההתחלתי.","חזרו על התנועה עם הרגל השמאלית.","המשיכו להחליף רגליים למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart.","Take a step forward with your right foot, keeping your back straight.","Lower your body by bending your knees until your right thigh is parallel to the ground.","Push through your right heel to return to the starting position.","Repeat with your left leg.","Continue alternating legs for the desired number of repetitions."],"mediaId":"13VW2VO"},{"id":"edb-0856","name":"לחיצה עם משקל","name_en":"weighted svend press","muscle":"chest","equipment":"weighted","target":"pectorals","bodyPart":"chest","secondaryMuscles":["shoulders","triceps"],"steps":["עמדו כשהרגליים ברוחב הכתפיים ואחזו בפלטת משקולת מול החזה בשתי הידיים.","שמרו על המרפקים כפופים מעט וכפות הידיים פונות זו לזו.","דחפו את פלטת המשקולת ישר לפניכם, תוך יישור מלא של הידיים.","עצרו לרגע בסיום התנועה, ולאחר מכן החזירו את פלטת המשקולת באיטיות לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Stand with your feet shoulder-width apart and hold a weight plate in front of your chest with both hands.","Keep your elbows slightly bent and your palms facing each other.","Press the weight plate straight out in front of you, fully extending your arms.","Pause for a moment at the end of the movement, then slowly bring the weight plate back to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"I1OBLnn"},{"id":"edb-1754","name":"weighted three bench dips","name_en":"weighted three bench dips","muscle":"triceps","equipment":"weighted","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["שבו על קצה הספסל כאשר הידיים אוחזות בקצה, והאצבעות פונות קדימה.","צעדו עם הרגליים קדימה, החליקו את הישבן מהספסל ותמכו במשקל הגוף באמצעות הידיים.","הורידו את הגוף על ידי כיפוף המרפקים, תוך שמירה על הגב קרוב לספסל.","עצרו לרגע בתחתית התנועה, ולאחר מכן דחפו את עצמכם בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the edge of a bench with your hands gripping the edge, fingers pointing forward.","Walk your feet forward, sliding your butt off the bench and supporting your weight with your arms.","Lower your body by bending your elbows, keeping your back close to the bench.","Pause for a moment at the bottom, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"gtO1ErP"},{"id":"edb-1755","name":"weighted tricep dips","name_en":"weighted tricep dips","muscle":"triceps","equipment":"weighted","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["שבו על קצה הספסל או הכיסא כאשר הידיים אוחזות בקצה ליד הירכיים.","החליקו את הישבן מקדמת הספסל כאשר הרגליים מושטות לפניכם.","שמרו על הגב קרוב לספסל והמרפקים כפופים מעט.","הורידו את הגוף על ידי כיפוף המרפקים עד שהזרועות מקבילות לרצפה.","דחפו את עצמכם חזרה למצב ההתחלתי על ידי יישור הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Sit on the edge of a bench or chair with your hands gripping the edge next to your hips.","Slide your butt off the front of the bench with your legs extended in front of you.","Keep your back close to the bench and your elbows slightly bent.","Lower your body by bending your elbows until your upper arms are parallel to the floor.","Push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"mediaId":"bZq4bwK"},{"id":"edb-1767","name":"מקבילים גבוה עם משקל","name_en":"weighted triceps dip on high parallel bars","muscle":"triceps","equipment":"weighted","target":"triceps","bodyPart":"upper arms","secondaryMuscles":["chest","shoulders"],"steps":["התמקמו בין שני מקבילים כאשר הידיים אוחזות במוטות והידיים ישרות לגמרי.","כופפו את המרפקים והורידו את הגוף עד שהזרועות העליונות מקבילות לרצפה.","עצרו לרגע, ולאחר מכן דחפו דרך כפות הידיים כדי ליישר את הידיים ולחזור לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Position yourself between two parallel bars with your hands gripping the bars and your arms fully extended.","Bend your elbows and lower your body until your upper arms are parallel to the ground.","Pause for a moment, then push through your palms to straighten your arms and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"K1vlode"},{"id":"edb-0857","name":"wheel rollerout","name_en":"wheel rollerout","muscle":"core","equipment":"wheel roller","target":"abs","bodyPart":"waist","secondaryMuscles":["lower back"],"steps":["כרעו על הרצפה והניחו את גלגל הכושר לפניכם.","הניחו את הידיים על ידיות גלגל הכושר והושיטו את הידיים ישר לפניכם.","הפעילו את שרירי הליבה וגלגלו את הגלגל קדימה באיטיות, תוך שמירה על גב ישר ובטן מכווצת.","המשיכו לגלגל קדימה עד שהגוף מיושר לחלוטין והזרועות מעל הראש.","עצרו לרגע, ולאחר מכן גלגלו את הגלגל באיטיות בחזרה לכיוון הברכיים, תוך שמירה על שליטה והפעלת שרירי הבטן.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Kneel on the floor and place the wheel roller in front of you.","Place your hands on the handles of the wheel roller and extend your arms straight out in front of you.","Engage your core muscles and slowly roll the wheel forward, keeping your back straight and your abs tight.","Continue rolling forward until your body is fully extended and your arms are overhead.","Pause for a moment, then slowly roll the wheel back towards your knees, maintaining control and keeping your abs engaged.","Repeat for the desired number of repetitions."],"mediaId":"NAgVB3t"},{"id":"edb-3637","name":"wheel run","name_en":"wheel run","muscle":"core","equipment":"body weight","target":"cardiovascular system","bodyPart":"cardio","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["התחילו בתנוחת פלאנק כאשר הידיים על הגלגל והגוף ישר.","הפעילו את שרירי הליבה והתחילו לגלגל את הגלגל קדימה על ידי יישור הידיים.","המשיכו לגלגל עד שהגוף מיושר לגמרי והידיים מעל הראש.","הפכו את כיוון התנועה על ידי משיכת הגלגל בחזרה לכיוון הגוף, באמצעות שרירי הליבה והידיים.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a plank position with your hands on the wheel and your body straight.","Engage your core and start rolling the wheel forward by extending your arms.","Continue rolling until your body is fully extended and your arms are overhead.","Reverse the movement by pulling the wheel back towards your body, using your core and arms.","Repeat for the desired number of repetitions."],"mediaId":"km2Ljzj"},{"id":"edb-1429","name":"מתח אחיזה רחבה","name_en":"wide grip pull-up","muscle":"back","equipment":"body weight","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["התלו על מוט מתח כאשר כפות הידיים פונות ממכם והידיים רחבות יותר מרוחב הכתפיים.","הפעילו את ליבת הגוף וכווצו את השכמות זו לזו.","משכו את הגוף כלפי מעלה לכיוון המוט עד שהסנטר מעל המוט.","הורידו את הגוף בחזרה לתנוחת ההתחלה בשליטה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Hang from a pull-up bar with your palms facing away from you and your hands wider than shoulder-width apart.","Engage your core and squeeze your shoulder blades together.","Pull your body up towards the bar until your chin is above the bar.","Lower your body back down to the starting position with control.","Repeat for the desired number of repetitions."],"mediaId":"Qqi7bko"},{"id":"edb-1367","name":"מתח אחיזה רחבה אחורי","name_en":"wide grip rear pull-up","muscle":"back","equipment":"body weight","target":"lats","bodyPart":"back","secondaryMuscles":["biceps","forearms"],"steps":["אחזו במוט המתח באחיזה עליונה רחבה, כאשר הידיים מעט רחבות יותר מרוחב הכתפיים.","היתלו מהמוט עם הזרועות ישרות לחלוטין והגוף ישר.","הפעילו את שרירי הגב ומשכו את הגוף כלפי מעלה לכיוון המוט, תוך הובלה עם החזה.","המשיכו למשוך עד שהסנטר מעל המוט.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו לאט את הגוף בחזרה לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Grab the pull-up bar with a wide overhand grip, hands slightly wider than shoulder-width apart.","Hang from the bar with your arms fully extended and your body straight.","Engage your back muscles and pull your body up towards the bar, leading with your chest.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"OYFhXVD"},{"id":"edb-1311","name":"שכיבת סמיכה רחב","name_en":"wide hand push up","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["התחילו בתנוחת פלאנק גבוה כאשר הידיים רחבות יותר מרוחב הכתפיים.","שמרו על הגוף בקו ישר מהראש ועד כפות הרגליים.","הורידו את החזה לכיוון הרצפה על ידי כיפוף המרפקים, תוך שמירה עליהם קרובים לגוף.","דחפו דרך כפות הידיים כדי ליישר את הידיים ולחזור לעמדת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Start in a high plank position with your hands wider than shoulder-width apart.","Keep your body in a straight line from head to toe.","Lower your chest towards the ground by bending your elbows, keeping them close to your sides.","Push through your palms to extend your arms and return to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"JmMVpR3"},{"id":"edb-2363","name":"מקבילים אחיזה רחבה גבוה","name_en":"wide-grip chest dip on high parallel bars","muscle":"chest","equipment":"body weight","target":"pectorals","bodyPart":"chest","secondaryMuscles":["triceps","shoulders"],"steps":["התמקמו על המקבילים כאשר הידיים ישרות לגמרי והגוף תלוי באוויר.","הטו את הגוף מעט קדימה והורידו אותו על ידי כיפוף המרפקים עד שהחזה קרוב מאוד למוטות.","עצרו לרגע, ואז דחפו את עצמכם בחזרה למצב ההתחלתי על ידי יישור הזרועות.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Position yourself on the parallel bars with your arms fully extended and your body suspended in the air.","Lean forward slightly and lower your body by bending your elbows until your chest is just above the bars.","Pause for a moment, then push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"mediaId":"O2K9Vb5"},{"id":"edb-0858","name":"wind sprints","name_en":"wind sprints","muscle":"core","equipment":"body weight","target":"abs","bodyPart":"waist","secondaryMuscles":["quadriceps","hamstrings","calves"],"steps":["אתרו שטח פתוח או מסלול לביצוע התרגיל.","התחילו בעמידה עם הרגליים ברוחב הכתפיים.","התחילו לרוץ במהירות המרבית שלכם, תוך הנעת הידיים והרמת הברכיים.","המשיכו בספרינט למרחק או לפרק זמן מסוימים.","נוחו וחזרו למספר החזרות הרצוי."],"steps_en":["Find an open space or a track to perform the exercise.","Start by standing with your feet shoulder-width apart.","Begin running as fast as you can, pumping your arms and driving your knees up.","Continue sprinting for a specific distance or time period.","Rest and repeat for the desired number of repetitions."],"mediaId":"Qoujh3Q"},{"id":"edb-1604","name":"מתיחה","name_en":"world greatest stretch","muscle":"legs","equipment":"body weight","target":"hamstrings","bodyPart":"upper legs","secondaryMuscles":["glutes","quadriceps","calves"],"steps":["התחילו בתנוחת לאנג' כאשר הרגל הימנית קדימה והרגל השמאלית מאחור.","הניחו את הידיים על הרצפה משני צידי הרגל הימנית.","הורידו את הברך השמאלית לרצפה ויישרו את הרגל הימנית, תוך שמירה על כף הרגל הימנית שטוחה על הרצפה.","סובבו את פלג הגוף העליון לצד ימין, והושיטו את היד הימנית למעלה לכיוון התקרה.","החזיקו בתנוחה זו למשך מספר שניות, ולאחר מכן חזרו לתנוחת ההתחלה.","החליפו צדדים וחזרו על המתיחה כאשר הרגל השמאלית קדימה."],"steps_en":["Start in a lunge position with your right foot forward and your left foot back.","Place your hands on the ground on either side of your right foot.","Lower your left knee to the ground and extend your right leg, keeping your right foot flat on the ground.","Rotate your torso to the right, reaching your right arm up towards the ceiling.","Hold this position for a few seconds, then return to the starting position.","Switch sides and repeat the stretch with your left foot forward."],"mediaId":"DFGXwZr"},{"id":"edb-1428","name":"wrist circles","name_en":"wrist circles","muscle":"biceps","equipment":"body weight","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["hands","wrists"],"steps":["הושיטו את הידיים ישר לפניכם.","סגרו את שתי הידיים לאגרוף.","סובבו את שורשי כף היד בתנועה מעגלית, תוך שמירה על הידיים נייחות.","המשיכו בסיבובי שורש כף היד למספר החזרות הרצוי."],"steps_en":["Extend your arms straight out in front of you.","Make a fist with both hands.","Rotate your wrists in a circular motion, keeping your arms still.","Continue the wrist circles for the desired number of repetitions."],"mediaId":"2zNKRUB"},{"id":"edb-0859","name":"wrist rollerer","name_en":"wrist rollerer","muscle":"biceps","equipment":"weighted","target":"forearms","bodyPart":"lower arms","secondaryMuscles":["biceps","triceps"],"steps":["חברו משקולת לקצה אחד של חבל או מוט.","אחזו בקצה השני של החבל או המוט בשתי הידיים, כאשר כפות הידיים פונות למטה.","עמדו כשהרגליים ברוחב הכתפיים והידיים מושטות לגמרי לפניכם.","גלגלו את המשקולת באיטיות כלפי מעלה לכיוון הידיים על ידי כיפוף שורשי כף היד.","עצרו לרגע בשיא התנועה, ולאחר מכן הורידו את המשקולת באיטיות בחזרה לתנוחת ההתחלה.","חזרו על התרגיל למספר החזרות הרצוי."],"steps_en":["Attach a weight to one end of a rope or bar.","Hold the other end of the rope or bar with both hands, palms facing down.","Stand with your feet shoulder-width apart and your arms fully extended in front of you.","Slowly roll the weight up towards your hands by flexing your wrists.","Pause for a moment at the top, then slowly lower the weight back down to the starting position.","Repeat for the desired number of repetitions."],"mediaId":"bd5b860"},{"id":"face-pull","name":"משיכת פנים","name_en":"Face Pull","muscle":"shoulders","equipment":"","target":"","bodyPart":"","secondaryMuscles":[],"steps":[],"steps_en":[],"mediaId":""},{"id":"hip-thrust","name":"היפ ת׳ראסט","name_en":"Hip Thrust","muscle":"glutes","equipment":"","target":"","bodyPart":"","secondaryMuscles":[],"steps":[],"steps_en":[],"mediaId":""},{"id":"plank","name":"פלאנק","name_en":"Plank","muscle":"core","equipment":"","target":"","bodyPart":"","secondaryMuscles":[],"steps":[],"steps_en":[],"mediaId":""}];

